/* =========================================================
   PLAYLY. — Dashboard Logic (auth + multi-view)
   ========================================================= */

// Version banner — log di console saat script load untuk verifikasi
// versi yang aktif (kadang browser/CDN cache serve versi lama).
console.info("%c[playly] script.js v583 (skeleton loading system + pricing modal distinction + concurrent session work)", "color:#DCA96D;font-weight:600;");

// ----------------------- ORPHAN KEYS CLEANUP (2026-05-22) -----------------------
// Cleanup key localStorage warisan dari versi lama yang sudah tidak ditulis lagi
// tapi cloud-sync mirror dari kv table → re-sync tiap load → state inconsistency.
// playly-current-user: dulu nyimpen current user (kayak "demo_creator"), sekarang
// tidak ada writer; tapi cloud kv masih punya value lama → bug yang dilaporkan user.
// Cloud-sync sudah di-update no-sync untuk key ini, tapi local copy yang sudah ada
// perlu dibersihin sekali. Idempotent — aman dipanggil tiap boot.
(function purgeOrphanKeys() {
  try { localStorage.removeItem("playly-current-user"); } catch (_) {}
})();

// ----------------------- CLOUD PURGE QUEUE RETRY (v538, 2026-05-25) -----------------------
// Boot-time retry untuk cloud removeKeys yg timeout di deleteUserAccount.
// Audit moderation flow finding H3: 8s timeout race bisa winning sebelum
// removeKeys finish → cloud row resurrect di next boot. Sekarang queue
// keys di localStorage saat delete, retry IIFE ini scan + remove +
// unqueue saat success. Non-blocking, silent fail aman.
(function retryCloudPurgeQueue() {
  try {
    var q = JSON.parse(localStorage.getItem("playly-cloud-purge-queue") || "[]");
    if (!Array.isArray(q) || !q.length) return;
    // Tunggu cloud-sync ready (anon client tersedia)
    var wait = 0;
    var iv = setInterval(function () {
      if (++wait > 30) { clearInterval(iv); return; } // max 15s wait
      if (!window.cloudSync || !window.cloudSync.removeKeys) return;
      clearInterval(iv);
      // Cloud-sync ready — retry purge
      window.cloudSync.removeKeys(q)
        .then(function () {
          try { localStorage.setItem("playly-cloud-purge-queue", "[]"); } catch {}
          console.info("[purge-queue] retry success — " + q.length + " stale keys removed from cloud");
        })
        .catch(function (err) { console.warn("[purge-queue] retry failed:", err); });
    }, 500);
  } catch (err) { console.warn("[purge-queue] init exception:", err); }
})();

// ----------------------- PURGE TEST ACCOUNTS (2026-05-25) -----------------------
// User lapor akun test "user1" muncul di halaman Pencarian padahal Supabase
// auth.users tidak punya entry ini. Akun-akun ini sisa-sisa testing yg di
// localStorage + ke-sync ke kv (sebelum B5 di-deploy). Cleanup IIFE ini
// hapus dari localStorage (cloud-sync hook akan otomatis push DELETE ke kv
// untuk key prefix yg masih ke-sync). Idempotent — flag mencegah re-run.
(function purgeTestAccounts() {
  // Bump flag jadi v2 (2026-05-25 round 2) supaya IIFE jalan lagi
  // walaupun device sudah set flag v1 sebelumnya — sekarang ada
  // tambahan stale account cantika@playly.app yang perlu di-cleanup.
  var FLAG = "playly-bf-purge-test-2026-05-25-v2";
  try {
    if (localStorage.getItem(FLAG) === "1") return;
    var testEmails = [
      "user1@gmail.com",
      "userbaru1@gmail.com",
      "usernew1@gmail.com",
      // Round 2 (2026-05-25): stale dup account yg conflict dgn real user
      // "cantika" (real user pakai email cantikaputri@gmail.com). Account
      // ini muncul di halaman Pencarian sbg "diri sendiri" karena username
      // collision. Bukan akun production yg sah.
      "cantika@playly.app",
    ];
    var testUsernames = ["user1", "userbaru1", "usernew1"];
    var removed = 0;
    // Hapus akun + state + prefs
    testEmails.forEach(function (e) {
      var k = "playly-account-" + e;
      if (localStorage.getItem(k) !== null) { localStorage.removeItem(k); removed++; }
      var p = "playly-prefs-" + e;
      if (localStorage.getItem(p) !== null) { localStorage.removeItem(p); removed++; }
    });
    testUsernames.forEach(function (u) {
      var s = "playly-state-" + u;
      if (localStorage.getItem(s) !== null) { localStorage.removeItem(s); removed++; }
      var w = "playly-welcomed-" + u;
      if (localStorage.getItem(w) !== null) { localStorage.removeItem(w); removed++; }
      var f = "playly-2fa-" + u;
      if (localStorage.getItem(f) !== null) { localStorage.removeItem(f); removed++; }
    });
    // Bersihkan playly-device-accounts (array email yg pernah login di device)
    try {
      var raw = localStorage.getItem("playly-device-accounts");
      if (raw) {
        var arr = JSON.parse(raw);
        if (Array.isArray(arr)) {
          var filtered = arr.filter(function (e) {
            return testEmails.indexOf(String(e).toLowerCase()) === -1;
          });
          if (filtered.length !== arr.length) {
            localStorage.setItem("playly-device-accounts", JSON.stringify(filtered));
            removed++;
          }
        }
      }
    } catch (_) {}
    localStorage.setItem(FLAG, "1");
    if (removed) console.info("[purge-test] removed " + removed + " test account keys (user1/userbaru1/usernew1)");
  } catch (err) {
    console.warn("[purge-test] exception:", err);
  }
})();

// ----------------------- AUTO-PUBLISH BACKFILL (2026-05-25) -----------------------
// Sebelum 2026-05-25, video upload default adminStatus "pending" → harus
// admin approve dulu. User bingung kenapa video tidak muncul di "Video Saya".
// Sekarang upload langsung "published" (line ~40105) — tapi video LAMA yang
// terlanjur ke-flag "pending" tetap stuck. Backfill ini flip semua
// "pending" → "published" sekali per device. Takedown/draft tidak disentuh.
// Flag idempotent supaya tidak ke-flip lagi kalau admin sengaja set pending.
(function backfillPendingToPublished() {
  var FLAG = "playly-bf-auto-publish-2026-05-25";
  try {
    if (localStorage.getItem(FLAG) === "1") return;
    var changed = 0;
    for (var i = 0; i < localStorage.length; i++) {
      var key = localStorage.key(i);
      if (!key || !key.startsWith("playly-state-")) continue;
      var raw = localStorage.getItem(key);
      if (!raw) continue;
      var s;
      try { s = JSON.parse(raw); } catch (_) { continue; }
      if (!s || !Array.isArray(s.myVideos)) continue;
      var touched = false;
      s.myVideos.forEach(function (v) {
        if (v && v.adminStatus === "pending") {
          v.adminStatus = "published";
          v.updatedAt = Date.now();
          touched = true;
          changed++;
        }
      });
      if (touched) {
        try { localStorage.setItem(key, JSON.stringify(s)); } catch (_) {}
      }
    }
    localStorage.setItem(FLAG, "1");
    if (changed) console.info("[backfill] " + changed + " video pending → published");
  } catch (err) {
    console.warn("[backfill] pending→published exception:", err);
  }
})();

// ----------------------- URL-TRIGGER ADMIN RESET -----------------------
// Visit /?cleanup=playly-reset → wipe all user data + payments + state.
// Admin accounts are preserved. Page reloads after cleanup. Per user
// request 2026-05-06 (Chrome blocks DevTools paste, so we expose a
// safe URL trigger instead).
(function adminCleanupTrigger() {
  try {
    const params = new URLSearchParams(window.location.search);
    if (params.get("cleanup") !== "playly-reset") return;
    // v543 (2026-05-25): admin.playly2 dihapus per konfirmasi user — bukan
    // akun admin real, sisa test data. Real admin tunggal: admin.playly@gmail.com.
    const adminEmails = ["admin.playly@gmail.com"];
    const removed = { accounts: 0, payments: 0, stateKeys: 0, otherKeys: 0 };
    const allKeys = Object.keys(localStorage);
    // Kumpulkan key yg dihapus → dihapus juga di cloud Supabase
    // (cleanup IIFE jalan SEBELUM hook removeItem cloud-sync terpasang,
    // jadi delete cloud harus eksplisit di sini). request user 2026-05-17.
    const cloudDeleteKeys = [];

    // 1. Non-admin accounts
    // B6c (2026-05-25): playly-account-* sekarang 100% user emails (system
    // key dipindah ke playly-syskey-* namespace via migrateCutoffKey).
    // Suffix-@ check tetap defensive — guard kalau ada legacy key tertinggal.
    allKeys.filter(k => k.startsWith("playly-account-")).forEach(k => {
      const suffix = k.replace("playly-account-", "");
      if (!suffix.includes("@")) return; // defensive: skip legacy system key
      if (!adminEmails.includes(suffix)) {
        localStorage.removeItem(k);
        cloudDeleteKeys.push(k);
        removed.accounts++;
      }
    });

    // 2. All premium-payments
    if (localStorage.getItem("playly-premium-payments")) {
      try {
        const arr = JSON.parse(localStorage.getItem("playly-premium-payments") || "[]");
        removed.payments = arr.length;
      } catch {}
      localStorage.setItem("playly-premium-payments", "[]");
    }

    // 3. Per-user state/prefs
    const userPrefixes = [
      "playly-state-", "playly-prefs-", "playly-welcomed-", "playly-welcome-",
      "playly-onboarding-", "playly-notif-", "playly-2fa-",
      "playly-videos-", "playly-followers-", "playly-following-",
      "playly-history-", "playly-trash-", "playly-downloads-",
      "playly-status-", "playly-pinned-",
    ];
    allKeys.forEach(k => {
      const isAdminScoped = adminEmails.some(e => k.endsWith(e) || k.includes(e));
      if (isAdminScoped) return;
      if (userPrefixes.some(p => k.startsWith(p))) {
        localStorage.removeItem(k);
        cloudDeleteKeys.push(k);
        removed.stateKeys++;
      }
    });

    // 4. Platform-wide aggregates
    ["playly-revenue-ledger", "playly-platform-videos", "playly-platform-comments",
     "playly-platform-likes", "playly-platform-views", "playly-admin-events",
     "playly-admin-events-log", "playly-takedowns", "playly-pending-videos",
     "playly-user", "playly-state"].forEach(k => {
      if (localStorage.getItem(k)) {
        localStorage.removeItem(k);
        cloudDeleteKeys.push(k);
        removed.otherKeys++;
      }
    });

    const finishRedirect = (cloudInfo) => {
      alert(
        `✓ Reset berhasil!\n\n` +
        `• ${removed.accounts} akun user dihapus\n` +
        `• ${removed.payments} payment dihapus\n` +
        `• ${removed.stateKeys} state keys dihapus\n` +
        `• ${removed.otherKeys} platform keys dihapus\n` +
        `• Cloud: ${cloudInfo}\n\n` +
        `Admin tetap aman. Klik OK untuk lanjut ke halaman bersih.`
      );
      // Strip cleanup param + redirect to clean URL
      window.location.replace(window.location.pathname);
    };
    // Hapus juga di cloud Supabase (mirror scope localStorage di atas;
    // 2 akun admin & system key TIDAK masuk cloudDeleteKeys karena
    // filter yg sama). Redirect DITUNDA sampai cloud delete selesai
    // supaya cloud-sync tidak menarik balik dummy sebelum terhapus.
    try {
      const cfg = window.PLAYLY_SUPABASE;
      if (cfg && cfg.url && cfg.key && window.supabase && window.supabase.createClient) {
        const sb = window.supabase.createClient(cfg.url, cfg.key, { auth: { persistSession: false } });
        const ops = [];
        // payments → reset [] di cloud juga
        ops.push(sb.from("kv").upsert(
          { key: "playly-premium-payments", value: [], updated_at: new Date().toISOString() },
          { onConflict: "key" }
        ));
        for (let i = 0; i < cloudDeleteKeys.length; i += 50) {
          ops.push(sb.from("kv").delete().in("key", cloudDeleteKeys.slice(i, i + 50)));
        }
        Promise.allSettled(ops)
          .then(() => finishRedirect(`${cloudDeleteKeys.length} key dihapus`))
          .catch(() => finishRedirect(`gagal (lihat console)`));
      } else {
        finishRedirect("dilewati (config tidak ada)");
      }
    } catch (e) {
      console.error("[cleanup] cloud delete failed:", e);
      finishRedirect("gagal (lihat console)");
    }
  } catch (err) {
    console.error("[cleanup] failed:", err);
  }
})();

// ----------------------- LEGACY SHARE LINK REDIRECT -----------------------
// Link share lama format `#video=<id>` (sebelum public watch page) → redirect
// ke `/watch?v=<id>` supaya bisa diputar tanpa login.
(function redirectLegacyVideoHash() {
  const m = /^#video=(\d+)/.exec(window.location.hash || "");
  if (!m) return;
  const id = m[1];
  // Pakai replace supaya entry lama gak nyangkut di history
  window.location.replace(`${window.location.origin}/watch?v=${id}`);
})();

// ----------------------- HASH ROUTER (v479) -----------------------
// Lightweight URL hash routing supaya user bisa share link / reload / back-fwd
// preserve halaman aktif. Format: `#/section` atau `#/section/param`.
// Contoh: `#/dashboard`, `#/watch/123`, `#/notifications`, `#/settings`.
// Router defer eksekusi sampai `switchView` & `openPlayer` ter-define
// (DOMContentLoaded). Public API: `window.playlyRouter.go(hash)` / `parse()`.
(function installHashRouter() {
  // Map hash section → view name yg dikenali switchView().
  // User-facing aliases (lebih natural) → internal view IDs.
  const ROUTE_TO_VIEW = {
    "":              "__default",
    "home":          "home",
    "dashboard":     "__default",   // role-aware: admin → admin-dashboard, user → home
    "library":       "videos",
    "videos":        "videos",
    "upload":        "upload",
    "storage":       "storage",
    "history":       "history",
    "stats":         "stats",
    "insight":       "stats",
    "messages":      "messages",
    "inbox":         "messages",
    "activity":      "activity",
    "discover":      "discover",
    "search":        "people",
    "people":        "people",
    "profile":       "profile",
    "myprofile":     "myprofile",
    "settings":      "settings",
    "notifications": "notifications",
    "watch":         "player",
    "player":        "player",
    // admin
    "admin":               "admin-dashboard",
    "admin-dashboard":     "admin-dashboard",
    "admin-users":         "admin-users",
    "admin-videos":        "admin-videos",
    "admin-comms":         "admin-comms",
    "admin-inbox":         "admin-inbox",
    "admin-audit":         "admin-audit",
    "admin-analytics":     "admin-analytics",
    "admin-ads":           "admin-ads",
    "admin-revenue":       "admin-revenue",
    "admin-premium-queue": "admin-premium-queue",
  };

  function parseHash(h) {
    const raw = String(h || "").replace(/^#\/?/, "").trim();
    if (!raw) return { section: "", param: "" };
    // Drop query string (e.g. `#/watch/123?t=5`)
    const noQuery = raw.split("?")[0];
    const parts = noQuery.split("/").filter(Boolean);
    return { section: parts[0] || "", param: parts.slice(1).join("/") };
  }

  // Apakah saat ini di auth landing? Kalau ya, JANGAN route ke view internal —
  // user belum login. (Auth-mode landing diatur via .auth-mode di body.)
  function isAuthMode() {
    return document.body.classList.contains("auth-mode");
  }

  let _routeInFlight = false;
  function routeFromHash() {
    if (_routeInFlight) return;
    if (isAuthMode()) return; // auth landing: skip routing
    const { section, param } = parseHash(location.hash);
    let viewName = ROUTE_TO_VIEW[section];
    if (viewName === "__default" || viewName == null) {
      // Default → role-aware home
      const role = (typeof user === "object" && user && user.role) || document.body.dataset.role || "user";
      viewName = role === "admin" ? "admin-dashboard" : "home";
    }
    _routeInFlight = true;
    try {
      // Special: watch/:videoId → openPlayer(id)
      if ((section === "watch" || section === "player") && param) {
        const vid = /^\d+$/.test(param) ? parseInt(param, 10) : param;
        if (typeof window.openPlayer === "function") {
          window.openPlayer(vid);
        } else if (typeof openPlayer === "function") {
          openPlayer(vid);
        }
        return;
      }
      if (typeof window.switchView === "function") {
        window.switchView(viewName);
      } else if (typeof switchView === "function") {
        switchView(viewName);
      }
    } finally {
      _routeInFlight = false;
    }
  }

  // Push current view ke hash tanpa trigger routing loop. Dipanggil oleh
  // switchView wrapper (lihat patch terpisah) supaya URL selalu sinkron.
  function pushView(viewName) {
    if (!viewName) return;
    if (isAuthMode()) return;
    // Map internal view → user-facing slug (reverse map). Pakai first-match.
    let slug = viewName;
    for (const [k, v] of Object.entries(ROUTE_TO_VIEW)) {
      if (v === viewName && k && k !== "__default") { slug = k; break; }
    }
    const next = `#/${slug}`;
    if (location.hash === next) return;
    // Pakai history.replaceState supaya tidak banjirin back stack saat user
    // klik sidebar berurutan. Back tetap jalan untuk navigasi sebenarnya
    // (sidebar click → hashchange → switchView → replaceState).
    try {
      history.replaceState(null, "", next);
    } catch {
      location.hash = next;
    }
  }

  function pushWatch(videoId) {
    if (!videoId) return;
    if (isAuthMode()) return;
    const next = `#/watch/${videoId}`;
    if (location.hash === next) return;
    try { history.pushState(null, "", next); } catch { location.hash = next; }
  }

  window.addEventListener("hashchange", routeFromHash);
  // Initial route — setelah dashboard boot. Listen ke event custom yg di-
  // dispatch saat showApp/bootDashboard selesai, plus fallback DOMContentLoaded.
  let _bootedOnce = false;
  function bootRoute() {
    if (_bootedOnce) return;
    if (isAuthMode()) return;
    _bootedOnce = true;
    if (location.hash && location.hash !== "#") routeFromHash();
  }
  window.addEventListener("playly:app-booted", bootRoute);
  document.addEventListener("DOMContentLoaded", () => setTimeout(bootRoute, 300));

  window.playlyRouter = {
    parse: parseHash,
    go: routeFromHash,
    pushView,
    pushWatch,
    isAuthMode,
  };
})();

// ----------------------- HELPERS -----------------------
const $ = (s, p = document) => p.querySelector(s);
const $$ = (s, p = document) => [...p.querySelectorAll(s)];

// ---- Device-local accounts list (TIDAK sync ke cloud) ----
// Hanya akun yang pernah login di device ini muncul di "Pindah Akun".
// Akun user lain di cloud tidak boleh kelihatan (privasi).
const DEVICE_ACCOUNTS_KEY = "playly-device-accounts";
function getDeviceAccountEmails() {
  try {
    const raw = localStorage.getItem(DEVICE_ACCOUNTS_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch { return []; }
}
function addDeviceAccount(email) {
  if (!email) return;
  const lower = String(email).toLowerCase();
  const list = getDeviceAccountEmails();
  if (list.includes(lower)) return;
  list.push(lower);
  // Pakai origSet supaya tidak trigger cloud sync (key sudah di NO_SYNC_KEYS sih, tapi extra safe)
  localStorage.setItem(DEVICE_ACCOUNTS_KEY, JSON.stringify(list));
}
function removeDeviceAccount(email) {
  if (!email) return;
  const lower = String(email).toLowerCase();
  const list = getDeviceAccountEmails().filter(e => e !== lower);
  localStorage.setItem(DEVICE_ACCOUNTS_KEY, JSON.stringify(list));
}
// Catatan: tracking device-account dilakukan SECARA EKSPLISIT di flow login &
// signup (lihat panggilan addDeviceAccount() di handler form login dan signup).
// Tidak pakai interceptor setItem supaya proses auto-boot, role-recovery, atau
// profile-update tidak ikut menambah email ke daftar perangkat.

