function emojiToIcon(str){
  if (str == null) return str;
  var s = String(str);
  if (s.indexOf('️') !== -1) s = s.replace(/️/g, '');
  for (var e in EMOJI_ICON){ if (s.indexOf(e) !== -1) s = s.split(e).join(EMOJI_ICON[e]); }
  return s;
}
window.emojiToIcon = emojiToIcon;

// Selektor KONTEN USER — JANGAN konversi emoji di sini (judul video, komentar,
// nama, bio, chat, input). Hanya chrome UI yang dikonversi. =====================
var _UI_EMOJI_SKIP = '.fyp-title,.fyp-desc,.fyp-card-caption,.fyp-cm-text,.fyp-cm-item,.fyp-cm-replies,.fyp-comments,.comment-text,.comment-body,.cmt-text,.cmt-body,.lib-meta,.lib-title,.video-title,.vid-title,.pv-title,#playerTitle,#playerDesc,.pv-desc,.pv-creator-row,.user-name,.creator-name,.people-name,.people-handle,.dm-thread-preview,.dm-thread-top,.dm-msg,.dm-bubble,.dm-chat-msg,.bnp-text,.bio,.hpc-bio,.suggest-name,.suggest-handle,.lb-name,input,textarea,[contenteditable],[data-no-emi]';
var _UI_EMOJI_RE = /[\u{1F000}-\u{1FAFF}\u{2600}-\u{27BF}\u{2190}-\u{21FF}\u{2B00}-\u{2BFF}\u{2300}-\u{23FF}]/u;
// Ganti emoji UI -> ikon SVG, HANYA di text-node chrome (lewati konten user &
// svg/script/style). Operasi pada text-node (elemen + listener tetap utuh).
function convertUiEmojis(root) {
  if (!root || typeof emojiToIcon !== "function" || !document.createTreeWalker) return;
  var tw = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, {
    acceptNode: function (node) {
      var v = node.nodeValue;
      if (!v || !_UI_EMOJI_RE.test(v)) return NodeFilter.FILTER_REJECT;
      var p = node.parentElement;
      if (!p) return NodeFilter.FILTER_REJECT;
      var tag = p.tagName;
      if (tag === "SCRIPT" || tag === "STYLE" || tag === "TEXTAREA") return NodeFilter.FILTER_REJECT;
      if (p.closest("svg")) return NodeFilter.FILTER_REJECT;
      if (p.closest(_UI_EMOJI_SKIP)) return NodeFilter.FILTER_REJECT;
      return NodeFilter.FILTER_ACCEPT;
    }
  });
  var nodes = [], n;
  while ((n = tw.nextNode())) nodes.push(n);
  for (var i = 0; i < nodes.length; i++) {
    var node = nodes[i];
    var html = emojiToIcon(node.nodeValue);
    if (html === node.nodeValue) continue;
    var tmp = document.createElement("template");
    tmp.innerHTML = html;
    node.parentNode.replaceChild(tmp.content, node);
  }
}
window.convertUiEmojis = convertUiEmojis;

// Observer: konversi subtree yg baru dirender. Disconnect saat memproses supaya
// sisipan SVG kita sendiri tidak memicu loop. Debounce 150ms.
var _emiObs = null, _emiQueue = null, _emiTimer = null;
function _emiFlush() {
  _emiTimer = null;
  if (_emiObs) _emiObs.disconnect();
  try {
    _emiQueue.forEach(function (node) { if (node && node.isConnected) convertUiEmojis(node); });
  } catch (e) {}
  _emiQueue.clear();
  var root = document.body;
  if (_emiObs && root) _emiObs.observe(root, { childList: true, subtree: true });
}
function initUiEmojiConvert() {
  // Root = body supaya mencakup chrome di LUAR .views: sidebar, top bar, ticker,
  // dan MODAL (edit video, bagikan, dll) yang di-append ke body. Aman karena
  // skip-list konten user + lewati svg/script + guard admin.
  var root = document.body;
  if (!root) return;
  if (document.body && document.body.dataset.role === "admin") return; // user dashboard saja
  try { convertUiEmojis(root); } catch (e) {}
  if (window.MutationObserver && !_emiObs) {
    _emiQueue = new Set();
    _emiObs = new MutationObserver(function (muts) {
      for (var j = 0; j < muts.length; j++) {
        var added = muts[j].addedNodes;
        for (var k = 0; k < added.length; k++) {
          var nd = added[k];
          if (nd.nodeType === 1) _emiQueue.add(nd);
          else if (nd.nodeType === 3 && nd.parentElement) _emiQueue.add(nd.parentElement);
        }
      }
      if (_emiQueue.size && !_emiTimer) _emiTimer = setTimeout(_emiFlush, 150);
    });
    _emiObs.observe(root, { childList: true, subtree: true });
  }
}
window.initUiEmojiConvert = initUiEmojiConvert;

function toast(msg, type = "") {
  const t = document.createElement("div");
  t.className = `toast ${type}`;
  t.innerHTML = emojiToIcon(msg);
  const host = $("#toastHost");
  host.append(t);
  // Anchor below bell icon (#openNotif) dgn margin 10px. Fallback ke
  // top-right kalau bell ga ada di viewport.
  const bell = document.getElementById("openNotif");
  if (bell) {
    const r = bell.getBoundingClientRect();
    host.style.top = `${Math.round(r.bottom + 10)}px`;
    host.style.right = `${Math.max(12, Math.round(window.innerWidth - r.right))}px`;
  }
  setTimeout(() => { t.style.opacity = "0"; t.style.transform = "translateY(-12px)"; }, 2800);
  setTimeout(() => t.remove(), 3200);
}
window.toast = toast;

// Popup notif yang anchor di bawah bell icon di topbar (id="openNotif").
// Variant ke-2 dari toast — per request user 2026-05-10aj. Auto-dismiss 4.5s.
function bellNotif(msg, type = "info") {
  const bell = document.getElementById("openNotif");
  if (!bell) {
    if (typeof toast === "function") toast(msg, type);
    return;
  }
  document.getElementById("__bellNotifPopup")?.remove();
  const popup = document.createElement("div");
  popup.id = "__bellNotifPopup";
  popup.className = `bell-notif-popup bell-notif-${type}`;
  popup.innerHTML = `
    <div class="bnp-arrow" aria-hidden="true"></div>
    <div class="bnp-text">${msg}</div>
    <button class="bnp-close" type="button" aria-label="Tutup">✕</button>
  `;
  document.body.appendChild(popup);
  // Position relative ke bell icon (centered di bawah)
  const r = bell.getBoundingClientRect();
  popup.style.position = "fixed";
  popup.style.top = `${Math.round(r.bottom + 10)}px`;
  popup.style.left = `${Math.round(r.left + r.width / 2)}px`;
  popup.style.zIndex = "9999";
  // Animate in next frame
  requestAnimationFrame(() => popup.classList.add("show"));
  // Auto-dismiss + manual close
  let timer = null;
  const dismiss = () => {
    if (timer) clearTimeout(timer);
    popup.classList.remove("show");
    setTimeout(() => popup.remove(), 220);
  };
  popup.querySelector(".bnp-close")?.addEventListener("click", dismiss);
  timer = setTimeout(dismiss, 4500);
}
window.bellNotif = bellNotif;

// Waktu relatif untuk chat (pesan + thread). Hanya menerima timestamp angka.
// Data lama yang tidak punya `ts` (mis. "Mantap 👍" yang sempat tersimpan dengan
// time: "baru") sengaja kembalikan "" supaya tidak terlihat seperti pesan baru.
function chatRelTime(ts) {
  if (!ts || typeof ts !== "number") return "";
  const diff = Date.now() - ts;
  // Pakai t() biar sinkron dengan locale aktif (default EN). Fallback string EN.
  if (diff < 0) return t("rel.justnow") || "now";
  if (diff < 60_000) return t("rel.justnow") || "now";
  if (diff < 3_600_000) return Math.floor(diff / 60_000) + " " + (t("chat.min.short") || "min");
  if (diff < 86_400_000) return Math.floor(diff / 3_600_000) + " " + (t("chat.hour.short") || "h");
  if (diff < 7 * 86_400_000) return Math.floor(diff / 86_400_000) + " " + (t("chat.day.short") || "d");
  const d = new Date(ts);
  const locale = (document.body?.dataset?.lang === "id") ? "id-ID" : "en-US";
  return d.toLocaleDateString(locale, { day: "numeric", month: "short" });
}

// ----------------------- PLATFORM CONTENT (dinamis dari semua user) -----------------------
// Tidak ada data hardcoded — Discover akan kosong sampai user upload.
// Konten platform = agregasi dari semua user yang sudah upload video.

function getPlatformVideos() {
  // Agregasi semua videos dari semua user yang punya state di localStorage.
  // Skip state milik akun demo/mock supaya video mereka tidak muncul di feed.
  // Approval workflow: HANYA video dengan adminStatus === "published" yang
  // muncul di feed publik (Discover, Trending, Spotlight, dst). Video pending,
  // rejected, takedown DI-FILTER OUT untuk public consumption.
  // Catatan: getAllAdminVideos() dipakai admin Content Control untuk
  // moderasi — itu pakai source berbeda yang tetap include semua status.
  const videos = [];
  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (!key || !key.startsWith("playly-state-")) continue;
    const uname = key.slice("playly-state-".length).toLowerCase();
    if (KNOWN_DEMO_USERNAMES.includes(uname)) continue;
    if (DUMMY_USERNAMES.includes(uname)) continue; // demo_creator + kreator palsu
    // Skip video milik akun admin — admin bukan creator publik
    try {
      const accRaw = localStorage.getItem(`playly-account-${uname}`)
                  || Object.keys(localStorage).filter(k => k.startsWith("playly-account-"))
                       .map(k => localStorage.getItem(k))
                       .find(raw => { try { return JSON.parse(raw)?.username?.toLowerCase() === uname; } catch { return false; } });
      const acc = accRaw ? JSON.parse(accRaw) : null;
      if (acc?.role === "admin") continue;
      if (acc?.email && typeof isAllowedAdminEmail === "function" && isAllowedAdminEmail(acc.email)) continue;
    } catch {}
    try {
      const s = JSON.parse(localStorage.getItem(key));
      if (Array.isArray(s.myVideos)) videos.push(...s.myVideos);
    } catch {}
  }
  // Filter: only published videos visible publicly
  const filtered = videos.filter(v => {
    const st = v.adminStatus;
    // Backward-compat: kalau video lama nggak punya field adminStatus,
    // anggap sudah published (jangan break content yang udah ada).
    if (st == null) return true;
    return st === "published";
  });
  // Sort by views desc, fallback by id (newest)
  filtered.sort((a, b) => (b.viewsNum || 0) - (a.viewsNum || 0) || b.id - a.id);
  return filtered;
}

function getPlatformCreators({ activeOnly = false } = {}) {
  // Daftar semua user terdaftar — kecuali user yang sedang login
  const creators = [];
  const seen = new Set();

  // Defensif: kumpulkan semua identifier yang termasuk "diri sendiri"
  const selfIds = new Set();
  if (user) {
    if (user.username) selfIds.add(String(user.username).toLowerCase());
    if (user.email) selfIds.add(String(user.email).toLowerCase());
    if (user.name) selfIds.add(String(user.name).toLowerCase().replace(/\s+/g, ""));
  }

  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (!key || !key.startsWith("playly-account-")) continue;
    try {
      const a = JSON.parse(localStorage.getItem(key));
      if (!a.username) continue;
      // Skip akun admin — di halaman user, admin tidak boleh muncul sebagai
      // saran kreator / di feed / di trending. Admin bukan creator publik.
      if (a.role === "admin") continue;
      const uname = String(a.username).toLowerCase();
      const aemail = String(a.email || "").toLowerCase();
      if (typeof isAllowedAdminEmail === "function" && isAllowedAdminEmail(aemail)) continue;
      // Akun lama (cutoff/ban list) — auto-clean & skip
      if (typeof shouldBanAccount === "function" && shouldBanAccount(a)) {
        try { localStorage.removeItem(key); } catch {}
        if (typeof purgeUserDataByUsername === "function") purgeUserDataByUsername(a.username);
        if (typeof addBannedEmails === "function") addBannedEmails([aemail]);
        continue;
      }
      // Skip diri sendiri (cek username, email, atau key)
      if (selfIds.has(uname) || selfIds.has(aemail)) continue;
      if (seen.has(uname)) continue;
      seen.add(uname);

      // Hitung jumlah video dari user ini + cari upload terakhir untuk fresh-ring
      const stateRaw = localStorage.getItem(`playly-state-${a.username}`);
      let videoCount = 0;
      let latestUploadAt = 0;
      let lastActivity = 0;
      try {
        const s = JSON.parse(stateRaw);
        const myVids = Array.isArray(s?.myVideos) ? s.myVideos : [];
        videoCount = myVids.length;
        for (const v of myVids) {
          const t = Number(v?.uploadedAt || v?.createdAt || v?.ts || 0);
          if (t > latestUploadAt) latestUploadAt = t;
        }
        // Last activity timestamp untuk presence detection (fix B5 audit
        // 2026-05-02). Sebelumnya pakai Math.random() > 0.4 → random
        // online dot tiap render → bohong soal presence. Sekarang real:
        // online kalau aktivitas terakhir < 5 menit lalu.
        lastActivity = Math.max(
          Number(s?.lastActivityAt || 0),
          Number(a?.lastActivityAt || 0),
          latestUploadAt
        );
      } catch {}

      // Kalau activeOnly, skip akun yang belum upload video
      if (activeOnly && videoCount === 0) continue;

      const isOnline = lastActivity > 0 && (Date.now() - lastActivity) < 5 * 60 * 1000;

      creators.push({
        name: a.username,
        displayName: a.name,
        subs: videoCount > 0 ? `${videoCount} video` : "New creator",
        online: isOnline,
        init: (a.name || a.username).slice(0, 2).toUpperCase(),
        videoCount,
        avatar: a.avatar || null,
        latestUploadAt,
        lastActivity
      });
    } catch {}
  }
  return creators;
}

// ----------------------- ONE-TIME RESET — DIHAPUS PERMANEN -----------------------
// Sebelumnya ada IIFE `purgePlaylyDataOnce` yang sekali per-browser menghapus
// semua key `playly-*` dari localStorage. Bug kritikal: cloud-sync.js men-hijack
// `localStorage.removeItem` dan otomatis ikut menghapus key dari Supabase.
// Akibatnya, tiap kali ada visitor baru/incognito buka site, akun & state user
// dari device lain ikut terhapus dari cloud — termasuk akun yang baru daftar.
// Itu sebabnya Search User & Komunitas Aktif kelihatan kosong di device user
// baru. Migrasi reset sudah selesai jadinya kode-nya dihapus permanen.
//
// Hapus flag yang mungkin masih nyangkut supaya bersih total.
try { localStorage.removeItem("__playly_reset_v4"); } catch {}

// ----------------------- ADMIN LOCK -----------------------
// Hanya email & username ini yang boleh jadi admin. User lain tidak boleh memakainya.
const OFFICIAL_ADMIN_EMAIL = "admin.playly@gmail.com";
const OFFICIAL_ADMIN_USERNAME = "admin";
function isOfficialAdminEmail(email) {
  return (email || "").trim().toLowerCase() === OFFICIAL_ADMIN_EMAIL;
}
function isReservedUsername(username) {
  return (username || "").trim().toLowerCase() === OFFICIAL_ADMIN_USERNAME;
}

// Allowlist admin tambahan — dikelola super admin via Settings → Buat Admin.
// Disimpan di localStorage (auto-mirror ke Supabase via cloud-sync) supaya
// admin tambahan ikut sinkron lintas device.
const ADMIN_ALLOWLIST_KEY = "playly-admin-allowlist";
function getExtraAdminEmails() {
  try {
    const arr = JSON.parse(localStorage.getItem(ADMIN_ALLOWLIST_KEY) || "[]");
    if (!Array.isArray(arr)) return [];
    return arr.map(e => String(e || "").trim().toLowerCase()).filter(Boolean);
  } catch { return []; }
}
function setExtraAdminEmails(arr) {
  const dedup = [...new Set((arr || []).map(e => String(e || "").trim().toLowerCase()).filter(Boolean))]
    .filter(e => e !== OFFICIAL_ADMIN_EMAIL);
  localStorage.setItem(ADMIN_ALLOWLIST_KEY, JSON.stringify(dedup));
}
function isAllowedAdminEmail(email) {
  const e = (email || "").trim().toLowerCase();
  if (!e) return false;
  if (e === OFFICIAL_ADMIN_EMAIL) return true;
  return getExtraAdminEmails().includes(e);
}
// Super admin = OFFICIAL_ADMIN_EMAIL. Hanya super admin yang boleh kelola
// admin tambahan (buat/cabut). Admin tambahan punya akses penuh sisanya.
function isSuperAdmin(u) {
  return !!u && isOfficialAdminEmail(u.email);
}

// Ambil data akun admin (kalau sudah signup)
function getAdminAccount() {
  return JSON.parse(localStorage.getItem(`playly-account-${OFFICIAL_ADMIN_EMAIL}`) || "null");
}

// Sweep semua akun di localStorage & paksa role sesuai admin lock.
// Ini fix akun lama yang dibuat sebelum admin lock diaktifkan.
function enforceAdminLock() {
  let fixed = 0;
  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (!key || !key.startsWith("playly-account-")) continue;
    try {
      const acc = JSON.parse(localStorage.getItem(key));
      if (!acc?.email) continue;
      const correctRole = isAllowedAdminEmail(acc.email) ? "admin" : "user";
      if (acc.role !== correctRole) {
        acc.role = correctRole;
        localStorage.setItem(key, JSON.stringify(acc));
        fixed++;
      }
    } catch {}
  }
  // Sync current user kalau ada
  const cu = JSON.parse(localStorage.getItem("playly-user") || "null");
  if (cu?.email) {
    const correctRole = isAllowedAdminEmail(cu.email) ? "admin" : "user";
    if (cu.role !== correctRole) {
      cu.role = correctRole;
      localStorage.setItem("playly-user", JSON.stringify(cu));
      fixed++;
    }
  }
  return fixed;
}

// Hash password h2 yang precomputed (SHA-256 + salt fixed). Wajib didefinisikan
// SEBELUM seedOfficialAdmin() dipanggil di bawah — kalau di-deklarasikan
// belakangan, JS lempar ReferenceError "Cannot access before initialization"
// (temporal dead zone) → seluruh script.js mati & login form tidak ter-wire.
// Hex dihitung dari `SHA-256("playly-pwd-salt-v1" + plaintext)`. Hash baru tiap
// akun (h3, PBKDF2 + salt random) di-generate runtime di hashPassword().
const ADMIN_PASSWORD_HASH = "h2:dfdfe2b61ee03d58533ec9bde92cf702eed7429afaaf71cbe65f306763850c96";
const DEFAULT_RESET_PASSWORD_HASH = "h2:c319bf31c9a66a26eaa315c7e0ab2167208179442f21d40591675b0f30b316e1";

// Seed akun admin resmi. Dijalankan sekali saat script load.
// Akun ini wajib ada di dashboard supaya admin bisa langsung login.
function seedOfficialAdmin() {
  const key = `playly-account-${OFFICIAL_ADMIN_EMAIL}`;
  const existing = JSON.parse(localStorage.getItem(key) || "null");

  // Identitas (email, username, role) selalu dipaksa — tahan manipulasi localStorage
  // yang coba jadiin user lain admin atau coba ganti email/role admin.
  const identity = {
    name: existing?.name || "admin.playly",
    username: OFFICIAL_ADMIN_USERNAME,
    email: OFFICIAL_ADMIN_EMAIL,
    role: "admin",
    joinedAt: existing?.joinedAt || new Date().toISOString()
  };

  // Password handling:
  // - Belum pernah ada akun → seed dengan hash default (admin pakai password awal).
  // - Sudah ada hash di existing → JANGAN overwrite (admin sudah ganti password
  //   custom; kalau di-overwrite tiap reload, password change form jadi sia-sia).
  // - Plaintext lama "Adminplayly123" → migrasi ke hash supaya cloud-sync ke
  //   Supabase tidak nyimpen plaintext.
  // - Plaintext custom (admin sempat ganti password sebelum hashing aktif) →
  //   biarkan, akan di-migrate lazily saat login berhasil.
  let password;
  if (!existing || !existing.password) {
    password = ADMIN_PASSWORD_HASH;
  } else if (existing.password === "Adminplayly123") {
    password = ADMIN_PASSWORD_HASH;
  } else {
    password = existing.password;
  }

  const merged = { ...(existing || {}), ...identity, password };
  localStorage.setItem(key, JSON.stringify(merged));
}

// Run sekali saat script load — sebelum apapun
seedOfficialAdmin();
enforceAdminLock();

