// ----------------------- PURGE DEMO/MOCK USERS (selalu jalan) -----------------------
// Dashboard wajib 100% real-time — hanya akun yang benar-benar sign up yang boleh tampil.
// Versi lama pernah seed akun demo (`*.demo@playly.local`, `demo: true`) + state mereka.
// Karena cloud-sync re-pull dari Supabase tiap reload, purge HARUS jalan tiap load
// (jangan pakai one-time flag) sampai cloud benar-benar bersih.
const DEMO_EMAIL_DOMAIN = "@playly.local";
// Domain semua akun dummy lama (demo_creator + 5 kreator palsu seedDummyCreators).
// BUKAN email user asli — user sign up pakai email sendiri (gmail dst), admin
// pakai @gmail.com. Jadi @playly.dev aman 100% sebagai penanda purge.
const DUMMY_EMAIL_DOMAIN = "@playly.dev";
const KNOWN_DEMO_USERNAMES = ["citra_d", "rinaldi", "mahasari", "budikece", "andiwijaya", "nadiap"];
// Username dummy lama yang WAJIB ikut dibersihkan. Tanpa ini akun demo_creator
// + 5 kreator palsu lolos dari isDemoAccount() → cloud-sync resurrect terus dari
// Supabase tiap reload (bug user 2026-05-17: "Demo" masih muncul + auto-login
// tanpa halaman login). Seeding-nya sudah dimatikan; ini bersihin SISA-nya.
const DUMMY_USERNAMES = [
  "demo_creator",
  "aldoramadhan", "sasitirta", "rianpranata", "mayalestari", "aritechid",
];

function isDemoAccount(acc) {
  if (!acc) return false;
  if (acc.demo === true) return true;
  if (acc.isDummy === true) return true;            // marker akun dummy/demo
  if (typeof acc.email === "string") {
    const em = acc.email.toLowerCase();
    if (em.endsWith(DEMO_EMAIL_DOMAIN)) return true;  // *.@playly.local
    if (em.endsWith(DUMMY_EMAIL_DOMAIN)) return true; // demo@playly.dev, *.@playly.dev
  }
  if (typeof acc.username === "string") {
    const un = acc.username.toLowerCase();
    if (KNOWN_DEMO_USERNAMES.includes(un)) return true;
    if (DUMMY_USERNAMES.includes(un)) return true;
  }
  return false;
}

function purgeDemoData() {
  const accountKeys = [];
  const stateKeys = [];
  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (!key) continue;
    if (key.startsWith("playly-account-")) {
      try {
        const acc = JSON.parse(localStorage.getItem(key));
        if (isDemoAccount(acc)) accountKeys.push({ key, username: acc?.username });
      } catch {}
    } else if (key.startsWith("playly-state-")) {
      const uname = key.slice("playly-state-".length).toLowerCase();
      if (KNOWN_DEMO_USERNAMES.includes(uname)) stateKeys.push(key);
    }
  }
  for (const { key, username } of accountKeys) {
    localStorage.removeItem(key); // cloud-sync hijack ikut hapus dari Supabase
    if (username) localStorage.removeItem(`playly-state-${username}`);
  }
  for (const key of stateKeys) localStorage.removeItem(key);
  // Jaga-jaga: hapus flag seeder versi lama supaya tidak ada yang nyangkut.
  localStorage.removeItem("playly-demo-users-seeded-v1");
  localStorage.removeItem("playly-dummy-creators-seed-v");
  // FIX no-login (user 2026-05-17): kalau session marker `playly-user` masih
  // nunjuk ke akun demo/dummy yang barusan dipurge, hapus markernya supaya
  // tryAutoBoot() tidak auto-login sebagai "Demo" — user dipaksa ke halaman
  // login. (playly-user device-local, tidak di-sync; aman dihapus di sini.)
  try {
    const curRaw = localStorage.getItem("playly-user");
    if (curRaw) {
      const cur = JSON.parse(curRaw);
      if (isDemoAccount(cur)) localStorage.removeItem("playly-user");
    }
  } catch {}
  return accountKeys.length + stateKeys.length;
}
purgeDemoData();
// Jalankan lagi setelah cloud-sync apply data dari Supabase (re-pull bisa bawa balik
// kalau cloud-delete sebelumnya belum sampai). Loop akan berhenti sendiri begitu
// cloud bersih.
window.addEventListener("playly:cloud-applied", () => { purgeDemoData(); });

// ----------------------- PERMANENT ACCOUNT BAN — TIME CUTOFF + EMAIL LIST -----------------------
// User minta wipe total semua akun lama (2026-05-09). Cloud-sync re-pull bisa
// bawa balik akun yang sudah dihapus. Dua mekanisme defense:
//   1. CUTOFF_TS — timestamp set sekali. Akun apa pun (non-admin) dengan
//      `joinedAt < cutoff` ATAU `joinedAt` missing → ban. Race-proof: nggak
//      perlu nunggu cloud-applied karena filter pakai timestamp di tiap acc.
//   2. BANNED_EMAILS — ban list email persistent. Filled tiap kali ada acc
//      yang kena cutoff (idempotent). Defense extra kalau acc dimodifikasi
//      joinedAt-nya di cloud (clock skew, dst).
// New signup (joinedAt > cutoff, email belum dibanned) tetap jalan normal.
// B6c (2026-05-25): rename system key ke namespace `playly-syskey-*`
// supaya `playly-account-*` 100% milik user accounts (suffix @email).
// Ini unblock B6a-4 (drop kv_anon_all) — semua `playly-account-*` jelas
// per-user, bisa di-stamp user_id via /api/kv/sync tanpa false positive.
//
// CUTOFF_TS_KEY = "playly-account-cutoff-ts-v1" → "playly-syskey-account-cutoff-ts-v1"
// Migration: read fallback dari old key (one-shot transfer + delete old).
const CUTOFF_TS_KEY = "playly-syskey-account-cutoff-ts-v1";
const CUTOFF_TS_KEY_LEGACY = "playly-account-cutoff-ts-v1";
const BANNED_EMAILS_KEY = "playly-banned-emails-v1";
// v543 (2026-05-25): admin.playly2 di-remove — bukan real admin, sisa test
// data. Cuma 1 admin resmi: admin.playly@gmail.com.
const ADMIN_EMAILS_PROTECTED = ["admin.playly@gmail.com"];

// One-shot migrate dari legacy key. Idempotent — flag set setelah jalan.
(function migrateCutoffKey() {
  try {
    if (localStorage.getItem("playly-syskey-migrate-cutoff-v1") === "1") return;
    const legacy = localStorage.getItem(CUTOFF_TS_KEY_LEGACY);
    if (legacy && !localStorage.getItem(CUTOFF_TS_KEY)) {
      localStorage.setItem(CUTOFF_TS_KEY, legacy);
    }
    if (legacy !== null) {
      localStorage.removeItem(CUTOFF_TS_KEY_LEGACY); // cleanup
    }
    localStorage.setItem("playly-syskey-migrate-cutoff-v1", "1");
  } catch (err) { console.warn("[migrateCutoffKey] failed:", err); }
})();

function getAccountCutoff() {
  // v541: read dari key baru, fallback ke legacy untuk safety (cross-device
  // sync mungkin masih ada legacy row di cloud kv sebelum cleanup).
  let raw = localStorage.getItem(CUTOFF_TS_KEY);
  if (!raw) raw = localStorage.getItem(CUTOFF_TS_KEY_LEGACY);
  return raw ? Number(raw) : 0;
}
function ensureAccountCutoff() {
  if (!getAccountCutoff()) {
    localStorage.setItem(CUTOFF_TS_KEY, String(Date.now()));
  }
}
function getBannedEmails() {
  try {
    const arr = JSON.parse(localStorage.getItem(BANNED_EMAILS_KEY) || "[]");
    return new Set(arr.map(e => (e || "").toLowerCase()));
  } catch { return new Set(); }
}
function addBannedEmails(emails) {
  const set = getBannedEmails();
  let changed = false;
  emails.forEach(e => {
    if (!e) return;
    const lo = String(e).toLowerCase();
    if (ADMIN_EMAILS_PROTECTED.includes(lo)) return;
    if (!set.has(lo)) { set.add(lo); changed = true; }
  });
  if (changed) localStorage.setItem(BANNED_EMAILS_KEY, JSON.stringify([...set]));
}
function isEmailBanned(email) {
  if (!email) return false;
  return getBannedEmails().has(String(email).toLowerCase());
}
// Hapus email dari banned list — dipanggil saat admin create user dengan
// email yang sebelumnya pernah dibanned (admin authoritative — kalau admin
// approve email ini buat akun baru, ban-nya cabut).
function removeBannedEmail(email) {
  if (!email) return false;
  const set = getBannedEmails();
  const lo = String(email).toLowerCase();
  if (!set.has(lo)) return false;
  set.delete(lo);
  localStorage.setItem(BANNED_EMAILS_KEY, JSON.stringify([...set]));
  return true;
}
// Cek apakah suatu acc harus dibanned. Test order: admin protect → BAN LIST →
// adminCreated exemption → joinedAt cutoff. Acc tanpa joinedAt valid dianggap "lama".
//
// FIX 2026-05-11: ban list check WAJIB sebelum adminCreated exemption. Sebelumnya
// reverse — bikin akun lama yg punya flag `adminCreated:true` lolos ban list (kasus
// `aisyahmaimunah` yg user explicit minta hapus permanent tapi resurrect terus
// karena exemption `adminCreated` skip ban list check).
function shouldBanAccount(acc) {
  if (!acc?.email) return false;
  const email = String(acc.email).toLowerCase();
  if (ADMIN_EMAILS_PROTECTED.includes(email)) return false;
  if (acc.role === "admin" || isOfficialAdminEmail?.(email)) return false;
  // PERMANENT PROTECTION (per fix user 2026-05-15 v15+): Flag `userRegistered` ditandai
  // saat user EXPLICITLY register via signup form. Akun ini di-protect dari auto-ban
  // selamanya — data terupgrade, bukan resurrected dari cloud. User authoritative.
  if (acc.userRegistered === true) return false;
  // GRACE WINDOW: akun fresh dalam 24 jam terakhir tidak di-ban (safety net untuk
  // akun lama yang belum punya flag userRegistered).
  const joinedT = acc.joinedAt ? Date.parse(acc.joinedAt) : NaN;
  if (Number.isFinite(joinedT) && (Date.now() - joinedT) < 24 * 3600 * 1000) {
    return false;
  }
  // Ban list ALWAYS wins (untuk akun lama tanpa flag) — explicit ban defeat
  // adminCreated. User authoritative di atas admin: kalau email udah di-ban, gak
  // peduli admin pernah create akun dgn email itu, harus tetap di-ban.
  if (isEmailBanned(email)) return true;
  // Akun yg dibuat admin via panel "Buat Akun" lolos auto-ban via cutoff: admin
  // authoritative, akun intentionally fresh. Cuma untuk cutoff timestamp check.
  if (acc.adminCreated === true) return false;
  const cutoff = getAccountCutoff();
  if (!cutoff) return false;
  if (!Number.isFinite(joinedT)) return true;
  return joinedT < cutoff;
}

// Per-user keys yang wajib di-purge bersama account (cloud-sync hijack ikut delete).
const PER_USER_KEY_PREFIXES = [
  "playly-state-", "playly-prefs-", "playly-welcomed-", "playly-welcome-",
  "playly-onboarding-", "playly-notif-", "playly-2fa-",
  "playly-videos-", "playly-followers-", "playly-following-",
  "playly-history-", "playly-trash-", "playly-downloads-",
  "playly-status-", "playly-pinned-",
];
function purgeUserDataByUsername(username) {
  if (!username) return;
  const u = String(username).toLowerCase();
  PER_USER_KEY_PREFIXES.forEach(p => {
    try { localStorage.removeItem(p + u); } catch {}
    try { localStorage.removeItem(p + username); } catch {}
  });
}

// Scan semua acc, hapus yang harus dibanned (cutoff atau ban list). Dipanggil
// tiap load dan tiap cloud-applied — tangkap acc yang resurrect dari Supabase.
function enforceAccountBan() {
  ensureAccountCutoff();
  const toDelete = [];
  const newBans = [];
  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (!key || !key.startsWith("playly-account-")) continue;
    const emailFromKey = key.slice("playly-account-".length).toLowerCase();
    if (ADMIN_EMAILS_PROTECTED.includes(emailFromKey)) continue;
    let acc = null;
    try { acc = JSON.parse(localStorage.getItem(key) || "null"); } catch {}
    // Pakai email dari key kalau acc rusak — tetap bisa ban berdasarkan key
    const accForCheck = acc || { email: emailFromKey };
    if (!shouldBanAccount(accForCheck)) continue;
    toDelete.push({ key, username: acc?.username, email: emailFromKey });
    newBans.push(emailFromKey);
  }
  if (newBans.length) addBannedEmails(newBans);
  toDelete.forEach(({ key, username }) => {
    try { localStorage.removeItem(key); } catch {}
    if (username) purgeUserDataByUsername(username);
  });
  return toDelete.length;
}

// Initial setup: set cutoff (sekali), bersihkan platform aggregates yang
// nyangkut akun lama, lalu enforce.
ensureAccountCutoff();
const PLATFORM_RESET_FLAG = "playly-platform-reset-2026-05-09-v1";
if (!localStorage.getItem(PLATFORM_RESET_FLAG)) {
  try { localStorage.setItem("playly-premium-payments", "[]"); } catch {}
  ["playly-platform-videos", "playly-platform-comments", "playly-platform-likes",
   "playly-platform-views", "playly-takedowns", "playly-pending-videos"]
    .forEach(k => { try { localStorage.removeItem(k); } catch {} });
  localStorage.setItem(PLATFORM_RESET_FLAG, String(Date.now()));
}
// One-time hard purge 2026-05-11: user explicit request — semua akun user
// non-admin (termasuk yang `adminCreated:true`) yang tersisa wajib dihapus
// karena dianggap residue dari sesi lama. Cuma akun super admin & backup
// admin yang protected. Bump cutoff ke now juga supaya cloud-resurrect
// kena ban-list defense.
//
// v2 (2026-05-11 round 2): user lapor `aisyahmaimunah` masih muncul setelah
// migrasi v1. Penyebab: `shouldBanAccount` lama check `adminCreated` exemption
// SEBELUM ban list, jadi cloud-resurrect dgn `adminCreated:true` lolos ban.
// Fix sudah applied di shouldBanAccount; bump flag ke v2 supaya migrasi
// re-run dgn logic baru.
//
// v3 (2026-05-11 round 3): user lapor video lama @userbaru1 masih muncul di
// Kontrol Konten. Penyebab: platform-videos aggregate persist terpisah dari
// per-user state. Fix: filter aggregate by purgedUsernames.
//
// v4 (2026-05-11 round 4): user lapor MASIH ada video setelah v3. Penyebab:
// filter v3 cuma drop entries owned by usernames yg dipurge dlm session yg
// sama. Kalau video udah ke-orphan dari banned email atau ke-resurrect dari
// cloud dgn owner tidak match purged list, dia lolos. Fix: WIPE TOTAL semua
// platform aggregate jadi `[]` (bukan filter). Plus wipe per-username video
// keys `playly-videos-*`. Admin authoritative — kalau user real punya video
// hilang, mereka tinggal upload ulang. Cleaner state > selectiveness.
// v5 (2026-05-11 round 5): user lapor masih ada @userbaru1 di Aktivitas User
// Live + Video Berkinerja Terbaik + Kreator Teratas walaupun Total Pengguna=0.
// Penyebab: `getPlatformVideos()` baca dari `playly-state-{username}.myVideos`
// (per-user state) BUKAN dari aggregate. v4 cuma wipe aggregate. Plus cloud-
// sync resurrect `playly-state-*` kembali setelah migration. Fix v5:
// 1. Wipe SEMUA `playly-state-*` keys (kecuali admin) di migration
// 2. Defense di `enforceAccountBan` — purge orphan state keys (username yg
//    tidak punya valid account record)
// 3. Clear current admin user's state.activities supaya feed bersih
// v7 (2026-05-11 round 7): user lapor @aisyahmaimunah dan akun user lama
// LAIN masih muncul di Manajemen User. Root cause: v6 cuma wipe localStorage,
// tapi cloud-sync `bidirectionalSync` re-pull dari Supabase setelah migration
// → row resurrect. `enforceAccountBan` localStorage-only, gak hapus dari cloud.
// Fix v7: panggil `cloudSync.wipeUserKeys(adminEmails)` async untuk DELETE
// dari Supabase cloud DIRECTLY (bulk via `like` filter). Cloud + local kedua-
// duanya bersih, jadi resurrect impossible.
const HARD_PURGE_FLAG_2026_05_11 = "playly-hard-purge-users-2026-05-11-v7";
if (!localStorage.getItem(HARD_PURGE_FLAG_2026_05_11)) {
  // Cleanup flag v1-v6 supaya tidak tersisa (idempotent)
  try { localStorage.removeItem("playly-hard-purge-users-2026-05-11-v1"); } catch {}
  try { localStorage.removeItem("playly-hard-purge-users-2026-05-11-v2"); } catch {}
  try { localStorage.removeItem("playly-hard-purge-users-2026-05-11-v3"); } catch {}
  try { localStorage.removeItem("playly-hard-purge-users-2026-05-11-v4"); } catch {}
  try { localStorage.removeItem("playly-hard-purge-users-2026-05-11-v5"); } catch {}
  try { localStorage.removeItem("playly-hard-purge-users-2026-05-11-v6"); } catch {}

  // Step 1: Kumpulin daftar username admin (PROTECTED — state-nya jangan dihapus)
  const protectedUsernames = new Set();
  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (!key || !key.startsWith("playly-account-")) continue;
    const emailFromKey = key.slice("playly-account-".length).toLowerCase();
    if (ADMIN_EMAILS_PROTECTED.includes(emailFromKey)) {
      try {
        const acc = JSON.parse(localStorage.getItem(key) || "null");
        if (acc?.username) protectedUsernames.add(String(acc.username).toLowerCase());
      } catch {}
    }
  }

  // Step 2: Banned & purge semua non-admin accounts
  const purgedEmails = [];
  const purgedUsernames = [];
  for (let i = localStorage.length - 1; i >= 0; i--) {
    const key = localStorage.key(i);
    if (!key || !key.startsWith("playly-account-")) continue;
    const emailFromKey = key.slice("playly-account-".length).toLowerCase();
    if (ADMIN_EMAILS_PROTECTED.includes(emailFromKey)) continue;
    let acc = null;
    try { acc = JSON.parse(localStorage.getItem(key) || "null"); } catch {}
    if (acc?.role === "admin") {
      if (acc?.username) protectedUsernames.add(String(acc.username).toLowerCase());
      continue;
    }
    if (typeof isOfficialAdminEmail === "function" && isOfficialAdminEmail(emailFromKey)) {
      if (acc?.username) protectedUsernames.add(String(acc.username).toLowerCase());
      continue;
    }
    try { localStorage.removeItem(key); } catch {}
    if (acc?.username) {
      purgedUsernames.push(String(acc.username).toLowerCase());
      if (typeof purgeUserDataByUsername === "function") {
        purgeUserDataByUsername(acc.username);
      }
    }
    purgedEmails.push(emailFromKey);
  }
  if (purgedEmails.length) addBannedEmails(purgedEmails);

  // Step 3: WIPE SEMUA per-user state keys yang BUKAN milik admin.
  // Inilah fix utama v5: getPlatformVideos baca dari playly-state-*, jadi
  // residue dari purged user di state-nya bikin video lama tetap muncul.
  try {
    const PURGE_PREFIXES = [
      "playly-state-", "playly-prefs-", "playly-welcomed-", "playly-welcome-",
      "playly-onboarding-", "playly-notif-", "playly-2fa-",
      "playly-videos-", "playly-followers-", "playly-following-",
      "playly-history-", "playly-trash-", "playly-downloads-",
      "playly-status-", "playly-pinned-",
    ];
    for (let i = localStorage.length - 1; i >= 0; i--) {
      const key = localStorage.key(i);
      if (!key) continue;
      for (const prefix of PURGE_PREFIXES) {
        if (key.startsWith(prefix)) {
          const uname = key.slice(prefix.length).toLowerCase();
          // JANGAN hapus state milik admin protected
          if (protectedUsernames.has(uname)) break;
          try { localStorage.removeItem(key); } catch {}
          break;
        }
      }
    }
  } catch {}

  // Step 4: WIPE TOTAL platform aggregates jadi `[]`
  try {
    [
      "playly-platform-videos",
      "playly-platform-comments",
      "playly-platform-likes",
      "playly-platform-views",
      "playly-takedowns",
      "playly-pending-videos",
      "playly-trash-videos",
    ].forEach(k => { try { localStorage.setItem(k, "[]"); } catch {} });

    // IndexedDB `playly-videos` blob store — delete fire-and-forget
    if (typeof clearAllVideoBlobs === "function") {
      try { clearAllVideoBlobs(); } catch {}
    } else if (typeof indexedDB !== "undefined") {
      try {
        const req = indexedDB.deleteDatabase("playly-videos");
        req.onerror = () => {};
        req.onsuccess = () => {};
      } catch {}
    }
  } catch {}

  // Step 5: Clear current admin user's state.activities (feed in-memory residue)
  try {
    for (const uname of protectedUsernames) {
      const stateKey = `playly-state-${uname}`;
      const raw = localStorage.getItem(stateKey);
      if (!raw) continue;
      const s = JSON.parse(raw);
      if (s) {
        s.activities = [];
        s.notifications = [];
        s.history = [];
        s.liked = [];
        s.saved = [];
        s.downloaded = [];
        localStorage.setItem(stateKey, JSON.stringify(s));
      }
    }
  } catch {}

  // Reset cutoff ke "now" supaya akun apapun yang resurrect dari cloud dgn
  // joinedAt < now ikut kena ban.
  try { localStorage.setItem(CUTOFF_TS_KEY, String(Date.now())); } catch {}

  // v6: force sign-out current non-admin session — user lapor masih login
  // sbg @iniakunbaru meskipun account record udah dipurge. Hapus marker
  // playly-user kalau email-nya bukan admin protected.
  try {
    const curRaw = localStorage.getItem("playly-user");
    if (curRaw) {
      const cur = JSON.parse(curRaw);
      const curEmail = String(cur?.email || "").toLowerCase();
      const isAdmin = ADMIN_EMAILS_PROTECTED.includes(curEmail)
        || (typeof isOfficialAdminEmail === "function" && isOfficialAdminEmail(curEmail));
      if (!isAdmin) {
        localStorage.removeItem("playly-user");
      }
    }
  } catch {}

  // v7: DELETE dari Supabase cloud kv table — fix utama. localStorage wipe
  // saja tidak cukup karena bidirectionalSync re-pull. Cloud delete bulk via
  // `cloudSync.wipeUserKeys(adminEmails)` (defined di cloud-sync.js ~354).
  // Fire-and-forget — kalau cloudSync gak ready, fallback OK karena flag set
  // mencegah re-run, plus enforceAccountBan + purgeOrphanStates run di
  // cloud-applied event yang fires setelah resurrect.
  try {
    if (window.cloudSync && typeof window.cloudSync.wipeUserKeys === "function") {
      window.cloudSync.wipeUserKeys(ADMIN_EMAILS_PROTECTED)
        .then(res => {
          if (res?.ok) {
            console.log("[hard-purge v7] cloud wipe OK, accounts deleted:", res.accountsDeleted);
          } else {
            console.warn("[hard-purge v7] cloud wipe skipped:", res?.reason);
          }
        })
        .catch(err => console.warn("[hard-purge v7] cloud wipe error:", err));
    } else {
      console.warn("[hard-purge v7] cloudSync.wipeUserKeys not available — cloud delete skipped, but local wipe done");
    }
  } catch (err) {
    console.warn("[hard-purge v7] cloud wipe exception:", err);
  }

  console.log("[hard-purge v7] migration done. Purged emails:", purgedEmails);
  localStorage.setItem(HARD_PURGE_FLAG_2026_05_11, String(Date.now()));
}

// Defense: setiap cloud-applied, scan orphan playly-state-* keys (username
// tanpa valid account record) → purge. Cegah cloud-sync resurrect data
// user lama yang sudah dibanned.
function purgeOrphanStates() {
  try {
    // Build map username → has-valid-account
    const validUsernames = new Set();
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (!key || !key.startsWith("playly-account-")) continue;
      try {
        const acc = JSON.parse(localStorage.getItem(key) || "null");
        if (acc?.username) validUsernames.add(String(acc.username).toLowerCase());
      } catch {}
    }
    // Scan state-* keys; orphan = username tidak ada di validUsernames
    for (let i = localStorage.length - 1; i >= 0; i--) {
      const key = localStorage.key(i);
      if (!key || !key.startsWith("playly-state-")) continue;
      const uname = key.slice("playly-state-".length).toLowerCase();
      // Orphan = state tanpa account record valid → purge (termasuk state
      // demo/dummy: pengecualian KNOWN_DEMO_USERNAMES dihapus per fix user
      // 2026-05-17 supaya sisa state demo tidak nyangkut).
      if (!validUsernames.has(uname)) {
        try { localStorage.removeItem(key); } catch {}
      }
    }
  } catch {}
}

