    "lp.trust.eyebrow":           "SECURITY & ACCESS",
    "lp.trust.title":             "Built for trust, monitored end-to-end",
    "lp.trust.subtitle":          "Admin access is restricted, every action is logged, and elevated changes require an extra step.",
    "lp.trust.preseed.title":     "Pre-seeded admin accounts",
    "lp.trust.provision":         "Admin credentials are provisioned, never created via public sign-up. Regular sign-up cannot reach the admin panel.",
    "lp.trust.2fa.title":         "Two-factor authentication",
    "lp.trust.2fa.desc":          "TOTP-based 2FA is required for super-admin actions. Codes verified in 30-second windows; lockout on repeated failures.",
    "lp.trust.role.title":        "Role-based permissions",
    "lp.trust.role.desc":         "Super-admin, admin, and moderator scopes with strict boundaries. Sensitive panels require the higher role.",
    "lp.trust.audit.title":       "Tamper-evident audit log",
    "lp.trust.audit.desc":        "Every suspend, takedown, role change, broadcast, and login is timestamped and attributed. Exportable for review.",
    "lp.trust.lock.title":        "Session lockout",
    "lp.trust.lock.desc":         "Failed login attempts trigger a temporary cooldown. Repeated failures escalate to a longer lock with notification.",
    "lp.trust.enc.title":         "Encrypted at rest & in transit",
    "lp.trust.enc.desc":          "All admin sessions, audit entries, and user data are encrypted. No plaintext secrets ever leave the platform.",
    // Security card flip-back content (caption + sub)
