    // i18n meddling.
    ".auth-topbar-brand", ".auth-topbar-name", ".auth-topbar-suffix",
    ".brand-text", ".brand-name",
    // Breadcrumb — sudah di-translate via trCrumb + t(key) di updateBreadcrumb.
    // Tree-walker jangan re-translate; bisa corrupt teks yang sudah benar.
    ".breadcrumb", ".breadcrumb a",
    // Auth topbar nav links — anchor ke section (Modules/Preview/Security/dll),
    // bukan content yang perlu di-translate.
    ".auth-topbar-nav", ".auth-topbar-link",
    // User dashboard topbar home nav (Beranda/Notifikasi/Insights) — section
