    // "settings.notifications" = "🔔 Notifikasi" → bocor emoji prefix).
    ".topbar-home-nav", ".topbar-home-nav .thn-link",
    // Sidebar nav text — jangan auto-translate ke value yang punya emoji
    // prefix (cth: "search.title" = "👥 Search User"). Nav text harus tetap
    // plain text saja, sesuai aturan logo-only di sidebar.
    ".sidebar .nav-item",
    ".sidebar .nav-item span",
    ".sidebar .nav-subitem",
    ".sidebar-footer .footer-link",
    ".sidebar .brand-text",
    // Login hero animated dashboard preview — semua text di dalam frame
    // adalah marketing mockup, jangan di-translate (cth: "Library" jangan
    // jadi "LIBRARY" karena dict reverse-map ke section-label key).
    ".auth-preview-frame",
    ".auth-preview-screen",
    ".lib-meta strong",          // video title (user content)
    ".lib-thumb-dur",            // duration "0:23"
    ".storage-file-info strong", // user video title di Storage page (jangan
                                 // translate "Download" → "Unduhan" dst)
    ".storage-file-info small",  // file size + view count
    ".storage-file-row",         // defense-in-depth: skip whole row
    ".dm-bubble-text",           // chat content
    ".dm-thread-info strong",    // chat username
    ".dm-thread-preview",        // chat preview
    ".dm-thread-time",
    ".dm-bubble-time",
    ".chat-body",                // chat history content
    ".video-title",
    ".comment-text", ".author",
    ".user-name", ".creator-name", ".people-name",
    ".people-handle", ".people-bio",
    ".cs-info h4", ".cs-info .uname",  // creator name di spotlight
    ".profile-header-name",
    ".profile-header-handle",
    ".profile-header-bio",
    ".myprofile-handle",
    ".user-email-subject",
    ".user-email-preview",
    ".activity-text",
    ".history-item h5",
    ".history-item .meta",
    ".continue-card h5",
    ".continue-card .meta",
    ".trending-info strong",     // hashtag content
    ".trending-info small",
    ".lib-inline-title",
    ".lib-inline-desc",
    ".bubble-video-info strong",
    ".bubble-video-info small",
    ".cs-top-vid-meta strong",   // video title
    ".cs-top-vid-meta small",    // view count text
    ".time", ".time-ago",        // timestamps
    ".badge", ".dot",            // numeric badges
    ".hs-info strong",           // stat numbers
    ".hc-update-info strong",
    ".myprofile-stat b",
    ".profile-header-stats b",
    ".lib-count",
    ".lib-thumb-fallback",
    ".dm-tab-count",
    ".dm-sub-badge",
    ".cs-counter",
    ".cs-info .stats b",         // numeric stats
    ".mini-chart-total",
    ".chart-tooltip",
    "#userLocalTimePreview",
    "#liveTime", "#heroDate",
    "#hsLastUpdate",
    "[data-no-i18n]",
    // Skip elements with explicit data-i18n — applyI18n() sudah handle mereka.
    // Tanpa ini, deep walker bisa re-translate dgn reverse-map yg first-wins
    // ke key lain (cth: "HAPUS" → "word.delete" → "Hapus" alih2 stay di
    // explicit key "lp.preview.badge.takedown" = "HAPUS"). Per fix 2026-05-20.
    "[data-i18n]",
    /* 2026-06-17: jangan translate highlight <mark> & teks translate="no" (fix a->Ke di hasil search) */
    "mark",
