// utama yang visible di UI (sidebar, page header, button, dll). Jangan terlalu
// lebar — bisa accidentally translate konten user-generated atau dynamic data.
const I18N_AUTO_SELECTORS = [
  ".nav-item > span",          // Sidebar nav-item label
  ".nav-subitem",              // Sidebar sub-item
  ".nav-label",                // Section header (MAIN/LIBRARY/SOCIAL)
  ".view-header h2",           // Page title (h2 wrapper)
  ".view-header h2 > span",    // Page title (jika ada inner span data-i18n)
  ".view-header > div > p",    // Page description
  ".admin-section-divider span",// Section divider
  ".footer-link",              // Settings, Help di sidebar footer
  ".storage-info small",       // Storage usage label
  ".btn[data-jump]",           // Jump buttons
  "#newChat",                  // + Pesan Baru button
  ".dm-tab",                   // DM tab
  ".hs-info small",            // Stats card labels (Total Video, etc)
  ".hc-update-info small",     // Hero clock stats (Total Video/Views/Likes)
  ".hc-status-line span:last-child", // System healthy text
  ".myprofile-stat small",     // Profile stat labels
  ".myprofile-section-head h3",// Profile section headers
  ".profile-header-stats small",
  ".tog > span",               // Settings toggle labels
  ".card > h3",                // Card section titles (Settings)
  ".card-head h3",             // Card head titles (My Library sections)
  ".card-head small",          // Card head sub-labels
  ".lib-thumb-status",         // Pending/Takedown badges
  ".status-sub-tab",           // Status video tabs
  ".people-card .people-handle .people-followers", // People follower count text
  ".cs-info .stats span",      // Spotlight stats spans (video/views/followers/likes)
  ".cs-top-videos-label",      // Top Videos label di spotlight
  ".trending-title h3",        // Trending heading
  ".activity-list .chip-tabs button", // Activity filter tabs
  ".chip-tabs button",         // Other chip tabs (chart range, etc)
  ".chart-card h3",            // Chart card titles
  ".chart-card p",             // Chart card desc
  ".mini-chart-title h4",      // Mini chart titles (Grafik Stats Video/Views/Followers)
  ".dropzone .dz-icon + p > b", // Upload "Pilih video" b
  ".dropzone p",               // Upload dropzone text
  ".dropzone small",           // Upload max size hint
  ".upload-form > label",      // Upload form labels (Judul/Deskripsi/Visibility)
  ".upload-actions-btns .btn", // Upload action buttons (Batal/Upload Sekarang)
  ".lock-banner b",            // Various banner labels
  ".dm-chat-empty h3",         // DM empty state heading
  ".dm-chat-input input",      // (placeholder handled separately)
  ".dm-chat-input .btn",       // Kirim button
  ".dm-side-list .dm-list-empty", // DM empty list
  ".help-section-title",       // Help center section titles
  ".help-q",                   // Help questions
  ".trending-chip",            // Trending tag chips
];

// Regex untuk strip emoji prefix di awal text — dipakai untuk sanitize
// label sidebar (logo brand only, no emoji per request user).
const EMOJI_PREFIX_RE = /^[\s\u{1F300}-\u{1FAFF}\u{2600}-\u{27BF}\u{2190}-\u{21FF}\u{2300}-\u{23FF}\u{2B00}-\u{2BFF}\u{FE0F}\u{200D}]+/gu;

function autoTranslateByText() {
  if (!__i18nReverse) __i18nReverse = buildI18nReverseMap();
  I18N_AUTO_SELECTORS.forEach(sel => {
    document.querySelectorAll(sel).forEach(el => {
      // Skip kalau element punya child element (struktur kompleks). Cuma element
      // dengan pure text content (atau text + 1-2 simple inline) yang aman.
      // SVG dimasukkan ke skip list — kalau ada svg child (cth: .footer-link
      // Settings/Help dengan icon), JANGAN replace textContent karena bakal
      // wipe svg icon-nya. Kasus ini di-handle via text-node replacement di
      // bawah, bukan textContent assignment.
      if (el.querySelector("button, input, select, textarea, span, b, i")) return;
      // Kalau sudah ada data-i18n explicit → skip (handled di loop utama)
      if (el.hasAttribute("data-i18n")) return;
      const txt = el.textContent.trim();
      if (!txt) return;
      // Cari key dari ORIGINAL English text. Simpan original di data-orig-text
      // supaya bisa retranslate kalau user ganti bahasa lagi nanti.
      let originalText;
      if (el.dataset.origText) {
        originalText = el.dataset.origText;
      } else {
        originalText = txt;
        el.dataset.origText = txt;
      }
      const key = __i18nReverse[originalText] || __i18nReverse[originalText.replace(/^[^\w(]+/, "").trim()];
      if (!key) return;
      let translated = t(key);
      // Sidebar nav text & footer-link: strip emoji prefix (logo only, no emoji
      // di sidebar per request user). Detect via closest match ke selector
      // sidebar — kalau element ada di dalam .sidebar atau .sidebar-footer,
      // bersihkan emoji prefix dari hasil translate.
      if (translated && (el.closest(".sidebar, .sidebar-footer") || el.querySelector(".ui-ico"))) {
        // 2026-06-17: kalau elemen SUDAH punya ikon hasil konversi emoji, JANGAN
        // ikut sertakan emoji dari nilai terjemahan (mis. "✓ Mengikuti") — kalau
        // tidak, tiap siklus i18n menambah ikon baru (centang menumpuk).
        translated = translated.replace(EMOJI_PREFIX_RE, "").trim();
      }
      if (translated && translated !== txt) {
        // Replace ONLY direct text node, JANGAN textContent assignment —
        // textContent wipe semua child element (cth: svg icon di
        // .footer-link Settings/Help). Cari text node terbesar (yang punya
        // label utama), preserve leading/trailing whitespace, replace.
        const textNodes = Array.from(el.childNodes).filter(n => n.nodeType === 3 && n.textContent.trim());
        if (textNodes.length >= 1) {
          const tn = textNodes.reduce((a, b) => b.textContent.trim().length > a.textContent.trim().length ? b : a);
          const lead = tn.textContent.match(/^\s*/)[0];
          const trail = tn.textContent.match(/\s*$/)[0];
          tn.textContent = lead + translated + trail;
        } else {
          el.textContent = translated; // fallback kalau tidak ada text node
        }
      }
    });
  });
}

// Walk DOM, translate elements with [data-i18n="key"] → replace direct text
// content + auto-translate by text matching untuk elemen yang tidak punya
// data-i18n attribute.
function applyI18n(lang) {
  if (lang) {
    // Sync select dropdowns
    document.querySelectorAll('[data-pref="lang"]').forEach(s => { if (s.value !== lang) s.value = lang; });
  }
  document.querySelectorAll("[data-i18n]").forEach(el => {
    const key = el.dataset.i18n;
    if (!key) return;
    const val = t(key);
    // Untuk <label>, isi child input sering ada — hanya update first text node
    const firstTextNode = Array.from(el.childNodes).find(n => n.nodeType === 3 && n.textContent.trim());
    if (firstTextNode) {
      firstTextNode.textContent = val + " ";
    } else if (!el.querySelector("input,select,textarea,button,svg")) {
      el.textContent = val;
    }
  });
  // v530 (2026-05-25) — support data-i18n-placeholder untuk input/textarea
  document.querySelectorAll("[data-i18n-placeholder]").forEach(el => {
    const key = el.dataset.i18nPlaceholder;
    if (!key) return;
    const val = t(key);
    if (val) el.setAttribute("placeholder", val);
  });
  // Sanitize sidebar nav items — strip emoji prefix yang mungkin sudah
  // di-inject oleh deep walker run sebelumnya. Sidebar harus text-only sesuai
  // request user (logo-only, no character emoji). Pakai regex: hapus emoji +
  // surrogate pair + variation selector di awal text, lalu trim.
  document.querySelectorAll(
    ".sidebar .nav-item > span:not(.badge):not(.nav-toggle), " +
    ".sidebar .nav-subitem, " +
    ".sidebar-footer .footer-link"
  ).forEach(el => {
    // Walk hanya direct text nodes (skip nested icon span / badge / svg / button)
    el.childNodes.forEach(n => {
      if (n.nodeType !== 3) return;
      const orig = n.textContent;
      // Emoji range: surrogate pairs U+1F300-1FAFF + variation selector U+FE0F + ZWJ U+200D
      const cleaned = orig.replace(/^[\s\u{1F300}-\u{1FAFF}\u{2600}-\u{27BF}\u{FE0F}\u{200D}]+/gu, "").trim();
      if (cleaned !== orig.trim()) n.textContent = cleaned;
    });
  });
  // Auto-translate berdasarkan text content (selector-based + deep walker)
  try { autoTranslateByText(); } catch (err) { console.warn("[i18n] auto-translate:", err); }
  // Deep walker — scan SELURUH document.body. Skip zone (user content, dll)
  // di-handle via SKIP_SELECTORS di dalam deepTranslateTextNodes. Pakai
  // body sebagai root supaya catch semua: sidebar, main, auth-screen,
  // floating panels, modals, tooltips, dll.
  try {
    if (document.body) deepTranslateTextNodes(document.body);
    // Translate placeholder + title + optgroup label attributes
    translatePlaceholders();
  } catch (err) { console.warn("[i18n] deep translate:", err); }
  document.documentElement.setAttribute("lang", currentLang());
  document.documentElement.setAttribute("dir", currentLang() === "ar" ? "rtl" : "ltr");
  // Set body.dataset.lang juga supaya helper format tanggal/Intl pakai locale benar
  if (document.body) document.body.dataset.lang = currentLang();
  // 2026-06-17: i18n re-set teks via textContent (bisa mengandung emoji spt "→")
  // → tidak terpantau observer (characterData). Konversi ulang emoji UI -> ikon.
  try {
    if (typeof convertUiEmojis === "function" && document.body && document.body.dataset.role !== "admin") {
      convertUiEmojis(document.body);
    }
  } catch (e) {}
}

// Apply i18n saat load awal — default Bahasa Indonesia untuk new user.
// Per user request 2026-05-06: kalau guest lang belum di-set, paksa "id"
// supaya page load pertama langsung dalam bahasa ID (bukan English raw HTML).
// User bisa ganti ke English / bahasa lain via Settings → Language.
window.addEventListener("DOMContentLoaded", () => {
  try {
    if (!localStorage.getItem("playly-guest-lang")) {
      localStorage.setItem("playly-guest-lang", "id");
    }
  } catch {}
  setTimeout(() => { try { applyI18n(currentLang()); } catch {} }, 100);
});

// Re-apply i18n setiap kali user pindah view atau ada re-render
// (page title bisa ke-overwrite oleh JS render functions). Throttle 60ms.
let __i18nReapplyTimer = null;
window.addEventListener("playly:view-changed", () => {
  if (__i18nReapplyTimer) return;
  __i18nReapplyTimer = setTimeout(() => {
    __i18nReapplyTimer = null;
    try { applyI18n(currentLang()); } catch {}
  }, 80);
});

// Periodic re-apply — setiap kali user pindah view, dispatch event sudah
// trigger applyI18n. Plus periodic check tiap 1.5s sebagai safety net untuk
// content yang di-render di luar event flow (timer-based render, async
// fetches, dll). Pakai flag __i18nApplying untuk avoid re-entry.
let __i18nApplying = false;
const __originalApplyI18n = applyI18n;
applyI18n = function(lang) {
  if (__i18nApplying) return;
  __i18nApplying = true;
  try { __originalApplyI18n(lang); }
  finally { setTimeout(() => { __i18nApplying = false; }, 50); }
};
// Periodic re-apply tiap 8 detik (sebelumnya 2s — terlalu agresif, bikin
// lag saat user mengetik / scroll). Cukup sebagai safety net untuk content
// yang di-render di luar event flow. Skip kalau tab background atau user
// sedang fokus pada input/textarea (mengetik).
setInterval(() => {
  if (document.hidden) return;
  const focused = document.activeElement;
  if (focused && (focused.tagName === "INPUT" || focused.tagName === "TEXTAREA")) return;
  try { applyI18n(currentLang()); } catch {}
}, 8000);

// Re-render notif & activity saat language berubah supaya text type-based
// auto-rebuild dari t() helper (bukan stored text yg fixed bahasanya).
window.addEventListener("playly:lang-changed", () => {
  try { if (typeof renderNotifications === "function") renderNotifications(); } catch {}
  try { if (typeof renderActivityList === "function") renderActivityList(); } catch {}
});

// ============== TIMEZONE ==============
// User pref "timezone" sekarang berisi IANA tz name (contoh "Asia/Jakarta").
// Format ulang waktu lokal sesuai pref user. Default Asia/Jakarta (WIB) untuk
// backward-compat dengan akun lama yang belum migrate ke IANA name.
const TZ_LEGACY_MAP = {
  "WIB":  "Asia/Jakarta",
  "WITA": "Asia/Makassar",
  "WIT":  "Asia/Jayapura",
  "UTC":  "UTC",
};
function currentTimezone() {
  let tz = (typeof getPref === "function") ? getPref("timezone", "Asia/Jakarta") : "Asia/Jakarta";
  if (TZ_LEGACY_MAP[tz]) tz = TZ_LEGACY_MAP[tz];
  return tz || "Asia/Jakarta";
}
function fmtLocalTime(date, opts = {}) {
  try {
    const tz = currentTimezone();
    return new Intl.DateTimeFormat(currentLang() || "en", {
      timeZone: tz,
      hour: "2-digit",
      minute: "2-digit",
      second: opts.withSeconds ? "2-digit" : undefined,
      hour12: false,
    }).format(date instanceof Date ? date : new Date(date));
  } catch {
    return new Date(date).toLocaleTimeString();
  }
}

// Update preview "Local time: HH:MM:SS (Asia/Jakarta)" di Settings.
function updateTimezonePreview() {
  const el = document.getElementById("userLocalTimePreview");
  if (!el) return;
  const tz = currentTimezone();
  const now = new Date();
  el.textContent = `${fmtLocalTime(now, { withSeconds: true })} (${tz})`;
}
// Tick preview tiap detik kalau settings page kebuka
setInterval(() => {
  if (document.getElementById("userLocalTimePreview")?.offsetParent) updateTimezonePreview();
}, 1000);

// ----------------------- HELPERS: baca preferensi user lain (untuk delivery checks) -----------------------
// Mapping dari notification type → settings key di sisi penerima.
const NOTIF_TYPE_PREF = {
  comment: "notif.comment",
  like: "notif.message", // like masuk kategori interaksi inbox-style
  follow: "notif.follower",
  "video-share": "notif.message",
  message: "notif.message"
};

function getOtherUserPref(email, key, def) {
  if (!email) return def;
  try {
    const prefs = JSON.parse(localStorage.getItem(`playly-prefs-${email}`) || "{}");
    const parts = key.split(".");
    let obj = prefs;
    for (const p of parts) {
      if (obj == null || typeof obj !== "object") return def;
      obj = obj[p];
    }
    return obj === undefined ? def : obj;
  } catch { return def; }
}

function getOtherUserPrefByUsername(username, key, def) {
  if (!username) return def;
  if (user && user.username === username) return getPref(key, def);
  const acc = getAllAccounts().find(a => a.username === username);
  if (!acc?.email) return def;
  return getOtherUserPref(acc.email, key, def);
}

// ----------------------- PLATFORM SETTINGS (admin-only, global) -----------------------
// Settings yang berlaku ke seluruh platform (bukan per-user). Disimpan di
// `playly-platform-config` dan dibaca oleh kode lain (signup, upload, comment).
const PLATFORM_CONFIG_KEY = "playly-platform-config";

function defaultPlatformConfig() {
  return {
    maintenance: false,
    registrationOpen: true,
    uploadEnabled: true,
    commentsEnabled: true,
    autoApproveUpload: true,
    autoFlagWords: true,
    notifyOnFlag: true,
    autoSuspendStrikes: 3,
    auditLog: true,
    serverTz: "WIB",
    currency: "IDR"
  };
}

function getPlatformConfig() {
  try {
    const c = JSON.parse(localStorage.getItem(PLATFORM_CONFIG_KEY) || "null");
    return { ...defaultPlatformConfig(), ...(c || {}) };
  } catch { return defaultPlatformConfig(); }
}

function getPlatformSetting(key, def) {
  const c = getPlatformConfig();
  return key in c ? c[key] : def;
}

function setPlatformSetting(key, val) {
  const c = getPlatformConfig();
  c[key] = val;
  localStorage.setItem(PLATFORM_CONFIG_KEY, JSON.stringify(c));
  applyPlatformSettingSideEffects(key, val);
  // Audit-log aksi kalau auditLog ON
  if (c.auditLog && user?.role === "admin" && typeof pushAdminEvent === "function") {
    pushAdminEvent("⚙️", `Setting platform "${key}" diubah ke ${JSON.stringify(val)}`);
  }
}

function applyPlatformSettingSideEffects(key, val) {
  if (key === "maintenance") {
    document.body.classList.toggle("platform-maintenance", !!val);
    if (val) toast("⚠️ Maintenance mode AKTIF — user non-admin diblokir", "warning");
  }
  if (key === "uploadEnabled" || key === "registrationOpen" || key === "commentsEnabled") {
    // Sinkronkan UI di tab admin saat ini (toggle disable / sembunyikan tombol)
    syncPlatformUiState();
  }
}

// Hidden state class hooks for user-side: <body> kebak class
// "platform-no-upload" / "platform-no-comments" / "platform-no-signup".
// CSS bisa disable tombol upload, hide comment box, dsb.
function syncPlatformUiState() {
  const c = getPlatformConfig();
  document.body.classList.toggle("platform-no-upload", !c.uploadEnabled);
  document.body.classList.toggle("platform-no-comments", !c.commentsEnabled);
  document.body.classList.toggle("platform-no-signup", !c.registrationOpen);
  document.body.classList.toggle("platform-maintenance", !!c.maintenance);
}
syncPlatformUiState();

// Cross-tab sync: kalau admin ubah platform setting di tab lain, refresh class
window.addEventListener("storage", e => {
  if (e.key === PLATFORM_CONFIG_KEY) syncPlatformUiState();
});

function populatePlatformSettings() {
  $$("[data-platform]").forEach(el => {
    const key = el.dataset.platform;
    const cur = getPlatformSetting(key, el.type === "checkbox" ? el.checked : el.value);
    if (el.type === "checkbox") el.checked = !!cur;
    else el.value = cur;
    if (!el.dataset.platformBound) {
      el.dataset.platformBound = "1";
      el.addEventListener("change", () => {
        let v = el.type === "checkbox" ? el.checked : el.value;
        // Coerce numeric for select with numeric values
        if (el.type !== "checkbox" && /^-?\d+$/.test(v)) v = Number(v);
        setPlatformSetting(key, v);
      });
    }
  });
  // Card "Buat Admin" disembunyikan via CSS [data-super-admin-only].
  // Cuma render daftar admin tambahan kalau super admin yang buka.
  if (isSuperAdmin(user)) renderExtraAdminList();
}

// Isi info sesi admin (browser saat ini) di card Keamanan Admin → Akses & Sesi.
function populateAdminSessionInfo() {
  const deviceEl = document.getElementById("adminSessionDevice");
  if (deviceEl) {
    const ua = navigator.userAgent || "";
    let browser = "Browser";
    if (/Edg\//.test(ua)) browser = "Edge";
    else if (/Chrome\//.test(ua)) browser = "Chrome";
    else if (/Firefox\//.test(ua)) browser = "Firefox";
    else if (/Safari\//.test(ua)) browser = "Safari";
    let os = "Desktop";
    if (/Windows/.test(ua)) os = "Windows";
    else if (/Mac OS X|Macintosh/.test(ua)) os = "macOS";
    else if (/Android/.test(ua)) os = "Android";
    else if (/iPhone|iPad|iOS/.test(ua)) os = "iOS";
    else if (/Linux/.test(ua)) os = "Linux";
    deviceEl.textContent = `${browser} • ${os} • aktif sekarang`;
  }
  const logoutBtn = document.getElementById("adminLogoutNowBtn");
  if (logoutBtn && !logoutBtn.dataset.bound) {
    logoutBtn.dataset.bound = "1";
    logoutBtn.addEventListener("click", () => {
      if (typeof confirmLogout === "function") confirmLogout();
    });
  }
}

// ----------------------- CHANGE PASSWORD -----------------------
document.getElementById("changePasswordForm")?.addEventListener("submit", async e => {
  e.preventDefault();
  if (!user) return;
  const fd = new FormData(e.target);
  const oldPw = fd.get("oldPw");
  const newPw = fd.get("newPw");
  const confirmPw = fd.get("confirmPw");

  if (newPw.length < 6) return toast("⚠️ Password baru minimal 6 karakter", "warning");
  if (newPw !== confirmPw) return toast("❌ Konfirmasi password tidak cocok", "error");

  const accKey = `playly-account-${user.email}`;
  const acc = JSON.parse(localStorage.getItem(accKey) || "null");
  if (!acc) return toast("❌ Akun tidak ditemukan", "error");
  const oldOk = await verifyPassword(oldPw, acc.password);
  if (!oldOk) return toast("❌ Password lama salah", "error");

  acc.password = await hashPassword(newPw);
  localStorage.setItem(accKey, JSON.stringify(acc));
  e.target.reset();
  toast(t("admin.toast.pw.changed"), "success");
});

// ----------------------- ADMIN SETTINGS (form handlers) -----------------------
$("#adminChangePasswordForm")?.addEventListener("submit", async e => {
  e.preventDefault();
  if (!user || user.role !== "admin") return;
  const fd = new FormData(e.target);
  const oldPw = fd.get("oldPw");
  const newPw = fd.get("newPw");
  const confirmPw = fd.get("confirmPw");
  if (newPw.length < 6) return toast("⚠️ Password baru minimal 6 karakter", "warning");
  if (newPw !== confirmPw) return toast("❌ Konfirmasi password tidak cocok", "error");
  const accKey = `playly-account-${user.email}`;
  const acc = JSON.parse(localStorage.getItem(accKey) || "null");
  if (!acc) return toast("❌ Akun admin tidak ditemukan", "error");
  const oldOk = await verifyPassword(oldPw, acc.password);
  if (!oldOk) return toast("❌ Password lama salah", "error");
  acc.password = await hashPassword(newPw);
  localStorage.setItem(accKey, JSON.stringify(acc));
  e.target.reset();
  if (typeof pushAdminEvent === "function") pushAdminEvent("🔐", "Password admin diubah");
  toast(t("admin.toast.pw.admin.changed"), "success");
});

// ----------------------- ADMIN MANAGEMENT (super admin only) -----------------------
$("#createAdminForm")?.addEventListener("submit", async e => {
  e.preventDefault();
  if (!isSuperAdmin(user)) return toast("⚠ Hanya super admin yang bisa membuat admin baru", "warning");
  const fd = new FormData(e.target);
  const name = String(fd.get("name") || "").trim();
  const username = String(fd.get("username") || "").trim().toLowerCase();
  const email = String(fd.get("email") || "").trim().toLowerCase();
  const password = String(fd.get("password") || "");
  const adminLevel = String(fd.get("adminLevel") || "moderator");
  if (name.length < 2) return toast("⚠ Nama minimal 2 karakter", "warning");
  if (!username) return toast("⚠ Username tidak boleh kosong", "warning");
  if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) return toast("⚠ Format email tidak valid", "warning");
  if (password.length < 6) return toast("⚠ Password minimal 6 karakter", "warning");
  if (isOfficialAdminEmail(email)) return toast("⚠ Email itu sudah dipakai super admin", "warning");
  if (isReservedUsername(username)) return toast("⚠ Username \"admin\" direservasi untuk super admin", "warning");
  if (findAccountByEmail(email)) return toast("⚠ Email sudah terdaftar", "warning");
  if (findAccountByUsername(username)) return toast("⚠ Username sudah dipakai", "warning");

  // Allowlist DULU supaya enforceAdminLock tidak downgrade akun ke "user" saat reload
  const list = getExtraAdminEmails();
  if (!list.includes(email)) list.push(email);
  setExtraAdminEmails(list);

  const hashedPw = await hashPassword(password);
  const acc = {
    name, username, email,
    role: "admin",
    adminLevel,
    joinedAt: new Date().toISOString(),
    password: hashedPw,
    createdBy: user.email
  };
  localStorage.setItem(`playly-account-${email}`, JSON.stringify(acc));

  const lvLabel = adminLevel === "senior" ? "Senior" : "Moderator";
  if (typeof pushAdminEvent === "function") pushAdminEvent("👑", `Admin baru ditambah: <b>@${escapeHtml(username)}</b> · ${lvLabel}`);
  e.target.reset();
  renderExtraAdminList();
  toast(`${t("admin.toast.admin.created")} <b>@${escapeHtml(username)}</b> ${t("admin.toast.created.suffix")} · ${lvLabel}`, "success");
});

