function openCreateUserModal() {
  const m = document.getElementById("createUserModal");
  if (!m) return;
  // Tentukan mode dari tombol pemicu (atau default "user")
  const trigger = document.getElementById("adminCreateUserBtn");
  const mode = trigger?.dataset.createMode === "admin" ? "admin" : "user";
  m.dataset.createMode = mode;
  // Title & subtitle modal
  const titleEl = document.getElementById("cuModalTitle");
  const subEl   = document.getElementById("cuModalSub");
  const submitBtn = document.getElementById("createUserSubmitBtn");
  if (mode === "admin") {
    if (titleEl) titleEl.textContent = "Buat Akun Admin";
    if (subEl)   subEl.textContent = "Buat akun admin tambahan — punya akses penuh ke dashboard admin.";
    // Hide tier section (admin tidak punya tier)
    const tierWrap = document.getElementById("cuTierWrap");
    const planWrap = document.getElementById("cuPlanSection");
    if (tierWrap) tierWrap.hidden = true;
    if (planWrap) planWrap.hidden = true;
    if (submitBtn) {
      submitBtn.innerHTML = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" style="width:15px;height:15px;flex-shrink:0"><path d="M12 22s-8-4-8-10V5l8-3 8 3v7c0 6-8 10-8 10z"/></svg> Buat Admin`;
    }
  } else {
    if (titleEl) titleEl.textContent = "Buat Akun User";
    if (subEl)   subEl.textContent = "Buat akun user baru dan atur tier langsung — tanpa proses pembayaran.";
    const tierWrap = document.getElementById("cuTierWrap");
    if (tierWrap) tierWrap.hidden = false;
    if (submitBtn) {
      submitBtn.innerHTML = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" style="width:15px;height:15px;flex-shrink:0"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><line x1="19" y1="8" x2="19" y2="14"/><line x1="22" y1="11" x2="16" y2="11"/></svg> Buat Akun`;
    }
  }
  m.classList.add("show");
  document.body.style.overflow = "hidden";
  requestAnimationFrame(() => m.querySelector("input[name='name']")?.focus());
}
function closeCreateUserModal() {
  const m = document.getElementById("createUserModal");
  if (!m) return;
  m.classList.remove("show");
  document.body.style.overflow = "";
  document.getElementById("createUserForm")?.reset();
  const ps = document.getElementById("cuPlanSection");
  if (ps) ps.hidden = true;
}
function openSetTierModal(username) {
  const m = document.getElementById("setTierModal");
  if (!m) return;
  const acc = getAllAccounts().find(a => a.username === username);
  if (!acc) return;
  const sub = document.getElementById("stModalSub");
  if (sub) sub.textContent = `@${username} · Tier saat ini: ${acc.tier === "premium" ? "Premium" : "Free"}`;
  const ui = document.getElementById("stUsername");
  if (ui) ui.value = username;
  const tr = m.querySelector(`input[name="tier"][value="${acc.tier || "free"}"]`);
  if (tr) tr.checked = true;
  const pr = m.querySelector(`input[name="premiumPlan"][value="${acc.premiumPlan || "monthly"}"]`);
  if (pr) pr.checked = true;
  const ps = document.getElementById("stPlanSection");
  if (ps) ps.hidden = (acc.tier !== "premium");
  m.classList.add("show");
  document.body.style.overflow = "hidden";
}
function closeSetTierModal() {
  const m = document.getElementById("setTierModal");
  if (!m) return;
  m.classList.remove("show");
  document.body.style.overflow = "";
  document.getElementById("setTierForm")?.reset();
  const ps = document.getElementById("stPlanSection");
  if (ps) ps.hidden = true;
}

