document.getElementById("createUserForm")?.addEventListener("submit", async e => {
  e.preventDefault();
  const modal = document.getElementById("createUserModal");
  const isAdminMode = modal?.dataset.createMode === "admin";
  // Bug #3 fix (2026-05-20): GATE admin-mode creation behind super-admin.
  // Sebelumnya handler ini honor createMode="admin" tanpa cek role aktif →
  // admin biasa bisa mint admin baru = self-escalate platform.
  if (isAdminMode) {
    const isSuper = (typeof isSuperAdmin === "function") ? isSuperAdmin(user) : false;
    if (!isSuper) {
      return toast("🔒 Hanya super-admin yang bisa membuat akun admin baru", "warning");
    }
  }
  const fd = new FormData(e.target);
  const name     = String(fd.get("name")        || "").trim();
  const username = String(fd.get("username")    || "").trim().toLowerCase();
  const email    = String(fd.get("email")       || "").trim().toLowerCase();
  const password = String(fd.get("password")    || "");
  const tier     = isAdminMode ? "free" : String(fd.get("tier")        || "free");
  const plan     = String(fd.get("premiumPlan") || "monthly");
  if (name.length < 2)
    return toast("⚠ Nama minimal 2 karakter", "warning");
  if (!/^[a-z0-9_.]{3,20}$/.test(username))
    return toast("⚠ Username 3–20 karakter (huruf kecil, angka, _ atau .)", "warning");
  if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email))
    return toast("⚠ Format email tidak valid", "warning");
  if (password.length < 6)
    return toast("⚠ Password minimal 6 karakter", "warning");
  if (isReservedUsername(username))
    return toast("⚠ Username itu direservasi sistem", "warning");
  // Cek email collision: di mode admin, email yang sudah jadi admin lain di-reject;
  // di mode user, email yang ada di allowlist admin di-reject (tidak boleh user daftar pakai email admin).
  if (isAdminMode) {
    if (email === OFFICIAL_ADMIN_EMAIL)
      return toast("⚠ Email itu adalah super admin — tidak bisa duplikat", "warning");
    if (getExtraAdminEmails().includes(email))
      return toast("⚠ Email sudah terdaftar sebagai admin", "warning");
  } else {
    if (isAllowedAdminEmail(email))
      return toast("⚠ Email itu terdaftar sebagai email admin", "warning");
  }
  // CR-3 fix (2026-05-21): force pull versi cloud terbaru sebelum cek duplikat.
  // Mencegah race: admin di device A buat akun yg sebenarnya sudah ada di
  // cloud (user signup di device lain belum sync).
  try {
    if (window.cloudSync?.syncSingleKey) {
      await Promise.resolve(window.cloudSync.syncSingleKey(`playly-account-${email}`));
    }
  } catch {}
  if (findAccountByEmail(email))
    return toast("⚠ Email sudah terdaftar", "warning");
  if (findAccountByUsername(username))
    return toast("⚠ Username sudah dipakai", "warning");

  const btn = document.getElementById("createUserSubmitBtn");
  if (btn) { btn.disabled = true; btn.textContent = "Creating…"; }

  const hashedPw = await hashPassword(password);
  const acc = {
    name, username, email,
    role: isAdminMode ? "admin" : "user",
    tier,
    joinedAt: new Date().toISOString(),
    password: hashedPw,
    createdBy: user?.email || "admin",
    adminCreated: true
  };
  if (!isAdminMode && tier === "premium") {
    acc.premiumPlan      = plan;
    acc.premiumStartedAt = Date.now();
    acc.premiumExpiresAt = computePremiumExpiry(plan);
    if (plan === "trial") acc.trialUsed = true;
  }
  // Cabut email dari banned list (kalau ada) — admin authoritative, kalau
  // admin re-create akun dengan email yang dulu dibanned, anggap unban.
  if (typeof removeBannedEmail === "function") removeBannedEmail(email);
  // Defense-in-depth: kalau email/username pernah dipakai sebelumnya, purge
  // per-user data lama (state, videos, history, prefs, dst.) supaya akun
  // baru benar-benar fresh — jangan inherit data legacy yang mungkin schema
  // lama. Email reuse OK, tapi isi data wajib hilang & pakai versi terbaru.
  if (typeof purgeUserDataByUsername === "function") purgeUserDataByUsername(username);
  try { localStorage.removeItem(`playly-prefs-${email}`); } catch {} // prefs dikey-by-email
  localStorage.setItem(`playly-account-${email}`, JSON.stringify(acc));
  // C-3 U-M2 fix (2026-05-21): allowlist push HANYA setelah account write
  // sukses. Sebelumnya push sebelum setItem → kalau setItem gagal (quota
  // exceeded, dll), allowlist updated tapi no account = inconsistent state.
  if (isAdminMode) {
    try {
      const extras = getExtraAdminEmails();
      if (!extras.includes(email)) {
        extras.push(email);
        setExtraAdminEmails(extras);
      }
    } catch (err) { console.warn("[create-user] allowlist push failed:", err); }
    // v564: Recovery Key auto-gen di v563 sudah dihapus per user request
    // (ganti ke PIN 2FA). Admin sekarang aktifkan 2FA manual dari
    // Pengaturan setelah login pertama. Tidak ada side-effect saat create.
  }

  const tl = isAdminMode
    ? "Admin"
    : (tier === "premium" ? `Premium · ${plan.charAt(0).toUpperCase() + plan.slice(1)}` : "Free");
  if (typeof pushAdminEvent === "function")
    pushAdminEvent(isAdminMode ? "🛡️" : "👤", `${isAdminMode ? "Admin" : "User"} baru dibuat: <b>@${escapeHtml(username)}</b> · ${tl}`);
  if (btn) {
    btn.disabled = false;
    btn.innerHTML = isAdminMode
      ? `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" style="width:15px;height:15px;flex-shrink:0"><path d="M12 22s-8-4-8-10V5l8-3 8 3v7c0 6-8 10-8 10z"/></svg> Buat Admin`
      : `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" style="width:15px;height:15px;flex-shrink:0"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><line x1="19" y1="8" x2="19" y2="14"/><line x1="22" y1="11" x2="16" y2="11"/></svg> Buat Akun`;
  }
  closeCreateUserModal();
  if (typeof renderAdminUsers === "function") renderAdminUsers();
  if (typeof renderAdminKPI   === "function") renderAdminKPI();
  toast(`${isAdminMode ? t("admin.toast.admin.created") : t("admin.toast.account.created")} <b>@${escapeHtml(username)}</b> ${t("admin.toast.created.suffix")} · ${tl}`, "success");
});

// === Inline Buat User Baru di section Pengaturan (per request user 2026-05-07).
// Reuse logic yang sama dengan modal createUserForm tapi tanpa modal close.
(() => {
  const form = document.getElementById("createUserInlineForm");
  if (!form) return;
  // Tier radio → toggle plan section visibility
  form.addEventListener("change", e => {
    if (e.target?.name !== "tier") return;
    const planSec = document.getElementById("cuiPlanSection");
    if (planSec) planSec.hidden = e.target.value !== "premium";
  });
  form.addEventListener("submit", async e => {
    e.preventDefault();
    // C-3 U-M3 fix (2026-05-21): SECURITY — gate inline create form ke admin.
    // Sebelumnya tidak ada cek role → kalau DOM form ke-expose ke non-admin
    // (stale cache, dev tools, dll) → mereka bisa create akun. Bahkan kalau
    // tier=premium mereka bisa self-grant premium tanpa bayar.
    if (!user || user.role !== "admin") {
      return toast("🔒 Hanya admin yang bisa membuat akun via form ini", "warning");
    }
    const fd = new FormData(form);
    const name     = String(fd.get("name")        || "").trim();
    const username = String(fd.get("username")    || "").trim().toLowerCase();
    const email    = String(fd.get("email")       || "").trim().toLowerCase();
    const password = String(fd.get("password")    || "");
    const tier     = String(fd.get("tier")        || "free");
    const plan     = String(fd.get("premiumPlan") || "monthly");
    if (name.length < 2)
      return toast("⚠ Nama minimal 2 karakter", "warning");
    if (!/^[a-z0-9_.]{3,20}$/.test(username))
      return toast("⚠ Username 3–20 karakter (huruf kecil, angka, _ atau .)", "warning");
    if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email))
      return toast("⚠ Format email tidak valid", "warning");
    if (password.length < 6)
      return toast("⚠ Password minimal 6 karakter", "warning");
    if (typeof isReservedUsername === "function" && isReservedUsername(username))
      return toast("⚠ Username itu direservasi sistem", "warning");
    if (typeof isAllowedAdminEmail === "function" && isAllowedAdminEmail(email))
      return toast("⚠ Email itu terdaftar sebagai email admin", "warning");
    // CR-3 fix (2026-05-21): force pull cloud sebelum cek dup (inline create form).
    try {
      if (window.cloudSync?.syncSingleKey) {
        await Promise.resolve(window.cloudSync.syncSingleKey(`playly-account-${email}`));
      }
    } catch {}
    if (typeof findAccountByEmail === "function" && findAccountByEmail(email))
      return toast("⚠ Email sudah terdaftar", "warning");
    if (typeof findAccountByUsername === "function" && findAccountByUsername(username))
      return toast("⚠ Username sudah dipakai", "warning");

    const submitBtn = form.querySelector('button[type="submit"]');
    const origHTML = submitBtn?.innerHTML;
    if (submitBtn) { submitBtn.disabled = true; submitBtn.textContent = "Membuat…"; }

    const hashedPw = await hashPassword(password);
    const acc = {
      name, username, email,
      role: "user",
      tier,
      joinedAt: new Date().toISOString(),
      password: hashedPw,
      createdBy: user?.email || "admin",
      adminCreated: true
    };
    if (tier === "premium") {
      acc.premiumPlan      = plan;
      acc.premiumStartedAt = Date.now();
      acc.premiumExpiresAt = computePremiumExpiry(plan);
      if (plan === "trial") acc.trialUsed = true;
    }
    if (typeof removeBannedEmail === "function") removeBannedEmail(email);
    // Defense-in-depth: purge data legacy supaya akun baru fresh
    if (typeof purgeUserDataByUsername === "function") purgeUserDataByUsername(username);
    try { localStorage.removeItem(`playly-prefs-${email}`); } catch {}
    localStorage.setItem(`playly-account-${email}`, JSON.stringify(acc));

    const tl = tier === "premium"
      ? `Premium · ${plan.charAt(0).toUpperCase() + plan.slice(1)}`
      : "Free";
    if (typeof pushAdminEvent === "function")
      pushAdminEvent("👤", `User baru dibuat: <b>@${escapeHtml(username)}</b> · ${tl}`);

    form.reset();
    const planSec = document.getElementById("cuiPlanSection");
    if (planSec) planSec.hidden = true;
    if (submitBtn) {
      submitBtn.disabled = false;
      submitBtn.innerHTML = origHTML;
    }
    if (typeof renderAdminUsers === "function") renderAdminUsers();
    if (typeof renderAdminKPI   === "function") renderAdminKPI();
    toast(`${t("admin.toast.account.created")} <b>@${escapeHtml(username)}</b> ${t("admin.toast.created.suffix")} · ${tl}`, "success");
  });
})();

document.getElementById("setTierForm")?.addEventListener("submit", e => {
  e.preventDefault();
  const fd       = new FormData(e.target);
  const username = String(fd.get("username")    || "").trim();
  const tier     = String(fd.get("tier")        || "free");
  const plan     = String(fd.get("premiumPlan") || "monthly");
  if (!username) return;
  const key = Object.keys(localStorage).find(k => {
    if (!k.startsWith("playly-account-")) return false;
    try { return JSON.parse(localStorage.getItem(k))?.username === username; } catch { return false; }
  });
  if (!key) return toast("⚠ Akun tidak ditemukan", "error");
  let acc;
  try { acc = JSON.parse(localStorage.getItem(key)); } catch { return; }

  // === DOWNGRADE / FREE → instant apply (tidak butuh approval queue) ===
  if (tier !== "premium") {
    acc.tier = "free";
    delete acc.premiumPlan;
    delete acc.premiumStartedAt;
    delete acc.premiumExpiresAt;
    localStorage.setItem(key, JSON.stringify(acc));
    if (window.user?.username === username) {
      window.user.tier = "free";
      window.user.premiumPlan = null;
      window.user.premiumStartedAt = null;
      window.user.premiumExpiresAt = null;
      localStorage.setItem("playly-user", JSON.stringify(window.user));
      document.body.dataset.tier = "free";
    }
    // C-2 H3 fix (2026-05-21): mark matching premium payment records sebagai
    // revoked supaya revenue widgets tidak terus count user ini, dan ada
    // audit trail tier-strip. Plus notify user.
    try {
      const accEmail = String(acc.email || "").toLowerCase();
      if (accEmail && typeof getPremiumPayments === "function") {
        const payments = getPremiumPayments();
        let modified = false;
        for (const p of payments) {
          if (!p || !p.email) continue;
          if (String(p.email).toLowerCase() !== accEmail) continue;
          if (p.status === "approved" || p.status === "activated") {
            p.status = "revoked";
            p.revokedAt = Date.now();
            p.revokedBy = (typeof user === "object" && user?.username) ? user.username : "admin";
            p.updatedAt = Date.now();
            modified = true;
          }
        }
        if (modified && typeof savePremiumPayments === "function") savePremiumPayments(payments);
      }
    } catch (err) { console.warn("[tier-downgrade] revoke payments failed:", err); }
    // Notify user
    if (typeof deliverNotification === "function") {
      try {
        deliverNotification(username, {
          type: "tier-downgrade",
          text: "⭐ Tier Premium kamu dicabut oleh admin. Akun sekarang Free. Hubungi support untuk informasi lebih lanjut.",
          init: "⭐", fromUsername: "admin",
        });
      } catch (err) { console.warn("[tier-downgrade] notify failed:", err); }
    }
    if (typeof pushAdminEvent === "function")
      pushAdminEvent("⭐", `Tier @${escapeHtml(username)} → <b>Free</b> (premium payment di-revoke)`);
    closeSetTierModal();
    if (typeof renderAdminUsers === "function") renderAdminUsers();
    toast(`✓ Tier <b>@${escapeHtml(username)}</b> → Free`, "success");
    return;
  }

  // === UPGRADE TO PREMIUM via admin grant — follow STEP-BY-STEP flow.
  // Per user 2026-05-10aw: jangan auto-upgrade instan. Buat payment record
  // pending (price=0, gratis admin grant) → masuk ke approval queue → admin
  // approve dari queue → auto-upgrade + celebration popup di user side.
  if (acc.tier === "premium") {
    closeSetTierModal();
    return toast(`User <b>@${escapeHtml(username)}</b> sudah Premium`, "info");
  }
  // C-3 U-M5 fix (2026-05-21): cek duplikat existing payment lebih ketat.
  // Sebelumnya hanya block pending → kalau race window approval→activation
  // belum selesai (status approved tapi acc.tier belum premium), admin
  // bisa grant lagi → dua premium records. Sekarang block kalau:
  //   - ada pending untuk email ini, ATAU
  //   - ada admin-grant approved/activated < 60 detik (mencegah double-click
  //     atau retry burst)
  const accEmailLc = String(acc.email || "").toLowerCase();
  const allPayments = (typeof getPremiumPayments === "function" ? getPremiumPayments() : []);
  const existingPending = allPayments.find(p => String(p.email || "").toLowerCase() === accEmailLc && p.status === "pending");
  if (existingPending) {
    closeSetTierModal();
    return toast(`Sudah ada permintaan Premium pending untuk <b>@${escapeHtml(username)}</b>`, "warning");
  }
  const recentGrant = allPayments.find(p =>
    String(p.email || "").toLowerCase() === accEmailLc &&
    p.flowContext === "admin-grant" &&
    (p.status === "approved" || p.status === "activated") &&
    (Date.now() - (p.paidAt || 0)) < 60000
  );
  if (recentGrant) {
    closeSetTierModal();
    return toast(`Premium grant baru saja dibuat (< 1 menit lalu). Tunggu sebentar.`, "warning");
  }
  const code = (typeof generatePremiumCode === "function") ? generatePremiumCode() : ("PLY-" + Date.now().toString(36).toUpperCase());
  const orderId = String(Date.now()).slice(-8);
  const payment = {
    code,
    email: acc.email,
    username: acc.username,
    tier: "premium",
    plan,
    amount: 0,                              // ← gratis: admin grant
    method: "Admin Grant",
    paidAt: Date.now(),
    status: "pending",
    flowContext: "admin-grant",             // tag supaya bisa identify origin
    orderId,
    codeSentToUser: true,                   // admin grant gak butuh code typing
    grantedBy: window.user?.email || "admin",
    note: "Premium grant gratis dari admin (bukan transaksi user)"
  };
  try {
    const arr = (typeof getPremiumPayments === "function") ? getPremiumPayments() : [];
    arr.unshift(payment);
    if (typeof savePremiumPayments === "function") savePremiumPayments(arr);
  } catch (err) { console.warn("[admin grant premium]", err); }

  if (typeof pushAdminEvent === "function") {
    pushAdminEvent("🎁", `Admin grant Premium · ${plan} (gratis) untuk <b>@${escapeHtml(username)}</b> — masuk approval queue`);
  }
  closeSetTierModal();
  if (typeof renderAdminUsers === "function") renderAdminUsers();
  if (typeof renderAdminPremiumQueue === "function") renderAdminPremiumQueue();
  toast(`📋 Permintaan Premium gratis untuk <b>@${escapeHtml(username)}</b> masuk approval queue. Approve dari queue untuk aktivasi.`, "success");
});

// =====================================================================

function renderExtraAdminList() {
  const box = document.getElementById("extraAdminList");
  if (!box) return;
  const emails = getExtraAdminEmails();
  if (!emails.length) {
    box.innerHTML = `<p class="muted" style="font-size:12px;margin-top:14px">Belum ada admin tambahan.</p>`;
    return;
  }
  const accounts = getAllAccounts();
  box.innerHTML = `
    <p class="muted" style="font-size:12px;margin:18px 0 8px">Admin tambahan (${emails.length}):</p>
    <ul style="list-style:none;padding:0;margin:0;display:flex;flex-direction:column;gap:6px">
      ${emails.map(em => {
        const a = accounts.find(x => (x.email || "").toLowerCase() === em);
        const label = a
          ? `<b>${escapeHtml(a.name)}</b> <span class="muted" style="font-size:12px">@${escapeHtml(a.username)} · ${escapeHtml(em)}</span>`
          : `<span class="muted">${escapeHtml(em)} <small>(akun belum disinkron)</small></span>`;
        return `<li style="display:flex;justify-content:space-between;align-items:center;gap:8px;padding:10px 12px;background:var(--bg-elev);border:1px solid var(--border);border-radius:8px"><span>${label}</span><button type="button" class="btn ghost danger" data-revoke-admin="${escapeHtml(em)}" style="padding:6px 12px;font-size:12px">Cabut</button></li>`;
      }).join("")}
    </ul>`;
}

document.addEventListener("click", e => {
  const btn = e.target.closest("[data-revoke-admin]");
  if (!btn) return;
  if (!isSuperAdmin(user)) return toast("⚠ Hanya super admin yang bisa mencabut admin", "warning");
  const email = String(btn.dataset.revokeAdmin || "").toLowerCase();
  if (!email || isOfficialAdminEmail(email)) return;
  openConfirm({
    icon: "⚠️", iconClass: "warn",
    title: "Cabut Akses Admin?",
    desc: `Akun <b>${escapeHtml(email)}</b> akan kehilangan akses admin dan jadi user biasa. Akun-nya tetap ada.`,
    btnText: "Cabut Admin", btnClass: "danger",
    onConfirm: () => {
      const list = getExtraAdminEmails().filter(e2 => e2 !== email);
      setExtraAdminEmails(list);
      const accKey = `playly-account-${email}`;
      const acc = JSON.parse(localStorage.getItem(accKey) || "null");
      if (acc) {
        acc.role = "user";
        localStorage.setItem(accKey, JSON.stringify(acc));
      }
      if (typeof pushAdminEvent === "function") pushAdminEvent("❌", `Admin dicabut: <b>${escapeHtml(email)}</b>`);
      renderExtraAdminList();
      toast("✓ Admin dicabut", "success");
    }
  });
});

function downloadJsonBlob(filename, data) {
  const blob = new Blob([JSON.stringify(data, null, 2)], { type: "application/json" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url; a.download = filename; a.click();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

// ----------------------- AUTH UI -----------------------
const authTabs = $(".auth-tabs");

function switchAuthTab(name) {
  $$("[data-auth-tab]").forEach(b => {
    if (b.tagName === "BUTTON") b.classList.toggle("active", b.dataset.authTab === name);
  });
  authTabs.classList.toggle("signup", name === "signup");
  $$(".auth-form").forEach(f => f.classList.toggle("active", f.dataset.form === name));
  // Sync state machine attribute supaya CSS rules untuk show/hide form bekerja
  // di dalam modal context (per request 2026-05-03 final).
  const card = document.getElementById("authCard");
  if (card && !card.dataset.authStateLock) {
    if (name === "signup") card.dataset.authState = "signup-form";
    else card.dataset.authState = "signin";
  }
}

$$("[data-auth-tab]").forEach(b => {
  b.addEventListener("click", e => { e.preventDefault(); switchAuthTab(b.dataset.authTab); });
});

// === AUTH MODAL (per request 2026-05-03 final) ===
// Auth-card sekarang modal popup. Topbar Sign In/Sign Up + plan CTA → openAuthModal.
function openAuthModal(state, opts = {}) {
  const wrap = document.getElementById("authModalWrap");
  if (!wrap) return;
  // Portal modal ke body saat buka — supaya kita bisa blur .auth-screen
  // utuh sebagai satu unit, tanpa modal ikut kena blur. Kalau modal tetep
  // nested di .auth-grid, blur ke parent akan cascade ke modal juga.
  if (wrap.parentElement && wrap.parentElement !== document.body) {
    wrap.dataset._origParentId = wrap.parentElement.id || "";
    document.body.appendChild(wrap);
  }
  wrap.classList.add("show");
  document.body.style.overflow = "hidden";
  document.body.setAttribute("data-auth-modal-open", "true");
  setAuthState(state || "signin", opts);
}
function closeAuthModal() {
  const wrap = document.getElementById("authModalWrap");
  if (!wrap) return;
  // If user closes auth modal while on account-check state (not continuing to
  // signin/signup), clear the pending guest plan so it doesn't fire later.
  const card = document.getElementById("authCard");
  if (card?.dataset.authState === "plan-auth-check") {
    delete window._guestPickedPlan;
  }
  wrap.classList.remove("show");
  // Restore modal ke parent originalnya (auth-grid)
  const origId = wrap.dataset._origParentId;
  if (origId) {
    const orig = document.getElementById(origId);
    if (orig && wrap.parentElement === document.body) orig.appendChild(wrap);
    delete wrap.dataset._origParentId;
  }
  document.body.style.overflow = "";
  document.body.removeAttribute("data-auth-modal-open");
}
// ESC key → close modal
document.addEventListener("keydown", e => {
  if (e.key === "Escape") {
    const wrap = document.getElementById("authModalWrap");
    if (wrap?.classList.contains("show")) closeAuthModal();
  }
});

// Deep-link: /login & /signup → auto-open modal pada landing.
// Sebelumnya URL ini 404 karena Next.js belum punya rewrite-nya. Rewrite
// sudah dipasang di next.config.mjs; script ini cuma men-trigger modal
// dan rewrite history-state ke "/" supaya URL tidak persist (deep-link
// share, refresh, dsb tetap clean).
(function handleAuthDeepLink() {
  function tryOpen() {
    const path = (location.pathname || "").toLowerCase();
    if (path !== "/login" && path !== "/signup") return;
    // Skip kalau user sudah login (akan ke-redirect oleh boot flow lain)
    if (document.body?.dataset.role) return;
    const wrap = document.getElementById("authModalWrap");
    if (!wrap) return;
    openAuthModal(path === "/signup" ? "signup-form" : "signin");
    try { history.replaceState(null, "", "/"); } catch {}
  }
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", tryOpen, { once: true });
  } else {
    setTimeout(tryOpen, 0);
  }
})();

// === AUTH STATE MACHINE (per request 2026-05-04 — flow flipped) ===
// States: landing | signin | signup-form | signup-pick
// New order: Sign Up → signup-form (daftar dulu) → submit → signup-pick (pilih
// Free/Premium) → if Premium: openPlanPicker → openPaymentModal → upgrade tier
// → bootDashboard. signup-pick is now POST-signup only (was pre-signup before).
function setAuthState(state, opts = {}) {
  const card = document.getElementById("authCard");
  if (!card) return;
  card.dataset.authState = state;
  // Mark post-signup mode on the plan picker so CSS can hide the Back button
  // (account already created → backing out to landing would be confusing).
  if (state === "signup-pick" && window.__playlyPostSignup) {
    card.dataset.postSignup = "1";
  } else {
    delete card.dataset.postSignup;
  }
  // Switch internal form tab when entering "signin" or "signup-form"
  if (state === "signin" && typeof switchAuthTab === "function") {
    switchAuthTab("signin");
  } else if (state === "signup-form" && typeof switchAuthTab === "function") {
    switchAuthTab("signup");
    // Pre-select tier if provided
    if (opts.tier) {
      const radio = document.querySelector(`#signupForm input[name="tier"][value="${opts.tier}"]`);
      if (radio) radio.checked = true;
      const pillLabel = document.getElementById("signupTierPillLabel");
      const pillIcon = document.getElementById("signupTierPillIcon");
      if (pillLabel) pillLabel.textContent = opts.tier === "premium" ? "Premium" : "Gratis";
      if (pillIcon) pillIcon.textContent = opts.tier === "premium" ? "⭐" : "🌱";
    }
  }
  // Scroll auth screen ke top supaya konten baru selalu kelihatan
  const screen = document.getElementById("authScreen");
  if (screen) screen.scrollTop = 0;
  // Refresh payment status banner whenever auth state changes
  if (typeof renderAuthPaymentBanner === "function") {
    try { renderAuthPaymentBanner(); } catch {}
  }
}

// Wire CTAs — semua trigger OPEN modal (bukan scroll lagi).
document.addEventListener("click", e => {
  // Modal close (backdrop atau X button)
  if (e.target.closest("[data-modal-close]")) {
    e.preventDefault();
    closeAuthModal();
    return;
  }
  // Internal state switch (Back button di dalam modal, dst.)
  const goBtn = e.target.closest("[data-go-state]");
  if (goBtn) {
    e.preventDefault();
    let target = goBtn.dataset.goState;
    // Smart Back from forms state: signup-form Back → landing (plan picker is
    // post-signup now; user hasn't seen it yet at this point). Sign-in Back also
    // → landing.
    if (goBtn.classList.contains("auth-back-btn-forms")) {
      target = "landing";
    }
    setAuthState(target);
    return;
  }
  // Plan picker pick (Free / Premium di dalam signup-pick state) —
  // POST-signup: account already created as free. Free → bootDashboard,
  // Premium → openPlanPicker → openPaymentModal → upgrade tier in storage.
  const pickTier = e.target.closest("[data-pick-tier]");
  if (pickTier) {
    e.preventDefault();
    const tier = pickTier.dataset.pickTier;
    // GUARD per request 2026-05-10: signup-pick state hanya valid POST-signup.
    // Tapi user bisa nyasar ke sini via "change" link di forms state tanpa
    // pernah sign up (user null). Tanpa guard ini, bootWithWelcome boot dashboard
    // dgn user=null → welcome card tampilin default "Kreator" + dashboard bocor
    // tanpa auth. Route balik ke signup-form / plan-auth-check untuk paksa auth.
    if (!user) {
      window._guestPickedPlan = tier === "premium" ? null : "free";
      if (tier === "premium") {
        // Premium butuh pilih plan dulu sebelum auth check
        if (typeof openPlanPicker === "function") openPlanPicker({ context: "guest-pick" });
      } else {
        _showGuestPlanAuthCheck("free");
      }
      return;
    }
    if (tier === "free") {
      delete window.__playlyPostSignup;
      // Per user 2026-05-11: tutup plan picker + auth modal SEBELUM welcome
      // overlay supaya tidak overlap di belakang animasi welcome stars.
      try { if (typeof closePlanPicker === "function") closePlanPicker(); } catch {}
      try { document.getElementById("planPickerModal")?.classList.remove("show"); } catch {}
      try { if (typeof closeAuthModal === "function") closeAuthModal(); } catch {}
      bootWithWelcome();
      return;
    }
    if (tier === "premium" && typeof openPlanPicker === "function") {
      openPlanPicker({
        context: "signup",
        onPick: (planKey) => {
          const finalize = () => {
            try {
              const email = user?.email;
              if (email) {
                const accRaw = localStorage.getItem(`playly-account-${email}`);
                const acc = accRaw ? JSON.parse(accRaw) : {};
                acc.tier = "premium";
                acc.premiumPlan = planKey;
                acc.premiumStartedAt = Date.now();
                acc.premiumExpiresAt = (typeof computePremiumExpiry === "function")
                  ? computePremiumExpiry(planKey) : null;
                if (planKey === "trial") acc.trialUsed = true;
                localStorage.setItem(`playly-account-${email}`, JSON.stringify(acc));
                user.tier = "premium";
                user.premiumPlan = planKey;
                user.premiumStartedAt = acc.premiumStartedAt;
                user.premiumExpiresAt = acc.premiumExpiresAt;
                localStorage.setItem("playly-user", JSON.stringify(user));
              }
            } catch (err) { console.warn("[signup] tier upgrade failed:", err); }
            delete window.__playlyPostSignup;
            bootWithWelcome();
          };
          if (planKey === "trial") { finalize(); return; }
          openPaymentModal({ onSuccess: finalize, planKey });
        }
      });
    }
    return;
  }
  // Topbar CTAs (Sign In / Sign Up) → OPEN modal langsung
  const topbarCta = e.target.closest("[data-topbar-cta]");
  if (topbarCta) {
    e.preventDefault();
    const target = topbarCta.dataset.topbarCta;
    openAuthModal(target === "signup" ? "signup-form" : "signin");
    return;
  }
  // Plan landing CTAs (Sign Up Free / Get Premium di pricing section).
  // Helper di-share dgn handler langsung supaya behavior konsisten:
  // force-logout dulu kalau ada session, lalu ke auth flow.
  const planPick = e.target.closest("[data-plan-pick]");
  if (planPick) {
    e.preventDefault();
    const tier = planPick.dataset.planPick === "premium" ? "premium" : "free";
    pickLandingPlanAsGuest(tier);
    return;
  }
  // Toggle periode penagihan Premium (Bulanan / Tahunan) — section Harga.
  // Cosmetic: ganti harga yg ditampilkan di kartu; checkout tetap lewat
  // plan picker (PREMIUM_PLANS) saat user klik "Dapatkan Premium".
  const billingOpt = e.target.closest("[data-billing]");
  if (billingOpt) {
    e.preventDefault();
    applyPlanBilling(billingOpt.dataset.billing === "yearly" ? "yearly" : "monthly");
    return;
  }
  // Final CTA: data-final-cta
  const finalCta = e.target.closest("[data-final-cta]");
  if (finalCta) {
    e.preventDefault();
    openAuthModal(finalCta.dataset.finalCta === "signin" ? "signin" : "signup-form");
    return;
  }
  // Topbar nav links — smooth scroll to section
  const scrollLink = e.target.closest("[data-scroll-target]");
  if (scrollLink) {
    e.preventDefault();
    const targetEl = document.getElementById(scrollLink.dataset.scrollTarget);
    if (targetEl) targetEl.scrollIntoView({ behavior: "smooth", block: "start" });
  }
});

