// =================== ADMIN FAQ CAROUSEL ===================
// Carousel horizontal: prev/next button + dots, active state via scroll position.
(function initAdminFaqCarousel() {
  const list = document.getElementById("adminFaqList");
  if (!list) return;
  const prev = document.querySelector(".admin-faq-nav-prev");
  const next = document.querySelector(".admin-faq-nav-next");
  const dotsWrap = document.getElementById("adminFaqDots");
  const items = Array.from(list.querySelectorAll(".admin-faq-item"));
  if (!items.length) return;

  // Build dots
  if (dotsWrap) {
    dotsWrap.innerHTML = items.map((_, i) =>
      `<button type="button" class="faq-dot${i === 0 ? " is-active" : ""}" data-faq-dot="${i}" aria-label="FAQ ${i + 1}"></button>`
    ).join("");
  }

  let currentIdx = 0;
  function scrollToIdx(idx) {
    const target = items[idx];
    if (!target) return;
    list.scrollTo({ left: target.offsetLeft - list.offsetLeft, behavior: "smooth" });
  }
  function updateActive() {
    // Find item closest to center of list viewport
    const center = list.scrollLeft + list.clientWidth / 2;
    let closestIdx = 0;
    let closestDist = Infinity;
    items.forEach((it, i) => {
      const c = it.offsetLeft + it.offsetWidth / 2;
      const d = Math.abs(c - center);
      if (d < closestDist) { closestDist = d; closestIdx = i; }
    });
    if (closestIdx !== currentIdx) {
      currentIdx = closestIdx;
      dotsWrap?.querySelectorAll(".faq-dot").forEach((d, i) => {
        d.classList.toggle("is-active", i === currentIdx);
      });
      const counter = document.getElementById("adminFaqCounter");
      if (counter) counter.textContent = String(currentIdx + 1);
    }
    if (prev) prev.disabled = currentIdx === 0;
    if (next) next.disabled = currentIdx === items.length - 1;
  }

  prev?.addEventListener("click", () => scrollToIdx(Math.max(0, currentIdx - 1)));
  next?.addEventListener("click", () => scrollToIdx(Math.min(items.length - 1, currentIdx + 1)));
  dotsWrap?.addEventListener("click", e => {
    const dot = e.target.closest("[data-faq-dot]");
    if (!dot) return;
    scrollToIdx(+dot.dataset.faqDot);
  });

  // rAF-throttled scroll listener
  let rafPending = false;
  list.addEventListener("scroll", () => {
    if (rafPending) return;
    rafPending = true;
    requestAnimationFrame(() => { updateActive(); rafPending = false; });
  });
  updateActive();
})();

// =================== AUTH TOPBAR SETTINGS DROPDOWN ===================
// Gear icon → menu pilih Language + Theme + Help. Support multiple instance
// (user landing + admin landing) lewat selector loop.
function _initAuthTopbarSettings(wrap, btn, menu) {
  if (!wrap || !btn || !menu) return;

  const close = () => {
    menu.hidden = true;
    btn.setAttribute("aria-expanded", "false");
    wrap.classList.remove("open");
  };
  const open = () => {
    menu.hidden = false;
    btn.setAttribute("aria-expanded", "true");
    wrap.classList.add("open");
    syncCheckmarks();
  };
  const syncCheckmarks = () => {
    const lang = (typeof currentLang === "function") ? currentLang() : "id";
    // Theme: read body.dataset.theme as source of truth (paling akurat — sudah
    // di-resolve dari guest/legacy localStorage di init). Hindari getPref karena
    // return default untuk guest (user belum login) → checkmark salah.
    const theme = document.body.dataset.theme || "dark";
    menu.querySelectorAll("[data-atsm-lang]").forEach(b => {
      b.classList.toggle("atsm-active", b.dataset.atsmLang === lang);
    });
    menu.querySelectorAll("[data-atsm-theme]").forEach(b => {
      b.classList.toggle("atsm-active", b.dataset.atsmTheme === theme);
    });
  };

  btn.addEventListener("click", e => {
    e.preventDefault();
    e.stopPropagation();
    if (menu.hidden) open(); else close();
  });
  // Click outside → close
  document.addEventListener("click", e => {
    if (!menu.hidden && !wrap.contains(e.target)) close();
  });
  document.addEventListener("keydown", e => {
    if (e.key === "Escape" && !menu.hidden) close();
  });

  // Language pick — simpan ke localStorage guest key (works tanpa login)
  menu.querySelectorAll("[data-atsm-lang]").forEach(b => {
    b.addEventListener("click", e => {
      e.preventDefault();
      const lang = b.dataset.atsmLang;
      try { localStorage.setItem("playly-guest-lang", lang); } catch {}
      try { if (typeof user !== "undefined" && user && typeof setPref === "function") setPref("lang", lang); } catch {}
      try { applyI18n(lang); } catch {}
      syncCheckmarks();
      if (typeof toast === "function") {
        const labels = { id: "Bahasa Indonesia", en: "English", ms: "Bahasa Melayu", ja: "日本語" };
        toast(`🌐 Bahasa: <b>${labels[lang] || lang}</b>`, "success");
      }
    });
  });
  // Theme pick — simpan ke kedua localStorage key (guest + legacy) supaya init
  // di top-of-file dan dashboard-side switch tetap konsisten. Apply ke body
  // + html DOM langsung. Sync checkmark via syncCheckmarks (pakai body.dataset
  // sebagai source of truth).
  menu.querySelectorAll("[data-atsm-theme]").forEach(b => {
    b.addEventListener("click", e => {
      e.preventDefault();
      const theme = b.dataset.atsmTheme;
      try {
        localStorage.setItem("playly-guest-theme", theme);
        localStorage.setItem("playly-theme", theme); // legacy key — dashboard switch consistency
      } catch {}
      try { if (typeof user !== "undefined" && user && typeof setPref === "function") setPref("theme", theme); } catch {}
      try {
        document.body.dataset.theme = theme;
        document.documentElement.setAttribute("data-theme", theme);
        // Sync legacy in-dashboard theme switch buttons (active class)
        document.querySelectorAll("[data-theme-set]").forEach(x => {
          x.classList.toggle("active", x.dataset.themeSet === theme);
        });
      } catch {}
      syncCheckmarks();
      if (typeof toast === "function") {
        toast(theme === "light" ? "☀️ Mode Terang" : "🌙 Mode Gelap", "success");
      }
    });
  });
  // Scroll target rows close menu after click
  menu.querySelectorAll("[data-scroll-target]").forEach(a => {
    a.addEventListener("click", () => close());
  });
}
