// === Animated dashboard preview slider ===
// Auto-rotate 4 mini-screens (Home → Upload → Analytics → Live) tiap 4.5s.
// Klik dot atau swipe → manual navigation; auto-rotate pause sebentar lalu resume.
(function initAuthHeroPreview() {
  const stage = document.getElementById("authPreviewStage");
  const dotsWrap = document.getElementById("authPreviewDots");
  if (!stage || !dotsWrap) return;
  const screens = stage.querySelectorAll(".auth-preview-screen");
  const dots = dotsWrap.querySelectorAll(".apd-dot");
  if (!screens.length) return;

  let current = 0;
  let timer = null;
  const INTERVAL = 4500;

  function go(idx) {
    idx = ((idx % screens.length) + screens.length) % screens.length;
    if (idx === current) return;
    const prev = screens[current];
    const next = screens[idx];
    // Smooth swap: kick prev ke leaving state dulu (decel keluar kiri),
    // lalu di-RAF berikutnya activate next (slide in dari kanan). Kedua
    // animasi paralel ~500ms (match CSS) — pakai double-RAF supaya browser
    // commit reflow sebelum classList ke-toggle, mencegah jump/skip.
    prev.classList.remove("aps-active");
    prev.classList.add("aps-leaving");
    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        next.classList.add("aps-active");
      });
    });
    // Cleanup leaving class setelah transition selesai (500ms + 50ms buffer)
    setTimeout(() => prev.classList.remove("aps-leaving"), 550);
    dots.forEach((d, i) => d.classList.toggle("apd-active", i === idx));
    current = idx;
  }

  function start() {
    stop();
    timer = setInterval(() => go(current + 1), INTERVAL);
  }
  function stop() { if (timer) { clearInterval(timer); timer = null; } }

  dots.forEach(dot => {
    dot.addEventListener("click", () => {
      const idx = parseInt(dot.dataset.goScreen, 10) || 0;
      go(idx);
      stop();
      setTimeout(start, 8000);
    });
  });

  // Pause auto-rotate saat hover di preview
  const frame = stage.closest(".auth-hero-preview");
  if (frame) {
    frame.addEventListener("mouseenter", stop);
    frame.addEventListener("mouseleave", start);
  }

  // Pause kalau tab tidak visible (hemat resource)
  document.addEventListener("visibilitychange", () => {
    if (document.hidden) stop();
    else start();
  });

  start();
})();

// Upgrade to Premium button (di profile dropdown) — buka plan picker dulu,
// lalu trial=instant atau paid=lewat payment modal.
document.getElementById("pdUpgradeBtn")?.addEventListener("click", () => {
  if (!user || user.tier === "premium") return;
  openPlanPicker({
    context: "upgrade",
    onPick: (planKey) => {
      const activatePremium = (planKey) => {
        const expiry = computePremiumExpiry(planKey);
        user.tier = "premium";
        user.premiumPlan = planKey;
        user.premiumStartedAt = Date.now();
        user.premiumExpiresAt = expiry;
        try {
          const acc = JSON.parse(localStorage.getItem(`playly-account-${user.email}`) || "{}");
          acc.tier = "premium";
          acc.premiumPlan = planKey;
          acc.premiumStartedAt = Date.now();
          acc.premiumExpiresAt = expiry;
          if (planKey === "trial") acc.trialUsed = true;
          localStorage.setItem(`playly-account-${user.email}`, JSON.stringify(acc));
          localStorage.setItem("playly-user", JSON.stringify(user));
        } catch {}
        applyRoleToUI?.();
        const plan = PREMIUM_PLANS[planKey];
        // planKey === "lifetime" → tampilkan "Selamanya" (durationLabel sudah Indonesia: "Selamanya").
        toast(`⭐ Premium ${plan.name} aktif! ${planKey === "lifetime" ? "Selamanya" : `Sampai ${new Date(expiry).toLocaleDateString("id-ID")}`}`, "success");
      };
      if (planKey === "trial") {
        // Trial — instant aktif tanpa payment & admin verify
        activatePremium("trial");
        return;
      }
      // Paid plans → buka payment modal (price & label disesuaikan dgn planKey)
      openPaymentModal({
        onSuccess: () => activatePremium(planKey),
        planKey,
      });
    }
  });
});

// =================== PREMIUM PLANS ===================
// 4 plan: Trial 7d (gratis instant), Monthly, Yearly, Lifetime.
// USD → IDR rate (approx, manual update). Dipakai di plan picker + payment modal
// untuk nampilin harga ekuivalen Rupiah di sebelah USD.
const USD_TO_IDR = 16500;
function fmtUsdAsIdr(usd) {
  if (!usd || usd <= 0) return "Gratis";
  const idr = Math.round(usd * USD_TO_IDR);
  return "Rp " + idr.toLocaleString("id-ID");
}

