let _pendingPlanKey = "monthly";
let _planPickerOnPick = null;

function openPlanPicker({ onPick, context = "upgrade" } = {}) {
  const modal = document.getElementById("planPickerModal");
  if (!modal) return;
  _planPickerOnPick = onPick || null;
  renderPlanPicker(context);
  modal.classList.add("show");
  document.body.style.overflow = "hidden";
}
function closePlanPicker() {
  const modal = document.getElementById("planPickerModal");
  if (!modal) return;
  modal.classList.remove("show");
  document.body.style.overflow = "";
  _planPickerOnPick = null;
}
function renderPlanPicker(context) {
  const grid = document.getElementById("planPickerGrid");
  if (!grid) return;
  // Existing user yang sudah pakai trial — disable trial button
  const trialUsedByThisAcc = (() => {
    if (!user?.email) return false;
    try {
      const acc = JSON.parse(localStorage.getItem(`playly-account-${user.email}`) || "{}");
      return !!acc.trialUsed;
    } catch { return false; }
  })();
  const order = ["trial", "monthly", "yearly", "lifetime"];
  // Inline check icon untuk fitur list (gantikan ✓ teks supaya rapi + warna konsisten via stroke).
  const checkSvg = '<svg class="pp-check" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M4 12l5 5L20 6"/></svg>';
  grid.innerHTML = order.map(key => {
    const p = PREMIUM_PLANS[key];
    const disabled = key === "trial" && trialUsedByThisAcc;
    const badge = p.badge ? `<span class="pp-badge">${p.badge}</span>` : "";
    const recommended = p.recommended ? ' pp-card-recommended' : "";
    const featuresHtml = (p.features || []).map(f => `<li>${checkSvg}<span>${f}</span></li>`).join("");
    // p.icon adalah key (gift/sparkle/flame/crown) → lookup ke PP_ICON_SVG.
    // Fallback ke emoji raw kalau key tidak dikenali (backward compat).
    const iconHtml = PP_ICON_SVG[p.icon] || p.icon || "";
    return `
      <button type="button" class="pp-card${recommended}${disabled ? ' pp-disabled' : ''}" data-plan-key="${p.key}"${disabled ? ' disabled' : ''}>
        ${badge}
        <span class="pp-icon">${iconHtml}</span>
        <strong class="pp-name">${p.name}</strong>
        <span class="pp-price">${p.priceLabel}${p.suffix ? `<small>${p.suffix}</small>` : ""}</span>
        ${p.price > 0 ? `<span class="pp-price-idr">≈ ${fmtUsdAsIdr(p.price)}</span>` : ""}
        <span class="pp-duration">${p.durationLabel}</span>
        <ul class="pp-features">${featuresHtml}</ul>
        <span class="pp-cta">${disabled ? "Sudah dipakai" : (key === "trial" ? "Mulai uji coba →" : "Pilih paket →")}</span>
      </button>`;
  }).join("");
}
// Plan card click handler
document.addEventListener("click", e => {
  const card = e.target.closest(".pp-card[data-plan-key]");
  if (!card || card.disabled) return;
  e.preventDefault();
  const key = card.dataset.planKey;
  _pendingPlanKey = key;
  // BUG FIX: simpan callback DULU sebelum close, karena closePlanPicker
  // reset _planPickerOnPick = null. Kalau urutannya kebalik, callback hilang
  // dan flow ke payment modal tidak pernah trigger.
  const cb = _planPickerOnPick;
  closePlanPicker();

  // Guest flow (not logged in) — intercept with account check before payment
  if (!user) {
    window._guestPickedPlan = key;
    _showGuestPlanAuthCheck(key);
    return;
  }

  if (typeof cb === "function") cb(key);
});

// Show account check state in auth modal after guest picks a plan
function _showGuestPlanAuthCheck(key) {
  // Untuk tier free pakai ikon leaf SVG (match signup-pick card).
  const FREE_LEAF_SVG = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M11 20A7 7 0 0 1 4 13c0-5 4-9 9-9h7v7c0 5-4 9-9 9z"/><path d="M11 20c0-5 3-9 9-12"/></svg>';
  const fallback = key === "free"
    ? { name: "Gratis", priceLabel: "Gratis", icon: "leaf" }
    : {};
  const plan = PREMIUM_PLANS[key] || fallback;
  const nameEl = document.getElementById("pacPlanName");
  const priceEl = document.getElementById("pacPlanPrice");
  const iconEl = document.getElementById("pacPlanIcon");
  if (nameEl) nameEl.textContent = plan.name || key;
  if (priceEl) priceEl.textContent = plan.priceLabel || "";
  // Ikon sekarang berupa key (gift/sparkle/flame/crown/leaf) → render SVG, bukan textContent.
  if (iconEl) {
    const iconHtml = plan.icon === "leaf" ? FREE_LEAF_SVG : (PP_ICON_SVG[plan.icon] || "");
    iconEl.innerHTML = iconHtml || '<span aria-hidden="true">★</span>';
  }
  openAuthModal("plan-auth-check");
}

// Helper: dipakai semua entry-point landing plan CTA (free + premium).
// Per request user 2026-05-10: setiap pilih plan dari landing WAJIB lewat auth
// (signup/login form). Kalau ada session lama yang ke-auto-restore, sign-out
// dulu supaya user explicitly mengisi email & password sebelum masuk dashboard.
// Toggle harga Bulanan/Tahunan di section Harga (2026-05-22).
// Cosmetic — ganti angka harga + note yg ditampilkan di kartu Premium.
// Harga riil (PREMIUM_PLANS): monthly $9.99, yearly $89.99/thn
// (= $7.50/bln ekuivalen, hemat 25%). Checkout tetap lewat plan picker.
function applyPlanBilling(mode) {
  const yearly = mode === "yearly";
  document.querySelectorAll(".plan-billing-toggle .pbt-opt").forEach(btn => {
    const on = btn.dataset.billing === mode;
    btn.classList.toggle("active", on);
    btn.setAttribute("aria-pressed", on ? "true" : "false");
  });
  // Class is-yearly di toggle → thumb wine meluncur ke segmen kanan +
  // hentikan pulse badge HEMAT (CSS handle animasi & transform).
  document.querySelectorAll(".plan-billing-toggle").forEach(tg => {
    tg.classList.toggle("is-yearly", yearly);
  });
  document.querySelectorAll(".plan-amount[data-amount-monthly]").forEach(el => {
    const v = yearly ? el.dataset.amountYearly : el.dataset.amountMonthly;
    if (v) el.textContent = v;
  });
  // Periode label Premium — selalu cocok dgn angka besar supaya tidak
  // rancu (Bulanan: $9.99/bulan · Tahunan: $89.99/tahun + note /bln).
  // Teks TANPA slash ("bulan"/"tahun"); garis miring "/" di-render via
  // CSS ::before — bulletproof dari kode lain di click-cycle yg strip "/".
  document.querySelectorAll(".plan-per-toggle").forEach(el => {
    el.textContent = yearly ? "tahun" : "bulan";
  });
  // Badge Premium — teks beda per mode: Bulanan "Direkomendasikan",
  // Tahunan "Paling Hemat" (sinyal yearly = pilihan terbaik value).
  document.querySelectorAll(".plan-badge-text[data-badge-monthly]").forEach(el => {
    el.textContent = yearly ? (el.dataset.badgeYearly || el.textContent)
                            : (el.dataset.badgeMonthly || el.textContent);
  });
  // Class billing-yearly di section → CSS pakai utk warna harga
  // Premium beda Bulanan (emas solid) vs Tahunan (emas gradient+glow).
  const _plansSec = document.getElementById("authPlansSection");
  if (_plansSec) _plansSec.classList.toggle("billing-yearly", yearly);
  document.querySelectorAll("[data-billing-note]").forEach(note => {
    note.hidden = !yearly;
  });
}

function pickLandingPlanAsGuest(tier) {
  // Force-clear session — user harus auth ulang untuk plan baru ini.
  try {
    if (typeof user !== "undefined" && user) {
      localStorage.removeItem("playly-user");
      user = null;
      if (typeof state !== "undefined") state = defaultState();
    }
  } catch {}
  // Pastikan auth screen visible (kalau dashboard sempat ke-render dari auto-boot).
  if (typeof showAuth === "function") {
    try { showAuth(); } catch {}
  }
  if (tier === "premium") {
    if (typeof openPlanPicker === "function") openPlanPicker({ context: "guest-pick" });
  } else {
    // Free → tampilkan plan-auth-check supaya user explicit pilih: udah punya
    // akun (Masuk) atau baru (Daftar). Sama UX-nya kayak premium tier.
    window._guestPickedPlan = "free";
    _showGuestPlanAuthCheck("free");
  }
}
