// Post-login plan modal close (backdrop / X)
document.getElementById("postLoginPlanModal")?.addEventListener("click", e => {
  if (e.target.matches("[data-close]") || e.target.closest("[data-close]") || e.target.matches(".modal-backdrop")) {
    _closePostLoginPlanPopup();
  }
});

// "Lanjutkan ke pembayaran" in post-login plan modal
document.getElementById("plpmBtnContinue")?.addEventListener("click", () => {
  const modal = document.getElementById("postLoginPlanModal");
  const planKey = modal?.dataset.planKey;
  _closePostLoginPlanPopup();
  if (!planKey || !user) return;
  if (planKey === "trial") {
    try {
      const expiry = computePremiumExpiry("trial");
      const acc = JSON.parse(localStorage.getItem(`playly-account-${user.email}`) || "{}");
      acc.tier = "premium"; acc.premiumPlan = "trial"; acc.trialUsed = true;
      acc.premiumStartedAt = Date.now(); acc.premiumExpiresAt = expiry;
      localStorage.setItem(`playly-account-${user.email}`, JSON.stringify(acc));
      user.tier = "premium"; user.premiumPlan = "trial";
      user.premiumStartedAt = acc.premiumStartedAt; user.premiumExpiresAt = expiry;
      localStorage.setItem("playly-user", JSON.stringify(user));
    } catch {}
    applyRoleToUI?.();
    toast("⭐ Trial Premium aktif!", "success");
    return;
  }
  const finalize = () => {
    try {
      const expiry = computePremiumExpiry(planKey);
      const acc = JSON.parse(localStorage.getItem(`playly-account-${user.email}`) || "{}");
      acc.tier = "premium"; acc.premiumPlan = planKey;
      acc.premiumStartedAt = Date.now(); acc.premiumExpiresAt = expiry;
      localStorage.setItem(`playly-account-${user.email}`, JSON.stringify(acc));
      user.tier = "premium"; user.premiumPlan = planKey;
      user.premiumStartedAt = acc.premiumStartedAt; user.premiumExpiresAt = expiry;
      localStorage.setItem("playly-user", JSON.stringify(user));
    } catch (err) { console.warn("[guest plan finalize]", err); }
    applyRoleToUI?.();
  };
  openPaymentModal({ planKey, onSuccess: finalize });
});

// "Masuk sebagai pengguna gratis" — dismiss popup, stay free
document.getElementById("plpmBtnFree")?.addEventListener("click", () => {
  _closePostLoginPlanPopup();
});

// Compute Premium expiration timestamp from plan + optional start date.
// v538 (2026-05-25): startTs param ditambah supaya expiry bisa di-hitung
// dari payment date (bukan approval date) — fix audit moderation H4 yg
// bilang admin late-approve = user dapat extended window unintended.
function computePremiumExpiry(planKey, startTs) {
  const plan = PREMIUM_PLANS[planKey];
  if (!plan || plan.durationMs === null) return null; // lifetime
  return (Number(startTs) || Date.now()) + plan.durationMs;
}

// Helper: cek apakah user premium masih aktif (tidak expired)
function isPremiumActive(u) {
  if (!u || u.tier !== "premium") return false;
  if (!u.premiumExpiresAt) return true; // lifetime / no expiry
  return u.premiumExpiresAt > Date.now();
}

// Helper: hari tersisa premium
function premiumDaysLeft(u) {
  if (!u || !u.premiumExpiresAt) return null;
  const ms = u.premiumExpiresAt - Date.now();
  if (ms <= 0) return 0;
  return Math.ceil(ms / (24 * 60 * 60 * 1000));
}

// =================== DUMMY PAYMENT MODAL ===================
// Client-side simulation only. No real payment processor wired up.
// Triggered from upgrade-to-premium flows; on "success" runs onSuccess callback.
// Verification flow: payment success → generate unique code → store as pending →
// admin reviews + approves → user proceed.
let _paymentOnSuccess = null;
let _premiumStatusPoller = null;

const PREMIUM_PAYMENTS_KEY = "playly-premium-payments";

function getPremiumPayments() {
  try { return JSON.parse(localStorage.getItem(PREMIUM_PAYMENTS_KEY) || "[]"); }
  catch { return []; }
}
function savePremiumPayments(arr) {
  try { localStorage.setItem(PREMIUM_PAYMENTS_KEY, JSON.stringify(arr)); }
  catch (err) { console.warn("[premium] save failed:", err); }
}
function generatePremiumCode() {
  // PLY-XXXXXXXX format, no confusing chars (no 0/O/1/I/L)
  // v546 (2026-05-25): Audit moderation M4 — dedup loop terhadap existing
  // payment codes. Sebelumnya pure random tanpa check → mungkin collision
  // (~1.1 trillion combo jadi rare tapi mungkin). Sekarang re-roll sampai
  // unique. Cap 20 attempts untuk safety; kalau exhausted (~impossible
  // dengan 32^8 keyspace) → log warn + return last code anyway (admin
  // bisa re-trigger generate kalau benar-benar konflik).
  const chars = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
  let existing = new Set();
  try {
    const arr = (typeof getPremiumPayments === "function") ? getPremiumPayments() : [];
    for (const p of arr) if (p && p.code) existing.add(p.code);
  } catch (_) { /* lookup failed — fallback to no-dedup */ }
  let code;
  for (let attempt = 0; attempt < 20; attempt++) {
    code = "PLY-";
    for (let i = 0; i < 8; i++) code += chars[Math.floor(Math.random() * chars.length)];
    if (!existing.has(code)) return code;
  }
  console.warn("[premium] generatePremiumCode: 20 collisions exhausted — returning anyway:", code);
  return code;
}
function getPremiumPaymentByCode(code) {
  return getPremiumPayments().find(p => p.code === code) || null;
}
function setPremiumPaymentStatus(code, status, processedBy) {
  const arr = getPremiumPayments();
  const idx = arr.findIndex(p => p.code === code);
  if (idx === -1) return false;
  const payment = arr[idx];
  payment.status = status;
  payment.processedAt = Date.now();
  // Bug #7 fix (2026-05-20): set updatedAt supaya cross-device merge bisa
  // tie-break dgn benar (lihat cloud-sync.js MERGE_KEYS_ARRAY).
  payment.updatedAt = Date.now();
  if (processedBy) payment.processedBy = processedBy;
  savePremiumPayments(arr);

  // C-2 H#5 fix (2026-05-21): lowercase email untuk perbandingan supaya
  // mismatch case (Adi@Gmail.com vs adi@gmail.com) tidak gagal upgrade.
  const paymentEmailLc = String(payment.email || "").toLowerCase();
  const userEmailLc = String((typeof user === "object" && user && user.email) || "").toLowerCase();

  // Track if this transition affects the active session (used to fire celebration)
  const activeSessionAffected =
    status === "approved" && paymentEmailLc &&
    userEmailLc && userEmailLc === paymentEmailLc;
  // Upgrade the user account when admin approves — fix 2026-05-05.
  if (status === "approved" && paymentEmailLc) {
    try {
      const accKey = `playly-account-${paymentEmailLc}`;
      const accRaw = localStorage.getItem(accKey);
      if (accRaw) {
        const acc = JSON.parse(accRaw);
        const planKey = payment.plan || "monthly";
        acc.tier = "premium";
        acc.premiumPlan = planKey;
        // C-2 H#6 fix (2026-05-21): guard double-write — premiumStartedAt
        // hanya set kalau belum ada. Sebelumnya setiap call (admin approve
        // + user activate modal) overwrite dgn Date.now() baru → drift
        // hours/days dari aktual approval time, distort expiry math.
        //
        // v538 HIGH FIX 4 (2026-05-25): Audit moderation flow H4 — start
        // date dari PAYMENT date (payment.paidAt / payment.ts), bukan
        // Date.now() (approval time). Sebelumnya kalau admin baru approve
        // 3 bulan setelah user bayar, user dapat extended window 3 bulan
        // unintended. Sekarang start = payment timestamp → expiry math
        // proper aligned dgn what user paid for.
        if (!acc.premiumStartedAt) {
          const paymentStart = Number(payment.paidAt || payment.ts || payment.createdAt) || Date.now();
          acc.premiumStartedAt = paymentStart;
          acc.premiumExpiresAt = (typeof computePremiumExpiry === "function")
            ? computePremiumExpiry(planKey, paymentStart)
            : null;
        }
        localStorage.setItem(accKey, JSON.stringify(acc));
        // If the upgraded account is the currently signed-in session, sync the
        // live user object + body data attribute so the UI reflects the change.
        if (userEmailLc && userEmailLc === paymentEmailLc) {
          user.tier = "premium";
          user.premiumPlan = planKey;
          user.premiumStartedAt = acc.premiumStartedAt;
          user.premiumExpiresAt = acc.premiumExpiresAt;
          localStorage.setItem("playly-user", JSON.stringify(user));
          if (document.body) document.body.dataset.tier = "premium";
          if (typeof applyRoleToUI === "function") { try { applyRoleToUI(); } catch {} }
        }
      }
    } catch (err) { console.warn("[setPremiumPaymentStatus] upgrade failed:", err); }
  }
  // Refresh the dashboard topbar pill so the user sees the new status immediately.
  try { if (typeof renderDashboardPaymentPill === "function") renderDashboardPaymentPill(); } catch {}
  try { if (typeof renderDashboardTierPill === "function") renderDashboardTierPill(); } catch {}
  // Fire celebration popup when active session user just got upgraded.
  if (activeSessionAffected) {
    try { if (typeof openPremiumCelebration === "function") openPremiumCelebration(payment.plan); } catch {}
  }
  // v546 (2026-05-25): Audit moderation M5 — silent grant fix. Approve path
  // tidak kirim notifikasi ke user (admin-grant flow paling kena). User di
  // device lain dapat premium TANPA tahu kenapa. Sekarang deliverNotification
  // explicit untuk semua approve, supaya user dapat tahu kode + tier change.
  // Reject juga di-notif supaya user nggak nunggu kode selamanya.
  if (status === "approved" || status === "rejected") {
    try {
      const targetUsername = payment.username
        || (paymentEmailLc && Object.keys(localStorage).reduce((acc, k) => {
            if (acc || !k.startsWith("playly-account-")) return acc;
            try {
              const a = JSON.parse(localStorage.getItem(k));
              if (a?.email && String(a.email).toLowerCase() === paymentEmailLc) return a.username;
            } catch {}
            return acc;
          }, null));
      if (targetUsername && typeof deliverNotification === "function") {
        if (status === "approved") {
          deliverNotification(targetUsername, {
            type: "premium-approved",
            text: `🎉 Pembayaran Premium <b>${escapeHtml(payment.code || "")}</b> sudah disetujui admin. Tier kamu sekarang <b>Premium</b>.`,
            init: "🎉",
            fromUsername: "admin",
          });
        } else {
          deliverNotification(targetUsername, {
            type: "premium-rejected",
            text: `❌ Pembayaran Premium <b>${escapeHtml(payment.code || "")}</b> ditolak admin. Cek detail di tab Premium kamu atau hubungi support.`,
            init: "❌",
            fromUsername: "admin",
          });
        }
      }
    } catch (err) { console.warn("[setPremiumPaymentStatus] notify user failed:", err); }
  }
  return true;
}
function markPaymentActivated(code) {
  const arr = getPremiumPayments();
  const idx = arr.findIndex(p => p.code === code);
  if (idx === -1) return false;
  arr[idx].activated = true;
  arr[idx].activatedAt = Date.now();
  savePremiumPayments(arr);
  return true;
}
function dismissPaymentRecord(code) {
  const arr = getPremiumPayments();
  const idx = arr.findIndex(p => p.code === code);
  if (idx === -1) return false;
  arr[idx].dismissed = true;
  savePremiumPayments(arr);
  return true;
}

// Bump tiap kali layout receipt berubah supaya record lama auto-regenerate
// di lazy-load openSupportCompose. v2 = pill auto-fit width (2026-05-04).
const PAYMENT_RECEIPT_VERSION = 2;

// Auto-generate receipt bukti pembayaran sebagai image dataURL (PNG).
// Dipanggil otomatis saat payment di-finalize — tersimpan ke payment.proofImage
// supaya saat user hubungi support email, bukti ini langsung auto-attach.
// Reason: user sering lupa screenshot success modal sebelum tutup, jadi
// sistem yang tangani capture-nya.
function generatePaymentReceiptImage({ code, orderId, method, plan, planKey, paidAt, email, username }) {
  const W = 720, H = 920;
  const canvas = document.createElement("canvas");
  canvas.width = W;
  canvas.height = H;
  const ctx = canvas.getContext("2d");
  if (!ctx) return null;

  // Background — wine gradient header + cream body
  const headerH = 200;
  const headerGrad = ctx.createLinearGradient(0, 0, W, headerH);
  headerGrad.addColorStop(0, "#561C24");
  headerGrad.addColorStop(0.5, "#6D2932");
  headerGrad.addColorStop(1, "#b5a07e");
  ctx.fillStyle = headerGrad;
  ctx.fillRect(0, 0, W, headerH);

  // Body bg
  ctx.fillStyle = "#fdf6ec";
  ctx.fillRect(0, headerH, W, H - headerH);

  // Decorative left-stripe wine
  ctx.fillStyle = "#6D2932";
  ctx.fillRect(0, headerH, 8, H - headerH);

  // Header — Playly brand
  ctx.fillStyle = "#E8D8C4";
  ctx.font = "bold 38px 'Inter', system-ui, sans-serif";
  ctx.textBaseline = "top";
  ctx.fillText("Playly.", 56, 52);

  ctx.font = "600 14px system-ui, sans-serif";
  ctx.fillStyle = "rgba(255, 250, 240, 0.9)";
  ctx.fillText("PAYMENT RECEIPT · BUKTI PEMBAYARAN", 56, 100);

  // Status pill (pending) — width auto-fit ke lebar text supaya tidak
  // overflow ke kanan. Padding kanan-kiri sama, vertical center via
  // (pillH - fontSize)/2.
  const pillText = "PENDING · MENUNGGU VERIFIKASI";
  const pillIcon = "⏳";
  const pillX = 56, pillY = 136, pillH = 40;
  const pillPadX = 20;
  const pillIconGap = 10;
  const pillFontSize = 13;
  ctx.font = `bold ${pillFontSize}px system-ui, sans-serif`;
  const pillIconW = ctx.measureText(pillIcon).width;
  const pillTextW = ctx.measureText(pillText).width;
  const pillW = Math.ceil(pillIconW + pillIconGap + pillTextW + pillPadX * 2);
  ctx.fillStyle = "rgba(245, 158, 11, 0.20)";
  _roundRect(ctx, pillX, pillY, pillW, pillH, pillH / 2);
  ctx.fill();
  ctx.strokeStyle = "rgba(245, 158, 11, 0.75)";
  ctx.lineWidth = 1.5;
  _roundRect(ctx, pillX, pillY, pillW, pillH, pillH / 2);
  ctx.stroke();
  ctx.fillStyle = "#fbbf24";
  const pillTextY = pillY + (pillH - pillFontSize) / 2;
  ctx.fillText(pillIcon, pillX + pillPadX, pillTextY);
  ctx.fillText(pillText, pillX + pillPadX + pillIconW + pillIconGap, pillTextY);

  // Body — title
  let y = headerH + 36;
  ctx.fillStyle = "#1a0c10";
  ctx.font = "bold 22px 'Inter', system-ui, sans-serif";
  ctx.fillText("Detail Transaksi", 56, y);
  y += 38;

  // Verification code — emphasized big
  ctx.fillStyle = "#8a6d62";
  ctx.font = "600 11px system-ui, sans-serif";
  ctx.fillText("KODE VERIFIKASI", 56, y);
  y += 20;
  ctx.fillStyle = "#561C24";
  ctx.font = "bold 32px 'JetBrains Mono', 'Courier New', monospace";
  ctx.fillText(code, 56, y);
  y += 50;

  // Divider
  ctx.strokeStyle = "rgba(86, 28, 36, 0.18)";
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(56, y);
  ctx.lineTo(W - 56, y);
  ctx.stroke();
  y += 24;

  // Detail rows
  const planLabelMap = {
    monthly:  "Playly Premium · Bulanan",
    yearly:   "Playly Premium · Tahunan",
    lifetime: "Playly Premium · Seumur Hidup",
  };
  const amountLabel = plan.priceLabel || `$${(plan.price || 9.99).toFixed(2)}`;
  const pad = n => String(n).padStart(2, "0");
  const dateStr = `${pad(paidAt.getDate())}/${pad(paidAt.getMonth()+1)}/${paidAt.getFullYear()} ${pad(paidAt.getHours())}:${pad(paidAt.getMinutes())}`;

  const rows = [
    ["Order ID",        `#${orderId}`],
    ["Tanggal & Waktu", dateStr],
    ["Paket",           planLabelMap[planKey] || "Playly Premium"],
    ["Jumlah",          amountLabel],
    ["Metode",          method],
    ["Email Akun",      email || "—"],
    ["Username",        username ? "@" + username : "—"],
  ];

  ctx.font = "500 14px system-ui, sans-serif";
  rows.forEach(([label, value]) => {
    ctx.fillStyle = "#8a6d62";
    ctx.fillText(label, 56, y);
    ctx.fillStyle = "#1a0c10";
    ctx.font = "bold 14px system-ui, sans-serif";
    const valX = 240;
    ctx.fillText(value, valX, y);
    ctx.font = "500 14px system-ui, sans-serif";
    y += 30;
  });

  // Total bar — big highlight
  y += 16;
  ctx.fillStyle = "rgba(161, 141, 109, 0.08)";
  _roundRect(ctx, 48, y, W - 96, 70, 12);
  ctx.fill();
  ctx.strokeStyle = "rgba(161, 141, 109, 0.25)";
  ctx.lineWidth = 1.5;
  _roundRect(ctx, 48, y, W - 96, 70, 12);
  ctx.stroke();
  ctx.fillStyle = "#561C24";
  ctx.font = "700 13px system-ui, sans-serif";
  ctx.fillText("TOTAL DIBAYAR", 70, y + 12);
  ctx.font = "bold 30px 'Inter', system-ui, sans-serif";
  ctx.fillText(amountLabel, 70, y + 30);
  y += 100;

  // Footer disclaimer
  ctx.strokeStyle = "rgba(86, 28, 36, 0.14)";
  ctx.beginPath();
  ctx.moveTo(56, H - 100);
  ctx.lineTo(W - 56, H - 100);
  ctx.stroke();
  ctx.fillStyle = "#8a6d62";
  ctx.font = "500 12px system-ui, sans-serif";
  ctx.fillText("Bukti pembayaran auto-generated oleh sistem Playly.", 56, H - 80);
  ctx.fillText("Tunjukkan kode verifikasi ini ke admin untuk aktivasi Premium.", 56, H - 60);
  ctx.font = "600 11px system-ui, sans-serif";
  ctx.fillStyle = "#561C24";
  ctx.fillText(`Generated: ${dateStr}  ·  © 2026 Playly`, 56, H - 36);

  return canvas.toDataURL("image/png");
}

// Helper untuk gambar rounded rectangle (Canvas tidak punya built-in roundRect
// di semua browser lama).
function _roundRect(ctx, x, y, w, h, r) {
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.lineTo(x + w - r, y);
  ctx.quadraticCurveTo(x + w, y, x + w, y + r);
  ctx.lineTo(x + w, y + h - r);
  ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
  ctx.lineTo(x + r, y + h);
  ctx.quadraticCurveTo(x, y + h, x, y + h - r);
  ctx.lineTo(x, y + r);
  ctx.quadraticCurveTo(x, y, x + r, y);
  ctx.closePath();
}

// =================== AUTH SCREEN PAYMENT STATUS BANNER ===================
// Persistent across all auth states. Shows latest premium payment for any
// account on this device (pending → polls every 5s; approved → click to
// activate & login; rejected → dismiss). Lets user re-check from login page
// after they closed the success modal.
let _authPaymentPollTimer = null;

function findAuthScreenPayment() {
  // Most recent non-consumed payment for any device-tracked account.
  // C-4 P-L15 fix (2026-05-21): kalau device-emails kosong (mis. user clear
  // device-accounts), fallback ke email yg sedang diketik di sign-in form.
  // Sebelumnya return null → user yg punya pending payment tidak lihat
  // banner-nya, padahal mungkin sedang di flow sign-in setelah signup.
  const deviceEmails = (typeof getDeviceAccountEmails === "function")
    ? getDeviceAccountEmails().map(e => String(e).toLowerCase())
    : [];
  if (!deviceEmails.length) {
    // Fallback: try email currently in sign-in form
    const signinEmail = String(document.querySelector('#signinForm input[name="email"]')?.value || "").trim().toLowerCase();
    if (signinEmail) deviceEmails.push(signinEmail);
    else return null;
  }
  const all = getPremiumPayments();

  // Auto-cleanup: kalau akun untuk payment email sudah premium tier,
  // berarti aktivasi sudah berhasil (entah lewat tombol Aktifkan Premium
  // atau auto-upgrade flow). Tandai payment sebagai activated supaya banner
  // tidak terus-menerus muncul.
  let dirty = false;
  const accounts = (typeof getAllAccounts === "function") ? getAllAccounts() : [];
  const premiumEmails = new Set(
    accounts
      .filter(a => a && a.email && a.tier === "premium")
      .map(a => String(a.email).toLowerCase())
  );
  for (const p of all) {
    if (!p || !p.email || p.activated || p.dismissed) continue;
    if (p.status !== "approved") continue;
    if (premiumEmails.has(String(p.email).toLowerCase())) {
      p.activated = true;
      p.activatedAt = p.activatedAt || Date.now();
      p.updatedAt = Date.now();
      dirty = true;
    }
  }
  // C-3 P-M10 fix (2026-05-21): re-fetch fresh array sebelum save supaya
  // cloud-applied event yg fire BETWEEN getPremiumPayments() di line 16320
  // dan save sini tidak ke-wipe. Pattern: read-modify-write race. Sekarang
  // pakai indexed update via setPremiumPaymentStatus-style: re-read, merge
  // hanya entry yg kita modify, save merged result.
  if (dirty) {
    try {
      const fresh = getPremiumPayments();
      const byCode = new Map(fresh.map(p => [p.code, p]));
      for (const p of all) {
        if (p.activated && p.code) {
          const cur = byCode.get(p.code);
          if (cur) {
            // Apply our changes to the fresh copy
            cur.activated = true;
            cur.activatedAt = p.activatedAt;
            cur.updatedAt = p.updatedAt;
          } else {
            // Entry didn't exist in fresh (cloud-applied removed it?) — re-add
            byCode.set(p.code, p);
          }
        }
      }
      savePremiumPayments(Array.from(byCode.values()));
    } catch {}
  }

  return all
    .filter(p => p && p.email && deviceEmails.includes(String(p.email).toLowerCase()))
    .filter(p => !p.activated && !p.dismissed)
    .filter(p => ["pending", "approved", "rejected"].includes(p.status))
    .sort((a, b) => (b.paidAt || 0) - (a.paidAt || 0))[0] || null;
}

function renderAuthPaymentBanner() {
  const banner = document.getElementById("authPaymentBanner");
  const pill = document.getElementById("authTopbarPaymentPill");
  if (!banner) return;

  // Admin login page (/admin) — hide banner. Premium payment status is
  // user-side info; admin verifies others' payments via admin queue, not here.
  if (typeof pickedRole !== "undefined" && pickedRole === "admin") {
    banner.hidden = true;
    if (pill) pill.hidden = true;
    if (_authPaymentPollTimer) {
      clearInterval(_authPaymentPollTimer);
      _authPaymentPollTimer = null;
    }
    return;
  }

  const p = findAuthScreenPayment();
  // Pill di halaman login hanya untuk user baru yang masih nunggu konfirmasi
  // admin (status === "pending"). Begitu admin approve/reject, auth pill
  // disembunyikan — user login biasa, dashboard pill yang tampilin status final.
  // Juga sembunyiin kalau user udah punya session aktif (sudah masuk dashboard).
  const hasActiveSession = (typeof user === "object" && user && user.email);
  const isPendingNewSignup = p && p.status === "pending";
  if (!p || hasActiveSession || !isPendingNewSignup) {
    banner.hidden = true;
    if (pill) pill.hidden = true;
    if (_authPaymentPollTimer) {
      clearInterval(_authPaymentPollTimer);
      _authPaymentPollTimer = null;
    }
    return;
  }

  // Sync topbar quick-access pill — same status as banner.
  if (pill) {
    const isID2 = (typeof currentLang === "function") ? (currentLang() === "id") : true;
    pill.hidden = false;
    pill.dataset.status = p.status;
    const iconMap = { pending: "⏳", approved: "⭐", rejected: "✕" };
    const labelMap = isID2
      ? { pending: "Pembayaran", approved: "Pembayaran", rejected: "Pembayaran" }
      : { pending: "Payment",    approved: "Payment",    rejected: "Payment"    };
    const statusMap = isID2
      ? { pending: "Diverifikasi", approved: "Disetujui", rejected: "Ditolak" }
      : { pending: "Verifying",    approved: "Approved",  rejected: "Rejected" };
    const setP = (id, txt) => { const el = document.getElementById(id); if (el) el.textContent = txt; };
    setP("atppIcon",   iconMap[p.status]   || "⏳");
    setP("atppLabel",  labelMap[p.status]  || labelMap.pending);
    setP("atppStatus", statusMap[p.status] || statusMap.pending);
    const dot = document.getElementById("atppDot");
    if (dot) dot.dataset.status = p.status;
  }

  // Sync popup modal kalau function tersedia (auto-update saat polling)
  try { if (typeof renderPaymentStatusModal === "function") renderPaymentStatusModal(); } catch {}

  const isID = (typeof currentLang === "function") ? (currentLang() === "id") : true;
  const planNameMap = {
    monthly:  isID ? "Playly Premium · Bulanan"      : "Playly Premium · Monthly",
    yearly:   isID ? "Playly Premium · Tahunan"      : "Playly Premium · Yearly",
    lifetime: isID ? "Playly Premium · Seumur Hidup" : "Playly Premium · Lifetime",
  };
  const plan = (p.plan && PREMIUM_PLANS[p.plan]) || PREMIUM_PLANS.monthly;
  const amountLabel = plan.priceLabel || `$${(p.amount || plan.price).toFixed(2)}`;

  banner.hidden = false;
  banner.dataset.status = p.status;

  const set = (id, txt) => { const el = document.getElementById(id); if (el) el.textContent = txt; };
  set("apbCode", p.code);
  set("apbPlan", planNameMap[p.plan] || planNameMap.monthly);
  set("apbAmount", amountLabel);

  const badgeEl = document.getElementById("apbStatusBadge");
  if (badgeEl) badgeEl.dataset.status = p.status;

  const actions = document.getElementById("apbActions");
  if (actions) actions.innerHTML = "";

  if (p.status === "pending") {
    set("apbIcon", "⏳");
    set("apbTitle", isID ? "Pembayaran sedang diverifikasi" : "Payment under review");
    set("apbStatusBadge", isID ? "Pending" : "Pending");
    // Flow per user request 2026-05-06:
    //   1. Code TIDAK ditampilkan ke user sampai admin klik "Kirim Kode" → set codeSentToUser
    //   2. Setelah dikirim → user ketik ulang kode → submit
    //   3. Admin verify match → approve
    const hasTyped = !!p.userTypedCode;
    const codeSent = !!p.codeSentToUser;
    // Sembunyikan kode di apbCode element kalau admin belum kirim
    set("apbCode", codeSent ? p.code : (isID ? "•••••••••" : "•••••••••"));
    if (!codeSent) {
      set("apbDesc", isID
        ? "Pembayaran kamu sudah masuk. Tunggu admin verifikasi & mengirim kode konfirmasi ke kamu."
        : "Your payment is recorded. Wait for admin to verify & send the confirmation code to you.");
    } else if (hasTyped) {
      set("apbDesc", isID
        ? `✓ Kode "${p.userTypedCode}" sudah kamu kirim ke admin. Tunggu admin memeriksa & meng-approve.`
        : `✓ Code "${p.userTypedCode}" submitted to admin. Wait for admin to verify & approve.`);
    } else {
      set("apbDesc", isID
        ? `Admin sudah kirim kode konfirmasi. Ketik ulang kode ${p.code} di bawah lalu klik Kirim.`
        : `Admin sent the confirmation code. Re-type code ${p.code} below then click Send.`);
    }
    if (actions) {
      if (!codeSent) {
        // Belum ada input — cuma refresh button
        actions.innerHTML =
          '<button type="button" class="apb-btn apb-btn-ghost" data-apb-action="refresh" data-apb-code="' + p.code + '">' +
          (isID ? "Refresh" : "Refresh") + '</button>';
      } else if (hasTyped) {
        actions.innerHTML =
          '<button type="button" class="apb-btn apb-btn-ghost" data-apb-action="refresh" data-apb-code="' + p.code + '">' +
          (isID ? "Refresh" : "Refresh") + '</button>';
      } else {
        actions.innerHTML =
          '<div class="apb-code-input-row" style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;width:100%">' +
            '<input type="text" class="apb-code-input" data-apb-code-input data-apb-code="' + p.code + '" ' +
              'placeholder="' + (isID ? "Ketik kode di sini" : "Type code here") + '" ' +
              'maxlength="16" autocomplete="off" spellcheck="false" ' +
              'style="flex:1;min-width:160px;padding:10px 14px;border-radius:10px;border:1px solid var(--border);background:var(--surface);color:var(--text);font-family:monospace;font-size:14px;letter-spacing:1.5px;text-transform:uppercase"/>' +
            '<button type="button" class="apb-btn apb-btn-primary" data-apb-action="submit-code" data-apb-code="' + p.code + '">' +
              (isID ? "Kirim ke Admin" : "Send to Admin") + '</button>' +
          '</div>';
      }
    }
    if (!_authPaymentPollTimer) {
      _authPaymentPollTimer = setInterval(() => {
        try { renderAuthPaymentBanner(); } catch {}
      }, 5000);
    }
  } else if (p.status === "approved") {
    set("apbIcon", "✅");
    set("apbTitle", isID ? "Pembayaran disetujui!" : "Payment approved!");
    set("apbStatusBadge", isID ? "Approved" : "Approved");
    const acctLine = (p.username || p.email)
      ? (isID
          ? `Untuk akun: ${p.username ? "@" + p.username : ""}${p.username && p.email ? " · " : ""}${p.email || ""}. `
          : `For account: ${p.username ? "@" + p.username : ""}${p.username && p.email ? " · " : ""}${p.email || ""}. `)
      : "";
    set("apbDesc", acctLine + (isID
      ? "Klik Aktifkan Premium untuk masuk ke akun kamu sebagai user Premium."
      : "Click Activate Premium to sign in to your account as a Premium user."));
    if (actions) {
      actions.innerHTML =
        '<button type="button" class="apb-btn apb-btn-primary" data-apb-action="activate" data-apb-code="' + p.code + '">' +
        (isID ? "Aktifkan Premium" : "Activate Premium") + '</button>';
    }
    if (_authPaymentPollTimer) { clearInterval(_authPaymentPollTimer); _authPaymentPollTimer = null; }
  } else if (p.status === "rejected") {
    set("apbIcon", "❌");
    set("apbTitle", isID ? "Pembayaran ditolak" : "Payment rejected");
    set("apbStatusBadge", isID ? "Rejected" : "Rejected");
    set("apbDesc", isID
      ? "Admin menolak pembayaran ini. Silakan hubungi support atau coba lagi."
      : "Admin rejected this payment. Please contact support or try again.");
    if (actions) {
      actions.innerHTML =
        '<button type="button" class="apb-btn apb-btn-ghost" data-apb-action="dismiss" data-apb-code="' + p.code + '">' +
        (isID ? "Tutup" : "Dismiss") + '</button>';
    }
    if (_authPaymentPollTimer) { clearInterval(_authPaymentPollTimer); _authPaymentPollTimer = null; }
  }
}

// =================== PREMIUM ACTIVATION CELEBRATION ===================
// Animated wine+gold popup (slate+blue for admin) when a user transitions
// to Premium. Confetti rain + radial bursts + icon pop + title shimmer.
// Triggered automatically by setPremiumPaymentStatus when status changes
// to "approved" for the active session, OR manually via openPremiumCelebration.
function openPremiumCelebration(planKey) {
  const modal = document.getElementById("premiumCelebrationModal");
  if (!modal) return;
  // Plan name label
  const planEl = document.getElementById("premiumCelebPlan");
  const isID = (typeof currentLang === "function") ? (currentLang() === "id") : true;
  const planNameMap = {
    monthly:  isID ? "Playly Premium · Bulanan"      : "Playly Premium · Monthly",
    yearly:   isID ? "Playly Premium · Tahunan"      : "Playly Premium · Yearly",
    lifetime: isID ? "Playly Premium · Seumur Hidup" : "Playly Premium · Lifetime",
    trial:    isID ? "Playly Premium · Free Trial"   : "Playly Premium · Free Trial",
  };
  if (planEl) planEl.textContent = planNameMap[planKey] || "Playly Premium";

  // Generate confetti pieces — randomized colors + positions matching theme
  const isAdmin = document.body?.dataset?.role === "admin";
  const palette = isAdmin
    ? ["#7EB4F0", "#C0D4F0", "#283676", "#DCD3A9", "#F0EBD3"]
    : ["#E8C88C", "#F0D89B", "#561C24", "#3e0e0b", "#C7B7A3"];
  const confetti = document.getElementById("premiumCelebConfetti");
  if (confetti) {
    confetti.innerHTML = "";
    for (let i = 0; i < 36; i++) {
      const piece = document.createElement("span");
      piece.style.left = (Math.random() * 100) + "%";
      piece.style.background = palette[i % palette.length];
      piece.style.animationDelay = (Math.random() * 1.2) + "s";
      piece.style.animationDuration = (2.4 + Math.random() * 1.6) + "s";
      piece.style.transform = "rotate(" + (Math.random() * 360) + "deg)";
      confetti.appendChild(piece);
    }
  }

  modal.classList.add("show");
  document.body.style.overflow = "hidden";

  // Bind close handlers (idempotent)
  if (!modal.dataset._bound) {
    modal.dataset._bound = "1";
    modal.querySelectorAll("[data-close]").forEach(el => {
      el.addEventListener("click", e => {
        e.preventDefault();
        closePremiumCelebration();
      });
    });
  }
}
function closePremiumCelebration() {
  const modal = document.getElementById("premiumCelebrationModal");
  if (!modal) return;
  modal.classList.remove("show");
  document.body.style.overflow = "";
  // Stop confetti to free CPU
  const confetti = document.getElementById("premiumCelebConfetti");
  if (confetti) confetti.innerHTML = "";
}

// =================== DASHBOARD TOPBAR PAYMENT PILL ===================
// Mirrors authTopbarPaymentPill but lives inside the user dashboard topbar
// (next to theme toggle / bell). Shows latest premium payment for the
// signed-in user — pending → poll for status; approved → click to view;
// rejected → click to dismiss. Auto-hides for admin role.
let _dashboardPaymentPollTimer = null;

function findDashboardPayment() {
  if (typeof user !== "object" || !user || user.role === "admin") return null;
  const email = String(user.email || "").toLowerCase();
  if (!email) return null;
  const all = (typeof getPremiumPayments === "function") ? getPremiumPayments() : [];
  return all
    .filter(p => p && p.email && String(p.email).toLowerCase() === email)
    .filter(p => !p.activated && !p.dismissed)
    .filter(p => ["pending", "approved", "rejected"].includes(p.status))
    .sort((a, b) => (b.paidAt || 0) - (a.paidAt || 0))[0] || null;
}

function renderDashboardPaymentPill() {
  const pill = document.getElementById("dashboardPaymentPill");
  if (!pill) return;
  const p = findDashboardPayment();
  if (!p) {
    pill.hidden = true;
    if (_dashboardPaymentPollTimer) { clearInterval(_dashboardPaymentPollTimer); _dashboardPaymentPollTimer = null; }
    return;
  }
  const isID = (typeof currentLang === "function") ? (currentLang() === "id") : true;
  // Removed checkmark (✅) from approved per request — use star (⭐) instead.
  const iconMap  = { pending: "⏳", approved: "⭐", rejected: "✕" };
  const labelMap = isID
    ? { pending: "Pembayaran",  approved: "Premium aktif!",   rejected: "Pembayaran" }
    : { pending: "Payment",     approved: "Premium active!",  rejected: "Payment"    };
  const statusMap = isID
    ? { pending: "Diverifikasi", approved: "Klik lihat", rejected: "Ditolak" }
    : { pending: "Verifying",    approved: "Click view", rejected: "Rejected" };
  pill.hidden = false;
  pill.dataset.status = p.status;
  pill.dataset.code = p.code;
  pill.innerHTML =
    '<span class="atpp-icon">' + (iconMap[p.status] || "⏳") + '</span>' +
    '<span class="atpp-text">' +
      '<span class="atpp-label">' + (labelMap[p.status] || labelMap.pending) + '</span>' +
      '<span class="atpp-status">' + (statusMap[p.status] || statusMap.pending) + '</span>' +
    '</span>' +
    '<span class="atpp-dot" data-status="' + p.status + '"></span>';
  if (!pill.dataset.bound) {
    pill.dataset.bound = "1";
    pill.addEventListener("click", e => {
      e.preventDefault();
      if (typeof openPaymentStatusModal === "function") openPaymentStatusModal();
    });
  }
  if (p.status === "pending") {
    if (!_dashboardPaymentPollTimer) {
      _dashboardPaymentPollTimer = setInterval(() => {
        const next = findDashboardPayment();
        if (!next || next.status !== "pending") renderDashboardPaymentPill();
      }, 5000);
    }
  } else if (_dashboardPaymentPollTimer) {
    clearInterval(_dashboardPaymentPollTimer);
    _dashboardPaymentPollTimer = null;
  }
}

// =================== DASHBOARD TOPBAR TIER PILL ===================
// Permanent indicator next to theme toggle yang nampilin tier akun aktif:
//   - Free   → label "Free", action = open plan picker (upgrade ke Premium)
//   - Premium → label "⭐ Premium", action = info tooltip / premium status
// Hidden untuk role admin (admin ga punya tier).
function renderDashboardTierPill() {
  const pill = document.getElementById("dashboardTierPill");
  if (!pill) return;
  if (typeof user !== "object" || !user || user.role === "admin") {
    pill.hidden = true;
    return;
  }
  const tier = (user.tier === "premium") ? "premium" : "free";
  const isID = (typeof currentLang === "function") ? (currentLang() === "id") : true;
  pill.hidden = false;
  pill.dataset.tier = tier;
  if (tier === "premium") {
    pill.innerHTML =
      '<span class="dtp-icon">⭐</span>' +
      '<span class="dtp-text">' +
        '<span class="dtp-label">Premium</span>' +
        '<span class="dtp-status">' + (isID ? "Aktif" : "Active") + '</span>' +
      '</span>';
    pill.title = isID ? "Akun Premium aktif" : "Premium account active";
  } else {
    // Audit 2026-05-25 req user — FINAL pilihan: opsi 2 (compact).
    // Icon ○ + label 1 kata "Gratis". Status text + badge + gradient
    // semua dihapus. Info Premium ada di tooltip hover. Bersih +
    // minimal di chrome topbar. Klik buka plan picker.
    pill.innerHTML =
      '<span class="dtp-icon">○</span>' +
      '<span class="dtp-text">' +
        '<span class="dtp-label">' + (isID ? "Gratis" : "Free") + '</span>' +
      '</span>';
    pill.title = isID ? "Klik untuk lihat opsi Premium" : "Click to see Premium options";
  }
  if (!pill.dataset.bound) {
    pill.dataset.bound = "1";
    pill.addEventListener("click", e => {
      e.preventDefault();
      const t = (user?.tier === "premium") ? "premium" : "free";
      if (t === "free") {
        if (typeof openPlanPicker === "function") openPlanPicker();
        else if (typeof openPaymentModal === "function") openPaymentModal("monthly");
      } else {
        // Premium → open detail popup with start/end dates
        openPremiumStatusPopup();
      }
    });
  }
}

// Premium status popup — info pop-up shown when user clicks Premium pill.
// Tampilin tanggal mulai + tanggal berakhir + plan + sisa hari.
function openPremiumStatusPopup() {
  const isID = (typeof currentLang === "function") ? (currentLang() === "id") : true;
  // Auto-create modal if not present
  let modal = document.getElementById("premiumStatusPopup");
  if (!modal) {
    modal = document.createElement("div");
    modal.id = "premiumStatusPopup";
    modal.className = "modal-overlay premium-status-popup";
    modal.innerHTML = `
      <div class="premium-status-card" role="dialog" aria-modal="true">
        <div class="psp-icon-burst" data-no-picon><svg viewBox="0 0 24 24" fill="#FFC94D" aria-hidden="true" style="width:1em;height:1em;display:block"><path d="M12 2l2.92 6.26 6.58.86-4.83 4.66 1.2 6.5L12 17.9 5.13 20.28l1.2-6.5L1.5 9.12l6.58-.86z"/></svg></div>
        <h3 class="psp-title">${isID ? "Akun Premium Aktif" : "Premium Account Active"}</h3>
        <p class="psp-subtitle" id="pspPlan">—</p>
        <div class="psp-dates">
          <div class="psp-date-row">
            <small>${isID ? "Mulai Premium" : "Premium Start"}</small>
            <b id="pspStart">—</b>
          </div>
          <div class="psp-date-row">
            <small>${isID ? "Berakhir / Selesai" : "End / Expires"}</small>
            <b id="pspEnd">—</b>
          </div>
          <div class="psp-date-row">
            <small>${isID ? "Sisa Waktu" : "Time Remaining"}</small>
            <b id="pspRemaining">—</b>
          </div>
        </div>
      </div>`;
    document.body.appendChild(modal);
    // Close on backdrop click only
    modal.addEventListener("click", e => {
      if (e.target === modal) {
        modal.classList.remove("show");
        document.body.style.overflow = "";
      }
    });
  }

  // Populate dates
  const startMs = Number(user?.premiumStartedAt) || 0;
  const endMs = Number(user?.premiumExpiresAt) || 0;
  const planKey = user?.premiumPlan || "monthly";
  const planLabel = isID
    ? ({ monthly: "Playly Premium · Bulanan", yearly: "Playly Premium · Tahunan", lifetime: "Playly Premium · Seumur Hidup", trial: "Playly Premium · Free Trial" })[planKey]
    : ({ monthly: "Playly Premium · Monthly", yearly: "Playly Premium · Yearly", lifetime: "Playly Premium · Lifetime", trial: "Playly Premium · Free Trial" })[planKey];
  const fmtDate = ms => {
    if (!ms) return "—";
    const d = new Date(ms);
    return d.toLocaleString(isID ? "id-ID" : "en-US", { day: "numeric", month: "long", year: "numeric" });
  };
  const fmtRemaining = () => {
    if (planKey === "lifetime") return isID ? "Seumur hidup" : "Lifetime";
    if (!endMs) return "—";
    const ms = endMs - Date.now();
    if (ms <= 0) return isID ? "⚠ Sudah berakhir" : "⚠ Expired";
    const days = Math.floor(ms / (1000 * 60 * 60 * 24));
    const hours = Math.floor((ms % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
    if (days > 0) return isID ? `${days} hari ${hours} jam` : `${days} days ${hours} hours`;
    return isID ? `${hours} jam` : `${hours} hours`;
  };
  const set = (id, txt) => { const el = document.getElementById(id); if (el) el.textContent = txt; };
  set("pspPlan", planLabel || (isID ? "Playly Premium" : "Playly Premium"));
  set("pspStart", fmtDate(startMs));
  set("pspEnd", planKey === "lifetime" ? (isID ? "Seumur hidup" : "Lifetime") : fmtDate(endMs));
  set("pspRemaining", fmtRemaining());

  modal.classList.add("show");
  document.body.style.overflow = "hidden";
}

function activateAuthScreenPayment(code) {
  const payment = getPremiumPaymentByCode(code);
  if (!payment || payment.status !== "approved") return;
  // C-2 H#5 fix (2026-05-21): lowercase email untuk consistency
  const email = String(payment.email || "").toLowerCase();
  if (!email) return;
  const accRaw = localStorage.getItem(`playly-account-${email}`);
  if (!accRaw) {
    if (typeof toast === "function") toast("⚠️ Akun tidak ditemukan di device ini", "warning");
    return;
  }
  const acc = JSON.parse(accRaw);
  acc.tier = "premium";
  acc.premiumPlan = payment.plan;
  // C-2 H#6 fix (2026-05-21): guard double-write — set hanya kalau belum ada
  if (!acc.premiumStartedAt) {
    acc.premiumStartedAt = Date.now();
    acc.premiumExpiresAt = (typeof computePremiumExpiry === "function")
      ? computePremiumExpiry(payment.plan) : null;
  }
  if (payment.plan === "trial") acc.trialUsed = true;
  localStorage.setItem(`playly-account-${email}`, JSON.stringify(acc));

  // Restore user session (signin programmatically)
  user = {
    name: acc.name,
    username: acc.username,
    email: acc.email,
    role: (typeof isAllowedAdminEmail === "function" && isAllowedAdminEmail(email)) ? "admin" : "user",
    tier: "premium",
    premiumPlan: payment.plan,
    premiumStartedAt: acc.premiumStartedAt,
    premiumExpiresAt: acc.premiumExpiresAt,
    joinedAt: acc.joinedAt,
    bio: acc.bio,
    avatar: acc.avatar,
  };
  localStorage.setItem("playly-user", JSON.stringify(user));
  if (typeof loadState === "function") state = loadState(user.username);

  markPaymentActivated(code);
  if (typeof toast === "function") toast("⭐ Premium aktif! Selamat datang kembali.", "success");
  bootDashboard();
}

// Click delegation for banner action buttons
document.addEventListener("click", (e) => {
  const btn = e.target.closest("[data-apb-action]");
  if (!btn) return;
  e.preventDefault();
  const action = btn.dataset.apbAction;
  const code = btn.dataset.apbCode;
  if (action === "activate") activateAuthScreenPayment(code);
  else if (action === "dismiss") { dismissPaymentRecord(code); renderAuthPaymentBanner(); }
  else if (action === "refresh") { renderAuthPaymentBanner(); }
  else if (action === "submit-code") {
    // User submit kode verifikasi yang admin minta. Cari payment record + simpan
    // p.userTypedCode + p.userTypedAt. Admin nantinya verifikasi match di modal.
    const wrap = btn.closest(".apb-code-input-row") || document;
    const input = wrap.querySelector('[data-apb-code-input]');
    const typed = (input?.value || "").trim().toUpperCase();
    if (!typed) {
      if (typeof toast === "function") toast("⚠ Ketik kode dulu sebelum kirim", "warning");
      return;
    }
    const arr = getPremiumPayments();
    const idx = arr.findIndex(x => x.code === code);
    if (idx === -1) return;
    arr[idx].userTypedCode = typed;
    arr[idx].userTypedAt = Date.now();
    savePremiumPayments(arr);
    if (typeof toast === "function") {
      const isID2 = (typeof currentLang === "function") ? (currentLang() === "id") : true;
      toast(isID2 ? "✓ Kode terkirim ke admin. Tunggu verifikasi." : "✓ Code submitted to admin. Awaiting verification.", "success");
    }
    renderAuthPaymentBanner();
    try { if (typeof renderPaymentStatusModal === "function") renderPaymentStatusModal(); } catch {}
  }
});

// Topbar payment pill — click → buka popup modal detail status pembayaran.
// Konten popup di-render dari findAuthScreenPayment() (sumber data sama dgn
// banner di auth card). Modal pakai class .show seperti modal lain.
document.addEventListener("click", (e) => {
  const pill = e.target.closest("#authTopbarPaymentPill");
  if (pill) {
    e.preventDefault();
    e.stopPropagation();
    openPaymentStatusModal();
    return;
  }
  // Close handler untuk popup (pakai delegation karena modal tidak ada saat
  // page load — handler global di line ~28999 cuma scan once.)
  const closeBtn = e.target.closest("#paymentStatusModal [data-close]");
  if (closeBtn) {
    e.preventDefault();
    document.getElementById("paymentStatusModal")?.classList.remove("show");
    return;
  }
  // Action button dalam popup (refresh/activate/dismiss)
  const psmBtn = e.target.closest("#paymentStatusModal [data-psm-action]");
  if (psmBtn) {
    e.preventDefault();
    const action = psmBtn.dataset.psmAction;
    const code = psmBtn.dataset.psmCode;
    if (action === "activate" && typeof activateAuthScreenPayment === "function") {
      activateAuthScreenPayment(code);
      document.getElementById("paymentStatusModal")?.classList.remove("show");
    } else if (action === "dismiss" && typeof dismissPaymentRecord === "function") {
      dismissPaymentRecord(code);
      try { renderAuthPaymentBanner(); } catch {}
      document.getElementById("paymentStatusModal")?.classList.remove("show");
    } else if (action === "refresh") {
      try { renderAuthPaymentBanner(); } catch {}
      try { renderPaymentStatusModal(); } catch {}
    } else if (action === "support") {
      openSupportChannelPicker(code);
    } else if (action === "submit-code") {
      const modal = document.getElementById("paymentStatusModal");
      const input = modal?.querySelector('[data-psm-code-input]');
      const typed = (input?.value || "").trim().toUpperCase();
      const isID3 = (typeof currentLang === "function") ? (currentLang() === "id") : true;
      if (!typed) {
        if (typeof toast === "function") toast(isID3 ? "⚠ Ketik kode dulu sebelum kirim" : "⚠ Enter the code before submitting", "warning");
        return;
      }
      const arr = getPremiumPayments();
      const idx = arr.findIndex(x => x.code === code);
      if (idx === -1) return;
      const p2 = arr[idx];
      const isMatch = typed === String(p2.code).toUpperCase();
      if (!isMatch) {
        // Kode salah — shake input + toast error
        if (input) {
          input.style.borderColor = "var(--danger, #d83a3a)";
          input.animate([{ transform: "translateX(-5px)" }, { transform: "translateX(5px)" },
            { transform: "translateX(-4px)" }, { transform: "translateX(4px)" },
            { transform: "translateX(0)" }], { duration: 320, easing: "ease-out" });
          setTimeout(() => { input.style.borderColor = ""; }, 1500);
        }
        if (typeof toast === "function") toast(isID3 ? "✕ Kode salah. Periksa kembali." : "✕ Wrong code. Please check again.", "error");
        return;
      }
      // Kode cocok — simpan, tutup modal, arahkan ke sign-in
      arr[idx].userTypedCode = typed;
      arr[idx].userTypedAt = Date.now();
      savePremiumPayments(arr);
      modal?.classList.remove("show");
      try { renderAuthPaymentBanner(); } catch {}
      if (typeof toast === "function") {
        toast(isID3 ? "✓ Kode benar! Silakan masuk ke akun kamu." : "✓ Code verified! Please sign in to your account.", "success");
      }
      // Buka sign-in modal dan pre-isi email dari record payment
      setTimeout(() => {
        if (typeof openAuthModal === "function") openAuthModal("signin");
        // Pre-fill email di form signin
        const emailInput = document.querySelector('#signinForm input[name="email"]');
        if (emailInput && p2.email) emailInput.value = p2.email;
      }, 350);
    }
  }
});

// =================== SUPPORT CHANNEL PICKER ===================
// Replaces the old direct-to-email flow. Now: klik "hubungi support" →
// popup pilihan 2 channel (Email / Live Chat). User pilih →
// route ke flow yang sesuai dengan payment context pre-filled.

function _buildSupportContext(code) {
  const payment = (typeof getPremiumPaymentByCode === "function" && code)
    ? getPremiumPaymentByCode(code)
    : (typeof findAuthScreenPayment === "function" ? findAuthScreenPayment() : null);

  const isID = (typeof currentLang === "function") ? (currentLang() === "id") : true;
  const planNameMap = {
    monthly:  isID ? "Playly Premium · Bulanan"      : "Playly Premium · Monthly",
    yearly:   isID ? "Playly Premium · Tahunan"      : "Playly Premium · Yearly",
    lifetime: isID ? "Playly Premium · Seumur Hidup" : "Playly Premium · Lifetime",
  };
  const planKey = payment?.plan || "monthly";
  const plan = (typeof PREMIUM_PLANS !== "undefined" && PREMIUM_PLANS[planKey])
    || (typeof PREMIUM_PLANS !== "undefined" ? PREMIUM_PLANS.monthly : { priceLabel: "$9.99", price: 9.99 });
  const statusLabel = isID
    ? ({ pending: "Menunggu verifikasi admin", approved: "Sudah disetujui", rejected: "Ditolak" }[payment?.status] || payment?.status || "—")
    : (payment?.status || "—");

  return {
    payment,
    isID,
    code: payment?.code || "—",
    planKey,
    planLabel: planNameMap[planKey] || planNameMap.monthly,
    amountLabel: plan.priceLabel || `$${(payment?.amount || plan.price || 9.99).toFixed(2)}`,
    statusLabel,
    email: payment?.email || "—",
  };
}

function openSupportChannelPicker(code) {
  // Cache the context so channel handlers can reuse without rebuild
  window._supportChannelCtx = _buildSupportContext(code);
  // Close payment status modal so picker sits on top
  document.getElementById("paymentStatusModal")?.classList.remove("show");
  const modal = document.getElementById("supportChannelModal");
  if (!modal) return;
  modal.classList.add("show");
}

function closeSupportChannelPicker() {
  document.getElementById("supportChannelModal")?.classList.remove("show");
}

// Click delegation: channel cards + close button
document.addEventListener("click", (e) => {
  // Close handler
  if (e.target.closest('#supportChannelModal [data-close]')) {
    e.preventDefault();
    closeSupportChannelPicker();
    return;
  }
  // Channel pick
  const card = e.target.closest("#supportChannelModal [data-support-channel]");
  if (!card) return;
  e.preventDefault();
  const channel = card.dataset.supportChannel;
  const ctx = window._supportChannelCtx || _buildSupportContext();
  closeSupportChannelPicker();

  if (channel === "email") {
    _openSupportViaEmail(ctx);
  } else if (channel === "chat") {
    _openSupportViaLiveChat(ctx);
  }
});

function _openSupportViaEmail(ctx) {
  const subjectDefault = ctx.isID
    ? `[${ctx.code}] Bantuan pembayaran Premium`
    : `[${ctx.code}] Premium payment support`;
  const bodyDefault = ctx.isID
    ? `Halo Admin Playly,\n\n` +
      `Saya butuh bantuan terkait pembayaran berikut:\n\n` +
      `• Kode verifikasi : ${ctx.code}\n` +
      `• Paket           : ${ctx.planLabel}\n` +
      `• Jumlah          : ${ctx.amountLabel}\n` +
      `• Status saat ini : ${ctx.statusLabel}\n` +
      `• Email akun      : ${ctx.email}\n\n` +
      `Detail keluhan / pertanyaan saya:\n[Tulis di sini...]`
    : `Hello Playly Admin,\n\n` +
      `I need help with the following payment:\n\n` +
      `• Verification code : ${ctx.code}\n` +
      `• Plan              : ${ctx.planLabel}\n` +
      `• Amount            : ${ctx.amountLabel}\n` +
      `• Current status    : ${ctx.statusLabel}\n` +
      `• Account email     : ${ctx.email}\n\n` +
      `My issue / question:\n[Type here...]`;

  if (typeof openSupportCompose === "function") {
    openSupportCompose({
      type: "email",
      subjectDefault,
      bodyDefault,
      title: ctx.isID ? "Email Admin · Pembayaran" : "Email Admin · Payment",
      desc:  ctx.isID
        ? "Pesanmu masuk langsung ke Email Inbox admin. Biasanya dibalas dalam 1 jam."
        : "Your message goes to admin Email Inbox. Usually replied within 1 hour.",
      icon:  "📧",
      // Pass payment code supaya proof field di form jadi visible + auto-attach
      // bukti yang sudah disimpan di payment record (kalau ada).
      paymentCode: ctx.code !== "—" ? ctx.code : null,
    });
  } else if (typeof toast === "function") {
    toast(ctx.isID ? "⚠️ Modal email support tidak tersedia." : "⚠️ Email modal unavailable.", "warning");
  }
}

function _openSupportViaLiveChat(ctx) {
  // Live Chat = DM admin di dashboard. Butuh user logged in + dashboard mounted.
  const onAuthScreen = document.body.classList.contains("auth-mode");
  if (onAuthScreen || !user) {
    if (typeof toast === "function") {
      toast(ctx.isID
        ? "💬 Live Chat butuh login dulu — masuk ke dashboard, lalu buka menu Messages."
        : "💬 Live Chat requires login — sign in, then open Messages.",
        "info");
    }
    return;
  }
  // Switch ke messages view + buka thread admin (kalau ada helper)
  if (typeof switchView === "function") switchView("messages");
  // Coba buka DM thread ke admin via fungsi yang sudah ada (kalau tersedia)
  if (typeof openDmThreadWithUsername === "function") {
    setTimeout(() => openDmThreadWithUsername("admin"), 80);
  } else if (typeof toast === "function") {
    toast(ctx.isID ? "💬 Buka DM dengan @admin di Messages" : "💬 Open DM with @admin in Messages", "info");
  }
}

// Render konten popup payment status — di-call saat user klik pill DAN setiap
// kali renderAuthPaymentBanner() jalan (supaya popup auto-update saat polling
// 5-detik mengubah status pending → approved/rejected).
function renderPaymentStatusModal() {
  const modal = document.getElementById("paymentStatusModal");
  if (!modal) return;
  // Prefer per-user dashboard payment when a user is signed in (avoids leaking
  // OTHER device-account payments into the active session's modal). Fall back
  // to device-wide lookup for the auth-screen banner case (no logged-in user).
  let p = null;
  if (typeof findDashboardPayment === "function" && typeof user === "object" && user) {
    p = findDashboardPayment();
  }
  if (!p && typeof findAuthScreenPayment === "function") p = findAuthScreenPayment();
  if (!p) {
    // Tidak ada record — tutup popup kalau sedang terbuka
    modal.classList.remove("show");
    return;
  }
  const isID = (typeof currentLang === "function") ? (currentLang() === "id") : true;
  const planNameMap = {
    monthly:  isID ? "Playly Premium · Bulanan"      : "Playly Premium · Monthly",
    yearly:   isID ? "Playly Premium · Tahunan"      : "Playly Premium · Yearly",
    lifetime: isID ? "Playly Premium · Seumur Hidup" : "Playly Premium · Lifetime",
  };
  const plan = (p.plan && typeof PREMIUM_PLANS !== "undefined" && PREMIUM_PLANS[p.plan]) || (typeof PREMIUM_PLANS !== "undefined" ? PREMIUM_PLANS.monthly : { priceLabel: "$9.99" });
  const amountLabel = plan.priceLabel || (`$${(p.amount || plan.price || 9.99).toFixed(2)}`);

  const set = (id, txt) => { const el = document.getElementById(id); if (el) el.textContent = txt; };
  const setHTML = (id, html) => { const el = document.getElementById(id); if (el) el.innerHTML = html; };

  // Header tinted by status
  const header = document.getElementById("psmHeader");
  if (header) header.dataset.status = p.status;
  const badgeEl = document.getElementById("psmStatusBadge");
  if (badgeEl) badgeEl.dataset.status = p.status;

  // Status-specific icon + title + desc + badge label
  const titleMap = isID
    ? { pending: "Pembayaran sedang diverifikasi", approved: "Pembayaran disetujui!", rejected: "Pembayaran ditolak" }
    : { pending: "Payment under review",            approved: "Payment approved!",     rejected: "Payment rejected"   };
  const iconMap   = { pending: "⏳", approved: "✅", rejected: "✕" };
  const badgeMap  = isID
    ? { pending: "Pending",  approved: "Disetujui", rejected: "Ditolak"  }
    : { pending: "Pending",  approved: "Approved",  rejected: "Rejected" };
  const acctLinePsm = (p.username || p.email)
    ? (isID
        ? `Untuk akun: ${p.username ? "@" + p.username : ""}${p.username && p.email ? " · " : ""}${p.email || ""}. `
        : `For account: ${p.username ? "@" + p.username : ""}${p.username && p.email ? " · " : ""}${p.email || ""}. `)
    : "";
  const codeSent = !!p.codeSentToUser;
  // Pending desc differs by codeSent state — kalau belum dikirim, jangan
  // suruh user ketik (toh codenya juga di-mask). Per user request 2026-05-06.
  const pendingDescSent = isID
    ? "Admin sudah kirim kode konfirmasi. Ketik ulang kode di atas lalu klik Kirim ke Admin."
    : "Admin sent the confirmation code. Re-type the code above then click Send to Admin.";
  const pendingDescWait = isID
    ? "Pembayaran kamu sudah masuk. Tunggu admin verifikasi & mengirim kode konfirmasi ke kamu."
    : "Your payment is recorded. Wait for admin to verify & send the confirmation code to you.";
  const descMap   = isID
    ? {
        pending:  codeSent ? pendingDescSent : pendingDescWait,
        approved: acctLinePsm + "Klik Aktifkan Premium untuk masuk ke akun kamu sebagai user Premium.",
        rejected: "Pembayaranmu ditolak admin. Hubungi support untuk klarifikasi atau ajukan ulang.",
      }
    : {
        pending:  codeSent ? pendingDescSent : pendingDescWait,
        approved: acctLinePsm + "Click Activate Premium to sign in to your account as a Premium user.",
        rejected: "Your payment was rejected by admin. Contact support for clarification or resubmit.",
      };

  set("psmIcon",   iconMap[p.status]   || "⏳");
  set("psmTitle",  titleMap[p.status]  || titleMap.pending);
  set("psmStatusBadge", badgeMap[p.status] || badgeMap.pending);
  set("psmDesc",   descMap[p.status]   || descMap.pending);
  // MASK code if admin hasn't sent it yet — user must wait for admin to release it
  set("psmCode",   (p.status === "pending" && !codeSent) ? "•••••••••" : p.code);
  set("psmPlan",   planNameMap[p.plan] || planNameMap.monthly);
  set("psmAmount", amountLabel);
  // Akun row — tampilkan @username (+ email) supaya user tahu pembayaran ini
  // untuk akun mana. Per request user 2026-05-11.
  const psmUserLabel = p.username
    ? "@" + p.username + (p.email ? " · " + p.email : "")
    : (p.email || "—");
  set("psmUser", psmUserLabel);

  // Action buttons per status
  const actionsHTML = (() => {
    const refreshLabel = isID ? "Refresh Status" : "Refresh Status";
    const activateLabel = isID ? "Aktifkan Premium" : "Activate Premium";
    const dismissLabel = isID ? "Tutup Notifikasi" : "Dismiss";
    if (p.status === "pending") {
      // Step 0: admin belum kirim kode → cuma refresh button
      if (!codeSent) {
        const waitMsg = isID
          ? "⏳ Menunggu admin mengirim kode konfirmasi…"
          : "⏳ Waiting for admin to send confirmation code…";
        return `<small class="muted" style="display:block;text-align:center;padding:8px">${waitMsg}</small>
          <button type="button" class="psm-action-ghost" data-psm-action="refresh" data-psm-code="${p.code}">↻ ${refreshLabel}</button>`;
      }
      // Step 1: admin sudah kirim, user belum ketik → tampilkan input
      // Step 2: user sudah ketik → tunggu admin verify
      if (p.userTypedCode) {
        const sentMsg = isID
          ? `✓ Kode "${escapeHtml(p.userTypedCode)}" terkirim. Tunggu admin approve.`
          : `✓ Code "${escapeHtml(p.userTypedCode)}" submitted. Wait for admin to approve.`;
        return `<small class="muted" style="display:block;text-align:center;padding:8px">${sentMsg}</small>
          <button type="button" class="psm-action-ghost" data-psm-action="refresh" data-psm-code="${p.code}">↻ ${refreshLabel}</button>`;
      }
      const promptLabel = isID ? "Ketik ulang kode di atas:" : "Re-type code above:";
      const sendLabel = isID ? "Kirim ke Admin" : "Send to Admin";
      return `
        <div style="display:flex;flex-direction:column;gap:8px;width:100%">
          <small class="muted" style="text-align:center">${promptLabel}</small>
          <div style="display:flex;gap:8px;flex-wrap:wrap">
            <input type="text" data-psm-code-input data-psm-code="${p.code}" placeholder="PLY-XXXXXXXX" maxlength="16" autocomplete="off" spellcheck="false" style="flex:1;min-width:140px;padding:10px 14px;border-radius:10px;border:1px solid var(--border);background:var(--surface);color:var(--text);font-family:monospace;font-size:14px;letter-spacing:1.5px;text-transform:uppercase"/>
            <button type="button" class="psm-action-success" data-psm-action="submit-code" data-psm-code="${p.code}">${sendLabel}</button>
          </div>
        </div>`;
    }
    if (p.status === "approved") {
      return `<button type="button" class="psm-action-success" data-psm-action="activate" data-psm-code="${p.code}">⭐ ${activateLabel}</button>`;
    }
    if (p.status === "rejected") {
      return `<button type="button" class="psm-action-ghost" data-psm-action="dismiss" data-psm-code="${p.code}">✕ ${dismissLabel}</button>`;
    }
    return "";
  })();
  setHTML("psmActions", actionsHTML);
}

function openPaymentStatusModal() {
  renderPaymentStatusModal();
  const modal = document.getElementById("paymentStatusModal");
  if (!modal) return;
  // Hanya show kalau ada record — kalau tidak, fungsi render sudah hide
  const hasRecord = (typeof findAuthScreenPayment === "function") ? !!findAuthScreenPayment() : false;
  if (hasRecord) modal.classList.add("show");
}

// =================== BILLING & REFUND HISTORY (shared) ===================
// Render transaction list (charge + refund-on-reject + approve events) into
// any container. Used in 2 places:
//   - Settings card (filtered by current user.email)
//   - Auth screen <details> (filtered by all device-account emails)
// Demo money, but log structure is production-ready.
function _escapeHtml(s) {
  return String(s == null ? "" : s)
    .replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;").replace(/'/g, "&#39;");
}
function _fmtMoney(n) {
  const v = Number(n) || 0;
  return "$" + (Math.abs(v) >= 100 && Number.isInteger(v) ? v.toFixed(0) : v.toFixed(2));
}
function _fmtDateTime(ts, isID) {
  if (!ts) return "—";
  try {
    return new Date(ts).toLocaleString(isID ? "id-ID" : "en-US", { dateStyle: "short", timeStyle: "short" });
  } catch { return "—"; }
}

function renderBillingHistory(opts = {}) {
  const { listEl, totalChargedEl, totalRefundedEl, netSpentEl, countEl, wrapperEl, emailFilter } = opts;
  if (!listEl) return;

  const isID = (typeof currentLang === "function") ? (currentLang() === "id") : true;

  // Filter records
  let records = (typeof getPremiumPayments === "function") ? getPremiumPayments() : [];
  if (Array.isArray(emailFilter) && emailFilter.length) {
    const set = new Set(emailFilter.map(e => String(e).toLowerCase()));
    records = records.filter(p => p && p.email && set.has(String(p.email).toLowerCase()));
  } else if (typeof emailFilter === "string" && emailFilter) {
    const wanted = emailFilter.toLowerCase();
    records = records.filter(p => p && p.email && String(p.email).toLowerCase() === wanted);
  } else if (Array.isArray(emailFilter) && !emailFilter.length) {
    records = []; // explicit empty filter → no records
  }
  records.sort((a, b) => (b.paidAt || 0) - (a.paidAt || 0));

  // Empty state
  if (!records.length) {
    if (wrapperEl) wrapperEl.hidden = true;
    listEl.innerHTML = `<div class="bl-empty">${isID ? "Belum ada transaksi pembayaran." : "No payment transactions yet."}</div>`;
    if (totalChargedEl)  totalChargedEl.textContent  = "$0.00";
    if (totalRefundedEl) totalRefundedEl.textContent = "$0.00";
    if (netSpentEl)      netSpentEl.textContent      = "$0.00";
    if (countEl)         countEl.textContent         = "0";
    return;
  }
  if (wrapperEl) wrapperEl.hidden = false;

  const planNameMap = {
    monthly:  isID ? "Bulanan"      : "Monthly",
    yearly:   isID ? "Tahunan"      : "Yearly",
    lifetime: isID ? "Seumur Hidup" : "Lifetime",
    trial:    isID ? "Uji Coba Gratis" : "Free Trial",
  };
  const statusText = {
    pending:  isID ? "Pending"   : "Pending",
    approved: isID ? "Disetujui" : "Approved",
    rejected: isID ? "Ditolak"   : "Rejected",
  };

  let totalCharged = 0;
  let totalRefunded = 0;
  const html = records.map(p => {
    const plan = (p.plan && PREMIUM_PLANS[p.plan]) || PREMIUM_PLANS.monthly;
    const amount = Number(p.amount) || Number(plan.price) || 0;
    totalCharged += amount;
    if (p.status === "rejected") totalRefunded += amount;

    const planLabel = planNameMap[p.plan] || planNameMap.monthly;

    const events = [];
    events.push(
      `<div class="bl-event" data-kind="charge"><span>${isID ? "Saldo dipotong" : "Charged"} · ${_fmtDateTime(p.paidAt, isID)}</span><b>−${_fmtMoney(amount)}</b></div>`
    );
    if (p.status === "approved" && p.processedAt) {
      events.push(
        `<div class="bl-event" data-kind="approve"><span>${isID ? "Disetujui admin · Premium aktif" : "Approved by admin · Premium activated"} · ${_fmtDateTime(p.processedAt, isID)}</span><b>—</b></div>`
      );
    }
    if (p.status === "rejected" && p.processedAt) {
      events.push(
        `<div class="bl-event" data-kind="refund"><span>${isID ? "Ditolak admin · Saldo dikembalikan" : "Rejected by admin · Refunded"} · ${_fmtDateTime(p.processedAt, isID)}</span><b>+${_fmtMoney(amount)}</b></div>`
      );
    }

    const netLabel = p.status === "rejected" ? "$0.00" : "−" + _fmtMoney(amount);

    return `
      <div class="bl-row" data-status="${_escapeHtml(p.status)}">
        <div class="bl-row-head">
          <div class="bl-code-block" style="display:flex; align-items:center; gap:8px; flex-wrap:wrap">
            <code class="bl-code">${_escapeHtml(p.code)}</code>
            <span class="bl-status-badge" data-status="${_escapeHtml(p.status)}">${_escapeHtml(statusText[p.status] || p.status)}</span>
          </div>
          <span class="bl-amount">${netLabel}</span>
        </div>
        <div class="bl-row-meta">
          <span>Playly Premium · ${_escapeHtml(planLabel)}</span>
          <span class="bl-divider">·</span>
          <span>${_escapeHtml(p.method || "—")}</span>
          ${p.email ? `<span class="bl-divider">·</span><span>${_escapeHtml(p.email)}</span>` : ""}
        </div>
        <div class="bl-events">${events.join("")}</div>
      </div>
    `;
  }).join("");

  listEl.innerHTML = html;
  if (totalChargedEl)  totalChargedEl.textContent  = _fmtMoney(totalCharged);
  if (totalRefundedEl) totalRefundedEl.textContent = _fmtMoney(totalRefunded);
  if (netSpentEl)      netSpentEl.textContent      = _fmtMoney(totalCharged - totalRefunded);
  if (countEl)         countEl.textContent         = String(records.length);
}

function renderSettingsBilling() {
  if (!user?.email) return;
  renderBillingHistory({
    listEl:           document.getElementById("billingList"),
    totalChargedEl:   document.getElementById("bsTotalCharged"),
    totalRefundedEl:  document.getElementById("bsTotalRefunded"),
    netSpentEl:       document.getElementById("bsNetSpent"),
    emailFilter:      user.email,
  });
}

// =================== ADMIN: PREMIUM VERIFICATION QUEUE ===================
let _adminPqFilter = "pending";
function renderAdminPremiumQueue() {
  const list = document.getElementById("premiumQueueList");
  if (!list) return;
  const all = getPremiumPayments();
  const pending  = all.filter(p => p.status === "pending");
  const approved = all.filter(p => p.status === "approved");
  const rejected = all.filter(p => p.status === "rejected");

  // Stats
  const setT = (id, n) => { const el = document.getElementById(id); if (el) el.textContent = n; };
  setT("pqStatPending", pending.length);
  setT("pqStatApproved", approved.length);
  setT("pqStatRejected", rejected.length);

  // Sidebar badge
  const badge = document.getElementById("adminPremiumBadge");
  if (badge) {
    badge.textContent = pending.length;
    badge.style.display = pending.length ? "" : "none";
  }

  // Filter
  let shown = all;
  if (_adminPqFilter === "pending")  shown = pending;
  else if (_adminPqFilter === "approved") shown = approved;
  else if (_adminPqFilter === "rejected") shown = rejected;

  const isIDQ = (typeof currentLang === "function") ? (currentLang() === "id") : true;
  if (!shown.length) {
    const emptyMsg = isIDQ ? "Tidak ada pembayaran di kategori ini." : "No payments in this category.";
    list.innerHTML = `<div class="pq-empty">${emptyMsg}</div>`;
    return;
  }

  list.innerHTML = shown.map(p => {
    const dt = new Date(p.paidAt);
    const pad = n => String(n).padStart(2, "0");
    const dateStr = `${pad(dt.getDate())}/${pad(dt.getMonth()+1)}/${dt.getFullYear()} ${pad(dt.getHours())}:${pad(dt.getMinutes())}`;
    const flowLabel = p.flowContext === "signup"
      ? (isIDQ ? "🆕 Signup baru" : "🆕 New signup")
      : (isIDQ ? "⬆️ Upgrade existing" : "⬆️ Existing upgrade");
    const userLabel = p.email || p.username || (p.flowContext === "signup"
      ? (isIDQ ? "Signup pending" : "Pending signup")
      : (isIDQ ? "Anonim" : "Anonymous"));
    const statusBadge = isIDQ
      ? (p.status === "approved" ? '<span class="pq-status pq-status-ok">✓ Disetujui</span>' :
         p.status === "rejected" ? '<span class="pq-status pq-status-bad">✕ Ditolak</span>' :
         '<span class="pq-status pq-status-pending">⏳ Pending</span>')
      : (p.status === "approved" ? '<span class="pq-status pq-status-ok">✓ Approved</span>' :
         p.status === "rejected" ? '<span class="pq-status pq-status-bad">✕ Rejected</span>' :
         '<span class="pq-status pq-status-pending">⏳ Pending</span>');
    // Code verification status indicator
    let codeIndicator = "";
    if (p.status === "pending") {
      if (p.userTypedCode) {
        const matches = String(p.userTypedCode).trim().toUpperCase() === String(p.code).toUpperCase();
        const matchTxt = isIDQ ? "✓ Kode user cocok" : "✓ User code matches";
        const failTxt = isIDQ ? "✗ Kode user salah" : "✗ User code wrong";
        codeIndicator = matches
          ? `<span class="pq-status pq-status-ok" style="font-size:10.5px">${matchTxt}</span>`
          : `<span class="pq-status pq-status-bad" style="font-size:10.5px">${failTxt}</span>`;
      } else {
        const waitTxt = isIDQ ? "⏳ Menunggu user ketik kode" : "⏳ Waiting for user to type code";
        codeIndicator = `<span class="pq-status pq-status-pending" style="font-size:10.5px">${waitTxt}</span>`;
      }
    }
    const orderLbl = isIDQ ? "Order ID" : "Order ID";
    const userLbl = isIDQ ? "User" : "User";
    const flowLbl = isIDQ ? "Alur" : "Flow";
    const methodLbl = isIDQ ? "Metode" : "Method";
    const amountLbl = isIDQ ? "Jumlah" : "Amount";
    const paidAtLbl = isIDQ ? "Dibayar pada" : "Paid at";
    const clickHint = isIDQ
      ? "🔍 Klik untuk lihat kode verifikasi + bukti pembayaran"
      : "🔍 Click to view verification code + payment proof";
    // Code REMOVED from row per user request 2026-05-06 — code only visible
    // when admin opens detail modal, not in queue row itself.
    const orderDisplay = p.orderId || (p.code ? `#${String(p.code).slice(-6)}` : "—");
    return `
      <div class="pq-row" data-status="${p.status}" data-pq-code="${escapeHtml(p.code)}" role="button" tabindex="0">
        <div class="pq-row-head">
          <div class="pq-code-block">
            <small class="pq-code-label">${orderLbl}</small>
            <code class="pq-code">#${escapeHtml(orderDisplay)}</code>
          </div>
          <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;justify-content:flex-end">
            ${codeIndicator}
            ${statusBadge}
          </div>
        </div>
        <div class="pq-row-detail">
          <div class="pq-cell"><small>${userLbl}</small><b>${escapeHtml(userLabel)}</b></div>
          <div class="pq-cell"><small>${flowLbl}</small><b>${flowLabel}</b></div>
          <div class="pq-cell"><small>${methodLbl}</small><b>${escapeHtml(p.method || "—")}</b></div>
          <div class="pq-cell"><small>${amountLbl}</small><b>$${(p.amount || 0).toFixed(2)}</b></div>
          <div class="pq-cell"><small>${paidAtLbl}</small><b>${dateStr}</b></div>
        </div>
        <div class="pq-actions pq-actions-done">
          <small class="muted">${clickHint}</small>
        </div>
      </div>`;
  }).join("");

  // Wire row click → open detail modal (replaces inline approve/reject buttons)
  list.querySelectorAll(".pq-row").forEach(row => {
    const code = row.dataset.pqCode;
    const open = () => openPremiumDetailModal(code);
    row.addEventListener("click", open);
    row.addEventListener("keydown", e => {
      if (e.key === "Enter" || e.key === " ") { e.preventDefault(); open(); }
    });
  });
}

// =================== PREMIUM VERIFICATION DETAIL MODAL ===================
// Click row di queue → open modal. Modal nampilin:
//   - Bukti pembayaran (proofImage dataURL, auto-generated saat user pay)
//   - Detail transaksi (email, plan, amount, dst.)
//   - Kode sistem (untuk diketik user) + kode yang user ketik (live status)
//   - Tombol Approve/Reject. Approve disabled kalau kode user belum cocok.
function openPremiumDetailModal(code) {
  const modal = document.getElementById("pqDetailModal");
  if (!modal) return;
  const p = (typeof getPremiumPaymentByCode === "function")
    ? getPremiumPaymentByCode(code)
    : (getPremiumPayments() || []).find(x => x.code === code);
  if (!p) return;

  const isID = (typeof currentLang === "function") ? (currentLang() === "id") : true;
  const set = (id, val) => { const el = document.getElementById(id); if (el) el.textContent = val; };
  const dt = new Date(p.paidAt);
  const pad = n => String(n).padStart(2, "0");
  const dateStr = `${pad(dt.getDate())}/${pad(dt.getMonth()+1)}/${dt.getFullYear()} ${pad(dt.getHours())}:${pad(dt.getMinutes())}`;

  // Status badge
  const statusEl = document.getElementById("pqdmStatus");
  if (statusEl) {
    statusEl.className = "pq-status " + (
      p.status === "approved" ? "pq-status-ok" :
      p.status === "rejected" ? "pq-status-bad" : "pq-status-pending"
    );
    statusEl.textContent = isID
      ? (p.status === "approved" ? "✓ Disetujui" : p.status === "rejected" ? "✕ Ditolak" : "⏳ Pending")
      : (p.status === "approved" ? "✓ Approved" : p.status === "rejected" ? "✕ Rejected" : "⏳ Pending");
  }

  set("pqdmUser", p.username ? `@${p.username}` : "—");
  set("pqdmEmail", p.email || "—");
  set("pqdmPlan", p.plan || "—");
  set("pqdmAmount", `$${(p.amount || 0).toFixed(2)}`);
  set("pqdmMethod", p.method || "—");
  set("pqdmPaidAt", dateStr);
  set("pqdmCodeSystem", p.code || "—");

  // Auto-regenerate proofImage jika belum ada (payment lama / canvas gagal saat pay)
  if (!p.proofImage && typeof generatePaymentReceiptImage === "function") {
    try {
      const regenerated = generatePaymentReceiptImage({
        code: p.code,
        orderId: p.orderId || String(p.paidAt).slice(-8),
        method: p.method || "—",
        plan: { price: p.amount || 0, priceLabel: `$${(p.amount || 0).toFixed(2)}` },
        planKey: p.plan || "monthly",
        paidAt: new Date(p.paidAt),
        email: p.email || "—",
        username: p.username || "—",
      });
      if (regenerated) {
        p.proofImage = regenerated;
        const arr = getPremiumPayments();
        const idx = arr.findIndex(x => x.code === p.code);
        if (idx !== -1) { arr[idx].proofImage = regenerated; savePremiumPayments(arr); }
      }
    } catch (e) { console.warn("[pqdm] regenerate proof failed:", e); }
  }

  // Receipt image
  const receiptWrap = document.getElementById("pqdmReceiptWrap");
  if (receiptWrap) {
    const altLbl = isID ? "Bukti pembayaran" : "Payment proof";
    const emptyLbl = isID ? "Bukti pembayaran belum di-generate untuk transaksi ini." : "Payment proof not yet generated for this transaction.";
    if (p.proofImage) {
      receiptWrap.innerHTML = `<img src="${p.proofImage}" alt="${altLbl} ${escapeHtml(p.code)}" title="${isID ? "Klik untuk perbesar" : "Click to enlarge"}"/>`;
      const img = receiptWrap.querySelector("img");
      if (img) {
        img.addEventListener("click", () => {
          const lb = document.createElement("div");
          lb.style.cssText = "position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,.88);display:flex;align-items:center;justify-content:center;cursor:zoom-out;backdrop-filter:blur(4px);-webkit-backdrop-filter:blur(4px);animation:fadeIn .18s ease-out";
          lb.innerHTML = `<img src="${p.proofImage}" alt="${altLbl}" style="max-width:92vw;max-height:90vh;border-radius:12px;box-shadow:0 24px 80px rgba(0,0,0,.8);display:block"/>`;
          lb.addEventListener("click", () => lb.remove());
          document.body.appendChild(lb);
        });
      }
    } else {
      receiptWrap.innerHTML = `<div class="pqdm-receipt-empty">${emptyLbl}</div>`;
    }
  }

  // User-typed code + match indicator
  const typedEl = document.getElementById("pqdmCodeTyped");
  const matchEl = document.getElementById("pqdmCodeMatch");
  const hasTyped = !!p.userTypedCode;
  const matches = hasTyped && String(p.userTypedCode).trim().toUpperCase() === String(p.code).toUpperCase();
  const codeSent = !!p.codeSentToUser;
  if (typedEl) {
    typedEl.textContent = hasTyped
      ? p.userTypedCode
      : (codeSent
          ? (isID ? "Kode sudah dikirim — menunggu user mengetik" : "Code sent — waiting for user to type")
          : (isID ? "Belum dikirim ke user" : "Not yet sent to user"));
    typedEl.dataset.state = !hasTyped ? "waiting" : (matches ? "match" : "mismatch");
  }
  if (matchEl) {
    if (!codeSent) {
      matchEl.dataset.state = "waiting";
      matchEl.textContent = isID
        ? "📤 Klik 'Kirim Kode ke User' supaya kode muncul di dashboard user, lalu user akan mengetik ulang sebagai konfirmasi."
        : "📤 Click 'Send Code to User' so the code appears in the user's dashboard, then user will re-type it as confirmation.";
    } else if (!hasTyped) {
      matchEl.dataset.state = "waiting";
      matchEl.textContent = isID
        ? "⏳ Kode sudah dikirim — tunggu user mengetik kode di dashboard mereka."
        : "⏳ Code sent — waiting for user to type the code in their dashboard.";
    } else if (matches) {
      matchEl.dataset.state = "match";
      matchEl.textContent = isID
        ? "✓ Kode cocok — siap di-approve."
        : "✓ Code matches — ready to approve.";
    } else {
      matchEl.dataset.state = "mismatch";
      matchEl.textContent = isID
        ? "✗ Kode user TIDAK cocok dengan kode sistem — verifikasi gagal."
        : "✗ User's code does NOT match system code — verification failed.";
    }
  }

  // Action buttons (admin only when status=pending)
  const actionsEl = document.getElementById("pqdmActions");
  if (actionsEl) {
    if (p.status === "pending") {
      // Bug #10 fix (2026-05-20): admin-grant flow tidak punya user yang
      // ketik kode (admin bikinkan akun + langsung approve). Sebelumnya
      // canApprove butuh matches && codeSent → tombol disabled selamanya
      // untuk admin-grant. Sekarang admin-grant auto-bypass typed-code req.
      const isAdminGrant = p.flowContext === "admin-grant";
      const canApprove = isAdminGrant ? true : (matches && codeSent);
      const rejectLbl = isID ? "✕ Tolak" : "✕ Reject";
      const approveLbl = isID ? "✓ Approve" : "✓ Approve";
      const sendCodeLbl = isID ? "📤 Kirim Kode ke User" : "📤 Send Code to User";
      const sentLbl = isID ? "✓ Kode sudah dikirim" : "✓ Code sent";
      const disabledTitle = isID
        ? (!codeSent ? "Kirim kode ke user dulu" : "User harus ketik kode dulu yang cocok dengan kode sistem")
        : (!codeSent ? "Send code to user first" : "User must first type a code that matches the system code");
      const sentCount = p.codeSentCount || 0;
      const sendLimit = 3;
      const remaining = sendLimit - sentCount;
      const limitReached = sentCount >= sendLimit;
      const limitLbl = isID ? `Batas ${sendLimit}× tercapai` : `Limit ${sendLimit}× reached`;
      const remainLbl = isID ? ` (sisa ${remaining}×)` : ` (${remaining} left)`;
      const sendBtn = limitReached
        ? `<small class="muted" style="align-self:center">${limitLbl}</small>`
        : (!codeSent
          ? `<button class="btn primary" data-pqdm-act="send-code" data-pqdm-code="${escapeHtml(p.code)}">${sendCodeLbl}${sentCount > 0 ? remainLbl : ""}</button>`
          : `<small class="muted" style="align-self:center">${sentLbl}${remaining > 0 ? remainLbl : ""}</small>`);
      actionsEl.innerHTML = `
        ${sendBtn}
        <button class="btn ghost" data-pqdm-act="reject" data-pqdm-code="${escapeHtml(p.code)}">${rejectLbl}</button>
        <button class="btn primary" data-pqdm-act="approve" data-pqdm-code="${escapeHtml(p.code)}" ${canApprove ? "" : `disabled title='${disabledTitle}'`}>${approveLbl}</button>
      `;
    } else {
      const procByLbl = isID ? "oleh" : "by";
      const procAtLbl = isID ? "pada" : "on";
      const procBy = p.processedBy ? `${procByLbl} @${escapeHtml(p.processedBy)}` : "";
      const procAt = p.processedAt ? `${procAtLbl} ${new Date(p.processedAt).toLocaleString(isID ? "id-ID" : "en-US")}` : "";
      const procLbl = isID ? "Diproses" : "Processed";
      actionsEl.innerHTML = `<small class="muted">${procLbl} ${procBy} ${procAt}</small>`;
    }
  }

  modal.hidden = false;
  modal.removeAttribute("hidden");
  modal.classList.add("show");
  modal.style.setProperty("display", "flex", "important");
  document.body.style.overflow = "hidden";
}

function closePremiumDetailModal() {
  const modal = document.getElementById("pqDetailModal");
  if (!modal) return;
  modal.classList.remove("show");
  modal.style.display = "";
  modal.hidden = true;
  document.body.style.overflow = "";
}

// Wire modal close + action delegation
document.addEventListener("click", e => {
  // Close button or backdrop click
  if (e.target.matches("[data-pqdm-close]") || e.target.classList?.contains("pq-detail-modal")) {
    if (e.target === e.currentTarget || e.target.matches("[data-pqdm-close]") || e.target.id === "pqDetailModal") {
      closePremiumDetailModal();
    }
  }
  // Action button (send-code/approve/reject)
  const actBtn = e.target.closest("[data-pqdm-act]");
  if (actBtn) {
    e.preventDefault();
    const code = actBtn.dataset.pqdmCode;
    const act = actBtn.dataset.pqdmAct;
    if (actBtn.disabled) return;
    if (act === "send-code") {
      const arr = getPremiumPayments();
      const idx = arr.findIndex(p => p.code === code);
      if (idx !== -1) {
        const cur = arr[idx].codeSentCount || 0;
        if (cur >= 3) {
          if (typeof toast === "function") toast("⚠ Batas pengiriman kode (3×) sudah tercapai.", "warning");
          return;
        }
        arr[idx].codeSentToUser = true;
        arr[idx].codeSentAt = Date.now();
        arr[idx].codeSentCount = cur + 1;
        arr[idx].updatedAt = Date.now();
        savePremiumPayments(arr);
        // C-2 H#8 fix (2026-05-21): kirim notifikasi ke user supaya mereka
        // tau kode sudah dikirim TANPA harus polling modal. Tanpa ini,
        // mobile user / user yg sudah tutup modal harus kebetulan buka
        // dashboard untuk lihat. Notif masuk via deliverNotification →
        // tampil di topbar bell + masuk ke list notif user.
        try {
          const username = arr[idx].username || null;
          if (username && typeof deliverNotification === "function") {
            deliverNotification(username, {
              type: "premium-code-sent",
              text: "🔑 Admin sudah mengirim kode verifikasi pembayaran Premium kamu. Buka dashboard untuk lihat kode.",
              init: "🔑",
            });
          }
        } catch (err) { console.warn("[send-code] notif failed:", err); }
      }
      // Re-render modal with updated state (button → "sent")
      openPremiumDetailModal(code);
      renderAdminPremiumQueue();
      if (typeof toast === "function") {
        toast(`📤 Kode <b>${code}</b> dikirim ke user`, "success");
      }
      return;
    }
    const adminUsername = (typeof user === "object" && user) ? user.username : "admin";
    const status = act === "approve" ? "approved" : "rejected";
    setPremiumPaymentStatus(code, status, adminUsername);
    closePremiumDetailModal();
    renderAdminPremiumQueue();
    if (typeof renderAdminActionCenter === "function") renderAdminActionCenter();
    if (typeof toast === "function") {
      toast(act === "approve"
        ? `✅ Payment <b>${code}</b> approved`
        : `❌ Payment <b>${code}</b> rejected`,
        act === "approve" ? "success" : "warning");
    }
  }
});
document.addEventListener("keydown", e => {
  if (e.key === "Escape") {
    const modal = document.getElementById("pqDetailModal");
    if (modal?.classList.contains("show")) closePremiumDetailModal();
  }
});

// Filter tab clicks
document.addEventListener("click", e => {
  const tab = e.target.closest(".pq-tab[data-pq-filter]");
  if (!tab) return;
  e.preventDefault();
  _adminPqFilter = tab.dataset.pqFilter;
  document.querySelectorAll(".pq-tab").forEach(t => t.classList.toggle("active", t === tab));
  renderAdminPremiumQueue();
});

// Bug #8 fix (2026-05-20): periodic auto-resync saat admin queue view aktif.
// EGRESS OPT (2026-05-21): pakai syncSingleKey untuk pull HANYA
// playly-premium-payments (~10 KB) instead of softResync (~5-10 MB full
// table). Interval naik 8s → 15s. Saving signifikan tanpa kehilangan UX.
let _adminPqAutoSyncTimer = null;
function _adminPqStartAutoSync() {
  if (_adminPqAutoSyncTimer) return;
  _adminPqAutoSyncTimer = setInterval(async () => {
    const sectionActive = document.querySelector('section.view[data-view="admin-premium-queue"].active');
    if (!sectionActive) return; // stop syncing if user left view
    if (document.hidden) return; // hemat saat tab hidden
    try {
      if (window.cloudSync?.syncSingleKey) {
        await Promise.resolve(window.cloudSync.syncSingleKey("playly-premium-payments"));
      } else if (window.cloudSync?.softResync) {
        await Promise.resolve(window.cloudSync.softResync());
      }
      if (typeof renderAdminPremiumQueue === "function") renderAdminPremiumQueue();
      if (typeof renderAdminActionCenter === "function") renderAdminActionCenter();
    } catch (err) { console.warn("[pq] auto-sync:", err); }
  }, 15000);
}
// Start the timer once script.js loads — it's idle until queue view is active.
try { _adminPqStartAutoSync(); } catch {}

// "Sync dari Cloud" button — force pull terbaru dari Supabase (req user
// 2026-05-20: queue admin kadang kosong padahal user sudah submit
// pembayaran karena cloud-sync belum catch up; admin butuh 1-klik refresh
// tanpa harus buka DevTools).
document.addEventListener("click", async e => {
  const btn = e.target.closest("#pqCloudSyncBtn");
  if (!btn) return;
  e.preventDefault();
  if (btn.dataset.busy === "1") return;
  btn.dataset.busy = "1";
  const labelEl = btn.querySelector("span");
  const origLabel = labelEl?.textContent || "Sync dari Cloud";
  if (labelEl) labelEl.textContent = "Menyinkron...";
  btn.classList.add("pq-syncing");
  try {
    if (window.cloudSync?.softResync) {
      await Promise.resolve(window.cloudSync.softResync());
    }
    renderAdminPremiumQueue();
    if (typeof renderAdminActionCenter === "function") renderAdminActionCenter();
    if (labelEl) labelEl.textContent = "Berhasil sync ✓";
    setTimeout(() => {
      if (labelEl) labelEl.textContent = origLabel;
      btn.classList.remove("pq-syncing");
      btn.dataset.busy = "0";
    }, 1400);
  } catch (err) {
    console.warn("[pq] cloud sync failed:", err);
    if (labelEl) labelEl.textContent = "Gagal sync ✗";
    setTimeout(() => {
      if (labelEl) labelEl.textContent = origLabel;
      btn.classList.remove("pq-syncing");
      btn.dataset.busy = "0";
    }, 1800);
  }
});

// Cross-tab sync — listen storage event to refresh queue
window.addEventListener("storage", e => {
  if (e.key === PREMIUM_PAYMENTS_KEY) {
    if (typeof renderAdminActionCenter === "function") renderAdminActionCenter();
    if (document.querySelector('section.view[data-view="admin-premium-queue"].active')) {
      renderAdminPremiumQueue();
    }
    // Update sidebar badge regardless
    const all = getPremiumPayments();
    const pendingN = all.filter(p => p.status === "pending").length;
    const badge = document.getElementById("adminPremiumBadge");
    if (badge) {
      badge.textContent = pendingN;
      badge.style.display = pendingN ? "" : "none";
    }
  }
});

function openPaymentModal({ onSuccess, planKey } = {}) {
  const modal = document.getElementById("paymentModal");
  if (!modal) return;
  _paymentOnSuccess = onSuccess || null;

  // Plan-aware pricing — read price/label/tax from PREMIUM_PLANS by planKey.
  // Fallback to monthly if planKey missing/invalid. Trial bypasses payment.
  const plan = (planKey && PREMIUM_PLANS[planKey] && PREMIUM_PLANS[planKey].price > 0)
    ? PREMIUM_PLANS[planKey]
    : PREMIUM_PLANS.monthly;
  modal.dataset.planKey = plan.key;

  const lang = (typeof currentLang === "function") ? currentLang() : "en";
  const isID = lang === "id";

  // Plan name (localized for monthly via dict; yearly/lifetime via inline map)
  const planNameMap = {
    monthly:  isID ? "Playly Premium · Bulanan"      : "Playly Premium · Monthly",
    yearly:   isID ? "Playly Premium · Tahunan"      : "Playly Premium · Yearly",
    lifetime: isID ? "Playly Premium · Seumur Hidup" : "Playly Premium · Lifetime",
  };
  const footMap = {
    monthly:  isID ? "Auto-renew bulanan. Batal kapan saja dari Settings."
                   : "Auto-renew monthly. Cancel anytime from Settings.",
    yearly:   isID ? "Auto-renew tahunan. Batal kapan saja dari Settings."
                   : "Auto-renew yearly. Cancel anytime from Settings.",
    lifetime: isID ? "Pembayaran sekali bayar. Premium selamanya, tanpa perpanjangan."
                   : "One-time payment. Premium forever, no renewal.",
  };

  // Money math: priceLabel is the gross total user pays (e.g. $9.99). Subtotal
  // = total / 1.11, Tax = total - subtotal (PPN 11% inclusive convention).
  const total = plan.price;
  const subtotal = +(total / 1.11).toFixed(2);
  const tax = +(total - subtotal).toFixed(2);
  const fmt = (n) => "$" + (Number.isInteger(n) ? n.toFixed(0) : n.toFixed(2));

  const planNameEl = document.getElementById("paymentPlanName");
  const subtotalEl = document.getElementById("paymentSubtotal");
  const taxEl      = document.getElementById("paymentTax");
  const totalEl    = document.getElementById("paymentTotalLabel");
  const idrEl      = document.getElementById("paymentTotalIdr");
  const footEl     = document.getElementById("paymentPlanFoot");
  if (planNameEl) planNameEl.textContent = planNameMap[plan.key] || planNameMap.monthly;
  if (subtotalEl) subtotalEl.textContent = fmt(subtotal);
  if (taxEl)      taxEl.textContent      = fmt(tax);
  if (totalEl)    totalEl.textContent    = plan.priceLabel || fmt(total);
  if (idrEl)      idrEl.textContent      = fmtUsdAsIdr(total);
  if (footEl)     footEl.textContent     = footMap[plan.key] || footMap.monthly;

  // Confirm button label — keep i18n prefix, swap any $X.XX with plan price.
  const confirmLabelEl = modal.querySelector(".payment-pay-label");
  if (confirmLabelEl) {
    const baseConfirm = (typeof t === "function") ? t("pay.confirm") : "Confirm Payment $9.99";
    confirmLabelEl.textContent = baseConfirm.replace(/\$[\d.,]+/, plan.priceLabel || fmt(total));
  }

  // Reset state every open
  modal.dataset.payMethod = "card";
  modal.querySelectorAll("[data-pay-method]").forEach(b => {
    b.classList.toggle("active", b.dataset.payMethod === "card");
  });
  modal.querySelectorAll("[data-pay-body]").forEach(b => {
    b.hidden = b.dataset.payBody !== "card";
  });
  // Reset form fields
  const form = document.getElementById("paymentForm");
  if (form) form.reset();
  // Hide success overlay + reset panel state if previously shown
  const ok = document.getElementById("paymentSuccess");
  if (ok) ok.hidden = true;
  const panel = modal.querySelector(".payment-panel");
  if (panel) delete panel.dataset.payState;
  // Reset send-money transition animation
  const animEl = document.getElementById("paymentAnim");
  if (animEl) {
    animEl.hidden = true;
    animEl.querySelector(".container")?.classList.remove("playing");
  }
  // Reset pay button
  const payBtn = document.getElementById("paymentPayBtn");
  if (payBtn) {
    payBtn.disabled = false;
    payBtn.querySelector(".payment-pay-label").hidden = false;
    payBtn.querySelector(".payment-pay-spinner").hidden = true;
  }
  modal.classList.add("show");
  document.body.style.overflow = "hidden";
}

function closePaymentModal() {
  const modal = document.getElementById("paymentModal");
  if (!modal) return;
  // Detect: user is closing while payment is in success/pending state (paid but
  // waiting admin approval). In that case dismiss the WHOLE auth flow and admit
  // user to dashboard as Free — admin approval will upgrade to Premium later
  // via the topbar payment pill. Without this, the underlying plan picker stays
  // open and traps the user (bug 2026-05-05).
  const panel = modal.querySelector(".payment-panel");
  const isPendingClose = panel?.dataset?.payState === "success" && _paymentOnSuccess;
  modal.classList.remove("show");
  document.body.style.overflow = "";
  _paymentOnSuccess = null;
  if (_premiumStatusPoller) {
    clearInterval(_premiumStatusPoller);
    _premiumStatusPoller = null;
  }
  if (isPendingClose) {
    // Close planPickerModal (Premium tier picker) if it's still open underneath
    document.getElementById("planPickerModal")?.classList.remove("show");
    // Boot dashboard as Free user — premium upgrade is pending admin approval.
    // The topbar payment pill / paymentStatusModal will reflect the pending state.
    // user is a let-scoped variable; check via typeof to avoid ReferenceError.
    if (typeof user !== "undefined" && user) {
      try { delete window.__playlyPostSignup; } catch {}
      // Close the auth modal flow first — bootWithWelcome shows welcome overlay
      // then bootDashboard, but doesn't dismiss authModalWrap on its own.
      if (typeof closeAuthModal === "function") closeAuthModal();
      if (typeof bootWithWelcome === "function") bootWithWelcome();
      // Render the topbar payment pill so the user has persistent quick-access
      // to verification status without needing the modal pinned open.
      setTimeout(() => {
        if (typeof renderDashboardPaymentPill === "function") renderDashboardPaymentPill();
        if (typeof openPaymentStatusModal === "function") openPaymentStatusModal();
      }, 800);
      if (typeof toast === "function") {
        toast("⏳ Pembayaran dikirim. Premium aktif setelah admin verifikasi.", "info");
      }
    }
  }
}

(function setupPaymentModal() {
  const modal = document.getElementById("paymentModal");
  if (!modal) return;

  // Method tabs
  modal.querySelectorAll(".payment-method").forEach(btn => {
    btn.addEventListener("click", e => {
      e.preventDefault();
      const m = btn.dataset.payMethod;
      modal.dataset.payMethod = m;
      modal.querySelectorAll(".payment-method").forEach(b => b.classList.toggle("active", b === btn));
      modal.querySelectorAll("[data-pay-body]").forEach(b => {
        b.hidden = b.dataset.payBody !== m;
      });
    });
  });

  // Card number formatter (1234 5678 9012 3456)
  const cardInput = modal.querySelector('[data-format="card-number"]');
  cardInput?.addEventListener("input", e => {
    const v = e.target.value.replace(/\D/g, "").slice(0, 16);
    e.target.value = v.replace(/(.{4})/g, "$1 ").trim();
    // Detect brand by IIN
    const brand = document.getElementById("paymentCardBrand");
    if (brand) {
      if (v.startsWith("4")) brand.textContent = "💎"; // visa-ish
      else if (v.startsWith("5") || v.startsWith("2")) brand.textContent = "🔶"; // mc-ish
      else if (v.startsWith("3")) brand.textContent = "🔷"; // amex-ish
      else brand.textContent = "💳";
    }
  });

  // Expiry formatter (MM/YY)
  const expInput = modal.querySelector('[data-format="card-expiry"]');
  expInput?.addEventListener("input", e => {
    const v = e.target.value.replace(/\D/g, "").slice(0, 4);
    e.target.value = v.length >= 3 ? `${v.slice(0, 2)}/${v.slice(2)}` : v;
  });

  // Close handlers (backdrop / X / cancel)
  modal.querySelectorAll("[data-close]").forEach(el => {
    el.addEventListener("click", e => {
      e.preventDefault();
      closePaymentModal();
    });
  });

  // Copy verification code to clipboard
  document.getElementById("paymentCopyCode")?.addEventListener("click", async () => {
    const code = document.getElementById("successCode")?.textContent || "";
    if (!code) return;
    try {
      await navigator.clipboard.writeText(code);
      if (typeof toast === "function") toast(`📋 Code <b>${code}</b> copied`, "success");
    } catch {
      if (typeof toast === "function") toast(`Code: <b>${code}</b>`, "info");
    }
  });

  // Custom bank dropdown (replaces native select that ignores dark theme on
  // Windows Chrome). Click trigger → toggle list. Click option → set value +
  // close. Click outside → close.
  const bankPicker  = document.getElementById("paymentBankPicker");
  const bankTrigger = document.getElementById("paymentBankTrigger");
  const bankList    = document.getElementById("paymentBankList");
  const bankLabel   = document.getElementById("paymentBankLabel");
  const bankValue   = document.getElementById("paymentBankValue");
  if (bankPicker && bankTrigger && bankList) {
    const closeBank = () => {
      bankList.hidden = true;
      bankTrigger.setAttribute("aria-expanded", "false");
      bankPicker.classList.remove("open");
    };
    bankTrigger.addEventListener("click", e => {
      e.preventDefault();
      const isOpen = !bankList.hidden;
      if (isOpen) closeBank();
      else {
        bankList.hidden = false;
        bankTrigger.setAttribute("aria-expanded", "true");
        bankPicker.classList.add("open");
      }
    });
    bankList.querySelectorAll(".payment-bank-opt").forEach(opt => {
      opt.addEventListener("click", e => {
        e.preventDefault();
        bankList.querySelectorAll(".payment-bank-opt").forEach(o => o.setAttribute("aria-selected", "false"));
        opt.setAttribute("aria-selected", "true");
        if (bankLabel) bankLabel.textContent = opt.dataset.label;
        if (bankValue) bankValue.value = opt.dataset.bank;
        closeBank();
      });
    });
    // Close when clicking outside the picker
    document.addEventListener("click", e => {
      if (!bankPicker.contains(e.target)) closeBank();
    });
    // Close on Escape
    document.addEventListener("keydown", e => {
      if (e.key === "Escape" && !bankList.hidden) closeBank();
    });
  }

  // Submit (dummy "process" → 1.5s → success)
  const form = document.getElementById("paymentForm");
  form?.addEventListener("submit", e => {
    e.preventDefault();
    const payBtn = document.getElementById("paymentPayBtn");
    const method = modal.dataset.payMethod;

    // Minimal validation per method
    const fail = (msg) => {
      if (typeof toast === "function") toast(`⚠️ ${msg}`, "warning");
    };
    if (method === "card") {
      const num = (form.cardNumber?.value || "").replace(/\s/g, "");
      const exp = form.cardExpiry?.value || "";
      const cvv = form.cardCvv?.value || "";
      const name = form.cardName?.value || "";
      if (num.length < 12) return fail("Enter a valid card number");
      if (!/^\d{2}\/\d{2}$/.test(exp)) return fail("Enter expiry as MM/YY");
      if (cvv.length < 3) return fail("Enter CVV");
      if (!name.trim()) return fail("Enter cardholder name");
    } else if (method === "ewallet") {
      const phone = form.ewalletPhone?.value || "";
      if (phone.replace(/\D/g, "").length < 9) return fail("Enter a valid phone number");
    }
    // bank transfer: VA always considered valid (user pays via banking app)

    // Start processing
    if (payBtn) {
      payBtn.disabled = true;
      payBtn.querySelector(".payment-pay-label").hidden = true;
      payBtn.querySelector(".payment-pay-spinner").hidden = false;
    }

    // Send-money transition animation — replaces the form UI with a
    // brief animated card that morphs into the success view. The CSS
    // rule .payment-panel[data-pay-state="animating"] hides everything
    // except #paymentAnim while playing.
    const animEl = document.getElementById("paymentAnim");
    const panel0 = modal.querySelector(".payment-panel");
    if (animEl && panel0) {
      animEl.hidden = false;
      panel0.dataset.payState = "animating";
      // force reflow so CSS animations restart on retries
      void animEl.offsetWidth;
      animEl.querySelector(".container")?.classList.add("playing");
    }

    setTimeout(() => {
      // Generate unique verification code + persist as pending payment
      const code = generatePremiumCode();
      const methodLabel = {
        card:    "Credit/Debit Card",
        ewallet: ({ gopay: "GoPay", ovo: "OVO", dana: "DANA", shopeepay: "ShopeePay" }[
                   (form.ewallet?.value || "gopay")] || "E-Wallet"),
        bank:    ({ bca: "BCA", mandiri: "Bank Mandiri", bni: "BNI", bri: "BRI", cimb: "CIMB Niaga" }[
                   (form.bank?.value || "bca")] || "Bank Transfer"),
      }[method] || "Payment";
      const flowContext = (typeof user === "object" && user) ? "upgrade" : "signup";
      // Read plan from modal.dataset.planKey (set by openPaymentModal).
      const _planKey = modal.dataset.planKey || "monthly";
      const _plan = PREMIUM_PLANS[_planKey] || PREMIUM_PLANS.monthly;
      const _orderId = String(Date.now()).slice(-8);
      const _payDate = new Date();
      const payment = {
        code,
        email: user?.email || null,
        username: user?.username || null,
        tier: "premium",
        plan: _planKey,
        amount: _plan.price,
        method: methodLabel,
        paidAt: Date.now(),
        status: "pending",
        flowContext,
        orderId: _orderId,
        // codeSentToUser: admin must explicitly send code via "Kirim Kode" button
        // before user can see it & type it back. Per user request 2026-05-06.
        codeSentToUser: false,
      };
      // Auto-generate receipt bukti pembayaran (canvas) lalu simpan ke
      // payment record. Saat user nanti hubungi support, bukti ini auto-
      // attach ke email tanpa perlu screenshot manual.
      try {
        payment.proofImage = generatePaymentReceiptImage({
          code,
          orderId: _orderId,
          method: methodLabel,
          plan: _plan,
          planKey: _planKey,
          paidAt: _payDate,
          email: user?.email || "—",
          username: user?.username || "—",
        });
        payment.proofVersion = PAYMENT_RECEIPT_VERSION;
      } catch (err) {
        console.warn("[payment] receipt generation failed:", err);
      }
      const arr = getPremiumPayments();
      // C-3 P-M9 fix (2026-05-21): cek duplikat pending untuk email yg sama
      // sebelum unshift. Sebelumnya user-side submit tidak ada guard →
      // user spam-click pay = N payment records muncul, admin pusing
      // verify. Guard 60s window aman utk handle double-click race +
      // network retry, tapi tidak block payment yg legit (mis. user
      // bayar tier lain dlm interval > 1 menit).
      const userEmailLc = String(user?.email || "").toLowerCase();
      if (userEmailLc) {
        const recentDup = arr.find(p =>
          p && String(p.email || "").toLowerCase() === userEmailLc &&
          p.status === "pending" &&
          (Date.now() - (p.paidAt || 0)) < 60000
        );
        if (recentDup) {
          console.warn("[payment] duplicate detected, skipping:", recentDup.code);
          if (typeof toast === "function") toast("⚠ Pembayaran sebelumnya masih diproses. Tunggu konfirmasi admin sebelum submit ulang.", "warning");
          return;
        }
      }
      arr.unshift(payment);
      savePremiumPayments(arr);

      // Populate order detail card (receipt-style success view)
      const orderIdEl = document.getElementById("successOrderId");
      const methodEl  = document.getElementById("successMethod");
      const dateEl    = document.getElementById("successDate");
      const totalEl   = document.getElementById("successTotal");
      const codeEl    = document.getElementById("successCode");
      const statusEl  = document.getElementById("successPendingStatus");
      const continueBtn = document.querySelector(".payment-success-cta");
      const flowMsgEl = document.getElementById("successFlowMsg");
      if (orderIdEl) orderIdEl.textContent = String(Date.now()).slice(-8);
      if (methodEl)  methodEl.textContent  = methodLabel;
      if (dateEl) {
        const d = new Date();
        const pad = n => String(n).padStart(2, "0");
        dateEl.textContent = `${pad(d.getDate())}/${pad(d.getMonth()+1)}/${String(d.getFullYear()).slice(-2)} ${pad(d.getHours())}:${pad(d.getMinutes())}`;
      }
      if (totalEl) totalEl.textContent = _plan.priceLabel || `$${_plan.price.toFixed(2)}`;
      // MASK code di success view per user request 2026-05-06 — kode tidak boleh
      // ditampilkan ke user sampai admin klik "Kirim Kode ke User" di queue.
      if (codeEl) codeEl.textContent = "•••••••••";
      // Sembunyiin tombol Copy + ubah label "Verification code" jadi pesan tunggu
      const successCopyBtn = document.getElementById("paymentCopyCode");
      if (successCopyBtn) successCopyBtn.style.display = "none";
      const successCodeLabel = document.querySelector(".psc-label");
      if (successCodeLabel) successCodeLabel.textContent = "Menunggu admin mengirim kode";
      if (statusEl) {
        statusEl.textContent = "⏳ Pending admin verification";
        statusEl.dataset.status = "pending";
      }
      if (flowMsgEl) {
        flowMsgEl.textContent = flowContext === "signup"
          ? "Pembayaran berhasil dikirim. Tunggu admin memverifikasi & mengirim kode konfirmasi ke kamu."
          : "Pembayaran berhasil dikirim. Tunggu admin memverifikasi & mengirim kode konfirmasi ke kamu.";
      }
      if (continueBtn) {
        continueBtn.disabled = true;
        continueBtn.textContent = "Waiting for admin approval…";
        continueBtn.dataset.code = code;
      }

      // Show success overlay
      const ok = document.getElementById("paymentSuccess");
      if (ok) ok.hidden = false;
      const panel = modal.querySelector(".payment-panel");
      if (panel) panel.dataset.payState = "success";

      // Wire user-code-typing UI (input + submit di success view).
      // User wajib ketik ulang kode setelah admin send → admin verify match → approve.
      const sentBanner = document.getElementById("successCodeSentBanner");
      const userCodeWrap = document.getElementById("successUserCodeWrap");
      const userCodeInput = document.getElementById("successUserCodeInput");
      const userCodeSubmit = document.getElementById("successUserCodeSubmit");
      const userCodeHint = document.getElementById("successUserCodeHint");
      // Reset state setiap modal terbuka (hide banner + input + clear value)
      if (sentBanner) sentBanner.hidden = true;
      if (userCodeWrap) userCodeWrap.hidden = true;
      if (userCodeInput) {
        userCodeInput.value = "";
        userCodeInput.disabled = false;
      }
      if (userCodeSubmit) {
        userCodeSubmit.disabled = true;
        userCodeSubmit.textContent = "Kirim";
      }
      if (userCodeHint) {
        userCodeHint.textContent = "Salin kode persis dari kotak di atas.";
        userCodeHint.classList.remove("err", "ok");
      }
      // Validate input vs actual code (case-insensitive). Enable submit kalau valid format.
      const validateUserCode = () => {
        if (!userCodeInput || !userCodeSubmit) return;
        const typed = (userCodeInput.value || "").trim().toUpperCase();
        userCodeSubmit.disabled = typed.length < 8;
      };
      if (userCodeInput) {
        userCodeInput.oninput = validateUserCode;
      }
      if (userCodeSubmit) {
        userCodeSubmit.onclick = () => {
          const typed = (userCodeInput?.value || "").trim().toUpperCase();
          if (!typed) return;
          // Save ke payment record — admin akan lihat di queue modal & verify match
          const arr = getPremiumPayments();
          const idx = arr.findIndex(x => x.code === code);
          if (idx >= 0) {
            arr[idx].userTypedCode = typed;
            arr[idx].userTypedAt = Date.now();
            savePremiumPayments(arr);
          }
          // Lock input + tunjukkan ke user kalau cocok / belum
          const matches = typed === String(code).toUpperCase();
          if (userCodeInput) userCodeInput.disabled = true;
          userCodeSubmit.disabled = true;
          userCodeSubmit.textContent = matches ? "✓ Terkirim" : "Coba lagi";
          if (userCodeHint) {
            if (matches) {
              userCodeHint.textContent = "Kode dikirim ke admin. Menunggu admin menyetujui…";
              userCodeHint.classList.add("ok");
              userCodeHint.classList.remove("err");
            } else {
              userCodeHint.textContent = "Kode tidak cocok. Pastikan persis sama dengan yang admin kirim.";
              userCodeHint.classList.add("err");
              userCodeHint.classList.remove("ok");
              // Reset supaya user bisa coba lagi
              setTimeout(() => {
                if (userCodeInput) {
                  userCodeInput.disabled = false;
                  userCodeInput.value = "";
                  userCodeInput.focus();
                }
                userCodeSubmit.textContent = "Kirim";
                userCodeSubmit.disabled = true;
              }, 1800);
            }
          }
          if (matches && typeof toast === "function") {
            toast("✅ Kode dikirim ke admin. Menunggu persetujuan…", "success");
          }
        };
      }

      // Track transition: kalau admin baru saja klik "Kirim Kode" → reveal code
      // di success view + show banner notif + show input field. One-shot per session.
      let _codeRevealedToUser = false;
      const revealCodeToUser = (p) => {
        if (_codeRevealedToUser) return;
        _codeRevealedToUser = true;
        if (codeEl) codeEl.textContent = p.code;
        if (successCopyBtn) successCopyBtn.style.display = "";
        if (successCodeLabel) successCodeLabel.textContent = "Verification code (kirim ke admin)";
        if (sentBanner) sentBanner.hidden = false;
        if (userCodeWrap) userCodeWrap.hidden = false;
        if (statusEl) {
          statusEl.textContent = "📩 Admin sudah mengirim kode";
          statusEl.dataset.status = "pending";
        }
        if (flowMsgEl) {
          flowMsgEl.textContent = "Salin kode di atas, ketik ulang di bawah, lalu klik Kirim. Setelah cocok admin akan menyetujui premium kamu.";
        }
        if (typeof toast === "function") toast("📩 Admin sudah mengirim kode verifikasi!", "success");
      };

      // Start polling: cek tiap 2 detik state dari payment record.
      // Transitions:
      //   - codeSentToUser: false → true → reveal code + show input
      //   - status: pending → approved → enable Continue + onSuccess
      //   - status: pending → rejected → show rejected, disable Continue
      if (_premiumStatusPoller) clearInterval(_premiumStatusPoller);
      _premiumStatusPoller = setInterval(async () => {
        // Bug #8 fix (2026-05-20): pull dari Supabase tiap iterasi supaya
        // user yg staring di modal langsung lihat admin approve dari device
        // lain (tanpa harus tab away/back).
        // EGRESS OPT (2026-05-21): pakai syncSingleKey supaya hemat egress
        // (~10 KB vs ~5 MB full table). User cuma butuh tau status premium
        // payment-nya, nggak butuh kv lainnya.
        try {
          if (window.cloudSync?.syncSingleKey) {
            await Promise.resolve(window.cloudSync.syncSingleKey("playly-premium-payments"));
          } else if (window.cloudSync?.softResync) {
            await Promise.resolve(window.cloudSync.softResync());
          }
        } catch {}
        const p = getPremiumPaymentByCode(code);
        if (!p) return;
        // Code-sent transition (sebelum status final)
        if (p.codeSentToUser && !_codeRevealedToUser) {
          revealCodeToUser(p);
        }
        if (p.status === "approved") {
          clearInterval(_premiumStatusPoller); _premiumStatusPoller = null;
          if (statusEl) {
            statusEl.textContent = "✅ Approved by admin — you can continue";
            statusEl.dataset.status = "approved";
          }
          // Hide input field, code box biar bersih
          if (userCodeWrap) userCodeWrap.hidden = true;
          if (sentBanner) sentBanner.hidden = true;
          if (continueBtn) {
            continueBtn.disabled = false;
            continueBtn.textContent = flowContext === "signup" ? "Continue to Sign Up" : "Activate Premium";
            continueBtn.onclick = () => {
              try { _paymentOnSuccess && _paymentOnSuccess(); } catch (err) { console.warn(err); }
              closePaymentModal();
            };
          }
          if (typeof toast === "function") toast("✅ Premium kamu sudah disetujui admin!", "success");
        } else if (p.status === "rejected") {
          clearInterval(_premiumStatusPoller); _premiumStatusPoller = null;
          if (statusEl) {
            statusEl.textContent = "❌ Rejected by admin — payment refunded";
            statusEl.dataset.status = "rejected";
          }
          if (userCodeWrap) userCodeWrap.hidden = true;
          if (sentBanner) sentBanner.hidden = true;
          if (continueBtn) {
            continueBtn.disabled = false;
            continueBtn.textContent = "Close";
            continueBtn.onclick = () => closePaymentModal();
          }
          if (typeof toast === "function") toast("⚠️ Pembayaran kamu ditolak admin. Silakan hubungi support.", "warning");
        }
      }, 2000);
    }, 2200);
  });
})();

// Plan landing CTAs (Free / Premium) — direct binding sebagai fallback
// kalau document-level handler kebablasan. pickLandingPlanAsGuest force
// logout + route ke auth check, jadi behavior konsisten.
$$("[data-plan-pick]").forEach(btn => {
  btn.addEventListener("click", e => {
    e.preventDefault();
    e.stopPropagation();
    const tier = btn.dataset.planPick === "premium" ? "premium" : "free";
    if (typeof pickLandingPlanAsGuest === "function") pickLandingPlanAsGuest(tier);
  });
});

// "Compare plans ↓" link in signup form — scroll ke plans section
$$("[data-scroll-plans]").forEach(link => {
  link.addEventListener("click", e => {
    e.preventDefault();
    document.getElementById("authPlansSection")?.scrollIntoView({ behavior: "smooth", block: "start" });
  });
});

// Password toggle
$$(".pw-toggle").forEach(b => {
  b.addEventListener("click", () => {
    const input = b.previousElementSibling?.tagName === "INPUT"
      ? b.previousElementSibling
      : b.parentElement.querySelector("input");
    if (!input) return;
    const showing = input.type === "text";
    input.type = showing ? "password" : "text";
    b.classList.toggle("is-shown", !showing);
    b.setAttribute("aria-label", showing ? "Tampilkan password" : "Sembunyikan password");
  });
});

// Password strength
const pwInput = $("#signupForm input[name='password']");
const pwStrength = $("#pwStrength");
pwInput?.addEventListener("input", () => {
  const v = pwInput.value;
  let s = 0;
  if (v.length >= 6) s++;
  if (v.length >= 10) s++;
  if (/[A-Z]/.test(v) && /[a-z]/.test(v)) s++;
  if (/[0-9]/.test(v) && /[^a-zA-Z0-9]/.test(v)) s++;
  pwStrength.className = "pw-strength" + (s ? ` s${s}` : "");
  pwStrength.querySelector("small").textContent = [t("pw.weak"), t("pw.weak"), t("pw.medium"), t("pw.strong"), t("pw.verystrong")][s];
});

// ----------------------- ACCOUNT LOOKUP HELPERS -----------------------
function findAccountByEmail(email) {
  if (!email) return null;
  return JSON.parse(localStorage.getItem(`playly-account-${email.trim().toLowerCase()}`) || "null");
}

function findAccountByUsername(username) {
  if (!username) return null;
  const target = username.trim().toLowerCase();
  for (let i = 0; i < localStorage.length; i++) {
    const k = localStorage.key(i);
    if (!k || !k.startsWith("playly-account-")) continue;
    try {
      const a = JSON.parse(localStorage.getItem(k));
      if (a?.username && a.username.toLowerCase() === target) return a;
    } catch {}
  }
  return null;
}

// Find the single registered admin account, if any. Only one admin is allowed.
function findExistingAdmin() {
  for (let i = 0; i < localStorage.length; i++) {
    const k = localStorage.key(i);
    if (!k || !k.startsWith("playly-account-")) continue;
    try {
      const a = JSON.parse(localStorage.getItem(k));
      if (a?.role === "admin") return a;
    } catch {}
  }
  return null;
}

// ----------------------- PIN HASH (untuk 2FA) -----------------------
// Sederhana — bukan kripto-grade tapi cukup supaya PIN tidak plain-text di localStorage.
// Cocok untuk demo/UI. Di production nyata pakai bcrypt/argon2 server-side.
function hashPin(pin) {
  let h = 5381;
  const salt = "playly-2fa-salt-v1";
  const s = salt + String(pin);
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h) ^ s.charCodeAt(i);
  return "h:" + (h >>> 0).toString(16);
}
function verifyPin(plainPin, storedHash) {
  // CR-2 fix (2026-05-21): SECURITY — sebelumnya return true kalau storedHash
  // falsy. Pattern "akun lama tanpa PIN → skip" disalahgunakan kalau
  // acc.pin pernah ke-clear (race condition / cloud collision / tampering).
  // Caller (login flow `if (existing.pin) { open2FAModal(...) }`) sudah cek
  // existence dulu — verifyPin TIDAK seharusnya pernah dipanggil dgn hash
  // kosong. Kalau dipanggil, perlakukan sebagai INVALID (fail-secure).
  if (!storedHash) return false;
  return hashPin(plainPin) === storedHash;
}

// ----------------------- PASSWORD HASH (versi-versi) -----------------------
// Pakai Web Crypto SubtleCrypto — async tapi jauh lebih kuat dari djb2.
//
// Format yang didukung (urut dari paling baru):
//   h3:<saltHex>:<iterations>:<hashHex>  → PBKDF2-SHA256, per-user random salt.
//                                           Iterations 100000 bikin brute-force
//                                           ~100k× lebih lambat dari SHA-256
//                                           single-pass.
//   h2:<sha256Hex>                        → SHA-256 dengan salt fixed (legacy
//                                           dari migrasi pertama). Diverifikasi
//                                           tapi semua login berhasil di-upgrade
//                                           ke h3.
//   <plaintext>                           → akun pra-hashing. Diverifikasi tapi
//                                           langsung di-upgrade saat login OK.
//
// Tujuan: meskipun database di Supabase ke-leak, attacker tetap kesulitan
// crack password karena tiap user punya salt random + iterations cost tinggi.

const PLAYLY_PASSWORD_SALT_V2 = "playly-pwd-salt-v1"; // tetap, jangan diubah — dipakai untuk verifikasi h2 lama
const PBKDF2_ITERATIONS = 100000;

function _hex(buf) {
  return [...new Uint8Array(buf)].map(b => b.toString(16).padStart(2, "0")).join("");
}
function _hexToBytes(hex) {
  const out = new Uint8Array(hex.length / 2);
  for (let i = 0; i < out.length; i++) out[i] = parseInt(hex.substr(i * 2, 2), 16);
  return out;
}

// Hash baru: PBKDF2-SHA256 dengan salt random per akun
async function hashPassword(plain) {
  const salt = crypto.getRandomValues(new Uint8Array(16));
  const keyMaterial = await crypto.subtle.importKey(
    "raw",
    new TextEncoder().encode(String(plain ?? "")),
    "PBKDF2",
    false,
    ["deriveBits"]
  );
  const buf = await crypto.subtle.deriveBits(
    { name: "PBKDF2", salt, iterations: PBKDF2_ITERATIONS, hash: "SHA-256" },
    keyMaterial,
    256
  );
  return `h3:${_hex(salt)}:${PBKDF2_ITERATIONS}:${_hex(buf)}`;
}

// Hash lama (h2): tetap di-support untuk verifikasi backward-compat.
async function hashPasswordV2(plain) {
  const data = new TextEncoder().encode(PLAYLY_PASSWORD_SALT_V2 + String(plain ?? ""));
  const buf = await crypto.subtle.digest("SHA-256", data);
  return "h2:" + _hex(buf);
}

function isHashedPassword(stored) {
  return typeof stored === "string" && (stored.startsWith("h3:") || stored.startsWith("h2:"));
}
function isLatestHashFormat(stored) {
  return typeof stored === "string" && stored.startsWith("h3:");
}

async function verifyPassword(plain, stored) {
  if (!stored) return false;
  if (typeof stored !== "string") return false;
  if (stored.startsWith("h3:")) {
    const parts = stored.split(":");
    if (parts.length !== 4) return false;
    const saltHex = parts[1];
    const iterations = parseInt(parts[2], 10);
    const expectedHashHex = parts[3];
    if (!iterations || iterations < 1 || !saltHex || !expectedHashHex) return false;
    try {
      const keyMaterial = await crypto.subtle.importKey(
        "raw",
        new TextEncoder().encode(String(plain ?? "")),
        "PBKDF2",
        false,
        ["deriveBits"]
      );
      const buf = await crypto.subtle.deriveBits(
        { name: "PBKDF2", salt: _hexToBytes(saltHex), iterations, hash: "SHA-256" },
        keyMaterial,
        expectedHashHex.length * 4 // 4 bits per hex char
      );
      return _hex(buf) === expectedHashHex;
    } catch { return false; }
  }
  if (stored.startsWith("h2:")) {
    const candidate = await hashPasswordV2(plain);
    return candidate === stored;
  }
  // Plaintext legacy — auto-migrate ke h3 setelah login berhasil
  return stored === plain;
}

// Konstanta ADMIN_PASSWORD_HASH & DEFAULT_RESET_PASSWORD_HASH dipindah ke atas
// (sebelum seedOfficialAdmin) supaya tidak kena temporal-dead-zone saat seed
// jalan di script load.

// ----------------------- B6b P1 PARALLEL-VERIFY TELEMETRY (2026-05-25 v545) ---
// Tujuan: ukur seberapa sering Supabase Auth setuju dengan local SHA-256
// verify SEBELUM kita cutover (P2: bridge-primary, P3: drop SHA-256).
//
// Dipanggil setelah verifyPassword() di login handler — pass apakah local
// accept atau reject. Background only, zero behavior change.
//
// Hasil di-aggregate di localStorage key `playly-auth-verify-stats` —
// counter per outcome. View pakai window.playlyAuthVerifyStats() di console.
//
// Outcomes:
//   agree       — local accept + bridge verified (ideal)
//   bridge_no   — local accept + bridge rejected (DANGER: local hash drift?)
//   local_no    — local reject + bridge verified (DANGER: lazy migrate gagal?)
//   both_no     — local reject + bridge rejected (normal wrong-password)
//   unreachable — bridge network error / 503 (no decision)
//   skipped     — supabaseAuthBridge.verifyStrict belum tersedia
const AUTH_VERIFY_STATS_KEY = "playly-auth-verify-stats";

function recordAuthVerifyTelemetry(email, password, localOk) {
  const bridge = window.supabaseAuthBridge;
  if (!bridge || typeof bridge.verifyStrict !== "function") {
    bumpAuthVerifyStat("skipped");
    return;
  }
  // Fire-and-forget. Hasil di-log ke console + bump stat counter.
  bridge.verifyStrict(email, password).then((res) => {
    if (!res) return bumpAuthVerifyStat("skipped");
    if (!res.networkOk) {
      console.warn("[auth-telemetry] bridge unreachable —", res.reason);
      return bumpAuthVerifyStat("unreachable");
    }
    const bridgeOk = !!res.verified;
    let outcome;
    if (localOk && bridgeOk) outcome = "agree";
    else if (localOk && !bridgeOk) outcome = "bridge_no";
    else if (!localOk && bridgeOk) outcome = "local_no";
    else outcome = "both_no";

    // Suara hanya untuk kondisi mencurigakan (mismatch) atau wrong-password.
    if (outcome === "bridge_no" || outcome === "local_no") {
      console.warn(
        "[auth-telemetry] MISMATCH:",
        outcome,
        "local=" + localOk,
        "bridge=" + bridgeOk,
        "reason=" + (res.reason || "ok"),
      );
    } else {
      console.log("[auth-telemetry]", outcome, "(reason=" + (res.reason || "ok") + ")");
    }
    bumpAuthVerifyStat(outcome);
  }).catch((err) => {
    console.warn("[auth-telemetry] exception:", err);
    bumpAuthVerifyStat("unreachable");
  });
}

function bumpAuthVerifyStat(outcome) {
  try {
    const raw = localStorage.getItem(AUTH_VERIFY_STATS_KEY);
    const stats = raw ? JSON.parse(raw) : {};
    stats[outcome] = (stats[outcome] || 0) + 1;
    stats._lastAt = Date.now();
    stats._lastOutcome = outcome;
    localStorage.setItem(AUTH_VERIFY_STATS_KEY, JSON.stringify(stats));
  } catch (_) { /* localStorage full / unavailable — ignore */ }
}

// Helper buat inspect dari devtools: window.playlyAuthVerifyStats()
window.playlyAuthVerifyStats = function () {
  try {
    const raw = localStorage.getItem(AUTH_VERIFY_STATS_KEY);
    const stats = raw ? JSON.parse(raw) : {};
    console.table(stats);
    return stats;
  } catch (e) {
    console.warn(e);
    return null;
  }
};

// ----------------------- LOGIN RATE LIMITING -----------------------
// Tracking per identifier (email/username, di-normalize lowercase) di localStorage.
// Setelah MAX_ATTEMPTS gagal berturut, akun di-lockout selama LOCKOUT_MS.
// Login sukses → reset counter.
// CAPTCHA_AFTER_FAILS: berapa failed attempt sebelum captcha required.
// Default 2 → attempt #1 & #2 mulus tanpa captcha, attempt #3+ baru kena.
// Tujuan: kurangi friction onboarding untuk user yang ketik password benar
// dari awal. Bot atau brute force tetap kena captcha sebelum lockout.
const LOGIN_MAX_ATTEMPTS = 5;
const CAPTCHA_AFTER_FAILS = 2;
const LOGIN_LOCKOUT_MS = 30 * 60 * 1000; // 30 menit
function loginAttemptKey(id) { return `playly-login-attempts-${id}`; }
function getLoginAttempts(id) {
  try {
    const raw = localStorage.getItem(loginAttemptKey(id));
    if (!raw) return { count: 0, lockedUntil: 0 };
    const obj = JSON.parse(raw);
    return { count: obj.count || 0, lockedUntil: obj.lockedUntil || 0 };
  } catch { return { count: 0, lockedUntil: 0 }; }
}
function checkLoginLockout(id) {
  const { lockedUntil } = getLoginAttempts(id);
  const remaining = lockedUntil - Date.now();
  return remaining > 0 ? remaining : 0;
}
function recordLoginFailure(id) {
  const cur = getLoginAttempts(id);
  cur.count += 1;
  if (cur.count >= LOGIN_MAX_ATTEMPTS) {
    cur.lockedUntil = Date.now() + LOGIN_LOCKOUT_MS;
    cur.count = 0; // reset counter, lockout aktif
  }
  try { localStorage.setItem(loginAttemptKey(id), JSON.stringify(cur)); } catch {}
  return cur;
}
function clearLoginAttempts(id) {
  try { localStorage.removeItem(loginAttemptKey(id)); } catch {}
}
function fmtLockoutDuration(ms) {
  const sec = Math.ceil(ms / 1000);
  if (sec >= 60) return `${Math.ceil(sec / 60)} menit`;
  return `${sec} detik`;
}

// ----------------------- INLINE LOCK BANNER -----------------------
// Pengganti modal popup "Akun Terkunci" — banner inline di form login
// supaya peringatan tetap terlihat di halaman login (tidak menutupi UI).
let _signinLockTimer = null;
function showLockBanner(lockMs) {
  const banner = $("#signinLockBanner");
  const cd = $("#signinLockCountdown");
  if (!banner || !cd) return;
  const targetTs = Date.now() + lockMs;
  banner.hidden = false;
  cd.textContent = fmtLockoutDuration(lockMs);
  if (_signinLockTimer) clearInterval(_signinLockTimer);
  _signinLockTimer = setInterval(() => {
    const remaining = targetTs - Date.now();
    if (remaining <= 0) {
      hideLockBanner();
      return;
    }
    cd.textContent = fmtLockoutDuration(remaining);
  }, 1000);
}
function hideLockBanner() {
  const banner = $("#signinLockBanner");
  if (banner) banner.hidden = true;
  if (_signinLockTimer) {
    clearInterval(_signinLockTimer);
    _signinLockTimer = null;
  }
}
// Proactive check: setiap user ketik email/username, periksa lockout.
// Pakai debounce supaya tidak terlalu sering trigger saat user lagi mengetik.
let _signinLockProbe = null;
function probeSigninLockout() {
  const form = $("#signinForm");
  if (!form) return;
  const input = form.querySelector('input[name="email"]');
  if (!input) return;
  const id = (input.value || "").trim().toLowerCase();
  if (!id) {
    hideLockBanner();
    return;
  }
  const lockMs = checkLoginLockout(id);
  if (lockMs > 0) showLockBanner(lockMs);
  else hideLockBanner();
}

// ----------------------- AUTH FORM ERROR UI HELPERS -----------------------
// Tampilkan error inline di bawah field + shake animation + auto-focus.
// Lebih jelas daripada cuma toast — user langsung tahu field mana yang salah.
function showFieldError(formOrInput, fieldName, message) {
  const form = formOrInput.tagName === "FORM" ? formOrInput : formOrInput.closest("form");
  const input = form?.querySelector(`[name="${fieldName}"]`) || formOrInput;
  if (!input) return;
  const wrap = input.closest(".auth-field") || input.parentElement;
  let err = wrap.querySelector(".field-error");
  if (!err) {
    err = document.createElement("small");
    err.className = "field-error";
    wrap.appendChild(err);
  }
  err.textContent = message;
  wrap.classList.add("has-error");
  input.classList.add("shake");
  setTimeout(() => input.classList.remove("shake"), 450);
  // Focus pertama yang error
  if (!form.querySelector(".has-error input:focus, .has-error textarea:focus")) {
    input.focus();
  }
}
function clearFieldErrors(form) {
  if (!form) return;
  form.querySelectorAll(".has-error").forEach(el => el.classList.remove("has-error"));
  form.querySelectorAll(".field-error").forEach(el => el.remove());
}
// Auto-clear error saat user mulai ngetik di field bermasalah
document.addEventListener("input", e => {
  const wrap = e.target.closest(".has-error");
  if (wrap) {
    wrap.classList.remove("has-error");
    wrap.querySelector(".field-error")?.remove();
  }
});

// Sign In
$("#signinForm").addEventListener("submit", async e => {
  e.preventDefault();
  const form = e.target;
  clearFieldErrors(form);
  const fd = new FormData(form);
  const identifier = (fd.get("email") || "").trim().toLowerCase();
  const password = fd.get("password");
  console.log("[Auth] submit start", { identifier, pickedRole, hasPw: !!password });

  // Validasi field — inline error
  let hasError = false;
  if (!identifier) { showFieldError(form, "email", "Email atau username wajib diisi"); hasError = true; }
  if (!password) { showFieldError(form, "password", "Password wajib diisi"); hasError = true; }
  else if (password.length < 6) { showFieldError(form, "password", "Password minimal 6 karakter"); hasError = true; }
  if (hasError) {
    return toast("⚠️ Lengkapi data login dulu", "warning");
  }

  // Cek lockout SEBELUM submit ke server — tampilkan banner inline (bukan modal)
  const lockMs = checkLoginLockout(identifier);
  if (lockMs > 0) {
    showLockBanner(lockMs);
    return;
  }

  // CAPTCHA gate — hanya tampil kalau user sudah failed >= CAPTCHA_AFTER_FAILS
  // attempt sebelumnya. Attempt pertama (count=0) dan kedua (count=1) mulus
  // tanpa captcha untuk reduce onboarding friction. Admin TETAP kena captcha
  // dari attempt pertama (security-critical, double-layer).
  const isAdminLogin = typeof isAllowedAdminEmail === "function" && isAllowedAdminEmail(identifier);
  const _failCount = getLoginAttempts(identifier).count || 0;
  const _captchaRequired = isAdminLogin || _failCount >= CAPTCHA_AFTER_FAILS;
  if (_captchaRequired) {
    console.log("[Auth] opening CAPTCHA", { admin: isAdminLogin, failCount: _failCount });
    const captchaPassed = await openCaptchaModal({ admin: isAdminLogin });
    console.log("[Auth] captcha result", captchaPassed);
    if (!captchaPassed) {
      return toast("⚠️ CAPTCHA verification cancelled — login cancelled", "warning");
    }
  } else {
    console.log("[Auth] CAPTCHA skipped — first attempts smooth", { failCount: _failCount });
  }

  const btn = e.target.querySelector(".auth-submit");
  btn.classList.add("loading");

  await sleep(800);

  // Resolve identifier → email. Bisa email langsung atau username.
  let email = identifier;
  let existing = null;
  if (identifier.includes("@")) {
    existing = JSON.parse(localStorage.getItem(`playly-account-${identifier}`) || "null");
  } else {
    const byUser = findAccountByUsername(identifier);
    if (byUser) {
      email = byUser.email.toLowerCase();
      existing = byUser;
    }
  }
  console.log("[Auth] account lookup", { email, found: !!existing, hasPin: !!existing?.pin, role: existing?.role, tier: existing?.tier, registered: existing?.userRegistered });

  // Helper: catat kegagalan + tampilkan inline field error + sisa percobaan.
  // field: "email" atau "password" — error muncul tepat di field bersangkutan
  // dari percobaan PERTAMA (bukan nunggu lockout).
  const onFail = (field, fieldMsg, toastMsg) => {
    const after = recordLoginFailure(identifier);
    const remaining = LOGIN_MAX_ATTEMPTS - after.count;
    btn.classList.remove("loading");
    if (after.lockedUntil > Date.now()) {
      showLockBanner(after.lockedUntil - Date.now());
      return;
    }
    const remTxt = remaining > 0 ? ` (sisa percobaan: ${remaining})` : "";
    showFieldError(form, field, fieldMsg + remTxt);
    return toast(`${toastMsg}${remTxt}`, "error");
  };

  // Tidak ketemu akun & input bukan email valid → user salah ketik
  if (!existing && !identifier.includes("@")) {
    return onFail("email", "Username tidak ditemukan", "❌ Username tidak ditemukan");
  }

  // Akun harus sudah terdaftar — tidak ada auto-create dari email asing.
  // Login gagal (email belum terdaftar) → catat sebagai kegagalan, tetap di halaman login.
  if (!existing) {
    return onFail("email", "Email belum terdaftar — silakan Daftar dulu", "❌ Email belum terdaftar — silakan Daftar dulu");
  }

  // Verifikasi password DULU — sebelum guard role. Kalau password salah, user
  // hanya lihat pesan "Password salah" (tidak bocor info bahwa email itu admin).
  // Popup "Akses Ditolak" hanya untuk credentials yang sudah lulus verifikasi.
  const passwordOk = await verifyPassword(password, existing.password);
  console.log("[Auth] password check", passwordOk);
  if (!passwordOk) {
    // B6b P1 telemetry (2026-05-25 v545): kalau local reject, panggil bridge
    // verify juga untuk catat false-negative case (local salah / hash drift).
    // Fire-and-forget, jangan block onFail.
    try { recordAuthVerifyTelemetry(email, password, /*localOk=*/false); } catch (_) {}
    return onFail("password", "Password salah", "❌ Password salah");
  }

  // B6b P1 telemetry: local pass → cek apakah bridge setuju. Background only,
  // zero behavior change. Tujuan: ukur agreement rate sebelum P2 cutover.
  try { recordAuthVerifyTelemetry(email, password, /*localOk=*/true); } catch (_) {}

  // Bug #1 fix (2026-05-20): cek suspended SETELAH password OK. tryAutoBoot
  // sudah cek ini, tapi handler login utama bypass — celah keamanan: user
  // di-suspend admin tetap bisa login normal di device lain. Sekarang block
  // login pada level handler.
  if (existing.suspended === true) {
    btn.classList.remove("loading");
    return openAlert({
      icon: "⛔",
      iconClass: "danger",
      title: "Akun Di-suspend",
      desc: existing.suspendedReason
        ? `Akun kamu di-suspend oleh admin. Alasan: ${existing.suspendedReason}. Hubungi support.`
        : "Akun kamu di-suspend oleh admin. Hubungi support untuk informasi lebih lanjut.",
      btnText: "Mengerti",
      btnClass: "danger"
    });
  }

  // Guard: akun admin (super admin / admin tambahan) tidak boleh login lewat halaman User (/).
  // Jangan auto-redirect ke /admin — tiap URL harus tetap di domainnya sendiri.
  // Dicek SETELAH password verified supaya popup hanya muncul ke admin asli, bukan ke
  // user yang kebetulan salah ketik email.
  if (isAllowedAdminEmail(email) && pickedRole !== "admin") {
    btn.classList.remove("loading");
    return openAlert({
      icon: "⚠️",
      iconClass: "warn",
      title: "Akses Ditolak",
      desc: `Akun admin tidak bisa login di halaman User. Gunakan kredensial user untuk login di sini.`,
      btnText: "Mengerti",
      btnClass: "primary"
    });
  }

  // Guard: halaman /admin hanya untuk akun yang ada di allowlist admin.
  // Jangan auto-redirect ke / — tiap URL harus tetap di domainnya sendiri.
  if (pickedRole === "admin" && !isAllowedAdminEmail(email)) {
    btn.classList.remove("loading");
    return openAlert({
      icon: "🔒",
      iconClass: "danger",
      title: "Akses Admin Ditolak",
      desc: `Akun ini bukan administrator. Halaman ini khusus admin platform.`,
      btnText: "Mengerti",
      btnClass: "danger"
    });
  }
  // Lazy upgrade ke format hash terbaru (plaintext → h3, h2 → h3)
  if (!isLatestHashFormat(existing.password)) {
    existing.password = await hashPassword(password);
    localStorage.setItem(`playly-account-${existing.email}`, JSON.stringify(existing));
  }
  // PERMANENT PROTECTION FLAG (per fix user 2026-05-15 v16): back-fill flag
  // userRegistered untuk akun yang berhasil login. Akun lama yang dibuat sebelum
  // patch ini akan dapat flag saat user login pertama kali setelah patch.
  // Setelah ini, shouldBanAccount() permanent skip akun ini selamanya.
  if (!existing.userRegistered) {
    existing.userRegistered = true;
    existing.registeredAt = existing.registeredAt || Date.now();
    localStorage.setItem(`playly-account-${existing.email}`, JSON.stringify(existing));
    // Auto-unban email kalau sempat di banned-list (defensive)
    try {
      const banned = JSON.parse(localStorage.getItem(BANNED_EMAILS_KEY) || "[]");
      const filtered = banned.filter(e => String(e).toLowerCase() !== existing.email.toLowerCase());
      if (filtered.length !== banned.length) {
        localStorage.setItem(BANNED_EMAILS_KEY, JSON.stringify(filtered));
      }
    } catch {}
  }
  // === 2FA: kalau akun punya PIN, minta PIN sebelum login ===
  // Pass verifier ke modal — modal auto-verify saat 6 digit terisi.
  // Returns: pin string (kalau valid) atau null (kalau cancel).
  if (existing.pin) {
    console.log("[Auth] opening 2FA modal");
    btn.classList.remove("loading");
    const enteredPin = await open2FAModal(pin => verifyPin(pin, existing.pin));
    console.log("[Auth] 2FA result", enteredPin === null ? "cancel" : "verified");
    if (enteredPin === null) {
      return; // user cancel — tetap di halaman login
    }
    // Sampai sini pasti valid karena modal sudah verify internal.
    btn.classList.add("loading"); // resume loading
  }
  // Force role berdasarkan allowlist admin — bukan dari data lama yang mungkin sudah dimanipulasi
  const correctRole = isAllowedAdminEmail(existing.email) ? "admin" : "user";
  user = { name: existing.name, username: existing.username, email: existing.email, joinedAt: existing.joinedAt, role: correctRole, tier: existing.tier || "free", premiumPlan: existing.premiumPlan || null, premiumStartedAt: existing.premiumStartedAt || null, premiumExpiresAt: existing.premiumExpiresAt || null, loggedInAt: Date.now() /* C-4 U-L1: session expiry stamp */ };

  // === SUPABASE AUTH BRIDGE (Phase B1, 2026-05-22) + HYDRATION (B4, 2026-05-25) ===
  // Sync legacy signin → Supabase auth.users (server-side, set cookie).
  // SETELAH cookie ter-set, pull state + profile dari Supabase dan apply
  // kalau cloud lebih baru — enables cross-device dashboard continuity.
  // Non-blocking di sini — boot loop yang await dgn budget waktu 1.5s.
  const _bridgeHydrationPromise = (async () => {
    try {
      const syncRes = await window.supabaseAuthBridge?.syncSignin?.(email, password, user);
      if (syncRes && syncRes.synced) {
        // Hydrate state + profile paralel (independent endpoints).
        const [stateRes, profileRes] = await Promise.all([
          hydrateStateFromCloud(user.username),
          hydrateProfileFromCloud(user.email),
        ]);
        return { state: stateRes, profile: profileRes };
      }
    } catch (_) {}
    return null;
  })();

  // C-4 U-L3 fix (2026-05-21): kalau admin reset password user, mustChangePassword
  // di-set true. Warn user supaya ganti via Settings → Account.
  if (existing.mustChangePassword) {
    setTimeout(() => {
      if (typeof toast === "function") {
        toast("🔑 Admin meng-reset password kamu. <b>Segera ganti password</b> via Settings → Akun.", "warning");
      }
    }, 1500);
  }

  // Login berhasil → reset rate limit counter & sembunyikan banner kalau masih ada
  clearLoginAttempts(identifier);
  hideLockBanner();

  localStorage.setItem("playly-user", JSON.stringify(user));
  // Track akun ini sebagai akun yang pernah login di device ini (untuk fitur
  // Pindah Akun). Hanya dipanggil di sini — bukan di auto-boot atau update.
  addDeviceAccount(user.email);
  state = loadState(user.username);
  btn.classList.remove("loading");

  // Login berhasil → tutup auth modal + tampilkan welcome overlay animated
  // (admin & user dapat overlay variant masing-masing) → boot dashboard.
  const isAdmin = isAllowedAdminEmail(user.email);
  console.log("[Auth] login success — opening welcome", { isAdmin, name: user.name });
  if (typeof closeAuthModal === "function") closeAuthModal();

  // Capture and clear guest plan before boot so the popup fires once
  const guestPlanAfterLogin = window._guestPickedPlan || null;
  if (guestPlanAfterLogin) delete window._guestPickedPlan;

  const afterBoot = () => {
    if (guestPlanAfterLogin && !isAdmin) {
      setTimeout(() => _openPostLoginPlanPopup(guestPlanAfterLogin), 450);
    }
  };

  // Defensive boot: kalau welcome overlay element missing atau animasi gagal
  // (CSS removed, race condition, dst), kita tetap WAJIB boot dashboard.
  // Sebelumnya: kalau showUserWelcome gagal panggil done(), user stuck di
  // layar putih / login screen tanpa feedback.
  let booted = false;
  const safeBoot = async () => {
    if (booted) return;
    booted = true;
    // Phase B4 (2026-05-25): tunggu hydration cloud max 1.5s sebelum
    // bootDashboard supaya first render pakai data terbaru dari cloud
    // (cross-device sync). Kalau cloud lambat, boot dgn local — hydration
    // selesai di background lalu trigger renderAll() sendiri.
    try {
      await Promise.race([
        _bridgeHydrationPromise,
        new Promise(r => setTimeout(r, 1500)),
      ]);
      // Re-load state dari localStorage — kalau hydration sudah apply, ini
      // baca versi cloud; kalau belum, baca versi local.
      if (user && user.username) {
        try { state = loadState(user.username); } catch (_) {}
      }
    } catch (_) {}
    console.log("[Auth] booting dashboard");
    try { bootDashboard(); afterBoot(); }
    catch (err) { console.error("[Auth] bootDashboard threw:", err); toast("⚠️ Gagal masuk dashboard — refresh halaman", "error"); }
  };
  // Failsafe: 3.5s setelah welcome triggered, kalau done() belum panggil → force boot.
  setTimeout(() => { if (!booted) { console.warn("[Auth] welcome callback timeout — force boot"); safeBoot(); } }, 3500);
  try {
    if (isAdmin) {
      showAdminWelcome(user.name.split(" ")[0], safeBoot);
    } else {
      showUserWelcome(user.name.split(" ")[0], safeBoot);
    }
  } catch (err) {
    console.error("[Auth] showWelcome threw — force boot:", err);
    safeBoot();
  }
});

/* Admin welcome overlay — tampilkan setelah login success, animasikan
   selama ~1.8s, lalu callback (biasanya bootDashboard).
   Animasi restart otomatis karena CSS di-scope ke [data-show]. */
function showAdminWelcome(name, done) {
  const ov = document.getElementById("adminWelcomeOverlay");
  if (!ov) { if (typeof done === "function") done(); return; }
  const nameEl = ov.querySelector("#awoName");
  if (nameEl && name) nameEl.textContent = name;
  ov.removeAttribute("data-closing");
  ov.removeAttribute("data-show");
  requestAnimationFrame(() => requestAnimationFrame(() => {
    ov.setAttribute("data-show", "");
    setTimeout(() => {
      if (typeof done === "function") done();
      setTimeout(() => {
        ov.removeAttribute("data-show");
        ov.setAttribute("data-closing", "");
        setTimeout(() => { ov.removeAttribute("data-closing"); }, 350);
      }, 150);
    }, 1800);
  }));
}

/* User welcome card — wine/gold animated card, tampilkan setelah user login/daftar.
   Per user 2026-05-06: differentiate teks new vs returning user.
   - New user (first time): "Welcome" + name + "Mari mulai berkreasi"
   - Returning user: "Welcome back" + name + "Siap berkreasi hari ini?" */
function showUserWelcome(name, done) {
  const ov = document.getElementById("userWelcomeCard");
  if (!ov) { if (typeof done === "function") done(); return; }
  const nameEl = ov.querySelector("#uwcName");
  const subEl = ov.querySelector(".uwc-sub");
  const taglineEl = ov.querySelector(".uwc-tagline");
  if (nameEl && name) nameEl.textContent = name;

  // Detect new vs returning via welcomed flag (per-username)
  const username = user?.username || "anon";
  const welcomedKey = `playly-welcomed-${username}`;
  const isNewUser = !localStorage.getItem(welcomedKey);
  const isID = (typeof currentLang === "function") ? (currentLang() === "id") : true;
  if (subEl) {
    subEl.textContent = isNewUser
      ? (isID ? "Selamat datang," : "Welcome,")
      : (isID ? "Selamat datang kembali," : "Welcome back,");
  }
  if (taglineEl) {
    taglineEl.textContent = isNewUser
      ? (isID ? "Mari mulai berkreasi & explore Playly!" : "Let's start creating & explore Playly!")
      : (isID ? "Siap berkreasi hari ini?" : "Ready to create today?");
  }
  // Mark as welcomed setelah first time tampilkan welcome (next time = returning)
  try { localStorage.setItem(welcomedKey, "1"); } catch {}

  ov.removeAttribute("data-closing");
  ov.removeAttribute("data-show");
  requestAnimationFrame(() => requestAnimationFrame(() => {
    ov.setAttribute("data-show", "");
    setTimeout(() => {
      // Mulai close animation dulu, baru boot dashboard setelah selesai
      ov.removeAttribute("data-show");
      ov.setAttribute("data-closing", "");
      setTimeout(() => {
        ov.removeAttribute("data-closing");
        if (typeof done === "function") done();
      }, 420);
    }, 2000);
  }));
}

// Proactive lockout probe — jalankan tiap user ketik di field email/username login.
// Debounce 350ms supaya tidak spam saat masih mengetik.
(() => {
  const form = $("#signinForm");
  if (!form) return;
  const input = form.querySelector('input[name="email"]');
  if (!input) return;
  input.addEventListener("input", () => {
    if (_signinLockProbe) clearTimeout(_signinLockProbe);
    _signinLockProbe = setTimeout(probeSigninLockout, 350);
  });
  // Cek juga saat form pertama kali dimuat (kalau autofill ngisi email locked)
  setTimeout(probeSigninLockout, 50);
  // Banner "Reset di sini" → trigger handler forgot password yang sudah ada
  form.addEventListener("click", e => {
    const link = e.target.closest('[data-auth-action="forgot"]');
    if (!link) return;
    e.preventDefault();
    $("#forgotPw")?.click();
  });
})();


// ----------------------- MODERN CAPTCHA SYSTEM -----------------------
// 4 verification variants, random pick per call:
//   A — press-hold : press & hold ~1.5s (Cloudflare Turnstile style)
//   B — slide      : drag handle left → right (Tencent/Alibaba style)
//   C — invisible  : auto-pass after brief "analyzing" spinner
//   D — checkbox   : click → spinner → check (reCAPTCHA v2 style)
// Admin login excludes "invisible" (always require active interaction).
// openCaptchaModal({ admin? }) returns Promise<boolean>.

let _captchaResolver = null;
let _captchaCurrentVariant = null;
const CAPTCHA_VARIANTS = ["press-hold", "slide", "invisible", "checkbox"];

function pickCaptchaVariant(opts = {}) {
  const pool = opts.admin
    ? CAPTCHA_VARIANTS.filter(v => v !== "invisible")
    : CAPTCHA_VARIANTS;
  return pool[Math.floor(Math.random() * pool.length)];
}

function openCaptchaModal(opts = {}) {
  return new Promise(resolve => {
    const modal = document.getElementById("captchaModal");
    if (!modal) { resolve(true); return; }

    // Resolve previous (if any) as cancelled — prevents stuck promises.
    if (_captchaResolver) { try { _captchaResolver(false); } catch {} }
    _captchaResolver = resolve;

    const variant = pickCaptchaVariant(opts);
    _captchaCurrentVariant = variant;
    modal.dataset.captchaType = variant;
    modal.dataset.captchaAdmin = opts.admin ? "1" : "0";

    // Show only the picked variant stage
    modal.querySelectorAll("[data-cap-stage]").forEach(s => {
      s.hidden = s.dataset.capStage !== variant;
    });

    // Reset & wire up the variant
    if (variant === "press-hold") setupCaptchaPressHold(opts);
    else if (variant === "slide")   setupCaptchaSlide(opts);
    else if (variant === "invisible") setupCaptchaInvisible(opts);
    else if (variant === "checkbox")  setupCaptchaCheckbox(opts);

    modal.classList.add("show");
    document.body.style.overflow = "hidden";
  });
}

function closeCaptchaModal(passed) {
  const modal = document.getElementById("captchaModal");
  if (!modal) return;
  modal.classList.remove("show");
  document.body.style.overflow = "";
  cleanupAllCaptchaVariants();
  if (_captchaResolver) {
    const r = _captchaResolver;
    _captchaResolver = null;
    try { r(!!passed); } catch {}
  }
}

function cleanupAllCaptchaVariants() {
  if (_pressHoldTimer) { clearTimeout(_pressHoldTimer); _pressHoldTimer = null; }
  if (_invisibleTimer) { clearTimeout(_invisibleTimer); _invisibleTimer = null; }
  if (_checkboxTimer) { clearTimeout(_checkboxTimer); _checkboxTimer = null; }
  if (_slideDragHandlers) {
    document.removeEventListener("mousemove", _slideDragHandlers.move);
    document.removeEventListener("mouseup", _slideDragHandlers.up);
    document.removeEventListener("touchmove", _slideDragHandlers.move);
    document.removeEventListener("touchend", _slideDragHandlers.up);
    _slideDragHandlers = null;
  }
}

// === A: PRESS & HOLD ===
let _pressHoldTimer = null;
let _pressHoldStart = 0;
let _pressHoldHandlers = null;
const PRESS_HOLD_MS = 1500;
const PRESS_HOLD_MS_ADMIN = 2200;

function setupCaptchaPressHold(opts = {}) {
  const btn = document.getElementById("capPressBtn");
  const fill = document.getElementById("capPressFill");
  const label = document.getElementById("capPressLabel");
  if (!btn || !fill || !label) return;

  const targetMs = opts.admin ? PRESS_HOLD_MS_ADMIN : PRESS_HOLD_MS;

  // Reset visual
  btn.classList.remove("pressing", "fail", "done");
  fill.style.transition = "none";
  fill.style.strokeDashoffset = "276.46";
  label.textContent = "Tahan untuk verifikasi";

  // Force reflow so the next transition restart cleanly
  void fill.offsetWidth;

  const start = (e) => {
    if (e.cancelable) e.preventDefault();
    if (btn.classList.contains("done")) return;
    btn.classList.add("pressing");
    btn.classList.remove("fail");
    _pressHoldStart = Date.now();
    label.textContent = "Tahan terus…";
    fill.style.transition = `stroke-dashoffset ${targetMs}ms linear`;
    fill.style.strokeDashoffset = "0";

    _pressHoldTimer = setTimeout(() => {
      btn.classList.remove("pressing");
      btn.classList.add("done");
      label.textContent = "Terverifikasi ✓";
      setTimeout(() => closeCaptchaModal(true), 360);
    }, targetMs);
  };
  const cancel = () => {
    if (!btn.classList.contains("pressing")) return;
    btn.classList.remove("pressing");
    if (_pressHoldTimer) { clearTimeout(_pressHoldTimer); _pressHoldTimer = null; }
    const elapsed = Date.now() - _pressHoldStart;
    if (elapsed < targetMs - 50) {
      btn.classList.add("fail");
      fill.style.transition = "stroke-dashoffset 0.35s ease";
      fill.style.strokeDashoffset = "276.46";
      label.textContent = "Lepas terlalu cepat — coba lagi";
      setTimeout(() => {
        btn.classList.remove("fail");
        label.textContent = "Tahan untuk verifikasi";
      }, 900);
    }
  };

  // Remove old handlers, attach fresh
  if (_pressHoldHandlers) {
    btn.removeEventListener("mousedown", _pressHoldHandlers.start);
    btn.removeEventListener("touchstart", _pressHoldHandlers.start);
    btn.removeEventListener("mouseup", _pressHoldHandlers.cancel);
    btn.removeEventListener("mouseleave", _pressHoldHandlers.cancel);
    btn.removeEventListener("touchend", _pressHoldHandlers.cancel);
    btn.removeEventListener("touchcancel", _pressHoldHandlers.cancel);
  }
  _pressHoldHandlers = { start, cancel };
  btn.addEventListener("mousedown", start);
  btn.addEventListener("touchstart", start, { passive: false });
  btn.addEventListener("mouseup", cancel);
  btn.addEventListener("mouseleave", cancel);
  btn.addEventListener("touchend", cancel);
  btn.addEventListener("touchcancel", cancel);
}

// === B: SLIDE TO VERIFY ===
let _slideDragHandlers = null;
let _slideHandleHandlers = null;

function setupCaptchaSlide(opts = {}) {
  const track = document.getElementById("capSlideTrack");
  const handle = document.getElementById("capSlideHandle");
  const fill = document.getElementById("capSlideFill");
  const label = document.getElementById("capSlideLabel");
  if (!track || !handle || !fill || !label) return;

  // Reset visual
  track.classList.remove("dragging", "done", "snap-back");
  fill.classList.remove("snap-back");
  handle.style.left = "4px";
  fill.style.width = "0px";
  label.textContent = "Geser ke kanan untuk verifikasi →";

  const onDown = (e) => {
    if (track.classList.contains("done")) return;
    if (e.cancelable) e.preventDefault();
    track.classList.add("dragging");
    track.classList.remove("snap-back");
    fill.classList.remove("snap-back");
    const trackRect = track.getBoundingClientRect();
    const handleW = handle.offsetWidth;
    const maxX = trackRect.width - handleW - 8; // 4px padding each side

    const startX = (e.touches ? e.touches[0].clientX : e.clientX);
    const startLeft = handle.offsetLeft;

    const move = (ev) => {
      const cx = (ev.touches ? ev.touches[0].clientX : ev.clientX);
      let dx = cx - startX;
      let nx = Math.max(4, Math.min(maxX + 4, startLeft + dx));
      handle.style.left = nx + "px";
      fill.style.width = (nx - 4 + handleW) + "px";
      // Verify when at far right
      if (nx >= maxX + 3.5) {
        finish();
      }
    };
    const up = () => {
      if (track.classList.contains("done")) return;
      document.removeEventListener("mousemove", move);
      document.removeEventListener("mouseup", up);
      document.removeEventListener("touchmove", move);
      document.removeEventListener("touchend", up);
      track.classList.remove("dragging");
      // Check if reached end
      const finalLeft = handle.offsetLeft;
      if (finalLeft >= maxX + 3.5) {
        finish();
      } else {
        // Snap back
        track.classList.add("snap-back");
        fill.classList.add("snap-back");
        handle.style.left = "4px";
        fill.style.width = "0px";
      }
      _slideDragHandlers = null;
    };
    const finish = () => {
      document.removeEventListener("mousemove", move);
      document.removeEventListener("mouseup", up);
      document.removeEventListener("touchmove", move);
      document.removeEventListener("touchend", up);
      track.classList.remove("dragging");
      track.classList.add("done");
      handle.style.left = (maxX + 4) + "px";
      fill.style.width = "100%";
      label.textContent = "Terverifikasi ✓";
      _slideDragHandlers = null;
      setTimeout(() => closeCaptchaModal(true), 360);
    };

    _slideDragHandlers = { move, up };
    document.addEventListener("mousemove", move);
    document.addEventListener("mouseup", up);
    document.addEventListener("touchmove", move, { passive: false });
    document.addEventListener("touchend", up);
  };

  if (_slideHandleHandlers) {
    handle.removeEventListener("mousedown", _slideHandleHandlers);
    handle.removeEventListener("touchstart", _slideHandleHandlers);
  }
  _slideHandleHandlers = onDown;
  handle.addEventListener("mousedown", onDown);
  handle.addEventListener("touchstart", onDown, { passive: false });
}

// === C: INVISIBLE / FRICTIONLESS ===
let _invisibleTimer = null;
const INVISIBLE_MS = 1300;

function setupCaptchaInvisible(opts = {}) {
  const stage = document.querySelector('[data-cap-stage="invisible"]');
  const label = document.getElementById("capInvisibleLabel");
  const wrap = stage?.querySelector(".cap-invisible");
  if (!wrap || !label) return;
  wrap.classList.remove("done");
  label.textContent = "Menganalisis pola interaksi…";

  _invisibleTimer = setTimeout(() => {
    wrap.classList.add("done");
    label.textContent = "Terverifikasi ✓";
    setTimeout(() => closeCaptchaModal(true), 500);
  }, INVISIBLE_MS);
}

// === D: CHECKBOX ===
let _checkboxTimer = null;
let _checkboxHandler = null;

function setupCaptchaCheckbox(opts = {}) {
  const btn = document.getElementById("capCheckboxBtn");
  const spinner = document.getElementById("capCheckboxSpinner");
  const check = document.getElementById("capCheckboxCheck");
  const text = document.getElementById("capCheckboxText");
  if (!btn || !spinner || !check || !text) return;

  // Reset
  btn.classList.remove("verifying", "done");
  btn.disabled = false;
  spinner.hidden = true;
  text.textContent = "Saya bukan robot";

  const onClick = () => {
    if (btn.classList.contains("done") || btn.classList.contains("verifying")) return;
    btn.classList.add("verifying");
    btn.disabled = true;
    spinner.hidden = false;
    text.textContent = "Memverifikasi…";

    _checkboxTimer = setTimeout(() => {
      btn.classList.remove("verifying");
      btn.classList.add("done");
      spinner.hidden = true;
      text.textContent = "Terverifikasi ✓";
      setTimeout(() => closeCaptchaModal(true), 380);
    }, 900);
  };

  if (_checkboxHandler) btn.removeEventListener("click", _checkboxHandler);
  _checkboxHandler = onClick;
  btn.addEventListener("click", onClick);
}

// === Init: cancel/close handlers ===
(function initModernCaptcha() {
  const modal = document.getElementById("captchaModal");
  if (!modal) return;
  // Backdrop + close button + Batal button — all use [data-captcha-cancel]
  modal.addEventListener("click", (e) => {
    if (e.target.closest("[data-captcha-cancel]")) {
      closeCaptchaModal(false);
    }
  });
  // ESC to cancel
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape" && modal.classList.contains("show")) {
      closeCaptchaModal(false);
    }
  });
})();


// ----------------------- 2FA PIN MODAL -----------------------
// Setelah password verified saat signin, kalau akun punya `pin` → minta PIN.
// Modal dengan 6 input box angka (auto-advance saat ketik).
// Per user 2026-05-07: auto-verify saat 6 digit terisi (tidak perlu klik button).
//   - Kalau verifier return true → modal close, resolve(pin)
//   - Kalau false → tampilkan error inline, clear inputs, focus ulang
let twoFAResolver = null;
let twoFAVerifyFn = null;

function open2FAModal(verifyFn) {
  const modal = $("#twoFAModal");
  if (!modal) return Promise.resolve(null);
  return new Promise(resolve => {
    twoFAResolver = resolve;
    twoFAVerifyFn = (typeof verifyFn === "function") ? verifyFn : null;
    modal.classList.add("show");
    // Reset inputs + focus pertama
    const inputs = $$("[data-pin-idx]", modal);
    inputs.forEach(i => { i.value = ""; i.classList.remove("twofa-input-error"); });
    $("#twoFAError").hidden = true;
    setTimeout(() => inputs[0]?.focus(), 100);
  });
}

// Auto-verify dipanggil dari input handler saat 6 digit komplet
function tryAutoVerify2FA() {
  const modal = $("#twoFAModal");
  if (!modal) return;
  const inputs = $$("[data-pin-idx]", modal);
  const pin = inputs.map(i => i.value).join("");
  if (pin.length !== 6) return;
  // Kalau ada verifier function → cek dulu
  if (twoFAVerifyFn) {
    const ok = twoFAVerifyFn(pin);
    if (ok) {
      close2FAModal(pin);
    } else {
      // Salah: shake + error msg + clear + refocus
      const err = $("#twoFAError");
      if (err) {
        err.textContent = "❌ Kode autentifikasi salah, coba lagi";
        err.hidden = false;
      }
      inputs.forEach(i => { i.classList.add("twofa-input-error"); i.value = ""; });
      setTimeout(() => {
        inputs.forEach(i => i.classList.remove("twofa-input-error"));
        inputs[0]?.focus();
      }, 600);
    }
  } else {
    // No verifier — resolve langsung (backward compat)
    close2FAModal(pin);
  }
}

function close2FAModal(result) {
  const modal = $("#twoFAModal");
  if (!modal) return;
  modal.classList.remove("show");
  if (twoFAResolver) {
    twoFAResolver(result);
    twoFAResolver = null;
  }
}

// ----------------------- SETUP PIN MODAL (post-signup / from settings) -----------------------
// Modal untuk SET (bukan verifikasi) PIN 2FA. Returns Promise<string|null>:
// - string PIN 6-digit kalau user klik Aktifkan dengan PIN valid
// - null kalau user klik Lewati / Batal
let setupPinResolver = null;

function openSetupPinModal({ context = "signup" } = {}) {
  const modal = $("#setupPinModal");
  if (!modal) return Promise.resolve(null);
  const title = $("#setupPinTitle");
  const desc = $("#setupPinDesc");
  if (context === "settings") {
    if (title) title.textContent = "Set 2FA PIN";
    if (desc) desc.textContent = "Create a new 6-digit PIN. The PIN is required at every login for extra security.";
  } else {
    if (title) title.textContent = "Enable 2FA?";
    if (desc) desc.textContent = "Create a 6-digit PIN for extra verification at login. You can skip and set it later in Settings.";
  }
  // Reset inputs + clear error
  const inputs = $$("[data-setpin-idx]", modal);
  inputs.forEach(i => { i.value = ""; });
  $("#setupPinError").hidden = true;
  modal.classList.add("show");
  setTimeout(() => inputs[0]?.focus(), 100);
  return new Promise(resolve => { setupPinResolver = resolve; });
}

function closeSetupPinModal(result) {
  const modal = $("#setupPinModal");
  if (!modal) return;
  modal.classList.remove("show");
  if (setupPinResolver) {
    setupPinResolver(result);
    setupPinResolver = null;
  }
}

function initSetupPinModal() {
  const modal = $("#setupPinModal");
  if (!modal) return;
  const inputs = $$("[data-setpin-idx]", modal);
  inputs.forEach((inp, idx) => {
    inp.addEventListener("input", () => {
      inp.value = inp.value.replace(/\D/g, "").slice(0, 1);
      if (inp.value && idx < inputs.length - 1) inputs[idx + 1].focus();
    });
    inp.addEventListener("keydown", e => {
      if (e.key === "Backspace" && !inp.value && idx > 0) inputs[idx - 1].focus();
      if (e.key === "Enter") $("#setupPinSave")?.click();
    });
    inp.addEventListener("paste", e => {
      e.preventDefault();
      const text = (e.clipboardData?.getData("text") || "").replace(/\D/g, "").slice(0, 6);
      if (!text) return;
      [...text].forEach((ch, i) => { if (inputs[i]) inputs[i].value = ch; });
      inputs[Math.min(text.length, 5)].focus();
    });
  });
  $("#setupPinSave")?.addEventListener("click", () => {
    const pin = inputs.map(i => i.value).join("");
    if (!/^\d{6}$/.test(pin)) {
      const err = $("#setupPinError");
      err.textContent = "PIN harus tepat 6 digit angka";
      err.hidden = false;
      return;
    }
    closeSetupPinModal(pin);
  });
  $("#setupPinSkip")?.addEventListener("click", () => closeSetupPinModal(null));
  modal.querySelector(".modal-backdrop")?.addEventListener("click", () => closeSetupPinModal(null));
}
initSetupPinModal();

// ----------------------- SETTINGS: 2FA management -----------------------
function refreshTwoFASettings() {
  if (!user) return;
  const acc = JSON.parse(localStorage.getItem(`playly-account-${user.email}`) || "null");
  const enabled = !!acc?.pin;
  const label = $("#twofaStatusLabel");
  const badge = $("#twofaBadge");
  const hint = $("#twofaStatusHint");
  const activate = $("#twofaActivate");
  const change = $("#twofaChange");
  const disable = $("#twofaDisable");
  if (label) label.textContent = enabled ? "Aktif ✓" : "Nonaktif";
  if (badge) {
    badge.textContent = enabled ? "ON" : "OFF";
    badge.classList.toggle("on", enabled);
  }
  if (hint) hint.textContent = enabled
    ? "PIN 6-digit kamu diminta setiap kali login. Bagus untuk keamanan!"
    : "Tambah lapisan keamanan dengan PIN 6 digit yang diminta saat login.";
  if (activate) activate.hidden = enabled;
  if (change) change.hidden = !enabled;
  if (disable) disable.hidden = !enabled;
}

async function handleTwoFAActivate() {
  const pin = await openSetupPinModal({ context: "settings" });
  if (!pin) return;
  const acc = JSON.parse(localStorage.getItem(`playly-account-${user.email}`) || "{}");
  acc.pin = hashPin(pin);
  localStorage.setItem(`playly-account-${user.email}`, JSON.stringify(acc));
  toast("🔐 2FA aktif. PIN akan diminta saat login.", "success");
  refreshTwoFASettings();
}

function handleTwoFADisable() {
  if (!user) return;
  openConfirm({
    icon: "⚠️",
    iconClass: "warn",
    title: "Nonaktifkan 2FA?",
    desc: "PIN tidak akan diminta lagi saat login. Akun jadi kurang aman.",
    btnText: "Ya, nonaktifkan",
    btnClass: "danger",
    onConfirm: () => {
      const acc = JSON.parse(localStorage.getItem(`playly-account-${user.email}`) || "{}");
      delete acc.pin;
      localStorage.setItem(`playly-account-${user.email}`, JSON.stringify(acc));
      toast("🔓 2FA dinonaktifkan", "success");
      refreshTwoFASettings();
    }
  });
}

$("#twofaActivate")?.addEventListener("click", handleTwoFAActivate);
$("#twofaChange")?.addEventListener("click", handleTwoFAActivate);
$("#twofaDisable")?.addEventListener("click", handleTwoFADisable);

function init2FAModal() {
  const modal = $("#twoFAModal");
  if (!modal) return;
  const inputs = $$("[data-pin-idx]", modal);
  inputs.forEach((inp, idx) => {
    inp.addEventListener("input", e => {
      // Hanya angka
      inp.value = inp.value.replace(/\D/g, "").slice(0, 1);
      if (inp.value && idx < inputs.length - 1) inputs[idx + 1].focus();
      // Per user 2026-05-07: auto-verify saat 6 digit komplet (no need klik button)
      const pin = inputs.map(i => i.value).join("");
      if (pin.length === 6) {
        // Defer 1 frame supaya last input visually update dulu
        requestAnimationFrame(tryAutoVerify2FA);
      }
    });
    inp.addEventListener("keydown", e => {
      if (e.key === "Backspace" && !inp.value && idx > 0) inputs[idx - 1].focus();
      if (e.key === "Enter") {
        const pin = inputs.map(i => i.value).join("");
        if (pin.length === 6) tryAutoVerify2FA();
      }
      if (e.key === "Escape") close2FAModal(null);
    });
    inp.addEventListener("paste", e => {
      e.preventDefault();
      const text = (e.clipboardData?.getData("text") || "").replace(/\D/g, "").slice(0, 6);
      if (!text) return;
      [...text].forEach((ch, i) => { if (inputs[i]) inputs[i].value = ch; });
      inputs[Math.min(text.length, 5)].focus();
      // Auto-verify kalau paste full 6 digit
      if (text.length === 6) requestAnimationFrame(tryAutoVerify2FA);
    });
  });
  // Backdrop click → cancel (button Batal udah dihapus per user 2026-05-07).
  // ESC key di-handle di keydown listener input di atas. Auto-verify ngurus
  // submit saat 6 digit komplet.
  modal.querySelector(".modal-backdrop[data-close]")?.addEventListener("click", () => {
    close2FAModal(null);
  });
}
init2FAModal();

// Sign Up
$("#signupForm").addEventListener("submit", async e => {
  e.preventDefault();
  const form = e.target;
  const btn = form.querySelector(".auth-submit");

  try {
    clearFieldErrors(form);
    const fd = new FormData(form);
    const name = (fd.get("name") || "").trim();
    const username = (fd.get("username") || "").trim().toLowerCase();
    const email = (fd.get("email") || "").trim().toLowerCase();
    const password = fd.get("password") || "";

    // Validasi field — inline error + shake + auto-focus
    let hasError = false;
    if (!name) { showFieldError(form, "name", "Nama wajib diisi"); hasError = true; }
    else if (name.length < 2) { showFieldError(form, "name", "Nama minimal 2 karakter"); hasError = true; }

    if (!username) { showFieldError(form, "username", "Username wajib diisi"); hasError = true; }
    else if (!/^[a-z0-9_.]{3,20}$/.test(username)) { showFieldError(form, "username", "3-20 karakter, hanya huruf kecil, angka, _ atau ."); hasError = true; }

    if (!email) { showFieldError(form, "email", "Email wajib diisi"); hasError = true; }
    else if (!/^[^@]+@[^@]+\.[^@]+$/.test(email)) { showFieldError(form, "email", "Format email tidak valid (contoh: nama@email.com)"); hasError = true; }

    if (!password) { showFieldError(form, "password", "Password wajib diisi"); hasError = true; }
    else if (password.length < 6) { showFieldError(form, "password", "Password minimal 6 karakter"); hasError = true; }

    const termsCheckbox = form.querySelector("input[type=checkbox]");
    if (!termsCheckbox.checked) {
      toast("⚠️ Centang persetujuan Syarat & Ketentuan dulu", "warning");
      termsCheckbox.closest(".auth-check")?.classList.add("shake");
      setTimeout(() => termsCheckbox.closest(".auth-check")?.classList.remove("shake"), 450);
      hasError = true;
    }

    if (hasError) {
      toast("⚠️ Ada kolom yang perlu diperbaiki — cek tanda merah", "warning");
      return;
    }

    // CR-3 fix (2026-05-21): SECURITY — force pull versi cloud terbaru
    // sebelum cek dup. Tanpa ini, attacker bisa exploit cross-device race:
    // Device A signup pakai email victim's yg belum sync ke Device A →
    // local check "not exist" → write new password → cloud-sync push →
    // victim account overwritten di device B.
    try {
      if (window.cloudSync?.syncSingleKey) {
        await Promise.resolve(window.cloudSync.syncSingleKey(`playly-account-${email}`));
      }
    } catch {}

    // Cek duplikat
    if (localStorage.getItem(`playly-account-${email}`)) {
      showFieldError(form, "email", "Email sudah terdaftar — coba login atau gunakan email lain");
      toast("❌ Email sudah terdaftar", "error");
      return;
    }
    if (findAccountByUsername(username)) {
      showFieldError(form, "username", "Username sudah dipakai user lain — pilih yang lain");
      toast("❌ Username sudah dipakai", "error");
      return;
    }

    // === CAPTCHA: minta verifikasi puzzle SETELAH field valid ===
    const captchaPassed = await openCaptchaModal();
    if (!captchaPassed) {
      toast("⚠️ CAPTCHA verification cancelled", "warning");
      return;
    }

    // Admin role lock: hanya OFFICIAL_ADMIN_EMAIL & OFFICIAL_ADMIN_USERNAME yang boleh jadi admin
    if (pickedRole === "admin") {
      if (!isOfficialAdminEmail(email) || !isReservedUsername(username)) {
        openAlert({
          icon: "🔒",
          iconClass: "danger",
          title: "Pendaftaran Admin Ditolak",
          desc: `Akun <b>Admin</b> sudah ditetapkan oleh sistem dan tidak bisa dibuat ulang.<br/><br/>
            Kalau kamu user biasa, silakan pilih role <b>User</b> di atas untuk mendaftar.`,
          btnText: "Pilih Role User",
          btnClass: "primary"
        });
        return;
      }
    } else {
      if (isAllowedAdminEmail(email) || isReservedUsername(username)) {
        openAlert({
          icon: "⚠️",
          iconClass: "warn",
          title: "Email atau Username Tidak Tersedia",
          desc: `Email atau username yang kamu masukkan tidak dapat dipakai untuk akun User.<br/><br/>
            Silakan gunakan email dan username lain untuk mendaftar.`,
          btnText: "Ganti Email/Username",
          btnClass: "primary"
        });
        return;
      }
    }

    btn.classList.add("loading");

    await sleep(900);

    const role = isAllowedAdminEmail(email) ? "admin" : "user";
    // Tier picker (Free/Premium) — default "free". Per request 2026-05-03.
    const tierInput = document.querySelector('#signupForm input[name="tier"]:checked');
    const tier = tierInput?.value === "premium" ? "premium" : "free";
    user = { name, username, email, role, tier, joinedAt: new Date().toISOString() };
    // Premium plan info — kalau user pilih plan via plan picker
    const pickedPlanKey = window.__playlyPickedPlan;
    if (tier === "premium" && pickedPlanKey && PREMIUM_PLANS[pickedPlanKey]) {
      user.premiumPlan = pickedPlanKey;
      user.premiumStartedAt = Date.now();
      user.premiumExpiresAt = computePremiumExpiry(pickedPlanKey);
    }
    // Buat account dulu tanpa PIN — setup 2FA opsional setelah ini
    const hashedPw = await hashPassword(password);
    const accountToSave = { ...user, password: hashedPw };
    // PERMANENT PROTECTION FLAG (per fix user 2026-05-15 v15+): tandai akun ini
    // sebagai user-registered. shouldBanAccount() check flag ini → never ban.
    // Akun terlindungi dari auto-purge cleanup, cutoff, dan resurrected-cloud check.
    accountToSave.userRegistered = true;
    accountToSave.registeredAt = Date.now();
    // v569c: tandai sebagai signup baru — onboarding tour trigger via flag ini
    // di initDashboard. Flag akan di-clear setelah user finish/skip tour.
    accountToSave.justSignedUp = true;
    if (pickedPlanKey === "trial") accountToSave.trialUsed = true;
    // Auto-unban: kalau email pernah masuk banned-list (mis. setelah admin cleanup),
    // un-ban saat user re-register fresh. Email re-registered explicitly dianggap
    // data baru — bukan resurrect dari cloud. User authoritative.
    try {
      const banned = JSON.parse(localStorage.getItem(BANNED_EMAILS_KEY) || "[]");
      const filteredBanned = banned.filter(e => String(e).toLowerCase() !== email.toLowerCase());
      if (filteredBanned.length !== banned.length) {
        localStorage.setItem(BANNED_EMAILS_KEY, JSON.stringify(filteredBanned));
      }
    } catch {}
    localStorage.setItem(`playly-account-${email}`, JSON.stringify(accountToSave));
    localStorage.setItem("playly-user", JSON.stringify(user));
    // Track akun ini di device-list — signup dianggap sebagai login pertama.
    addDeviceAccount(user.email);

    // === SUPABASE AUTH BRIDGE (Phase B1, 2026-05-22) ===
    // Sync legacy signup → Supabase auth.users. Foundation backend migration.
    // CATATAN B4: signup path TIDAK hydrate dari cloud — defaultState() di
    // baris bawah langsung wipe + push via syncState debounce, jadi cloud
    // GET segera setelahnya akan return empty state-nya kita sendiri (race).
    // Returning user yang ganti device → pakai signin path (auto-hydrate
    // dari user_state). Edge case: re-signup dgn email yg sama setelah cache
    // wipe → bridge route POST jalankan signin internal, cookie ter-set, tapi
    // state tidak ter-restore di sesi ini. Workaround: logout + login ulang.
    try { window.supabaseAuthBridge?.syncSignup?.(email, password, user); } catch (_) {}
    state = defaultState();
    saveState();

    btn.classList.remove("loading");
    toast(`🎉 Akun dibuat! Selamat datang, <b>${name.split(" ")[0]}</b>!`, "success");

    // === Tawarin setup 2FA — opsional, bisa di-skip & diatur di Settings nanti ===
    const newPin = await openSetupPinModal({ context: "signup" });
    if (newPin) {
      const acc = JSON.parse(localStorage.getItem(`playly-account-${email}`) || "{}");
      acc.pin = hashPin(newPin);
      localStorage.setItem(`playly-account-${email}`, JSON.stringify(acc));
      toast("🔐 2FA aktif. PIN diminta saat login berikutnya.", "success");
    }

    // Flow flip per request 2026-05-04: daftar dulu → pilih plan setelahnya.
    // Admin signup skips plan picker (admins don't have tier choice).
    if (role === "admin") {
      bootWithWelcome();
    } else if (window._guestPickedPlan) {
      // User arrived via plan picker (guest flow) → skip signup-pick, go direct to payment
      const pendingKey = window._guestPickedPlan;
      delete window._guestPickedPlan;
      if (pendingKey === "free") {
        // Free plan dari landing — gak butuh payment, langsung boot.
        bootWithWelcome();
      } else if (pendingKey === "trial") {
        // Trial — instant activate without payment modal
        try {
          const expiry = computePremiumExpiry("trial");
          const acc = JSON.parse(localStorage.getItem(`playly-account-${email}`) || "{}");
          acc.tier = "premium"; acc.premiumPlan = "trial"; acc.trialUsed = true;
          acc.premiumStartedAt = Date.now(); acc.premiumExpiresAt = expiry;
          localStorage.setItem(`playly-account-${email}`, JSON.stringify(acc));
          user.tier = "premium"; user.premiumPlan = "trial";
          user.premiumStartedAt = acc.premiumStartedAt; user.premiumExpiresAt = expiry;
          localStorage.setItem("playly-user", JSON.stringify(user));
        } catch {}
        bootWithWelcome();
      } else {
        // Paid plan → boot dashboard langsung, lalu payment modal
        bootDashboard();
        setTimeout(() => {
          const finalize = () => {
            try {
              const expiry = computePremiumExpiry(pendingKey);
              const acc = JSON.parse(localStorage.getItem(`playly-account-${email}`) || "{}");
              acc.tier = "premium"; acc.premiumPlan = pendingKey;
              acc.premiumStartedAt = Date.now(); acc.premiumExpiresAt = expiry;
              localStorage.setItem(`playly-account-${email}`, JSON.stringify(acc));
              user.tier = "premium"; user.premiumPlan = pendingKey;
              user.premiumStartedAt = acc.premiumStartedAt; user.premiumExpiresAt = expiry;
              localStorage.setItem("playly-user", JSON.stringify(user));
            } catch (err) { console.warn("[guest signup plan]", err); }
            applyRoleToUI?.();
          };
          openPaymentModal({ planKey: pendingKey, onSuccess: finalize });
        }, 600);
      }
    } else {
      window.__playlyPostSignup = true;
      setAuthState("signup-pick");
    }
  } catch (err) {
    console.error("[signup] error:", err);
    btn?.classList.remove("loading");
    toast(`⚠️ Gagal mendaftar: ${err?.message || "kesalahan tidak terduga"}`, "error");
  }
});

// Social login (Google/GitHub) sudah dihapus — Playly hanya pakai email/password.

// ----------------------- FORGOT PASSWORD FLOW -----------------------
// Modal reset password: minta email/username + password baru. Kalau akun
// ada di localStorage, password di-hash & disimpan, lockout di-clear.
function openForgotPwModal(prefillId = "") {
  const modal = $("#forgotPwModal");
  const form = $("#forgotPwForm");
  if (!modal || !form) return;
  form.reset();
  clearFieldErrors(form);
  if (prefillId) {
    const emailInput = form.querySelector('input[name="email"]');
    emailInput.value = prefillId;
    // v563: fire input event supaya listener auto show/hide Recovery Key field
    // ke-trigger. Programmatic .value = ... tidak fire input event by default.
    emailInput.dispatchEvent(new Event("input", { bubbles: true }));
  }
  modal.classList.add("show");
  setTimeout(() => {
    const target = prefillId ? form.querySelector('input[name="password"]') : form.querySelector('input[name="email"]');
    target?.focus();
  }, 100);
}
function closeForgotPwModal(opts = {}) {
  $("#forgotPwModal")?.classList.remove("show");
  // v567: kalau di-open dari choice picker dan close BUKAN karena success,
  // balik ke choice picker supaya user bisa pilih opsi OTP.
  if (window._forgotPwFromChoice && !opts.success) {
    const prefill = window._forgotPwReturnPrefill || "";
    window._forgotPwFromChoice = false;
    window._forgotPwReturnPrefill = "";
    setTimeout(() => {
      if (typeof openUniversalRecoveryChoiceModal === "function") {
        openUniversalRecoveryChoiceModal(prefill);
      }
    }, 100);
  } else if (opts.success) {
    // Success: clear flags supaya next open dari direct call ngga re-trigger
    window._forgotPwFromChoice = false;
    window._forgotPwReturnPrefill = "";
  }
}

$("#forgotPw")?.addEventListener("click", e => {
  e.preventDefault();
  // v566: ganti dari direct openForgotPwModal ke universal choice picker.
  // User pilih dulu: pakai PIN 2FA / password sendiri ATAU minta OTP dari
  // super admin. Lalu route ke modal yang sesuai.
  const loginInput = $("#signinForm")?.querySelector('input[name="email"]');
  const prefill = (loginInput?.value || "").trim().toLowerCase();
  if (typeof openUniversalRecoveryChoiceModal === "function") {
    openUniversalRecoveryChoiceModal(prefill);
  } else {
    // Safety net kalau choice modal tidak ke-load
    openForgotPwModal(prefill);
  }
});

// Tombol close (x, backdrop, batal) di forgot-pw modal
$("#forgotPwModal")?.addEventListener("click", e => {
  if (e.target.matches("[data-close]")) closeForgotPwModal();
});

// CR-1 fix (2026-05-21): SECURITY CRITICAL — sebelumnya handler ini overwrite
// password TANPA verifikasi identitas SAMA SEKALI. Siapapun yg tau email/
// username target bisa take-over akun (termasuk super-admin). Sekarang:
//   1. Block OFFICIAL_ADMIN_EMAIL entirely (super-admin recovery via manual process)
//   2. Force cloud sync sebelum cek → pull versi terbaru account (CR-3 prevention)
//   3. Kalau account punya PIN (2FA), wajib PIN verification dulu
//   4. Rate limit: max 3 reset attempts per email per hour
//   5. Audit log entry untuk admin visibility
const _forgotPwAttempts = new Map(); // email → [timestamp, ...]
const FORGOT_PW_MAX_PER_HOUR = 3;
function checkForgotPwRateLimit(email) {
  const now = Date.now();
  const hourAgo = now - 3600000;
  const arr = (_forgotPwAttempts.get(email) || []).filter(t => t > hourAgo);
  arr.push(now);
  _forgotPwAttempts.set(email, arr);
  return arr.length <= FORGOT_PW_MAX_PER_HOUR;
}

$("#forgotPwForm")?.addEventListener("submit", async e => {
  e.preventDefault();
  const form = e.target;
  clearFieldErrors(form);
  const fd = new FormData(form);
  const id = (fd.get("email") || "").trim().toLowerCase();
  const pw1 = fd.get("password");
  const pw2 = fd.get("password2");

  let hasError = false;
  if (!id) { showFieldError(form, "email", "Email atau username wajib diisi"); hasError = true; }
  if (!pw1) { showFieldError(form, "password", "Password baru wajib diisi"); hasError = true; }
  else if (pw1.length < 6) { showFieldError(form, "password", "Password minimal 6 karakter"); hasError = true; }
  if (!pw2) { showFieldError(form, "password2", "Konfirmasi password wajib diisi"); hasError = true; }
  else if (pw1 && pw1 !== pw2) { showFieldError(form, "password2", "Konfirmasi password tidak cocok"); hasError = true; }
  if (hasError) return;

  // CR-1: block reset untuk super-admin email
  if (isOfficialAdminEmail(id)) {
    showFieldError(form, "email", "Akun super-admin tidak bisa reset via form ini. Hubungi support.");
    return toast("🔒 Reset password super-admin tidak diizinkan via form. Hubungi support.", "error");
  }

  // CR-1: rate limit
  if (!checkForgotPwRateLimit(id)) {
    return toast(`⚠️ Terlalu banyak percobaan reset. Coba lagi dalam 1 jam.`, "warning");
  }

  // CR-1 + CR-3: force pull versi terbaru account dari cloud sebelum cek.
  // Tanpa ini, attacker bisa exploit timing window di mana victim's account
  // belum sync ke device attacker → reset terpasang lokal → cloud-sync push
  // ke kolam → victim ke-takeover di device lain.
  if (id.includes("@")) {
    try {
      if (window.cloudSync?.syncSingleKey) {
        await Promise.resolve(window.cloudSync.syncSingleKey(`playly-account-${id}`));
      }
    } catch {}
  }

  // Resolve identifier → existing account
  let existing = null;
  let email = id;
  if (id.includes("@")) {
    existing = JSON.parse(localStorage.getItem(`playly-account-${id}`) || "null");
  } else {
    const byUser = findAccountByUsername(id);
    if (byUser) { email = byUser.email.toLowerCase(); existing = byUser; }
  }
  if (!existing) {
    showFieldError(form, "email", "Akun tidak ditemukan");
    return;
  }

  // CR-1: kalau account email == email super-admin (resolve via username), tetap blok
  if (isOfficialAdminEmail(email)) {
    showFieldError(form, "email", "Akun super-admin tidak bisa reset via form ini.");
    return toast("🔒 Reset password super-admin tidak diizinkan.", "error");
  }

  // v565/v567: PIN 2FA gate UNIFIED untuk user + admin. Field selalu visible.
  // v567: tambah 3-attempt limit. Kalau salah 3x, lockout 15 menit. Warning
  // di setiap percobaan ("sisa 2 percobaan", "sisa 1 percobaan", "terkunci").
  const _pinInputRaw = String(fd.get("adminPin") || "").trim();
  if (existing.pin) {
    if (!_pinInputRaw) {
      showFieldError(form, "adminPin", "PIN 2FA wajib karena akun ini sudah aktifkan 2FA");
      return toast("🔐 Isi PIN 2FA untuk reset password", "warning");
    }
    if (!/^\d{6}$/.test(_pinInputRaw)) {
      showFieldError(form, "adminPin", "PIN harus 6 digit angka");
      return toast("⚠️ Format PIN tidak valid", "warning");
    }
    if (typeof verifyPin !== "function") {
      return toast("⚠️ PIN verifier tidak tersedia. Hubungi support.", "error");
    }

    // === 3-attempt limit + 15-min lockout ===
    const pinAttemptKey = `playly-forgot-pin-attempts-${email}`;
    const PIN_MAX_ATTEMPTS = 3;
    const PIN_LOCKOUT_MS = 15 * 60 * 1000;
    let attemptsState = { count: 0, lockedUntil: 0 };
    try {
      const raw = localStorage.getItem(pinAttemptKey);
      if (raw) attemptsState = JSON.parse(raw);
    } catch {}
    // Cek lockout aktif
    if (attemptsState.lockedUntil && Date.now() < attemptsState.lockedUntil) {
      const minLeft = Math.ceil((attemptsState.lockedUntil - Date.now()) / 60000);
      showFieldError(form, "adminPin", `Terlalu banyak percobaan salah. Coba lagi dalam ${minLeft} menit.`);
      return toast(`🔒 PIN locked ${minLeft} menit lagi karena 3x salah berturut-turut`, "error");
    }
    // Reset count kalau lockout sudah lewat
    if (attemptsState.lockedUntil && Date.now() >= attemptsState.lockedUntil) {
      attemptsState = { count: 0, lockedUntil: 0 };
    }

    const pinOk = await verifyPin(_pinInputRaw, existing.pin);
    if (!pinOk) {
      attemptsState.count = (attemptsState.count || 0) + 1;
      if (attemptsState.count >= PIN_MAX_ATTEMPTS) {
        attemptsState.lockedUntil = Date.now() + PIN_LOCKOUT_MS;
        attemptsState.count = 0;
        try { localStorage.setItem(pinAttemptKey, JSON.stringify(attemptsState)); } catch {}
        showFieldError(form, "adminPin", `Salah 3 kali. PIN 2FA terkunci 15 menit untuk akun ini.`);
        return toast(`🔒 PIN salah 3x — terkunci 15 menit. Tunggu atau pakai opsi OTP via Super Admin.`, "error");
      }
      const remaining = PIN_MAX_ATTEMPTS - attemptsState.count;
      try { localStorage.setItem(pinAttemptKey, JSON.stringify(attemptsState)); } catch {}
      showFieldError(form, "adminPin", `PIN 2FA salah. Sisa ${remaining} percobaan.`);
      return toast(`❌ PIN salah — sisa ${remaining} percobaan sebelum dikunci 15 menit`, "error");
    }
    // PIN ok — clear attempt counter
    try { localStorage.removeItem(pinAttemptKey); } catch {}
  }

  // Hash password baru & simpan
  try {
    existing.password = await hashPassword(pw1);
    existing.passwordResetAt = Date.now();
    localStorage.setItem(`playly-account-${email}`, JSON.stringify(existing));
    // Reset rate limit & banner — supaya user langsung bisa login pakai password baru
    clearLoginAttempts(id);
    clearLoginAttempts(email);
    hideLockBanner();
    closeForgotPwModal({ success: true });
    // v572: Audit log — catat password change. Pakai emailOverride karena
    // user mungkin belum login (forgot pw flow). Storage di acc.email.
    try {
      if (typeof addUserAuditEvent === "function") {
        addUserAuditEvent("password", "Password di-reset",
          `Password baru disetel via Lupa Kata Sandi flow`,
          { emailOverride: email });
      }
    } catch {}
    // CR-1: audit log — admin bisa lihat reset history
    try {
      if (typeof pushAdminEvent === "function") {
        pushAdminEvent("🔑", `Password reset via self-service untuk <b>${escapeHtml(existing.username || email)}</b>`);
      }
    } catch {}
    toast("🔑 Password berhasil di-reset. Silakan login dengan password baru.", "success");
    const loginInput = $("#signinForm")?.querySelector('input[name="email"]');
    if (loginInput) loginInput.value = id;
  } catch (err) {
    console.error("[forgot-pw] error:", err);
    toast("⚠️ Gagal reset password. Coba lagi.", "error");
  }
});

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

// ============================================================
// =================== DASHBOARD INIT =========================
// ============================================================

// Defer non-critical render → tunggu browser idle frame supaya above-fold
// painting selesai dulu. Pakai requestIdleCallback (fallback setTimeout).
// Tujuan: kurangi cognitive load awal + improve perceived performance pada
// Beranda yang punya banyak section. Below-fold seperti Pencapaian, Papan
// Peringkat, Level Kreator detail tidak butuh tampil instan.
function _deferRender(fn) {
  if (typeof fn !== "function") return;
  const run = () => { try { fn(); } catch (e) { console.warn("[deferRender]", e); } };
  if (typeof requestIdleCallback === "function") {
    requestIdleCallback(run, { timeout: 1500 });
  } else {
    setTimeout(run, 0);
  }
}

// ====================================================================
// ============ ADMIN RECOVERY (BACKUP ADMIN OTP FLOW) ================
// ====================================================================
// Per request user 2026-05-26: backup admin yang lupa password tidak bisa
// pakai email reset biasa (karena Playly belum punya email infra). Alur:
//   1. Backup admin: klik "Lupa kata sandi" → pilih "OTP via Super Admin"
//      → submit email/username → request masuk ke super admin
//   2. Super admin: lihat pending request → klik "Generate OTP" → sistem
//      buat 4 digit acak, HANYA super admin yang lihat plaintext-nya
//      (hash disimpan, plaintext dilempar lewat external channel)
//   3. Super admin: re-ketik OTP yang dia kirim (double-check anti-typo)
//   4. Super admin: kirim 4 digit ke backup admin via WA/SMS/telepon
//   5. Backup admin: input 4 digit di recovery screen → status "received"
//   6. Super admin: lihat yang di-input backup admin → final approve/deny
//   7. Approved: backup admin granted access (force password reset)
//
// SECURITY:
// - OTP hashed sebelum store (jangan plain text di localStorage)
// - TTL 30 menit per request (auto-expire)
// - Super admin email TIDAK boleh request via flow ini (rejected)
// - Backup admin yang minta WAJIB email-nya ada di admin allowlist

const ADMIN_RECOVERY_KEY = "playly-admin-recovery-requests";
const ADMIN_RECOVERY_TTL_MS = 30 * 60 * 1000; // 30 menit

// Status constants — state machine satu arah (kecuali deny dari mana saja)
const AR_STATUS = {
  PENDING:        "pending",        // request masuk, super admin belum action
  OTP_GENERATED:  "otp_generated",  // OTP dibuat, tunggu super admin re-verify
  OTP_VERIFIED:   "otp_verified",   // super admin re-typed correctly
  WAITING_INPUT:  "waiting_input",  // tunggu backup admin input OTP
  INPUT_RECEIVED: "input_received", // backup admin sudah input, tunggu final
  APPROVED:       "approved",       // super admin approve, backup boleh login
  DENIED:         "denied",         // super admin tolak
  EXPIRED:        "expired"         // TTL habis tanpa final decision
};

// Hash 4-digit OTP — pakai SHA-256 dengan dedicated salt. Jangan re-use
// password salt supaya OTP hash space terpisah secara cryptographic.
const PLAYLY_OTP_SALT_V1 = "playly-admin-otp-salt-v1";
async function hashAdminOtp(otpPlain) {
  const data = new TextEncoder().encode(PLAYLY_OTP_SALT_V1 + String(otpPlain ?? ""));
  const buf = await crypto.subtle.digest("SHA-256", data);
  return "otp:" + Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2, "0")).join("");
}

function _readAdminRecoveryRequests() {
  try {
    const raw = localStorage.getItem(ADMIN_RECOVERY_KEY);
    if (!raw) return [];
    const arr = JSON.parse(raw);
    return Array.isArray(arr) ? arr : [];
  } catch { return []; }
}

function _writeAdminRecoveryRequests(arr) {
  try {
    localStorage.setItem(ADMIN_RECOVERY_KEY, JSON.stringify(arr));
  } catch (e) { console.warn("[admin-recovery] write failed", e); }
}

// Expire old pending requests yang lewat TTL. Dipanggil tiap kali read.
function _expireOldRecoveryRequests(arr) {
  const now = Date.now();
  let mutated = false;
  for (const req of arr) {
    if (req.status === AR_STATUS.APPROVED || req.status === AR_STATUS.DENIED || req.status === AR_STATUS.EXPIRED) continue;
    if (req.expires_at && now > req.expires_at) {
      req.status = AR_STATUS.EXPIRED;
      mutated = true;
    }
  }
  return mutated;
}

function getAdminRecoveryRequests() {
  const arr = _readAdminRecoveryRequests();
  if (_expireOldRecoveryRequests(arr)) _writeAdminRecoveryRequests(arr);
  return arr;
}

// Get the ACTIVE (non-final) request for a given email, kalau ada.
// Dipakai backup admin untuk polling status request yang dia submit.
function getMyAdminRecoveryRequest(email) {
  const e = (email || "").trim().toLowerCase();
  if (!e) return null;
  const arr = getAdminRecoveryRequests();
  // Sort by created_at descending, ambil yang terbaru
  const mine = arr.filter(r => r.requester_email === e);
  mine.sort((a, b) => (b.created_at || 0) - (a.created_at || 0));
  return mine[0] || null;
}

// Create a new request. Validates:
// - Akun harus ada (user atau backup admin OK)
// - BUKAN super admin email (super admin pakai recovery code nanti)
// - Ngga ada request aktif yang baru (cegah spam)
// v566: di-extend untuk accept user accounts juga, bukan cuma backup admin.
function createAdminRecoveryRequest(emailOrUsername) {
  const id = (emailOrUsername || "").trim().toLowerCase();
  if (!id) return { ok: false, error: "Email atau username wajib diisi" };

  // Resolve to email + cek akun ada
  let email = id;
  let acct = null;
  if (!id.includes("@")) {
    acct = typeof findAccountByUsername === "function" ? findAccountByUsername(id) : null;
    if (!acct) return { ok: false, error: "Username tidak ditemukan" };
    email = (acct.email || "").toLowerCase();
  } else {
    try { acct = JSON.parse(localStorage.getItem(`playly-account-${email}`) || "null"); } catch {}
    if (!acct) return { ok: false, error: "Email belum terdaftar" };
  }

  // Block super admin (recovery code flow nanti — bukan via OTP)
  if (typeof isOfficialAdminEmail === "function" && isOfficialAdminEmail(email)) {
    return { ok: false, error: "Akun super admin tidak bisa recovery via OTP. Pakai recovery code." };
  }

  const arr = getAdminRecoveryRequests();

  // Cek apakah ada request aktif (non-final, non-expired) untuk email ini
  const existing = arr.find(r =>
    r.requester_email === email &&
    [AR_STATUS.PENDING, AR_STATUS.OTP_GENERATED, AR_STATUS.OTP_VERIFIED, AR_STATUS.WAITING_INPUT, AR_STATUS.INPUT_RECEIVED].includes(r.status)
  );
  if (existing) {
    return { ok: true, request: existing, alreadyExisted: true };
  }

  const now = Date.now();
  const req = {
    id: "rcv_" + now.toString(36) + "_" + Math.random().toString(36).slice(2, 8),
    requester_email: email,
    requester_username: id.includes("@") ? "" : id,
    otp_hash: null,
    otp_entered: null,
    otp_super_verified: false,
    status: AR_STATUS.PENDING,
    created_at: now,
    expires_at: now + ADMIN_RECOVERY_TTL_MS,
    final_decision_at: null
  };
  arr.push(req);
  _writeAdminRecoveryRequests(arr);
  return { ok: true, request: req, alreadyExisted: false };
}

// Super admin generate OTP. Returns plain OTP (4 digit) sekali — caller
// HARUS tampilkan ke super admin lalu jangan store/kirim ke siapa-siapa.
// State: PENDING → OTP_GENERATED
async function generateRecoveryOtp(requestId) {
  const arr = getAdminRecoveryRequests();
  const req = arr.find(r => r.id === requestId);
  if (!req) return { ok: false, error: "Request tidak ditemukan" };
  if (req.status !== AR_STATUS.PENDING) {
    return { ok: false, error: "OTP sudah pernah di-generate untuk request ini" };
  }
  const otpPlain = String(Math.floor(1000 + Math.random() * 9000)); // 4 digit, 1000-9999
  req.otp_hash = await hashAdminOtp(otpPlain);
  req.status = AR_STATUS.OTP_GENERATED;
  _writeAdminRecoveryRequests(arr);
  return { ok: true, otpPlain, request: req };
}

// v568: combined generate + send dalam 1 step. Super admin click 1 button,
// sistem auto-generate OTP + transition status ke WAITING_INPUT (= sent via
// email). Return plain OTP untuk display ke super admin (simulasi konten
// email yang dikirim ke user).
async function generateAndSendRecoveryOtp(requestId) {
  const gen = await generateRecoveryOtp(requestId);
  if (!gen.ok) {
    // Kalau status sudah OTP_GENERATED (legacy v562 flow), generate ulang
    // by manually transitioning + creating new OTP
    const arr = getAdminRecoveryRequests();
    const req = arr.find(r => r.id === requestId);
    if (req && (req.status === AR_STATUS.OTP_GENERATED || req.status === AR_STATUS.INPUT_RECEIVED)) {
      // Force re-generate
      req.status = AR_STATUS.PENDING;
      _writeAdminRecoveryRequests(arr);
      const retry = await generateRecoveryOtp(requestId);
      if (!retry.ok) return retry;
      // Mark sent
      retry.request.status = AR_STATUS.WAITING_INPUT;
      _writeAdminRecoveryRequests(getAdminRecoveryRequests().map(r => r.id === requestId ? retry.request : r));
      return { ok: true, otpPlain: retry.otpPlain, request: retry.request };
    }
    return gen;
  }
  // Transition status ke WAITING_INPUT (= email terkirim ke user)
  const arr = getAdminRecoveryRequests();
  const req = arr.find(r => r.id === requestId);
  if (req && req.status === AR_STATUS.OTP_GENERATED) {
    req.status = AR_STATUS.WAITING_INPUT;
    _writeAdminRecoveryRequests(arr);
  }
  return { ok: true, otpPlain: gen.otpPlain, request: req };
}

// Super admin re-types OTP untuk konfirmasi bahwa dia ngga typo saat baca.
// State: OTP_GENERATED → OTP_VERIFIED (kalau cocok) atau stay (kalau salah)
// v568: deprecated — alur sekarang combine generate+send + auto-verify.
// Fungsi ini tetap diexpose untuk backwards compat tapi tidak dipanggil
// dari UI baru.
async function verifyGeneratedOtp(requestId, otpReentered) {
  const arr = getAdminRecoveryRequests();
  const req = arr.find(r => r.id === requestId);
  if (!req) return { ok: false, error: "Request tidak ditemukan" };
  if (req.status !== AR_STATUS.OTP_GENERATED) {
    return { ok: false, error: "Request bukan dalam state otp_generated" };
  }
  const hashReentered = await hashAdminOtp(otpReentered);
  if (hashReentered !== req.otp_hash) {
    return { ok: false, error: "OTP yang kamu re-type tidak cocok dengan yang di-generate. Coba lagi." };
  }
  req.status = AR_STATUS.WAITING_INPUT;
  _writeAdminRecoveryRequests(arr);
  return { ok: true, request: req };
}

// v568: submitBackupOtp sekarang AUTO-VERIFY langsung (tidak ada step
// INPUT_RECEIVED + manual super admin approve). Kalau OTP match: status
// langsung APPROVED. Kalau salah: counter increment, kalau exceed 3 →
// status DENIED.
async function submitBackupOtp(requestId, otp) {
  const arr = getAdminRecoveryRequests();
  const req = arr.find(r => r.id === requestId);
  if (!req) return { ok: false, error: "Request tidak ditemukan" };
  if (req.status !== AR_STATUS.WAITING_INPUT) {
    if (req.status === AR_STATUS.APPROVED) {
      return { ok: true, request: req, alreadyApproved: true };
    }
    if (req.status === AR_STATUS.DENIED) {
      return { ok: false, error: "Request sudah ditolak. Submit permintaan baru." };
    }
    if (req.status === AR_STATUS.EXPIRED) {
      return { ok: false, error: "Request kadaluarsa. Submit permintaan baru." };
    }
    return { ok: false, error: "Request belum siap menerima OTP. Super admin/admin harus kirim OTP dulu." };
  }
  const clean = String(otp || "").trim();
  if (!/^\d{4}$/.test(clean)) {
    return { ok: false, error: "OTP harus 4 digit angka" };
  }
  // Auto-verify via hash
  const enteredHash = await hashAdminOtp(clean);
  if (enteredHash === req.otp_hash) {
    req.otp_entered = clean;
    req.status = AR_STATUS.APPROVED;
    req.final_decision_at = Date.now();
    _writeAdminRecoveryRequests(arr);
    return { ok: true, request: req, approved: true };
  }
  // Wrong OTP — increment counter
  req.wrong_attempts = (req.wrong_attempts || 0) + 1;
  if (req.wrong_attempts >= 3) {
    req.status = AR_STATUS.DENIED;
    req.final_decision_at = Date.now();
    _writeAdminRecoveryRequests(arr);
    return { ok: false, error: "OTP salah 3x. Request otomatis ditolak. Submit permintaan baru.", lockedOut: true };
  }
  _writeAdminRecoveryRequests(arr);
  const remaining = 3 - req.wrong_attempts;
  return { ok: false, error: `OTP salah — sisa ${remaining} percobaan`, attemptLeft: remaining };
}

// Super admin final approve atau deny berdasarkan OTP yang di-input backup
// admin. Approve = system also validate that otp_entered matches otp_hash
// (defense in depth — super admin bisa keliru lihat).
// State: INPUT_RECEIVED → APPROVED atau DENIED
async function finalDecideRecovery(requestId, approve) {
  const arr = getAdminRecoveryRequests();
  const req = arr.find(r => r.id === requestId);
  if (!req) return { ok: false, error: "Request tidak ditemukan" };
  if (req.status !== AR_STATUS.INPUT_RECEIVED) {
    return { ok: false, error: "Request belum di-input OTP oleh backup admin" };
  }

  if (approve) {
    // Defense in depth: sistem juga cross-check hash
    const enteredHash = await hashAdminOtp(req.otp_entered);
    if (enteredHash !== req.otp_hash) {
      // Super admin keliru approve OTP yang sebenarnya salah → tetap deny
      req.status = AR_STATUS.DENIED;
      req.final_decision_at = Date.now();
      _writeAdminRecoveryRequests(arr);
      return { ok: false, error: "OTP yang di-input backup admin TIDAK COCOK dengan yang di-generate. Request otomatis di-deny demi keamanan." };
    }
    req.status = AR_STATUS.APPROVED;
  } else {
    req.status = AR_STATUS.DENIED;
  }
  req.final_decision_at = Date.now();
  _writeAdminRecoveryRequests(arr);
  return { ok: true, request: req };
}

// Helper: count pending requests (untuk badge di sidebar super admin)
function countPendingAdminRecovery() {
  return getAdminRecoveryRequests().filter(r =>
    [AR_STATUS.PENDING, AR_STATUS.OTP_GENERATED, AR_STATUS.WAITING_INPUT, AR_STATUS.INPUT_RECEIVED].includes(r.status)
  ).length;
}

// Expose for testing + UI hooks
window._adminRecovery = {
  getRequests: getAdminRecoveryRequests,
  getMine: getMyAdminRecoveryRequest,
  create: createAdminRecoveryRequest,
  generate: generateRecoveryOtp,
  verify: verifyGeneratedOtp,
  submit: submitBackupOtp,
  decide: finalDecideRecovery,
  countPending: countPendingAdminRecovery,
  STATUS: AR_STATUS
};

// ============ ADMIN RECOVERY — UI LAYER =============================
// Semua modal di-inject dinamis (avoid edit index.html). Pakai existing
// .modal / .modal-panel / data-close pattern + global click handler
// untuk close. Setiap function open* membuat element, append ke body,
// return element supaya bisa di-remove saat close.

function _arRemoveOpenModals() {
  document.querySelectorAll(".ar-modal").forEach(el => el.remove());
}

function _arEscapeHtml(s) {
  return String(s ?? "").replace(/[&<>"']/g, c => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[c]));
}

// Status label helper untuk display.
function _arStatusLabel(status) {
  switch (status) {
    case AR_STATUS.PENDING:        return "🆕 Menunggu super admin";
    case AR_STATUS.OTP_GENERATED:  return "🔑 OTP dibuat, super admin re-verify";
    case AR_STATUS.OTP_VERIFIED:   return "✅ OTP terverifikasi";
    case AR_STATUS.WAITING_INPUT:  return "📨 Menunggu kamu input OTP";
    case AR_STATUS.INPUT_RECEIVED: return "⏳ Menunggu konfirmasi super admin";
    case AR_STATUS.APPROVED:       return "✅ Disetujui — akses diberikan";
    case AR_STATUS.DENIED:         return "❌ Ditolak super admin";
    case AR_STATUS.EXPIRED:        return "⏰ Kadaluarsa (30 menit)";
    default: return status;
  }
}

// ───────────────────── BACKUP ADMIN SIDE ─────────────────────

// Modal pilih jalur recovery: Email atau OTP via Super Admin.
// Buka dari handler #forgotPw setelah cek backup admin status.
function openAdminRecoveryChoiceModal(prefillId = "") {
  _arRemoveOpenModals();
  const m = document.createElement("div");
  m.className = "modal show ar-modal";
  m.id = "adminRecoveryChoiceModal";
  m.style.zIndex = "10020";
  m.innerHTML = `
    <div class="modal-backdrop" data-close></div>
    <div class="modal-panel ar-panel-narrow">
      <button class="modal-close" data-close aria-label="Tutup">×</button>
      <h3>Pilih cara recovery akun admin</h3>
      <p class="muted">Akun admin cadangan punya 2 cara recovery. Pilih salah satu.</p>
      <div class="ar-choice-grid">
        <button type="button" class="ar-choice-card" data-ar-choice="email">
          <div class="ar-choice-ico">✉️</div>
          <strong>Reset via Email</strong>
          <small>Pakai email akun untuk set password baru. Cepat kalau kamu masih akses email.</small>
        </button>
        <button type="button" class="ar-choice-card" data-ar-choice="otp">
          <div class="ar-choice-ico">🔐</div>
          <strong>Minta OTP ke Super Admin</strong>
          <small>Super admin akan kirim 4 digit OTP via WA/SMS untuk verify identitasmu.</small>
        </button>
      </div>
    </div>
  `;
  document.body.appendChild(m);

  m.querySelector('[data-ar-choice="email"]')?.addEventListener("click", () => {
    m.remove();
    if (typeof openForgotPwModal === "function") openForgotPwModal(prefillId);
  });
  m.querySelector('[data-ar-choice="otp"]')?.addEventListener("click", () => {
    m.remove();
    openAdminRecoveryOtpRequestModal(prefillId);
  });
  return m;
}

// Modal: user/admin submit request OTP. v567: copy "Super Admin atau Admin",
// hapus X button, Batal click → balik ke choice picker (kalau opened from
// choice). Opts: { fromChoice: bool }
function openAdminRecoveryOtpRequestModal(prefillId = "", opts = {}) {
  _arRemoveOpenModals();
  // v568: context-aware copy + via email (bukan WA/SMS)
  const _isAdminCtx = document.body.dataset.role === "admin";
  const _approverLabel = _isAdminCtx ? "Super Admin" : "Super Admin atau Admin";
  const _approverDesc = _isAdminCtx ? "Super admin" : "Super admin atau admin";
  const m = document.createElement("div");
  m.className = "modal show ar-modal";
  m.style.zIndex = "10020";
  const fromChoice = !!opts.fromChoice;
  m.innerHTML = `
    <div class="modal-backdrop" data-ar-back></div>
    <div class="modal-panel ar-panel-narrow" data-no-i18n>
      <h3 class="ar-text-center" data-no-i18n>🔐 Minta OTP ke ${_arEscapeHtml(_approverLabel)}</h3>
      <p class="muted ar-text-center" data-no-i18n>Masukkan email/username akunmu. ${_arEscapeHtml(_approverDesc)} akan generate OTP dan kirim 4-digit OTP ke email kamu.</p>
      <form class="ar-form" id="arOtpRequestForm">
        <label class="ar-label" data-no-i18n>Email atau Username</label>
        <input type="text" name="id" placeholder="kamu@email.com atau username" value="${_arEscapeHtml(prefillId)}" autocomplete="off" required />
        <div class="ar-form-err" hidden></div>
        <div class="ar-form-actions ar-form-actions-compact">
          <button type="button" class="btn ghost btn-compact" data-ar-back>Batal</button>
          <button type="submit" class="btn primary btn-compact">Kirim Permintaan</button>
        </div>
      </form>
    </div>
  `;
  document.body.appendChild(m);

  // Back to choice picker (Batal / backdrop)
  m.addEventListener("click", e => {
    if (e.target.matches("[data-ar-back]")) {
      m.remove();
      if (fromChoice && typeof openUniversalRecoveryChoiceModal === "function") {
        setTimeout(() => openUniversalRecoveryChoiceModal(prefillId), 50);
      }
    }
  });

  m.querySelector("#arOtpRequestForm")?.addEventListener("submit", e => {
    e.preventDefault();
    const fd = new FormData(e.target);
    const id = String(fd.get("id") || "").trim().toLowerCase();
    const errEl = m.querySelector(".ar-form-err");
    const showErr = (msg) => { errEl.textContent = msg; errEl.hidden = false; };
    const r = createAdminRecoveryRequest(id);
    if (!r.ok) return showErr(r.error || "Gagal membuat permintaan");
    m.remove();
    openAdminRecoveryWaitModal(r.request.id);
  });
  return m;
}

// Modal: backup admin menunggu super admin generate OTP + input OTP saat sudah ada.
// Polling status tiap 3 detik.
function openAdminRecoveryWaitModal(requestId) {
  _arRemoveOpenModals();
  const m = document.createElement("div");
  m.className = "modal show ar-modal";
  m.id = "adminRecoveryWaitModal";
  m.dataset.requestId = requestId;
  m.style.zIndex = "10020";
  m.innerHTML = `<div class="modal-backdrop"></div><div class="modal-panel ar-panel-narrow"><div class="ar-body"></div></div>`;
  document.body.appendChild(m);

  const body = m.querySelector(".ar-body");
  let pollTimer = null;
  let submitting = false;

  function render() {
    const req = getAdminRecoveryRequests().find(r => r.id === requestId);
    if (!req) {
      body.innerHTML = `<h3>Permintaan hilang</h3><p class="muted">Permintaan tidak ditemukan. Mungkin sudah di-cancel super admin.</p>
        <div class="ar-form-actions"><button type="button" class="btn primary" data-close-ok>Tutup</button></div>`;
      stopPoll();
      return;
    }

    const remainingMin = Math.max(0, Math.ceil((req.expires_at - Date.now()) / 60000));

    // v568: context-aware copy
    const _isAdminCtx = document.body.dataset.role === "admin";
    const _approverLabel = _isAdminCtx ? "Super Admin" : "Super Admin atau Admin";

    if (req.status === AR_STATUS.PENDING || req.status === AR_STATUS.OTP_GENERATED) {
      body.innerHTML = `
        <h3 class="ar-text-center" data-no-i18n>🆕 Permintaan terkirim</h3>
        <p class="muted ar-text-center" data-no-i18n>Tunggu ${_arEscapeHtml(_approverLabel)} kirim OTP. Kamu bakal terima 4-digit OTP via email.</p>
        <div class="ar-status-pill ar-pill-pending">${_arEscapeHtml(_arStatusLabel(req.status))}</div>
        <div class="ar-ttl">Berlaku ${remainingMin} menit lagi</div>
        <div class="ar-form-actions-compact"><button type="button" class="btn ghost btn-compact" data-close>Tutup (request tetap aktif)</button></div>
      `;
    } else if (req.status === AR_STATUS.WAITING_INPUT) {
      body.innerHTML = `
        <h3 class="ar-text-center" data-no-i18n>📨 Masukkan OTP dari email</h3>
        <p class="muted ar-text-center" data-no-i18n>Cek email kamu, ketik 4-digit OTP yang ${_arEscapeHtml(_approverLabel)} kirim.</p>
        <div class="ar-otp-grid" data-ar-otp-grid>
          <input type="text" inputmode="numeric" maxlength="1" data-ar-otp-cell="0" />
          <input type="text" inputmode="numeric" maxlength="1" data-ar-otp-cell="1" />
          <input type="text" inputmode="numeric" maxlength="1" data-ar-otp-cell="2" />
          <input type="text" inputmode="numeric" maxlength="1" data-ar-otp-cell="3" />
        </div>
        <div class="ar-form-err" hidden></div>
        <div class="ar-ttl">Berlaku ${remainingMin} menit lagi</div>
        <div class="ar-form-actions-compact">
          <button type="button" class="btn ghost btn-compact" data-close>Tutup</button>
          <button type="button" class="btn primary btn-compact" data-ar-submit-otp>Verify</button>
        </div>
      `;
      wireOtpInputs(body);
    } else if (req.status === AR_STATUS.INPUT_RECEIVED) {
      // v568: legacy state (alur lama). Tampilkan password reset langsung
      // karena di alur baru INPUT_RECEIVED tidak terpakai.
      renderInlinePasswordReset(body, req);
      stopPoll();
    } else if (req.status === AR_STATUS.APPROVED) {
      // v568: tampilkan password reset INLINE di modal yang sama
      renderInlinePasswordReset(body, req);
      stopPoll();
    } else if (req.status === AR_STATUS.DENIED) {
      body.innerHTML = `
        <h3>❌ Permintaan ditolak</h3>
        <p class="muted">Super admin menolak permintaan recovery. Hubungi super admin langsung kalau ini kesalahan.</p>
        <div class="ar-form-actions"><button type="button" class="btn ghost" data-close>Tutup</button></div>
      `;
      stopPoll();
    } else if (req.status === AR_STATUS.EXPIRED) {
      body.innerHTML = `
        <h3>⏰ Permintaan kadaluarsa</h3>
        <p class="muted">Permintaan ini sudah lebih dari 30 menit. Silakan submit permintaan baru.</p>
        <div class="ar-form-actions"><button type="button" class="btn primary" data-ar-retry>Submit Permintaan Baru</button></div>
      `;
      stopPoll();
      body.querySelector("[data-ar-retry]")?.addEventListener("click", () => {
        m.remove();
        openAdminRecoveryOtpRequestModal(req.requester_email);
      });
    }
  }

  function wireOtpInputs(scope) {
    const cells = Array.from(scope.querySelectorAll("[data-ar-otp-cell]"));
    cells.forEach((cell, i) => {
      cell.addEventListener("input", e => {
        const v = (e.target.value || "").replace(/\D/g, "").slice(-1);
        e.target.value = v;
        if (v && i < cells.length - 1) cells[i + 1].focus();
      });
      cell.addEventListener("keydown", e => {
        if (e.key === "Backspace" && !cell.value && i > 0) cells[i - 1].focus();
      });
    });
    cells[0]?.focus();
    scope.querySelector("[data-ar-submit-otp]")?.addEventListener("click", async () => {
      if (submitting) return;
      const otp = cells.map(c => c.value).join("");
      if (!/^\d{4}$/.test(otp)) {
        const err = scope.querySelector(".ar-form-err");
        err.textContent = "Lengkapi 4 digit OTP";
        err.hidden = false;
        return;
      }
      submitting = true;
      // v568: submitBackupOtp sekarang AUTO-VERIFY (return approved=true kalau match)
      const r = await submitBackupOtp(requestId, otp);
      submitting = false;
      if (!r.ok) {
        const err = scope.querySelector(".ar-form-err");
        err.textContent = r.error || "Gagal verify OTP";
        err.hidden = false;
        // Clear cells supaya bisa input ulang
        cells.forEach(c => c.value = "");
        cells[0].focus();
        return;
      }
      // OTP match → status APPROVED, refresh render (akan auto-tampil password reset inline)
      render();
    });
  }

  // v568: render password reset form INLINE di modal yang sama (bukan
  // navigate ke forgotPwModal). Setelah OTP approved, user langsung set
  // password baru di sini.
  function renderInlinePasswordReset(scope, req) {
    scope.innerHTML = `
      <h3 class="ar-text-center" data-no-i18n>✅ OTP terverifikasi</h3>
      <p class="muted ar-text-center" data-no-i18n>Sekarang atur password baru untuk akun <b>${_arEscapeHtml(req.requester_email)}</b>.</p>
      <form class="ar-form" id="arInlinePwForm" autocomplete="off">
        <label class="ar-label" data-no-i18n>Password Baru</label>
        <input type="password" name="pw1" placeholder="Min. 6 karakter" required minlength="6" autocomplete="new-password" />
        <label class="ar-label" data-no-i18n>Konfirmasi Password Baru</label>
        <input type="password" name="pw2" placeholder="Ulangi password baru" required minlength="6" autocomplete="new-password" />
        <div class="ar-form-err" hidden></div>
        <div class="ar-form-actions-compact">
          <button type="submit" class="btn primary btn-compact">Set Password Baru</button>
        </div>
      </form>
    `;
    const form = scope.querySelector("#arInlinePwForm");
    form?.addEventListener("submit", async e => {
      e.preventDefault();
      const fd = new FormData(form);
      const pw1 = String(fd.get("pw1") || "");
      const pw2 = String(fd.get("pw2") || "");
      const errEl = form.querySelector(".ar-form-err");
      const showErr = msg => { errEl.textContent = msg; errEl.hidden = false; };
      if (pw1.length < 6) return showErr("Password minimal 6 karakter");
      if (pw1 !== pw2) return showErr("Konfirmasi password tidak cocok");
      try {
        const acct = JSON.parse(localStorage.getItem(`playly-account-${req.requester_email}`) || "null");
        if (!acct) return showErr("Akun tidak ditemukan");
        acct.password = await hashPassword(pw1);
        acct.passwordResetAt = Date.now();
        localStorage.setItem(`playly-account-${req.requester_email}`, JSON.stringify(acct));
        // Reset login lockout
        if (typeof clearLoginAttempts === "function") {
          clearLoginAttempts(req.requester_email);
          if (req.requester_username) clearLoginAttempts(req.requester_username);
        }
        // Audit log
        try {
          if (typeof pushAdminEvent === "function") {
            pushAdminEvent("🔑", `Password reset via OTP recovery untuk <b>${escapeHtml(acct.username || req.requester_email)}</b>`);
          }
        } catch {}
        if (typeof toast === "function") {
          toast("🔑 Password berhasil di-reset. Silakan login dengan password baru.", "success");
        }
        m.remove();
        // Pre-fill email di login form
        const loginInput = document.querySelector('#signinForm input[name="email"]');
        if (loginInput) loginInput.value = req.requester_email;
      } catch (err) {
        console.error("[inline-pw-reset] error", err);
        showErr("Gagal reset password. Coba lagi.");
      }
    });
  }

  function stopPoll() { if (pollTimer) { clearInterval(pollTimer); pollTimer = null; } }

  render();
  pollTimer = setInterval(render, 3000);

  m.addEventListener("click", e => {
    if (e.target.matches("[data-close], [data-close-ok], .modal-backdrop")) {
      stopPoll();
      m.remove();
    }
  });
  return m;
}

// ───────────────────── SUPER ADMIN SIDE ─────────────────────

// Modal list pending requests untuk super admin.
function openSuperAdminRecoveryListModal() {
  _arRemoveOpenModals();
  const m = document.createElement("div");
  m.className = "modal show ar-modal";
  m.id = "superRecoveryListModal";
  m.style.zIndex = "10020";
  m.innerHTML = `
    <div class="modal-backdrop" data-close></div>
    <div class="modal-panel ar-panel-wide">
      <button class="modal-close" data-close aria-label="Tutup">×</button>
      <h3 data-no-i18n>🔐 Permintaan Akses Akun</h3>
      <p class="muted" data-no-i18n>Daftar user/admin yang minta recovery via OTP. Klik aksi sesuai status.</p>
      <div class="ar-req-list"></div>
    </div>
  `;
  document.body.appendChild(m);

  const listEl = m.querySelector(".ar-req-list");
  let pollTimer = null;

  function render() {
    const reqs = getAdminRecoveryRequests()
      .filter(r => r.status !== AR_STATUS.EXPIRED && r.status !== AR_STATUS.APPROVED && r.status !== AR_STATUS.DENIED)
      .sort((a, b) => (b.created_at || 0) - (a.created_at || 0));

    if (!reqs.length) {
      listEl.innerHTML = `<div class="ar-empty">
        <div class="ar-empty-ico">📭</div>
        <p>Tidak ada permintaan recovery yang aktif.</p>
      </div>`;
      return;
    }

    listEl.innerHTML = reqs.map(r => {
      const ageMin = Math.floor((Date.now() - (r.created_at || 0)) / 60000);
      const ttlMin = Math.max(0, Math.ceil(((r.expires_at || 0) - Date.now()) / 60000));
      // v568: simplified flow — combine generate+send jadi 1 button "Kirim OTP".
      // Setelah dikirim, auto-verify saat user input. Tidak ada step re-verify
      // atau manual konfirmasi.
      let actionBtn = "";
      if (r.status === AR_STATUS.PENDING || r.status === AR_STATUS.OTP_GENERATED) {
        actionBtn = `<button class="btn primary btn-compact" data-ar-action="send" data-ar-id="${_arEscapeHtml(r.id)}">📨 Kirim OTP</button>`;
      } else if (r.status === AR_STATUS.WAITING_INPUT) {
        actionBtn = `<span class="ar-status-pill ar-pill-waiting">OTP terkirim, tunggu user input...</span>`;
      } else if (r.status === AR_STATUS.INPUT_RECEIVED) {
        // Legacy state — kalau ada request lama, auto-redirect ke "kirim ulang"
        actionBtn = `<button class="btn primary btn-compact" data-ar-action="send" data-ar-id="${_arEscapeHtml(r.id)}">📨 Kirim OTP Ulang</button>`;
      }
      return `
        <div class="ar-req-row" data-ar-req-row="${_arEscapeHtml(r.id)}">
          <div class="ar-req-info">
            <strong>${_arEscapeHtml(r.requester_email)}</strong>
            <div class="ar-req-meta">
              <span class="ar-status-pill ar-pill-${r.status}">${_arEscapeHtml(_arStatusLabel(r.status))}</span>
              <span class="ar-req-age">${ageMin} menit lalu · TTL ${ttlMin}m</span>
            </div>
          </div>
          <div class="ar-req-actions">${actionBtn}</div>
        </div>
      `;
    }).join("");
  }

  listEl.addEventListener("click", async e => {
    const btn = e.target.closest("[data-ar-action]");
    if (!btn) return;
    const action = btn.dataset.arAction;
    const id = btn.dataset.arId;
    if (action === "send") {
      // v568: combined generate + send. Auto-transition status ke WAITING_INPUT.
      // Tampilkan modal display OTP supaya super admin bisa copy + verify
      // bahwa "email sudah terkirim" (dalam simulasi via system message).
      const gen = await generateAndSendRecoveryOtp(id);
      if (!gen.ok) return toast(gen.error || "Gagal kirim OTP", "error");
      // Open modal display OTP + confirmation
      openSuperAdminSendOtpModal(id, gen.otpPlain);
      // Refresh list di belakang (modal akan re-open list setelah close)
    }
  });

  render();
  pollTimer = setInterval(render, 3000);

  m.addEventListener("click", e => {
    if (e.target.matches("[data-close], .modal-backdrop")) {
      if (pollTimer) clearInterval(pollTimer);
      m.remove();
    }
  });
  return m;
}

// Modal: super admin lihat OTP yang baru terkirim ke email user.
// v568: gabungan dari generate + verify modal lama. Status sudah ter-update
// ke WAITING_INPUT saat modal ini terbuka (via generateAndSendRecoveryOtp).
// Super admin lihat OTP plain untuk verifikasi konten email yang sudah
// terkirim. Tutup modal = balik ke list super admin.
function openSuperAdminSendOtpModal(requestId, otpPlain) {
  _arRemoveOpenModals();
  const m = document.createElement("div");
  m.className = "modal show ar-modal";
  m.style.zIndex = "10020";
  const otpDigits = String(otpPlain).split("").map(d => `<span class="ar-otp-digit">${d}</span>`).join("");
  // Get user email for display
  const req = getAdminRecoveryRequests().find(r => r.id === requestId);
  const userEmail = req?.requester_email || "user";
  m.innerHTML = `
    <div class="modal-backdrop" data-ar-back-list></div>
    <div class="modal-panel ar-panel-narrow" data-no-i18n>
      <h3 class="ar-text-center" data-no-i18n>📨 OTP terkirim ke email</h3>
      <p class="muted ar-text-center" data-no-i18n>OTP 4-digit di bawah sudah dikirim ke <b>${_arEscapeHtml(userEmail)}</b>. User sekarang akan diminta input OTP ini di layar mereka.</p>
      <div class="ar-otp-display">${otpDigits}</div>
      <button type="button" class="btn ghost ar-copy-btn btn-compact" data-ar-copy="${_arEscapeHtml(otpPlain)}">📋 Copy OTP</button>
      <div class="ar-divider"></div>
      <p class="muted ar-text-center" data-no-i18n>Sistem akan auto-verify saat user input OTP. Kamu tidak perlu approve manual.</p>
      <div class="ar-form-actions-compact">
        <button type="button" class="btn primary btn-compact" data-ar-back-list>Selesai</button>
      </div>
    </div>
  `;
  document.body.appendChild(m);

  m.querySelector("[data-ar-copy]")?.addEventListener("click", async e => {
    const otp = e.currentTarget.dataset.arCopy;
    try { await navigator.clipboard.writeText(otp); toast("✅ OTP di-copy", "success"); } catch { toast("Gagal copy, salin manual", "warning"); }
  });
  // Klik "Selesai" atau backdrop → balik ke list
  m.addEventListener("click", e => {
    if (e.target.matches("[data-ar-back-list]")) {
      m.remove();
      openSuperAdminRecoveryListModal();
    }
  });
  return m;
}

// Modal: super admin ketik ulang OTP untuk verify anti-typo.
function openSuperAdminVerifyOtpModal(requestId) {
  _arRemoveOpenModals();
  const m = document.createElement("div");
  m.className = "modal show ar-modal";
  m.style.zIndex = "10020";
  m.innerHTML = `
    <div class="modal-backdrop" data-close></div>
    <div class="modal-panel ar-panel-narrow">
      <button class="modal-close" data-close aria-label="Tutup">×</button>
      <h3>🔍 Re-verify OTP</h3>
      <p class="muted">Ketik ulang 4 digit OTP yang barusan kamu kirim ke backup admin. Ini untuk pastikan kamu ngga typo waktu kirim.</p>
      <div class="ar-otp-grid">
        <input type="text" inputmode="numeric" maxlength="1" data-ar-otp-cell="0" />
        <input type="text" inputmode="numeric" maxlength="1" data-ar-otp-cell="1" />
        <input type="text" inputmode="numeric" maxlength="1" data-ar-otp-cell="2" />
        <input type="text" inputmode="numeric" maxlength="1" data-ar-otp-cell="3" />
      </div>
      <div class="ar-form-err" hidden></div>
      <div class="ar-form-actions">
        <button type="button" class="btn ghost" data-close>Tutup</button>
        <button type="button" class="btn primary" data-ar-submit>Verify</button>
      </div>
    </div>
  `;
  document.body.appendChild(m);

  const cells = Array.from(m.querySelectorAll("[data-ar-otp-cell]"));
  cells.forEach((cell, i) => {
    cell.addEventListener("input", e => {
      const v = (e.target.value || "").replace(/\D/g, "").slice(-1);
      e.target.value = v;
      if (v && i < cells.length - 1) cells[i + 1].focus();
    });
    cell.addEventListener("keydown", e => {
      if (e.key === "Backspace" && !cell.value && i > 0) cells[i - 1].focus();
    });
  });
  cells[0]?.focus();

  m.querySelector("[data-ar-submit]")?.addEventListener("click", async () => {
    const otp = cells.map(c => c.value).join("");
    const err = m.querySelector(".ar-form-err");
    if (!/^\d{4}$/.test(otp)) { err.textContent = "Lengkapi 4 digit"; err.hidden = false; return; }
    const v = await verifyGeneratedOtp(requestId, otp);
    if (!v.ok) {
      err.textContent = v.error || "Verify gagal";
      err.hidden = false;
      cells.forEach(c => c.value = "");
      cells[0].focus();
      return;
    }
    m.remove();
    if (typeof toast === "function") toast("✅ OTP terverifikasi. Sekarang tunggu backup admin input OTP.", "success");
    openSuperAdminRecoveryListModal();
  });
  return m;
}

// Modal: super admin final approve/deny setelah backup admin input OTP.
function openSuperAdminFinalConfirmModal(requestId, otpEntered) {
  _arRemoveOpenModals();
  const m = document.createElement("div");
  m.className = "modal show ar-modal";
  m.style.zIndex = "10020";
  const digitsDisplay = String(otpEntered || "----").padEnd(4, "-").slice(0, 4).split("").map(d => `<span class="ar-otp-digit">${d}</span>`).join("");
  m.innerHTML = `
    <div class="modal-backdrop" data-close></div>
    <div class="modal-panel ar-panel-narrow">
      <button class="modal-close" data-close aria-label="Tutup">×</button>
      <h3>🔎 Konfirmasi OTP backup admin</h3>
      <p class="muted">Backup admin sudah input OTP berikut. Cocokkan dengan yang barusan kamu kirim — kalau sama, approve. Kalau beda, deny.</p>
      <div class="ar-otp-display ar-otp-display-muted">${digitsDisplay}</div>
      <div class="ar-divider"></div>
      <p class="muted">Approve = backup admin granted access + bisa set password baru. Deny = request closed.</p>
      <div class="ar-form-actions">
        <button type="button" class="btn ghost" data-ar-deny>❌ Tolak</button>
        <button type="button" class="btn primary" data-ar-approve>✅ Setujui Akses</button>
      </div>
    </div>
  `;
  document.body.appendChild(m);

  m.querySelector("[data-ar-approve]")?.addEventListener("click", async () => {
    const r = await finalDecideRecovery(requestId, true);
    if (r.ok) {
      if (typeof toast === "function") toast("✅ Akses diberikan ke backup admin", "success");
    } else {
      if (typeof toast === "function") toast(r.error || "Approve gagal", "error");
    }
    m.remove();
    openSuperAdminRecoveryListModal();
  });
  m.querySelector("[data-ar-deny]")?.addEventListener("click", async () => {
    const r = await finalDecideRecovery(requestId, false);
    if (typeof toast === "function") toast(r.ok ? "Request ditolak" : (r.error || "Deny gagal"), r.ok ? "info" : "error");
    m.remove();
    openSuperAdminRecoveryListModal();
  });
  return m;
}

