// ───────────────── SUPER ADMIN ENTRY POINT — TOPBAR BUTTON ─────────────────
// Inject "Permintaan Akses" button ke topbar admin. Muncul HANYA kalau user
// adalah super admin. Badge count auto-update via polling 5s.
function mountSuperAdminRecoveryEntry() {
  // Sudah di-mount?
  if (document.getElementById("arSuperEntry")) return;
  // Cek super admin status
  const u = window.user || null;
  if (typeof isSuperAdmin === "function" && !isSuperAdmin(u)) return;

  // Cari container yang cocok di topbar — coba beberapa fallback
  const candidates = [
    "#topbarRight",
    ".topbar-right",
    ".topbar .topbar-actions",
    ".topbar"
  ];
  let container = null;
  for (const sel of candidates) {
    container = document.querySelector(sel);
    if (container) break;
  }
  if (!container) return;

  const btn = document.createElement("button");
  btn.type = "button";
  btn.id = "arSuperEntry";
  btn.className = "ar-super-entry";
  btn.title = "Permintaan Akses Admin";
  btn.setAttribute("data-count", "0");
  btn.innerHTML = `
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
      <path d="M12 2L4 5v7c0 5 3.5 9.5 8 11 4.5-1.5 8-6 8-11V5l-8-3z"/>
      <path d="M9 12l2 2 4-4"/>
    </svg>
    <span class="ar-super-entry-badge"></span>
  `;
  // Insert di awal container biar paling kiri (atau gunakan prepend)
  container.insertBefore(btn, container.firstChild);

  btn.addEventListener("click", () => openSuperAdminRecoveryListModal());

  function refreshBadge() {
    const count = countPendingAdminRecovery();
    btn.setAttribute("data-count", String(count));
    const badge = btn.querySelector(".ar-super-entry-badge");
    if (badge) badge.textContent = count > 0 ? String(count) : "";
  }
  refreshBadge();
  // Polling badge tiap 5 detik
  setInterval(refreshBadge, 5000);
}

// Auto-mount saat dashboard init (super admin only). Coba beberapa kali
// dengan retry karena topbar mungkin belum render saat first call.
function _arTryMountSuperEntry() {
  let tries = 0;
  const timer = setInterval(() => {
    tries++;
    mountSuperAdminRecoveryEntry();
    if (document.getElementById("arSuperEntry") || tries > 10) {
      clearInterval(timer);
    }
  }, 400);
}

// Mount saat view berubah ke admin dashboard
window.addEventListener("playly:view-changed", e => {
  if (e.detail?.view === "admin-dashboard") _arTryMountSuperEntry();
});
window.addEventListener("playly:cloud-applied", () => {
  setTimeout(_arTryMountSuperEntry, 500);
});

// ============ PIN 2FA GATE (SELF-RESET, UNIFIED v565) ================
// v565: ganti dari Recovery Key (v563*) ke PIN 2FA existing, sekarang
// unified untuk user + admin per request "di dashboard user juga samakan".
//
// Flow:
// - Field SELALU visible di forgotPwModal (user + admin context).
// - JS refresh: lookup account, kalau acc.pin set → required + tag "WAJIB",
//   kalau gak ada → optional + tag "opsional".
// - Submit: kalau acc.pin set → verify pakai verifyPin inline (skip popup
//   modal). Kalau gak ada → field kosong OK, lanjut tanpa verify.

function _refreshForgotAdminPinField() {
  const form = document.getElementById("forgotPwForm");
  if (!form) return;
  const field = document.getElementById("forgotAdminPinField");
  if (!field) return;
  const pinInput = field.querySelector('input[name="adminPin"]');
  const pinTag = field.querySelector(".pin-tag");

  // Resolve email + look up account untuk cek acc.pin
  const idInput = form.querySelector('input[name="email"]');
  const id = (idInput?.value || "").trim().toLowerCase();
  let acct = null;
  if (id) {
    if (id.includes("@")) {
      try { acct = JSON.parse(localStorage.getItem(`playly-account-${id}`) || "null"); } catch {}
    } else if (typeof findAccountByUsername === "function") {
      acct = findAccountByUsername(id);
    }
  }
  const has2FA = !!(acct && acct.pin);

  if (pinInput) {
    if (has2FA) {
      pinInput.setAttribute("required", "");
      field.classList.add("pin-required");
    } else {
      pinInput.removeAttribute("required");
      field.classList.remove("pin-required");
    }
  }
  if (pinTag) {
    pinTag.textContent = has2FA ? "wajib" : "opsional";
  }
}

// Listen email changes + modal opens
document.addEventListener("input", e => {
  if (e.target.matches('#forgotPwForm input[name="email"]')) {
    _refreshForgotAdminPinField();
  }
});
document.addEventListener("click", e => {
  if (e.target.closest("#forgotPw")) {
    setTimeout(_refreshForgotAdminPinField, 150);
  }
});

// Numeric-only filter untuk PIN input
document.addEventListener("input", e => {
  if (!e.target.matches('#forgotPwForm input[name="adminPin"]')) return;
  const stripped = e.target.value.replace(/\D/g, "").slice(0, 6);
  if (e.target.value !== stripped) e.target.value = stripped;
});

window._adminPinGate = {
  refreshFormField: _refreshForgotAdminPinField
};

// ───────────────────── UNIVERSAL RECOVERY CHOICE MODAL (v566) ─────────────────
// Per request user 2026-05-26: jangan langsung buka kolom — pilih dulu mana
// cara recovery (PIN 2FA sendiri atau minta OTP ke super admin), baru
// arahkan ke modal/form yang sesuai.
//
// Diganti dari openAdminRecoveryChoiceModal (v562 backup-admin-only). Choice
// modal sekarang universal: berlaku untuk user + backup admin. Super admin
// tetap di-block via createAdminRecoveryRequest validator (recovery code
// flow nanti).
function openUniversalRecoveryChoiceModal(prefillId = "") {
  _arRemoveOpenModals();
  // v568: context-aware copy. ADMIN dashboard (body[data-role="admin"]):
  //   "Super Admin" saja — backup admin tidak bisa approve admin recovery
  //   (security: only super admin handles admin keys). USER dashboard:
  //   "Super Admin/Admin" — backup admin BISA approve user recovery.
  const _isAdminCtx = document.body.dataset.role === "admin";
  const _approverLabel = _isAdminCtx ? "Super Admin" : "Super Admin/Admin";
  const _approverDesc = _isAdminCtx ? "super admin" : "super admin atau admin";
  const m = document.createElement("div");
  m.className = "modal show ar-modal ar-modal-choice";
  m.id = "universalRecoveryChoiceModal";
  m.style.zIndex = "10020";
  m.innerHTML = `
    <div class="modal-backdrop" data-close></div>
    <div class="modal-panel ar-panel-narrow" data-no-i18n>
      <h3 class="ar-text-center" data-no-i18n>Pilih cara recovery akun</h3>
      <p class="muted ar-text-center" data-no-i18n>Mau reset sendiri atau minta verifikasi dari ${_approverDesc}? Pilih yang paling cocok dengan situasimu.</p>
      <div class="ar-choice-grid">
        <button type="button" class="ar-choice-card" data-ar-choice="self">
          <div class="ar-choice-ico">🔐</div>
          <strong data-no-i18n>Reset Sendiri</strong>
          <small data-no-i18n>Atur password baru langsung. Kalau akunmu aktif 2FA, perlu masukkan PIN 6-digit untuk verifikasi.</small>
        </button>
        <button type="button" class="ar-choice-card" data-ar-choice="otp">
          <div class="ar-choice-ico">📨</div>
          <strong data-no-i18n>Minta OTP via ${_arEscapeHtml(_approverLabel)}</strong>
          <small data-no-i18n>${_arEscapeHtml(_approverDesc.charAt(0).toUpperCase() + _approverDesc.slice(1))} akan kirim OTP 4-digit ke email kamu. Cocok kalau lupa PIN 2FA atau belum aktifkan.</small>
        </button>
      </div>
    </div>
  `;
  document.body.appendChild(m);

  m.querySelector('[data-ar-choice="self"]')?.addEventListener("click", () => {
    m.remove();
    if (typeof openForgotPwModal === "function") {
      // v567: track bahwa modal di-open dari choice picker, supaya Batal/
      // backdrop close → balik ke choice picker (bukan close total)
      window._forgotPwFromChoice = true;
      window._forgotPwReturnPrefill = prefillId;
      openForgotPwModal(prefillId);
    }
  });
  m.querySelector('[data-ar-choice="otp"]')?.addEventListener("click", () => {
    m.remove();
    if (typeof openAdminRecoveryOtpRequestModal === "function") {
      openAdminRecoveryOtpRequestModal(prefillId, { fromChoice: true });
    }
  });
  // v568b: klik backdrop di luar panel → close modal total. User minta
  // "klik di luar dari dalam kolom keluar dari halaman pop up".
  m.addEventListener("click", e => {
    if (e.target.matches(".modal-backdrop, [data-close]")) {
      m.remove();
    }
  });
  return m;
}

// Expose untuk inline caller (#forgotPw direct listener)
window.openUniversalRecoveryChoiceModal = openUniversalRecoveryChoiceModal;

