// =================== ADMIN: TOP INSIGHTS (dashboard panel) ===================
function renderAdminTopInsights() {
  // FIX 2026-05-19: dulu early-return kalau #adminTopVideosLive tidak ada.
  // Panel "Top Performing Videos" sudah dihapus dari markup dashboard,
  // sehingga guard ini membuat SELURUH fungsi bail → kolom TERKINI
  // (Video baru di upload / User Baru / Kreator Teratas) tidak pernah
  // ke-render. Sekarang bail HANYA kalau semua panel TERKINI juga tidak
  // ada (mis. bukan di halaman admin dashboard). Blok Top Videos
  // di-guard null sendiri di bawah.
  if (!$("#adminTopVideosLive") && !$("#adminRecentVideosLive") &&
      !$("#adminTopCreatorsLive") && !$("#adminRecentUsersLive")) return;
  const m = getAdminMetrics();
  // Filter admin dari pool — dashboard fokus pada aktivitas USER, bukan akun admin
  const accounts = (m.accounts || []).filter(a => a.role !== "admin");
  const videos = (m.videos || []).filter(v => v.creator && !isAdminUsername(v.creator));

  // Top Performing Videos — combined ranking by views + likes (sort by total engagement)
  // Score = viewsNum + likes*5 (likes lebih bernilai dari sekedar view)
  const topVids = [...videos]
    .map(v => ({ ...v, _score: (v.viewsNum || 0) + (v.likes || 0) * 5 }))
    .sort((a, b) => b._score - a._score)
    .slice(0, 5);
  const tvEl = $("#adminTopVideosLive");
  if (tvEl) {
    tvEl.innerHTML = topVids.length ? topVids.map((v, i) => `
    <div class="admin-list-row admin-list-row-playable" data-open-video="${v.id}" title="Play video">
      <span class="rank">#${i + 1}</span>
      <div>
        <strong>${escapeHtml(v.title)}</strong>
        <small>@${escapeHtml(v.creator)} • ${v.duration || "0:00"}</small>
      </div>
      <b style="display:flex;gap:14px;align-items:center;white-space:nowrap">
        <span title="Views">👁️ ${fmtNum(v.viewsNum || 0)}</span>
        <span title="Likes">♥ ${fmtNum(v.likes || 0)}</span>
      </b>
      <button type="button" class="admin-row-play" title="Play video" aria-label="Play video">
        <svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><path d="M8 5v14l11-7z"/></svg>
      </button>
    </div>
  `).join("") : `<div style="text-align:center;padding:20px;color:var(--muted);font-size:12px">No videos yet.</div>`;
    $$("[data-open-video]", tvEl).forEach(b => {
      b.addEventListener("click", () => {
        const vid = Number(b.dataset.openVideo);
        if (vid && typeof openPlayer === "function") openPlayer(vid);
      });
    });
  }

  // Recent Uploads (video baru di-upload) — sort by id (=Date.now() saat upload)
  const recentVids = [...videos].sort((a, b) => (b.id || 0) - (a.id || 0)).slice(0, 5);
  const rvEl = $("#adminRecentVideosLive");
  if (rvEl) {
    rvEl.innerHTML = recentVids.length ? recentVids.map(v => {
      const uploaded = v.id ? relTime(v.id) : "—";
      const thumb = v.thumb || `https://picsum.photos/seed/playly-${v.id || Math.random()}/96/56`;
      return `
        <div class="admin-list-row admin-list-row-playable admin-row-with-thumb" data-open-video="${v.id}" title="Play video">
          <div class="admin-row-thumb">
            <img src="${thumb}" alt="" loading="lazy"/>
            <span class="admin-row-thumb-overlay" aria-hidden="true">
              <svg viewBox="0 0 24 24" fill="currentColor"><path d="M8 5v14l11-7z"/></svg>
            </span>
          </div>
          <div>
            <strong>${escapeHtml(v.title)}</strong>
            <small>@${escapeHtml(v.creator)} • ${uploaded}</small>
          </div>
          <b style="font-size:11px;color:var(--muted);font-weight:600">${fmtNum(v.viewsNum || 0)} views</b>
          <button type="button" class="admin-row-play admin-row-play-prominent" data-open-video="${v.id}" title="Play video" aria-label="Play video">
            <svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><path d="M8 5v14l11-7z"/></svg>
            <span>Play</span>
          </button>
        </div>
      `;
    }).join("") : `<div style="text-align:center;padding:20px;color:var(--muted);font-size:12px">Belum ada video yang diunggah.</div>`;
    $$("[data-open-video]", rvEl).forEach(b => {
      b.addEventListener("click", () => {
        const vid = Number(b.dataset.openVideo);
        if (!vid) return;
        // Admin role → dedicated preview modal; otherwise fallback to player view.
        const isAdmin = document.body.dataset.role === "admin";
        if (isAdmin && typeof openAdminPlayer === "function") {
          openAdminPlayer(vid);
        } else if (typeof openPlayer === "function") {
          openPlayer(vid);
        }
      });
    });
  }

  // Top 5 creators by total views (sudah filter admin di videos)
  const creatorMap = {};
  videos.forEach(v => {
    if (!v.creator) return;
    creatorMap[v.creator] = creatorMap[v.creator] || { name: v.creator, videos: 0, views: 0 };
    creatorMap[v.creator].videos++;
    creatorMap[v.creator].views += v.viewsNum || 0;
  });
  const topCreators = Object.values(creatorMap).sort((a, b) => b.views - a.views).slice(0, 5);
  $("#adminTopCreatorsLive").innerHTML = topCreators.length ? topCreators.map((c, i) => {
    // Avatar = profil kreator sendiri (gambar yg di-set user, atau
    // avatar generatif per-username) — BUKAN tema admin slate.
    const av = _findAvatarByUsername(c.name, accounts)
      || ("https://api.dicebear.com/7.x/avataaars/svg?seed=" + encodeURIComponent(c.name || "user"));
    return `
    <div class="admin-list-row" style="cursor:pointer" data-open-user="${escapeHtml(c.name)}">
      <span class="admin-row-av"><img src="${escapeHtml(av)}" alt="" loading="lazy" referrerpolicy="no-referrer"/></span>
      <div>
        <strong>@${escapeHtml(c.name)}</strong>
        <small>#${i + 1} • ${c.videos} video</small>
      </div>
      <b>${fmtNum(c.views)} views</b>
    </div>
  `;
  }).join("") : `<div style="text-align:center;padding:20px;color:var(--muted);font-size:12px">Belum ada kreator aktif.</div>`;
  $$("[data-open-user]", $("#adminTopCreatorsLive")).forEach(b => {
    b.addEventListener("click", () => openUserDetail(b.dataset.openUser));
  });

  // Recent users (5 terbaru, BUKAN admin) — sort by joinedAt
  const recentUsers = [...accounts]
    .sort((a, b) => new Date(b.joinedAt || 0) - new Date(a.joinedAt || 0))
    .slice(0, 5);
  $("#adminRecentUsersLive").innerHTML = recentUsers.length ? recentUsers.map(a => {
    const joined = a.joinedAt ? relTime(new Date(a.joinedAt).getTime()) : "—";
    // Avatar = gambar profil yg di-set user, atau avatar generatif
    // per-username (identitas user) — BUKAN inisial "U" / tema admin.
    const av = a.avatar
      || ("https://api.dicebear.com/7.x/avataaars/svg?seed=" + encodeURIComponent(a.username || a.name || "user"));
    return `
      <div class="admin-list-row" style="cursor:pointer" data-open-user="${escapeHtml(a.username)}">
        <span class="admin-row-av"><img src="${escapeHtml(av)}" alt="" loading="lazy" referrerpolicy="no-referrer"/></span>
        <div>
          <strong>${escapeHtml(a.name || a.username)}</strong>
          <small>@${escapeHtml(a.username)} • ${joined}</small>
        </div>
        <b style="font-size:10px;color:var(--muted);font-weight:600">USER</b>
      </div>
    `;
  }).join("") : `<div style="text-align:center;padding:20px;color:var(--muted);font-size:12px">Belum ada user terdaftar.</div>`;
  $$("[data-open-user]", $("#adminRecentUsersLive")).forEach(b => {
    b.addEventListener("click", () => openUserDetail(b.dataset.openUser));
  });

  // Live Activity Stream — gabungan event signup + upload
  renderAdminLiveActivity(accounts, videos);

  // Trend 7 hari terakhir — bar chart upload count per hari
  renderAdminTrend(videos);

  // Ringkasan hari ini
  renderAdminTodaySummary(m, accounts, videos);
}

// Helper: cek apakah username adalah admin (defensive — admin tidak boleh muncul di feed user)
function isAdminUsername(username) {
  if (!username) return false;
  if (typeof OFFICIAL_ADMIN_USERNAME !== "undefined" && username === OFFICIAL_ADMIN_USERNAME) return true;
  // Fallback: cek di accounts
  try {
    const accounts = getAllAccounts();
    return accounts.some(a => a.username === username && a.role === "admin");
  } catch { return false; }
}

function renderAdminLiveActivity(accounts, videos) {
  const list = $("#adminLiveActivity"); if (!list) return;

  const events = [];
  // Event: video upload
  for (const v of videos) {
    if (!v.id) continue;
    events.push({
      type: "upload",
      ts: v.id,
      icon: "🎬",
      text: `<b>@${escapeHtml(v.creator || "—")}</b> upload video <i>"${escapeHtml((v.title || "").slice(0, 60))}${(v.title || "").length > 60 ? "..." : ""}"</i>`,
      onClick: () => { if (typeof openPlayer === "function") openPlayer(v.id); }
    });
  }
  // Event: user signup
  for (const a of accounts) {
    if (!a.joinedAt) continue;
    const ts = new Date(a.joinedAt).getTime();
    if (!ts) continue;
    events.push({
      type: "signup",
      ts,
      icon: "👤",
      text: `<b>@${escapeHtml(a.username)}</b> ${escapeHtml(a.name || "")} bergabung sebagai <i>${(a.role || "user")}</i>`,
      onClick: () => { if (typeof openUserDetail === "function") openUserDetail(a.username); }
    });
  }
  // Event: like milestone — kalau ada video dengan likes >= 10, anggap "trending"
  for (const v of videos) {
    if ((v.likes || 0) >= 10) {
      events.push({
        type: "like",
        ts: (v.id || 0) + 1, // urut sedikit setelah upload
        icon: "❤️",
        text: `Video <i>"${escapeHtml((v.title || "").slice(0, 50))}"</i> dari <b>@${escapeHtml(v.creator || "—")}</b> mencapai <b>${fmtNum(v.likes)}</b> likes`,
        onClick: () => { if (typeof openPlayer === "function") openPlayer(v.id); }
      });
    }
  }

  events.sort((a, b) => b.ts - a.ts);
  const top = events.slice(0, 30);

  if (!top.length) {
    list.innerHTML = `<div style="text-align:center;padding:32px 16px;color:var(--muted)">
      <div style="font-size:36px;opacity:.55;margin-bottom:8px">⏳</div>
      <p style="font-size:13px">No user activity yet. Activity will appear in real-time once a user signs up or uploads a video.</p>
    </div>`;
    return;
  }

  list.innerHTML = top.map((e, i) => `
    <div class="activity-row ${e.type}" data-act-idx="${i}" title="Klik untuk detail">
      <div class="activity-icon">${e.icon}</div>
      <div class="activity-text">${e.text}</div>
      <small class="activity-time" title="${new Date(e.ts).toLocaleString("id-ID")}">${chatRelTime(e.ts) || relTime(e.ts) || "—"}</small>
    </div>
  `).join("");

  list.querySelectorAll("[data-act-idx]").forEach(el => {
    const idx = Number(el.dataset.actIdx);
    const ev = top[idx];
    if (ev?.onClick) el.addEventListener("click", ev.onClick);
  });
}

function renderAdminTrend(videos) {
  const ID_DAYS_SHORT_LOCAL = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
  const now = new Date();
  const days = [];
  for (let i = 6; i >= 0; i--) {
    const d = new Date(now);
    d.setDate(d.getDate() - i);
    d.setHours(0, 0, 0, 0);
    const next = new Date(d); next.setDate(next.getDate() + 1);
    const count = videos.filter(v => {
      const t = v.id || 0; // id = Date.now() saat upload
      return t >= d.getTime() && t < next.getTime();
    }).length;
    // Tambah simulasi engagement biar bar tidak kosong total
    const value = count * 5 + ((d.getDate() * 7) % 12);
    days.push({ label: ID_DAYS_SHORT_LOCAL[d.getDay()], count, value });
  }
  const max = Math.max(...days.map(d => d.value), 1);
  const chart = $("#adminTrendChart");
  if (!chart) return;
  chart.innerHTML = days.map(d => {
    const pct = (d.value / max) * 100;
    return `<div class="rev-bar">
      <span class="bar-value">${d.count > 0 ? d.count : ""}</span>
      <div class="bar-fill" style="height: calc(${pct}% - 24px)"></div>
      <span class="bar-label">${d.label}</span>
    </div>`;
  }).join("");
}

function renderAdminTodaySummary(m, accounts, videos) {
  const today = new Date(); today.setHours(0, 0, 0, 0);
  const todayMs = today.getTime();

  const uploadsToday = videos.filter(v => (v.id || 0) >= todayMs).length;
  const usersToday = accounts.filter(a => new Date(a.joinedAt || 0).getTime() >= todayMs).length;
  const totalViewsToday = Math.floor((m.totalViews || 0) * 0.05);
  const totalLikes = videos.reduce((s, v) => s + (v.likes || 0), 0);
  const likesToday = Math.floor(totalLikes * 0.08);
  const reportsToday = (getAdminData("mod") || []).filter(x => (x.reportedAt || 0) >= todayMs).length;
  const ticketsToday = (getAdminData("tickets") || []).filter(x => (x.createdAt || 0) >= todayMs).length;

  const setSum = (id, n) => {
    const el = $("#" + id);
    if (!el) return;
    el.textContent = fmtNum(n);
    el.classList.toggle("zero", n === 0);
  };
  setSum("sumUploadsToday", uploadsToday);
  setSum("sumUsersToday", usersToday);
  setSum("sumViewsToday", totalViewsToday);
  setSum("sumLikesToday", likesToday);
  setSum("sumReportsToday", reportsToday);
  setSum("sumTicketsToday", ticketsToday);
}

// =================== ADMIN: AD MANAGER ===================
// Setiap section (running text / banner / pre-roll) mendukung BANYAK item.
// Player memilih satu item per video sesuai mode rotasi (random/sequential),
// atau menampilkan semua sekaligus untuk running text. Pre-roll blob disimpan
// per-id di IndexedDB. Auto-save: tidak ada tombol Simpan global.

const AD_CONFIG_KEY = "playly-ad-config";
const AD_PREROLL_BLOB_PREFIX = "__ad_preroll_";   // + id
const AD_PREROLL_LEGACY_ID  = "__ad_preroll__";   // single-item lama

function adUid() { return "ad_" + Math.random().toString(36).slice(2, 10); }
function prerollBlobId(id) { return AD_PREROLL_BLOB_PREFIX + id; }
function adCap(s) { return s[0].toUpperCase() + s.slice(1); }

function defaultRtItem() {
  return {
    id: adUid(), name: "", enabled: true,
    text: "", position: "bottom", speed: 80,
    textColor: "#ffffff", bgColor: "#000000", bgOpacity: 70,
    fontFamily: "Inter", fontSize: 14, fontWeight: 600,
    italic: false, padding: 8,
    iconImage: ""
  };
}
function defaultBnItem() {
  return {
    id: adUid(), name: "", enabled: true,
    imageUrl: "", linkUrl: "",
    // Redirect saat klik tombol X: klik ke-1 → buka closeRedirect1Url di tab baru,
    // klik ke-2 → buka closeRedirect2Url di tab baru, klik ke-3 → banner hilang.
    // Kalau salah satu URL kosong, step itu di-skip (tetap pakai counter berikutnya).
    closeRedirect1Url: "", closeRedirect2Url: "",
    position: "bottom-right", showAfterSec: 3, closable: true,
    size: "medium", radius: 12, shadow: true, animation: "fade"
  };
}
function defaultPrItem() {
  return {
    id: adUid(), name: "", enabled: true,
    // mediaType: "video" | "image" — pre-roll bisa video atau gambar
    mediaType: "video",
    videoUrl: "", hasBlob: false,
    imageUrl: "",
    durationSec: 5,           // durasi tampil image (detik); video pakai durasi file-nya
    linkUrl: "",              // klik iklan → buka URL ini di tab baru (opsional)
    skippable: true, skipAfterSec: 5
  };
}

function defaultSbItem() {
  return {
    id: adUid(), name: "", enabled: true,
    badge: "", label: "",
    title: "", subtitle: "",
    ctaText: "Visit", ctaUrl: "",
    gradient: "blue",
    icon: "",
    imageUrl: ""
  };
}
function defaultSideBannerConfig() {
  // Format baru: array items (bisa banyak banner samping). Multi-item.
  return { rotation: "random", items: [] };
}
function defaultAdConfig() {
  return {
    runningText: { rotation: "random", items: [] },
    banner:      { rotation: "random", items: [] },
    preroll:     { rotation: "random", items: [] },
    sideBanner:  defaultSideBannerConfig()
  };
}

// Migrasi config lama (1 object per section) → format array.
// Juga isi field baru (font, size, animation, dll) ke item lama via merge default.
function migrateAdConfig(c) {
  function defaultsFor(type) {
    if (type === "rt") return defaultRtItem();
    if (type === "bn") return defaultBnItem();
    return defaultPrItem();
  }
  function fillDefaults(it, type) {
    const def = defaultsFor(type);
    // Default dulu, lalu timpa dengan value yang sudah ada di item.
    // ID asli & nama dipertahankan.
    return { ...def, ...it, id: it.id || def.id };
  }
  function asList(section, type) {
    if (Array.isArray(section?.items)) {
      return {
        rotation: section.rotation || "random",
        items: section.items.map(it => fillDefaults(it, type))
      };
    }
    if (section && typeof section === "object" && "enabled" in section) {
      const hasContent = type === "rt" ? !!section.text
                       : type === "bn" ? !!section.imageUrl
                       : !!(section.videoUrl || section.hasBlob);
      if (hasContent) {
        const base = defaultsFor(type);
        const item = { ...base, ...section, id: base.id, name: section.name || "Iklan #1" };
        return { rotation: "random", items: [item] };
      }
    }
    return { rotation: "random", items: [] };
  }
  // Side banner: support old single-object format → migrate to {rotation, items: [...]}
  function asSbList(section) {
    if (Array.isArray(section?.items)) {
      return {
        rotation: section.rotation || "random",
        items: section.items.map(it => ({ ...defaultSbItem(), ...it, id: it.id || adUid() }))
      };
    }
    // Old format: single object dengan field-field langsung. Migrate ke 1 item.
    if (section && typeof section === "object" && ("title" in section || "imageUrl" in section || "ctaUrl" in section)) {
      const hasContent = !!(section.title || section.imageUrl || section.ctaUrl);
      if (hasContent) {
        const base = defaultSbItem();
        const item = {
          ...base,
          enabled:  section.enabled ?? true,
          badge:    section.badge    || "",
          label:    section.label    || "",
          title:    section.title    || "",
          subtitle: section.subtitle || "",
          ctaText:  section.ctaText  || "Visit",
          ctaUrl:   section.ctaUrl   || "",
          gradient: section.gradient || "blue",
          icon:     section.icon     || "",
          imageUrl: section.imageUrl || "",
          name:     section.name     || "Banner Samping #1"
        };
        return { rotation: "random", items: [item] };
      }
    }
    return { rotation: "random", items: [] };
  }
  return {
    runningText: asList(c?.runningText, "rt"),
    banner:      asList(c?.banner,      "bn"),
    preroll:     asList(c?.preroll,     "pr"),
    sideBanner:  asSbList(c?.sideBanner)
  };
}

function getAdConfig() {
  try {
    const c = JSON.parse(localStorage.getItem(AD_CONFIG_KEY) || "null");
    if (!c) return defaultAdConfig();
    return migrateAdConfig(c);
  } catch { return defaultAdConfig(); }
}

function saveAdConfig(cfg) {
  try {
    localStorage.setItem(AD_CONFIG_KEY, JSON.stringify(cfg));
    window.dispatchEvent(new CustomEvent("playly:ads-updated"));
  } catch (e) {
    toast("⚠ Gagal menyimpan: storage penuh. Hapus banner besar atau pakai URL.", "error");
    throw e;
  }
}

// ----------------------- PURGE IKLAN DUMMY (clean-slate) -----------------------
// req user 2026-05-19: iklan dummy yang dulu ter-seed (commit 3d8061e) sudah
// terlanjur tertanam di localStorage & ter-propagate ke Supabase. Hardened
// opsi 3 (user): hanya hapus item yang nama-nya dummy DAN konten-nya cocok
// SIDIK-JARI seed (URL/teks unik) — iklan ASLI bernama sama (mis. "Playly
// Premium" tapi link/gambar sendiri) TIDAK tersentuh. SEKALI-JALAN: setelah
// pembersihan historis selesai (flag), purge tidak pernah menyentuh config
// lagi (load berikutnya & cloud-applied jadi no-op).
const AD_DUMMY_PURGE_FLAG = "playly-ad-dummy-purged-v2";
const AD_DUMMY_NAMES = new Set([
  "Promo Bulanan", "Follow Sosmed",
  "Playly Premium", "Sponsor BrandX",
  "Sponsor 15 detik", "Sponsor 15 detik (alt)",
  "Playly Premium SB", "Sponsor BrandX SB"
]);
// Substring unik milik SEED dummy (tidak akan ada di iklan asli admin
// kecuali kebetulan pakai URL/teks dummy yang sama persis).
const AD_DUMMY_FINGERPRINTS = [
  "playly.app/premium",
  "brandx.example.com",
  "commondatastorage.googleapis.com/gtv-videos-bucket/sample/",
  "Diskon 50% untuk Playly Premium",
  "@playlyofficial di Instagram",
  "Bebas iklan · Kualitas 4K · Upload tanpa batas.",
  "Solusi kreatif untuk konten video kamu.",
  "Dipersembahkan BrandX",
  "PROMO%20SPESIAL", "BrandX%20Studio"
];
function _isSeedDummyAd(it) {
  if (!it || !AD_DUMMY_NAMES.has(it.name || "")) return false;
  let blob = "";
  try { blob = JSON.stringify(it); } catch (_) { return false; }
  return AD_DUMMY_FINGERPRINTS.some(fp => blob.indexOf(fp) !== -1);
}
function purgeDummyAds() {
  try {
    if (localStorage.getItem(AD_DUMMY_PURGE_FLAG)) return; // sekali-jalan: sudah beres
    const raw = localStorage.getItem(AD_CONFIG_KEY);
    if (!raw) return;                                       // config belum ada → coba lagi load berikutnya
    const c = JSON.parse(raw);
    if (!c) { localStorage.setItem(AD_DUMMY_PURGE_FLAG, "1"); return; }
    let changed = false;
    ["runningText", "banner", "preroll", "sideBanner"].forEach(sec => {
      if (c[sec] && Array.isArray(c[sec].items)) {
        const before = c[sec].items.length;
        c[sec].items = c[sec].items.filter(it => !_isSeedDummyAd(it));
        if (c[sec].items.length !== before) changed = true;
      }
    });
    if (changed) {
      localStorage.setItem(AD_CONFIG_KEY, JSON.stringify(c));
      window.dispatchEvent(new CustomEvent("playly:ads-updated"));
      try { if (typeof refreshLiveAds === "function") refreshLiveAds(); } catch (_) {}
    }
    // Pembersihan historis selesai → jangan pernah sentuh config lagi.
    localStorage.setItem(AD_DUMMY_PURGE_FLAG, "1");
  } catch (_) {}
}
purgeDummyAds();
// cloud-applied: tetap dipasang, tapi self-gated via flag (sekali-jalan).
// Kalau cloud baru membawa config SEBELUM purge sempat jalan, ini yang
// menangkapnya; setelah flag set → no-op.
window.addEventListener("playly:cloud-applied", () => { try { purgeDummyAds(); } catch (_) {} });

// Konstanta seed iklan dummy (AD_SEED_FLAG, svgDataUri, DEMO_BANNER_*,
// seedDefaultAds) DIHAPUS TOTAL 2026-05-19 — sudah tidak dirujuk siapa
// pun. Pembersihan iklan dummy ditangani purgeDummyAds() di atas.

// SEED IKLAN DUMMY DIHAPUS TOTAL (req user 2026-05-19, prinsip
// clean-slate / no-dummy). Tidak ada lagi auto-inject iklan contoh
// per-browser maupun propagasi dummy via cloud-sync. Iklan hanya
// muncul kalau admin meng-set sendiri di halaman Kelola Iklan.

function adSection(cfg, type) {
  if (type === "rt") return cfg.runningText;
  if (type === "bn") return cfg.banner;
  if (type === "pr") return cfg.preroll;
  if (type === "sb") return cfg.sideBanner;
  return null;
}

function adItemHasContent(type, it) {
  if (type === "rt") return !!(it.text && it.text.trim());
  if (type === "bn") return !!it.imageUrl;
  if (type === "pr") {
    if (it.mediaType === "image") return !!it.imageUrl;
    return !!(it.videoUrl || it.hasBlob);
  }
  if (type === "sb") return !!(it.title || it.imageUrl || it.ctaUrl);
  return false;
}

// File helpers
function readImageFileAsDataURL(file, maxSize = Infinity) {
  return new Promise((resolve, reject) => {
    if (!file) return reject(new Error("No file"));
    if (maxSize !== Infinity && file.size > maxSize) {
      const mb = Math.round(maxSize / (1024 * 1024));
      return reject(new Error(`File terlalu besar (max ${mb}MB)`));
    }
    const r = new FileReader();
    r.onload = () => resolve(r.result);
    r.onerror = () => reject(r.error);
    r.readAsDataURL(file);
  });
}
async function savePrerollItemBlob(id, file) {
  // File size limit dihapus per request 2026-05-03.
  await saveVideoBlob(prerollBlobId(id), file);
}
async function getPrerollItemBlobUrl(id) {
  const blob = await getVideoBlob(prerollBlobId(id));
  return blob ? URL.createObjectURL(blob) : null;
}
async function deletePrerollBlob(id) {
  try {
    const db = await openVideoDB();
    const tx = db.transaction(VIDEO_STORE, "readwrite");
    tx.objectStore(VIDEO_STORE).delete(prerollBlobId(id));
  } catch {}
}

// ----------- Render -----------
function loadAdManagerForm() {
  if (!$("#adRtList")) return;
  const cfg = getAdConfig();
  if ($("#adRtRotation")) $("#adRtRotation").value = cfg.runningText.rotation;
  if ($("#adBnRotation")) $("#adBnRotation").value = cfg.banner.rotation;
  if ($("#adPrRotation")) $("#adPrRotation").value = cfg.preroll.rotation;
  if ($("#adSbRotation")) $("#adSbRotation").value = (cfg.sideBanner?.rotation) || "random";
  renderAdItems("rt");
  renderAdItems("bn");
  renderAdItems("pr");
  if ($("#adSbList")) renderAdItems("sb");
}

/* === Side Banner form bindings (admin Ad Manager) === */
function loadSideBannerForm() {
  const cfg = getAdConfig();
  const sb = cfg.sideBanner || defaultSideBannerConfig();
  const setVal = (id, v) => { const el = $(`#${id}`); if (el && el.value !== v) el.value = v ?? ""; };
  const setChk = (id, v) => { const el = $(`#${id}`); if (el) el.checked = !!v; };
  setChk("adSbEnabled", sb.enabled);
  setVal("adSbBadge", sb.badge);
  setVal("adSbLabel", sb.label);
  setVal("adSbTitle", sb.title);
  setVal("adSbSubtitle", sb.subtitle);
  setVal("adSbCtaText", sb.ctaText);
  setVal("adSbCtaUrl", sb.ctaUrl);
  setVal("adSbGradient", sb.gradient || "blue");
  setVal("adSbIcon", sb.icon);
  updateSideBannerPreview();
}
function updateSideBannerPreview() {
  const sb = (getAdConfig().sideBanner) || defaultSideBannerConfig();
  const grad = ($("#adSbGradient")?.value) || sb.gradient || "blue";
  const set = (id, txt) => { const el = $(`#${id}`); if (el) el.textContent = txt || "—"; };
  set("adSbPrevBadge",    $("#adSbBadge")?.value    || sb.badge);
  set("adSbPrevLabel",    $("#adSbLabel")?.value    || sb.label);
  set("adSbPrevTitle",    $("#adSbTitle")?.value    || sb.title);
  set("adSbPrevSubtitle", $("#adSbSubtitle")?.value || sb.subtitle);
  set("adSbPrevCta",      $("#adSbCtaText")?.value  || sb.ctaText);
  const banner = document.querySelector("#adSbPreview .ps-ad-hero-banner");
  if (banner) banner.dataset.grad = grad;
  const iconWrap = $("#adSbPrevIcon");
  if (iconWrap) {
    const emoji = ($("#adSbIcon")?.value || sb.icon || "").trim();
    if (emoji) iconWrap.innerHTML = `<span style="font-size:18px">${escapeHtml(emoji)}</span>`;
    else iconWrap.innerHTML = `<svg viewBox="0 0 24 24" fill="currentColor"><path d="M3 11h18l-9-9-9 9zm0 2v8h18v-8l-9 9-9-9z"/></svg>`;
  }
}
function bindSideBannerForm() {
  if (!$("#adSbBadge")) return;
  loadSideBannerForm();
  const persist = () => {
    const cfg = getAdConfig();
    const prev = cfg.sideBanner || {};
    cfg.sideBanner = {
      enabled:  $("#adSbEnabled")?.checked ?? true,
      badge:    ($("#adSbBadge")?.value    || "").trim(),
      label:    ($("#adSbLabel")?.value    || "").trim(),
      title:    ($("#adSbTitle")?.value    || "").trim(),
      subtitle: ($("#adSbSubtitle")?.value || "").trim(),
      ctaText:  ($("#adSbCtaText")?.value  || "").trim(),
      ctaUrl:   ($("#adSbCtaUrl")?.value   || "").trim(),
      gradient: ($("#adSbGradient")?.value || "blue"),
      icon:     ($("#adSbIcon")?.value     || "").trim(),
      imageUrl: prev.imageUrl || ""
    };
    saveAdConfig(cfg);
    updateSideBannerPreview();
    if (typeof renderUserPlayerSideBanner === "function") renderUserPlayerSideBanner();
  };
  ["adSbEnabled", "adSbBadge", "adSbLabel", "adSbTitle", "adSbSubtitle", "adSbCtaText", "adSbCtaUrl", "adSbGradient", "adSbIcon"].forEach(id => {
    const el = $(`#${id}`);
    if (!el) return;
    el.addEventListener("input", persist);
    el.addEventListener("change", persist);
  });

  // Collapsible head — match pattern ad-item (rt/bn/pr): collapsed by default,
  // klik head atau tombol toggle → expand body editor. Klik di area kontrol
  // (checkbox Aktif) jangan ikut toggle.
  const sbCard = document.querySelector('.ad-section[data-ad-type="sb"]');
  const sbHead = $("#adSbToggleHead");
  const sbBody = $("#adSbBody");
  const sbToggleBtn = $("#adSbToggle");
  if (sbCard && sbHead && sbBody) {
    const setCollapsed = (collapsed) => {
      sbCard.classList.toggle("ad-sb-collapsed", collapsed);
      sbBody.hidden = collapsed;
      if (sbToggleBtn) sbToggleBtn.setAttribute("aria-expanded", String(!collapsed));
    };
    sbHead.addEventListener("click", e => {
      // Jangan toggle saat klik di kontrol header (checkbox Aktif, label-nya)
      if (e.target.closest(".ad-section-controls")) return;
      setCollapsed(!sbCard.classList.contains("ad-sb-collapsed"));
    });
  }

  // Side Banner image dropzone (drag-drop + hover overlay)
  const dz = $("#adSbImageDz");
  const input = $("#adSbImageInput");
  const preview = $("#adSbImagePreview");
  const replaceBtn = $("#adSbImageReplace");
  const removeBtn = $("#adSbImageRemove");
  if (dz && input) {
    // Hydrate from saved config
    const sb = (getAdConfig().sideBanner) || defaultSideBannerConfig();
    if (sb.imageUrl) {
      preview.src = sb.imageUrl;
      dz.dataset.state = "filled";
    }
    const persistImage = (url) => {
      const cfg = getAdConfig();
      cfg.sideBanner = { ...(cfg.sideBanner || defaultSideBannerConfig()), imageUrl: url || "" };
      saveAdConfig(cfg);
      if (typeof renderUserPlayerSideBanner === "function") renderUserPlayerSideBanner();
    };
    const setFilled = (dataUrl) => {
      preview.src = dataUrl;
      dz.dataset.state = "filled";
      persistImage(dataUrl);
    };
    const setEmpty = () => {
      input.value = "";
      preview.removeAttribute("src");
      dz.dataset.state = "empty";
      persistImage("");
    };
    const pick = async (file) => {
      if (!file) return;
      if (!/^image\//.test(file.type)) return toast("⚠️ File harus gambar (JPG/PNG/WebP)", "warning");
      try {
        const dataUrl = await readImageFileAsDataURL(file);
        setFilled(dataUrl);
        toast(`✓ Banner image di-upload (${Math.round(file.size/1024)} KB)`, "success");
      } catch (err) { toast(`❌ ${err.message}`, "error"); }
    };
    input.addEventListener("change", () => pick(input.files?.[0]));
    ["dragenter", "dragover"].forEach(ev =>
      dz.addEventListener(ev, e => { e.preventDefault(); dz.classList.add("is-dragging"); })
    );
    ["dragleave", "drop"].forEach(ev =>
      dz.addEventListener(ev, e => { e.preventDefault(); dz.classList.remove("is-dragging"); })
    );
    dz.addEventListener("drop", e => {
      const f = e.dataTransfer.files?.[0];
      if (f && f.type.startsWith("image/")) pick(f);
    });
    dz.addEventListener("click", e => {
      if (e.target.closest(".dz-pro-action")) return;
      if (dz.dataset.state === "filled") { e.preventDefault(); }
    });
    replaceBtn?.addEventListener("click", e => {
      e.preventDefault(); e.stopPropagation();
      input.click();
    });
    removeBtn?.addEventListener("click", e => {
      e.preventDefault(); e.stopPropagation();
      setEmpty();
    });
  }
}

/* Render admin-controlled Side Banner in user's player sidebar.
   Multi-item: pick first enabled item with content (random pick kalau rotation = random). */
function renderUserPlayerSideBanner() {
  const heroAd = document.querySelector("#playerSidebar .ps-ad-hero");
  if (!heroAd) return;
  // Premium users → AD-FREE viewing (sejajar dgn applyAdOverlays).
  if (user?.tier === "premium") { heroAd.hidden = true; return; }
  const sbCfg = getAdConfig().sideBanner || defaultSideBannerConfig();
  const items = (sbCfg.items || []).filter(it => it.enabled && adItemHasContent("sb", it));
  if (!items.length) { heroAd.hidden = true; return; }
  // Rotation: random pick once per render; sequential = first item.
  const sb = (sbCfg.rotation === "sequential") ? items[0] : items[Math.floor(Math.random() * items.length)];
  heroAd.hidden = false;
  const banner = heroAd.querySelector(".ps-ad-hero-banner");
  if (banner) banner.dataset.grad = sb.gradient || "blue";
  const set = (sel, txt) => { const el = heroAd.querySelector(sel); if (el) el.textContent = txt; };
  set(".ps-ad-hero-percent", sb.badge || "");
  set(".ps-ad-hero-tag", sb.label || "");
  set(".ps-ad-text strong", sb.title || "");
  set(".ps-ad-text small", sb.subtitle || "");
  const cta = heroAd.querySelector(".ps-ad-cta");
  if (cta) {
    cta.textContent = sb.ctaText || "Visit";
    cta.onclick = () => { if (sb.ctaUrl) window.open(sb.ctaUrl, "_blank", "noopener"); };
  }
  // Image override (kalau ada): set as background, hide text overlay tetap normal
  if (banner) {
    if (sb.imageUrl) {
      banner.style.backgroundImage = `url("${sb.imageUrl.replace(/"/g, '\\"')}")`;
      banner.style.backgroundSize = "cover";
      banner.style.backgroundPosition = "center";
    } else {
      banner.style.backgroundImage = "";
    }
  }
  const iconWrap = heroAd.querySelector(".ps-ad-icon");
  if (iconWrap) {
    if (sb.icon) iconWrap.innerHTML = `<span style="font-size:18px">${escapeHtml(sb.icon)}</span>`;
    else iconWrap.innerHTML = `<svg viewBox="0 0 24 24" fill="currentColor"><path d="M3 11h18l-9-9-9 9zm0 2v8h18v-8l-9 9-9-9z"/></svg>`;
  }
}

function renderAdItems(type) {
  const list = $(`#ad${adCap(type)}List`);
  const empty = $(`#ad${adCap(type)}Empty`);
  const count = $(`#ad${adCap(type)}Count`);
  if (!list) return;
  const cfg = getAdConfig();
  const items = adSection(cfg, type).items;
  list.innerHTML = "";
  if (count) count.textContent = items.length;
  if (!items.length) { if (empty) empty.hidden = false; return; }
  if (empty) empty.hidden = true;
  items.forEach((it, idx) => list.appendChild(renderAdItemCard(type, it, idx)));
}

function renderAdItemCard(type, item, idx) {
  const div = document.createElement("div");
  div.className = "ad-item";
  div.dataset.type = type;
  div.dataset.id = item.id;
  if (type === "pr") div.dataset.mediaType = item.mediaType === "image" ? "image" : "video";
  if (!item.enabled) div.classList.add("disabled");
  const placeholder = type === "rt" ? "Misal: Promo Liburan" : type === "bn" ? "Misal: Banner 18Toto" : "Misal: Pre-roll Sponsor A";
  div.innerHTML = `
    <div class="ad-item-head">
      <button type="button" class="ad-item-toggle" title="Expand">▸</button>
      <span class="ad-item-num">#${idx + 1}</span>
      <input class="ad-item-name" type="text" value="${escapeHtml(item.name || "")}" placeholder="${placeholder}" data-field="name"/>
      <span class="ad-item-summary muted">${adItemSummary(type, item)}</span>
      <label class="ad-toggle ad-toggle-mini" title="${item.enabled ? "Aktif" : "Nonaktif"}">
        <input type="checkbox" class="ad-item-enabled" data-field="enabled" ${item.enabled ? "checked" : ""}/>
        <span class="ad-toggle-track"><span class="ad-toggle-thumb"></span></span>
      </label>
      <button type="button" class="ad-item-del icon-btn-tiny" title="Hapus iklan">🗑</button>
    </div>
    <div class="ad-item-body" hidden>${adItemFormHtml(type, item)}</div>
  `;
  return div;
}

function adItemSummary(type, it) {
  if (type === "rt") {
    const t = (it.text || "").slice(0, 50);
    if (!t) return "<i>belum ada teks</i>";
    return `"${escapeHtml(t)}${it.text.length > 50 ? "…" : ""}" • ${it.position} • ${it.speed}px/dtk`;
  }
  if (type === "bn") {
    if (!it.imageUrl) return "<i>belum ada gambar</i>";
    const src = it.imageUrl.startsWith("data:") ? "📁 file" : "🔗 URL";
    return `${src} • ${it.position} • after ${it.showAfterSec}s`;
  }
  if (type === "sb") {
    if (!it.title && !it.imageUrl) return "<i>belum ada konten</i>";
    const grad = it.gradient || "blue";
    const ctaTxt = (it.ctaText || "").trim();
    const titleTxt = (it.title || "").slice(0, 30);
    const img = it.imageUrl ? "🖼 img • " : "";
    return `${img}${escapeHtml(titleTxt)}${(it.title || "").length > 30 ? "…" : ""} • ${grad}${ctaTxt ? ` • ${escapeHtml(ctaTxt)}` : ""}`;
  }
  if (type === "pr") {
    const isImg = it.mediaType === "image";
    if (isImg) {
      if (!it.imageUrl) return "<i>belum ada gambar</i>";
      const src = it.imageUrl.startsWith("data:") ? "📁 file" : "🔗 URL";
      return `🖼️ ${src}`;
    }
    const linkBadge = it.linkUrl ? " • 🔗 klik" : "";
    if (it.hasBlob) return `🎬 📁 video tersimpan • skip ${it.skipAfterSec}s${linkBadge}`;
    if (it.videoUrl) return `🎬 🔗 URL • skip ${it.skipAfterSec}s${linkBadge}`;
    return "<i>belum ada video</i>";
  }
  return "";
}

// Sync inline-style preview di running text item saat field berubah
function refreshRtPreview(itemEl, id) {
  const cfg = getAdConfig();
  const it = cfg.runningText.items.find(x => x.id === id);
  if (!it) return;
  const box = itemEl.querySelector(".ad-rt-preview-box");
  if (!box) return;
  box.style.background = hexToRgba(it.bgColor || "#000", (it.bgOpacity || 70) / 100);
  box.style.color = it.textColor || "#fff";
  box.style.fontFamily = `${it.fontFamily || "Inter"}, sans-serif`;
  box.style.fontSize = `${it.fontSize || 14}px`;
  box.style.fontWeight = it.fontWeight || 600;
  box.style.fontStyle = it.italic ? "italic" : "normal";
  box.style.padding = `${it.padding != null ? it.padding : 8}px 12px`;
  box.textContent = it.text || "Pesan iklan akan tampil seperti ini.";
}

