// Live sync untuk USER (non-admin): kalau admin mengirim pesan dari tab lain,
// inbox user di tab ini ikut ter-update tanpa reload.
function setupUserMessageSync() {
  if (window.__userMsgSyncBound) return;
  window.__userMsgSyncBound = true;
  // Catat pesan terakhir per-thread supaya toast cuma fire untuk pesan benar-benar baru
  // (bukan thread lama yang masih unread).
  let lastSeenByThread = new Map();
  window.addEventListener("storage", e => {
    if (!user || !e.key || e.key !== `playly-state-${user.username}`) return;
    let fresh; try { fresh = JSON.parse(e.newValue || "null"); } catch { return; }
    if (!fresh) return;
    if (Array.isArray(fresh.messages)) {
      state.messages = fresh.messages;
      if (typeof renderMsgList === "function") renderMsgList();
      // Refresh badge & Pusat Komunikasi kalau admin lagi melihatnya
      if (typeof syncAdminNavBadges === "function") syncAdminNavBadges();
      if (state?.currentView === "admin-comms" && typeof renderAdminComms === "function") {
        renderAdminComms();
      }
      // Refresh kolom Live Chat di Inbox kalau admin lagi melihatnya
      if (state?.currentView === "admin-inbox" && typeof renderAdminInbox === "function") {
        renderAdminInbox();
      }
      // Cek tiap thread unread, fire toast hanya kalau pesan terbaru di thread itu BERBEDA
      // dari yang sudah pernah kita lihat (mencegah spam toast).
      const isAdmin = user.role === "admin";
      for (const m of fresh.messages) {
        if (!m.unread || !Array.isArray(m.history) || !m.history.length) continue;
        const last = m.history[m.history.length - 1];
        if (!last || last.from !== "them") continue;
        const sig = `${m.name}:${m.history.length}:${(last.text || "").slice(0, 60)}`;
        if (lastSeenByThread.get(m.name) === sig) continue;
        lastSeenByThread.set(m.name, sig);
        const label = m.isAdmin ? "Admin" : (isAdmin ? "User" : "Kreator");
        toast(`📨 Pesan baru dari <b>@${escapeHtml(m.name)}</b> (${label})`, "info");
      }
    }
    // Notifikasi dari user lain (like / comment / follow) — sync agar lonceng
    // di topbar dan panel notifikasi langsung update.
    if (Array.isArray(fresh.notifications)) {
      const prevTopId = state.notifications?.[0]?.id;
      state.notifications = fresh.notifications;
      if (typeof renderNotifications === "function") renderNotifications();
      // Re-render home notif widget supaya real-time (per request 2026-05-03 fix bug)
      if (typeof renderHomeNotifLatest === "function") renderHomeNotifLatest();
    renderHomeTierWidget();
      // Toast cuma kalau notifikasi baru benar-benar masuk (id paling atas berubah)
      const newest = fresh.notifications[0];
      if (newest && newest.id !== prevTopId && newest.unread) {
        const plain = String(newest.text || "").replace(/<[^>]*>/g, "");
        toast(`🔔 ${plain}`, "info");
      }
    }
  });
}
setupUserMessageSync();

// Cross-tab sync untuk user non-admin: kalau admin update Ad Manager dari
// tab lain, ad config di tab ini ikut refresh kalau dibutuhkan.
// (Tidak ada lagi global banner — banner hanya muncul di dalam player.)
function setupAdConfigCrossTabSync() {
  if (window.__adConfigSyncBound) return;
  window.__adConfigSyncBound = true;
  const refreshLiveAds = () => {
    // Bersihkan overlay sisa lama
    document.getElementById("globalBannerOverlay")?.remove();
    // Refresh side banner di full player sidebar (kalau lagi terbuka)
    if (typeof renderUserPlayerSideBanner === "function") {
      try { renderUserPlayerSideBanner(); } catch {}
    }
    // Re-apply 4 jenis iklan ke setiap surface video yang lagi attached
    document.querySelectorAll(".player-screen video, .lib-inline-screen video").forEach(v => {
      if (!v.isConnected) return;
      try { applyAdOverlays(v); } catch {}
    });
  };
  // Cross-tab (browser yang sama)
  window.addEventListener("storage", e => {
    if (e.key !== AD_CONFIG_KEY) return;
    refreshLiveAds();
  });
  // Cross-device via Supabase cloud-sync
  window.addEventListener("playly:cloud-applied", e => {
    const keys = e.detail?.keys || [];
    if (keys.includes(AD_CONFIG_KEY)) refreshLiveAds();
  });
  // Same-tab signal (dispatched dari saveAdConfig)
  window.addEventListener("playly:ads-updated", refreshLiveAds);
}
setupAdConfigCrossTabSync();

// Cross-tab sync: when admin acts in one tab, other tabs update too.
function setupAdminCrossTabSync() {
  if (window.__adminSyncBound) return;
  window.__adminSyncBound = true;
  const handleKey = (key) => {
    if (!key || document.body.dataset.role !== "admin") return;
    if (key === ADMIN_KEYS.events) {
      renderAdminLiveFeed();
      if (state?.currentView === "admin-audit") renderAdminAudit();
    }
    if (key === ADMIN_KEYS.mod) { renderAdminModeration(); renderAdminAlerts(); renderAdminActionCenter(); syncAdminNavBadges(); }
    if (key === ADMIN_KEYS.tickets) { renderAdminTickets(); renderAdminInbox(); renderAdminAlerts(); renderAdminActionCenter(); syncAdminNavBadges(); }
    if (key === ADMIN_KEYS.bugs) { renderAdminBugs(); renderAdminInbox(); renderAdminAlerts(); renderAdminActionCenter(); syncAdminNavBadges(); }
    if (key.startsWith("playly-account-") || key.startsWith("playly-state-")) {
      renderAdminKPI(); renderAdminUsers(); renderAdminAlerts();
      if (state?.currentView === "admin-videos") renderAdminVideos();
      else syncAdminNavBadges();
      // Refresh Pusat Komunikasi kalau lagi dibuka — DM atau broadcast log berubah
      if (state?.currentView === "admin-comms") renderAdminComms();
    }
    if (key === "playly-admin-sent" && state?.currentView === "admin-comms") {
      renderAdminComms();
    }
    if (key === REVENUE_LEDGER_KEY && state?.currentView === "admin-revenue") {
      tickRevenue();
    }
  };
  // Cross-tab (browser yang sama)
  window.addEventListener("storage", e => handleKey(e.key));
  // Cross-device: cloud-sync apply data dari Supabase → dispatch event ini
  window.addEventListener("playly:cloud-applied", e => {
    const keys = e.detail?.keys || [];
    keys.forEach(handleKey);
  });
}

// Badge sidebar dimatikan total — user minta menu bersih tanpa indikator
// number/dot di sidebar. Counter aktivitas baru tetap ada di dalam view
// (Inbox, Audit Log, KPI, dll) supaya tidak duplikat dengan sidebar.
// C-3 V-M3 fix (2026-05-21): signature mismatch. Sebelumnya hanya terima
// `el` (1 arg) tapi callers pass `(el, count, hasItems)` (3 args). Body
// hide-semua → sidebar badges utk users/inbox/videos/comms/audit selalu
// kosong meskipun ada data. Sekarang implement properly:
//   - count > 0 → tampilkan angka
//   - count === 0 && hasItems → tampilkan dot (glow indicator)
//   - count === 0 && !hasItems → hide
function setBadgeMode(el, count, hasItems) {
  if (!el) return;
  el.className = el.className.replace(/\bglow-dot\b/g, "").trim();
  const n = Number(count) || 0;
  if (n > 0) {
    el.textContent = n > 99 ? "99+" : String(n);
    el.style.display = "";
  } else if (hasItems) {
    el.textContent = "";
    el.style.display = "";
    el.className = (el.className + " glow-dot").trim();
  } else {
    el.textContent = "";
    el.style.display = "none";
  }
}

function syncAdminNavBadges() {
  const m = getAdminMetrics();
  // User Management: new users 24h → number; ada akun → dot; kosong → hidden
  setBadgeMode($("#adminUserBadge"), m.newUsers24h, m.accounts.length > 0);
  const mb = $("#adminModBadge"); if (mb) { mb.textContent = m.mod; mb.style.display = m.mod ? "" : "none"; }
  const tb = $("#adminTicketBadge"); if (tb) { tb.textContent = m.tickets; tb.style.display = m.tickets ? "" : "none"; }
  // Inbox: tiket new + bug open → number; ada tiket/bug apapun → dot; kosong → hidden
  const allTickets = getAdminData("tickets") || [];
  const allBugs = getAdminData("bugs") || [];
  const openBugs = allBugs.filter(b => b.status === "open" || !b.status).length;
  setBadgeMode($("#adminInboxBadge"), (m.tickets || 0) + openBugs, allTickets.length + allBugs.length > 0);
  // Content Control: pending videos → number; ada video di platform → dot; kosong → hidden
  setBadgeMode($("#adminVideoBadge"), countAdminPendingVideos(), (m.videos || 0) > 0);
  // Conversation: thread unread → number; ada thread → dot; kosong → hidden
  const threads = Array.isArray(state?.messages) ? state.messages : [];
  const unreadThreads = threads.filter(t => t.unread).length;
  setBadgeMode($("#adminCommsBadge"), unreadThreads, threads.length > 0);
  // Audit Log: event hari ini → number; pernah ada event → dot; kosong → hidden
  const events = getAdminData("events") || [];
  const startOfDay = new Date(); startOfDay.setHours(0, 0, 0, 0);
  const todayEvents = events.filter(e => Number(e.ts) >= startOfDay.getTime()).length;
  setBadgeMode($("#adminAuditBadge"), todayEvents, events.length > 0);
}

function setKPI(el, val) {
  if (!el) return;
  if (el.textContent !== val) {
    el.textContent = val;
    el.classList.remove("kpi-flash");
    void el.offsetWidth;
    el.classList.add("kpi-flash");
  }
}

function renderAdminKPI() {
  const m = getAdminMetrics();
  // Total Pengguna = user only (admin di-exclude — admin punya tab sendiri di User Management)
  const userCount = (m.userAccounts || []).length;
  setKPI($("#kpiUsers"), fmtNum(userCount));
  setKPI($("#kpiVideos"), fmtNum(m.videos.length));
  setKPI($("#kpiViews"), fmtNum(m.totalViews));
  setKPI($("#kpiRevenue"), fmtIDR(m.revenue));
  // Count-up animation on numeric KPIs (after setKPI sets initial value + flash)
  setTimeout(() => {
    countUp($("#kpiUsers"),  userCount,            fmtNum);
    countUp($("#kpiVideos"), m.videos.length,      fmtNum);
    countUp($("#kpiViews"),  m.totalViews,         fmtNum);
  }, 120);

  // Tren Total Pengguna → format PERSEN, konsisten dgn kartu lain
  // (↑ X%), bukan "N baru 24j". (req user 2026-05-19). Hitung % real:
  // kontribusi user baru 24 jam terhadap total user.
  const trendEls = $$(".admin-kpi-card .kpi-trend");
  const usersPct = userCount > 0
    ? Math.round((m.newUsers24h / userCount) * 1000) / 10
    : 0;
  if (trendEls[0]) trendEls[0].textContent = `↑ ${usersPct}%`;

  // Avatar-stack melayang dihapus (req user 2026-05-19) — avatar
  // sekarang di DALAM row daftar, pakai profil user masing-masing.

  // (Sparkline opsi A dihapus 2026-05-19 — user pilih opsi B+D.)

  // Baris sub-statistik per kartu KPI (req user 2026-05-19, opsi B) —
  // breakdown ringkas data REAL, mengisi kartu secara vertikal.
  try {
    const fmt = typeof fmtNum === "function" ? fmtNum : (n => String(n));
    const ua = m.userAccounts || [];
    const premium = ua.filter(a => (a && (a.tier || a.plan)) === "premium").length;
    const vids = m.videos || [];
    const DAY = 86400000, now = Date.now();
    const vTime = v => {
      const t = v && (v.createdAt || v.uploadedAt || v.publishedAt || v.date || v.ts);
      return t ? new Date(t).getTime() : 0;
    };
    const newVid24 = vids.filter(v => { const t = vTime(v); return t > 0 && t >= now - DAY; }).length;
    const avgViews = vids.length ? Math.round((m.totalViews || 0) / vids.length) : 0;
    const subU = document.getElementById("kpiSubUsers");
    const subV = document.getElementById("kpiSubVideos");
    const subW = document.getElementById("kpiSubViews");
    if (subU) subU.textContent = `${m.newUsers24h || 0} baru 24 jam · ${premium} premium`;
    if (subV) subV.textContent = `${newVid24} baru 24 jam · ${m.mod || 0} perlu moderasi`;
    if (subW) subW.textContent = `Ø ${fmt(avgViews)}/video · ${fmt(vids.length)} video`;
    // Kartu ke-4 Pendapatan (opsi D): angka ringkas + sub breakdown REAL
    const subR = document.getElementById("kpiSubRevenue");
    const revEl = document.getElementById("kpiRevenue");
    if (subR || revEl) {
      const rpS = typeof fmtRpShort === "function" ? fmtRpShort
                : (typeof fmtRp === "function" ? fmtRp : (n => "Rp " + fmt(n)));
      let rv = { total: m.revenue || 0, today: 0, rate: 0 };
      try { if (typeof computeRevenueFromLedger === "function") rv = computeRevenueFromLedger(); } catch (_) {}
      if (revEl) revEl.textContent = rpS(rv.total || 0);
      if (subR)  subR.textContent  = `${rpS(rv.today || 0)} hari ini · ${rpS(rv.rate || 0)}/mnt`;
    }
  } catch (_) {}

  // Ringkasan PENDAPATAN di beranda (req user 2026-05-18) — data REAL sama
  // dgn halaman Pendapatan (computeRevenueFromLedger). Dipanggil tiap render
  // KPI (nav + live-refresh loop) jadi tetap sinkron.
  try {
    if ($("#dashRevTotal") && typeof computeRevenueFromLedger === "function") {
      const rv = computeRevenueFromLedger();
      const rp = typeof fmtRp === "function" ? fmtRp : (n => "Rp " + fmtNum(n));
      $("#dashRevTotal").textContent = rp(rv.total || 0);
      $("#dashRevToday").textContent = rp(rv.today || 0);
      $("#dashRevRate").textContent  = `${rp(rv.rate || 0)}/menit`;
    }
  } catch (_) {}
}

/* ---------- Komunitas Aktif avatar stack (user home) ---------- */
function renderUserCommunityStack() {
  const wrap = document.querySelector("#userCommunityStack");
  if (!wrap) return;
  let creators = [];
  try {
    creators = (typeof getPlatformCreators === "function" ? getPlatformCreators({ activeOnly: true }) : []) || [];
  } catch { creators = []; }
  // Sort by latest upload (paling baru aktif di atas), fallback ke videoCount
  creators.sort((a, b) => (b.latestUploadAt || 0) - (a.latestUploadAt || 0) || (b.videoCount || 0) - (a.videoCount || 0));
  const total = creators.length;

  // Update subtitle dengan jumlah real
  const sub = document.getElementById("communitySubtitle");
  if (sub) sub.textContent = total > 0
    ? `${total} active creators on Playly`
    : "No other creators yet — be the first to upload!";

  // Tandai stack ini sebagai komunitas (bukan admin) supaya CSS bisa kasih ukuran beda
  wrap.classList.add("community-stack");

  if (!total) { wrap.innerHTML = ""; return; }
  // Tampilkan lebih banyak (max 12) supaya kolom terisi rapi & tidak banyak
  // ruang kosong. Sebelumnya cuma 5 → kolom kelihatan sepi.
  const VISIBLE = 12;
  const items = creators.slice(0, VISIBLE).map(c => ({
    label: c.displayName || c.name || "U",
    username: c.name,                        // ← dipakai untuk klik → profil
    avatar: c.avatar || null
  }));
  const more = Math.max(0, total - items.length);
  const html = items.map(it => {
    const init = String(it.label || "U")
      .split(/\s+/).map(s => s[0]).slice(0, 2).join("").toUpperCase() || "U";
    const handle = escapeHtml(it.username || "");
    const tooltip = `${escapeHtml(it.label)} (@${handle}) — buka profil`;
    if (it.avatar) {
      return `<button type="button" class="ast-item ast-clickable" data-community-user="${handle}" title="${tooltip}" aria-label="${tooltip}"><img src="${escapeHtml(it.avatar)}" alt=""/></button>`;
    }
    return `<button type="button" class="ast-item ast-clickable" data-community-user="${handle}" title="${tooltip}" aria-label="${tooltip}">${escapeHtml(init)}</button>`;
  }).join("");
  // "+N" lingkaran dipindah dari mid-stack ke tombol "more>" di pojok kanan-bawah
  // (hilang dari avatar stack supaya layout konsisten dgn Spotlight Kreator).
  wrap.innerHTML = html;
  // Update tombol "more>" jumlah remaining biar visible & informative
  const moreBtn = wrap.parentElement?.querySelector('.community-more-wrap .people-more-btn span');
  if (moreBtn) moreBtn.textContent = more > 0 ? `more (+${more})` : "more";

  // Klik avatar → buka profil user terkait. Klik "+N more" → halaman Search User.
  // stopPropagation supaya tidak ikut trigger handler `.community-card[data-jump]`
  // di parent (yang lompat ke discover).
  wrap.querySelectorAll("[data-community-user]").forEach(btn => {
    btn.addEventListener("click", e => {
      e.stopPropagation();
      const uname = btn.dataset.communityUser;
      if (uname && typeof openUserProfile === "function") openUserProfile(uname);
    });
  });
  wrap.querySelectorAll("[data-community-more]").forEach(btn => {
    btn.addEventListener("click", e => {
      e.stopPropagation();
      if (typeof switchView === "function") switchView("people");
    });
  });
}

/* ---------- Avatar stacks (recent videos / users / top creators) ---------- */
function renderAdminAvatarStacks(m) {
  const accounts = m.accounts || [];
  const videos = m.videos || [];

  // Recent videos — 5 video terbaru, ambil avatar dari kreator
  const recentVids = [...videos].sort((a, b) => (b.uploadedAt || b.ts || 0) - (a.uploadedAt || a.ts || 0)).slice(0, 5);
  _renderAvatarStack("#adminRecentVideosStack", recentVids.map(v => ({
    label: (v.creator || "U"),
    avatar: _findAvatarByUsername(v.creator, accounts)
  })), videos.length);

  // Recent users — 5 user terbaru (exclude admin)
  const userAccounts = accounts.filter(a => a.role !== "admin");
  const recentUsers = [...userAccounts].sort((a, b) => new Date(b.joinedAt || 0) - new Date(a.joinedAt || 0)).slice(0, 5);
  _renderAvatarStack("#adminRecentUsersStack", recentUsers.map(a => ({
    label: a.name || a.username || "U",
    avatar: a.avatar
  })), userAccounts.length);

  // Top creators — by total views
  const creatorMap = {};
  videos.forEach(v => {
    if (!v.creator) return;
    creatorMap[v.creator] = creatorMap[v.creator] || { name: v.creator, views: 0 };
    creatorMap[v.creator].views += v.viewsNum || 0;
  });
  const topCreators = Object.values(creatorMap).sort((a, b) => b.views - a.views).slice(0, 5);
  _renderAvatarStack("#adminTopCreatorsStack", topCreators.map(c => ({
    label: c.name,
    avatar: _findAvatarByUsername(c.name, accounts)
  })), Object.keys(creatorMap).length);
}

function _findAvatarByUsername(uname, accounts) {
  if (!uname || !accounts) return null;
  const a = accounts.find(x => String(x.username || "").toLowerCase() === String(uname).toLowerCase());
  return a?.avatar || null;
}

function _renderAvatarStack(selector, items, total) {
  const wrap = document.querySelector(selector);
  if (!wrap) return;
  if (!items.length) { wrap.innerHTML = ""; return; }
  const visible = items.slice(0, 4);
  const more = Math.max(0, total - visible.length);
  const html = visible.map(it => {
    const init = String(it.label || "U")
      .split(/\s+/).map(s => s[0]).slice(0, 2).join("").toUpperCase() || "U";
    if (it.avatar) {
      return `<div class="ast-item"><img src="${escapeHtml(it.avatar)}" alt=""/></div>`;
    }
    return `<div class="ast-item">${escapeHtml(init)}</div>`;
  }).join("") + (more > 0 ? `<div class="ast-item ast-more">+${more}</div>` : "");
  wrap.innerHTML = html;
}

// Infer view-jump dari teks/icon event admin (untuk live feed di notif panel)
function inferAdminEventJump(e) {
  const t = (e?.text || "").toLowerCase();
  const ico = e?.ico || "";
  if (ico === "🐛" || /\bbug\b/.test(t)) return "admin-inbox";
  if (ico === "📧" || ico === "🎫" || /\b(tiket|email|inbox|pesan baru di inbox)\b/.test(t)) return "admin-inbox";
  if (ico === "💬" || /\b(chat|live chat|pesan dari)\b/.test(t)) return "admin-inbox";
  if (ico === "📢" || /broadcast/.test(t)) return "admin-comms";
  if (ico === "🛡️" || /login ke control panel|2fa|admin.*login/.test(t)) return "admin-audit";
  if (ico === "🗑️" || /(suspend|reactiv|hapus|akun)/.test(t)) return "admin-users";
  if (/(user baru|registrasi|@\w+)/.test(t)) return "admin-users";
  if (/(video|moderasi|approve|reject|takedown|publish)/.test(t)) return "admin-videos";
  return null;
}

// Kolom notifikasi aktivitas di samping hero card (request user 2026-05-18).
// Sumber data sama dengan live feed: getAdminData("events") — mencakup SEMUA
// aktivitas admin (termasuk admin cadangan, lihat actorEmail/actorTier) &
// seluruh user. Tanpa emoji (indikator dot CSS, konsisten no-emoji).
let lastHeroFeedTopId = null;
function renderAdminHeroFeed() {
  const list = $("#adminHeroFeed"); if (!list) return;
  const events = getAdminData("events").slice(0, 14);
  if (!events.length) {
    list.innerHTML = `<li class="ahf-empty">
      <strong>Belum ada aktivitas</strong>
      <small>Aktivitas admin &amp; user akan muncul di sini secara real-time.</small>
    </li>`;
    lastHeroFeedTopId = null;
    return;
  }
  const newTop = events[0].id;
  const isNew = lastHeroFeedTopId !== null && newTop !== lastHeroFeedTopId;
  list.innerHTML = events.map((e, i) => {
    const jump = inferAdminEventJump(e);
    const cls = `ahf-row${i === 0 && isNew ? " is-new" : ""}${jump ? " is-clickable" : ""}`;
    const attrs = jump ? ` data-jump="${jump}" role="button" tabindex="0"` : "";
    const who = e.actorEmail
      ? `<small class="ahf-who">${e.actorTier === "super-admin" ? "Admin" : e.actorTier === "admin" ? "Admin cadangan" : "User"} · ${e.actorEmail}</small>`
      : "";
    return `<li class="${cls}"${attrs}>
      <span class="ahf-dot"></span>
      <span class="ahf-body">
        <span class="ahf-text">${e.text}</span>
        ${who}
      </span>
      <span class="ahf-time">${relTime(e.ts)}</span>
    </li>`;
  }).join("");
  lastHeroFeedTopId = newTop;
}

let lastFeedTopId = null;
function renderAdminLiveFeed() {
  try { renderAdminHeroFeed(); } catch (_) {}
  const list = $("#adminLiveFeed"); if (!list) return;
  const events = getAdminData("events").slice(0, 10);
  if (!events.length) {
    list.innerHTML = `<li class="feed-empty">
      <span class="feed-empty-icon">📭</span>
      <div>
        <strong>Belum ada aktivitas</strong>
        <small>Aksi admin (suspend, approve, kirim pesan, dll.) akan muncul di sini.</small>
      </div>
    </li>`;
    lastFeedTopId = null;
    return;
  }
  const newTop = events[0].id;
  const isNew = lastFeedTopId !== null && newTop !== lastFeedTopId;
  list.innerHTML = events.map((e, i) => {
    const jump = inferAdminEventJump(e);
    const cls = `${i === 0 && isNew ? " new-event" : ""}${jump ? " feed-clickable" : ""}`.trim();
    const attrs = jump ? ` data-jump="${jump}" data-close-sp="notifPanel" role="button" tabindex="0"` : "";
    return `<li${cls ? ` class="${cls}"` : ""}${attrs}>
      <span class="feed-ico">${e.ico}</span>
      <span class="feed-text">${e.text}</span>
      <span class="feed-time">${relTime(e.ts)}</span>
    </li>`;
  }).join("");
  lastFeedTopId = newTop;
}

function renderAdminAlerts() {
  const wrap = $(".admin-alerts"); if (!wrap) return;
  const m = getAdminMetrics();
  const rows = [
    { cls: "red",   text: `${m.mod} video dilaporkan menunggu review`,        count: m.mod,           view: "admin-videos" },
    { cls: "amber", text: `${m.tickets} pesan baru di Inbox belum ditangani`, count: m.tickets,       view: "admin-inbox" },
    { cls: "blue",  text: `${m.newUsers24h} user baru dalam 24 jam terakhir`, count: m.newUsers24h,   view: "admin-users" },
    { cls: "gray",  text: `${m.bugsCritical} bug severity tinggi di Inbox`,   count: m.bugsCritical,  view: "admin-inbox" }
  ].filter(r => r.count > 0);

  if (!rows.length) {
    wrap.innerHTML = `<li class="alert-empty">
      <span class="alert-empty-icon">✅</span>
      <div>
        <strong>Semua aman</strong>
        <small>Tidak ada moderasi pending, tiket terbuka, atau bug critical.</small>
      </div>
    </li>`;
    return;
  }

  wrap.innerHTML = rows.map(r => `<li class="alert-row ${r.cls}" data-jump="${r.view}" data-close-sp="notifPanel" role="button" tabindex="0" style="cursor:pointer">
    <span>${r.text}</span><b>${r.count}</b>
  </li>`).join("");
}

// =================== USER NOTIF SECTIONS (per request 2026-05-10) ===================
// Mirror struktur admin (Perlu Perhatian + Aktivitas Real-time) untuk user dashboard.
// Pakai data dari state.myVideos / state.activities. Theme color via CSS vars.

function renderUserNotifAlerts() {
  const wrap = document.getElementById("userNotifAlerts");
  if (!wrap) return;
  const myVids = Array.isArray(state?.myVideos) ? state.myVideos : [];
  const pendingCount = myVids.filter(v => v.adminStatus === "pending").length;
  const takedownCount = myVids.filter(v => v.adminStatus === "takedown").length;
  // Premium expiring dalam 7 hari
  let expiringSoon = 0;
  try {
    const acc = (typeof findAccountByEmail === "function" && user?.email)
      ? findAccountByEmail(user.email)
      : null;
    if (acc?.tier === "premium" && acc.premiumExpiresAt) {
      const daysLeft = (acc.premiumExpiresAt - Date.now()) / 86400000;
      if (daysLeft > 0 && daysLeft < 7) expiringSoon = Math.ceil(daysLeft);
    }
  } catch {}
  // Pending payment status
  const paymentPending = state?.premiumPaymentStatus === "pending" ? 1 : 0;

  const rows = [
    { cls: "amber", text: `${pendingCount} video menunggu review admin`, count: pendingCount, view: "videos" },
    { cls: "red",   text: `${takedownCount} video di-takedown admin`,    count: takedownCount, view: "videos" },
    { cls: "blue",  text: `Premium kedaluwarsa dalam ${expiringSoon} hari`, count: expiringSoon, view: "settings" },
    { cls: "gray",  text: `Pembayaran premium menunggu approval admin`,  count: paymentPending, view: "settings" },
  ].filter(r => r.count > 0);

  if (!rows.length) {
    wrap.innerHTML = `<li class="alert-empty">
      <span class="alert-empty-icon">✅</span>
      <div>
        <strong>Semua aman</strong>
        <small>Tidak ada video pending, takedown, atau status premium yang perlu perhatian.</small>
      </div>
    </li>`;
    return;
  }
  wrap.innerHTML = rows.map(r => `<li class="alert-row ${r.cls}" data-jump="${r.view}" data-close-sp="notifPanel" role="button" tabindex="0" style="cursor:pointer">
    <span>${r.text}</span><b>${r.count}</b>
  </li>`).join("");
}

function renderUserLiveFeed() {
  const list = document.getElementById("userLiveFeed");
  if (!list) return;
  const acts = Array.isArray(state?.activities) ? state.activities.slice(0, 10) : [];
  if (!acts.length) {
    list.innerHTML = `<li class="feed-empty">
      <span class="feed-empty-icon">📭</span>
      <div>
        <strong>Belum ada aktivitas</strong>
        <small>Aktivitas kamu (upload, suka, komentar, follow) akan muncul di sini.</small>
      </div>
    </li>`;
    return;
  }
  list.innerHTML = acts.map(a => `<li>
    <span class="feed-ico">${a.icon || "🔔"}</span>
    <span class="feed-text">${a.text || ""}</span>
    <span class="feed-time">${a.ts ? relTime(a.ts) : (a.time || "")}</span>
  </li>`).join("");
}

// =================== ADMIN ACTION CENTER (per 2026-05-07) ===================
// Strip prominent di home dashboard admin (paling atas setelah hero) — tampilkan
// pending tasks yang butuh aksi admin: verifikasi premium, moderasi laporan,
// tiket baru, bug critical. Item dengan count > 0 di-highlight dengan severity
// color (danger/warn/amber/info); count === 0 di-dim. Empty state hijau "✅
// Semua aman" kalau totalnya 0.
function renderAdminActionCenter() {
  const wrap = document.getElementById("adminActionCenter");
  if (!wrap) return;

  const m = (typeof getAdminMetrics === "function") ? getAdminMetrics() : { mod: 0, tickets: 0, bugsCritical: 0 };
  const premiumPending = (typeof getPremiumPayments === "function")
    ? getPremiumPayments().filter(p => p && p.status === "pending").length
    : 0;

  // Ikon monokrom (Lucide-style, stroke=currentColor) — konsisten dgn
  // ikon Ringkasan Pendapatan (.ars-ico). NO emoji, flat slate.
  const SVG = {
    open: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">',
    close: '</svg>'
  };
  const icoShieldCheck = SVG.open + '<path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/><path d="m9 12 2 2 4-4"/>' + SVG.close;
  const icoFlag        = SVG.open + '<path d="M4 21V4"/><path d="M4 4h13l-2 4 2 4H4"/>' + SVG.close;
  const icoMail        = SVG.open + '<rect x="3" y="5" width="18" height="14" rx="2"/><path d="m3 7 9 6 9-6"/>' + SVG.close;
  const icoAlertTri    = SVG.open + '<path d="M10.3 3.9 1.8 18a2 2 0 0 0 1.7 3h17a2 2 0 0 0 1.7-3L13.7 3.9a2 2 0 0 0-3.4 0z"/><path d="M12 9v4"/><path d="M12 17h.01"/>' + SVG.close;
  const icoVideo       = SVG.open + '<rect x="3" y="5" width="18" height="14" rx="2"/><path d="m10 9 5 3-5 3z"/>' + SVG.close;
  const icoBan         = SVG.open + '<circle cx="12" cy="12" r="9"/><path d="m5.6 5.6 12.8 12.8"/>' + SVG.close;

  const items = [
    {
      key: "premium", svg: icoShieldCheck,
      label: "Verifikasi Premium",
      desc: "Pembayaran menunggu approval",
      count: premiumPending,
      view: "admin-premium-queue",
      cls: "warn"
    },
    {
      key: "mod", svg: icoFlag,
      label: "Moderasi Laporan",
      desc: "Video dilaporkan menunggu review",
      count: m.mod || 0,
      view: "admin-videos",
      cls: "danger"
    },
    {
      key: "tickets", svg: icoMail,
      label: "Inbox",
      desc: "Pesan/keluhan user belum ditangani",
      count: m.tickets || 0,
      view: "admin-inbox",
      cls: "info"
    },
    {
      key: "bugs", svg: icoAlertTri,
      label: "Bug Critical/High",
      desc: "Bug severity tinggi belum ditutup",
      count: m.bugsCritical || 0,
      view: "admin-inbox",
      cls: "amber"
    },
    {
      // req user 2026-05-18 — video baru menunggu approval/verifikasi
      // admin (adminStatus "pending"). Beda dari Moderasi (video dilaporkan).
      key: "vidPending", svg: icoVideo,
      label: "Video Butuh Verifikasi",
      desc: "Video baru menunggu approval admin",
      count: (typeof countAdminPendingVideos === "function") ? countAdminPendingVideos() : 0,
      view: "admin-videos",
      cls: "warn"
    },
    {
      // req user 2026-05-18 — video yang sudah di-takedown; perlu
      // audit/tinjau ulang (restore bila salah takedown).
      key: "vidTakedown", svg: icoBan,
      label: "Video Di-takedown",
      desc: "Video dihapus — tinjau/restore bila perlu",
      count: ((typeof getAllAdminVideos === "function" ? getAllAdminVideos() : []) || [])
               .filter(v => v && v.adminStatus === "takedown").length,
      view: "admin-videos",
      cls: "amber"
    }
  ];

  // PUSAT AKSI SELALU TAMPIL (req user 2026-05-18): 6 kartu permanen,
  // count 0 di-dim (aac-zero) — TIDAK diganti empty-state "Semua aman".
  // Layout: ikon chip slate | label + desc | count pill di kanan.
  wrap.innerHTML = items.map(it => {
    const stateCls = it.count > 0 ? "aac-active" : "aac-zero";
    return `
      <button type="button" class="admin-action-card aac-${it.cls} ${stateCls}" data-key="${it.key}" data-jump="${it.view}" title="${escapeHtml(it.desc)}">
        <span class="aac-icon">${it.svg}</span>
        <div class="aac-content">
          <span class="aac-label">${escapeHtml(it.label)}</span>
          <span class="aac-desc">${escapeHtml(it.desc)}</span>
        </div>
        <span class="aac-badge">${it.count}</span>
      </button>
    `;
  }).join("");
}

function renderAdminUsers() {
  const tbody = $("#adminUserTbody"); if (!tbody) return;
  const search = ($("#adminUserSearch")?.value || "").toLowerCase().trim();
  const accounts = getAllAccounts();
  const now = Date.now();
  const rows = accounts.map(a => {
    // Hitung video real + last activity timestamp dari user state.
    // Last activity = max(state.lastActivityAt, latest upload, latest history,
    // joinedAt fallback). Include lastActivityAt yang ditulis heartbeat 60s.
    const stateRaw = localStorage.getItem(`playly-state-${a.username}`);
    let videoCount = 0;
    let lastActivity = a.joinedAt ? new Date(a.joinedAt).getTime() : 0;
    try {
      const s = JSON.parse(stateRaw) || {};
      const arr = Array.isArray(s.myVideos) ? s.myVideos : [];
      videoCount = arr.length;
      // Heartbeat timestamp dari saveState/heartbeat (60s)
      const hbTs = Number(s.lastActivityAt || 0);
      if (hbTs > lastActivity) lastActivity = hbTs;
      // Latest upload timestamp
      arr.forEach(v => {
        const t = Number(v.uploadedAt || v.createdAt || (typeof v.id === "number" && v.id > 1e12 ? v.id : 0));
        if (t > lastActivity) lastActivity = t;
      });
      // Latest history watch timestamp (proxy for "user actively browsing")
      const hist = Array.isArray(s.history) ? s.history : [];
      hist.forEach(h => { if (h.ts && h.ts > lastActivity) lastActivity = h.ts; });
    } catch {}
    // Status real-time (req user 2026-05-19) — 4 nilai:
    //   suspend  → akun di-suspend admin (merah)
    //   online   → aktivitas < 5 menit (hijau)
    //   offline  → aktivitas < 7 hari, tapi tidak online sekarang (abu-abu)
    //   deactive → tidak ada aktivitas >= 7 hari / belum pernah (biru terang)
    let status;
    if (a.suspended) status = "suspend";
    else if (a.deactivated) status = "deactive";   // di-deactive manual oleh admin
    else {
      const diff = now - lastActivity;
      if (lastActivity && diff < 5 * 60 * 1000) status = "online";
      else if (lastActivity && diff < 7 * 24 * 60 * 60 * 1000) status = "offline";
      else status = "deactive";
    }
    return {
      name: a.name, username: a.username, email: a.email,
      role: a.role || "user",
      tier: a.tier || "free",
      premiumPlan: a.premiumPlan || null,
      premiumExpiresAt: a.premiumExpiresAt || null,
      avatar: a.avatar || "",
      videos: videoCount,
      joinedAt: (a.joinedAt || "").split("T")[0] || "—",
      lastActivity, status
    };
  });

  // Update last-refresh timestamp di header
  const stamp = $("#adminUserRefreshTime");
  if (stamp) {
    const now = new Date();
    stamp.textContent = `${String(now.getHours()).padStart(2, "0")}:${String(now.getMinutes()).padStart(2, "0")}:${String(now.getSeconds()).padStart(2, "0")}`;
  }

  // Split by role for tab counts
  // Per user 2026-05-09: SUPER ADMIN tidak boleh muncul di Admin tab list
  // (mereka punya halaman super admin sendiri). Admin biasa tetap muncul.
  const userRows  = rows.filter(r => r.role !== "admin");
  const adminRows = rows.filter(r => r.role === "admin" && !isOfficialAdminEmail(r.email));
  const setT = (id, n) => { const el = document.getElementById(id); if (el) el.textContent = n; };
  setT("adminUserCntUser", userRows.length);
  setT("adminUserCntAdmin", adminRows.length);

  // Active role tab — default "user"
  const activeRoleTab = (document.querySelector('[data-user-role-tab].active')?.dataset.userRoleTab) || "user";
  const roleFiltered = activeRoleTab === "admin" ? adminRows : userRows;

  const filtered = search ? roleFiltered.filter(r =>
    r.name.toLowerCase().includes(search) ||
    r.username.toLowerCase().includes(search) ||
    r.email.toLowerCase().includes(search)
  ) : roleFiltered;

  if (!filtered.length) {
    const emptyMsg = search
      ? "Tidak ada user yang cocok"
      : (activeRoleTab === "admin" ? "Belum ada akun admin" : "Belum ada user terdaftar");
    tbody.innerHTML = `<tr><td colspan="8" style="text-align:center;padding:32px;color:var(--muted)">${emptyMsg}</td></tr>`;
    return;
  }

  const STATUS_LABEL = {
    online: "Online", offline: "Offline", deactive: "Deactive", suspend: "Suspend"
  };
  tbody.innerHTML = filtered.map(r => {
    const init = (r.name || r.username).split(" ").map(p => p[0]).slice(0,2).join("").toUpperCase();
    const statusLabel = STATUS_LABEL[r.status] || r.status;
    const isPrem = r.tier === "premium";
    const tierLabel = isPrem
      ? `${r.premiumPlan ? r.premiumPlan.charAt(0).toUpperCase() + r.premiumPlan.slice(1) : "Premium"}`
      : "Free";
    const tierExpiry = isPrem && r.premiumExpiresAt
      ? `Expires ${new Date(r.premiumExpiresAt).toLocaleDateString("id-ID")}`
      : isPrem ? "Lifetime" : "";
    const isAdminRow = r.role === "admin";
    const isSuperAdminRow = isAdminRow && (r.email || "").toLowerCase() === OFFICIAL_ADMIN_EMAIL;
    // Admin: tidak punya tier & tidak punya profil → sembunyikan ⭐ dan 👤.
    // Super admin: juga sembunyikan 💬 (gak chat ke diri sendiri) & 🗑️ (gak self-delete).
    // Backup admin: 💬 dan 🗑️ tetap ada (super admin bisa chat / cabut admin tambahan).
    const showSetTier = !isAdminRow;
    const showMessage = !isSuperAdminRow;
    const showDetail  = !isAdminRow;
    const showDelete  = !isSuperAdminRow;
    const userCellAction = isAdminRow ? "" : `data-action="detail"`;
    const tierBadgeAction = isAdminRow ? "" : `data-action="set-tier"`;
    return `<tr data-username="${r.username}">
      <td><div class="user-cell" ${userCellAction}><div class="avatar-sm">${r.avatar ? `<img src="${escapeHtml(r.avatar)}" alt="" referrerpolicy="no-referrer"/>` : init}</div><div><b>${r.name}</b><small style="display:block;color:var(--muted);font-size:11px">@${r.username}</small></div></div></td>
      <td>${r.email}</td>
      <td><span class="role-tag ${r.role}">${r.role.toUpperCase()}</span></td>
      <td class="col-tier"><span class="tier-badge ${isPrem ? "premium" : "free"}" title="${tierExpiry}" ${tierBadgeAction}>${isPrem ? `<svg class="tier-star" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><path d="M12 3l2.6 5.4 5.9.9-4.3 4.1 1 5.9L12 16.6 6.8 19.3l1-5.9L3.5 9.3l5.9-.9Z"/></svg>` : ""}${tierLabel}</span></td>
      <td class="col-videos">${r.videos}</td>
      <td>${r.joinedAt}</td>
      <td><span class="row-status status-${r.status}" title="${r.lastActivity ? `Last activity: ${relTime(r.lastActivity)}` : "No activity recorded"}">${statusLabel}</span></td>
      <td><div class="row-actions">
        ${showSetTier ? `<button title="Set Tier" data-action="set-tier">⭐</button>` : ""}
        ${showMessage ? `<button title="Obrolan Langsung" data-action="message" class="action-chat"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" style="width:15px;height:15px"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg></button>` : ""}
        ${showDetail  ? `<button title="Detail" data-action="detail">👤</button>` : ""}
        ${showDelete  ? `<button title="Delete Account" class="danger" data-action="delete">🗑️</button>` : ""}
      </div></td>
    </tr>`;
  }).join("");

  // Wire up delete account (irreversible — confirm modal)
  tbody.querySelectorAll("[data-action='delete']").forEach(btn => {
    btn.addEventListener("click", e => {
      e.stopPropagation();
      const tr = e.currentTarget.closest("tr");
      deleteUserAccount(tr.dataset.username);
    });
  });
  // Klik baris atau tombol detail untuk buka modal profile
  tbody.querySelectorAll("[data-action='detail']").forEach(btn => {
    btn.addEventListener("click", e => {
      e.stopPropagation();
      const tr = e.currentTarget.closest("tr");
      openUserDetail(tr.dataset.username);
    });
  });
  // Kirim pesan ke user dari row table → buka DM chat biasa, bukan modal template
  tbody.querySelectorAll("[data-action='message']").forEach(btn => {
    btn.addEventListener("click", e => {
      e.stopPropagation();
      const tr = e.currentTarget.closest("tr");
      startChatWithUser(tr.dataset.username);
    });
  });
  // Set tier — tombol ⭐ dan tier badge sama-sama membuka modal set tier
  tbody.querySelectorAll("[data-action='set-tier']").forEach(el => {
    el.addEventListener("click", e => {
      e.stopPropagation();
      const tr = e.currentTarget.closest("tr");
      openSetTierModal(tr.dataset.username);
    });
  });
}

// Tab switch handler — User / Admin role split di User Management.
// Sekalian update label tombol Create: "Create User" ↔ "Create Admin".
document.addEventListener("click", e => {
  const tab = e.target.closest("[data-user-role-tab]");
  if (!tab) return;
  e.preventDefault();
  const tabs = document.querySelectorAll("[data-user-role-tab]");
  tabs.forEach(t => t.classList.toggle("active", t === tab));
  // Set attribute pada view supaya CSS bisa hide kolom Tier/Videos di Admin tab
  const view = document.querySelector('section.view[data-view="admin-users"]');
  if (view) view.dataset.activeTab = tab.dataset.userRoleTab;
  syncCreateAccountBtnLabel();
  if (typeof renderAdminUsers === "function") renderAdminUsers();
});

function syncCreateAccountBtnLabel() {
  const activeTab = document.querySelector('[data-user-role-tab].active')?.dataset.userRoleTab || "user";
  const label = document.getElementById("adminCreateUserBtnLabel");
  const btn   = document.getElementById("adminCreateUserBtn");
  const isAdminMode = activeTab === "admin";
  if (label) label.textContent = isAdminMode ? "Buat Admin" : "Buat User";
  if (btn) {
    btn.title = isAdminMode ? "Create new admin account" : "Create new user account";
    btn.dataset.createMode = isAdminMode ? "admin" : "user";
  }
}

// Reset Platform Data — hapus semua akun user + state, admin tetap
// Reset Platform Data — custom modal (replace native confirm() popup).
// Backend logic SAMA persis: hapus akun user + state + welcome flag, admin protected.
document.getElementById("adminResetPlatformBtn")?.addEventListener("click", () => {
  const accounts = (typeof getAllAccounts === "function" ? getAllAccounts() : [])
    .filter(a => a.role !== "admin");
  if (!accounts.length) {
    toast?.("Tidak ada data user untuk dihapus.", "info");
    return;
  }
  // Tampilkan custom modal — populate count
  const modal = document.getElementById("adminResetModal");
  const countEl = document.getElementById("adminResetCount");
  if (countEl) countEl.textContent = accounts.length;
  if (modal) modal.classList.add("show");
  document.body.style.overflow = "hidden";
});

// Custom modal: confirm button handler (real delete).
// `async` supaya bisa AWAIT cloud-side deletes sebelum tutup modal.
// Tanpa await, race-condition: hijack `removeItem` fire-and-forget ke
// Supabase, tapi user reload sebelum delete committed → bidirectionalSync
// di boot berikutnya pull row stale dari cloud lalu re-apply → akun "balik".
document.getElementById("adminResetConfirmBtn")?.addEventListener("click", async () => {
  const accounts = (typeof getAllAccounts === "function" ? getAllAccounts() : [])
    .filter(a => a.role !== "admin");
  const usernames = accounts.map(a => a.username).filter(Boolean);
  const usernameSet = new Set(usernames);
  let removed = 0;

  // Disable confirm button + tampil loading state
  const confirmBtn = document.getElementById("adminResetConfirmBtn");
  const originalBtnText = confirmBtn?.innerHTML;
  if (confirmBtn) {
    confirmBtn.disabled = true;
    confirmBtn.innerHTML = "⏳ Menghapus & sync ke cloud...";
  }

  const keysToScan = [];
  for (let i = 0; i < localStorage.length; i++) keysToScan.push(localStorage.key(i));

  keysToScan.forEach(key => {
    if (!key) return;
    let shouldDelete = false;

    if (key.startsWith("playly-account-")) {
      try {
        const a = JSON.parse(localStorage.getItem(key) || "{}");
        if (a.role !== "admin" && a.username) shouldDelete = true;
      } catch {}
    } else if (key.startsWith("playly-state-") ||
               key.startsWith("playly-welcomed-") ||
               key.startsWith("playly-welcome-") ||
               key.startsWith("playly-onboarding-") ||
               key.startsWith("playly-notif-") ||
               key.startsWith("playly-prefs-")) {
      const ident = key.split("-").slice(2).join("-");
      // playly-prefs-* dikey-by-EMAIL (per script.js:2010), sisanya dikey-by-username.
      // Cek di kedua set: kalau prefs, match email; selain itu match username.
      const isMatch = key.startsWith("playly-prefs-")
        ? accounts.some(a => String(a.email || "").toLowerCase() === ident.toLowerCase())
        : usernameSet.has(ident);
      if (isMatch) shouldDelete = true;
    }

    if (shouldDelete) { localStorage.removeItem(key); removed++; }
  });

  // Clear admin event/audit data
  ["mod", "tickets", "bugs", "events"].forEach(k => {
    if (typeof saveAdminData === "function") saveAdminData(k, []);
  });

  // Cloud-side BULK CLEANUP — pakai wipeUserKeys yang bulk-delete by prefix.
  // Strategy:
  //   1. Fetch semua playly-account-* dari cloud, filter non-admin, delete
  //   2. Bulk delete playly-{state,welcomed,welcome,onboarding,notif,prefs}-*
  //      dalam 1 request per prefix (Supabase `like` filter)
  // AWAIT semua sebelum reload supaya commit fully di server. Dengan begini
  // bahkan kalau ada akun cloud-only yang local nggak punya snapshot-nya
  // (mis. kalau user pernah login di device lain), tetap ke-hapus.
  try {
    if (window.cloudSync?.wipeUserKeys) {
      // Compile admin emails: official + extra. wipeUserKeys exclude key
      // yang match email ini.
      const adminEmails = [];
      try {
        if (typeof OFFICIAL_ADMIN_EMAIL !== "undefined") adminEmails.push(OFFICIAL_ADMIN_EMAIL);
        if (typeof getExtraAdminEmails === "function") {
          adminEmails.push(...getExtraAdminEmails());
        }
      } catch {}
      await Promise.race([
        window.cloudSync.wipeUserKeys(adminEmails),
        new Promise(r => setTimeout(r, 12000)),
      ]);
    } else if (window.cloudSync?.removeKeys) {
      // Fallback ke removeKeys lama kalau wipeUserKeys belum loaded
      await Promise.race([
        window.cloudSync.removeKeys([
          ...accounts.flatMap(a => [
            `playly-account-${a.username}`,
            `playly-account-${a.email}`,
          ]),
          ...usernames.flatMap(u => [
            `playly-state-${u}`,
            `playly-welcomed-${u}`,
            `playly-welcome-${u}`,
            `playly-onboarding-${u}`,
            `playly-notif-${u}`,
            `playly-prefs-${u}`,
          ]),
        ]),
        new Promise(r => setTimeout(r, 8000)),
      ]);
    }
  } catch (err) {
    console.warn("[reset-data] cloud cleanup error:", err);
  }

  // Restore confirm button
  if (confirmBtn) {
    confirmBtn.disabled = false;
    if (originalBtnText) confirmBtn.innerHTML = originalBtnText;
  }

  // Close modal
  const modal = document.getElementById("adminResetModal");
  if (modal) modal.classList.remove("show");
  document.body.style.overflow = "";

  toast?.(`✓ ${accounts.length} akun user dihapus permanen. Reload halaman...`, "success");

  // FORCE RELOAD — paling reliable cara mencegah bidirectionalSync re-push
  // stale local snapshot (yang sebenarnya udah dihapus tapi masih ada di
  // memory variable lain). Reload halaman → cloud-sync boot ulang → fetch
  // cloud bersih (just-deleted) → applyToLocal nothing → user clean.
  setTimeout(() => {
    try { location.reload(); } catch { window.location.href = window.location.href; }
  }, 800);
});

// Custom modal: cancel + backdrop close
document.getElementById("adminResetModal")?.addEventListener("click", (e) => {
  if (e.target.matches("[data-close]")) {
    const modal = document.getElementById("adminResetModal");
    if (modal) modal.classList.remove("show");
    document.body.style.overflow = "";
  }
});

// ESC key close
document.addEventListener("keydown", (e) => {
  if (e.key === "Escape") {
    const modal = document.getElementById("adminResetModal");
    if (modal?.classList.contains("show")) {
      modal.classList.remove("show");
      document.body.style.overflow = "";
    }
  }
});

// Hapus akun user — destructive, butuh konfirmasi typed-text. Admin/super-admin
// dilindungi (sama seperti suspend dulu). Cleanup localStorage account + state +
// welcome flag, lalu push event ke audit log + toast.
function deleteUserAccount(username) {
  const accountKey = Object.keys(localStorage).find(k => {
    if (!k.startsWith("playly-account-")) return false;
    try { return JSON.parse(localStorage.getItem(k))?.username === username; } catch { return false; }
  });
  if (!accountKey) return toast("❌ User tidak ditemukan", "error");
  const acc = JSON.parse(localStorage.getItem(accountKey));
  if (isAllowedAdminEmail(acc.email)) {
    return toast("🔒 Akun Admin tidak bisa dihapus dari sini", "warning");
  }
  openConfirm({
    icon: "🗑️", iconClass: "danger",
    title: "Delete Account Permanently?",
    desc: `<b style="color:var(--danger)">This action cannot be undone.</b><br>Account <b>@${escapeHtml(username)}</b> along with all videos, messages, and related data will be permanently removed from the platform.`,
    btnText: "🗑 Delete Permanently", btnClass: "danger", typeText: "DELETE",
    onConfirm: async () => {
      // C-2 H4 fix (2026-05-21): EXTEND cleanup list + AWAIT cloud removal.
      // Sebelumnya leak: playly-prefs-*, playly-2fa-*, playly-premium-payments
      // entries dgn email user ini, IndexedDB video blobs, Supabase Storage
      // blobs. AND removeKeys was fire-and-forget → race condition memungkinkan
      // bidirectionalSync di boot berikutnya pull row stale & "resurrect"
      // akun.
      const email = String(acc.email || "").toLowerCase();
      const usernameLc = String(username || "").toLowerCase();
      // 1. Hapus playly-premium-payments entries milik user ini
      // v546 (2026-05-25): Audit moderation M-extra — match email OR username.
      // Sebelumnya filter cuma by email; kalau payment record punya email
      // null/missing (legacy data atau admin-grant tanpa email) tapi username
      // ada → orphan tertinggal di queue, render baris ghost di admin-premium-queue.
      try {
        if ((email || usernameLc) && typeof getPremiumPayments === "function") {
          const payments = getPremiumPayments();
          const filtered = payments.filter(p => {
            const pEmail = String(p.email || "").toLowerCase();
            const pUser = String(p.username || "").toLowerCase();
            if (email && pEmail && pEmail === email) return false;
            if (usernameLc && pUser && pUser === usernameLc) return false;
            return true;
          });
          if (filtered.length !== payments.length && typeof savePremiumPayments === "function") {
            savePremiumPayments(filtered);
          }
        }
      } catch (err) { console.warn("[deleteUser] cleanup payments failed:", err); }
      // 2. Hapus IndexedDB video blobs milik user ini
      try {
        const stateRaw = localStorage.getItem(`playly-state-${username}`);
        if (stateRaw) {
          const s = JSON.parse(stateRaw);
          if (Array.isArray(s.myVideos)) {
            for (const v of s.myVideos) {
              if (typeof openVideoDB === "function" && v.id) {
                try {
                  openVideoDB().then(db => {
                    const tx = db.transaction(VIDEO_STORE, "readwrite");
                    tx.objectStore(VIDEO_STORE).delete(v.id);
                  }).catch(() => {});
                } catch {}
              }
              // 3. Hapus cloud storage blob (CR-5 helper)
              // v547: pass v.videoUrl supaya R2 vs Supabase dispatch tepat.
              if (window.cloudSync?.deleteVideoBlob && v.id) {
                try { window.cloudSync.deleteVideoBlob(v.id, v.videoUrl); } catch {}
              }
            }
          }
        }
      } catch (err) { console.warn("[deleteUser] cleanup blobs failed:", err); }
      // 4. localStorage cleanup — extended list (prefs, 2fa, dll)
      localStorage.removeItem(accountKey);
      localStorage.removeItem(`playly-state-${username}`);
      localStorage.removeItem(`playly-welcomed-${username}`);
      localStorage.removeItem(`playly-welcome-${username}`);
      localStorage.removeItem(`playly-onboarding-${username}`);
      localStorage.removeItem(`playly-notif-${username}`);
      localStorage.removeItem(`playly-prefs-${username}`);
      localStorage.removeItem(`playly-prefs-${email}`);
      localStorage.removeItem(`playly-2fa-${username}`);
      localStorage.removeItem(`playly-2fa-${email}`);

      // v537 CRITICAL FIX 1 (2026-05-25): Orphan cleanup di other users' state.
      // Audit moderation flow finding C1: delete account hanya hapus key utama
      // tapi LEAVE behind references di state user lain (followingCreators
      // array masih punya username deleted, state.messages thread to deleted
      // user, comments di videos lain). Sekarang scan semua playly-state-*
      // keys + purge references.
      try {
        let orphansCleaned = 0;
        for (let i = 0; i < localStorage.length; i++) {
          const k = localStorage.key(i);
          if (!k || !k.startsWith("playly-state-")) continue;
          const otherUsername = k.slice("playly-state-".length);
          if (otherUsername === username) continue;
          let s;
          try { s = JSON.parse(localStorage.getItem(k)); } catch { continue; }
          if (!s) continue;
          let touched = false;
          // 4a. followingCreators array
          if (Array.isArray(s.followingCreators) && s.followingCreators.includes(username)) {
            s.followingCreators = s.followingCreators.filter(u => u !== username);
            touched = true;
          }
          // 4b. followers array (some user might "follow" deleted via legacy data)
          if (Array.isArray(s.followers) && s.followers.includes(username)) {
            s.followers = s.followers.filter(u => u !== username);
            touched = true;
          }
          // 4c. messages threads
          if (Array.isArray(s.messages)) {
            const before = s.messages.length;
            s.messages = s.messages.filter(m =>
              !(m.with === username || m.name === username || m.fromUsername === username)
            );
            if (s.messages.length !== before) touched = true;
          }
          // 4d. comments object (per-video comments by deleted user)
          if (s.comments && typeof s.comments === "object") {
            Object.keys(s.comments).forEach(vid => {
              if (!Array.isArray(s.comments[vid])) return;
              const before = s.comments[vid].length;
              s.comments[vid] = s.comments[vid].filter(c => c.user !== username);
              if (s.comments[vid].length !== before) touched = true;
              if (!s.comments[vid].length) delete s.comments[vid];
            });
          }
          if (touched) {
            try { localStorage.setItem(k, JSON.stringify(s)); orphansCleaned++; } catch {}
          }
        }
        if (orphansCleaned) console.info(`[deleteUser] cleaned ${orphansCleaned} other users' state from references to @${username}`);
      } catch (err) { console.warn("[deleteUser] orphan cleanup failed:", err); }
      // 5. Cloud-side cleanup — AWAIT supaya tidak ada race dgn next boot sync
      try {
        if (window.cloudSync?.removeKeys) {
          // v538 HIGH FIX 3 (2026-05-25): track keys + boot-time re-purge.
          // Audit moderation flow finding H3: Promise.race 8s timeout WIN tapi
          // removeKeys masih in-flight — next boot sync bisa resurrect stale
          // rows kalau cloud delete finish setelah local re-pull. Sekarang
          // queue keys ke localStorage "playly-cloud-purge-queue" → IIFE di
          // boot top scan queue, retry removeKeys + verify lalu unqueue.
          const keysToDelete = [
            accountKey,
            `playly-account-${username}`,
            `playly-account-${email}`,
            `playly-state-${username}`,
            `playly-welcomed-${username}`,
            `playly-welcome-${username}`,
            `playly-onboarding-${username}`,
            `playly-notif-${username}`,
            `playly-prefs-${username}`,
            `playly-prefs-${email}`,
            `playly-2fa-${username}`,
            `playly-2fa-${email}`,
          ];
          // Enqueue keys SEBELUM start delete — kalau timeout/error, queue
          // tetap ada untuk boot retry.
          try {
            const q = JSON.parse(localStorage.getItem("playly-cloud-purge-queue") || "[]");
            keysToDelete.forEach(k => { if (!q.includes(k)) q.push(k); });
            localStorage.setItem("playly-cloud-purge-queue", JSON.stringify(q));
          } catch {}
          let removeOk = false;
          await Promise.race([
            window.cloudSync.removeKeys(keysToDelete).then(() => { removeOk = true; }),
            new Promise(r => setTimeout(r, 8000)),
          ]);
          // Kalau success dalam window → unqueue. Kalau timeout → biarkan
          // queue, IIFE boot akan retry.
          if (removeOk) {
            try {
              const q = JSON.parse(localStorage.getItem("playly-cloud-purge-queue") || "[]");
              const filtered = q.filter(k => !keysToDelete.includes(k));
              localStorage.setItem("playly-cloud-purge-queue", JSON.stringify(filtered));
            } catch {}
          } else {
            console.warn(`[deleteUser] removeKeys timeout — ${keysToDelete.length} keys queued for boot retry`);
          }
        }
      } catch (err) { console.warn("[deleteUser] cloud cleanup failed:", err); }
      pushAdminEvent("🗑️", `Akun <b>@${escapeHtml(username)}</b> (${escapeHtml(email)}) dihapus permanen`);
      toast(`🗑️ Akun <b>@${escapeHtml(username)}</b> berhasil dihapus`, "success");
      renderAdminUsers();
      renderAdminLiveFeed?.();
      renderAdminKPI?.();
    }
  });
}

// Toggle suspend status — masih dipakai dari modal detail user.
function toggleUserSuspend(username) {
  const accountKey = Object.keys(localStorage).find(k => {
    if (!k.startsWith("playly-account-")) return false;
    try { return JSON.parse(localStorage.getItem(k))?.username === username; } catch { return false; }
  });
  if (!accountKey) return null;
  const acc = JSON.parse(localStorage.getItem(accountKey));
  if (isAllowedAdminEmail(acc.email)) {
    toast("🔒 Akun Admin tidak bisa di-suspend", "warning");
    return acc;
  }
  // C-2 H1+H2 fix (2026-05-21): suspend → prompt reason, simpan field;
  // unsuspend → clear stale reason fields.
  const willSuspend = !acc.suspended;
  if (willSuspend) {
    // Prompt reason via confirm modal w/ text input
    if (typeof openConfirm === "function") {
      openConfirm({
        icon: "⛔", iconClass: "warning",
        title: `Suspend user @${username}?`,
        desc: `Akun <b>@${escapeHtml(username)}</b> akan di-suspend dari platform. Mohon isi alasan singkat di bawah supaya user dapat informasi yg jelas dan admin lain bisa lihat di audit log.`,
        btnText: "Suspend", btnClass: "danger",
        typeText: "Alasan suspend (wajib)",
        onConfirm: (reason) => {
          const reasonText = String(reason || "").trim() || "Tidak ada alasan spesifik";
          acc.suspended = true;
          acc.suspendedAt = Date.now();
          acc.suspendedBy = (typeof user === "object" && user?.username) ? user.username : "admin";
          acc.suspendedReason = reasonText;
          localStorage.setItem(accountKey, JSON.stringify(acc));
          // v538 HIGH FIX 2 (2026-05-25): Explicit cloud-sync push supaya
          // suspend langsung visible di device user (force logout). Sebelumnya
          // mengandalkan background interval 4-15s → window jeda user masih
          // bisa upload/messaging.
          try { window.cloudSync?.syncSingleKey?.(accountKey); } catch (err) { console.warn("[suspend] cloud push failed:", err); }
          pushAdminEvent("⛔", `Suspended user <b>@${escapeHtml(username)}</b> — alasan: ${escapeHtml(reasonText)}`);
          toast(`⛔ User <b>@${escapeHtml(username)}</b> di-suspend`, "warning");
          renderAdminUsers();
          renderAdminLiveFeed();
        }
      });
      return acc; // optimistic; actual update happens onConfirm
    } else {
      // Fallback (no confirm modal available)
      acc.suspended = true;
      acc.suspendedAt = Date.now();
      acc.suspendedReason = "Tidak ada alasan spesifik";
    }
  } else {
    // Unsuspend → clear stale reason
    acc.suspended = false;
    delete acc.suspendedReason;
    delete acc.suspendedAt;
    delete acc.suspendedBy;
    acc.reactivatedAt = Date.now();
  }
  localStorage.setItem(accountKey, JSON.stringify(acc));
  // v538 HIGH FIX 2 (2026-05-25): Cloud push juga di fallback + unsuspend path
  try { window.cloudSync?.syncSingleKey?.(accountKey); } catch (err) { console.warn("[suspend] cloud push failed:", err); }
  pushAdminEvent(acc.suspended ? "⛔" : "✓", `${acc.suspended ? "Suspended" : "Reactivated"} user <b>@${escapeHtml(username)}</b>`);
  toast(acc.suspended ? `⛔ User <b>@${escapeHtml(username)}</b> di-suspend` : `✓ User <b>@${escapeHtml(username)}</b> diaktifkan`, acc.suspended ? "warning" : "success");
  renderAdminUsers();
  renderAdminLiveFeed();
  return acc;
}

// Toggle DEACTIVE status (req user 2026-05-19) — berlaku utk akun
// USER maupun ADMIN. Hanya super admin resmi yg dilindungi supaya
// root tidak bisa mengunci diri sendiri. Beda dari suspend:
// deactive = nonaktifkan akun (status biru), bukan blokir/ban.
function toggleUserDeactivate(username) {
  const accountKey = Object.keys(localStorage).find(k => {
    if (!k.startsWith("playly-account-")) return false;
    try { return JSON.parse(localStorage.getItem(k))?.username === username; } catch { return false; }
  });
  if (!accountKey) return null;
  const acc = JSON.parse(localStorage.getItem(accountKey));
  // C-3 U-M4 fix (2026-05-21): SECURITY — block super-admin, block self,
  // block deactivating other admin accounts (yg jadi backup admin).
  // Sebelumnya extra-admin bisa deactivate extra-admin lain (atau diri sendiri)
  // → admin pool habis = platform locked out.
  if (typeof isOfficialAdminEmail === "function" && isOfficialAdminEmail(acc.email)) {
    toast("🔒 Super Admin tidak bisa di-deactive", "warning");
    return acc;
  }
  // Self-deactivate block
  if (typeof user === "object" && user && (acc.email === user.email || acc.username === user.username)) {
    toast("🔒 Kamu tidak bisa men-deactive akunmu sendiri", "warning");
    return acc;
  }
  // Block deactivate admin lain (mirror suspend behavior)
  if (typeof isAllowedAdminEmail === "function" && isAllowedAdminEmail(acc.email)) {
    toast("🔒 Akun admin lain tidak bisa di-deactive — minta super-admin", "warning");
    return acc;
  }
  acc.deactivated = !acc.deactivated;
  if (acc.deactivated) {
    acc.deactivatedAt = Date.now();
    acc.deactivatedBy = (typeof user === "object" && user?.username) || "admin";
  } else {
    delete acc.deactivatedAt;
    delete acc.deactivatedBy;
  }
  localStorage.setItem(accountKey, JSON.stringify(acc));
  pushAdminEvent(acc.deactivated ? "🔵" : "✓", `${acc.deactivated ? "Deactivated" : "Reactivated"} account <b>@${escapeHtml(username)}</b>`);
  toast(acc.deactivated ? `🔵 Akun <b>@${escapeHtml(username)}</b> di-deactive` : `✓ Akun <b>@${escapeHtml(username)}</b> diaktifkan kembali`, acc.deactivated ? "warning" : "success");
  renderAdminUsers();
  renderAdminLiveFeed();
  return acc;
}

// =================== ADMIN: USER DETAIL MODAL ===================
let currentUserDetail = null;

function openUserDetail(username) {
  const accountKey = Object.keys(localStorage).find(k => {
    if (!k.startsWith("playly-account-")) return false;
    try { return JSON.parse(localStorage.getItem(k))?.username === username; } catch { return false; }
  });
  if (!accountKey) return toast("❌ User tidak ditemukan", "error");
  const acc = JSON.parse(localStorage.getItem(accountKey));
  currentUserDetail = acc;
  fillUserDetailModal(acc);
  $("#adminUserDetailModal").classList.add("show");
}

function fillUserDetailModal(acc) {
  // Header
  const init = (acc.name || acc.username || "U").split(/\s+/).map(p => p[0]).slice(0, 2).join("").toUpperCase();
  const av = $("#audAvatar");
  av.innerHTML = acc.avatar
    ? `<img src="${acc.avatar}" alt=""/>`
    : `<span>${init}</span>`;
  $("#audName").textContent = acc.name || acc.username;
  $("#audUsername").textContent = "@" + acc.username;

  // Role badge
  const role = acc.role || "user";
  const roleBadge = $("#audRoleBadge");
  roleBadge.textContent = role.toUpperCase();
  roleBadge.className = `role-tag ${role}`;

  // Status badge
  const status = acc.suspended ? "suspended" : "active";
  const statusBadge = $("#audStatusBadge");
  statusBadge.textContent = status;
  statusBadge.className = `row-status ${status === "active" ? "" : status}`;

  // Stats
  const stateRaw = localStorage.getItem(`playly-state-${acc.username}`);
  let userState = null;
  try { userState = JSON.parse(stateRaw); } catch {}
  const videos = userState?.myVideos || [];
  const totalLikes = videos.reduce((s, v) => s + (v.likes || 0), 0);
  $("#audVideos").textContent = fmtNum(videos.length);
  $("#audFollowing").textContent = fmtNum(userState?.followingCreators?.length || 0);
  $("#audLikes").textContent = fmtNum(totalLikes);
  $("#audJoined").textContent = acc.joinedAt ? relTime(new Date(acc.joinedAt).getTime()) : "—";

  // Info
  $("#audEmail").textContent = acc.email;
  $("#audBio").textContent = acc.bio?.trim() ? acc.bio : "—";
  $("#audJoinedFull").textContent = acc.joinedAt
    ? new Date(acc.joinedAt).toLocaleDateString("id-ID", { weekday: "long", day: "numeric", month: "long", year: "numeric" })
    : "—";
  $("#audProvider").textContent = acc.provider ? acc.provider.charAt(0).toUpperCase() + acc.provider.slice(1) : "Email/Password";
  $("#audUid").textContent = `playly-${acc.username}`;

  // Social links — only show section if any are set
  const socials = [
    { key: "website", icon: "🌐", label: "Website", href: v => v },
    { key: "twitter", icon: "𝕏", label: "X / Twitter", href: v => `https://x.com/${(v || "").replace("@", "")}` },
    { key: "instagram", icon: "📷", label: "Instagram", href: v => `https://instagram.com/${(v || "").replace("@", "")}` },
    { key: "github", icon: "🐙", label: "GitHub", href: v => `https://github.com/${(v || "").replace("@", "")}` }
  ];
  const linksHtml = socials
    .filter(s => acc[s.key]?.trim())
    .map(s => `<div class="info-row"><span>${s.icon} ${s.label}</span><b><a href="${s.href(acc[s.key])}" target="_blank" rel="noopener" style="color:var(--primary)">${escapeHtml(acc[s.key])}</a></b></div>`)
    .join("");
  const socialSection = $("#audSocialSection");
  if (linksHtml) {
    socialSection.style.display = "";
    $("#audSocialGrid").innerHTML = linksHtml;
  } else {
    socialSection.style.display = "none";
  }

  // Recent videos (top 3 berdasarkan upload terbaru)
  const recent = [...videos].sort((a, b) => (b.id || 0) - (a.id || 0)).slice(0, 3);
  $("#audRecentVideos").innerHTML = recent.length ? recent.map(v => `
    <div class="admin-list-row">
      <span class="rank">🎬</span>
      <div>
        <strong>${escapeHtml(v.title)}</strong>
        <small>${v.duration || "0:00"} • ${v.views || "0"} views</small>
      </div>
      <b>${fmtNum(v.likes || 0)} ♥</b>
    </div>
  `).join("") : `<div style="text-align:center;padding:16px;color:var(--muted);font-size:12px">User belum upload video</div>`;

  // Suspend button label
  const suspendBtn = $("#audSuspendBtn");
  if (acc.suspended) {
    suspendBtn.innerHTML = "✓ Aktifkan Akun";
    suspendBtn.className = "btn success";
  } else {
    suspendBtn.innerHTML = "⛔ Suspend Akun";
    suspendBtn.className = "btn danger";
  }
  // Sembunyikan suspend untuk akun admin (super + admin tambahan)
  suspendBtn.style.display = isAllowedAdminEmail(acc.email) ? "none" : "";

  // Deactivate button (req user 2026-05-19) — berlaku utk user & admin.
  const deactBtn = $("#audDeactivateBtn");
  if (deactBtn) {
    if (acc.deactivated) {
      deactBtn.innerHTML = "✓ Aktifkan Akun";
      deactBtn.className = "btn success";
    } else {
      deactBtn.innerHTML = "🔵 Deactive Akun";
      deactBtn.className = "btn";
    }
    // Hanya super admin resmi yg disembunyikan (tidak bisa di-deactive)
    const isSuper = typeof isOfficialAdminEmail === "function" && isOfficialAdminEmail(acc.email);
    deactBtn.style.display = isSuper ? "none" : "";
  }
}

