// =================== ADMIN → USER MESSAGING ===================
// Kirim pesan dari admin langsung ke inbox user. Pesan ditulis ke
// `playly-state-{username}.messages` milik penerima sehingga user lihat
// di tab Messages mereka.

const ADMIN_MSG_TEMPLATES = {
  welcome: "Halo! Selamat datang di Playly 🎉 Semoga betah & jangan ragu hubungi support kalau ada kendala ya.",
  warning: "⚠️ Tim moderasi kami menemukan konten yang berpotensi melanggar pedoman komunitas. Tolong dicek kembali video terbaru kamu — terima kasih atas kerjasamanya.",
  update:  "📢 Ada update baru di Playly! Cek halaman Discover untuk fitur terbaru. Stay tuned 🚀",
  suspend: "🚫 Akun kamu sedang dalam peninjauan karena pelanggaran pedoman. Hubungi support kalau merasa ini keliru.",
  custom:  ""
};

let __asmTargets = [];   // array of usernames to deliver to
let __asmIsBroadcast = false;

function openAdminSendMsg({ targets = [], broadcast = false } = {}) {
  if (broadcast) {
    const accounts = getAllAccounts().filter(a => !isAllowedAdminEmail(a.email));
    targets = accounts.map(a => a.username);
  }
  if (!targets.length) {
    return toast("⚠️ Tidak ada user untuk dikirimi pesan", "warning");
  }
  __asmTargets = targets;
  __asmIsBroadcast = broadcast;

  // Render recipient chips
  const list = $("#asmRecipientList");
  if (broadcast) {
    list.innerHTML = `<div class="asm-broadcast-chip">📢 Broadcast ke <b>${targets.length} user</b></div>`;
    $("#asmSubtitle").textContent = `Pesan ini akan dikirim ke seluruh ${targets.length} user terdaftar.`;
  } else {
    list.innerHTML = targets.map(u => {
      const init = u.slice(0, 2).toUpperCase();
      return `<div class="asm-chip"><span class="asm-chip-avatar">${init}</span>@${escapeHtml(u)}</div>`;
    }).join("");
    $("#asmSubtitle").textContent = targets.length === 1
      ? `Pesan akan masuk ke inbox @${targets[0]}.`
      : `Pesan akan dikirim ke ${targets.length} user.`;
  }

  $("#asmBody").value = "";
  updateAsmCharCount();
  $$(".asm-tpl").forEach(b => b.classList.remove("active"));
  $("#adminSendMsgModal").classList.add("show");
  setTimeout(() => $("#asmBody")?.focus(), 80);
}

function updateAsmCharCount() {
  const ta = $("#asmBody"); const c = $("#asmCharCount");
  if (!ta || !c) return;
  c.textContent = `${ta.value.length} / 500`;
}

// Tulis 1 pesan ke inbox `username`. Idempoten per-thread (cari thread by name = admin's username).
function deliverAdminMessage(username, text) {
  const key = `playly-state-${username}`;
  let s;
  try { s = JSON.parse(localStorage.getItem(key)); } catch { s = null; }
  if (!s) {
    // User belum punya state — buat shell minimal supaya pesan tidak hilang
    s = { messages: [] };
  }
  if (!Array.isArray(s.messages)) s.messages = [];

  const senderName = user?.username || "admin";
  const senderInit = (user?.name || senderName).slice(0, 2).toUpperCase();

  let thread = s.messages.find(m => m.name === senderName);
  if (!thread) {
    thread = {
      name: senderName, init: senderInit, isAdmin: true,
      preview: "", time: "baru", ts: Date.now(), unread: false, online: true, history: []
    };
    s.messages.unshift(thread);
  } else {
    // Pastikan thread ditandai sebagai admin & pindahkan ke atas
    thread.isAdmin = true;
    s.messages = [thread, ...s.messages.filter(m => m !== thread)];
  }
  const now = Date.now();
  thread.history.push({ from: "them", text, time: "baru", ts: now, isAdmin: true });
  thread.preview = text.length > 60 ? text.slice(0, 57) + "..." : text;
  thread.time = "baru";
  thread.ts = now;
  thread.unread = true;

  localStorage.setItem(key, JSON.stringify(s));

  // Kalau user yang sedang login adalah penerima (misal admin uji coba di tab sama),
  // refresh in-memory state agar UI live ikut update.
  if (user && user.username === username && Array.isArray(state?.messages)) {
    state.messages = s.messages;
    if (typeof renderMsgList === "function") renderMsgList();
  }
}

// Catat aksi kirim ke log audit admin
function logAdminMessageSent(targets, text) {
  const KEY = "playly-admin-sent";
  let log = [];
  try { log = JSON.parse(localStorage.getItem(KEY) || "[]"); } catch {}
  log.unshift({
    id: Date.now(),
    targets: targets.slice(0, 50),
    targetCount: targets.length,
    text: text.slice(0, 200),
    sentAt: new Date().toISOString(),
    by: user?.username || "admin"
  });
  localStorage.setItem(KEY, JSON.stringify(log.slice(0, 200)));
}

$("#asmBody")?.addEventListener("input", updateAsmCharCount);

$$(".asm-tpl").forEach(btn => {
  btn.addEventListener("click", () => {
    const tpl = btn.dataset.asmTpl;
    $$(".asm-tpl").forEach(b => b.classList.toggle("active", b === btn));
    const content = ADMIN_MSG_TEMPLATES[tpl] ?? "";
    $("#asmBody").value = content;
    updateAsmCharCount();
    $("#asmBody").focus();
  });
});

$("#asmSendBtn")?.addEventListener("click", () => {
  const text = $("#asmBody").value.trim();
  if (!text) return toast("⚠️ Pesan kosong", "warning");
  if (!__asmTargets.length) return;

  __asmTargets.forEach(u => deliverAdminMessage(u, text));
  logAdminMessageSent(__asmTargets, text);

  const n = __asmTargets.length;
  const eventLabel = __asmIsBroadcast
    ? `📢 Broadcast pesan ke <b>${n} user</b>`
    : n === 1
      ? `Kirim pesan ke <b>@${__asmTargets[0]}</b>`
      : `Kirim pesan ke <b>${n} user</b>`;
  pushAdminEvent("📨", eventLabel);
  renderAdminLiveFeed();

  toast(__asmIsBroadcast
    ? `📢 Broadcast terkirim ke <b>${n} user</b>`
    : n === 1
      ? `📨 Pesan terkirim ke <b>@${__asmTargets[0]}</b>`
      : `📨 Pesan terkirim ke <b>${n} user</b>`, "success");

  $("#adminSendMsgModal").classList.remove("show");
  __asmTargets = [];
  __asmIsBroadcast = false;
});

$("#adminBroadcastBtn")?.addEventListener("click", () => {
  openAdminSendMsg({ broadcast: true });
});

// =================== ANALYTICS & MONITORING ===================
// Aggregate metrics dari getPlatformVideos(): total views, watch time,
// bandwidth, traffic harian, top videos. Tidak ada tracking real-time
// karena tidak ada backend — angka diturunkan dari data video yang sungguh
// ada di localStorage agar konsisten & tidak menyesatkan.

const anState = { range: "day" };

function anParseDuration(d) {
  if (!d) return 0;
  const parts = String(d).split(":").map(Number);
  if (parts.some(isNaN)) return 0;
  if (parts.length === 2) return parts[0] * 60 + parts[1];
  if (parts.length === 3) return parts[0] * 3600 + parts[1] * 60 + parts[2];
  return 0;
}

function anFormatBytes(bytes) {
  if (bytes < 1024) return Math.round(bytes) + " B";
  if (bytes < 1024 ** 2) return (bytes / 1024).toFixed(1) + " KB";
  if (bytes < 1024 ** 3) return (bytes / 1024 ** 2).toFixed(1) + " MB";
  if (bytes < 1024 ** 4) return (bytes / 1024 ** 3).toFixed(2) + " GB";
  return (bytes / 1024 ** 4).toFixed(2) + " TB";
}

function anFormatWatchTime(sec) {
  if (sec <= 0) return "0";
  if (sec < 60) return Math.floor(sec) + "s";
  if (sec < 3600) return Math.floor(sec / 60) + "m";
  if (sec < 86400) return (sec / 3600).toFixed(1) + "h";
  if (sec < 604800) return (sec / 86400).toFixed(1) + "d";
  return (sec / 604800).toFixed(1) + "w";
}

function anComputeMetrics() {
  const videos = getPlatformVideos();
  const totalViews = videos.reduce((s, v) => s + (v.viewsNum || 0), 0);
  const totalLikes = videos.reduce((s, v) => s + (v.likes || 0), 0);
  // Watch time = views × duration × avg retention (60%)
  const totalWatchSec = videos.reduce((s, v) => s + (v.viewsNum || 0) * anParseDuration(v.duration) * 0.6, 0);
  // Bandwidth = views × duration × avg bitrate (~3.5 Mbps untuk 720p)
  const bandwidthBytes = videos.reduce((s, v) => s + (v.viewsNum || 0) * anParseDuration(v.duration) * (3.5 * 1e6 / 8), 0);
  // Engagement = likes / views (real ratio, no random multiplier)
  const engagementPct = totalViews > 0 ? (totalLikes / totalViews) * 100 : 0;
  return { videos, totalViews, totalLikes, totalWatchSec, bandwidthBytes, engagementPct };
}

function renderAnKPIs() {
  const m = anComputeMetrics();
  setKPI($("#anKpiTotalViews"), fmtNum(m.totalViews));
  $("#anKpiWatchTime") && ($("#anKpiWatchTime").textContent = anFormatWatchTime(m.totalWatchSec));
  $("#anKpiBandwidth") && ($("#anKpiBandwidth").textContent = anFormatBytes(m.bandwidthBytes));
  $("#anKpiEngagement") && ($("#anKpiEngagement").textContent = `${m.engagementPct.toFixed(1)}%`);
  $("#anKpiEngagementSub") && ($("#anKpiEngagementSub").textContent =
    m.totalViews > 0 ? `${fmtNum(m.totalLikes)} likes ÷ ${fmtNum(m.totalViews)} views` : "likes ÷ views");
  $("#anKpiTotalSub") && ($("#anKpiTotalSub").textContent = m.videos.length ? `dari ${m.videos.length} video` : "global");
}

// =================== KPI DETAIL MODAL ===================
// Klik kartu KPI di Analytics / Revenue → modal breakdown.
// Provider mengembalikan { icon, title, desc, value, valueSub, rows[], jump? }.
// rows[] elemen bisa: { type:"row", label, value } | { type:"section", label }
//                   | { type:"bar", label, value, pct }

function _kpiTopVideos(videos, key, fmtVal, limit = 5) {
  return [...videos]
    .filter(v => (v[key] || 0) > 0)
    .sort((a, b) => (b[key] || 0) - (a[key] || 0))
    .slice(0, limit)
    .map(v => ({
      type: "row",
      label: (v.title || "Untitled").slice(0, 48),
      value: fmtVal(v[key] || 0)
    }));
}

const KPI_DETAIL_PROVIDERS = {
  "an-views": () => {
    const m = anComputeMetrics();
    const avg = m.videos.length ? m.totalViews / m.videos.length : 0;
    const rows = [
      { type: "row", label: "Jumlah video aktif", value: fmtNum(m.videos.length) },
      { type: "row", label: "Rata-rata per video", value: fmtNum(Math.round(avg)) },
      { type: "row", label: "Total likes", value: fmtNum(m.totalLikes) },
    ];
    const top = _kpiTopVideos(m.videos, "viewsNum", fmtNum, 5);
    if (top.length) rows.push({ type: "section", label: "Top 5 video by views" }, ...top);
    return {
      icon: "👁️", title: "Total Views", desc: "Akumulasi views dari semua video di platform.",
      value: fmtNum(m.totalViews),
      valueSub: m.videos.length ? `dari ${m.videos.length} video` : "belum ada video",
      rows
    };
  },
  "an-watchtime": () => {
    const m = anComputeMetrics();
    const sec = m.totalWatchSec;
    const avgPerView = m.totalViews > 0 ? sec / m.totalViews : 0;
    const rows = [
      { type: "row", label: "Total (detik)", value: Math.round(sec).toLocaleString("id-ID") + " s" },
      { type: "row", label: "Total (menit)", value: (sec / 60).toFixed(0) + " menit" },
      { type: "row", label: "Total (jam)", value: (sec / 3600).toFixed(1) + " jam" },
      { type: "row", label: "Rata-rata per view", value: avgPerView > 0 ? avgPerView.toFixed(1) + " detik" : "—" },
      { type: "section", label: "Asumsi perhitungan" },
      { type: "row", label: "Avg retention", value: "60% durasi video" },
      { type: "row", label: "Formula", value: "views × durasi × 0.6" }
    ];
    return {
      icon: "⏱️", title: "Total Watch Time", desc: "Estimasi total durasi tonton (views × durasi × retention).",
      value: anFormatWatchTime(sec),
      valueSub: m.totalViews > 0 ? `dari ${fmtNum(m.totalViews)} views` : "belum ada views",
      rows
    };
  },
  "an-bandwidth": () => {
    const m = anComputeMetrics();
    const bytes = m.bandwidthBytes;
    const avgPerVideo = m.videos.length ? bytes / m.videos.length : 0;
    const rows = [
      { type: "row", label: "Total (byte)", value: Math.round(bytes).toLocaleString("id-ID") + " B" },
      { type: "row", label: "Total (MB)", value: (bytes / 1024 ** 2).toFixed(1) + " MB" },
      { type: "row", label: "Total (GB)", value: (bytes / 1024 ** 3).toFixed(2) + " GB" },
      { type: "row", label: "Rata-rata per video", value: anFormatBytes(avgPerVideo) },
      { type: "section", label: "Asumsi perhitungan" },
      { type: "row", label: "Bitrate rata-rata", value: "3.5 Mbps (720p)" },
      { type: "row", label: "Formula", value: "views × durasi × bitrate" }
    ];
    return {
      icon: "📡", title: "Bandwidth Estimasi", desc: "Estimasi konsumsi bandwidth dari semua views.",
      value: anFormatBytes(bytes),
      valueSub: m.videos.length ? `${m.videos.length} video, ${fmtNum(m.totalViews)} views` : "belum ada konsumsi",
      rows
    };
  },
  "an-engagement": () => {
    const m = anComputeMetrics();
    const rate = m.engagementPct;
    const rows = [
      { type: "row", label: "Total likes", value: fmtNum(m.totalLikes) },
      { type: "row", label: "Total views", value: fmtNum(m.totalViews) },
      { type: "row", label: "Rasio (likes / views)", value: rate.toFixed(2) + "%" },
      { type: "section", label: "Benchmark industri" },
      { type: "row", label: "Excellent", value: "≥ 6%" },
      { type: "row", label: "Good", value: "3% – 6%" },
      { type: "row", label: "Average", value: "1% – 3%" }
    ];
    if (m.videos.length) {
      const top = [...m.videos]
        .filter(v => (v.viewsNum || 0) > 0)
        .map(v => ({ ...v, _eng: ((v.likes || 0) / (v.viewsNum || 1)) * 100 }))
        .sort((a, b) => b._eng - a._eng)
        .slice(0, 5)
        .map(v => ({ type: "row", label: (v.title || "Untitled").slice(0, 48), value: v._eng.toFixed(1) + "%" }));
      if (top.length) rows.push({ type: "section", label: "Top 5 video engagement" }, ...top);
    }
    return {
      icon: "❤️", title: "Engagement Rate", desc: "Rasio likes terhadap views — indikator kualitas konten.",
      value: rate.toFixed(1) + "%",
      valueSub: m.totalViews > 0 ? `${fmtNum(m.totalLikes)} likes ÷ ${fmtNum(m.totalViews)} views` : "belum ada data",
      rows
    };
  },
  "rev-total": () => {
    const r = computeRevenueFromLedger();
    const adsPct = r.total > 0 ? (r.ads / r.total) * 100 : 0;
    const subPct = r.total > 0 ? (r.sub / r.total) * 100 : 0;
    const rows = [];
    if (r.isEmpty) {
      rows.push({ type: "row", label: "Status", value: "No transactions yet" });
    } else {
      rows.push(
        { type: "row", label: "Total transaksi", value: r.ledger.length.toLocaleString("id-ID") },
        { type: "section", label: "Breakdown sumber" },
        { type: "bar", label: "Iklan (Ads)", value: fmtRp(r.ads), pct: adsPct },
        { type: "bar", label: "Subscription", value: fmtRp(r.sub), pct: subPct },
        { type: "section", label: "Distribusi" },
        { type: "row", label: "Platform (65%)", value: fmtRp(r.total - r.payout) },
        { type: "row", label: "Creator payout (35%)", value: fmtRp(r.payout) }
      );
    }
    return {
      icon: "💰", title: "Total Revenue", desc: "Akumulasi pendapatan dari ledger transaksi.",
      value: fmtRp(r.total),
      valueSub: r.isEmpty ? "menunggu transaksi pertama" : `${r.ledger.length} transaksi tercatat`,
      rows
    };
  },
  "rev-today": () => {
    const r = computeRevenueFromLedger();
    const todayStart = new Date().setHours(0, 0, 0, 0);
    const todayLedger = r.ledger.filter(l => l.ts >= todayStart);
    const todayAds = todayLedger.filter(l => (l.type || "").toLowerCase() === "ads")
      .reduce((s, l) => s + (Number(l.amount) || 0), 0);
    const todaySub = todayLedger.filter(l => ["sub", "subscription"].includes((l.type || "").toLowerCase()))
      .reduce((s, l) => s + (Number(l.amount) || 0), 0);
    const sharePct = r.total > 0 ? (r.today / r.total) * 100 : 0;
    const adsPct = r.today > 0 ? (todayAds / r.today) * 100 : 0;
    const subPct = r.today > 0 ? (todaySub / r.today) * 100 : 0;
    const rows = [];
    if (r.today <= 0) {
      rows.push({ type: "row", label: "Status", value: "No transactions today" });
    } else {
      rows.push(
        { type: "row", label: "Transaksi hari ini", value: todayLedger.length.toLocaleString("id-ID") },
        { type: "row", label: "% dari total revenue", value: sharePct.toFixed(1) + "%" },
        { type: "section", label: "Sumber hari ini" },
        { type: "bar", label: "Iklan", value: fmtRp(todayAds), pct: adsPct },
        { type: "bar", label: "Subscription", value: fmtRp(todaySub), pct: subPct }
      );
    }
    return {
      icon: "📅", title: "Pendapatan Hari Ini", desc: "Akumulasi sejak pukul 00:00 hari ini.",
      value: fmtRp(r.today),
      valueSub: r.today > 0 ? `${todayLedger.length} transaksi sejak 00:00` : "sejak 00:00",
      rows
    };
  },
  "rev-rate": () => {
    const r = computeRevenueFromLedger();
    const fiveMinAgo = Date.now() - 5 * 60 * 1000;
    const recent = r.ledger.filter(l => l.ts >= fiveMinAgo);
    const recentSum = recent.reduce((s, l) => s + (Number(l.amount) || 0), 0);
    const projHour = r.rate * 60;
    const projDay = r.rate * 60 * 24;
    const rows = [];
    if (r.rate <= 0) {
      rows.push(
        { type: "row", label: "Status", value: "No transactions in last 5 minutes" },
        { type: "row", label: "Window pengukuran", value: "5 menit terakhir" }
      );
    } else {
      rows.push(
        { type: "row", label: "Transaksi (5 menit terakhir)", value: recent.length.toLocaleString("id-ID") },
        { type: "row", label: "Total (5 menit terakhir)", value: fmtRp(recentSum) },
        { type: "section", label: "Proyeksi (asumsi rate konstan)" },
        { type: "row", label: "Per jam", value: fmtRp(projHour) },
        { type: "row", label: "Per 24 jam", value: fmtRp(projDay) }
      );
    }
    return {
      icon: "⚡", title: "Earnings Rate", desc: "Rata-rata pendapatan per menit dari transaksi 5 menit terakhir.",
      value: `${fmtRp(r.rate)}/menit`,
      valueSub: r.rate > 0 ? "diukur dari 5 menit terakhir" : "menunggu transaksi",
      rows
    };
  },
  "rev-payout": () => {
    const r = computeRevenueFromLedger();
    const platform = r.total - r.payout;
    const platformPct = r.total > 0 ? (platform / r.total) * 100 : 65;
    const payoutPct = r.total > 0 ? (r.payout / r.total) * 100 : 35;
    const rows = [
      { type: "section", label: "Pembagian revenue" },
      { type: "bar", label: "Platform (65%)", value: fmtRp(platform), pct: platformPct },
      { type: "bar", label: "Creator payout (35%)", value: fmtRp(r.payout), pct: payoutPct },
      { type: "section", label: "Skema kontrak" },
      { type: "row", label: "Share kreator", value: "35% dari revenue total" },
      { type: "row", label: "Share platform", value: "65% (operasional + margin)" },
      { type: "row", label: "Basis perhitungan", value: "Revenue ledger × 0.35" }
    ];
    return {
      icon: "🏦", title: "Creator Payouts", desc: "Estimasi payout kreator berdasarkan share 35%.",
      value: fmtRp(r.payout),
      valueSub: r.total > 0 ? `dari total ${fmtRp(r.total)}` : "menunggu revenue",
      rows
    };
  }
};

function openKpiDetail(key) {
  const provider = KPI_DETAIL_PROVIDERS[key];
  const modal = $("#kpiDetailModal");
  if (!provider || !modal) return;
  const data = provider();
  $("#kpiDetailIcon").textContent = data.icon || "📊";
  $("#kpiDetailTitle").textContent = data.title || "—";
  $("#kpiDetailDesc").textContent = data.desc || "";
  $("#kpiDetailValue").textContent = data.value || "—";
  $("#kpiDetailValueSub").textContent = data.valueSub || "";
  const body = $("#kpiDetailBody");
  if (!data.rows || !data.rows.length) {
    body.innerHTML = `<div class="kpi-detail-empty">No data to display.</div>`;
  } else {
    body.innerHTML = data.rows.map(r => {
      if (r.type === "section") {
        return `<div class="kpi-detail-section">${escapeHtml(r.label)}</div>`;
      }
      if (r.type === "bar") {
        const pct = Math.max(0, Math.min(100, Number(r.pct) || 0));
        return `<div class="kpi-detail-bar">
          <div class="kpi-bar-row"><span>${escapeHtml(r.label)}</span><b>${escapeHtml(r.value)}</b></div>
          <div class="kpi-bar-track"><div class="kpi-bar-fill" style="width:${pct.toFixed(1)}%"></div></div>
        </div>`;
      }
      return `<div class="kpi-detail-row"><span>${escapeHtml(r.label)}</span><b>${escapeHtml(r.value)}</b></div>`;
    }).join("");
  }
  const jumpBtn = $("#kpiDetailJumpBtn");
  if (jumpBtn) {
    if (data.jump) {
      jumpBtn.hidden = false;
      jumpBtn.textContent = data.jumpLabel || "Lihat Selengkapnya";
      jumpBtn.dataset.jump = data.jump;
    } else {
      jumpBtn.hidden = true;
      delete jumpBtn.dataset.jump;
    }
  }
  modal.classList.add("show");
}

document.addEventListener("click", e => {
  const k = e.target.closest("[data-kpi]");
  if (!k) return;
  // Jangan trigger kalau klik berasal dari elemen interaktif di dalam card,
  // KECUALI kalau elemen itu sendiri yang punya data-kpi (mini-kpi pill).
  const inner = e.target.closest("a, button:not([data-close])");
  if (inner && inner !== k) return;
  e.preventDefault();
  openKpiDetail(k.dataset.kpi);
});
document.addEventListener("keydown", e => {
  if (e.key !== "Enter" && e.key !== " ") return;
  const k = e.target.closest?.("[data-kpi][role='button'], [data-kpi][tabindex]");
  if (!k) return;
  e.preventDefault();
  openKpiDetail(k.dataset.kpi);
});

// ----------- Daily traffic series (deterministic distribution dari real totalViews) -----------
// ============== Real-time view bucket tracking ==============
// Setiap kali totalViews bertambah, delta-nya dicatat ke bucket jam saat ini.
// First-run di-seed dari createdAt video (timestamp asli) supaya chart tidak kosong.
const VIEW_BUCKETS_KEY = "playly:viewBuckets";
const VIEW_LAST_TOTAL_KEY = "playly:viewLastTotal";

function _vbLoad() {
  try { return JSON.parse(localStorage.getItem(VIEW_BUCKETS_KEY) || "{}"); }
  catch { return {}; }
}
function _vbSave(b) {
  try { localStorage.setItem(VIEW_BUCKETS_KEY, JSON.stringify(b)); } catch {}
}
function _vbHourKey(d) {
  return `${d.getFullYear()}-${pad2(d.getMonth()+1)}-${pad2(d.getDate())}T${pad2(d.getHours())}`;
}
function _vbSeedFromVideos(buckets) {
  getPlatformVideos().forEach(v => {
    const ts = v.createdAt || (typeof v.id === "number" && v.id > 1e12 ? v.id : Date.now());
    const k = _vbHourKey(new Date(ts));
    buckets[k] = (buckets[k] || 0) + (v.viewsNum || 0);
  });
}
function tickViewBuckets() {
  const totalNow = getPlatformVideos().reduce((s, v) => s + (v.viewsNum || 0), 0);
  const lastRaw = localStorage.getItem(VIEW_LAST_TOTAL_KEY);
  const buckets = _vbLoad();
  if (lastRaw === null) {
    _vbSeedFromVideos(buckets);
    _vbSave(buckets);
  } else {
    const delta = totalNow - (parseInt(lastRaw, 10) || 0);
    if (delta > 0) {
      const k = _vbHourKey(new Date());
      buckets[k] = (buckets[k] || 0) + delta;
      _vbSave(buckets);
    }
  }
  try { localStorage.setItem(VIEW_LAST_TOTAL_KEY, String(totalNow)); } catch {}
}

function anGenSeries(range /*, totalViews */) {
  tickViewBuckets();
  const buckets = _vbLoad();
  const now = new Date();

  const sumDay = (d) => {
    const dp = `${d.getFullYear()}-${pad2(d.getMonth()+1)}-${pad2(d.getDate())}`;
    let s = 0;
    for (let h = 0; h < 24; h++) s += (buckets[`${dp}T${pad2(h)}`] || 0);
    return s;
  };

  // Hari ini — 24 jam, jam 00:00 → 23:00
  if (range === "day" || range === "24h") {
    const labels = [], values = [];
    const dp = `${now.getFullYear()}-${pad2(now.getMonth()+1)}-${pad2(now.getDate())}`;
    for (let h = 0; h < 24; h++) {
      labels.push(`${pad2(h)}:00`);
      values.push(buckets[`${dp}T${pad2(h)}`] || 0);
    }
    return { labels, values };
  }

  // Minggu ini — Senin → Minggu
  if (range === "week" || range === "7d") {
    const labels = [], values = [];
    const dayNames = ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"];
    // ISO week: Senin = day 1
    const dow = (now.getDay() + 6) % 7; // 0=Sen .. 6=Min
    const monday = new Date(now.getFullYear(), now.getMonth(), now.getDate() - dow);
    for (let i = 0; i < 7; i++) {
      const d = new Date(monday.getFullYear(), monday.getMonth(), monday.getDate() + i);
      labels.push(dayNames[i]);
      values.push(sumDay(d));
    }
    return { labels, values };
  }

  // Bulan ini — tanggal 1 → akhir bulan
  if (range === "month" || range === "30d") {
    const labels = [], values = [];
    const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
    for (let i = 1; i <= daysInMonth; i++) {
      const d = new Date(now.getFullYear(), now.getMonth(), i);
      labels.push(String(i));
      values.push(sumDay(d));
    }
    return { labels, values };
  }

  // Tahun ini — Jan → Dec/Des (localized)
  if (range === "year") {
    const monthNames = (typeof _chartLabels === "function")
      ? _chartLabels("yearly")
      : ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
    const labels = [], values = [];
    for (let m = 0; m < 12; m++) {
      labels.push(monthNames[m]);
      const daysInM = new Date(now.getFullYear(), m + 1, 0).getDate();
      let s = 0;
      for (let day = 1; day <= daysInM; day++) {
        s += sumDay(new Date(now.getFullYear(), m, day));
      }
      values.push(s);
    }
    return { labels, values };
  }

  // fallback — empty
  return { labels: [], values: [] };
}

function anRangeLabel(r) {
  if (r === "day"   || r === "24h") return "Today";
  if (r === "week"  || r === "7d")  return "This week";
  if (r === "month" || r === "30d") return "This month";
  if (r === "year")                  return "This year";
  return "Today";
}

// Legacy compat — older callers (anTrafficLegend) expect top + totalAll shape.
function anComputePerUserViews(limit = 5) {
  const { arr, totalViews } = anComputePerUserStats();
  const filtered = arr.filter(u => u.views > 0);
  const top = filtered.slice(0, limit);
  const restTotal = filtered.slice(limit).reduce((s, u) => s + u.views, 0);
  if (restTotal > 0) top.push({ name: "Other", views: restTotal, _rest: true });
  return { top, totalAll: totalViews };
}

// Aggregate views, followers, shares per creator across all platform videos.
// Returns ALL creators (no limit) sorted desc by total views, with each
// metric attached. Used to populate the per-user breakdown grid.
function anComputePerUserStats() {
  const videos = (typeof getPlatformVideos === "function") ? getPlatformVideos() : [];
  const grouped = {};
  videos.forEach(v => {
    const k = v.creator || "—";
    if (!grouped[k]) grouped[k] = { name: k, views: 0, shares: 0, videos: 0 };
    grouped[k].views += v.viewsNum || 0;
    grouped[k].videos += 1;
    try {
      if (typeof getShareCount === "function") {
        grouped[k].shares += getShareCount(v.id) || 0;
      }
    } catch {}
  });
  // Include accounts even tanpa video (jarang) — supaya "all users" benar-benar all
  try {
    if (typeof getAllAccounts === "function") {
      getAllAccounts().forEach(a => {
        if (!a.username || a.role === "admin") return;
        if (!grouped[a.username]) grouped[a.username] = { name: a.username, views: 0, shares: 0, videos: 0 };
      });
    }
  } catch {}
  // Followers count per user
  Object.values(grouped).forEach(c => {
    try { c.followers = (typeof getUserFollowers === "function" ? getUserFollowers(c.name) : []).length; }
    catch { c.followers = 0; }
  });
  const arr = Object.values(grouped).sort((a, b) => (b.views - a.views) || (b.followers - a.followers));
  const totalViews = arr.reduce((s, u) => s + u.views, 0);
  return { arr, totalViews };
}

// Render per-user mini graph panels — each user gets their own card showing
// views/followers/shares pills + sparkline (views trend over period).
// Now displays ALL users (not limited).
function renderAnPerUserCharts(series, periodTotal) {
  const wrap = document.getElementById("anPerUserCharts");
  if (!wrap) return;
  const { arr, totalViews } = anComputePerUserStats();
  if (!arr.length) {
    wrap.innerHTML = `<div class="an-per-user-empty muted">No users yet.</div>`;
    return;
  }
  const palette = ["#A4C0E0","#7DA3CC","#CFDDEA","#E8D8C4","#C7B7A3","#7A5C45","#3a425e","#5a6378","#94A3B8","#475569"];
  const safeSeries = (series && series.values && series.values.length)
    ? series
    : { values: [0,0,0,0,0,0,0] };

  wrap.innerHTML = `
    <div class="an-per-user-head">
      <span>📊 All Users · ${arr.length}</span>
      <span class="muted">${anRangeLabel(anState.range)}</span>
    </div>
    <div class="an-per-user-grid">
      ${arr.map((u, i) => {
        const color = palette[i % palette.length];
        const init = String(u.name || "U").slice(0, 2).toUpperCase();
        return `
          <div class="an-per-user-card" data-username="${escapeHtml(u.name)}">
            <div class="an-per-user-head-row">
              <div class="an-per-user-avatar" style="background:${color}">
                <span>${escapeHtml(init)}</span>
              </div>
              <div class="an-per-user-meta">
                <strong>@${escapeHtml(u.name)}</strong>
                <small>${u.videos} ${u.videos === 1 ? "video" : "videos"}</small>
              </div>
            </div>
            <div class="an-per-user-pills">
              <span class="an-per-user-pill" title="Views">
                <i>👁️</i><b>${fmtNum(u.views)}</b><em>views</em>
              </span>
              <span class="an-per-user-pill" title="Followers">
                <i>👥</i><b>${fmtNum(u.followers)}</b><em>followers</em>
              </span>
              <span class="an-per-user-pill" title="Shares">
                <i>↗</i><b>${fmtNum(u.shares)}</b><em>shares</em>
              </span>
            </div>
            <svg class="an-per-user-svg" viewBox="0 0 200 80" preserveAspectRatio="none"
                 data-an-user-svg="${i}" data-color="${color}"></svg>
          </div>`;
      }).join("")}
    </div>
  `;

  // Render mini line chart untuk tiap user (scale platform series by user's view share)
  arr.forEach((u, i) => {
    const svg = wrap.querySelector(`[data-an-user-svg="${i}"]`);
    if (!svg) return;
    const share = totalViews > 0 ? (u.views / totalViews) : 0;
    const values = safeSeries.values.map(v => v * share);
    drawMiniLineChart(svg, values, palette[i % palette.length]);
  });

  // Klik card → buka profil user
  wrap.querySelectorAll(".an-per-user-card[data-username]").forEach(card => {
    card.style.cursor = "pointer";
    card.addEventListener("click", () => {
      if (typeof openUserProfile === "function") openUserProfile(card.dataset.username);
    });
  });
}

// Draw a simple mini line chart (no axes, no labels, no tooltip) for per-user
// panels. svg viewBox 200x80, padding 4px. (kpiSpark7 dihapus 2026-05-19 —
// sparkline opsi A tidak dipakai; drawMiniLineChart tetap utk Grafik Per User.)
function drawMiniLineChart(svg, values, color) {
  if (!svg || !values || !values.length) return;
  const W = 200, H = 80, PAD = 4;
  const max = Math.max(...values, 0.0001);
  const n = values.length;
  const stepX = (W - PAD * 2) / Math.max(1, n - 1);
  const innerH = H - PAD * 2;
  const points = values.map((v, i) => [PAD + i * stepX, H - PAD - (v / max) * innerH]);
  const path = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p[0].toFixed(1)} ${p[1].toFixed(1)}`).join(" ");
  const lastX = points[n - 1][0];
  const firstX = points[0][0];
  const area = `${path} L ${lastX.toFixed(1)} ${H - PAD} L ${firstX.toFixed(1)} ${H - PAD} Z`;
  const gradId = "anUserG" + Math.random().toString(36).slice(2, 8);
  // Approximate stroke length untuk draw animation
  let pathLen = 0;
  for (let i = 1; i < points.length; i++) {
    const dx = points[i][0] - points[i-1][0];
    const dy = points[i][1] - points[i-1][1];
    pathLen += Math.sqrt(dx*dx + dy*dy);
  }
  // Disamakan dgn Grafik Trafik (req user 2026-05-18): palet admin
  // navy→slate-blue, animasi draw-in + titik ujung berdenyut real-time.
  const lp = points[n - 1];
  svg.innerHTML = `
    <defs>
      <linearGradient id="${gradId}L" x1="0" y1="0" x2="1" y2="0">
        <stop offset="0%" stop-color="#3C5078"/>
        <stop offset="100%" stop-color="#9DB4DA"/>
      </linearGradient>
      <linearGradient id="${gradId}" x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stop-color="#5B7BB4" stop-opacity="0.34"/>
        <stop offset="100%" stop-color="#5B7BB4" stop-opacity="0"/>
      </linearGradient>
    </defs>
    <path class="chart-area-anim" d="${area}" fill="url(#${gradId})"/>
    <path class="chart-line-anim" d="${path}" fill="none" stroke="url(#${gradId}L)" stroke-width="1.8" stroke-linejoin="round" stroke-linecap="round" style="stroke-dasharray:${pathLen.toFixed(0)};stroke-dashoffset:${pathLen.toFixed(0)};--chart-len:${pathLen.toFixed(0)}"/>
    <circle cx="${lp[0].toFixed(1)}" cy="${lp[1].toFixed(1)}" r="2.6" fill="url(#${gradId}L)">
      <animate attributeName="r" values="2.6;4.6;2.6" dur="1.6s" repeatCount="indefinite"/>
      <animate attributeName="opacity" values="1;.4;1" dur="1.6s" repeatCount="indefinite"/>
    </circle>
  `;
}

function renderAnTrafficLegend(periodTotal) {
  const el = document.getElementById("anTrafficLegend");
  if (!el) return;
  const { top, totalAll } = anComputePerUserViews(5);
  if (!top.length || totalAll === 0) {
    el.innerHTML = `<div class="an-traffic-legend-empty">No views per user for this period yet.</div>`;
    return;
  }
  // Scale per-user views to this period's total so the legend reflects the chart.
  // (We don't have per-user-per-hour buckets, so use the user's overall share.)
  const factor = (totalAll > 0 && periodTotal >= 0) ? (periodTotal / totalAll) : 0;
  const palette = ["#A4C0E0","#E8D8C4","#C7B7A3","#7A5C45","#561C24","#3a425e"];
  const max = Math.max(...top.map(u => u.views), 1);
  el.innerHTML = `
    <div class="an-traffic-legend-head">
      <span>Distribution per user — top ${Math.min(5, top.length)}</span>
      <span class="muted">total ${fmtNum(Math.round(periodTotal))} views</span>
    </div>
    <div class="an-traffic-legend-list">
      ${top.map((u, i) => {
        const color = u._rest ? "#5a6378" : (palette[i] || "#A4C0E0");
        const pct = (u.views / max) * 100;
        const userPeriod = Math.round(u.views * factor);
        return `<div class="an-traffic-legend-row">
          <span class="an-tlg-dot" style="background:${color}"></span>
          <span class="an-tlg-name">${u._rest ? u.name : "@" + escapeHtml(u.name)}</span>
          <span class="an-tlg-bar"><i style="width:${pct.toFixed(1)}%;background:${color}"></i></span>
          <b class="an-tlg-val">${fmtNum(userPeriod)}</b>
        </div>`;
      }).join("")}
    </div>
  `;
}

// Common SVG chart drawing helpers
function anDrawAreaChart(svg, values, labels, opts = {}) {
  // Visual identik dengan user chart (drawChart): straight lines + all dots
  // dengan gradient stroke + area fill wine→cream + hover tooltip. Hanya
  // padding/H disesuaikan dengan container admin (240px vs user 200px).
  const wrap = svg.parentElement;
  const containerW = Math.max(600, Math.round(wrap?.offsetWidth || svg.clientWidth || 700));
  const W = containerW, H = 240;
  const PAD_L = opts.padL ?? 52, PAD_R = 20, PAD_T = 22, PAD_B = 40;
  svg.setAttribute("viewBox", `0 0 ${W} ${H}`);

  const rawMax = Math.max(...values, 1);
  const nice = niceYAxis(rawMax);
  const max = nice.max;
  const n = values.length;
  const stepX = (W - PAD_L - PAD_R) / Math.max(1, n - 1);
  const innerH = H - PAD_T - PAD_B;
  const points = values.map((v, i) => [PAD_L + i * stepX, H - PAD_B - (v / max) * innerH]);

  // Straight lines — match user chart (no bezier smoothing)
  const path = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p[0]} ${p[1]}`).join(" ");
  const lastX = points[n - 1][0];
  const firstX = points[0][0];
  const lastPt = points[n - 1];
  const area = `${path} L ${lastX} ${H - PAD_B} L ${firstX} ${H - PAD_B} Z`;
  // Panjang garis untuk animasi draw-in (real-time feel)
  let _pLen = 0;
  for (let i = 1; i < points.length; i++) {
    const dx = points[i][0] - points[i-1][0], dy = points[i][1] - points[i-1][1];
    _pLen += Math.sqrt(dx*dx + dy*dy);
  }
  const fmt = opts.yFmt || (v => fmtNum(Math.round(v)));

  let grid = "";
  for (let i = 0; i < nice.ticks.length; i++) {
    const tickVal = nice.ticks[i];
    const y = H - PAD_B - (tickVal / max) * innerH;
    grid += `<line x1="${PAD_L}" y1="${y}" x2="${W - PAD_R}" y2="${y}" stroke="rgba(160,172,196,.18)" stroke-dasharray="3,5"/>`;
    grid += `<text x="${PAD_L - 10}" y="${y + 4.5}" fill="rgba(205,213,228,.92)" font-size="13" font-weight="600" text-anchor="end" font-family="Inter">${fmt(tickVal)}</text>`;
  }

  // Label X — lebih besar & jelas, tidak terlalu rapat (≤7 label)
  let xLabels = "";
  const labelStep = Math.max(1, Math.ceil(n / 7));
  labels.forEach((l, i) => {
    if (i % labelStep !== 0 && i !== n - 1) return;
    xLabels += `<text x="${PAD_L + i * stepX}" y="${H - PAD_B + 22}" fill="rgba(205,213,228,.88)" font-size="12.5" font-weight="600" text-anchor="middle" font-family="Inter">${l}</text>`;
  });

  // ALL dots — sama persis kayak user chart, bukan cuma peak.
  const dotFill = getComputedStyle(document.body).getPropertyValue("--bg-elev").trim() || "#11131f";
  const gradId = opts.gradId || 'anG';
  let dots = "";
  points.forEach((p, i) => {
    dots += `<circle cx="${p[0]}" cy="${p[1]}" r="3.5" fill="${dotFill}" stroke="url(#${gradId})" stroke-width="2" data-i="${i}" class="an-traffic-dot" style="cursor:pointer;transition:r .2s"/>`;
  });

  // Wine→cream gradient (match user chart)
  // Palet admin (navy → slate-blue), modern + animasi draw-in real-time
  svg.innerHTML = `
    <defs>
      <linearGradient id="${gradId}" x1="0" y1="0" x2="1" y2="0">
        <stop offset="0%" stop-color="#3C5078"/>
        <stop offset="100%" stop-color="#9DB4DA"/>
      </linearGradient>
      <linearGradient id="${gradId}Fill" x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stop-color="#5B7BB4" stop-opacity=".34"/>
        <stop offset="100%" stop-color="#5B7BB4" stop-opacity="0"/>
      </linearGradient>
    </defs>
    ${grid}
    <path class="chart-area-anim" d="${area}" fill="url(#${gradId}Fill)"/>
    <path class="chart-line-anim" d="${path}" fill="none" stroke="url(#${gradId})" stroke-width="2.5" stroke-linejoin="round" stroke-linecap="round" style="stroke-dasharray:${_pLen.toFixed(0)};stroke-dashoffset:${_pLen.toFixed(0)};--chart-len:${_pLen.toFixed(0)}"/>
    <circle cx="${lastPt[0]}" cy="${lastPt[1]}" r="4" fill="url(#${gradId})">
      <animate attributeName="r" values="4;7;4" dur="1.6s" repeatCount="indefinite"/>
      <animate attributeName="opacity" values="1;.45;1" dur="1.6s" repeatCount="indefinite"/>
    </circle>
    ${dots}
    ${xLabels}
  `;

  // Hover tooltip — copy persis behavior dari user chart drawChart()
  const tip = wrap?.querySelector(".chart-tooltip");
  if (tip) {
    $$(".an-traffic-dot", svg).forEach((d, i) => {
      d.addEventListener("mouseenter", () => {
        d.setAttribute("r", "5");
        const rect = svg.getBoundingClientRect();
        const cx = +d.getAttribute("cx") * (rect.width / W);
        const cy = +d.getAttribute("cy") * (rect.height / H);
        tip.innerHTML = `<small>${labels[i]}</small><b>${fmt(values[i])}</b>`;
        tip.style.left = `${cx - tip.offsetWidth / 2}px`;
        tip.style.top = `${cy - tip.offsetHeight - 10}px`;
        tip.classList.add("show");
      });
      d.addEventListener("mouseleave", () => { d.setAttribute("r", "3.5"); tip.classList.remove("show"); });
    });
  }
}

// Nice Y-axis: hasilkan max dan tick array yang "manusiawi" — untuk nilai
// kecil pakai integer step 1, untuk besar pakai step 10/50/100/dst.
function niceYAxis(rawMax) {
  if (rawMax <= 4) {
    const m = Math.max(2, Math.ceil(rawMax));
    const ticks = [];
    for (let v = 0; v <= m; v++) ticks.push(v);
    return { max: m, ticks };
  }
  // Cari step terbesar dari [1, 2, 5] × 10^n yang menghasilkan ≤ 6 tick
  const targetTicks = 4;
  const rough = rawMax / targetTicks;
  const mag = Math.pow(10, Math.floor(Math.log10(rough)));
  const norm = rough / mag;
  let step;
  if (norm <= 1) step = 1 * mag;
  else if (norm <= 2) step = 2 * mag;
  else if (norm <= 5) step = 5 * mag;
  else step = 10 * mag;
  const max = Math.ceil(rawMax / step) * step;
  const ticks = [];
  for (let v = 0; v <= max; v += step) ticks.push(v);
  return { max, ticks };
}

// Buat smooth path dari array points pakai catmull-rom-ish bezier
function buildSmoothPath(points) {
  if (points.length < 2) return points.length === 1 ? `M ${points[0][0]} ${points[0][1]}` : "";
  let d = `M ${points[0][0]} ${points[0][1]}`;
  for (let i = 0; i < points.length - 1; i++) {
    const [x0, y0] = points[Math.max(0, i - 1)];
    const [x1, y1] = points[i];
    const [x2, y2] = points[i + 1];
    const [x3, y3] = points[Math.min(points.length - 1, i + 2)];
    const cp1x = x1 + (x2 - x0) / 6;
    const cp1y = y1 + (y2 - y0) / 6;
    const cp2x = x2 - (x3 - x1) / 6;
    const cp2y = y2 - (y3 - y1) / 6;
    d += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${x2} ${y2}`;
  }
  return d;
}

function anDrawBarChart(svg, values, labels, opts = {}) {
  const W = 700, H = 200, PAD_L = opts.padL ?? 50, PAD_R = 14, PAD_T = 16, PAD_B = 28;
  const max = Math.max(...values, 1) * 1.1;
  const n = values.length;
  const stepX = (W - PAD_L - PAD_R) / n;
  const barW = stepX * 0.65;
  const fmt = opts.yFmt || (v => fmtNum(Math.round(v)));

  let bars = "";
  values.forEach((v, i) => {
    const x = PAD_L + i * stepX + (stepX - barW) / 2;
    const h = (v / max) * (H - PAD_T - PAD_B);
    const y = H - PAD_B - h;
    bars += `<rect x="${x}" y="${y}" width="${barW}" height="${h}" fill="url(#anBwG)" rx="2"/>`;
  });
  let grid = "";
  for (let i = 0; i <= 3; i++) {
    const y = PAD_T + (i * (H - PAD_T - PAD_B) / 3);
    const val = max - (i * max / 3);
    grid += `<line x1="${PAD_L}" y1="${y}" x2="${W - PAD_R}" y2="${y}" stroke="rgba(140,150,180,.08)" stroke-dasharray="2,4"/>`;
    grid += `<text x="${PAD_L - 6}" y="${y + 3}" fill="rgba(140,150,180,.6)" font-size="9" text-anchor="end" font-family="Inter">${fmt(val)}</text>`;
  }
  let xLabels = "";
  const labelStep = n > 14 ? Math.ceil(n / 8) : 1;
  labels.forEach((l, i) => {
    if (i % labelStep !== 0 && i !== n - 1) return;
    xLabels += `<text x="${PAD_L + i * stepX + stepX / 2}" y="${H - PAD_B + 16}" fill="rgba(140,150,180,.6)" font-size="10" text-anchor="middle" font-family="Inter">${l}</text>`;
  });
  const isAdmin = document.body.dataset.role === "admin";
  const bwStops = isAdmin
    ? { a: "#A4C0E0", b: "#1B3A5C" }
    : { a: "#E8D8C4", b: "#561C24" };
  svg.innerHTML = `
    <defs>
      <linearGradient id="anBwG" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="${bwStops.a}"/><stop offset="100%" stop-color="${bwStops.b}"/></linearGradient>
    </defs>
    ${grid}${bars}${xLabels}
  `;
}

function drawAnTrafficChart() {
  const svg = $("#anTrafficChart"); if (!svg) return;
  const empty = $("#anTrafficEmpty");
  const m = anComputeMetrics();
  const series = anGenSeries(anState.range, m.totalViews);
  const total = series.values.reduce((s, v) => s + v, 0);
  $("#anTrafficTotal") && ($("#anTrafficTotal").textContent = `${fmtNum(total)} views`);
  $("#anTrafficSubtitle") && ($("#anTrafficSubtitle").textContent =
    `Views distribution per user — ${anRangeLabel(anState.range)}`);

  // Sync active tab styling for the new an-tab row
  document.querySelectorAll(".an-tab[data-an-range]").forEach(b => {
    const on = b.dataset.anRange === anState.range;
    b.classList.toggle("active", on);
    b.setAttribute("aria-selected", on ? "true" : "false");
  });

  if (m.totalViews === 0) {
    svg.innerHTML = "";
    if (empty) empty.hidden = false;
    renderAnTrafficLegend(0);
    renderAnPerUserCharts(null, 0);
    return;
  }
  if (empty) empty.hidden = true;
  anDrawAreaChart(svg, series.values, series.labels, { gradId: "anTrG" });
  renderAnTrafficLegend(total);
  renderAnPerUserCharts(series, total);
}

// Auto-redraw admin traffic chart saat container width berubah
// (window resize / sidebar collapse). viewBox dihitung dari container width
// sehingga tanpa observer, chart stuck di lebar lama.
(function setupAnTrafficResizeObserver() {
  const wrap = document.getElementById("anTrafficWrap");
  if (!wrap || !window.ResizeObserver) return;
  let lastW = 0;
  let raf = 0;
  const ro = new ResizeObserver(entries => {
    const w = Math.round(entries[0].contentRect.width);
    if (w === lastW || w < 100) return;
    lastW = w;
    cancelAnimationFrame(raf);
    raf = requestAnimationFrame(() => {
      if (state?.currentView === "admin-analytics") drawAnTrafficChart();
    });
  });
  ro.observe(wrap);
})();

function drawAnBandwidthChart() {
  const svg = $("#anBwChart"); if (!svg) return;
  const empty = $("#anBwEmpty");
  const m = anComputeMetrics();
  // Bandwidth per range = totalBytes × range_factor (estimasi linier).
  // 30d (1 bulan) = baseline 1.0; periode lain di-skala relatif terhadap itu.
  const rangeFactor = ({
    "day":   1 / 30,
    "24h":   1 / 30,
    "week":  7 / 30,
    "7d":    7 / 30,
    "month": 1,
    "30d":   1,
    "year":  12,
  })[anState.range] ?? 1;
  const totalBwForRange = m.bandwidthBytes * rangeFactor;
  const series = anGenSeries(anState.range, m.totalViews);
  const sumViews = series.values.reduce((s, v) => s + v, 0) || 1;
  // Distribusikan bandwidth proporsional dengan distribusi traffic
  const bwSeries = series.values.map(v => totalBwForRange * v / sumViews);
  $("#anBwTotal") && ($("#anBwTotal").textContent = anFormatBytes(totalBwForRange));
  $("#anBwSubtitle") && ($("#anBwSubtitle").textContent = `Estimasi CDN • ${anRangeLabel(anState.range)}`);

  if (m.totalViews === 0) {
    svg.innerHTML = "";
    if (empty) empty.hidden = false;
    return;
  }
  if (empty) empty.hidden = true;
  anDrawBarChart(svg, bwSeries, series.labels, { yFmt: anFormatBytes });
}

// ----------- Top videos & creators -----------
function renderAnTopVideos() {
  const allVideos = getPlatformVideos();
  renderAnTopVideosList(allVideos);
  renderAnTopCreatorsList(allVideos);
}

function renderAnTopVideosList(allVideos) {
  const list = $("#anTopList"); if (!list) return;
  const videos = allVideos.slice(0, 10);
  if (!videos.length) {
    list.innerHTML = `<div class="an-empty"><div class="an-empty-icon">🎬</div><h4>Belum ada video</h4><p>Top 10 akan muncul setelah ada video di platform.</p></div>`;
    return;
  }
  const maxViews = Math.max(...videos.map(v => v.viewsNum || 0), 1);
  list.innerHTML = videos.map((v, i) => {
    const pct = ((v.viewsNum || 0) / maxViews) * 100;
    const cat = CATEGORIES.find(c => c.key === v.category);
    return `<div class="an-top-row">
      <span class="an-rank rank-${i + 1}">${i + 1}</span>
      <div class="an-top-thumb"><img src="${v.thumb}" alt=""/></div>
      <div class="an-top-info">
        <strong>${escapeHtml(v.title || t("video.untitled"))}</strong>
        <small>@${escapeHtml(v.creator || "—")} • ${cat ? cat.emoji + " " + cat.label : "—"} • ${v.duration || "0:00"}</small>
        <div class="an-top-bar"><div class="an-top-bar-fill" style="width:${pct.toFixed(1)}%"></div></div>
      </div>
      <div class="an-top-stats">
        <b>${fmtNum(v.viewsNum || 0)}</b><small>views</small>
      </div>
    </div>`;
  }).join("");
}

function renderAnTopCreatorsList(allVideos) {
  const list = $("#anTopCreatorsList"); if (!list) return;
  // Group videos by creator → sum views, count videos & likes
  const grouped = {};
  allVideos.forEach(v => {
    const k = v.creator || "—";
    grouped[k] = grouped[k] || { name: k, videos: 0, views: 0, likes: 0 };
    grouped[k].videos++;
    grouped[k].views += v.viewsNum || 0;
    grouped[k].likes += v.likes || 0;
  });
  const creators = Object.values(grouped).sort((a, b) => b.views - a.views).slice(0, 10);

  if (!creators.length) {
    list.innerHTML = `<div class="an-empty"><div class="an-empty-icon">👤</div><h4>Belum ada kreator</h4><p>Top creators akan muncul setelah ada video.</p></div>`;
    return;
  }
  const maxViews = Math.max(...creators.map(c => c.views), 1);
  list.innerHTML = creators.map((c, i) => {
    const pct = (c.views / maxViews) * 100;
    const init = c.name.slice(0, 2).toUpperCase();
    return `<div class="an-top-row">
      <span class="an-rank rank-${i + 1}">${i + 1}</span>
      <div class="an-top-thumb an-creator-avatar"><span>${escapeHtml(init)}</span></div>
      <div class="an-top-info">
        <strong>@${escapeHtml(c.name)}</strong>
        <small>${c.videos} video • ${fmtNum(c.likes)} likes</small>
        <div class="an-top-bar"><div class="an-top-bar-fill" style="width:${pct.toFixed(1)}%"></div></div>
      </div>
      <div class="an-top-stats">
        <b>${fmtNum(c.views)}</b><small>views</small>
      </div>
    </div>`;
  }).join("");
}

// ----------- Achievement User: 3 kolom (Top Likes / Top Followers / Top Views) -----------
function renderAnUserAchievement(allVideos) {
  const wrap = $("#anUserAchievement");
  if (!wrap) return;
  // Aggregate per creator: total likes, total views, follower count via getUserFollowers
  const grouped = {};
  allVideos.forEach(v => {
    const k = v.creator || "—";
    grouped[k] = grouped[k] || { name: k, videos: 0, views: 0, likes: 0 };
    grouped[k].videos++;
    grouped[k].views += v.viewsNum || 0;
    grouped[k].likes += v.likes || 0;
  });
  // Tambahkan creator yang punya follower tapi belum upload (jarang tapi mungkin)
  try {
    if (typeof getAllAccounts === "function") {
      getAllAccounts().forEach(a => {
        if (!a.username || a.role === "admin") return;
        if (!grouped[a.username]) grouped[a.username] = { name: a.username, videos: 0, views: 0, likes: 0 };
      });
    }
  } catch {}
  // Hitung follower per creator
  Object.values(grouped).forEach(c => {
    try { c.followers = (typeof getUserFollowers === "function" ? getUserFollowers(c.name) : []).length; }
    catch { c.followers = 0; }
  });
  const arr = Object.values(grouped);
  const initOf = (name) => String(name || "U").slice(0, 2).toUpperCase();
  const fillCol = (id, sortKey, valFmt, metaFn) => {
    const el = document.getElementById(id);
    if (!el) return;
    const sorted = arr.slice().sort((a, b) => (b[sortKey] || 0) - (a[sortKey] || 0)).slice(0, 5);
    if (!sorted.length || sorted.every(c => !(c[sortKey] || 0))) {
      el.innerHTML = `<div style="padding:14px 8px;text-align:center;color:var(--muted);font-size:11px">Belum ada data.</div>`;
      return;
    }
    el.innerHTML = sorted.map((c, i) => `
      <div class="an-user-row" data-username="${escapeHtml(c.name)}">
        <span class="an-user-rank">${i + 1}</span>
        <div class="an-user-avatar"><span>${escapeHtml(initOf(c.name))}</span></div>
        <div class="an-user-info">
          <div class="an-user-name">@${escapeHtml(c.name)}</div>
          <div class="an-user-meta">${metaFn(c)}</div>
        </div>
        <div class="an-user-value">${valFmt(c[sortKey] || 0)}</div>
      </div>`).join("");
    // Klik baris → buka profil user
    el.querySelectorAll("[data-username]").forEach(row => {
      row.style.cursor = "pointer";
      row.addEventListener("click", () => {
        if (typeof openUserProfile === "function") openUserProfile(row.dataset.username);
      });
    });
  };
  fillCol("anUserTopLikes",     "likes",     v => fmtNum(v) + " ❤️", c => `${c.videos} video`);
  fillCol("anUserTopFollowers", "followers", v => fmtNum(v) + " 👥", c => `${c.videos} video • ${fmtNum(c.likes)} likes`);
  fillCol("anUserTopViews",     "views",     v => fmtNum(v) + " 👁️", c => `${c.videos} video • ${fmtNum(c.likes)} likes`);
}

// ----------- Master render & lifecycle -----------
function renderAdminAnalytics() {
  renderAnKPIs();
  drawAnTrafficChart();
  drawAnBandwidthChart();
  renderAnTopVideos();
  // Achievement User 3-kolom — kalau wrap ada, populate
  if (document.getElementById("anUserAchievement")) {
    try { renderAnUserAchievement(getPlatformVideos()); } catch {}
  }
}

(function setupAnalyticsEvents() {
  if (window.__analyticsBound) return;
  window.__analyticsBound = true;
  // 4 period tabs (Hari ini / Minggu ini / Bulan ini / Tahun ini)
  document.addEventListener("click", e => {
    const tab = e.target.closest(".an-tab[data-an-range]");
    if (!tab) return;
    const r = tab.dataset.anRange;
    if (!r || r === anState.range) return;
    anState.range = r;
    drawAnTrafficChart();
    drawAnBandwidthChart();
  });
})();

// =================== GLOBAL VIDEO CONTROL ===================
// Aggregates videos from all `playly-state-{username}` records, lets admin
// approve/reject/edit/takedown/delete and bulk-act on them.

// C-3 V-M6 fix (2026-05-21): persist filter/search/sort ke sessionStorage
// supaya admin tidak kehilangan context saat reload / pindah view.
// `selected` (Set) dan `selectMode` tetap ephemeral (logical UI state).
const _ADMIN_VIDEO_STATE_KEY = "playly-admin-video-state";
function _loadAdminVideoState() {
  try {
    const raw = sessionStorage.getItem(_ADMIN_VIDEO_STATE_KEY);
    if (!raw) return null;
    const j = JSON.parse(raw);
    return {
      filter: j.filter || "all",
      search: j.search || "",
      category: j.category || "",
      sort: j.sort || "newest",
    };
  } catch { return null; }
}
function _saveAdminVideoState() {
  try {
    sessionStorage.setItem(_ADMIN_VIDEO_STATE_KEY, JSON.stringify({
      filter: adminVideoState.filter,
      search: adminVideoState.search,
      category: adminVideoState.category,
      sort: adminVideoState.sort,
    }));
  } catch {}
}
const _persistedAvs = _loadAdminVideoState();
const adminVideoState = {
  filter: _persistedAvs?.filter || "all",      // all | pending | published | rejected | takedown
  search: _persistedAvs?.search || "",
  category: _persistedAvs?.category || "",
  sort: _persistedAvs?.sort || "newest",
  selectMode: false,  // checkbox column hidden until admin opts in
  selected: new Set() // ids of selected videos
};

// Read all videos across every user's state, tagged with their owner key.
function getAllAdminVideos() {
  const out = [];
  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (!key || !key.startsWith("playly-state-")) continue;
    const username = key.slice("playly-state-".length);
    let s;
    try { s = JSON.parse(localStorage.getItem(key)); } catch { continue; }
    if (!s || !Array.isArray(s.myVideos)) continue;
    s.myVideos.forEach(v => {
      // C-4 V-L4 fix (2026-05-21): defensive — skip null/non-object entries
      // dan yang tidak punya id valid. Render template assume v.id exist;
      // tanpa guard ini, corrupt entry bisa muncul sebagai "undefined"
      // row + bikin patchAdminVideo find() return mismatched target.
      if (!v || typeof v !== "object" || v.id == null) return;
      out.push({ ...v, _ownerKey: key, _owner: username });
    });
  }
  return out;
}

// Update a single video by id inside its owner's playly-state record.
function patchAdminVideo(id, patch) {
  const all = getAllAdminVideos();
  const target = all.find(v => v.id === id);
  if (!target) return null;
  const s = JSON.parse(localStorage.getItem(target._ownerKey));
  const idx = (s.myVideos || []).findIndex(v => v.id === id);
  if (idx === -1) return null;
  // C-3 V-M2 fix (2026-05-21): set updatedAt timestamp di setiap patch
  // supaya cross-device merge bisa tie-break dgn benar (nanti kalau kita
  // tambah merge config utk playly-state-*). Sebelumnya tidak ada timestamp
  // → race condition antara admin device + user device meng-edit video
  // bersamaan = last-write-wins.
  const patchWithTs = { ...patch, updatedAt: Date.now() };
  Object.assign(s.myVideos[idx], patchWithTs);
  localStorage.setItem(target._ownerKey, JSON.stringify(s));
  // Also keep current session's in-memory state in sync if it's the logged-in user
  if (user && target._owner === user.username && Array.isArray(state?.myVideos)) {
    const liveIdx = state.myVideos.findIndex(v => v.id === id);
    if (liveIdx !== -1) Object.assign(state.myVideos[liveIdx], patchWithTs);
  }
  return s.myVideos[idx];
}

// Force-delete a video across all stores (state + IndexedDB blob + Supabase Storage).
// C-4 V-L3 fix (2026-05-21): function jadi async, IDB delete + cloud blob
// delete bisa di-await caller kalau perlu memastikan delete commit sebelum
// reload page (jika tidak di-await, masih fire-and-forget compatible).
async function deleteAdminVideo(id) {
  const all = getAllAdminVideos();
  const target = all.find(v => v.id === id);
  if (!target) return false;
  // v547 (2026-05-25): capture videoUrl SEBELUM filter supaya bisa pass ke
  // deleteVideoBlob — caller tahu R2 atau Supabase, dispatch tepat.
  const targetVideoUrl = target.videoUrl || null;
  let s;
  try { s = JSON.parse(localStorage.getItem(target._ownerKey)); } catch { return false; }
  if (!s) return false;
  s.myVideos = (s.myVideos || []).filter(v => v.id !== id);
  localStorage.setItem(target._ownerKey, JSON.stringify(s));
  if (user && target._owner === user.username && Array.isArray(state?.myVideos)) {
    state.myVideos = state.myVideos.filter(v => v.id !== id);
  }
  // Remove blob from IndexedDB — await supaya delete commit
  try {
    const db = await openVideoDB();
    await new Promise((resolve, reject) => {
      const tx = db.transaction(VIDEO_STORE, "readwrite");
      const req = tx.objectStore(VIDEO_STORE).delete(id);
      req.onsuccess = () => resolve();
      req.onerror = () => reject(req.error);
      // Safety timeout — jangan block forever
      setTimeout(() => resolve(), 3000);
    });
  } catch (err) { console.warn("[deleteAdminVideo] IDB delete failed:", err); }
  // CR-5 fix (2026-05-21): juga hapus video blob di cloud storage.
  // v547: pass videoUrl supaya dispatch R2 vs Supabase tepat.
  try {
    if (window.cloudSync?.deleteVideoBlob) {
      Promise.resolve(window.cloudSync.deleteVideoBlob(id, targetVideoUrl)).catch(() => {});
    }
  } catch {}
  return true;
}

function countAdminPendingVideos() {
  // Bug #6 fix (2026-05-20): selaras dgn getAdminVideoStatus yg default
  // ke "published" untuk missing adminStatus. Sebelumnya helper ini default
  // ke "pending" → badge stuck counting legacy videos yg admin tidak bisa
  // clear karena tab Pending tidak menampilkan mereka.
  return getAllAdminVideos().filter(v => v.adminStatus === "pending").length;
}

function getAdminVideoStatus(v) {
  // Status: pending (review) | published | takedown | draft.
  // C-2 H2 fix (2026-05-21): treat "rejected" as takedown (user library
  // alias), recognize "draft" sebagai bucket terpisah. Sebelumnya
  // anything non-pending/non-takedown jadi "published" → draft videos
  // muncul di Published tab + counted di KPI.
  if (v.adminStatus === "takedown" || v.adminStatus === "rejected") return "takedown";
  if (v.adminStatus === "pending") return "pending";
  if (v.adminStatus === "draft") return "draft";
  return "published";
}

function adminVideoStatusBadge(status) {
  const map = {
    pending:   { label: "Pending",   cls: "warn" },
    published: { label: "Published", cls: "ok" },
    takedown:  { label: "Takedown",  cls: "bad" }
  };
  const m = map[status] || map.published;
  return `<span class="gv-status ${m.cls}">${m.label}</span>`;
}

function renderAdminVideos() {
  const tbody = $("#adminVideoTbody"); if (!tbody) return;

  // Reflect select mode in DOM (CSS shows/hides the checkbox column).
  const section = $("section[data-view='admin-videos']");
  if (section) section.classList.toggle("gv-select-mode", adminVideoState.selectMode);
  const toggleBtn = $("#adminVideoSelectToggle");
  if (toggleBtn) {
    toggleBtn.classList.toggle("active", adminVideoState.selectMode);
    toggleBtn.textContent = adminVideoState.selectMode ? "✕ Batal Pilih" : "☑ Pilih";
  }

  const all = getAllAdminVideos();

  // Stats (always reflect totals, not filtered set)
  $("#gvStatTotal") && ($("#gvStatTotal").textContent = all.length);
  $("#gvStatPending") && ($("#gvStatPending").textContent = all.filter(v => getAdminVideoStatus(v) === "pending").length);
  $("#gvStatPublished") && ($("#gvStatPublished").textContent = all.filter(v => getAdminVideoStatus(v) === "published").length);
  $("#gvStatTakedown") && ($("#gvStatTakedown").textContent = all.filter(v => getAdminVideoStatus(v) === "takedown").length);

  // Apply filters
  let list = all.slice();
  if (adminVideoState.filter === "new") {
    // "New videos" — published & uploaded < 24 jam
    const cutoff = Date.now() - 24 * 60 * 60 * 1000;
    list = list.filter(v => getAdminVideoStatus(v) === "published"
      && Number(v.uploadedAt || v.createdAt || v.id || 0) > cutoff);
  } else if (adminVideoState.filter !== "all") {
    list = list.filter(v => getAdminVideoStatus(v) === adminVideoState.filter);
  }
  const q = (adminVideoState.search || "").toLowerCase().trim();
  if (q) {
    list = list.filter(v =>
      (v.title || "").toLowerCase().includes(q) ||
      (v.creator || "").toLowerCase().includes(q) ||
      (v.desc || "").toLowerCase().includes(q) ||
      (v.tags || "").toLowerCase().includes(q)
    );
  }

  // Sort
  const sorters = {
    newest: (a, b) => (b.id || 0) - (a.id || 0),
    oldest: (a, b) => (a.id || 0) - (b.id || 0),
    views:  (a, b) => (b.viewsNum || 0) - (a.viewsNum || 0),
    likes:  (a, b) => (b.likes || 0) - (a.likes || 0),
    title:  (a, b) => (a.title || "").localeCompare(b.title || "")
  };
  list.sort(sorters[adminVideoState.sort] || sorters.newest);

  const empty = $("#gvEmpty");
  if (!list.length) {
    tbody.innerHTML = "";
    if (empty) empty.hidden = false;
  } else {
    if (empty) empty.hidden = true;
    tbody.innerHTML = list.map(v => {
      const status = getAdminVideoStatus(v);
      const checked = adminVideoState.selected.has(v.id) ? "checked" : "";
      const thumb = v.thumb || "https://picsum.photos/seed/playly/120/72";
      return `<tr data-vid="${v.id}" class="${checked ? "gv-row-selected" : ""}">
        <td class="gv-col-check"><input type="checkbox" class="gv-row-check" ${checked}/></td>
        <td>
          <div class="gv-video-cell" data-gv-act="play" title="Play video">
            <div class="gv-thumb">
              <img src="${thumb}" alt=""/>
              <span class="gv-thumb-play">▶</span>
            </div>
            <div class="gv-video-meta">
              <strong title="${escapeHtml(v.title || "")}">${escapeHtml(v.title || t("video.untitled"))}</strong>
              <small>${escapeHtml(v.duration || "0:00")} • ${escapeHtml(v.visibility || "public")}</small>
            </div>
          </div>
        </td>
        <td><span class="gv-creator">@${escapeHtml(v.creator || v._owner || "—")}</span></td>
        <td>${fmtNum(v.viewsNum || 0)}</td>
        <td>${fmtNum(v.likes || 0)}</td>
        <td>${adminVideoStatusBadge(status)}</td>
        <td><small class="muted">${(() => {
          // Real-time relative timestamp dari upload time. Fallback ke v.time string
          // (legacy) atau v.id (yang juga Date.now() saat upload).
          const ts = Number(v.uploadedAt || v.createdAt || (typeof v.id === "number" && v.id > 1e12 ? v.id : 0));
          return ts ? relTime(ts) : escapeHtml(v.time || "—");
        })()}</small></td>
        <td>
          <div class="row-actions gv-actions">
            <button title="Play video" class="gv-act-play" data-gv-act="play" aria-label="Play video">
              <svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><path d="M8 5v14l11-7z"/></svg>
            </button>
            ${status === "pending"   ? `<button title="Publish" class="success" data-gv-act="publish">✅</button><button title="Takedown" class="danger" data-gv-act="takedown">⛔</button>`
              : status === "takedown" ? `<button title="Restore" data-gv-act="restore">↻</button>`
              : `<button title="Takedown" class="danger" data-gv-act="takedown">⛔</button>`}
            <button title="Edit metadata" data-gv-act="edit">✏️</button>
            <button title="Force delete" class="danger" data-gv-act="delete">🗑️</button>
          </div>
        </td>
      </tr>`;
    }).join("");
  }

  // Sync bulk bar
  updateGvBulkBar();
  syncAdminNavBadges();
}

function updateGvBulkBar() {
  const bar = $("#gvBulkBar"); if (!bar) return;
  const n = adminVideoState.selected.size;
  bar.hidden = !adminVideoState.selectMode || n === 0;
  const c = $("#gvSelectedCount"); if (c) c.textContent = n;
  const all = $("#gvSelectAll");
  if (all) {
    const rows = $$("#adminVideoTbody .gv-row-check").length;
    all.checked = rows > 0 && n >= rows;
    all.indeterminate = n > 0 && n < rows;
  }
}

function applyGvBulkAction(action) {
  const ids = [...adminVideoState.selected];
  if (!ids.length) return;
  const map = {
    takedown: { patch: { adminStatus: "takedown"  }, icon: "⛔", msg: "di-takedown" }
  };
  // C-2 H3 fix (2026-05-21): cache video records sebelum bulk action supaya
  // bisa notify creator per-video setelah mutasi. Sebelumnya bulk hanya
  // pushAdminEvent aggregate, creator tidak di-notify.
  const allVideos = (typeof getAllAdminVideos === "function") ? getAllAdminVideos() : [];
  const videoById = new Map(allVideos.map(v => [v.id, v]));

  if (action === "delete") {
    openConfirm({
      icon: "🗑️", iconClass: "danger",
      title: `Hapus ${ids.length} video?`,
      desc: `<b>${ids.length}</b> video akan dihapus permanen dari platform. Aksi ini tidak bisa dibatalkan.`,
      btnText: "Hapus Semua", btnClass: "danger",
      onConfirm: async () => {
        // C-2 H3: notify SEBELUM delete supaya creator info masih tersedia.
        // v538 HIGH FIX 1 (2026-05-25): await deleteAdminVideo sequentially.
        // Audit moderation H1: fire-and-forget bikin blob cleanup race —
        // admin sees "success" toast tapi IDB blob mungkin orphan kalau
        // delete promise reject. Sekarang Promise.all + log failures.
        const deletePromises = [];
        for (const id of ids) {
          const v = videoById.get(id);
          // v538: fallback creator → _owner (C3 pattern)
          const target = v && (v.creator || v._owner);
          if (v && target && typeof deliverNotification === "function") {
            try {
              deliverNotification(target, {
                type: "video-takedown",
                text: `🗑️ Video kamu <b>"${escapeHtml(v.title || t("video.untitled"))}"</b> dihapus permanen oleh admin.`,
                init: "🗑️", videoId: id, fromUsername: "admin",
              });
            } catch (err) { console.warn("[bulk] notif failed for", id, err); }
          }
          if (v) pushAdminEvent("🗑️", `Force delete video <i>"${escapeHtml(v.title || t("video.untitled"))}"</i> dari <b>@${escapeHtml(target || "?")}</b>`);
          // Collect promises supaya bisa Promise.all + count failures
          deletePromises.push(
            Promise.resolve(deleteAdminVideo(id)).catch(err => {
              console.warn(`[bulk] deleteAdminVideo(${id}) failed:`, err);
              return false;
            })
          );
        }
        const results = await Promise.all(deletePromises);
        const failed = results.filter(r => r === false).length;
        pushAdminEvent("🗑️", `Bulk: ${ids.length - failed}/${ids.length} video deleted${failed ? ` (${failed} failed)` : ""}`);
        adminVideoState.selected.clear();
        toast(
          failed
            ? `🗑️ ${ids.length - failed} dari ${ids.length} video dihapus (${failed} gagal — cek console)`
            : `🗑️ ${ids.length} video dihapus`,
          failed ? "warning" : "error"
        );
        renderAdminVideos();
        renderAdminLiveFeed();
      }
    });
    return;
  }
  const cfg = map[action]; if (!cfg) return;
  ids.forEach(id => {
    patchAdminVideo(id, cfg.patch);
    // C-2 H3: notify creator + per-video audit
    const v = videoById.get(id);
    if (v && v.creator && typeof deliverNotification === "function") {
      try {
        const notifMap = {
          takedown: { type: "video-takedown", text: `⛔ Video kamu <b>"${escapeHtml(v.title || t("video.untitled"))}"</b> di-takedown oleh admin.` },
        };
        const n = notifMap[action];
        if (n) {
          deliverNotification(v.creator, { type: n.type, text: n.text, init: cfg.icon, videoId: id, fromUsername: "admin" });
        }
      } catch (err) { console.warn("[bulk] notif failed:", err); }
    }
    if (v) pushAdminEvent(cfg.icon, `Video <i>"${escapeHtml(v.title || "(no title)")}"</i> ${cfg.msg}`);
  });
  pushAdminEvent(cfg.icon, `Bulk: ${ids.length} video ${cfg.msg}`);
  adminVideoState.selected.clear();
  toast(`${cfg.icon} ${ids.length} video ${cfg.msg}`, action === "takedown" ? "warning" : "success");
  renderAdminVideos();
  renderAdminLiveFeed();
}

function applyGvRowAction(id, action) {
  const v = getAllAdminVideos().find(x => x.id === id);
  if (!v) return;
  const titleEsc = escapeHtml(v.title || t("video.untitled"));
  const simple = {
    takedown: { patch: { adminStatus: "takedown"  }, icon: "⛔", msg: "di-takedown",     tone: "warning" },
    restore:  { patch: { adminStatus: "published" }, icon: "↻",  msg: "dikembalikan",    tone: "" },
    publish:  { patch: { adminStatus: "published" }, icon: "✅", msg: "dipublikasikan",  tone: "success" }
  };
  // C-3 V-M1 fix (2026-05-21): takedown prompt reason supaya creator dapat
  // info kenapa video dihapus. Sebelumnya notif cuma "Your video was taken
  // down" tanpa konteks. Restore/publish nggak butuh reason.
  if (action === "takedown") {
    if (typeof openConfirm === "function") {
      openConfirm({
        icon: "⛔", iconClass: "warning",
        title: `Takedown video?`,
        desc: `Video <b>${titleEsc}</b> akan di-takedown dari platform. Mohon isi alasan supaya creator dapat info yg jelas dan ada audit trail.`,
        btnText: "Takedown", btnClass: "danger",
        typeText: "Alasan takedown (wajib)",
        onConfirm: (reason) => {
          const reasonText = String(reason || "").trim() || "Tidak ada alasan spesifik";
          const c = simple.takedown;
          patchAdminVideo(id, { ...c.patch, takedownReason: reasonText, takedownAt: Date.now() });
          pushAdminEvent(c.icon, `Video <i>"${titleEsc}"</i> ${c.msg} — alasan: ${escapeHtml(reasonText)}`);
          toast(`${c.icon} <b>${titleEsc}</b> ${c.msg}`, c.tone);
          if (typeof deliverNotification === "function" && v.creator) {
            try {
              deliverNotification(v.creator, {
                type: "video-takedown",
                text: `⛔ Video kamu <b>"${titleEsc}"</b> di-takedown oleh admin. Alasan: ${escapeHtml(reasonText)}`,
                init: "📨", videoId: id, fromUsername: "admin"
              });
            } catch (err) { console.warn("[admin] notify creator failed:", err); }
          }
          renderAdminVideos();
          renderAdminLiveFeed();
        }
      });
      return;
    }
    // Fallback (no openConfirm)
  }
  if (simple[action]) {
    const c = simple[action];
    patchAdminVideo(id, c.patch);
    pushAdminEvent(c.icon, `Video <i>"${titleEsc}"</i> ${c.msg}`);
    toast(`${c.icon} <b>${titleEsc}</b> ${c.msg}`, c.tone);
    // v537 CRITICAL FIX 3 (2026-05-25): fallback ke v._owner kalau v.creator
    // null. Audit moderation flow finding C3: legacy data kadang punya
    // _owner tapi tidak creator → notif silent fail tanpa admin tahu.
    const notifTarget = v.creator || v._owner;
    if (typeof deliverNotification === "function" && notifTarget) {
      // v537: text di-translate ke Indonesia, sebelumnya English hardcoded
      const notifMap = {
        takedown: { type: "video-takedown", text: `⛔ Video kamu <b>"${titleEsc}"</b> di-takedown oleh admin.` },
        restore:  { type: "video-approved", text: `↻ Video kamu <b>"${titleEsc}"</b> dipulihkan admin & LIVE lagi!` },
        publish:  { type: "video-approved", text: `✅ Video kamu <b>"${titleEsc}"</b> sudah dipublikasikan admin!` },
      };
      const n = notifMap[action];
      if (n) {
        try {
          deliverNotification(notifTarget, {
            type: n.type, text: n.text, init: "📨", videoId: id, fromUsername: "admin"
          });
        } catch (err) { console.warn("[admin] notify creator failed:", err); }
      }
    } else if (!notifTarget) {
      console.warn(`[admin] video ${id} has no creator/owner — notif not sent`);
    }
    renderAdminVideos();
    renderAdminLiveFeed();
    return;
  }
  if (action === "delete") {
    // v537 CRITICAL FIX 3: same fallback for delete flow
    const deleteNotifTarget = v.creator || v._owner;
    openConfirm({
      icon: "🗑️", iconClass: "danger",
      title: "Force Delete Video?",
      desc: `Video <b>${titleEsc}</b> akan dihapus permanen dari akun <b>@${escapeHtml(deleteNotifTarget || "?")}</b>. Aksi ini tidak bisa dibatalkan.`,
      btnText: "Hapus Permanen", btnClass: "danger",
      onConfirm: () => {
        // C-2 H4 fix (2026-05-21): notify creator SEBELUM delete supaya
        // record masih ada saat notify
        if (typeof deliverNotification === "function" && deleteNotifTarget) {
          try {
            // v537: pakai deleteNotifTarget (creator || _owner) bukan v.creator langsung
            deliverNotification(deleteNotifTarget, {
              type: "video-takedown",
              text: `🗑️ Video kamu <b>${titleEsc}</b> dihapus permanen oleh admin.`,
              init: "🗑️", videoId: id, fromUsername: "admin",
            });
          } catch (err) { console.warn("[delete] notify failed:", err); }
        }
        deleteAdminVideo(id);
        pushAdminEvent("🗑️", `Force delete video <i>"${titleEsc}"</i> dari <b>@${escapeHtml(v.creator || v._owner)}</b>`);
        toast(`🗑️ <b>${titleEsc}</b> dihapus permanen`, "error");
        renderAdminVideos();
        renderAdminLiveFeed();
      }
    });
    return;
  }
  if (action === "edit") {
    openAdminVideoEdit(v);
    return;
  }
  if (action === "play") {
    // Admin role → use dedicated admin preview modal (slate/chrome theme,
    // dgn quick actions). Non-admin → fallback ke standard player view.
    const isAdmin = document.body.dataset.role === "admin";
    if (isAdmin && typeof openAdminPlayer === "function") {
      openAdminPlayer(id);
    } else {
      openPlayer(id);
    }
  }
}

// ----- Edit metadata modal -----
let __aveCurrent = null;

function openAdminVideoEdit(v) {
  __aveCurrent = v;
  const modal = $("#adminVideoEditModal"); if (!modal) return;
  $("#aveTitle").value = v.title || "";
  $("#aveDesc").value = v.desc || "";
  $("#aveTags").value = v.tags || "";
  $("#aveVisibility").value = v.visibility || "public";
  $("#aveCreator").textContent = `@${v.creator || v._owner || "—"}`;
  $("#aveStats").textContent = `${fmtNum(v.viewsNum || 0)} views • ${fmtNum(v.likes || 0)} likes`;
  $("#aveThumb").src = v.thumb || "https://picsum.photos/seed/playly/240/140";

  const catSel = $("#aveCategory");
  catSel.innerHTML = `<option value="">— Tanpa Kategori —</option>` +
    CATEGORIES.map(c => `<option value="${c.key}">${c.emoji} ${c.label}</option>`).join("");
  catSel.value = v.category || "";

  $("#aveSubtitle").innerHTML = `Mengedit: <b>${escapeHtml(v.title || t("video.untitled"))}</b>`;
  modal.classList.add("show");
}

$("#aveSaveBtn")?.addEventListener("click", () => {
  if (!__aveCurrent) return;
  const before = __aveCurrent;
  const patch = {
    title:      $("#aveTitle").value.trim() || __aveCurrent.title,
    desc:       $("#aveDesc").value.trim(),
    tags:       $("#aveTags").value.trim(),
    category:   $("#aveCategory").value,
    visibility: $("#aveVisibility").value
  };
  patchAdminVideo(__aveCurrent.id, patch);
  // C-2 H5 fix (2026-05-21): audit log dgn DIFF per-field (sebelumnya hanya
  // title baru, tidak ada track changes). Plus C-2 H4: notify creator.
  const diffs = [];
  if ((before.title || "") !== patch.title) diffs.push(`title: "${before.title || ""}" → "${patch.title}"`);
  if ((before.desc || "") !== patch.desc) diffs.push("desc changed");
  if ((before.tags || "") !== patch.tags) diffs.push("tags changed");
  if ((before.category || "") !== patch.category) diffs.push(`category: "${before.category || ""}" → "${patch.category}"`);
  if ((before.visibility || "") !== patch.visibility) diffs.push(`visibility: "${before.visibility || ""}" → "${patch.visibility}"`);
  const diffSummary = diffs.length ? ` [${diffs.map(d => escapeHtml(d)).join(", ")}]` : "";
  pushAdminEvent("✏️", `Metadata video <i>"${escapeHtml(patch.title)}"</i> diupdate${diffSummary}`);
  // C-2 H4 fix (2026-05-21): notify creator kalau metadata diubah
  if (diffs.length && typeof deliverNotification === "function" && before.creator) {
    try {
      deliverNotification(before.creator, {
        type: "video-edited",
        text: `✏️ Admin mengedit metadata video kamu <b>"${escapeHtml(patch.title)}"</b>.`,
        init: "✏️", videoId: before.id, fromUsername: "admin",
      });
    } catch (err) { console.warn("[edit] notify failed:", err); }
  }
  toast(`💾 <b>${escapeHtml(patch.title)}</b> berhasil diupdate`, "success");
  $("#adminVideoEditModal").classList.remove("show");
  __aveCurrent = null;
  renderAdminVideos();
  renderAdminLiveFeed();
});

// ----- Event delegation for the admin-videos view -----
function setupAdminVideoEvents() {
  if (window.__adminVideoEventsBound) return;
  window.__adminVideoEventsBound = true;

  // Tab filter
  document.addEventListener("click", e => {
    const tab = e.target.closest(".gv-tab");
    if (!tab) return;
    $$(".gv-tab").forEach(t => t.classList.toggle("active", t === tab));
    adminVideoState.filter = tab.dataset.gvFilter;
    adminVideoState.selected.clear();
    _saveAdminVideoState(); // C-3 V-M6: persist
    renderAdminVideos();
  });

  // Search & dropdowns
  $("#adminVideoSearch")?.addEventListener("input", e => {
    adminVideoState.search = e.target.value;
    _saveAdminVideoState(); // C-3 V-M6: persist
    renderAdminVideos();
  });
  $("#gvSortBy")?.addEventListener("change", e => {
    adminVideoState.sort = e.target.value;
    _saveAdminVideoState(); // C-3 V-M6: persist
    renderAdminVideos();
  });
  // Toggle select mode — checkbox column tampil hanya saat dibutuhkan
  $("#adminVideoSelectToggle")?.addEventListener("click", () => {
    adminVideoState.selectMode = !adminVideoState.selectMode;
    if (!adminVideoState.selectMode) adminVideoState.selected.clear();
    renderAdminVideos();
  });

  // Row + bulk action delegation (lives on tbody, which is stable)
  const tbody = $("#adminVideoTbody");
  if (tbody) {
    tbody.addEventListener("click", e => {
      const actBtn = e.target.closest("[data-gv-act]");
      if (actBtn) {
        e.stopPropagation();
        const id = Number(actBtn.closest("tr").dataset.vid);
        applyGvRowAction(id, actBtn.dataset.gvAct);
        return;
      }
      const check = e.target.closest(".gv-row-check");
      if (check) {
        const id = Number(check.closest("tr").dataset.vid);
        if (check.checked) adminVideoState.selected.add(id);
        else adminVideoState.selected.delete(id);
        check.closest("tr").classList.toggle("gv-row-selected", check.checked);
        updateGvBulkBar();
        return;
      }
    });
  }

  $("#gvSelectAll")?.addEventListener("change", e => {
    const rows = $$("#adminVideoTbody tr");
    if (e.target.checked) {
      rows.forEach(r => adminVideoState.selected.add(Number(r.dataset.vid)));
    } else {
      adminVideoState.selected.clear();
    }
    renderAdminVideos();
  });

  $("#gvClearSel")?.addEventListener("click", () => {
    adminVideoState.selected.clear();
    renderAdminVideos();
  });

  document.addEventListener("click", e => {
    const b = e.target.closest("[data-gv-bulk]");
    if (!b) return;
    applyGvBulkAction(b.dataset.gvBulk);
  });
}
setupAdminVideoEvents();

function renderAdminModeration() {
  const grid = $("#adminModGrid"); if (!grid) return;
  const filter = $(".mod-tab.active")?.dataset.modFilter || "pending";
  const items = getAdminData("mod").filter(m => m.status === filter);

  // Update tab counts
  const all = getAdminData("mod");
  const counts = { pending: all.filter(m => m.status === "pending").length, approved: all.filter(m => m.status === "approved").length, removed: all.filter(m => m.status === "removed").length };
  $$(".mod-tab").forEach(t => {
    const f = t.dataset.modFilter;
    const bEl = t.querySelector("b");
    if (bEl) bEl.textContent = counts[f] || 0;
    else if (counts[f]) t.insertAdjacentHTML("beforeend", `<b>${counts[f]}</b>`);
  });

  if (!items.length) {
    grid.innerHTML = `<div style="grid-column:1/-1;text-align:center;padding:48px;color:var(--muted)">✓ Tidak ada item ${filter}</div>`;
    return;
  }

  // CR-4 fix (2026-05-21): SECURITY — semua field user-controlled HARUS
  // di-escapeHtml sebelum di-interpolate ke innerHTML. Sebelumnya i.title,
  // i.creator, i.reason, i.thumb di-render mentah → stored XSS via judul
  // video. Attacker upload judul `<img src=x onerror=...>` lalu ada yg
  // report → admin buka Moderasi → JS jalan di session admin.
  grid.innerHTML = items.map(i => `<div class="mod-card" data-mod-id="${escapeHtml(String(i.id || ""))}">
    <div class="mod-thumb">${escapeHtml(String(i.thumb || "🎬"))}<span class="mod-flag-pill">${escapeHtml(String(i.flag || "🚩"))}</span></div>
    <div class="mod-card-body">
      <h4>${escapeHtml(String(i.title || "(tanpa judul)"))}</h4>
      <small>${escapeHtml(String(i.creator || "anonim"))} • ${escapeHtml(String(relTime(i.reportedAt) || ""))}</small>
      <div class="mod-reason">⚠️ ${escapeHtml(String(i.reason || ""))}</div>
      ${i.status === "pending" ? `<div class="mod-actions">
        <button class="approve" data-mod-action="approve">✓ Approve</button>
        <button class="remove" data-mod-action="remove">✕ Hapus</button>
      </div>` : `<div class="mod-actions"><button data-mod-action="restore">↻ Restore ke Pending</button></div>`}
    </div>
  </div>`).join("");

  // C-4 V-L5 fix (2026-05-21): pakai event delegation (1x bind) instead of
  // attach handler per button per render. Sebelumnya tiap re-render bikin
  // handler baru → fast clicks trigger multiple actions + memory leak.
  // Guard via window flag supaya bind hanya 1x.
  if (!window.__adminModHandlerBound) {
    window.__adminModHandlerBound = true;
    document.addEventListener("click", e => {
      const btn = e.target.closest("[data-mod-action]");
      if (!btn) return;
      const card = btn.closest(".mod-card");
      if (!card) return;
      const id = Number(card.dataset.modId);
      const action = btn.dataset.modAction;
      const list = getAdminData("mod");
      const idx = list.findIndex(x => x.id === id);
      if (idx === -1) return;
      const item = list[idx];
      // Bug #5 fix (2026-05-20): aksi moderasi WAJIB juga mengubah
      // adminStatus video aslinya.
      if (action === "approve") {
        item.status = "approved";
        // C-2 H1 fix (2026-05-21): JANGAN auto-republish kalau video sudah
        // takedown via path lain. Approve di mod queue artinya laporan
        // ditolak — tapi kalau admin sudah explicit takedown via tabel
        // video, status takedown harus stay. Hanya bump dari "pending"
        // → "published".
        if (item.videoId && typeof patchAdminVideo === "function") {
          try {
            const all = (typeof getAllAdminVideos === "function") ? getAllAdminVideos() : [];
            const target = all.find(v => v.id === item.videoId);
            const curStatus = target && target.adminStatus;
            if (curStatus === "pending" || !curStatus) {
              patchAdminVideo(item.videoId, { adminStatus: "published" });
            } else {
              // already published or takedown — leave alone, just close the report
              console.info(`[mod] approve report only — video adminStatus stays "${curStatus}"`);
            }
          } catch (err) { console.warn("[mod] approve patch failed:", err); }
        }
        // C-4 V-L1 fix (2026-05-21): include reporter info di audit log untuk
        // visibility — admin lain bisa lihat siapa yg laporkan + alasannya
        const reporterInfo = item.reportedBy ? ` (dilaporkan @${escapeHtml(item.reportedBy)}${item.reason ? `, alasan: ${escapeHtml(item.reason)}` : ""})` : "";
        pushAdminEvent("✓", `Laporan video <i>"${escapeHtml(item.title)}"</i> di-approve${reporterInfo}`);
      }
      if (action === "remove") {
        item.status = "removed";
        if (item.videoId && typeof patchAdminVideo === "function") {
          try { patchAdminVideo(item.videoId, { adminStatus: "takedown" }); } catch (err) { console.warn("[mod] remove patch failed:", err); }
        }
        pushAdminEvent("🗑️", `Video <i>"${item.title}"</i> dihapus`);
      }
      if (action === "restore") {
        // C-4 V-L2 fix (2026-05-21): semantic alignment dgn video-row restore.
        // Sebelumnya: mod queue restore → "pending" (re-review), video-row
        // restore → "published" (langsung live). Inconsistent — admin
        // confused mana yg ngapain. Pilih: keduanya → "published" (klik
        // restore = video LIVE lagi). Mod queue restore artinya admin
        // overturn laporan/takedown sebelumnya.
        item.status = "pending"; // status RECORD laporan tetap "pending" (akan re-review-able)
        if (item.videoId && typeof patchAdminVideo === "function") {
          try { patchAdminVideo(item.videoId, { adminStatus: "published" }); } catch (err) { console.warn("[mod] restore patch failed:", err); }
        }
        pushAdminEvent("↻", `Video <i>"${escapeHtml(item.title)}"</i> di-restore (LIVE lagi)`);
      }
      saveAdminData("mod", list);
      toast(
        action === "approve" ? t("admin.toast.video.approved")
          : action === "remove" ? t("admin.toast.video.removed")
          : t("admin.toast.video.restored"),
        action === "remove" ? "error" : "success"
      );
      renderAdminModeration();
      renderAdminAlerts();
      renderAdminLiveFeed();
      syncAdminNavBadges();
    });
  }
}

// =========== ADMIN: Pusat Komunikasi (admin-comms) ===========
function renderAdminComms() {
  if (!user || user.role !== "admin") return;
  renderCommsKpis();
  renderCommsInbox();
  renderCommsBroadcastLog();
  renderCommsUserList(($("#commsUserSearch")?.value || "").trim().toLowerCase());
}

// Filter aktif untuk inbox: "all" | "unread" | "read"
let __commsInboxFilter = "all";

// Pesan Masuk: flatten semua history dari thread admin → list pesan masuk
// (yang dikirim user ke admin), urut berdasar waktu terbaru.
function renderCommsInbox() {
  const list = $("#commsInboxList");
  if (!list) return;
  const threads = Array.isArray(state?.messages) ? state.messages : [];

  // Kumpulkan semua incoming message (from !== "me") dari semua thread
  const inbox = [];
  threads.forEach((thread, threadIdx) => {
    const history = Array.isArray(thread.history) ? thread.history : [];
    history.forEach((h, msgIdx) => {
      if (!h || h.from === "me") return; // skip pesan keluar (admin → user)
      inbox.push({
        threadIdx, msgIdx,
        senderName: h.from || thread.name || "user",
        senderInit: thread.init || (thread.name || "U").slice(0, 2).toUpperCase(),
        text: String(h.text || ""),
        ts: typeof h.ts === "number" ? h.ts : 0,
        threadUnread: !!thread.unread
      });
    });
  });
  // Urut: terbaru di atas
  inbox.sort((a, b) => (b.ts || 0) - (a.ts || 0));

  // Counter total (sebelum filter)
  const countEl = $("#commsInboxCount");
  if (countEl) countEl.textContent = inbox.length;

  // Apply filter
  let filtered = inbox;
  if (__commsInboxFilter === "unread") filtered = inbox.filter(m => m.threadUnread);
  else if (__commsInboxFilter === "read") filtered = inbox.filter(m => !m.threadUnread);

  if (!filtered.length) {
    // v533 (2026-05-25): empty state full Bahasa Indonesia + lebih informatif.
    const emptyMsg = __commsInboxFilter === "unread"
      ? "Tidak ada pesan yang belum dibaca."
      : __commsInboxFilter === "read"
        ? "Belum ada pesan yang sudah dibaca."
        : "Belum ada pesan masuk dari user. Pesan baru akan muncul di sini secara real-time.";
    list.innerHTML = `<div class="comms-empty">
      <div class="comms-empty-icon">📭</div>
      ${emptyMsg}
    </div>`;
    return;
  }

  list.innerHTML = filtered.map(m => {
    const init = escapeHtml(m.senderInit);
    const preview = escapeHtml(m.text.slice(0, 120));
    const time = chatRelTime(m.ts);
    return `<div class="comms-inbox-item ${m.threadUnread ? "unread" : ""}" data-thread-idx="${m.threadIdx}" data-msg-idx="${m.msgIdx}">
      <div class="avatar"><span>${init}</span></div>
      <div class="comms-inbox-info">
        <strong>@${escapeHtml(m.senderName)}</strong>
        <small>${preview}</small>
      </div>
      <div class="comms-inbox-meta">
        ${time ? `<small>${time}</small>` : ""}
        ${m.threadUnread ? `<span class="badge">unread</span>` : ""}
      </div>
    </div>`;
  }).join("");

  list.querySelectorAll("[data-thread-idx]").forEach(el => {
    el.addEventListener("click", () => {
      const idx = Number(el.dataset.threadIdx);
      if (Number.isNaN(idx) || !state.messages[idx]) return;
      switchView("messages");
      setTimeout(() => openChat(idx), 80);
    });
  });
}

// Bind filter buttons (idempotent)
(function bindInboxFilters() {
  if (window.__inboxFiltersBound) return;
  window.__inboxFiltersBound = true;
  document.addEventListener("click", e => {
    const btn = e.target.closest(".comms-inbox-filter");
    if (!btn) return;
    const f = btn.dataset.inboxFilter || "all";
    __commsInboxFilter = f;
    document.querySelectorAll(".comms-inbox-filter").forEach(b => {
      b.classList.toggle("active", b.dataset.inboxFilter === f);
    });
    renderCommsInbox();
  });
})();

function renderCommsKpis() {
  const threads = Array.isArray(state?.messages) ? state.messages : [];
  const unread = threads.filter(t => t.unread).length;
  let bcCount = 0;
  try { bcCount = (JSON.parse(localStorage.getItem("playly-admin-sent") || "[]") || []).length; } catch {}
  const userCount = getAllAccounts().filter(a => a.role !== "admin").length;

  $("#commsKpiUnread")  && ($("#commsKpiUnread").textContent  = unread);
  $("#commsKpiBroadcasts") && ($("#commsKpiBroadcasts").textContent = bcCount);
  $("#commsKpiUsers") && ($("#commsKpiUsers").textContent = userCount);

  // Sidebar badge — total unread
  const badge = $("#adminCommsBadge");
  if (badge) { badge.textContent = unread; badge.style.display = unread ? "" : "none"; }
}

function renderCommsThreads() {
  const list = $("#commsThreadList"); if (!list) return;
  const threads = Array.isArray(state?.messages) ? state.messages.slice() : [];
  // Sort by ts desc (terbaru di atas), fallback ke posisi asli
  threads.sort((a, b) => (b.ts || 0) - (a.ts || 0));

  if (!threads.length) {
    list.innerHTML = `<div class="comms-empty">
      <div class="comms-empty-icon">💬</div>
      Belum ada conversation. Mulai chat dari panel kanan.
    </div>`;
    return;
  }

  list.innerHTML = threads.map((t, i) => {
    const idx = state.messages.indexOf(t);
    const init = escapeHtml(t.init || (t.name || "U").slice(0, 2).toUpperCase());
    const preview = escapeHtml((t.preview || "—").slice(0, 80));
    const time = chatRelTime(t.ts);
    return `<div class="comms-thread-item" data-comms-thread="${idx}">
      <div class="avatar"><span>${init}</span></div>
      <div class="comms-thread-info">
        <strong>@${escapeHtml(t.name)}</strong>
        <small>${preview}</small>
      </div>
      <div class="comms-thread-meta">
        ${time ? `<small>${time}</small>` : ""}
        ${t.unread ? `<span class="badge">unread</span>` : ""}
      </div>
    </div>`;
  }).join("");

  list.querySelectorAll("[data-comms-thread]").forEach(el => {
    el.addEventListener("click", () => {
      const idx = Number(el.dataset.commsThread);
      if (Number.isNaN(idx) || !state.messages[idx]) return;
      switchView("messages");
      setTimeout(() => openChat(idx), 80);
    });
  });
}

function renderCommsBroadcastLog() {
  const list = $("#commsBroadcastLog"); if (!list) return;
  let log = [];
  try { log = JSON.parse(localStorage.getItem("playly-admin-sent") || "[]") || []; } catch {}
  // Hide "Hapus Semua" button kalau log kosong
  const clearBtn = $("#commsBroadcastClear");
  if (clearBtn) clearBtn.hidden = !log.length;
  if (!log.length) {
    list.innerHTML = `<div class="comms-empty">
      <div class="comms-empty-icon">📢</div>
      Belum ada broadcast yang dikirim.
    </div>`;
    return;
  }
  list.innerHTML = log.slice(0, 30).map((item, idx) => {
    const ts = item.sentAt ? new Date(item.sentAt).getTime() : item.id;
    const time = chatRelTime(ts) || "—";
    const targetLabel = item.targetCount > 1
      ? `📢 Broadcast ke <b>${item.targetCount}</b> user`
      : `→ <b>@${escapeHtml((item.targets && item.targets[0]) || "user")}</b>`;
    return `<div class="comms-bc-item" data-bc-id="${escapeHtml(String(item.id || idx))}">
      <div class="comms-bc-head">
        <span class="comms-bc-target">${targetLabel}</span>
        <span class="comms-bc-time">${time}</span>
        <button type="button" class="comms-bc-del icon-btn-tiny" title="Hapus broadcast ini">🗑</button>
      </div>
      <div class="comms-bc-text">${escapeHtml(item.text || "")}</div>
    </div>`;
  }).join("");
  // Per-item delete handler
  list.querySelectorAll(".comms-bc-del").forEach(btn => {
    btn.addEventListener("click", e => {
      e.stopPropagation();
      const item = e.currentTarget.closest(".comms-bc-item");
      const id = item?.dataset.bcId;
      if (!id) return;
      openConfirm({
        icon: "🗑", iconClass: "danger",
        title: "Hapus broadcast ini?",
        desc: "Entry broadcast akan dihapus dari riwayat. Pesan yang sudah terkirim ke user tidak ikut terhapus.",
        btnText: "Hapus", btnClass: "danger",
        onConfirm: () => {
          let cur = [];
          try { cur = JSON.parse(localStorage.getItem("playly-admin-sent") || "[]") || []; } catch {}
          cur = cur.filter(x => String(x.id) !== id);
          localStorage.setItem("playly-admin-sent", JSON.stringify(cur));
          renderCommsBroadcastLog();
          if (typeof renderCommsKpis === "function") renderCommsKpis();
          toast("✓ Broadcast dihapus", "success");
        }
      });
    });
  });
}

// Wire "Hapus Semua" button (one-time)
$("#commsBroadcastClear")?.addEventListener("click", () => {
  let cur = [];
  try { cur = JSON.parse(localStorage.getItem("playly-admin-sent") || "[]") || []; } catch {}
  if (!cur.length) return;
  openConfirm({
    icon: "🗑", iconClass: "danger",
    title: `Hapus semua riwayat broadcast?`,
    desc: `Akan menghapus ${cur.length} entry broadcast dari riwayat. Pesan yang sudah terkirim ke user tidak ikut terhapus. Tindakan ini tidak bisa dibatalkan.`,
    btnText: "Hapus Semua", btnClass: "danger",
    onConfirm: () => {
      localStorage.setItem("playly-admin-sent", "[]");
      renderCommsBroadcastLog();
      if (typeof renderCommsKpis === "function") renderCommsKpis();
      toast("✓ Riwayat broadcast dikosongkan", "success");
    }
  });
});

function renderCommsUserList(query = "") {
  const list = $("#commsUserList"); if (!list) return;
  const myUsername = user?.username;
  const accounts = getAllAccounts()
    .filter(a => a.username !== myUsername)
    .filter(a => !query || (a.name || "").toLowerCase().includes(query) || (a.username || "").toLowerCase().includes(query))
    .sort((a, b) => (a.name || "").localeCompare(b.name || ""));

  if (!accounts.length) {
    list.innerHTML = `<div class="comms-empty">
      <div class="comms-empty-icon">👥</div>
      ${query ? "Tidak ada user yang cocok." : "Belum ada user terdaftar."}
    </div>`;
    return;
  }

  list.innerHTML = accounts.slice(0, 50).map(a => {
    const init = (a.name || a.username || "U").split(/\s+/).map(p => p[0]).slice(0, 2).join("").toUpperCase();
    const isAdmin = a.role === "admin";
    return `<div class="comms-user-item">
      <div class="avatar"><span>${escapeHtml(init)}</span></div>
      <div class="info">
        <strong>${escapeHtml(a.name || a.username)} ${isAdmin ? '<span class="role-tag admin">ADMIN</span>' : ''}</strong>
        <small>@${escapeHtml(a.username)}</small>
      </div>
      <button data-comms-msg="${escapeHtml(a.username)}">💬 Chat</button>
    </div>`;
  }).join("");

  list.querySelectorAll("[data-comms-msg]").forEach(b => {
    b.addEventListener("click", () => startChatWithUser(b.dataset.commsMsg));
  });
}

// Wire up event handlers (one-time)
$("#commsBroadcastBtn")?.addEventListener("click", () => openAdminSendMsg({ broadcast: true }));
$("#commsBroadcastBtn2")?.addEventListener("click", () => openAdminSendMsg({ broadcast: true }));

// =========== ADMIN: Audit Log (admin-audit) ===========
let __auditFilter = "all";
let __auditActor = "all"; // "all" | "super-admin" | "admin"

function getAuditEvents() {
  // Gabungkan event admin (pushAdminEvent) + broadcast log → satu timeline
  const events = (getAdminData("events") || []).map(e => ({
    id: `evt-${e.id}`,
    ico: e.ico || "•",
    text: e.text || "",
    ts: Number(e.ts) || 0,
    // Backward-compat: event lama tanpa actorTier dianggap super-admin
    // (historikal cuma satu admin) — supaya filter Super Admin gak kosong total.
    actorTier: e.actorTier || "super-admin",
    actorEmail: e.actorEmail || ""
  }));
  let bc = [];
  try { bc = JSON.parse(localStorage.getItem("playly-admin-sent") || "[]") || []; } catch {}
  for (const item of bc) {
    const ts = item.sentAt ? new Date(item.sentAt).getTime() : Number(item.id) || 0;
    const target = item.targetCount > 1
      ? `<b>${item.targetCount} user</b>`
      : `<b>@${escapeHtml((item.targets && item.targets[0]) || "user")}</b>`;
    const senderEmail = String(item.senderEmail || item.sender || "").toLowerCase();
    const tier = (typeof OFFICIAL_ADMIN_EMAIL !== "undefined" && senderEmail === OFFICIAL_ADMIN_EMAIL)
      ? "super-admin" : (senderEmail ? "admin" : "super-admin");
    events.push({
      id: `bc-${item.id || ts}`,
      ico: "📨",
      text: `Broadcast/DM ke ${target}: <i>"${escapeHtml((item.text || "").slice(0, 120))}${(item.text || "").length > 120 ? "..." : ""}"</i>`,
      ts,
      actorTier: tier,
      actorEmail: senderEmail
    });
  }
  // === USER EVENTS (req 2026-05-26) ===
  // Admin mau monitor pergerakan user — aggregate dari multiple sources:
  // - Signup (createdAt dari akun)
  // - Upload video (uploadedAt + creator dari videos array)
  // - Premium purchase (payments log)
  // - Like / follow / comment (notifications, kalau ada)
  for (const ev of getUserEvents()) events.push(ev);
  events.sort((a, b) => b.ts - a.ts);
  return events;
}

// === USER EVENTS aggregator (req 2026-05-26) ===
// Kumpulkan aksi user platform (signup, upload, payment) jadi timeline
// supaya admin bisa monitor pergerakan user di Log Audit.
function getUserEvents() {
  const events = [];
  // 1. Signup events — dari getAllAccounts() (skip admin accounts)
  try {
    const accounts = (typeof getAllAccounts === "function" ? getAllAccounts() : []) || [];
    for (const a of accounts) {
      if (!a || a.role === "admin") continue;
      const ts = Number(a.createdAt || a.signupAt || 0);
      if (!ts) continue;
      events.push({
        id: `usr-signup-${a.username}`,
        ico: "👤",
        text: `User <b>@${escapeHtml(a.username || "")}</b> daftar akun baru${a.tier === "premium" ? " (Premium)" : ""}`,
        ts,
        actorTier: "user",
        actorEmail: (a.email || "").toLowerCase(),
        actorUsername: a.username || ""
      });
    }
  } catch {}
  // 2. Upload video events — dari global videos array
  try {
    const vids = (typeof videos !== "undefined" && Array.isArray(videos)) ? videos : [];
    for (const v of vids) {
      if (!v) continue;
      const ts = Number(v.uploadedAt || v.createdAt || (typeof v.id === "number" && v.id > 1e12 ? v.id : 0));
      if (!ts) continue;
      const title = String(v.title || "(tanpa judul)").slice(0, 60);
      events.push({
        id: `usr-upload-${v.id}`,
        ico: "🎬",
        text: `<b>@${escapeHtml(v.creator || "?")}</b> upload video "<i>${escapeHtml(title)}</i>"`,
        ts,
        actorTier: "user",
        actorEmail: "",
        actorUsername: v.creator || ""
      });
    }
  } catch {}
  // 3. Premium purchase events — dari payments log (localStorage atau adminData)
  try {
    let payments = [];
    try { payments = JSON.parse(localStorage.getItem("playly-payments") || "[]") || []; } catch {}
    if (!payments.length) payments = (getAdminData("payments") || []) || [];
    for (const p of payments) {
      if (!p) continue;
      const ts = Number(p.paidAt || p.ts || p.createdAt || 0);
      if (!ts) continue;
      const uname = p.username || p.user || "?";
      const amt = p.amountLabel || (p.amount ? `$${p.amount}` : "");
      events.push({
        id: `usr-pay-${p.id || ts}-${uname}`,
        ico: "💳",
        text: `<b>@${escapeHtml(uname)}</b> upgrade ke Premium${amt ? ` (${escapeHtml(amt)})` : ""}`,
        ts,
        actorTier: "user",
        actorEmail: "",
        actorUsername: uname
      });
    }
  } catch {}
  return events;
}

function applyAuditFilter(events, filter) {
  const now = Date.now();
  if (filter === "today") {
    const startOfDay = new Date(); startOfDay.setHours(0, 0, 0, 0);
    return events.filter(e => e.ts >= startOfDay.getTime());
  }
  if (filter === "week")  return events.filter(e => now - e.ts <= 7 * 86400000);
  if (filter === "month") return events.filter(e => now - e.ts <= 30 * 86400000);
  return events;
}

function renderAuditStats(allEvents) {
  const now = Date.now();
  const startOfDay = new Date(); startOfDay.setHours(0, 0, 0, 0);
  const today = allEvents.filter(e => e.ts >= startOfDay.getTime()).length;
  const week  = allEvents.filter(e => now - e.ts <= 7 * 86400000).length;
  const userCount = allEvents.filter(e => e.actorTier === "user").length;
  let bcCount = 0;
  try { bcCount = (JSON.parse(localStorage.getItem("playly-admin-sent") || "[]") || []).length; } catch {}

  $("#auditStatToday")      && ($("#auditStatToday").textContent = today);
  $("#auditStatWeek")       && ($("#auditStatWeek").textContent  = week);
  $("#auditStatTotal")      && ($("#auditStatTotal").textContent = allEvents.length);
  $("#auditStatUsers")      && ($("#auditStatUsers").textContent = userCount);
  $("#auditStatBroadcasts") && ($("#auditStatBroadcasts").textContent = bcCount);

  // Sidebar badge — total aksi hari ini
  const badge = $("#adminAuditBadge");
  if (badge) { badge.textContent = today; badge.style.display = today ? "" : "none"; }
}

function renderAuditTimeline(filter, query) {
  const list = $("#auditTimeline"); if (!list) return;
  const all = getAuditEvents();
  renderAuditStats(all);

  // Role-aware base filter (per user request 2026-05-06):
  //  - Super admin: lihat SEMUA event (super admin + admin biasa). Default
  //    rendering = split jadi 2 section terpisah.
  //  - Admin biasa: HANYA lihat aksi sendiri (actorEmail match). Nggak bisa
  //    lihat aktivitas super admin atau admin biasa lain.
  const isSuper = (typeof isSuperAdmin === "function") ? isSuperAdmin(user) : false;
  const myEmail = (user?.email || "").toLowerCase();
  let baseScope = all;
  if (!isSuper) {
    baseScope = all.filter(e => (e.actorEmail || "").toLowerCase() === myEmail);
  }

  let filtered = applyAuditFilter(baseScope, filter);
  // Apply actor filter dari sidebar sub-item (cuma berlaku untuk super admin)
  if (isSuper) {
    if (__auditActor === "super-admin") filtered = filtered.filter(e => e.actorTier === "super-admin");
    else if (__auditActor === "admin")  filtered = filtered.filter(e => e.actorTier === "admin");
    else if (__auditActor === "user")   filtered = filtered.filter(e => e.actorTier === "user");
  }
  if (query) {
    const q = query.toLowerCase();
    filtered = filtered.filter(e => (e.text || "").toLowerCase().includes(q) || (e.ico || "").toLowerCase().includes(q));
  }

  if (!filtered.length) {
    list.innerHTML = `<div class="audit-empty">
      <div class="audit-empty-icon">📋</div>
      <p>${query ? `Tidak ada log yang cocok dengan "<b>${escapeHtml(query)}</b>".` : "Belum ada aksi yang tercatat untuk periode ini."}</p>
    </div>`;
    return;
  }

  const tierMeta = (tier) => {
    if (tier === "super-admin") return "👑";
    if (tier === "user") return "👤";
    return "🛡️";
  };
  const renderRow = (e) => {
    const tier = e.actorTier || "admin";
    const metaIdent = (tier === "user")
      ? (e.actorUsername ? `@${escapeHtml(e.actorUsername)}` : "")
      : escapeHtml(e.actorEmail || "");
    return `
    <div class="audit-row" data-actor-tier="${tier}">
      <div class="audit-icon">${e.ico}</div>
      <div class="audit-text">
        ${e.text}
        ${isSuper && metaIdent ? `<small class="audit-actor-meta">${tierMeta(tier)} ${metaIdent}</small>` : ""}
      </div>
      <small class="audit-time" title="${new Date(e.ts).toLocaleString("id-ID")}">${chatRelTime(e.ts) || "—"}</small>
    </div>`;
  };

  // Super admin + actor filter "all" → split jadi 3 section (Super Admin /
  // Admin / User). Filter spesifik → tampil flat list.
  const showSplit = isSuper && (__auditActor === "all" || !__auditActor);
  if (showSplit) {
    const isIDA = (typeof currentLang === "function") ? (currentLang() === "id") : true;
    const superEvents = filtered.filter(e => e.actorTier === "super-admin").slice(0, 100);
    const adminEvents = filtered.filter(e => e.actorTier === "admin").slice(0, 100);
    const userEvents  = filtered.filter(e => e.actorTier === "user").slice(0, 100);
    const superHead = isIDA ? "Aktivitas Super Admin" : "Super Admin Activity";
    const adminHead = isIDA ? "Aktivitas Admin Biasa" : "Admin Activity";
    const userHead  = isIDA ? "Aktivitas User"        : "User Activity";
    const sectionEmpty = (kind) => {
      const msg = isIDA ? `Tidak ada aksi ${kind} di periode ini.` : `No ${kind} actions in this period.`;
      return `<div class="audit-empty" style="padding:18px"><p style="margin:0;font-size:12.5px">${msg}</p></div>`;
    };
    list.innerHTML = `
      <div class="audit-section">
        <div class="audit-section-head">
          <span class="audit-section-icon">👑</span>
          <h4>${superHead}</h4>
          <span class="audit-section-count">${superEvents.length}</span>
        </div>
        <div class="audit-section-body">
          ${superEvents.length ? superEvents.map(renderRow).join("") : sectionEmpty(isIDA ? "super admin" : "super admin")}
        </div>
      </div>
      <div class="audit-section">
        <div class="audit-section-head">
          <span class="audit-section-icon">🛡️</span>
          <h4>${adminHead}</h4>
          <span class="audit-section-count">${adminEvents.length}</span>
        </div>
        <div class="audit-section-body">
          ${adminEvents.length ? adminEvents.map(renderRow).join("") : sectionEmpty(isIDA ? "admin biasa" : "admin")}
        </div>
      </div>
      <div class="audit-section">
        <div class="audit-section-head">
          <span class="audit-section-icon">👤</span>
          <h4>${userHead}</h4>
          <span class="audit-section-count">${userEvents.length}</span>
        </div>
        <div class="audit-section-body">
          ${userEvents.length ? userEvents.map(renderRow).join("") : sectionEmpty(isIDA ? "user" : "user")}
        </div>
      </div>`;
  } else {
    // Filter spesifik (super-admin / admin) atau admin biasa →
    // tampil tetap dalam 1 audit-section card (per request user 2026-05-07
    // supaya konsisten dengan tampilan split, tidak floating tanpa card).
    const isIDA = (typeof currentLang === "function") ? (currentLang() === "id") : true;
    let head, icon;
    if (__auditActor === "super-admin") {
      head = isIDA ? "Aktivitas Super Admin" : "Super Admin Activity";
      icon = "👑";
    } else if (__auditActor === "admin") {
      head = isIDA ? "Aktivitas Admin Biasa" : "Admin Activity";
      icon = "🛡️";
    } else if (__auditActor === "user") {
      head = isIDA ? "Aktivitas User" : "User Activity";
      icon = "👤";
    } else {
      head = isIDA ? "Aktivitas Saya" : "My Activity";
      icon = "📋";
    }
    const rows = filtered.slice(0, 200).map(renderRow).join("");
    list.innerHTML = `
      <div class="audit-section">
        <div class="audit-section-head">
          <span class="audit-section-icon">${icon}</span>
          <h4>${escapeHtml(head)}</h4>
          <span class="audit-section-count">${filtered.length}</span>
        </div>
        <div class="audit-section-body">
          ${rows}
        </div>
      </div>`;
  }
}

function renderAdminAudit() {
  if (!user || user.role !== "admin") return;
  const search = ($("#auditSearch")?.value || "").trim();
  renderAuditTimeline(__auditFilter, search);
}

// Wire up handlers (one-time)
$$(".audit-filter").forEach(b => {
  b.addEventListener("click", () => {
    $$(".audit-filter").forEach(x => x.classList.toggle("active", x === b));
    __auditFilter = b.dataset.auditFilter || "all";
    renderAdminAudit();
  });
});
$("#auditSearch")?.addEventListener("input", () => renderAdminAudit());

// =================== INBOX (Email + Live Chat + Bug Reports) ===================
const _inboxState = { filter: "all", search: "" };

function renderAdminInbox() {
  // PENTING: ada DUA element dengan data-view="admin-inbox" — nav-item di sidebar
  // dan section view di main. querySelector("[data-view=...]") ngambil nav-item
  // yang gak nerima klik card. Pakai selector spesifik ke section.
  const wrap = document.querySelector('section.view[data-view="admin-inbox"]');
  if (!wrap) return;

  const tickets = [...getAdminData("tickets")].sort((a, b) => b.createdAt - a.createdAt);
  const bugs = [...getAdminData("bugs")].sort((a, b) => b.createdAt - a.createdAt);
  // Email column = semua tiket dari Email Support modal
  let emailTickets = tickets.filter(t => t.type !== "chat" && t.ch !== "💬");

  // Live Chat column = thread chat real dari state.messages (admin's conversations).
  // Tiap thread: { name, init, unread, history:[{from, text, ts}, ...] }
  const threads = Array.isArray(state?.messages) ? state.messages : [];
  // Buat list dengan latest message + sort terbaru di atas
  let chatItems = threads.map((th, idx) => {
    const hist = Array.isArray(th.history) ? th.history : [];
    const last = hist[hist.length - 1];
    return {
      idx,
      name: th.name || "user",
      init: th.init || (th.name || "U").slice(0, 2).toUpperCase(),
      unread: !!th.unread,
      lastText: last ? String(last.text || "") : "",
      lastFrom: last?.from || "",
      lastTs: typeof last?.ts === "number" ? last.ts : 0
    };
  }).filter(x => x.lastText).sort((a, b) => b.lastTs - a.lastTs);

  let bugList = bugs;

  // Top stats pill — pakai TOTAL tanpa filter biar count akurat
  $("#inboxStatEmail") && ($("#inboxStatEmail").textContent = emailTickets.length);
  $("#inboxStatChat") && ($("#inboxStatChat").textContent = chatItems.length);
  $("#inboxStatBug") && ($("#inboxStatBug").textContent = bugList.length);

  // Apply status filter (untuk tiket & bug; chat selalu tampil semua)
  const f = _inboxState.filter;
  if (f === "draft") {
    // Draft filter: tampilkan hanya item yang di-mark sebagai draft (admin nge-save
    // untuk dilihat nanti). Termasuk chat thread draft juga.
    emailTickets = emailTickets.filter(t => !!t.draft);
    bugList = bugList.filter(b => !!b.draft);
    chatItems = chatItems.filter(c => !!threads[c.idx]?.draft);
  } else {
    // Non-draft filter: exclude items yang udah di-draft (mereka cuma muncul di tab Draft).
    emailTickets = emailTickets.filter(t => !t.draft);
    bugList = bugList.filter(b => !b.draft);
    chatItems = chatItems.filter(c => !threads[c.idx]?.draft);
    if (f === "new") {
      emailTickets = emailTickets.filter(t => (t.status || "new") === "new");
      bugList = bugList.filter(b => (b.status || "open") === "open");
    } else if (f === "progress") {
      emailTickets = emailTickets.filter(t => t.status === "progress");
      bugList = bugList.filter(b => b.status === "assigned");
    } else if (f === "resolved") {
      emailTickets = emailTickets.filter(t => t.status === "resolved");
      bugList = bugList.filter(b => b.status === "closed");
    }
  }

  // Apply search across all columns (case-insensitive)
  const q = (_inboxState.search || "").toLowerCase().trim();
  if (q) {
    emailTickets = emailTickets.filter(t =>
      (t.title || "").toLowerCase().includes(q) ||
      (t.from || "").toLowerCase().includes(q) ||
      (t.fromEmail || "").toLowerCase().includes(q) ||
      (t.body || "").toLowerCase().includes(q)
    );
    bugList = bugList.filter(b =>
      (b.title || "").toLowerCase().includes(q) ||
      (b.reporter || "").toLowerCase().includes(q) ||
      (b.desc || "").toLowerCase().includes(q)
    );
    chatItems = chatItems.filter(c =>
      (c.name || "").toLowerCase().includes(q) ||
      (c.lastText || "").toLowerCase().includes(q)
    );
  }

  // Per-column count badge — count setelah filter/search
  $("#inboxEmailCount") && ($("#inboxEmailCount").textContent = emailTickets.length);
  $("#inboxChatCount") && ($("#inboxChatCount").textContent = chatItems.length);
  $("#inboxBugCount") && ($("#inboxBugCount").textContent = bugList.length);

  // Last-refresh stamp
  const stamp = $("#inboxRefreshTime");
  if (stamp) {
    const now = new Date();
    stamp.textContent = `${String(now.getHours()).padStart(2, "0")}:${String(now.getMinutes()).padStart(2, "0")}:${String(now.getSeconds()).padStart(2, "0")}`;
  }

  const ticketLabels = { new: "NEW", progress: "IN PROGRESS", resolved: "RESOLVED" };

  // Inisial avatar dari nama
  const initOf = (name) => (String(name || "U").trim().split(/\s+/).map(p => p[0]).slice(0, 2).join("") || "U").toUpperCase();

  // Email row — Gmail-style: avatar, sender, subject + preview snippet, time.
  // Unread = bold sender + subject. Klik = detail.
  const renderTicketCard = (t) => {
    const sender = t.from || "—";
    const subj = t.title || "(tanpa subjek)";
    const preview = (t.body || "").replace(/\s+/g, " ").trim().slice(0, 90);
    const isUnread = (t.status || "new") === "new";
    const time = relTime(t.createdAt);
    const tier = (t.fromEmail && t.fromEmail.toLowerCase() === (typeof OFFICIAL_ADMIN_EMAIL !== "undefined" ? OFFICIAL_ADMIN_EMAIL : "")) ? "super" : "";
    // Premium-verification email = email yang punya paymentCode (auto-set via
    // openSupportCompose dari payment status modal). Tampilkan chip kuning emas
    // supaya admin langsung tahu ini bukan support biasa, melainkan request
    // verifikasi pembayaran yang harus di-approve/reject di Premium Queue.
    const isPremiumVerif = !!t.paymentCode;
    const verifChip = isPremiumVerif
      ? `<span class="inbox-row-verif-chip" title="Email ini terkait verifikasi pembayaran Premium">⭐ VERIFIKASI PREMIUM · ${escapeHtml(t.paymentCode)}</span>`
      : "";
    const isDraft = !!t.draft;
    return `<div class="inbox-row inbox-row-email ${isUnread ? "unread" : ""} ${isDraft ? "is-draft" : ""} ${isPremiumVerif ? "is-premium-verif" : ""}" data-card-kind="ticket" data-card-id="${t.id}">
      <div class="inbox-row-avatar"><span>${escapeHtml(initOf(sender))}</span></div>
      <div class="inbox-row-main">
        <div class="inbox-row-line1">
          <span class="inbox-row-sender">${escapeHtml(sender)}${tier ? ' <span class="inbox-tier-badge">SUPER</span>' : ""}</span>
          <span class="inbox-row-time">${time}</span>
        </div>
        <div class="inbox-row-line2">
          <span class="inbox-row-subject">${escapeHtml(subj)}</span>
          ${preview ? `<span class="inbox-row-snippet"> — ${escapeHtml(preview)}</span>` : ""}
        </div>
        <div class="inbox-row-line3">
          <span class="inbox-row-status status-${t.status || "new"}">${ticketLabels[t.status] || (t.status || "new").toUpperCase()}</span>
          ${isDraft ? `<span class="inbox-row-status" style="background:rgba(220,169,109,.18);border-color:rgba(220,169,109,.4);color:#DCA96D">📥 DRAFT</span>` : ""}
          ${verifChip}
          ${(t.fromEmail && t.fromEmail !== "—") ? `<span class="inbox-row-email">✉️ ${escapeHtml(t.fromEmail)}</span>` : ""}
        </div>
      </div>
      <div class="inbox-row-quick-actions">
        <button type="button" class="inbox-quick-btn" data-card-action="draft" title="${isDraft ? "Keluarkan dari draft" : "Simpan ke draft"}" aria-label="Draft">${isDraft ? "📤" : "📥"}</button>
        <button type="button" class="inbox-quick-btn inbox-quick-btn-danger" data-card-action="delete" title="Hapus" aria-label="Hapus">🗑️</button>
      </div>
    </div>`;
  };

  // Bug row — kolom: severity badge, title, reporter, browser, time, action.
  const renderBugCard = (b) => {
    const sevColor = { critical: "danger", high: "danger", medium: "warn", low: "ok" }[b.sev] || "warn";
    const statusBtnLabel = b.status === "open" ? "Assign" : b.status === "assigned" ? "Close" : "Reopen";
    const isDraft = !!b.draft;
    return `<div class="inbox-row inbox-row-bug sev-${b.sev} ${isDraft ? "is-draft" : ""}" data-card-kind="bug" data-card-id="${b.id}">
      <span class="inbox-row-sev ${sevColor}">${(b.sev || "medium").toUpperCase()}</span>
      <div class="inbox-row-main">
        <div class="inbox-row-title">${escapeHtml(b.title || "(tanpa judul)")}${isDraft ? ` <span class="inbox-row-status" style="background:rgba(220,169,109,.18);border-color:rgba(220,169,109,.4);color:#DCA96D">📥 DRAFT</span>` : ""}</div>
        <div class="inbox-row-meta">
          <span class="inbox-row-reporter">👤 ${escapeHtml(b.reporter || "—")}</span>
          <span class="inbox-row-browser">🖥️ ${escapeHtml((b.browser || "—").slice(0, 32))}</span>
          <span class="inbox-row-time">${relTime(b.createdAt)}</span>
        </div>
      </div>
      <div class="inbox-row-actions">
        <button class="btn ghost sm" data-card-action="detail">Detail</button>
        <button class="btn primary sm" data-card-action="bug-status">${statusBtnLabel}</button>
      </div>
      <div class="inbox-row-quick-actions">
        <button type="button" class="inbox-quick-btn" data-card-action="draft" title="${isDraft ? "Keluarkan dari draft" : "Simpan ke draft"}" aria-label="Draft">${isDraft ? "📤" : "📥"}</button>
        <button type="button" class="inbox-quick-btn inbox-quick-btn-danger" data-card-action="delete" title="Hapus" aria-label="Hapus">🗑️</button>
      </div>
    </div>`;
  };

  // Chat row — kolom: avatar, sender, preview, time, action.
  const renderChatCard = (c) => {
    const preview = (c.lastText || "").slice(0, 80);
    const time = (typeof chatRelTime === "function" ? chatRelTime(c.lastTs) : relTime(c.lastTs));
    const fromLabel = c.lastFrom === "me" ? `<span class="inbox-row-from-tag">Kamu:</span> ` : "";
    const isDraft = !!threads[c.idx]?.draft;
    return `<div class="inbox-row inbox-row-chat ${c.unread ? "unread" : ""} ${isDraft ? "is-draft" : ""}" data-card-kind="chat" data-card-thread="${c.idx}">
      <div class="inbox-row-avatar"><span>${escapeHtml(c.init || initOf(c.name))}</span></div>
      <div class="inbox-row-main">
        <div class="inbox-row-line1">
          <span class="inbox-row-sender">@${escapeHtml(c.name)}${isDraft ? ` <span class="inbox-row-status" style="background:rgba(220,169,109,.18);border-color:rgba(220,169,109,.4);color:#DCA96D;font-size:9.5px">📥 DRAFT</span>` : ""}</span>
          <span class="inbox-row-time">${time || ""}</span>
        </div>
        <div class="inbox-row-snippet inbox-row-chat-preview">${fromLabel}${escapeHtml(preview)}</div>
      </div>
      ${c.unread ? `<span class="inbox-row-unread-dot" title="Belum dibaca"></span>` : ""}
      <div class="inbox-row-quick-actions">
        <button type="button" class="inbox-quick-btn" data-card-action="draft" title="${isDraft ? "Keluarkan dari draft" : "Simpan ke draft"}" aria-label="Draft">${isDraft ? "📤" : "📥"}</button>
        <button type="button" class="inbox-quick-btn inbox-quick-btn-danger" data-card-action="delete" title="Hapus" aria-label="Hapus">🗑️</button>
      </div>
    </div>`;
  };

  const emptyState = (icon, text) => `<div class="inbox-empty"><div class="inbox-empty-icon">${icon}</div><p>${text}</p></div>`;

  const emailEl = $("#inboxEmailList");
  const chatEl = $("#inboxChatList");
  const bugEl = $("#inboxBugList");

  const emptyMsg = q ? `Tidak ada hasil untuk "${escapeHtml(q)}"` : null;
  if (emailEl) emailEl.innerHTML = emailTickets.length
    ? emailTickets.map(renderTicketCard).join("")
    : emptyState("📧", emptyMsg || (f === "all" ? "Belum ada email masuk." : "Tidak ada email di filter ini."));
  if (chatEl) chatEl.innerHTML = chatItems.length
    ? chatItems.map(renderChatCard).join("")
    : emptyState("💬", emptyMsg || "Belum ada thread obrolan langsung.");
  if (bugEl) bugEl.innerHTML = bugList.length
    ? bugList.map(renderBugCard).join("")
    : emptyState("🐛", emptyMsg || (f === "all" ? "Belum ada bug dilaporkan." : "Tidak ada bug di filter ini."));

  // Event delegation — pasang listener SEKALI di wrap level. Re-render innerHTML
  // tidak menghilangkan listener karena listener-nya di parent yang persistent.
  if (!wrap.__inboxBound) {
    wrap.__inboxBound = true;
    wrap.addEventListener("click", e => {
      // Match both legacy `.inbox-card` & new gmail-style `.inbox-row` rows
      const card = e.target.closest(".inbox-card, .inbox-row");
      if (!card) return;
      const kind = card.dataset.cardKind;
      const btn = e.target.closest("[data-card-action]");
      const action = btn?.dataset.cardAction;

      // Ticket id (untuk ticket & bug, bukan chat)
      const cardId = Number(card.dataset.cardId);

      // Helper: buka detail modal
      const openDetail = () => {
        if (kind === "ticket") {
          const t = getAdminData("tickets").find(x => x.id === cardId);
          if (t) openInboxDetailModal({ kind: "ticket", item: t });
        } else if (kind === "bug") {
          const b = getAdminData("bugs").find(x => x.id === cardId);
          if (b) openInboxDetailModal({ kind: "bug", item: b });
        }
      };
      const openChatThread = () => {
        const idx = Number(card.dataset.cardThread);
        if (Number.isNaN(idx) || !state?.messages?.[idx]) return;
        switchView("messages");
        setTimeout(() => { if (typeof openChat === "function") openChat(idx); }, 80);
      };

      // Action button click
      if (btn) {
        e.stopPropagation();

        // Draft toggle — pindah ke/dari draft. Sumber data:
        //   ticket → getAdminData("tickets") via t.draft
        //   bug    → getAdminData("bugs") via b.draft
        //   chat   → state.messages[idx] via thread.draft + saveState()
        if (action === "draft") {
          if (kind === "ticket") {
            const arr = getAdminData("tickets");
            const t = arr.find(x => x.id === cardId); if (!t) return;
            t.draft = !t.draft;
            saveAdminData("tickets", arr);
            toast(t.draft ? "📥 Email dipindah ke Draft" : "📤 Email dikeluarkan dari Draft", "");
          } else if (kind === "bug") {
            const arr = getAdminData("bugs");
            const b = arr.find(x => x.id === cardId); if (!b) return;
            b.draft = !b.draft;
            saveAdminData("bugs", arr);
            toast(b.draft ? "📥 Bug dipindah ke Draft" : "📤 Bug dikeluarkan dari Draft", "");
          } else if (kind === "chat") {
            const idx = Number(card.dataset.cardThread);
            const th = state?.messages?.[idx]; if (!th) return;
            th.draft = !th.draft;
            if (typeof saveState === "function") saveState();
            toast(th.draft ? "📥 Chat dipindah ke Draft" : "📤 Chat dikeluarkan dari Draft", "");
          }
          renderAdminInbox();
          syncAdminNavBadges?.();
          return;
        }

        // Delete — hapus permanen. Pakai openConfirm modal kalau ada,
        // fallback ke native confirm.
        if (action === "delete") {
          const labelMap = { ticket: "email", bug: "bug report", chat: "chat thread" };
          const itemLabel = labelMap[kind] || "item";
          const doDelete = () => {
            if (kind === "ticket") {
              const arr = getAdminData("tickets").filter(x => x.id !== cardId);
              saveAdminData("tickets", arr);
            } else if (kind === "bug") {
              const arr = getAdminData("bugs").filter(x => x.id !== cardId);
              saveAdminData("bugs", arr);
            } else if (kind === "chat") {
              const idx = Number(card.dataset.cardThread);
              if (state?.messages && state.messages[idx]) {
                state.messages.splice(idx, 1);
                if (typeof saveState === "function") saveState();
              }
            }
            toast(`🗑️ ${itemLabel} dihapus`, "success");
            renderAdminInbox();
            syncAdminNavBadges?.();
          };
          if (typeof openConfirm === "function") {
            openConfirm({
              icon: "🗑️", iconClass: "danger",
              title: `Hapus ${itemLabel}?`,
              desc: `Tindakan ini tidak bisa dibatalkan.`,
              btnText: "🗑 Hapus permanen", btnClass: "danger",
              onConfirm: doDelete
            });
          } else if (window.confirm(`Hapus ${itemLabel}?`)) {
            doDelete();
          }
          return;
        }

        if (action === "detail") return openDetail();
        if (action === "open-chat") return openChatThread();
        if (kind === "ticket" && action === "status") {
          const labels = { new: "NEW", progress: "IN PROGRESS", resolved: "RESOLVED" };
          const arr = getAdminData("tickets");
          const t = arr.find(x => x.id === cardId); if (!t) return;
          const next = { new: "progress", progress: "resolved", resolved: "new" };
          t.status = next[t.status] || "new";
          saveAdminData("tickets", arr);
          pushAdminEvent("🎫", `Tiket <b>"${t.title}"</b> → ${labels[t.status]}`);
          toast(`🎫 Tiket → <b>${labels[t.status]}</b>`, t.status === "resolved" ? "success" : "");
          renderAdminInbox();
          syncAdminNavBadges?.();
          return;
        }
        if (kind === "bug" && action === "bug-status") {
          const arr = getAdminData("bugs");
          const b = arr.find(x => x.id === cardId); if (!b) return;
          if (b.status === "open") b.status = "assigned";
          else if (b.status === "assigned") b.status = "closed";
          else b.status = "open";
          saveAdminData("bugs", arr);
          pushAdminEvent(b.status === "closed" ? "✓" : (b.status === "assigned" ? "👤" : "↻"),
            `Bug <i>"${b.title}"</i> → ${b.status.toUpperCase()}`);
          toast(`🐛 Bug → <b>${b.status.toUpperCase()}</b>`, b.status === "closed" ? "success" : "");
          renderAdminInbox();
          syncAdminNavBadges?.();
          return;
        }
        return;
      }
      // Klik area card (selain button) → langsung buka detail/chat
      if (kind === "chat") return openChatThread();
      openDetail();
    });
  }

  // Toolbar bindings — search, filter chips, refresh button
  if (!wrap.__inboxToolbarBound) {
    wrap.__inboxToolbarBound = true;
    const searchEl = $("#inboxSearch");
    if (searchEl) {
      let t = null;
      searchEl.addEventListener("input", e => {
        clearTimeout(t);
        t = setTimeout(() => {
          _inboxState.search = e.target.value || "";
          renderAdminInbox();
        }, 120);
      });
    }
    wrap.querySelectorAll(".inbox-filter").forEach(btn => {
      btn.addEventListener("click", () => {
        wrap.querySelectorAll(".inbox-filter").forEach(b => b.classList.remove("active"));
        btn.classList.add("active");
        _inboxState.filter = btn.dataset.inboxFilter || "all";
        renderAdminInbox();
      });
    });
    const refreshBtn = $("#inboxRefresh");
    if (refreshBtn) {
      refreshBtn.addEventListener("click", () => {
        refreshBtn.classList.add("spinning");
        // Trigger soft re-pull dari cloud kalau tersedia, lalu re-render.
        const done = () => {
          renderAdminInbox();
          syncAdminNavBadges?.();
          setTimeout(() => refreshBtn.classList.remove("spinning"), 320);
          toast("✓ Inbox di-refresh", "success");
        };
        if (window.cloudSync?.softResync) {
          Promise.resolve(window.cloudSync.softResync()).finally(done);
        } else {
          done();
        }
      });
    }
  }
}

// Modal detail untuk ticket email & bug report. Tampilkan full content + aksi
// (Balas via Email untuk ticket, Update Status untuk keduanya). Modal di-inject
// dinamis ke body supaya tidak butuh markup HTML statis.
function openInboxDetailModal({ kind, item }) {
  // v535: status labels i18n (sebelumnya hardcoded EN)
  const ticketLabels = {
    new: t("admin.ticket.status.new"),
    progress: t("admin.ticket.status.progress"),
    resolved: t("admin.ticket.status.resolved"),
  };
  const bugStatusLabels = {
    open: t("admin.bug.status.open"),
    assigned: t("admin.bug.status.assigned"),
    closed: t("admin.bug.status.closed"),
  };
  const isTicket = kind === "ticket";
  const title = item.title || (isTicket ? t("ticket.no.subject") : t("video.untitled"));
  const body = isTicket ? (item.body || "(Pesan kosong)") : (item.desc || "(Deskripsi bug kosong)");
  const sender = item.from || item.reporter || "—";
  const senderEmail = item.fromEmail || "";
  const status = isTicket ? (item.status || "new") : (item.status || "open");
  const statusLabel = isTicket ? (ticketLabels[status] || status.toUpperCase()) : (bugStatusLabels[status] || status.toUpperCase());
  const sev = !isTicket ? (item.sev || "medium") : null;
  const browser = !isTicket ? item.browser : null;
  const ts = item.createdAt || Date.now();
  const dateStr = new Date(ts).toLocaleString("id-ID", { dateStyle: "full", timeStyle: "short" });
  const replies = isTicket && Array.isArray(item.replies) ? item.replies : [];

  const repliesHtml = replies.length ? `
    <div class="ticket-thread" style="margin-bottom:14px">
      <div style="font-size:11px;color:var(--muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:8px;font-weight:700">Riwayat Balasan (${replies.length})</div>
      ${replies.map(r => `
        <div class="ticket-thread-item">
          <div class="ticket-thread-head">
            <span class="ticket-thread-avatar">${escapeHtml((r.fromName || "Admin").slice(0,1).toUpperCase())}</span>
            <div class="ticket-thread-meta">
              <strong>${escapeHtml(r.fromName || "Super Admin")}</strong>
              <span>&lt;${escapeHtml(r.fromEmail || OFFICIAL_ADMIN_EMAIL)}&gt;</span>
            </div>
            <span class="ticket-thread-time" title="${new Date(r.ts).toLocaleString("id-ID")}">${chatRelTime(r.ts) || relTime(r.ts) || "—"}</span>
          </div>
          <div class="ticket-thread-body">${escapeHtml(r.body || "")}</div>
        </div>
      `).join("")}
    </div>
  ` : "";

  // Premium-verification email — admin perlu approve/reject di Premium Queue,
  // BUKAN cycle status biasa (new→progress→resolved). Detect via paymentCode
  // yang otomatis ke-set saat user kirim email lewat "Hubungi Support" → Email
  // dari payment status modal. Tombol Update Status diganti deep-link ke
  // admin-revenue + scroll ke baris payment yang dimaksud.
  const isPremiumVerif = isTicket && !!item.paymentCode;
  const premiumBadge = isPremiumVerif
    ? `<span style="font-size:10px;font-weight:700;padding:3px 8px;border-radius:4px;background:linear-gradient(90deg,#d4a93a,#f4c969);color:#1a0e10;letter-spacing:0.5px">⭐ VERIFIKASI PREMIUM · ${escapeHtml(item.paymentCode)}</span>`
    : "";

  const modal = document.createElement("div");
  modal.className = "modal show inbox-detail-modal";
  modal.style.cssText = "z-index:9999";
  modal.dataset.ticketId = isTicket ? String(item.id) : "";
  modal.innerHTML = `
    <div class="modal-backdrop" data-inbox-close></div>
    <div class="modal-panel" style="max-width:580px;padding:24px">
      <button class="modal-close" data-inbox-close>✕</button>
      <div style="display:flex;align-items:center;gap:10px;margin-bottom:6px;flex-wrap:wrap">
        <span style="font-size:22px">${isTicket ? "📧" : "🐛"}</span>
        <span style="font-size:10px;font-weight:700;padding:3px 8px;border-radius:4px;background:${isTicket ? "linear-gradient(90deg,#6D2932,#C7B7A3)" : (sev === "critical" || sev === "high" ? "#c0392b" : sev === "medium" ? "#d68910" : "#27ae60")};color:#fff;letter-spacing:0.5px">${statusLabel}${sev ? ` · ${sev.toUpperCase()}` : ""}</span>
        ${premiumBadge}
      </div>
      <h3 style="margin:0 0 14px;font-size:18px">${escapeHtml(title)}</h3>
      <div style="background:var(--bg-elev);border:1px solid var(--border);border-radius:10px;padding:14px;margin-bottom:14px">
        <div style="display:grid;grid-template-columns:auto 1fr;gap:6px 14px;font-size:13px">
          <span style="color:var(--muted)">Dari</span><strong>${escapeHtml(sender)}</strong>
          ${senderEmail ? `<span style="color:var(--muted)">Email</span><span style="color:var(--text)">${escapeHtml(senderEmail)}</span>` : ""}
          <span style="color:var(--muted)">Waktu</span><span>${escapeHtml(dateStr)}</span>
          ${browser ? `<span style="color:var(--muted)">Browser</span><span style="font-size:11.5px;color:var(--muted);word-break:break-all">${escapeHtml(browser)}</span>` : ""}
        </div>
      </div>
      <div style="background:var(--bg);border:1px solid var(--border);border-radius:10px;padding:14px;margin-bottom:14px;max-height:260px;overflow-y:auto">
        <div style="font-size:11px;color:var(--muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px;font-weight:700">${isTicket ? "Isi Pesan" : "Deskripsi Bug"}</div>
        <div style="font-size:14px;line-height:1.6;white-space:pre-wrap">${escapeHtml(body)}</div>
      </div>
      ${(isTicket && item.proofImage) ? `
      <div style="background:var(--bg);border:1px solid var(--border);border-radius:10px;padding:14px;margin-bottom:14px">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px">
          <div style="font-size:11px;color:var(--muted);text-transform:uppercase;letter-spacing:0.5px;font-weight:700">📎 Lampiran Bukti Pembayaran</div>
          ${item.paymentCode ? `<code style="font-family:'JetBrains Mono',monospace;font-size:11.5px;font-weight:700;background:var(--surface-2);padding:3px 8px;border-radius:6px;border:1px solid var(--border);color:var(--text)">${escapeHtml(item.paymentCode)}</code>` : ""}
        </div>
        <button type="button" class="inbox-proof-trigger" data-inbox-action="proof-zoom" style="display:block;width:100%;border-radius:8px;overflow:hidden;border:1px solid var(--border);background:var(--bg-elev);text-align:center;padding:0;cursor:zoom-in" title="Klik untuk lihat ukuran penuh + zoom">
          <img src="${item.proofImage}" alt="Bukti pembayaran" style="display:block;max-width:100%;max-height:380px;margin:0 auto;object-fit:contain;pointer-events:none"/>
        </button>
        <small style="display:block;margin-top:8px;font-size:11px;color:var(--muted);text-align:center">${escapeHtml(item.proofName || "bukti-pembayaran.png")} · klik gambar untuk perbesar &amp; zoom</small>
      </div>
      ` : ""}
      ${repliesHtml}
      <div style="display:flex;gap:10px;flex-wrap:wrap">
        ${isTicket && senderEmail ? `<button class="btn primary" data-inbox-action="reply">📧 ${replies.length ? "Balas Lagi" : "Balas Email"}</button>` : ""}
        ${isPremiumVerif
          ? `<button class="btn ghost" data-inbox-action="goto-verif" style="background:linear-gradient(90deg,#d4a93a,#f4c969);color:#1a0e10;font-weight:700;border:0">🔓 Verifikasi di Premium Queue</button>`
          : `<button class="btn ghost" data-inbox-action="status">↻ ${isTicket ? "Update Status" : (status === "open" ? "Assign" : status === "assigned" ? "Tutup" : "Reopen")}</button>`
        }
        <button class="btn ghost" data-inbox-close>Tutup</button>
      </div>
    </div>
  `;
  document.body.appendChild(modal);

  modal.addEventListener("click", e => {
    if (e.target.closest("[data-inbox-close]")) { modal.remove(); return; }
    const actBtn = e.target.closest("[data-inbox-action]");
    if (!actBtn) return;
    const act = actBtn.dataset.inboxAction;
    if (act === "reply" && senderEmail && isTicket) {
      // Tutup detail modal dulu supaya tidak overlap dengan compose
      modal.remove();
      openEmailComposer({ ticket: item, reopenDetailOnSend: true });
      return;
    }
    if (act === "proof-zoom" && item.proofImage) {
      // Open lightbox — admin perlu lihat detail receipt buat verifikasi.
      // Modal tetap terbuka di belakang biar admin bisa lanjut workflow.
      openImageLightbox({
        src: item.proofImage,
        name: item.proofName || "bukti-pembayaran.png",
        code: item.paymentCode || "",
      });
      return;
    }
    if (act === "goto-verif" && isPremiumVerif) {
      // Premium-verification email — tutup modal, switch ke admin-revenue,
      // lalu scroll & highlight baris payment dengan code yang dimaksud.
      modal.remove();
      goToPremiumVerification(item.paymentCode);
      return;
    }
    if (act === "status") {
      if (isTicket) {
        const arr = getAdminData("tickets");
        const t = arr.find(x => x.id === item.id); if (!t) return;
        const next = { new: "progress", progress: "resolved", resolved: "new" };
        t.status = next[t.status] || "new";
        saveAdminData("tickets", arr);
        pushAdminEvent("🎫", `Tiket <b>"${t.title}"</b> → ${ticketLabels[t.status]}`);
        toast(`🎫 Tiket → <b>${ticketLabels[t.status]}</b>`, t.status === "resolved" ? "success" : "");
      } else {
        const arr = getAdminData("bugs");
        const b = arr.find(x => x.id === item.id); if (!b) return;
        if (b.status === "open") b.status = "assigned";
        else if (b.status === "assigned") b.status = "closed";
        else b.status = "open";
        saveAdminData("bugs", arr);
        pushAdminEvent(b.status === "closed" ? "✓" : (b.status === "assigned" ? "👤" : "↻"), `Bug <i>"${b.title}"</i> → ${b.status.toUpperCase()}`);
        toast(`🐛 Bug → <b>${b.status.toUpperCase()}</b>`, b.status === "closed" ? "success" : "");
      }
      modal.remove();
      renderAdminInbox();
      syncAdminNavBadges?.();
    }
  });
}

// =================== IMAGE LIGHTBOX (admin proof viewer) ===================
// Full-screen lightbox untuk lihat receipt detail. Dipanggil dari modal
// detail email saat admin klik bukti pembayaran. Fitur: zoom 1x ↔ 2x via
// click, ESC/backdrop-close, code+filename labels supaya admin gak salah
// orang/code saat verifikasi.
function openImageLightbox({ src, name, code } = {}) {
  if (!src) return;
  // Hapus dulu kalau sudah ada lightbox sebelumnya (avoid stack)
  document.querySelectorAll(".image-lightbox").forEach(el => el.remove());

  const lb = document.createElement("div");
  lb.className = "image-lightbox";
  lb.innerHTML = `
    <div class="ilb-backdrop" data-ilb-close></div>
    <button type="button" class="ilb-close" data-ilb-close aria-label="Close">✕</button>
    <div class="ilb-head">
      ${code ? `<code class="ilb-code">${escapeHtml(code)}</code>` : ""}
      <span class="ilb-name">${escapeHtml(name || "bukti-pembayaran.png")}</span>
    </div>
    <div class="ilb-stage" data-ilb-stage>
      <img class="ilb-img" src="${src}" alt="${escapeHtml(name || "Bukti pembayaran")}"/>
    </div>
    <div class="ilb-foot">
      <small>Klik gambar untuk zoom · ESC atau klik area kosong untuk tutup</small>
    </div>
  `;
  document.body.appendChild(lb);
  // Force reflow + animate-in
  void lb.offsetWidth;
  lb.classList.add("show");

  const img = lb.querySelector(".ilb-img");
  const stage = lb.querySelector("[data-ilb-stage]");
  let zoomed = false;
  img?.addEventListener("click", () => {
    zoomed = !zoomed;
    img.classList.toggle("zoomed", zoomed);
    stage.style.cursor = zoomed ? "zoom-out" : "zoom-in";
    stage.style.overflow = zoomed ? "auto" : "hidden";
  });

  const close = () => {
    lb.classList.remove("show");
    setTimeout(() => lb.remove(), 200);
    document.removeEventListener("keydown", onKey);
  };
  const onKey = (e) => { if (e.key === "Escape") close(); };
  document.addEventListener("keydown", onKey);

  lb.addEventListener("click", (e) => {
    if (e.target.closest("[data-ilb-close]")) close();
  });
}

// =================== ADMIN: GO TO PREMIUM VERIFICATION ===================
// Dipanggil dari email detail modal saat admin klik "Verifikasi di Premium
// Queue". Switch ke view admin-premium-queue (BUKAN admin-revenue — itu
// dashboard pendapatan yang beda), reset filter ke "Semua" supaya code-nya
// pasti ke-render apapun status-nya, lalu scroll + highlight baris target.
function goToPremiumVerification(code) {
  if (typeof switchView !== "function") return;
  switchView("admin-premium-queue");
  if (typeof _adminPqFilter !== "undefined") _adminPqFilter = "all";
  if (typeof renderAdminPremiumQueue === "function") {
    try { renderAdminPremiumQueue(); } catch {}
  }
  // Sync filter chip UI (toggle "all"/"semua" active)
  document.querySelectorAll('[data-pq-filter]').forEach(b => {
    b.classList.toggle("active", b.dataset.pqFilter === "all");
  });
  // Scroll + highlight target row
  setTimeout(() => {
    const row = document.querySelector(`.pq-row[data-pq-code="${CSS.escape(code)}"]`);
    if (!row) {
      if (typeof toast === "function") toast(`⚠️ Payment ${code} tidak ditemukan di queue.`, "warning");
      return;
    }
    row.scrollIntoView({ behavior: "smooth", block: "center" });
    row.classList.add("pq-row-highlight");
    setTimeout(() => row.classList.remove("pq-row-highlight"), 2400);
    if (typeof toast === "function") toast(`🔓 Buka verifikasi untuk ${code}`, "info");
  }, 220);
}

// Modal compose untuk admin balas email tiket. Centered di tengah halaman
// supaya menyatu dengan dashboard (bukan floating dock di pojok). Kirim
// menyimpan reply ke ticket.replies[], otomatis status → progress, dan
// deliver salinan ke chat thread user supaya user tahu admin sudah balas
// (tanpa simulasi/auto-reply — ini dipicu manual oleh admin).
function openEmailComposer({ ticket, reopenDetailOnSend }) {
  // Hindari duplicate composer untuk ticket yang sama
  const existing = document.querySelector(`.compose-modal[data-ticket-id="${ticket.id}"]`);
  if (existing) { existing.querySelector(".compose-body-input")?.focus(); return; }

  const adminName = user?.name || user?.username || "Super Admin";
  const adminEmail = user?.email || OFFICIAL_ADMIN_EMAIL;
  const subjectDefault = (ticket.title || "").startsWith("Re:") ? ticket.title : `Re: ${ticket.title || "(tanpa subjek)"}`;
  const recipientName = ticket.from || "User";
  const recipientUsernameMatch = /\(@([^)]+)\)/.exec(ticket.from || "");
  const recipientUsername = recipientUsernameMatch ? recipientUsernameMatch[1] : null;
  const greeting = recipientName.replace(/\s*\(@[^)]+\)\s*$/, "").trim();

  const dock = document.createElement("div");
  dock.className = "compose-modal";
  dock.dataset.ticketId = String(ticket.id);
  dock.innerHTML = `
    <div class="compose-modal-backdrop" data-compose-close></div>
    <div class="compose-modal-panel">
      <div class="compose-header">
        <span class="compose-title">📧 Balas Pesan</span>
        <button type="button" class="compose-icon-btn" data-compose-close title="Tutup">✕</button>
      </div>
      <div class="compose-fields">
        <div class="compose-row">
          <label class="compose-label">Dari</label>
          <div class="compose-static">${escapeHtml(adminName)} &lt;${escapeHtml(adminEmail)}&gt;</div>
        </div>
        <div class="compose-row">
          <label class="compose-label">Kepada</label>
          <div class="compose-static">${escapeHtml(recipientName)} &lt;${escapeHtml(ticket.fromEmail)}&gt;</div>
        </div>
        <div class="compose-row">
          <label class="compose-label" for="composeSubject_${ticket.id}">Subjek</label>
          <input type="text" id="composeSubject_${ticket.id}" class="compose-subject-input" value="${escapeHtml(subjectDefault)}" />
        </div>
        <textarea class="compose-body-input" placeholder="Tulis balasan kamu di sini..." rows="10">Halo ${escapeHtml(greeting)},

Terima kasih sudah menghubungi kami.

[Tulis balasan di sini]

Salam,
${escapeHtml(adminName)}
Tim Playly</textarea>
      </div>
      <div class="compose-footer">
        <button type="button" class="btn primary compose-send-btn">📤 Kirim</button>
        <button type="button" class="btn ghost" data-compose-close>Batal</button>
        <span class="compose-hint">Pesan masuk ke inbox user via chat &amp; tersimpan di tiket</span>
      </div>
    </div>
  `;
  document.body.appendChild(dock);
  setTimeout(() => dock.querySelector(".compose-body-input")?.focus(), 80);

  // ESC key to close
  const escHandler = (ev) => {
    if (ev.key === "Escape" && document.body.contains(dock)) {
      ev.preventDefault();
      tryClose();
    }
  };
  document.addEventListener("keydown", escHandler);

  function tryClose() {
    const ta = dock.querySelector(".compose-body-input");
    const original = `Halo ${greeting},\n\nTerima kasih sudah menghubungi kami.`;
    const dirty = ta && ta.value.trim() && !ta.value.startsWith(original.slice(0, 30));
    if (dirty && !confirm("Buang draft balasan?")) return;
    dock.remove();
    document.removeEventListener("keydown", escHandler);
  }

  dock.addEventListener("click", e => {
    if (e.target.closest("[data-compose-close]")) { tryClose(); return; }
    if (e.target.closest(".compose-send-btn")) {
      const subjectInput = dock.querySelector(".compose-subject-input");
      const bodyInput = dock.querySelector(".compose-body-input");
      const subject = (subjectInput.value || "").trim();
      const replyBody = (bodyInput.value || "").trim();
      if (!subject) { subjectInput.focus(); toast("⚠️ Subjek wajib diisi", "warning"); return; }
      if (replyBody.length < 10) { bodyInput.focus(); toast("⚠️ Pesan minimal 10 karakter", "warning"); return; }

      const tickets = getAdminData("tickets");
      const t = tickets.find(x => x.id === ticket.id);
      if (!t) { toast("⚠️ Tiket tidak ditemukan", "warning"); return; }
      if (!Array.isArray(t.replies)) t.replies = [];
      const replyEntry = {
        id: Date.now() + Math.random(),
        ts: Date.now(),
        fromName: adminName,
        fromEmail: adminEmail,
        subject,
        body: replyBody
      };
      t.replies.push(replyEntry);
      // Auto-bump status → progress kalau masih new
      if (t.status === "new") t.status = "progress";
      saveAdminData("tickets", tickets);

      // Deliver ke chat thread user supaya user dapat notif real (tidak auto-reply,
      // ini balasan manual admin atas tiket user).
      if (recipientUsername && typeof deliverAdminMessage === "function") {
        const chatPreview = `📧 Balasan dari admin untuk tiket "${ticket.title}":\n\n${replyBody}`;
        try { deliverAdminMessage(recipientUsername, chatPreview); } catch {}
      }
      // Push notif kategori "email-reply" supaya muncul di Notifikasi Panel
      // user (📧 Balasan Email Admin section).
      if (recipientUsername && typeof pushUserNotification === "function") {
        try {
          pushUserNotification(recipientUsername, {
            type: "email-reply",
            text: `📧 Admin membalas email kamu: <b>"${escapeHtml(ticket.title || '')}"</b>`,
            init: "📧",
            fromUsername: "admin",
          });
        } catch {}
      }

      pushAdminEvent("📨", `Balasan email terkirim ke <b>${recipientName}</b>`);
      toast("📨 Balasan terkirim & tersimpan di tiket", "success");

      dock.remove();
      document.removeEventListener("keydown", escHandler);
      // Re-open detail modal dengan reply terbaru (kalau awalnya dibuka dari sana)
      if (reopenDetailOnSend) {
        openInboxDetailModal({ kind: "ticket", item: t });
      }
      renderAdminInbox?.();
      renderAdminTickets?.();
      syncAdminNavBadges?.();

      // Cloud sync — propagate ke device lain
      try { window.cloudSync?.softResync?.(); } catch {}
    }
  });
}

function renderAdminTickets() {
  const list = $("#adminTicketList"); if (!list) return;
  const tickets = [...getAdminData("tickets")].sort((a, b) => b.createdAt - a.createdAt);
  // v534 (2026-05-25): status labels i18n
  const labels = {
    new: t("admin.ticket.status.new"),
    progress: t("admin.ticket.status.progress"),
    resolved: t("admin.ticket.status.resolved"),
  };

  // Update top status pills
  const stats = $(".ticket-stats"); if (stats) {
    const m = getAdminMetrics();
    stats.innerHTML = `
      <span class="status-pill red"><i></i> ${m.tickets} baru</span>
      <span class="status-pill amber"><i></i> ${m.ticketsProgress} in-progress</span>
      <span class="status-pill green"><i></i> ${m.ticketsResolved} resolved</span>`;
  }

  // v533 (2026-05-25): empty state fallback — sebelumnya list.innerHTML = "" tanpa fallback.
  if (!tickets.length) {
    list.innerHTML = `<div class="admin-empty-state">
      <div class="admin-empty-icon">🎫</div>
      <h4>Belum ada tiket dukungan</h4>
      <p>Tiket dari user akan muncul di sini. Status awal "Baru" → klik tombol Status untuk siklus Diproses → Selesai.</p>
    </div>`;
    return;
  }

  list.innerHTML = tickets.map(t => {
    const bodyHtml = t.body
      ? `<div class="ticket-body" hidden>${escapeHtml(t.body).replace(/\n/g, "<br/>")}</div>`
      : "";
    const fromEmailHtml = t.fromEmail && t.fromEmail !== "—"
      ? `<small class="ticket-email">✉️ ${escapeHtml(t.fromEmail)}</small>`
      : "";
    return `<div class="ticket-item ${t.priority || "normal"}" data-ticket-id="${t.id}" data-ticket-status="${escapeHtml(t.status || "")}" data-ticket-updated-at="${Number(t.updatedAt) || 0}">
      <div class="ticket-row-main">
        <div class="ticket-channel">${t.ch || "📧"}</div>
        <div class="ticket-meta">
          <b>${escapeHtml(t.title || window.t("ticket.no.subject"))}</b>
          <div class="ticket-from">${escapeHtml(t.from || "—")}</div>
          ${fromEmailHtml}
          <small>${relTime(t.createdAt)}</small>
        </div>
        <div class="ticket-actions">
          <span class="ticket-status ${t.status}">${labels[t.status] || (t.status || "").toUpperCase()}</span>
          ${t.body ? `<button class="btn ghost sm" data-ticket-action="toggle">📖 Detail</button>` : ""}
          <button class="btn ghost sm" data-ticket-action="status">↻ Status</button>
        </div>
      </div>
      ${bodyHtml}
    </div>`;
  }).join("");

  // Action buttons: toggle body, cycle status
  list.querySelectorAll("[data-ticket-action]").forEach(btn => {
    btn.addEventListener("click", e => {
      e.stopPropagation();
      const item = btn.closest(".ticket-item");
      const id = Number(item.dataset.ticketId);
      const action = btn.dataset.ticketAction;
      if (action === "toggle") {
        const body = item.querySelector(".ticket-body");
        if (body) body.hidden = !body.hidden;
        return;
      }
      if (action === "status") {
        // v546 (2026-05-25): Audit moderation M3 — dual-admin race detection.
        // Bandingkan state yang user LIHAT (data-attr di DOM saat render) vs
        // state CURRENT di storage. Kalau ada admin lain (atau cloud-sync)
        // sudah modify ticket setelah render → toast warning + re-render,
        // abort write. Tanpa ini: last writer wins silent overwrite.
        const renderedStatus = item.dataset.ticketStatus || "";
        const renderedUpdatedAt = Number(item.dataset.ticketUpdatedAt) || 0;
        const arr = getAdminData("tickets");
        const t = arr.find(x => x.id === id);
        if (!t) {
          toast("⚠️ Tiket sudah dihapus admin lain. Refresh halaman.", "warning");
          renderAdminTickets();
          return;
        }
        const currentUpdatedAt = Number(t.updatedAt) || 0;
        if (currentUpdatedAt > renderedUpdatedAt || (t.status || "") !== renderedStatus) {
          toast(`⚠️ Tiket sudah diubah admin lain${t.updatedBy ? " (" + escapeHtml(t.updatedBy) + ")" : ""}. Refresh & coba lagi.`, "warning");
          renderAdminTickets();
          return;
        }
        const next = { new: "progress", progress: "resolved", resolved: "new" };
        const oldStatus = t.status;
        t.status = next[t.status] || "new";
        t.updatedAt = Date.now();
        t.updatedBy = user?.username || "admin";
        // v537 CRITICAL FIX 2 (2026-05-25): track admin yang resolve untuk
        // audit accountability + race-detection (audit moderation flow C2).
        if (t.status === "resolved" && !t.resolvedBy) {
          t.resolvedBy = user?.username || "admin";
          t.resolvedAt = Date.now();
        }
        saveAdminData("tickets", arr);
        pushAdminEvent("🎫", `Tiket <b>"${t.title}"</b> → ${labels[t.status]}`);
        toast(`${window.t("admin.toast.ticket.status")} <b>${labels[t.status]}</b>`, t.status === "resolved" ? "success" : "");
        // v537 CRITICAL FIX 2: notify submitter ticket. Sebelumnya status
        // cycle tidak kirim notif ke user yg submit → user silent diam-diam
        // status berubah. Sekarang trigger deliverNotification.
        try {
          const submitterUsername = t.fromUsername || (t.from && t.from.replace(/^@/, ""));
          if (submitterUsername && typeof deliverNotification === "function") {
            const statusMsg = t.status === "progress" ? "sedang diproses admin"
              : t.status === "resolved" ? "sudah diselesaikan admin"
              : "dibuka kembali oleh admin";
            deliverNotification(submitterUsername, {
              type: "ticket-status",
              text: `🎫 Tiket kamu <b>"${escapeHtml(t.title || window.t("ticket.no.subject"))}"</b> ${statusMsg}.`,
              init: "🎫",
              fromUsername: "admin",
            });
          }
        } catch (err) { console.warn("[ticket] notify submitter failed:", err); }
        renderAdminTickets();
        renderAdminAlerts();
        renderAdminLiveFeed();
        syncAdminNavBadges();
      }
    });
  });
  // Klik baris (selain tombol) → toggle detail
  list.querySelectorAll(".ticket-item").forEach(item => {
    item.addEventListener("click", e => {
      if (e.target.closest("[data-ticket-action]")) return;
      const body = item.querySelector(".ticket-body");
      if (body) body.hidden = !body.hidden;
    });
  });
}

// One-time admin event wiring (mod tabs, user search) — uses delegation
function setupAdminEvents() {
  if (window.__adminEventsBound) return;
  window.__adminEventsBound = true;

  // Moderation tab filter
  document.addEventListener("click", e => {
    const tab = e.target.closest(".mod-tab");
    if (!tab) return;
    $$(".mod-tab").forEach(t => t.classList.toggle("active", t === tab));
    renderAdminModeration();
  });

  // User search (live filter)
  const search = $("#adminUserSearch");
  if (search && !search.dataset.bound) {
    search.dataset.bound = "1";
    search.addEventListener("input", () => renderAdminUsers());
  }

  // Refresh button — narik state terbaru dari Supabase lalu re-render
  const refresh = $("#adminUserRefresh");
  if (refresh && !refresh.dataset.bound) {
    refresh.dataset.bound = "1";
    refresh.addEventListener("click", () => {
      refresh.classList.add("spinning");
      const done = () => {
        renderAdminUsers();
        renderAdminKPI?.();
        syncAdminNavBadges?.();
        setTimeout(() => refresh.classList.remove("spinning"), 320);
        toast("✓ User Management di-refresh dari cloud", "success");
      };
      if (window.cloudSync?.softResync) {
        Promise.resolve(window.cloudSync.softResync()).finally(done);
      } else {
        done();
      }
    });
  }
}

function renderAdminBugs() {
  const list = $("#adminBugList"); if (!list) return;
  const bugs = [...getAdminData("bugs")].sort((a, b) => {
    const order = { critical: 0, high: 1, medium: 2, low: 3 };
    return (order[a.sev] || 9) - (order[b.sev] || 9) || b.createdAt - a.createdAt;
  });

  list.innerHTML = bugs.map(b => `<div class="bug-item" data-bug-id="${b.id}">
    <div>
      <h4><span class="sev ${b.sev}">${b.sev.toUpperCase()}</span>${b.title} ${b.status === "closed" ? `<small style='color:#10b981;font-weight:600;margin-left:8px'>✓ ${t("admin.bug.status.closed")}</small>` : b.status === "assigned" ? `<small style='color:#f59e0b;font-weight:600;margin-left:8px'>👤 ${t("admin.bug.status.assigned")}</small>` : ""}</h4>
      <p>${b.desc}</p>
      <div class="bug-meta">📌 ${b.reporter} • ${relTime(b.createdAt)} • 🖥️ ${b.browser}</div>
    </div>
    <div class="bug-side">
      <button class="btn ghost sm" data-bug-action="detail">Detail</button>
      ${b.status === "open" ? `<button class="btn primary sm" data-bug-action="assign">Assign</button>` : ""}
      ${b.status === "assigned" ? `<button class="btn primary sm" data-bug-action="close">Close</button>` : ""}
      ${b.status === "closed" ? `<button class="btn ghost sm" data-bug-action="reopen">Reopen</button>` : ""}
    </div>
  </div>`).join("");

  list.querySelectorAll("[data-bug-action]").forEach(btn => {
    btn.addEventListener("click", e => {
      const id = Number(e.currentTarget.closest(".bug-item").dataset.bugId);
      const action = e.currentTarget.dataset.bugAction;
      const arr = getAdminData("bugs");
      const b = arr.find(x => x.id === id); if (!b) return;
      if (action === "detail") return toast(`📋 ${b.title}<br/><small>${b.desc}</small>`);
      if (action === "assign") { b.status = "assigned"; pushAdminEvent("👤", `Bug <i>"${b.title}"</i> di-assign ke moderator`); toast(t("admin.toast.bug.assigned"), "success"); }
      if (action === "close") { b.status = "closed"; pushAdminEvent("✓", `Bug <i>"${b.title}"</i> di-close`); toast(t("admin.toast.bug.closed"), "success"); }
      if (action === "reopen") { b.status = "open"; pushAdminEvent("↻", `Bug <i>"${b.title}"</i> di-reopen`); toast("↻ Bug di-reopen"); }
      saveAdminData("bugs", arr);
      renderAdminBugs();
      renderAdminLiveFeed();
    });
  });
}

// ----------------------- VIEW SWITCHING -----------------------
function switchView(name, { fromNav = false } = {}) {
  const homeView = user?.role === "admin" ? "admin-dashboard" : "home";

  // Access guard — admin-revenue HANYA boleh diakses super admin (per user
  // 2026-05-06). Admin biasa yang nyoba (lewat URL/deep-link/sidebar leak)
  // di-redirect ke admin-dashboard + dikasih toast.
  if (name === "admin-revenue" && user?.role === "admin") {
    const isSuper = (typeof isSuperAdmin === "function") ? isSuperAdmin(user) : false;
    if (!isSuper) {
      if (typeof toast === "function") {
        toast("🔒 Halaman Pendapatan hanya bisa diakses super admin", "warning");
      }
      name = "admin-dashboard";
    }
  }

  // Access guard — user-only views (videos/upload/profile/stats/insight/dst.)
  // JANGAN bisa diakses admin (per request user 2026-05-11). Sebelumnya admin
  // bisa nyangkut di halaman Pustaka Saya kosong + ke-trigger ads ticker.
  // Redirect ke admin-dashboard + toast info.
  const USER_ONLY_VIEWS = [
    "videos", "upload", "storage", "profile", "myprofile",
    "stats", "insight", "premium-insight",
    "people", "discover", "history", "activity",
    "player", "user-profile", "user-email"
  ];
  if (user?.role === "admin" && USER_ONLY_VIEWS.includes(name)) {
    if (typeof toast === "function") {
      toast("Halaman ini khusus untuk user kreator", "info");
    }
    name = "admin-dashboard";
  }

  // BUG FIX: dulu ada "klik nav 2x → balik ke prevView" yang bikin user balik
  // ke Home saat klik bar yang sama dua kali. User minta klik bar lagi tetap
  // stay di halaman itu. Logic back-navigation dihilangkan sepenuhnya.
  // Sidebar "My Library" → halaman /videos (3 section: My Video, New Videos,
  // Download) sekarang aktif lagi sebagai view utama. Render via renderMyLibrary.
  // (Dulu redirect ke player; sekarang user mau halaman list yang benar.)
  // Safety net: clear any leftover body overflow lock from modals that were
  // dismissed without their close handler (e.g., celebration popup, status popup)
  document.body.style.overflow = "";

  // Cleanup player kalau user meninggalkan view 'player'
  if (state.currentView === "player" && name !== "player") {
    cleanupPlayerView();
  }
  // Inline players di card juga di-pause supaya tidak terus jalan di background
  if (name !== state.currentView) cleanupAllInlinePlayers();
  // Cleanup placeholder DM threads (no history) saat user meninggalkan messages view.
  // Per request 2026-05-09: kalau user buka picker → pilih lawan → tidak jadi nulis
  // pesan, threadnya jangan persist. Keep: thread yang sudah ada history, broadcast
  // admin, dan archived chats.
  if (state.currentView === "messages" && name !== "messages" && Array.isArray(state.messages)) {
    const before = state.messages.length;
    state.messages = state.messages.filter(m =>
      (Array.isArray(m.history) && m.history.length > 0) || m.isAdmin || m.isBroadcast || m.archived
    );
    if (state.messages.length !== before) {
      saveState();
    }
    // Pastikan chat user-picker modal tidak ikut "bocor" ke view lain
    document.getElementById("__chatUserPicker")?.remove();
  }
  if (name !== state.currentView) state.prevView = state.currentView;
  state.currentView = name;
  saveState();

  $$(".view").forEach(v => v.classList.toggle("active", v.dataset.view === name));
  $$(".nav-item, .footer-link[data-view]").forEach(n => n.classList.toggle("active", n.dataset.view === name));

  // Ticker & Ad Banner — tampil hanya saat player view aktif
  // EXCLUSIVE untuk user FREE: admin & premium user JANGAN dapat ads sama sekali
  // (per request user 2026-05-11). Gate triple: view=player + role!=admin + tier!=premium.
  const _ticker    = document.getElementById("playerTicker");
  const _adBanner  = document.getElementById("playerAdBanner");
  const _isPlayer  = name === "player";
  const _isAdmin   = user?.role === "admin" || document.body.dataset.role === "admin";
  const _isPremium = user?.tier === "premium";
  const _showAds   = _isPlayer && !_isAdmin && !_isPremium;
  if (_ticker)   _ticker.hidden   = !_showAds;
  if (_adBanner) _adBanner.hidden = !_showAds;
  document.body.classList.toggle("player-view-active", _isPlayer);

  // Dreams FX hanya aktif di dashboard utama (user / admin).
  document.body.classList.toggle("dreams-on", name === "home" || name === "admin-dashboard");

  const crumb = $("#breadcrumb");
  // Breadcrumb root: pakai "Home" untuk semua role — supaya admin & user dashboard
  // konsisten (sebelumnya admin tampil "Admin" yang membingungkan navigasi).
  // Terjemahkan via t() supaya tidak bergantung pada tree-walker.
  const homeLabel = t("page.home") || "Home";
  if (name === homeView) {
    crumb.innerHTML = `<a href="#" class="active" data-view="${homeView}">${homeLabel}</a>`;
  } else {
    // Build parent chain: home → ...parents → current
    const chain = [];
    let cur = name;
    const guard = new Set();
    while (VIEW_PARENTS[cur] && !guard.has(cur)) {
      guard.add(cur);
      cur = VIEW_PARENTS[cur];
      chain.unshift(cur);
    }
    // Helper: get translated breadcrumb label
    const trCrumb = (vname) => {
      const titleKeyMap = {
        home: "page.home", videos: "page.library", upload: "page.upload",
        history: "page.history", stats: "page.stats", messages: "page.messages",
        activity: "page.activity", discover: "page.discover", people: "page.search",
        profile: "page.profile.edit", settings: "page.settings",
        player: "page.library", "user-profile": "page.profile.creator",
        "myprofile": "page.profile.my", "user-email": "page.email",
      };
      const key = titleKeyMap[vname];
      if (key) return t(key);
      return VIEW_TITLES[vname] || vname;
    };
    const parts = [`<a href="#" data-view="${homeView}">${homeLabel}</a>`];
    for (const v of chain) {
      parts.push(`<span class="sep">/</span><a href="#" data-view="${v}">${trCrumb(v)}</a>`);
    }
    // Library view: ganti label di breadcrumb sesuai sub-tab aktif.
    // Parent ("all") → "My Library", sub-tab → label sub-tab dalam Bahasa Indonesia.
    let crumbLabel = trCrumb(name);
    if (name === "videos") {
      const labelMap = {
        all:      "My Library",
        my:       "Video Saya",
        status:   "Status Video",
        new:      "New Videos",
        download: "Unduhan",
      };
      crumbLabel = labelMap[state?.libTab || "all"] || "My Library";
    }
    parts.push(`<span class="sep">/</span><a href="#" class="active">${crumbLabel}</a>`);
    crumb.innerHTML = parts.join("");
  }
  crumb.querySelectorAll("[data-view]").forEach(a => {
    a.addEventListener("click", e => { e.preventDefault(); switchView(a.dataset.view); });
  });

  // Tier-gated views (premium-only) — render premium UI atau upgrade prompt
  // Live Stream view dihapus 2026-05-04 — routing skip.
  if (name === "premium-insights") renderPremiumInsightsView();

  if (name === "home") {
    // Refresh konten home tiap kali user navigate ke sini — supaya Featured
    // dan tile lain selalu sinkron dengan upload terbaru / follow / dll.
    renderHomeActivity();
    renderHomeStats();
    renderLiveMetrics();
    renderCreatorSpotlight();
    renderFeatured();
    renderCreators();
    // 2-col home row baru (per request 2026-05-03 — replaces RECENT ACTIVITY
    // + SPOTLIGHT CREATOR section): CONTINUE WATCHING + NEW FROM FOLLOWING
    renderHomeNotifLatest();
    renderHomeTierWidget();
    renderHomeFollowingFeed();
    if (typeof renderHomePerfCard === "function") renderHomePerfCard();
    if (typeof renderHomeSuggestCard === "function") renderHomeSuggestCard();
    renderHomeWeather();
    if (typeof renderHomeSmartActions === "function") renderHomeSmartActions();
    updateHeroDmAlert();
  }
  if (name === "history") renderHistory();
  if (name === "notifications") {
    if (typeof renderNotifPage === "function") renderNotifPage();
  }
  if (name === "storage") renderStoragePage();
  if (name === "stats") setStatsTab("all"); // default tampil semua section
  if (name === "stats") setTimeout(drawChart, 50);
  if (name === "admin-premium-queue") {
    if (typeof renderAdminPremiumQueue === "function") setTimeout(renderAdminPremiumQueue, 30);
  }
  if (name === "videos") {
    renderVideoGrid();
    renderMyLibrary();
    // Restore last active library tab (default "my")
    setTimeout(() => {
      try { setLibraryTab(state?.libTab || "my"); } catch {}
      try { syncLibTabCounts(); } catch {}
    }, 30);
  }
  if (name === "messages") {
    // Pastikan list pesan fresh saat user buka view (cover kasus pesan masuk
    // dari user lain saat user di view lain). renderMsgList sudah include
    // re-load state.messages dari localStorage di awal function.
    renderMsgList();
    // Auto-open picker dihilangkan: terlalu intrusive saat user cuma mau
    // navigate ke Pesan. User dapat klik tombol "+ New Message" untuk
    // memulai chat baru — empty state list sudah memberi instruksi tsb.
  }
  if (name === "people") {
    // Render dulu pakai data lokal supaya tampilan tidak kosong, lalu force pull
    // semua akun terbaru dari Supabase. Setelah cloud-sync apply, listener
    // playly:cloud-applied yang sudah meng-handle "people" akan re-render
    // otomatis sehingga user baru dari device lain langsung muncul.
    renderPeople();
    if (window.cloudSync?.softResync) {
      Promise.resolve(window.cloudSync.softResync()).then(() => renderPeople()).catch(() => {});
    }
  }
  if (name === "discover") {
    renderFYP();
    renderSuggestUsers();
    renderDiscoverTrending();
  }
  else pauseAllFypVideos?.(); // jeda video FYP saat pindah view
  if (name === "profile") populateProfileForm();
  if (name === "user-profile") renderUserProfile();
  if (name === "settings") {
    populateSettingsPrefs();
    refreshTwoFASettings();
    if (user?.role === "admin") {
      populatePlatformSettings();
      populateAdminSessionInfo();
    } else if (typeof renderSettingsBilling === "function") {
      renderSettingsBilling();
    }
  }
  if (name === "admin-revenue") renderAdminRevenue();
  else stopRevenueLive();
  if (name === "admin-videos") { renderAdminVideos(); renderAdminModeration(); }
  if (name === "admin-comms") renderAdminComms();
  if (name === "admin-comms-broadcasts") {
    renderCommsKpis();
    renderCommsBroadcastLog();
  }
  if (name === "admin-audit") renderAdminAudit();
  if (name === "admin-analytics") renderAdminAnalytics();
  if (name === "admin-ads") loadAdManagerForm();
  if (name === "admin-inbox") renderAdminInbox();
  // Admin views yang bergantung pada data lintas-device → soft resync dari Supabase
  // begitu admin masuk view, supaya data user/inbox terbaru langsung kelihatan
  // tanpa harus refresh manual atau tunggu interval 4s.
  if (name === "admin-dashboard") {
    // Stagger fade-in: reset class lalu re-add di next frame supaya animasi jalan ulang
    const ah = document.querySelector(".admin-hero");
    if (ah) {
      ah.classList.remove("anim-enter");
      requestAnimationFrame(() => requestAnimationFrame(() => ah.classList.add("anim-enter")));
    }
  }
  if ((name === "admin-users" || name === "admin-inbox" || name === "admin-dashboard")
      && window.cloudSync?.softResync) {
    Promise.resolve(window.cloudSync.softResync()).then(() => {
      if (state?.currentView === name) {
        if (name === "admin-users") renderAdminUsers();
        else if (name === "admin-inbox") renderAdminInbox();
        else if (name === "admin-dashboard") { renderAdminKPI?.(); renderAdminTopInsights?.(); }
        renderAdminAlerts?.();
        renderAdminLiveFeed?.();
        syncAdminNavBadges?.();
      }
    }).catch(() => {});
  }

  if (window.innerWidth <= 768) $("#sidebar").classList.remove("open");
  window.scrollTo({ top: 0, behavior: "smooth" });

  // Sync URL hash supaya reload/share preserve view aktif (v479).
  // pushView pakai replaceState (no back-stack flood). Skip kalau view=player
  // — pushWatch dipanggil di openPlayer dengan videoId.
  try {
    if (window.playlyRouter && name !== "player") window.playlyRouter.pushView(name);
  } catch {}

  // Beritahu observer scroll-reveal supaya re-scan element baru di view ini
  window.dispatchEvent(new CustomEvent("playly:view-changed", { detail: { view: name } }));
}

$$(".nav-item, .footer-link[data-view], .storage-clickable[data-view]").forEach(n => {
  n.addEventListener("click", e => {
    e.preventDefault();
    const group = n.closest(".nav-group");
    const hasSub = !!group; // parent yang punya sub-list

    // PARENT dengan sub-items → toggle expand + navigate ke parent view.
    // Klik parent label → reset sub-item active state + tampilkan gabungan
    // semua section (sesuai permintaan user 2026-05-05).
    if (hasSub && n.classList.contains("nav-parent")) {
      e.stopPropagation();
      const willExpand = !group.classList.contains("expanded");
      // Tutup group lain (collapse all siblings) untuk UX yang lebih bersih
      $$(".nav-group.expanded").forEach(g => { if (g !== group) toggleNavGroup(g, false); });
      toggleNavGroup(group, willExpand);
      // Reset active sub-item di group ini
      group.querySelectorAll(".nav-subitem").forEach(x => x.classList.remove("active"));
      // Navigate ke parent view (idempotent)
      switchView(n.dataset.view, { fromNav: true });
      // Khusus My Library: reset library tab ke "all" supaya tampil gabungan.
      // Dipanggil setelah switchView selesai (yang restore libTab terakhir).
      if (n.dataset.view === "videos") {
        setTimeout(() => {
          if (typeof setLibraryTab === "function") setLibraryTab("all");
          const view = document.querySelector('section.view[data-view="videos"]');
          if (view) {
            const h = view.querySelector(".page-head h2, .view-header h2");
            if (h && h.dataset.originalTitle) {
              h.textContent = h.dataset.originalTitle;
              delete h.dataset.originalTitle;
            }
            if (typeof applyFocus === "function") applyFocus(view, "all");
          }
        }, 50);
      }
      // Khusus Messages: reset DM filter ke "all" + re-render. Plus reset
      // ke landing (per request user 2026-05-16): layout/list muncul hanya
      // setelah klik tab atau "+ Pesan Baru".
      if (n.dataset.view === "messages") {
        setTimeout(() => {
          if (typeof dmState !== "undefined") dmState.filter = "all";
          if (typeof renderDmList === "function") renderDmList();
          if (typeof _dmApplyView === "function") _dmApplyView();
          document.querySelectorAll(".dm-section-tab").forEach(function (t) {
            t.classList.toggle("active", t.dataset.dmFilter === "all");
          });
        }, 50);
      }
      // Khusus User Email: reset filter ke "all" + re-render
      if (n.dataset.view === "user-email") {
        setTimeout(() => {
          if (typeof userEmailState !== "undefined") userEmailState.filter = "all";
          if (typeof renderUserEmail === "function") renderUserEmail();
        }, 50);
      }
      // Khusus Statistik: reset stats tab ke "all"
      if (n.dataset.view === "stats") {
        setTimeout(() => {
          if (typeof setStatsTab === "function") setStatsTab("all");
        }, 50);
      }
      return;
    }

    // Plain nav-item (tanpa sub) → navigasi seperti biasa.
    // Per request user 2026-05-10h: pindah ke fitur lain → group sidebar yg
    // sebelumnya expanded harus auto-collapse supaya UI bersih.
    $$(".nav-group.expanded").forEach(g => toggleNavGroup(g, false));
    switchView(n.dataset.view, { fromNav: true });
  });
});

// ----------------------- SIDEBAR EXPAND/COLLAPSE & SUB-NAV -----------------------
// User minta: jangan langsung terbuka — hanya buka saat di-klik. Jadi default
// SEMUA group collapsed di awal (tidak ada restore localStorage, tidak ada
// auto-expand berdasarkan view aktif).
function toggleNavGroup(group, expand) {
  group.classList.toggle("expanded", !!expand);
}
// Bersihkan localStorage flag versi lama supaya tidak ada group yang nyangkut
// terbuka di reload berikutnya.
try { localStorage.removeItem("playly-nav-expanded"); } catch {}

// Sub-item click → deep-link ke parent view + jalankan aksi (filter / scroll / focus)
document.addEventListener("click", e => {
  const sub = e.target.closest(".nav-subitem");
  if (!sub) return;
  e.preventDefault();
  e.stopPropagation();
  const targetView = sub.dataset.view;
  const action = sub.dataset.subAction || "";
  const subText = (sub.textContent || "").trim();
  // Mark active sub-item dalam group-nya
  const group = sub.closest(".nav-group");
  if (group) {
    group.querySelectorAll(".nav-subitem").forEach(x => x.classList.toggle("active", x === sub));
    if (!group.classList.contains("expanded")) toggleNavGroup(group, true);
  }
  // Navigate ke parent view dulu
  if (typeof switchView === "function" && targetView) {
    switchView(targetView, { fromNav: true });
  }
  // Jalankan SEMUA aksi (composable dengan separator "|") setelah view siap,
  // lalu update judul halaman supaya match dengan nama sub-item.
  setTimeout(() => {
    action.split("|").forEach(a => runSubAction(a.trim()));
    const view = document.querySelector(`section.view[data-view="${targetView}"]`);
    if (view) updateViewTitle(view, subText);
  }, 80);
  // Tutup sidebar di mobile
  if (window.innerWidth <= 768) $("#sidebar")?.classList.remove("open");
});

// Update h2 view dengan judul sub-item — simpan judul asli sekali supaya bisa
// di-restore saat user reset/keluar dari focus mode.
function updateViewTitle(view, title) {
  if (!view || !title) return;
  // FIX 2026-05-25: skip kalau dm-filter sub-action lagi jalan — title untuk
  // halaman messages dikelola oleh renderMsgList (strip emoji + sinkron SVG
  // icon). updateViewTitle akan override dgn teks polos, bikin emoji nongol
  // lagi + SVG icon nggak ganti.
  if (window.__dmFilterFromNav && view.dataset.view === "messages") return;
  const h = view.querySelector(".page-head h2, .view-header h2");
  if (!h) return;
  if (!h.dataset.originalTitle) h.dataset.originalTitle = h.textContent;
  h.textContent = title;
  // Update breadcrumb biar match dengan focus
  const crumb = document.querySelector(".breadcrumb");
  if (crumb) {
    const links = crumb.querySelectorAll("a");
    const last = links[links.length - 1];
    if (last) {
      if (!last.dataset.originalText) last.dataset.originalText = last.textContent;
      last.textContent = title;
    }
  }
}
function restoreViewTitle(view) {
  if (!view) return;
  const h = view.querySelector(".page-head h2, .view-header h2");
  if (h && h.dataset.originalTitle) {
    h.textContent = h.dataset.originalTitle;
    delete h.dataset.originalTitle;
  }
  const crumb = document.querySelector(".breadcrumb");
  if (crumb) {
    crumb.querySelectorAll("a").forEach(a => {
      if (a.dataset.originalText) {
        a.textContent = a.dataset.originalText;
        delete a.dataset.originalText;
      }
    });
  }
}

// Reset focus + active sub-item saat user klik parent label langsung
// (tanpa via sub-item) — kembalikan view ke "show all"
function resetGroupFocus(group) {
  if (!group) return;
  group.querySelectorAll(".nav-subitem").forEach(x => x.classList.remove("active"));
  const targetView = group.querySelector(".nav-parent")?.dataset.view;
  if (!targetView) return;
  const view = document.querySelector(`section.view[data-view="${targetView}"]`);
  if (view) applyFocus(view, "all");
  // Khusus My Library: reset ke "all" supaya semua section (My Videos + Status + Unduhan) tampil gabungan
  if (targetView === "videos" && typeof setLibraryTab === "function") {
    setLibraryTab("all");
  }
}

function runSubAction(action) {
  if (!action) return;
  const idx = action.indexOf(":");
  const kind = idx === -1 ? action : action.slice(0, idx);
  const value = idx === -1 ? "" : action.slice(idx + 1);
  if (!kind) return;

  if (kind === "focus") {
    // Cari section view aktif lalu apply focus
    const activeView = document.querySelector("section.view.active");
    if (activeView) applyFocus(activeView, value);
    // Sync ke library tab system kalau sidebar sub-item nge-target library section.
    // Ini bridge sistem lama (focus-target) → sistem baru (data-lib-active + breadcrumb)
    const focusToLibTab = {
      "my-video": "my",
      "status-videos": "status",

      "download": "download",
    };
    if (focusToLibTab[value] && typeof setLibraryTab === "function") {
      setLibraryTab(focusToLibTab[value]);
    }
    // Side Banner: auto-expand body editor saat user klik sidebar "Banner Samping"
    if (value === "sb") {
      const sbCard = document.querySelector('.ad-section[data-ad-type="sb"]');
      const sbBody = document.getElementById("adSbBody");
      const sbToggle = document.getElementById("adSbToggle");
      if (sbCard && sbBody) {
        sbCard.classList.remove("ad-sb-collapsed");
        sbBody.hidden = false;
        if (sbToggle) sbToggle.setAttribute("aria-expanded", "true");
      }
    }
    return;
  }
  if (kind === "scroll") {
    const target = document.querySelector(value);
    if (target) {
      target.scrollIntoView({ behavior: "smooth", block: "start" });
      target.classList.add("nav-sub-flash");
      setTimeout(() => target.classList.remove("nav-sub-flash"), 1200);
    }
    return;
  }
  if (kind === "stats-tab") {
    // Sidebar sub-item Statistik → set tab spesifik
    if (typeof setStatsTab === "function") setStatsTab(value);
    return;
  }
  if (kind === "gv-filter") {
    const tab = document.querySelector(`.gv-tab[data-gv-filter="${value}"]`);
    tab?.click();
    return;
  }
  if (kind === "act-filter") {
    const chip = document.querySelector(`#activityFilters button[data-act-filter="${value}"]`);
    chip?.click();
    return;
  }
  if (kind === "audit-actor") {
    // value: "super-admin" | "admin" | "all"
    __auditActor = value;
    if (typeof renderAdminAudit === "function") renderAdminAudit();
    return;
  }
  if (kind === "chart-tab") {
    const tab = document.querySelector(`#chartTabs button[data-range="${value}"]`);
    tab?.click();
    return;
  }
  if (kind === "msg-filter") {
    const tab = document.querySelector(`.msg-tabs button[data-msg-filter="${value}"]`);
    tab?.click();
    return;
  }
  if (kind === "dm-filter") {
    // Buka messages view + apply filter ke DM list. FIX 2026-05-25: sebelumnya
    // cuma set dmState.filter + render list. Akibatnya:
    //   1) dmOverview (4-card "Semua") tetap visible padahal user klik
    //      Permintaan/DM/Broadcast/Arsip — UI ngga sinkron dgn filter.
    //   2) Top tab pill ngga update active state.
    //   3) Title h2 di-override oleh updateViewTitle pakai teks polos
    //      (bypass renderMsgList yg strip emoji + swap SVG icon).
    // Solusi: panggil _dmApplyView() (toggle overview/layout/broadcast)
    // + sync top tab pill active state + flag supaya updateViewTitle skip.
    if (typeof switchView === "function") switchView("messages");
    if (typeof dmState !== "undefined") {
      dmState.filter = value;
      // Sync top tab pill active state supaya konsisten
      document.querySelectorAll(".dm-section-tab").forEach(function (t) {
        t.classList.toggle("active", t.dataset.dmFilter === value);
      });
      // Apply view (overview/layout/broadcast switch) — ini yg sebelumnya hilang
      if (typeof _dmApplyView === "function") setTimeout(_dmApplyView, 50);
      if (typeof renderDmList === "function") setTimeout(renderDmList, 60);
      if (typeof renderMsgList === "function") setTimeout(renderMsgList, 70);
    }
    // Tandai supaya updateViewTitle skip (kalau dipanggil setelah ini) — title
    // dikelola oleh renderMsgList yg strip emoji + match SVG icon.
    window.__dmFilterFromNav = true;
    setTimeout(function () { window.__dmFilterFromNav = false; }, 200);
    return;
  }
  if (kind === "nav") {
    // Sub-item shortcut nav ke view berbeda dari parent (mis. My Library → upload)
    if (typeof switchView === "function") switchView(value, { fromNav: true });
    return;
  }
}

// Apply focus mode ke section: hanya sub-section dengan data-focus-target sesuai
// yang ditampilkan. value="all" → kembalikan show-all + restore judul asli.
function applyFocus(view, value) {
  if (!view) return;
  const key = (value || "all").trim();
  view.dataset.focus = key;
  // Toggle class untuk styling visual + tampilkan/sembunyikan focus-target
  const targets = view.querySelectorAll("[data-focus-target]");
  targets.forEach(el => {
    if (key === "all") {
      el.removeAttribute("data-focus-hidden");
    } else {
      // Cocokin key — boleh multi value dipisah spasi (mis. "rt always")
      const own = (el.dataset.focusTarget || "").split(/\s+/);
      if (own.includes(key) || own.includes("always")) {
        el.removeAttribute("data-focus-hidden");
      } else {
        el.setAttribute("data-focus-hidden", "1");
      }
    }
  });
  // Kalau ada Ad-grid yang biasanya 3-kolom, paksa jadi 1-kolom saat focus
  view.classList.toggle("focus-mode", key !== "all");
  // Saat reset ke "all" → restore judul asli (sebelum dimodifikasi oleh sub-item)
  if (key === "all") restoreViewTitle(view);
  // v590 (2026-05-27): sync tab pill UI dgn current focus key. Jadi
  // saat sidebar sub-item di-klik (focus:my-video, dst), tab pill di
  // page Pustaka Saya juga ikut update active state.
  const tabBtns = view.querySelectorAll("button[data-focus-tab]");
  if (tabBtns.length) {
    tabBtns.forEach(b => b.classList.toggle("active", b.dataset.focusTab === key));
  }
}

// User minta: jangan auto-expand saat view berubah. Group hanya buka via klik.
// Tapi tetap restore judul-h2 view yang ditinggalkan (kalau pernah di-focus
// rename) supaya saat user balik lagi pakai parent click → judul asli, bukan
// stale title dari focus sebelumnya.
window.addEventListener("playly:view-changed", e => {
  const incoming = e.detail?.view;
  if (!incoming) return;
  // Restore semua view non-aktif yang masih punya originalTitle (sisa dari
  // focus terakhir). View yang baru aktif jangan di-restore sekarang — kalau
  // dia punya focus aktif via sub-item, judul akan di-set oleh handler.
  document.querySelectorAll('section.view h2[data-original-title]').forEach(h => {
    const sec = h.closest('section.view');
    if (!sec || sec.dataset.view === incoming) return;
    h.textContent = h.dataset.originalTitle;
    delete h.dataset.originalTitle;
    // Kalau view yang ditinggalkan tidak ada lagi sub-item active → reset focus juga
    if (sec.classList.contains('focus-mode')) {
      const navGroup = document.querySelector(`.nav-group [data-view="${sec.dataset.view}"]`)?.closest('.nav-group');
      if (navGroup) navGroup.querySelectorAll('.nav-subitem.active').forEach(x => x.classList.remove('active'));
      applyFocus(sec, 'all');
    }
  });
  // Reset audit actor filter saat keluar dari Audit Log
  if (incoming !== "admin-audit" && __auditActor !== "all") {
    __auditActor = "all";
    if (typeof renderAdminAudit === "function") renderAdminAudit();
  }
});

