// ----------------------- SIDEBAR -----------------------
function _setSidebar(open) {
  const sb = $("#sidebar");
  const backdrop = document.getElementById("sidebarBackdrop");
  if (!sb) return;
  sb.classList.toggle("open", open);
  document.body.classList.toggle("sidebar-open", open);
  // Sync backdrop visibility (mobile only — CSS handles display)
  if (backdrop) backdrop.hidden = !open;
}
// Klik backdrop → tutup sidebar
document.addEventListener("click", e => {
  if (e.target?.id === "sidebarBackdrop") _setSidebar(false);
});
// Event delegation — robust untuk mobile dan element yang mungkin baru ada
// setelah script.js eksekusi. Pakai pointerup supaya respon cepat di HP.
document.addEventListener("click", (e) => {
  const t = e.target;
  // Klik tombol hamburger
  if (t.closest("#toggleSidebar")) {
    e.preventDefault();
    const sb = $("#sidebar");
    _setSidebar(!sb?.classList.contains("open"));
    return;
  }
  // Klik di luar sidebar saat sidebar terbuka di mobile → tutup
  if (document.body.classList.contains("sidebar-open") && window.innerWidth <= 768) {
    if (!t.closest("#sidebar")) _setSidebar(false);
  }
});
document.addEventListener("keydown", (e) => {
  if (e.key === "Escape" && document.body.classList.contains("sidebar-open")) _setSidebar(false);
});
// Tutup sidebar otomatis saat memilih menu di mobile (event delegation)
document.addEventListener("click", (e) => {
  if (window.innerWidth > 768) return;
  if (!document.body.classList.contains("sidebar-open")) return;
  const link = e.target.closest("#sidebar .nav-item, #sidebar [data-route]");
  if (link) _setSidebar(false);
});
// Reset class sidebar-open jika di-resize ke desktop
window.addEventListener("resize", () => {
  if (window.innerWidth > 768 && document.body.classList.contains("sidebar-open")) _setSidebar(false);
});

// ----------------------- COUNT-UP (when value > 0) -----------------------
function countUp(el, target, fmt) {
  if (target == null) target = +el.dataset.count;
  if (target === 0) { el.textContent = fmt ? fmt(0) : "0"; return; }
  const dur = 900, t0 = performance.now();
  function step(t) {
    const p = Math.min(1, (t - t0) / dur);
    const v = Math.floor(target * (1 - Math.pow(1 - p, 3)));
    el.textContent = p < 1 ? v.toLocaleString("id-ID") : (fmt ? fmt(target) : v.toLocaleString("id-ID"));
    if (p < 1) requestAnimationFrame(step);
  }
  requestAnimationFrame(step);
}

function fmtNum(n) {
  if (n >= 1_000_000) return (n/1_000_000).toFixed(1).replace(/\.0$/, "") + "M";
  if (n >= 1_000) return (n/1_000).toFixed(1).replace(/\.0$/, "") + "k";
  return n.toLocaleString("id-ID");
}

function renderStatsRow() {
  const row = $("#statsRow");
  if (!row) return;
  const myUploads = state.myVideos.length;
  const myViews = state.myVideos.reduce((s, v) => s + (v.viewsNum || 0), 0);
  const myLikes = state.myVideos.reduce((s, v) => s + (v.likes || 0), 0);
  // v595 (2026-05-28): Following → Followers (channel kamu yang di-follow),
  // tambah Total Komentar + Engagement Rate. Following = metric viewer, bukan
  // creator — diganti Followers per cleanup user.
  const myComments = state.myVideos.reduce((s, v) =>
    s + ((state.comments?.[v.id]?.length) || 0), 0);
  let myFollowers = 0;
  try {
    myFollowers = (typeof getUserFollowers === "function" && user?.username)
      ? getUserFollowers(user.username).length
      : (Array.isArray(state?.followers) ? state.followers.length : 0);
  } catch {}
  const engagementPct = myViews > 0 ? ((myLikes + myComments) / myViews * 100) : 0;
  const engagementText = engagementPct > 0 ? engagementPct.toFixed(1) + "%" : "—";

  const cards = [
    { label: "Total Videos", value: myUploads, raw: myUploads, icon: `<rect x="3" y="5" width="18" height="14" rx="2" stroke="currentColor" stroke-width="2.2"/><path d="m10 9 5 3-5 3z" fill="currentColor"/>`, c1: "#7d3640", c2: "#561C24", trend: myUploads > 0 ? "up" : null, trendText: myUploads > 0 ? "videos published" : "—", spark: "#BE9752" },
    { label: "Total Views", value: fmtNum(myViews), raw: myViews, icon: `<path d="M2 12s4-7 10-7 10 7 10 7-4 7-10 7-10-7-10-7Z" stroke="currentColor" stroke-width="2.2"/><circle cx="12" cy="12" r="3" stroke="currentColor" stroke-width="2.2"/>`, c1: "#7d3640", c2: "#561C24", trend: myViews > 0 ? "up" : null, trendText: myViews > 0 ? "views earned" : "—", spark: "#BE9752" },
    { label: "Total Likes", value: fmtNum(myLikes), raw: myLikes, icon: `<path d="M20.8 4.6a5.5 5.5 0 0 0-7.8 0L12 5.6l-1-1a5.5 5.5 0 1 0-7.8 7.8l1 1L12 21l7.8-7.8 1-1a5.5 5.5 0 0 0 0-7.6Z" stroke="currentColor" stroke-width="2.2" stroke-linejoin="round"/>`, c1: "#7d3640", c2: "#561C24", trend: myLikes > 0 ? "up" : null, trendText: myLikes > 0 ? "disukai user" : "—", spark: "#BE9752" },
    { label: "Total Komentar", value: fmtNum(myComments), raw: myComments, icon: `<path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z" stroke="currentColor" stroke-width="2.2" stroke-linejoin="round"/>`, c1: "#7d3640", c2: "#561C24", trend: myComments > 0 ? "up" : null, trendText: myComments > 0 ? "komentar diterima" : "—", spark: "#BE9752" },
    { label: "Followers", value: fmtNum(myFollowers), raw: myFollowers, icon: `<path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2" stroke="currentColor" stroke-width="2.2" stroke-linecap="round"/><circle cx="9" cy="7" r="4" stroke="currentColor" stroke-width="2.2"/><path d="M23 21v-2a4 4 0 0 0-3-3.87M16 3.13a4 4 0 0 1 0 7.75" stroke="currentColor" stroke-width="2.2" stroke-linecap="round"/>`, c1: "#7d3640", c2: "#561C24", trend: myFollowers > 0 ? "up" : null, trendText: myFollowers > 0 ? "subscribers channel" : "—", spark: "#BE9752" },
    { label: "Engagement", value: engagementText, raw: engagementPct, icon: `<path d="M12 20.5l-1.45-1.32C5.4 14.36 2 11.28 2 7.5 2 4.42 4.42 2 7.5 2 9.24 2 10.91 2.81 12 4.09 13.09 2.81 14.76 2 16.5 2 19.58 2 22 4.42 22 7.5c0 3.78-3.4 6.86-8.55 11.69L12 20.5z" stroke="currentColor" stroke-width="2.2" stroke-linejoin="round"/><circle cx="12" cy="11" r="1.5" fill="currentColor"/>`, c1: "#7d3640", c2: "#561C24", trend: engagementPct > 0 ? "up" : null, trendText: engagementPct > 0 ? "(likes + komentar) / views" : "—", spark: "#BE9752" }
  ];

  row.innerHTML = cards.map(c => `
    <div class="stat-card">
      <div class="stat-icon" style="--c1:${c.c1};--c2:${c.c2}"><svg viewBox="0 0 24 24" fill="none">${c.icon}</svg></div>
      <p class="stat-label">${c.label}</p>
      <h3 class="stat-value">${c.value}</h3>
      ${c.trend ? `<div class="stat-trend ${c.trend}"><svg viewBox="0 0 24 24" fill="none"><path d="m6 14 6-6 6 6" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>${c.trendText}</div>` : `<div class="stat-trend neutral">${c.trendText}</div>`}
      ${c.raw > 0 ? `<div class="spark"><svg viewBox="0 0 100 30" preserveAspectRatio="none"><polyline fill="none" stroke="${c.spark}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" points="0,22 14,18 28,20 42,12 56,16 70,8 84,10 100,6"/></svg></div>` : ""}
    </div>
  `).join("");
}

function renderAchievements() {
  const grid = $("#badgeGrid");
  if (!grid) return;

  const myUploads = state.myVideos.length;
  const myViews = state.myVideos.reduce((s, v) => s + (v.viewsNum || 0), 0);
  const myLikes = state.myVideos.reduce((s, v) => s + (v.likes || 0), 0);
  const following = state.followingCreators.length;
  const commentCount = Object.values(state.comments || {}).reduce((s, arr) => s + (arr?.length || 0), 0);
  const watchedCount = state.history.length;

  const list = [
    { emoji: "🎬", name: "1st Upload",    earned: myUploads >= 1 },
    { emoji: "📺", name: "Penonton",      earned: watchedCount >= 1 },
    { emoji: "♥",  name: "10 Likes",      earned: myLikes >= 10 || state.liked.length >= 10 },
    { emoji: "👥", name: "Sosial",        earned: following >= 1 },
    { emoji: "💬", name: "Komentar",      earned: commentCount >= 1 },
    { emoji: "👁", name: "100 Views",     earned: myViews >= 100 },
    { emoji: "🚀", name: "Trending",      earned: myViews >= 1000 }
  ];

  grid.innerHTML = list.map(b => `
    <div class="badge-chip ${b.earned ? 'earned' : ''}" title="${b.name}">
      ${b.emoji}<small>${b.name}</small>
    </div>
  `).join("");

  const earned = list.filter(b => b.earned).length;
  $("#achEarned") && ($("#achEarned").textContent = earned);
  $("#achTotal") && ($("#achTotal").textContent = list.length);
  $("#achBar") && ($("#achBar").style.setProperty("--w", `${(earned / list.length) * 100}%`));
  $("#achSubtitle") && ($("#achSubtitle").textContent = earned === 0
    ? t("achievement.empty")
    : `${earned} ${t("achievement.of")} ${list.length} ${t("achievement.unlocked")}`);
}

// Patch satu angka di widget home stats. Kasih animasi "bump" cuma kalau
// nilainya BERBEDA dari sebelumnya — supaya user lihat data lagi update.
// Parse "1.234" (id-ID locale, dot as thousand separator) atau "1234" → 1234.
// Return null kalau ada non-digit selain pemisah ribuan (mis. "1.5k", "—").
function _parseLocaleInt(s) {
  if (typeof s !== "string") return null;
  const stripped = s.replace(/\./g, "").replace(/,/g, "").trim();
  if (!/^\d+$/.test(stripped)) return null;
  return parseInt(stripped, 10);
}

// Easing function — ease-out cubic (cepet di awal, melambat di akhir)
function _easeOutCubic(t) { return 1 - Math.pow(1 - t, 3); }

function patchHomeStat(selector, newText) {
  const el = document.querySelector(selector);
  if (!el) return;
  if (el.textContent === newText) return;

  // Cancel animation frame yang lagi running di element ini supaya tidak race
  if (el._countAnim) {
    cancelAnimationFrame(el._countAnim);
    el._countAnim = null;
  }

  const reduceMotion = window.matchMedia?.("(prefers-reduced-motion: reduce)").matches;
  const fromN = _parseLocaleInt(el.textContent);
  const toN   = _parseLocaleInt(newText);

  // Kalau dua-duanya pure integer & user tidak minta reduce-motion → count-up animate.
  // Kalau ada compact format (1.5k / 2.3M), skip animasi — langsung set + bump.
  if (fromN !== null && toN !== null && fromN !== toN && !reduceMotion) {
    const start = performance.now();
    const dur = Math.min(900, 400 + Math.log10(Math.abs(toN - fromN) + 1) * 200);
    const tick = (now) => {
      const t = Math.min(1, (now - start) / dur);
      const v = Math.round(fromN + (toN - fromN) * _easeOutCubic(t));
      el.textContent = v.toLocaleString("id-ID");
      if (t < 1) {
        el._countAnim = requestAnimationFrame(tick);
      } else {
        el._countAnim = null;
        el.textContent = newText;
      }
    };
    el._countAnim = requestAnimationFrame(tick);
  } else {
    el.textContent = newText;
  }

  // Bump animation (existing) — kasih feedback visual saat angka berubah
  el.classList.remove("hs-bump");
  void el.offsetWidth;
  el.classList.add("hs-bump");
}

// Ticker — update teks "baru saja / X menit lalu" tiap 30 detik.
// Stop kalau widget belum mount (selama login screen).
setInterval(() => {
  const updEl = document.getElementById("hsLastUpdate");
  if (!updEl) return;
  const ts = parseInt(updEl.dataset.ts || "0", 10);
  if (!ts) return;
  const diff = Math.floor((Date.now() - ts) / 1000);
  if (diff < 10) updEl.textContent = "just now";
  else if (diff < 60) updEl.textContent = `${diff} detik lalu`;
  else if (diff < 3600) updEl.textContent = `${Math.floor(diff / 60)} min ago`;
  else updEl.textContent = `${Math.floor(diff / 3600)} hr ago`;
}, 30000);

function renderUserStats() {
  // v550 (2026-05-26): defensive null guards. Fungsi ini dipanggil dari
  // cloud-sync applyToLocal SETELAH state hydrated, tapi ada race condition
  // saat anonymous/auto-boot sebelum loadState() jalan → state masih null
  // atau missing arrays → TypeError "Cannot read properties of null
  // (reading 'myVideos')" di console (tracked dari live test v547).
  if (!state) return;
  const myVideos = Array.isArray(state.myVideos) ? state.myVideos : [];
  const followingCreators = Array.isArray(state.followingCreators) ? state.followingCreators : [];
  const messages = Array.isArray(state.messages) ? state.messages : [];

  const myViews = myVideos.reduce((s, v) => s + (v.viewsNum || 0), 0);
  const myUploads = myVideos.length;
  const myLikes = myVideos.reduce((s, v) => s + (v.likes || 0), 0);
  const following = followingCreators.length;

  // Real-time home stats widget — kasih animasi bump kalau angka berubah
  patchHomeStat("#hsVideos", String(myUploads));
  patchHomeStat("#hsViews", fmtNum(myViews));
  patchHomeStat("#hsFollowing", String(following));
  patchHomeStat("#hsLikes", fmtNum(myLikes));
  // Hero card "CREATOR HUB" tiles — sinkronkan dengan home stats
  patchHomeStat("#heroHcVideos", String(myUploads));
  patchHomeStat("#heroHcViews", fmtNum(myViews));
  patchHomeStat("#heroHcLikes", fmtNum(myLikes));
  // Update "last update" indicator → kasih tau widget barusan refresh
  const updEl = document.getElementById("hsLastUpdate");
  if (updEl) {
    updEl.textContent = "just now";
    updEl.dataset.ts = String(Date.now());
  }

  renderStatsRow();
  renderAchievements();
  renderUserCommunityStack();
  renderHomeWeather();

  // Quick stats (Videos view)
  $("#qsTotal") && ($("#qsTotal").textContent = myUploads);
  $("#qsViews") && ($("#qsViews").textContent = fmtNum(myViews));
  // Sidebar Videos badge: angka kalau ada upload baru 24 jam, dot kalau punya
  // video tapi tidak ada yang baru, hidden kalau belum punya video apapun.
  const oneDayMs = 86400000;
  const newUploads24h = myVideos.filter(v => {
    const t = Number(v.ts || v.uploadedAt || 0);
    return t > 0 && (Date.now() - t) <= oneDayMs;
  }).length;
  setBadgeMode($("#videoCount"), newUploads24h, myUploads > 0);

  // Messages badge: angka kalau ada unread, dot kalau ada thread, hidden kalau kosong
  const unread = messages.filter(m => m.unread).length;
  setBadgeMode($("#msgBadge"), unread, messages.length > 0);
}

// ----------------------- LIVE CLOCK & GREETING -----------------------
const ID_DAYS = ["Minggu", "Senin", "Selasa", "Rabu", "Kamis", "Jumat", "Sabtu"];
const ID_DAYS_SHORT = ["Min", "Sen", "Sel", "Rab", "Kam", "Jum", "Sab"];
const ID_MONTHS = ["Januari", "Februari", "Maret", "April", "Mei", "Juni", "Juli", "Agustus", "September", "Oktober", "November", "Desember"];
const ID_MONTHS_SHORT = ["Jan", "Feb", "Mar", "Apr", "Mei", "Jun", "Jul", "Agt", "Sep", "Okt", "Nov", "Des"];

function pad2(n) { return String(n).padStart(2, "0"); }

function timeOfDayGreeting(h) {
  // Ikon waktu minimalis monokrom (per request user 2026-05-16, bukan emoji
  // warna). SVG string single-quote, NO backtick — di-inject via innerHTML.
  var _S = 'viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"';
  var _MOON = '<svg ' + _S + '><path d="M21 12.8A9 9 0 1 1 11.2 3a7 7 0 0 0 9.8 9.8Z"/></svg>';
  var _SUN  = '<svg ' + _S + '><circle cx="12" cy="12" r="4"/><path d="M12 2v2M12 20v2M4.9 4.9l1.4 1.4M17.7 17.7l1.4 1.4M2 12h2M20 12h2M4.9 19.1l1.4-1.4M17.7 6.3l1.4-1.4"/></svg>';
  var _COFFEE = '<svg ' + _S + '><path d="M17 8h1a4 4 0 0 1 0 8h-1"/><path d="M3 8h14v9a4 4 0 0 1-4 4H7a4 4 0 0 1-4-4Z"/><path d="M6 2v3M10 2v3M14 2v3"/></svg>';
  var _SUNRISE = '<svg ' + _S + '><path d="M12 2v6M4.2 10.2l1.4 1.4M1 18h2M21 18h2M18.4 11.6l1.4-1.4M23 22H1"/><path d="M8 18a4 4 0 0 1 8 0"/><path d="M8 6l4-4 4 4"/></svg>';
  if (h < 5) return { greet: t("greet.latenight"), emoji: _MOON };
  if (h < 11) return { greet: t("greet.morning"), emoji: _SUN };
  if (h < 15) return { greet: t("greet.afternoon"), emoji: _COFFEE };
  if (h < 18) return { greet: t("greet.evening"), emoji: _SUNRISE };
  return { greet: t("greet.night"), emoji: _MOON };
}

// (HERO SIDE SLOT / renderHeroSideSlot DIHAPUS per request user 2026-05-16
//  setelah banyak iterasi — hero dibiarkan bersih. Helper _myVideos/_vTs/
//  _myFollowers/_xpForLevel tetap (dipakai widget lain / harmless.)

function buildHeroSubtitle() {
  if (!user || !state) return "";
  const h = new Date().getHours();
  // Ikon matahari/bulan (emoji) di akhir subtitle DIHAPUS per request
  // user 2026-05-16 — `emoji` sengaja tidak dipakai lagi.
  const { greet } = timeOfDayGreeting(h);
  const myUploads = state.myVideos.length;
  const following = state.followingCreators.length;

  if (myUploads === 0 && following === 0) {
    return `${greet}! ${t("hero.sub.empty.start")} <b data-jump="upload" style="cursor:pointer; color:var(--primary)">${t("hero.sub.empty.upload")}</b> ${t("hero.sub.empty.or")} <b data-jump="discover" style="cursor:pointer; color:var(--primary)">${t("hero.sub.empty.discover")}</b>`;
  }
  if (following > 0 && myUploads === 0) {
    return `${greet}! ${t("hero.sub.following.pre")} <b>${following}</b> ${t("hero.sub.following.post")}`;
  }
  if (myUploads > 0 && following === 0) {
    return `${greet}! ${t("hero.sub.uploaded.pre")} <b>${myUploads}</b> ${t("hero.sub.uploaded.post")}`;
  }
  return `${greet}! <b>${myUploads}</b> ${t("hero.sub.video")} • <b>${following}</b> ${t("hero.sub.followed")}`;
}

let liveClockTimer = null;

function tickLiveClock() {
  const now = new Date();
  const day = now.getDay();
  const date = now.getDate();
  const month = now.getMonth();
  const year = now.getFullYear();
  const hh = pad2(now.getHours()), mm = pad2(now.getMinutes()), ss = pad2(now.getSeconds());

  // Hero pills (user + admin)
  const heroDate = $("#heroDate");
  if (heroDate) heroDate.textContent = `${ID_DAYS_SHORT[day]}, ${date} ${ID_MONTHS_SHORT[month]} ${year}`;
  const adminHeroDate = $("#adminHeroDate");
  if (adminHeroDate) adminHeroDate.textContent = `${ID_DAYS_SHORT[day]}, ${date} ${ID_MONTHS_SHORT[month]} ${year}`;
  const liveTime = $("#liveTime");
  if (liveTime) liveTime.textContent = `${hh}:${mm}:${ss}`;
  const adminLiveTime = $("#adminLiveTime");
  if (adminLiveTime) adminLiveTime.textContent = `${hh}:${mm}:${ss}`;

  // Hero clock card (user)
  const hcDay = $("#hcDay");
  if (hcDay) hcDay.textContent = ID_DAYS[day].toUpperCase();
  const hcDate = $("#hcDate");
  if (hcDate) hcDate.textContent = pad2(date);
  const hcMonth = $("#hcMonth");
  if (hcMonth) hcMonth.textContent = `${ID_MONTHS[month]} ${year}`;
  const hcTimeBig = $("#hcTimeBig");
  if (hcTimeBig) hcTimeBig.textContent = `${hh}:${mm}`;

  // Hero clock card (admin)
  const adminHcDay = $("#adminHcDay");
  if (adminHcDay) adminHcDay.textContent = ID_DAYS[day].toUpperCase();
  const adminHcDate = $("#adminHcDate");
  if (adminHcDate) adminHcDate.textContent = pad2(date);
  const adminHcMonth = $("#adminHcMonth");
  if (adminHcMonth) adminHcMonth.textContent = `${ID_MONTHS[month]} ${year}`;
  const adminHcTimeBig = $("#adminHcTimeBig");
  if (adminHcTimeBig) adminHcTimeBig.textContent = `${hh}:${mm}`;

  // Greeting (only refresh once per minute since seconds change)
  if (now.getSeconds() === 0 || !$("#heroSubtitle")?.dataset.init) {
    refreshHeroGreeting();
  }
}

