// v617 (2026-05-28): Standalone CSV export — dipakai dari Settings (semua user,
// termasuk Gratis). Read state.myVideos directly, no premium gate.
function _exportVideosToCSV() {
  const myVideos = Array.isArray(state?.myVideos) ? state.myVideos : [];
  if (!myVideos.length) {
    toast?.("Belum ada data video untuk di-export.", "info");
    return;
  }
  const headers = ["id", "title", "uploaded_at", "views", "likes", "comments", "shares", "tags", "category"];
  const rows = myVideos.map(v => [
    v.id || "",
    `"${String(v.title || "").replace(/"/g, '""')}"`,
    v.createdAt ? new Date(v.createdAt).toISOString() : "",
    v.viewsNum || 0,
    v.likes || 0,
    Array.isArray(v.comments) ? v.comments.length : (v.comments || 0),
    v.shares || 0,
    `"${(Array.isArray(v.tags) ? v.tags.join(",") : "")}"`,
    v.category || "",
  ].join(","));
  const csv = [headers.join(","), ...rows].join("\n");
  // UTF-8 BOM (﻿) → Excel auto-detect encoding sebagai UTF-8.
  const blob = new Blob(["﻿" + csv], { type: "text/csv;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `playly-data-video-${new Date().toISOString().slice(0, 10)}.csv`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1500);
  toast?.(`✓ Data ${myVideos.length} video berhasil diunduh.`, "success");
}

// ----------------------- HOME — UPLOAD STREAK (7-day activity bar) -----------------------
function renderHomeStreak() {
  const wrap = document.getElementById("homeStreakCard");
  if (!wrap) return;
  const myVideos = Array.isArray(state?.myVideos) ? state.myVideos : [];

  // Build a map of upload count per day for the last 7 days (index 0 = 6 days ago, 6 = today)
  const now = new Date();
  const days = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(now);
    d.setDate(d.getDate() - (6 - i));
    d.setHours(0, 0, 0, 0);
    return d.getTime();
  });
  const dayCounts = days.map(dayTs => {
    const nextDay = dayTs + 86400000;
    return myVideos.filter(v => {
      const ts = v.createdAt || 0;
      return ts >= dayTs && ts < nextDay;
    }).length;
  });

  // Calculate consecutive streak ending today
  let streak = 0;
  for (let i = 6; i >= 0; i--) {
    if (dayCounts[i] > 0) streak++;
    else break;
  }

  const maxCount = Math.max(...dayCounts, 1);
  const shortDays = ["Min", "Sen", "Sel", "Rab", "Kam", "Jum", "Sab"];
  const todayIdx = now.getDay(); // 0=Sun

  const barsHtml = days.map((dayTs, i) => {
    const cnt = dayCounts[i];
    const heightPct = Math.max(8, Math.round((cnt / maxCount) * 100));
    const d = new Date(dayTs);
    const isToday = i === 6;
    const activeClass = cnt > 0 ? (isToday ? "hsc-bar-today" : "hsc-bar-active") : "";
    const dayLabel = shortDays[d.getDay()];
    return `
      <div class="hsc-bar-wrap">
        <div class="hsc-bar ${activeClass}" style="height:${heightPct}%" title="${cnt} video"></div>
        <span class="hsc-bar-day ${isToday ? "hsc-today-label" : ""}">${isToday ? "Hari ini" : dayLabel}</span>
      </div>`;
  }).join("");

  const streakZeroClass = streak === 0 ? "hsc-streak-zero" : "";
  const streakMsg = streak === 0
    ? "Belum ada upload hari ini"
    : streak === 1 ? "Bagus! Pertahankan terus"
    : streak < 4 ? `${streak} hari berturut-turut!`
    : `🔥 ${streak} hari streak — luar biasa!`;
  const ctaLabel = streak > 0 ? "Unggah lagi hari ini →" : "Mulai streak hari ini →";

  wrap.innerHTML = `
    <div class="hsc-inner ${streakZeroClass}">
      <div class="hsc-left">
        <span class="hsc-flame">🔥</span>
        <div>
          <div class="hsc-streak-num">${streak}</div>
          <div class="hsc-streak-label">Hari Streak</div>
          <div class="hsc-streak-sub">${streakMsg}</div>
        </div>
      </div>
      <div class="hsc-bars">
        <div class="hsc-bars-label">Upload 7 hari terakhir</div>
        <div class="hsc-bars-row">${barsHtml}</div>
      </div>
      <div class="hsc-right">
        <button type="button" class="hsc-cta" data-hsc-upload>${ctaLabel}</button>
      </div>
    </div>`;

  wrap.querySelector("[data-hsc-upload]")?.addEventListener("click", () => {
    document.querySelector("[data-jump='upload']")?.click();
  });
}

// ----------------------- HOME — WEATHER WIDGET -----------------------
// Uses ipapi.co (IP geolocation, free) + Open-Meteo (weather, free, no key).
// Cache result 30 min so we don't spam APIs on every view switch.
const _weatherCache = { data: null, ts: 0 };
const WEATHER_TTL = 30 * 60 * 1000; // 30 min

function _wmoInfo(code) {
  if (code === 0)            return { label: "Cerah", icon: "☀️" };
  if (code <= 1)             return { label: "Cerah Berawan", icon: "🌤️" };
  if (code <= 2)             return { label: "Berawan Sebagian", icon: "⛅" };
  if (code <= 3)             return { label: "Mendung", icon: "☁️" };
  if (code <= 48)            return { label: "Berkabut", icon: "🌫️" };
  if (code <= 57)            return { label: "Gerimis", icon: "🌦️" };
  if (code <= 67)            return { label: "Hujan", icon: "🌧️" };
  if (code <= 77)            return { label: "Bersalju", icon: "❄️" };
  if (code <= 82)            return { label: "Hujan Lebat", icon: "🌧️" };
  if (code <= 86)            return { label: "Hujan Salju", icon: "🌨️" };
  return                            { label: "Badai Petir", icon: "⛈️" };
}

const _ID_DAYS_SHORT = ["Min","Sen","Sel","Rab","Kam","Jum","Sab"];

async function renderHomeWeather() {
  const card = document.getElementById("homeWeatherCard");
  if (!card) return;

  // Use cache if fresh
  if (_weatherCache.data && (Date.now() - _weatherCache.ts) < WEATHER_TTL) {
    _renderWeatherHTML(card, _weatherCache.data);
    return;
  }

  // Show skeleton while fetching
  card.innerHTML = `<div class="hwc-skeleton"><div class="hwc-skel-top"></div><div class="hwc-skel-mid"></div><div class="hwc-skel-row"></div></div>`;

  try {
    // 1. IP-based geolocation (no key required)
    const geoRes = await fetch("https://ipapi.co/json/", { signal: AbortSignal.timeout(6000) });
    const geo = await geoRes.json();
    const { latitude, longitude, city, country_name } = geo;
    if (!latitude || !longitude) throw new Error("no coords");

    // 2. Open-Meteo weather (no key required)
    const wUrl = `https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}&current=temperature_2m,weather_code&daily=temperature_2m_max,temperature_2m_min,weather_code&timezone=auto&forecast_days=4`;
    const wRes = await fetch(wUrl, { signal: AbortSignal.timeout(8000) });
    const w = await wRes.json();

    const payload = {
      city: city || "—",
      country: country_name || "",
      tempNow: Math.round(w.current.temperature_2m),
      codeNow: w.current.weather_code,
      forecast: w.daily.time.slice(1, 4).map((date, i) => ({
        day: _ID_DAYS_SHORT[new Date(date).getDay()],
        max: Math.round(w.daily.temperature_2m_max[i + 1]),
        min: Math.round(w.daily.temperature_2m_min[i + 1]),
        code: w.daily.weather_code[i + 1]
      }))
    };

    _weatherCache.data = payload;
    _weatherCache.ts = Date.now();
    _renderWeatherHTML(card, payload);
  } catch {
    card.innerHTML = `
      <div class="hwc-error">
        <div class="hwc-error-icon">🌐</div>
        <span>Cuaca tidak tersedia</span>
      </div>`;
  }
}

function _renderWeatherHTML(card, d) {
  const { label, icon } = _wmoInfo(d.codeNow);
  const forecastHtml = d.forecast.map(f => {
    const fi = _wmoInfo(f.code);
    return `
      <div class="hwc-day">
        <span class="hwc-day-name">${f.day}</span>
        <span class="hwc-day-icon">${fi.icon}</span>
        <span class="hwc-day-temp">${f.max}°</span>
        <span class="hwc-day-range">${f.min}°</span>
      </div>`;
  }).join("");

  card.innerHTML = `
    <div class="hwc-body">
      <div class="hwc-location">
        <svg viewBox="0 0 24 24" fill="currentColor"><path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7zm0 9.5c-1.38 0-2.5-1.12-2.5-2.5s1.12-2.5 2.5-2.5 2.5 1.12 2.5 2.5-1.12 2.5-2.5 2.5z"/></svg>
        ${d.city}${d.country ? `, ${d.country}` : ""}
      </div>
      <div class="hwc-top">
        <div class="hwc-main">
          <div class="hwc-temp">${d.tempNow}°C</div>
          <div class="hwc-condition">${label}</div>
        </div>
        <div class="hwc-icon-wrap">${icon}</div>
      </div>
      <div class="hwc-forecast">${forecastHtml}</div>
    </div>`;
}

// ----------------------- HOME — TIER WIDGET (Free quota / Premium insights) -----------------------
// Render widget berbeda di home page berdasarkan user tier:
//   - FREE: monthly upload quota meter (60 video / 1 GB)
//   - PREMIUM: premium insights (engagement, avg watch time, top region)
function renderHomeTierWidget() {
  const wrap = document.getElementById("homeTierWidget");
  if (!wrap) return;
  const tier = user?.tier || "free";

  if (tier === "free") {
    const myVideos = Array.isArray(state?.myVideos) ? state.myVideos : [];
    const monthStart = new Date();
    monthStart.setDate(1); monthStart.setHours(0,0,0,0);
    const mStartTs = monthStart.getTime();
    const thisMonth = myVideos.filter(v => (v.createdAt || v.id || 0) >= mStartTs);
    const usedCount = thisMonth.length;
    const usedBytes = thisMonth.reduce((s, v) => s + (v.fileSize || 0), 0);
    const MAX_COUNT = 60;
    const MAX_BYTES = 1024 * 1024 * 1024; // 1 GB
    const pctCount = Math.min(100, Math.round((usedCount / MAX_COUNT) * 100));
    const pctBytes = Math.min(100, Math.round((usedBytes / MAX_BYTES) * 100));
    const usedMB = (usedBytes / (1024 * 1024)).toFixed(usedBytes < 1024*1024*100 ? 1 : 0);

    wrap.innerHTML = `
      <div class="tier-widget tier-widget-free">
        <div class="tw-head">
          <span class="tw-badge">🌱 FREE PLAN</span>
          <span class="tw-title">Monthly upload quota</span>
          <button type="button" class="tw-upgrade" data-tw-upgrade>⭐ Upgrade to Premium</button>
        </div>
        <div class="tw-meters">
          <div class="tw-meter">
            <div class="tw-meter-row"><span>Videos uploaded</span><b>${usedCount} / ${MAX_COUNT}</b></div>
            <div class="tw-bar"><i style="width:${pctCount}%"></i></div>
          </div>
          <div class="tw-meter">
            <div class="tw-meter-row"><span>Storage used</span><b>${usedMB} MB / 1 GB</b></div>
            <div class="tw-bar"><i style="width:${pctBytes}%"></i></div>
          </div>
        </div>
        <p class="tw-hint">Quota resets on the 1st of each month. Upgrade to Premium for unlimited uploads.</p>
      </div>
    `;
    wrap.querySelector("[data-tw-upgrade]")?.addEventListener("click", () => {
      document.getElementById("pdUpgradeBtn")?.click();
    });
    return;
  }

  // PREMIUM — semua data real dari state
  const myVideos = Array.isArray(state?.myVideos) ? state.myVideos : [];
  const totalViews = myVideos.reduce((s, v) => s + (v.viewsNum || 0), 0);
  const totalLikes = myVideos.reduce((s, v) => s + (v.likes || 0), 0);
  const engagement = totalViews > 0 ? ((totalLikes / totalViews) * 100).toFixed(1) : "0.0";

  // Avg watch time dari history (progress × durasi video)
  const history = Array.isArray(state?.history) ? state.history : [];
  let avgWatchStr = "—";
  if (history.length > 0) {
    const watchedSecs = [];
    history.forEach(h => {
      const v = myVideos.find(vid => vid.id === h.id);
      if (!v || !h.progress) return;
      const parts = (v.duration || "").split(":");
      if (parts.length < 2) return;
      const totalSecs = parseInt(parts[0]) * 60 + parseInt(parts[1]);
      if (isFinite(totalSecs) && totalSecs > 0) watchedSecs.push(totalSecs * h.progress);
    });
    if (watchedSecs.length) {
      const avg = Math.round(watchedSecs.reduce((a, b) => a + b) / watchedSecs.length);
      avgWatchStr = `${Math.floor(avg / 60)}m ${avg % 60}s`;
    }
  }

  // Video terpopuler (views terbanyak)
  const topVideo = myVideos.length
    ? myVideos.reduce((best, v) => (v.viewsNum || 0) > (best.viewsNum || 0) ? v : best, myVideos[0])
    : null;
  const topVideoLabel = topVideo ? `"${(topVideo.title || "Video").slice(0, 22)}${topVideo.title?.length > 22 ? "…" : ""}"` : "—";
  const topVideoViews = topVideo ? `${topVideo.viewsNum || 0} views` : "Belum ada video";

  // Member since — dari joinedAt akun
  const acc = (() => { try { return JSON.parse(localStorage.getItem(`playly-account-${user?.email}`) || "{}"); } catch { return {}; } })();
  const joinedAt = acc.joinedAt || user?.joinedAt;
  let memberSinceStr = "—";
  if (joinedAt) {
    const days = Math.floor((Date.now() - new Date(joinedAt).getTime()) / 864e5);
    memberSinceStr = days === 0 ? "Hari ini" : days === 1 ? "1 hari lalu" : `${days} hari lalu`;
  }

  // Trend: bandingkan total views vs setengah dari total (tidak ada data harian → tampilkan views total saja)
  const trendLabel = totalViews > 0 ? `${totalViews} total views` : "Belum ada tontonan";

  wrap.innerHTML = `
    <div class="tier-widget tier-widget-premium">
      <div class="tw-head">
        <span class="tw-badge tw-badge-premium">⭐ PREMIUM INSIGHTS</span>
        <span class="tw-title">Advanced analytics — exclusive to Premium</span>
        <span class="tw-trend">${trendLabel}</span>
      </div>
      <div class="tw-insights">
        <div class="tw-insight">
          <span class="tw-insight-label">Engagement rate</span>
          <strong>${engagement}%</strong>
          <small>${totalViews} views · ${totalLikes} likes</small>
        </div>
        <div class="tw-insight">
          <span class="tw-insight-label">Rata-rata waktu tonton</span>
          <strong>${avgWatchStr}</strong>
          <small>${history.length ? `dari ${history.length} riwayat` : "Belum ada riwayat"}</small>
        </div>
        <div class="tw-insight">
          <span class="tw-insight-label">Video terpopuler</span>
          <strong>${topVideoLabel}</strong>
          <small>${topVideoViews}</small>
        </div>
        <div class="tw-insight">
          <span class="tw-insight-label">Premium status</span>
          <strong>⭐ Verified</strong>
          <small>Member sejak ${memberSinceStr}</small>
        </div>
      </div>
      <div class="tw-perks">
        <span class="tw-perk">🚫 Ad-free everywhere</span>
        <span class="tw-perk">∞ Unlimited uploads</span>
        <span class="tw-perk">🎥 4K quality</span>
        <span class="tw-perk">🔴 Live streaming</span>
        <span class="tw-perk">⚡ Priority support</span>
      </div>
    </div>
  `;
}

// ----------------------- HOME — NOTIFICATIONS LATEST -----------------------
// Replaces CONTINUE · WATCHING (per request 2026-05-03 revisi — "fitur
// continue watching kurang suka, ganti lagi"). Snapshot of latest 4-5
// notifications: likes/comments/follows pada konten user. Actionable
// (clickable → buka panel notif full) + personal — cocok untuk dashboard.
function renderHomeNotifLatest() {
  const wrap = document.getElementById("homeNotifList");
  if (!wrap) return;
  const notifs = Array.isArray(state?.notifications) ? [...state.notifications] : [];
  // Sort newest first by id (timestamp-ish)
  notifs.sort((a, b) => (b.id || 0) - (a.id || 0));
  const top = notifs.slice(0, 5);

  if (!top.length) {
    // H audit (2026-05-25): paralel dengan empty state panel notif.
    // Copy lebih actionable + ada CTA ke discover.
    wrap.innerHTML = `
      <div class="hra-empty">
        <div class="hra-empty-icon">${NI_BELL}</div>
        <p>${escapeHtml(t("notif.empty.home"))}</p>
        <button type="button" class="btn primary sm hra-empty-cta" data-jump-view="discover">${escapeHtml(t("notif.empty.home.cta"))}</button>
      </div>`;
    wrap.querySelector("[data-jump-view]")?.addEventListener("click", () => {
      const link = document.querySelector('.nav-item[data-view="discover"]');
      if (link) link.click();
    });
    return;
  }

  // Map type → icon. Ikon minimalis monokrom (per request user 2026-05-16,
  // bukan emoji warna) — reuse konstanta NI_* global (SVG string single-quote,
  // NO backtick). Konsisten dgn NOTIF_CATEGORY_MAP di notification panel.
  const iconMap = {
    "like": NI_HEART, "video-like": NI_HEART,
    "comment": NI_COMMENT, "video-comment": NI_COMMENT,
    "follow": NI_USER,
    "share": NI_SHARE, "video-share": NI_SHARE,
    "video-approved": NI_BELL, "video-rejected": NI_BELL, "video-takedown": NI_BELL,
    "email-reply": NI_MAIL, "broadcast": NI_CAST, "admin-broadcast": NI_CAST,
  };

  wrap.innerHTML = top.map(n => {
    const ico = iconMap[n.type] || NI_BELL;
    const text = escapeHtml(String(n.text || "").replace(/<[^>]+>/g, ""));
    const ts = (typeof relTime === "function" && typeof n.id === "number") ? relTime(n.id) : "";
    const unread = n.read ? "" : "unread";
    return `
      <button type="button" class="hn-item ${unread}" data-notif-id="${n.id}">
        <span class="hn-icon">${ico}</span>
        <span class="hn-body">
          <span class="hn-text">${text}</span>
          ${ts ? `<small class="hn-time">${escapeHtml(ts)}</small>` : ""}
        </span>
      </button>`;
  }).join("");

  // Klik item → buka full notification panel di topbar
  wrap.querySelectorAll(".hn-item").forEach(it => {
    it.addEventListener("click", () => {
      const btn = document.getElementById("openNotif");
      if (btn) btn.click();
    });
  });
}

// ----------------------- HOME — NEW FROM FOLLOWING -----------------------
// Replace SPOTLIGHT · CREATOR (per request 2026-05-03). Show video terbaru
// dari kreator yang user follow — sort by createdAt desc. Empty state dengan
// CTA Discover kalau user belum follow siapa pun.
// Live activity ticker — render real-time platform events di right column home.
// Sumber data: platform videos (uploads + view milestones), accounts (signups baru),
// state.activities (current user's actions). Sort newest-first, max 12 entries.
// Auto-refresh tiap 5s supaya timestamp "X menit lalu" tetap fresh & feed feels alive.
function collectPlatformActivities() {
  const events = [];
  const now = Date.now();
  const MAX_AGE_MS = 24 * 60 * 60 * 1000; // 24 jam terakhir
  const myUsername = (user?.username || "").toLowerCase();

  // 1. Recent uploads dari platform — gabung published (dari semua user lewat
  //    getPlatformVideos) DAN myVideos user sendiri (termasuk pending), supaya
  //    feed gak kosong di single-user scenario / video yg masih pending review.
  try {
    const platform = (typeof getPlatformVideos === "function") ? getPlatformVideos() : [];
    const ownVideos = Array.isArray(state?.myVideos) ? state.myVideos : [];
    const seenIds = new Set();
    const combined = [];
    platform.forEach(v => {
      if (v?.id != null && !seenIds.has(v.id)) { seenIds.add(v.id); combined.push(v); }
    });
    ownVideos.forEach(v => {
      if (v?.id != null && !seenIds.has(v.id)) {
        seenIds.add(v.id);
        combined.push({ ...v, creator: v.creator || user?.username });
      }
    });
    combined.forEach(v => {
      if (!v) return;
      const ts = Number(v.createdAt || (typeof v.id === "number" && v.id > 1e12 ? v.id : 0));
      if (!ts || now - ts > MAX_AGE_MS) return;
      const isMe = String(v.creator || "").toLowerCase() === myUsername;
      const title = String(v.title || "video").slice(0, 38);
      const who = isMe ? `<b>Kamu</b>` : `<b>@${escapeHtml(v.creator || "user")}</b>`;
      events.push({
        ts,
        icon: "🎬",
        html: `${who} upload <span class="hat-link" data-vid="${v.id}">"${escapeHtml(title)}"</span>`,
        type: "upload"
      });

      // 1b. View milestones — kalau video lewatin threshold, push proxy event
      const views = Number(v.viewsNum || 0);
      const milestones = [10000, 5000, 1000, 500, 100, 50];
      const reached = milestones.find(m => views >= m);
      if (reached && views < reached * 1.4) {
        events.push({
          ts: ts + reached * 60 * 1000,
          icon: "🔥",
          html: `<span class="hat-link" data-vid="${v.id}">"${escapeHtml(title)}"</span> capai <b>${reached.toLocaleString("id-ID")}</b> views`,
          type: "milestone"
        });
      }
    });
  } catch {}

  // 2. New accounts — user lain yang baru daftar dalam 24 jam
  try {
    const accounts = (typeof getAllAccounts === "function") ? getAllAccounts() : [];
    accounts.forEach(a => {
      if (!a || !a.username) return;
      if (String(a.username).toLowerCase() === myUsername) return;
      const ts = Number(a.joinedAt ? new Date(a.joinedAt).getTime() : 0);
      if (!ts || now - ts > MAX_AGE_MS) return;
      events.push({
        ts,
        icon: "✨",
        html: `<b>@${escapeHtml(a.username)}</b> bergabung di Playly`,
        type: "signup"
      });
    });
  } catch {}

  // 3. Aktivitas user sendiri (dari state.activities) — selingan personal.
  // Skip type="upload" karena sudah ke-cover di branch 1 (myVideos langsung).
  try {
    const myActs = Array.isArray(state?.activities) ? state.activities : [];
    myActs.slice(0, 5).forEach(a => {
      if (a.type === "upload") return;
      const ts = Number(a.ts || 0);
      if (!ts || now - ts > MAX_AGE_MS) return;
      events.push({
        ts,
        icon: a.icon || "📝",
        html: `<b>Kamu</b> ${escapeHtml(String(a.text || "").replace(/<[^>]*>/g, ""))}`,
        type: "self"
      });
    });
  } catch {}

  // Dedupe by html (proxy timestamps bisa nabrak)
  const seen = new Set();
  const dedup = [];
  events.sort((a, b) => b.ts - a.ts);
  for (const e of events) {
    const key = e.html;
    if (seen.has(key)) continue;
    seen.add(key);
    dedup.push(e);
    if (dedup.length >= 12) break;
  }
  return dedup;
}

function renderHomeActivityTicker() {
  const wrap = document.getElementById("homeActivityTicker");
  if (!wrap) return;
  let events = collectPlatformActivities();
  // Fallback platform announcement events — kalau real activity < 3, isi
  // dengan tips/welcome supaya kolom LIVE AKTIVITAS tidak kosong (per user
  // 2026-05-08). Bukan fake user — ini announcement resmi Playly.
  if (events.length < 3) {
    const now = Date.now();
    const announcements = [
      { ts: now - 5 * 60 * 1000, icon: "📣", html: `<b>Playly</b> · Platform sedang melayani <b>12.408+</b> kreator aktif`, type: "announce" },
      { ts: now - 18 * 60 * 1000, icon: "💡", html: `<b>Tips:</b> Upload jam <b>7–9 malam</b> untuk engagement tertinggi`, type: "tip" },
      { ts: now - 42 * 60 * 1000, icon: "🚀", html: `<b>Update:</b> Auto-subtitle AI sekarang dukung <b>16 bahasa</b>`, type: "announce" },
      { ts: now - 70 * 60 * 1000, icon: "🎯", html: `<b>Premium:</b> 4K streaming + ad-free + storage unlimited`, type: "tip" },
      { ts: now - 95 * 60 * 1000, icon: "✨", html: `<b>Tahukah kamu?</b> Streak 7 hari = badge "Konsisten Kreator"`, type: "tip" },
      { ts: now - 130 * 60 * 1000, icon: "📊", html: `<b>Stats:</b> Engagement rata-rata Playly <b>+18%</b> bulan ini`, type: "announce" },
    ];
    events = events.concat(announcements).sort((a, b) => b.ts - a.ts);
  }
  const fmtRel = (ts) => (typeof relTime === "function") ? relTime(ts) : "—";
  wrap.innerHTML = events.map(e => `
    <div class="hat-item hat-type-${e.type}" data-ts="${e.ts}">
      <span class="hat-icon" aria-hidden="true">${e.icon}</span>
      <span class="hat-text">${e.html}</span>
      <span class="hat-time">${fmtRel(e.ts)}</span>
    </div>
  `).join("");
  // Click on .hat-link[data-vid] → open video
  wrap.querySelectorAll(".hat-link[data-vid]").forEach(el => {
    el.addEventListener("click", e => {
      e.preventDefault();
      const id = +el.dataset.vid;
      if (typeof switchView === "function") switchView("videos");
      setTimeout(() => {
        if (typeof openInlinePlayer === "function") openInlinePlayer(id);
        else if (typeof playVideo === "function") playVideo(id);
      }, 60);
    });
  });
}

// Backward-compat alias — call sites lama panggil renderHomeFollowingFeed().
// Sekarang re-route ke ticker (per request 2026-05-10: ganti following feed
// dengan live activity ticker yg lebih hidup).
function renderHomeFollowingFeed() {
  renderHomeActivityTicker();
}

// =================== HOME TRENDING SEKARANG + UNTUK KAMU ===================
// Per user 2026-05-11: 2 section baru di akhir home view — 4-col grid video.
// "Trending sekarang" = top platform videos by views (desc).
// "Untuk kamu" = platform videos filtered by category tag (Vlog/Gaming/etc).
// Pakai existing .video-card style supaya konsisten dgn dashboard user theme.

const HOME_FORYOU_CAT_KEYWORDS = {
  vlog: ["vlog", "harian", "daily", "rutinitas"],
  gaming: ["game", "gaming", "gameplay", "main"],
  musik: ["musik", "lagu", "music", "cover", "live music"],
  tutorial: ["tutorial", "belajar", "panduan", "cara"],
  kuliner: ["kuliner", "masak", "resep", "makan", "food"],
  travel: ["travel", "trip", "jalan", "wisata", "tour", "bajo"],
  tech: ["tech", "tekno", "gadget", "review", "rig", "setup"],
  komedi: ["komedi", "lucu", "stand up", "humor", "ngakak"],
};

function _matchForYouCategory(video, cat) {
  if (!cat || cat === "all") return true;
  const keywords = HOME_FORYOU_CAT_KEYWORDS[cat] || [];
  if (!keywords.length) return false;
  const hay = `${video.title || ""} ${video.description || ""} ${(video.tags || []).join(" ")}`.toLowerCase();
  return keywords.some(k => hay.includes(k));
}

function _homeVideoCardHTML(v, opts) {
  // Compact video card untuk grid home. Per fix user 2026-05-15 v67:
  // badge kontekstual — opts.badge "trending" → TRENDING (merah),
  // "category" → label kategori video (mis. VLOG), default → no badge.
  const isOwn = v.creator === user?.username;
  const liked = state?.liked?.includes(v.id);
  const saved = state?.saved?.includes(v.id);
  const views = v.views || (v.viewsNum != null ? fmtNum(v.viewsNum) : "0");
  let badgeHtml = "";
  const badge = opts && opts.badge;
  if (badge === "trending") {
    badgeHtml = `<span class="home-vid-trending-tag">TRENDING</span>`;
  } else if (badge === "category") {
    const cat = (v.category || "").trim();
    if (cat) badgeHtml = `<span class="home-vid-cat-tag">${escapeHtml(cat.toUpperCase())}</span>`;
  }
  return `
    <div class="video-card home-vid-card" data-vid="${v.id}">
      <div class="thumb">
        <img src="${v.thumb || ""}" alt="${escapeHtml(v.title || "")}" loading="lazy"/>
        ${badgeHtml}
        ${isOwn ? `<button class="delete-btn" data-delete-vid="${v.id}" title="Hapus video">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" width="14" height="14"><path d="M3 6h18M8 6V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/></svg>
        </button>` : ""}
        <div class="thumb-overlay">
          <button class="play-btn"><svg viewBox="0 0 24 24" fill="currentColor"><path d="M8 5v14l11-7z"/></svg></button>
          <span class="duration">${escapeHtml(v.duration || "")}</span>
        </div>
      </div>
      <div class="video-info">
        <h4>${escapeHtml(v.title || "")}</h4>
        <p><span class="creator">@${escapeHtml(v.creator || "—")}</span> · ${views} views</p>
      </div>
    </div>
  `;
}

function _homeVidEmpty(icon, msg) {
  return `<div class="home-vid-empty">
    <div class="home-vid-empty-icon">${icon}</div>
    <p>${msg}</p>
  </div>`;
}

function renderHomeTrendingNow() {
  const grid = document.getElementById("homeTrendingNowGrid");
  if (!grid) return;
  let videos = [];
  try { videos = (typeof getPlatformVideos === "function") ? getPlatformVideos() : []; } catch {}
  // Sort by viewsNum desc, take top 4
  videos = videos
    .slice()
    .sort((a, b) => (b.viewsNum || 0) - (a.viewsNum || 0))
    .slice(0, 4);
  if (!videos.length) {
    grid.innerHTML = _homeVidEmpty("🔥", "Belum ada video trending — upload video pertama untuk muncul di sini.");
    window._homeTrendingIds = new Set();
    return;
  }
  // Simpan ID trending → dipakai renderHomeForYou buat exclude (anti-duplikat)
  window._homeTrendingIds = new Set(videos.map(v => v.id));
  grid.innerHTML = videos.map(v => _homeVideoCardHTML(v, { badge: "trending" })).join("");
}

let __homeForYouCat = "all";
function renderHomeForYou(cat) {
  if (cat != null) __homeForYouCat = cat;
  const grid = document.getElementById("homeForYouGrid");
  if (!grid) return;
  let videos = [];
  try { videos = (typeof getPlatformVideos === "function") ? getPlatformVideos() : []; } catch {}
  // Anti-duplikat: exclude video yg udah tampil di Trending (per fix v67)
  const trendingIds = window._homeTrendingIds instanceof Set ? window._homeTrendingIds : new Set();
  // Filter by category + exclude trending, then take 8 most recent
  const filtered = videos
    .filter(v => _matchForYouCategory(v, __homeForYouCat))
    .filter(v => !trendingIds.has(v.id))
    .slice()
    .sort((a, b) => (b.id || 0) - (a.id || 0))
    .slice(0, 8);
  if (!filtered.length) {
    const catLabel = __homeForYouCat === "all" ? "video" : `video kategori ${__homeForYouCat}`;
    grid.innerHTML = _homeVidEmpty("🎬", `Belum ada ${catLabel} lain di kategori ini.`);
    return;
  }
  // Badge kategori (bukan TRENDING) di section "Untuk kamu"
  grid.innerHTML = filtered.map(v => _homeVideoCardHTML(v, { badge: "category" })).join("");
}

// ===== 👥 UPDATE KREATOR DIIKUTI (per request user 2026-05-15 v71) =====
// Video terbaru dari kreator yang user follow (state.followingCreators).
function renderHomeFollowingUpdates() {
  const grid = document.getElementById("homeFollowingGrid");
  if (!grid) return;
  let following = [];
  try {
    following = (typeof getUserFollowing === "function")
      ? getUserFollowing((user?.username || "").toLowerCase())
      : (Array.isArray(state?.followingCreators) ? state.followingCreators : []);
  } catch {}
  if (!following.length) {
    grid.innerHTML = _homeVidEmpty("👥", "Belum mengikuti kreator. Jelajahi & ikuti kreator untuk lihat update mereka.");
    return;
  }
  let all = [];
  try { all = (typeof getPlatformVideos === "function") ? getPlatformVideos() : []; } catch {}
  const followSet = new Set(following.map(u => String(u).toLowerCase()));
  const vids = all
    .filter(v => followSet.has(String(v.creator || "").toLowerCase()))
    .slice()
    .sort((a, b) => (b.id || 0) - (a.id || 0))
    .slice(0, 8);
  if (!vids.length) {
    grid.innerHTML = _homeVidEmpty("🎬", "Kreator yang kamu ikuti belum upload video baru.");
    return;
  }
  grid.innerHTML = vids.map(v => _homeVideoCardHTML(v, { badge: "category" })).join("");
}

// ===== 🎖️ PENCAPAIAN KREATOR (per request user 2026-05-15 v71) =====
function renderHomeAchievements() {
  const grid = document.getElementById("homeAchievementsGrid");
  if (!grid) return;
  const myVids = Array.isArray(state?.myVideos) ? state.myVideos : [];
  const totalViews = myVids.reduce((s, v) => s + (Number(v.viewsNum) || 0), 0);
  const totalLikes = myVids.reduce((s, v) => s + (Number(v.likes) || 0), 0);
  let followers = 0;
  try { followers = (typeof getUserFollowers === "function") ? getUserFollowers((user?.username || "").toLowerCase()).length : (Array.isArray(state?.followers) ? state.followers.length : 0); } catch {}
  // Ikon minimalis SVG monokrom (per request user 2026-05-16: bukan emoji
   // warna). Single-quote string, double-quote di dalam SVG, NO backtick.
  const SI = 'viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"';
  const IC_VIDEO  = '<svg ' + SI + '><rect x="2" y="4" width="20" height="16" rx="2"/><path d="M10 9l5 3-5 3z"/></svg>';
  const IC_STACK  = '<svg ' + SI + '><rect x="3" y="3" width="13" height="13" rx="2"/><path d="M8 21h11a2 2 0 0 0 2-2V8"/></svg>';
  const IC_EYE    = '<svg ' + SI + '><path d="M2 12s3.5-7 10-7 10 7 10 7-3.5 7-10 7S2 12 2 12Z"/><circle cx="12" cy="12" r="3"/></svg>';
  const IC_TREND  = '<svg ' + SI + '><polyline points="3 17 9 11 13 15 21 7"/><polyline points="15 7 21 7 21 13"/></svg>';
  const IC_HEART  = '<svg ' + SI + '><path d="M20.8 4.6a5.5 5.5 0 0 0-7.8 0L12 5.6l-1-1a5.5 5.5 0 1 0-7.8 7.8l1 1L12 21l7.8-7.8 1-1a5.5 5.5 0 0 0 0-7.6Z"/></svg>';
  const IC_STAR   = '<svg ' + SI + '><polygon points="12 2 15 9 22 9.3 16.5 14 18.5 21 12 17 5.5 21 7.5 14 2 9.3 9 9"/></svg>';
  const IC_USERS  = '<svg ' + SI + '><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87M16 3.13a4 4 0 0 1 0 7.75"/></svg>';
  const IC_TROPHY = '<svg ' + SI + '><circle cx="12" cy="8" r="6"/><path d="M8.5 13.5 7 22l5-3 5 3-1.5-8.5"/></svg>';
  const IC_LOCK   = '<svg ' + SI + '><rect x="4" y="11" width="16" height="10" rx="2"/><path d="M8 11V8a4 4 0 0 1 8 0v3"/></svg>';
  const ACH = [
    { ico: IC_VIDEO,  name:"Video Pertama",   desc:"Upload 1 video",        ok: myVids.length >= 1 },
    { ico: IC_STACK,  name:"Produktif",        desc:"Upload 10 video",       ok: myVids.length >= 10 },
    { ico: IC_EYE,    name:"100 Tontonan",     desc:"Capai 100 tontonan",    ok: totalViews >= 100 },
    { ico: IC_TREND,  name:"1K Tontonan",      desc:"Capai 1.000 tontonan",  ok: totalViews >= 1000 },
    { ico: IC_HEART,  name:"Disukai",          desc:"Capai 100 suka",        ok: totalLikes >= 100 },
    { ico: IC_STAR,   name:"Idola Baru",       desc:"Capai 1.000 suka",      ok: totalLikes >= 1000 },
    { ico: IC_USERS,  name:"Punya Pengikut",   desc:"Capai 10 pengikut",     ok: followers >= 10 },
    { ico: IC_TROPHY, name:"Populer",          desc:"Capai 100 pengikut",    ok: followers >= 100 },
  ];
  const unlocked = ACH.filter(a => a.ok).length;
  const countEl = document.getElementById("haCount");
  if (countEl) countEl.textContent = `${unlocked}/${ACH.length} ter-unlock`;
  grid.innerHTML = ACH.map(a => `
    <div class="ha-badge ${a.ok ? "unlocked" : "locked"}">
      <div class="ha-badge-ico">${a.ok ? a.ico : IC_LOCK}</div>
      <div class="ha-badge-text">
        <strong>${escapeHtml(a.name)}</strong>
        <small>${escapeHtml(a.desc)}</small>
      </div>
    </div>`).join("");
}

