// =================== PERFORMA HARI INI (home page card) ===================
// Tampilkan: total views/likes/followers user + delta vs kemarin + 7-day sparkline.
// Daily snapshot disimpan di localStorage `playly-daily-snapshot-${username}` —
// rolling 7 hari terakhir ({date: "YYYY-MM-DD", views, likes, followers}).
const __PERF_SNAPSHOT_KEY = (username) => `playly-daily-snapshot-${username}`;

function _todayDateStr() {
  const d = new Date();
  const y = d.getFullYear(), m = String(d.getMonth() + 1).padStart(2, "0"), day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
}
function _yesterdayDateStr() {
  const d = new Date();
  d.setDate(d.getDate() - 1);
  const y = d.getFullYear(), m = String(d.getMonth() + 1).padStart(2, "0"), day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
}

function _readPerfSnapshots() {
  if (!user?.username) return [];
  try {
    const raw = localStorage.getItem(__PERF_SNAPSHOT_KEY(user.username));
    return raw ? JSON.parse(raw) : [];
  } catch { return []; }
}
function _writePerfSnapshots(snaps) {
  if (!user?.username) return;
  try { localStorage.setItem(__PERF_SNAPSHOT_KEY(user.username), JSON.stringify(snaps)); } catch {}
}
function _capturePerfSnapshotIfNew() {
  if (!user?.username) return _readPerfSnapshots();
  const myVids = Array.isArray(state?.myVideos) ? state.myVideos : [];
  const totals = {
    views:     myVids.reduce((s, v) => s + (Number(v.viewsNum) || 0), 0),
    likes:     myVids.reduce((s, v) => s + (Number(v.likes)    || 0), 0),
    followers: Array.isArray(state?.followers) ? state.followers.length : 0
  };
  const today = _todayDateStr();
  let snaps = _readPerfSnapshots();
  const idx = snaps.findIndex(s => s.date === today);
  if (idx >= 0) {
    // Update today's snapshot dengan angka terbaru (incremental — captures growth selama hari ini)
    snaps[idx] = { date: today, ...totals };
  } else {
    snaps.push({ date: today, ...totals });
  }
  // Rolling 7 hari (urut by date asc, keep last 7)
  snaps.sort((a, b) => (a.date > b.date ? 1 : -1));
  if (snaps.length > 7) snaps = snaps.slice(-7);
  _writePerfSnapshots(snaps);
  return snaps;
}

function _fmtNumShort(n) {
  if (typeof fmtNum === "function") return fmtNum(n);
  if (n >= 1e6) return (n / 1e6).toFixed(1) + "M";
  if (n >= 1e3) return (n / 1e3).toFixed(1) + "k";
  return String(n);
}

// Build mini-sparkline SVG dari array values (length up to 7).
function _buildSparkline(values, width = 100, height = 28) {
  const n = values.length;
  if (n < 2) return "";
  const max = Math.max(...values, 1);
  const min = Math.min(...values, 0);
  const range = max - min || 1;
  const stepX = width / (n - 1);
  const points = values.map((v, i) => {
    const x = i * stepX;
    const y = height - ((v - min) / range) * (height - 4) - 2;
    return `${x.toFixed(1)},${y.toFixed(1)}`;
  }).join(" ");
  // Area path
  const areaPath = `M0,${height} L${points.replace(/ /g, " L")} L${width},${height} Z`;
  return `
    <svg viewBox="0 0 ${width} ${height}" preserveAspectRatio="none" class="hpf-spark">
      <defs>
        <linearGradient id="hpfGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="var(--primary, #6D2932)" stop-opacity=".42"/>
          <stop offset="100%" stop-color="var(--primary, #6D2932)" stop-opacity="0"/>
        </linearGradient>
      </defs>
      <path d="${areaPath}" fill="url(#hpfGrad)"/>
      <polyline points="${points}" fill="none" stroke="var(--primary, #6D2932)" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round"/>
    </svg>
  `;
}

function renderHomePerfCard() {
  const wrap = document.getElementById("homePerfCard");
  if (!wrap) return;
  const myVids = Array.isArray(state?.myVideos) ? state.myVideos : [];
  if (!myVids.length) {
    wrap.innerHTML = `
      <div class="hra-empty">
        <div class="hra-empty-icon">📊</div>
        <p>Upload video pertamamu untuk mulai tracking performa di sini.</p>
        <button class="btn primary small" data-jump="upload" style="margin-top:10px">Upload Sekarang</button>
      </div>`;
    wrap.querySelector("[data-jump]")?.addEventListener("click", () => switchView?.("upload"));
    return;
  }
  const snaps = _capturePerfSnapshotIfNew();
  const today = snaps[snaps.length - 1] || null;
  const yesterday = snaps.length >= 2 ? snaps[snaps.length - 2] : null;

  const todayViews     = today?.views || 0;
  const todayLikes     = today?.likes || 0;
  const todayFollowers = today?.followers || 0;

  const calcDelta = (cur, prev) => {
    if (prev == null || prev === 0) return cur > 0 ? "+∞" : "—";
    const d = cur - prev;
    if (d === 0) return "0";
    const sign = d > 0 ? "+" : "";
    return `${sign}${d}`;
  };
  const dViews     = yesterday ? calcDelta(todayViews,     yesterday.views)     : "—";
  const dLikes     = yesterday ? calcDelta(todayLikes,     yesterday.likes)     : "—";
  const dFollowers = yesterday ? calcDelta(todayFollowers, yesterday.followers) : "—";

  const trendCls = (d) => {
    if (d.startsWith("+") && d !== "+0") return "up";
    if (d.startsWith("-")) return "down";
    return "flat";
  };

  const viewsSeries = snaps.map(s => Number(s.views) || 0);
  const sparkline = (snaps.length >= 2) ? _buildSparkline(viewsSeries) : "";

  wrap.innerHTML = `
    <div class="hpf-grid">
      <div class="hpf-stat">
        <span class="hpf-icon" aria-hidden="true">👁</span>
        <div class="hpf-stat-body">
          <small>Views</small>
          <strong>${_fmtNumShort(todayViews)}</strong>
          <span class="hpf-delta hpf-${trendCls(dViews)}">${dViews}</span>
        </div>
      </div>
      <div class="hpf-stat">
        <span class="hpf-icon" aria-hidden="true">❤️</span>
        <div class="hpf-stat-body">
          <small>Likes</small>
          <strong>${_fmtNumShort(todayLikes)}</strong>
          <span class="hpf-delta hpf-${trendCls(dLikes)}">${dLikes}</span>
        </div>
      </div>
      <div class="hpf-stat">
        <span class="hpf-icon" aria-hidden="true">👥</span>
        <div class="hpf-stat-body">
          <small>Followers</small>
          <strong>${_fmtNumShort(todayFollowers)}</strong>
          <span class="hpf-delta hpf-${trendCls(dFollowers)}">${dFollowers}</span>
        </div>
      </div>
    </div>
    ${sparkline ? `
      <div class="hpf-spark-wrap">
        <small class="hpf-spark-label">Tren views 7 hari</small>
        ${sparkline}
      </div>
    ` : `<small class="hpf-no-data">Tren 7 hari muncul setelah 2+ hari aktif.</small>`}
  `;
}

// =================== SARAN KREATOR (home page card) ===================
// Top 5 kreator yg belum di-follow — sort by followers count desc, then random.
function renderHomeSuggestCard() {
  const wrap = document.getElementById("homeSuggestCard");
  if (!wrap) return;
  const all = (typeof getPlatformCreators === "function") ? getPlatformCreators({ activeOnly: true }) : [];
  const followingSet = new Set((state?.followingCreators || []).map(x => String(x).toLowerCase()));
  const myUsername = String(user?.username || "").toLowerCase();
  const candidates = all
    .filter(c => c && c.name)
    .filter(c => String(c.name).toLowerCase() !== myUsername)
    .filter(c => !followingSet.has(String(c.name).toLowerCase()))
    .sort((a, b) => (Number(b.followers) || 0) - (Number(a.followers) || 0))
    .slice(0, 5);

  if (!candidates.length) {
    wrap.innerHTML = `
      <div class="hra-empty">
        <div class="hra-empty-icon">🤝</div>
        <p>Belum ada kreator lain untuk disarankan. Ajak temanmu bergabung di Playly!</p>
      </div>`;
    return;
  }

  wrap.innerHTML = `
    <div class="hsg-list">
      ${candidates.map(c => {
        const init = escapeHtml(c.init || (c.name || "?").slice(0, 1).toUpperCase());
        const name = escapeHtml(c.name);
        const subs = escapeHtml(c.subs || `${c.followers || 0} followers`);
        return `
          <div class="hsg-item" data-creator="${name}">
            <div class="hsg-avatar">${init}</div>
            <div class="hsg-info">
              <strong>@${name}</strong>
              <small>${subs}</small>
            </div>
            <button type="button" class="hsg-follow-btn" data-suggest-follow="${name}">+ Follow</button>
          </div>`;
      }).join("")}
    </div>
  `;

  wrap.querySelectorAll(".hsg-item").forEach(item => {
    item.addEventListener("click", e => {
      if (e.target.closest("[data-suggest-follow]")) return;
      const name = item.dataset.creator;
      if (typeof openCreatorProfile === "function") openCreatorProfile(name);
      else if (typeof switchView === "function") switchView("creators");
    });
  });
  wrap.querySelectorAll("[data-suggest-follow]").forEach(btn => {
    btn.addEventListener("click", e => {
      e.stopPropagation();
      const name = btn.dataset.suggestFollow;
      if (!Array.isArray(state.followingCreators)) state.followingCreators = [];
      if (!state.followingCreators.some(x => String(x).toLowerCase() === String(name).toLowerCase())) {
        state.followingCreators.push(name);
        saveState?.();
        toast?.(`✓ Follow <b>@${escapeHtml(name)}</b>`, "success");
        renderHomeSuggestCard();
      }
    });
  });
}

