/* =========================================================
   HOME — Live Metrics, Quick Actions, Creator Spotlight
   ========================================================= */

// ---- Live Metrics (real-time platform stats) ----
function renderLiveMetrics() {
  const wrap = $("#liveMetrics");
  if (!wrap) return;
  const videos = getPlatformVideos();
  const totalViews = videos.reduce((s, v) => s + (v.viewsNum || 0), 0);
  const totalVideos = videos.length;
  // Total kreator = semua user terdaftar yang punya min. 1 video, plus diri sendiri kalau punya video
  const otherCreators = getPlatformCreators({ activeOnly: true }).length;
  const myHasVideos = (state?.myVideos?.length || 0) > 0 ? 1 : 0;
  const totalCreators = otherCreators + myHasVideos;
  // Upload hari ini = video dengan createdAt < 24 jam yang lalu (atau id sebagai fallback timestamp)
  const now = Date.now();
  const oneDay = 24 * 60 * 60 * 1000;
  const todayCount = videos.filter(v => {
    const t = v.createdAt || (typeof v.id === "number" && v.id > 1e12 ? v.id : 0);
    return t && (now - t) < oneDay;
  }).length;

  const targets = { views: totalViews, videos: totalVideos, creators: totalCreators, today: todayCount };
  wrap.querySelectorAll(".metric-card").forEach(card => {
    const key = card.dataset.metric;
    const target = targets[key] || 0;
    const valEl = card.querySelector(".metric-value");
    if (!valEl) return;
    const prev = parseInt(valEl.dataset.target) || 0;
    if (prev === target) return;
    valEl.dataset.target = String(target);
    animateCount(valEl, prev, target, 800);
  });
}

function animateCount(el, from, to, duration = 800) {
  const start = performance.now();
  const fmt = n => fmtNum(Math.round(n));
  function frame(now) {
    const t = Math.min(1, (now - start) / duration);
    const eased = 1 - Math.pow(1 - t, 3); // ease-out cubic
    const val = from + (to - from) * eased;
    el.textContent = fmt(val);
    if (t < 1) requestAnimationFrame(frame);
    else el.textContent = fmt(to);
  }
  requestAnimationFrame(frame);
}

// ---- Quick Actions Bar ----
function bindQuickActions() {
  const copyBtn = $("#qaCopyProfileLink");
  if (copyBtn && !copyBtn.dataset.bound) {
    copyBtn.dataset.bound = "1";
    copyBtn.addEventListener("click", async () => {
      const uname = user?.username || "";
      if (!uname) return toast("⚠️ Username belum tersedia", "warning");
      const url = `${location.origin}${location.pathname}?u=${encodeURIComponent(uname)}`;
      try {
        await navigator.clipboard.writeText(url);
        toast("✓ Link profil disalin", "success");
      } catch {
        const ta = document.createElement("textarea");
        ta.value = url;
        ta.style.position = "fixed"; ta.style.opacity = "0";
        document.body.appendChild(ta);
        ta.select();
        try { document.execCommand("copy"); toast("✓ Link disalin", "success"); }
        catch { toast("❌ Gagal salin link", "error"); }
        ta.remove();
      }
    });
  }
  const switchBtn = $("#qaSwitchAccount");
  if (switchBtn && !switchBtn.dataset.bound) {
    switchBtn.dataset.bound = "1";
    switchBtn.addEventListener("click", () => {
      if (typeof openSwitchAccount === "function") openSwitchAccount();
    });
  }
}

// ---- Creator Spotlight Slider ----
const csState = { idx: 0, list: [], timer: null };

// =================== TRENDING HARI INI (X-style: judul artikel + hashtag) ===================
// Trending = REAL platform data only — fix B6 audit 2026-05-02.
// TRENDING_POOL (25 hardcoded curated topics) DIHAPUS karena bukan data
// real-time. Sebelumnya pool ini di-rotate harian via date hash supaya
// "fresh", tapi user request data semua harus real-time. Sekarang hanya
// hashtag dari video 48 jam terakhir di platform — empty state kalau belum
// ada video dengan hashtag.

function _extractHashtagsFromVideo(v) {
  const text = `${v.title || ""} ${v.desc || ""} ${v.tags || ""}`.toLowerCase();
  const tags = [];
  const re = /#([a-z0-9_\-]{2,30})/gi;
  let m;
  while ((m = re.exec(text)) !== null) {
    if (!tags.includes(m[1])) tags.push(m[1]);
  }
  if (tags.length === 0 && v.category) {
    tags.push(String(v.category).toLowerCase().replace(/[^a-z0-9]/g, ""));
  }
  return tags.filter(Boolean);
}


// 🏆 Leaderboard — daftar vertikal rapi (per request user 2026-05-16:
// kartu flip/animasi lama diganti, kolom memanjang). String-concat, NO backtick.
function renderHomeRanking() {
  const row   = document.getElementById("rankingRow");
  const empty = document.getElementById("rankingEmpty");
  if (!row) return;

  let vids = [];
  try { vids = (typeof getPlatformVideos === "function") ? getPlatformVideos() : []; } catch (e) {}
  const map = {};
  vids.forEach(function (v) {
    const k = v.creator || v.username || "-";
    map[k] = map[k] || { name: k, views: 0, likes: 0, videos: 0 };
    map[k].views  += v.viewsNum || 0;
    map[k].likes  += v.likes    || 0;
    map[k].videos++;
  });
  const rankedAll = Object.keys(map).map(function (k) { return map[k]; })
    .sort(function (a, b) { return b.views - a.views; });
  if (!rankedAll.length) {
    if (empty) empty.hidden = false;
    row.innerHTML = "";
    return;
  }
  if (empty) empty.hidden = true;

  const me = ((user && user.username) || "").toLowerCase();
  const myIdx = rankedAll.findIndex(function (c) { return String(c.name).toLowerCase() === me; });
  const total = rankedAll.length;
  const ranked = rankedAll.slice(0, 3);   // Top 3 saja (request user 2026-05-17)

  // Kalimat ajakan utk user (request user 2026-05-17): muncul DI ATAS
  // daftar 1-2-3, mendorong user bertanding masuk Top Creators.
  let cta;
  if (myIdx > -1 && myIdx < 3) {
    cta = 'Keren! Kamu sudah di <b>Top 3</b> kreator — pertahankan posisimu!';
  } else if (myIdx > -1) {
    cta = 'Kamu peringkat <b>#' + (myIdx + 1) + '</b> dari ' + total +
      ' kreator. Tingkatkan tontonan &amp; suka untuk bertanding masuk <b>Top Creators</b>!';
  } else {
    cta = 'Unggah video &amp; kumpulkan tontonan untuk bertanding masuk <b>Top Creators</b>!';
  }

  // (Kartu "Lawan Berikutnya" DIHAPUS per request user 2026-05-17 —
  // user kurang suka; minta saran fitur lain.)

  // Ikon stat monokrom SVG (per request user 2026-05-17: ganti emoji
  // 👁❤🎬 → SVG, konsisten dgn Level/Pencapaian yg sudah no-emoji).
  // String-concat, NO backtick (konvensi render fn beranda).
  const _lbsi = 'viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"';
  const LB_EYE   = '<svg ' + _lbsi + '><path d="M2 12s3.5-7 10-7 10 7 10 7-3.5 7-10 7S2 12 2 12Z"/><circle cx="12" cy="12" r="3"/></svg>';
  const LB_HEART = '<svg ' + _lbsi + '><path d="M20.8 4.6a5.5 5.5 0 0 0-7.8 0L12 5.6l-1-1a5.5 5.5 0 1 0-7.8 7.8l1 1L12 21l7.8-7.8 1-1a5.5 5.5 0 0 0 0-7.6Z"/></svg>';
  const LB_VIDEO = '<svg ' + _lbsi + '><rect x="2" y="4" width="20" height="16" rx="2"/><path d="M10 9l5 3-5 3z"/></svg>';
  const rows = ranked.map(function (c, i) {
    const isMe = String(c.name).toLowerCase() === me;
    const init = (String(c.name).replace(/[^a-zA-Z0-9]/g, "").slice(0, 2).toUpperCase()) || "U";
    // Rank 1-3 = MEDALI jelas (pita + medalion + angka di tengah) —
    // request user 2026-05-17 ("medali tapi yang jelas"). Netral krem.
    const rankCell = (i < 3)
      ? '<span class="lb-medal3" data-rank="' + (i + 1) + '">' +
          '<span class="lb-medal3-disc">' + (i + 1) + '</span></span>'
      : '<span class="lb-num">' + (i + 1) + '</span>';
    return '<div class="lb-row' + (isMe ? ' is-me' : '') + '">' +
      '<div class="lb-rank">' + rankCell + '</div>' +
      '<div class="lb-av">' + escapeHtml(init) + '</div>' +
      '<div class="lb-name">@' + escapeHtml(c.name) +
        (isMe ? '<span class="lb-you">kamu</span>' : '') + '</div>' +
      '<div class="lb-stats">' +
        '<span class="lb-st" title="Tontonan">' + LB_EYE + fmtNum(c.views) + '</span>' +
        '<span class="lb-st" title="Suka">' + LB_HEART + fmtNum(c.likes) + '</span>' +
        '<span class="lb-st" title="Video">' + LB_VIDEO + fmtNum(c.videos) + '</span>' +
      '</div>' +
    '</div>';
  }).join("");
  row.innerHTML = '<div class="lb-cta">' + cta + '</div>' +
    '<div class="lb-list">' + rows + '</div>';
}


// ===== 4 WIDGET FOKUS-KREATOR DI BERANDA (per request user 2026-05-16) =======
// Leaderboard caption + Rekap Mingguan + Momentum + Checklist.
// SEMUA dibangun pakai string-concat ('...' + '...'), BUKAN template literal,
// jadi mustahil kena bug backtick yg pernah matikan script.js (lihat pitfalls).
function _vTs(v) {
  return Number(v && (v.uploadedAt || v.createdAt ||
    (typeof v.id === "number" && v.id > 1e12 ? v.id : 0))) || 0;
}
function _myVideos() {
  return Array.isArray(state && state.myVideos) ? state.myVideos : [];
}
function _myFollowers() {
  try {
    if (typeof getUserFollowers === "function")
      return getUserFollowers(((user && user.username) || "").toLowerCase()).length;
  } catch (e) {}
  return Array.isArray(state && state.followers) ? state.followers.length : 0;
}

// ---- 🏆 Caption "Peringkat kamu" (renderHomeRanking sudah render top-3) ----
function renderHomeRankingSelf() {
  const el = document.getElementById("hrkSelf");
  if (!el) return;
  let vids = [];
  try { vids = (typeof getPlatformVideos === "function") ? getPlatformVideos() : []; } catch (e) {}
  const map = {};
  vids.forEach(function (v) {
    const k = (v.creator || v.username || "-");
    map[k] = map[k] || { name: k, views: 0 };
    map[k].views += v.viewsNum || 0;
  });
  const ranked = Object.keys(map).map(function (k) { return map[k]; })
    .sort(function (a, b) { return b.views - a.views; });
  const total = ranked.length;
  const me = ((user && user.username) || "").toLowerCase();
  let pos = -1;
  for (let i = 0; i < ranked.length; i++) {
    if (String(ranked[i].name).toLowerCase() === me) { pos = i + 1; break; }
  }
  if (pos > 0) el.innerHTML = "Peringkat kamu: <b>#" + pos + "</b> dari " + total + " kreator";
  else el.textContent = "Top kreator berdasarkan total tontonan";
}

// ---- 📈 Level Kreator (XP) — "lawan" Pencapaian: progress kontinu, tak
//      pernah mentok. Per request user 2026-05-16. String-concat, NO backtick.
//      XP dari data nyata: tontonan + suka + jumlah video + pengikut.
function _xpForLevel(L) { return 250 * L * (L - 1); } // L1=0,L2=500,L3=1500,L4=3000...
function renderHomeCreatorLevel() {
  const wrap = document.getElementById("homeCreatorLevel");
  if (!wrap) return;
  const vids = _myVideos();
  const views = vids.reduce(function (s, v) { return s + (Number(v.viewsNum) || 0); }, 0);
  const likes = vids.reduce(function (s, v) { return s + (Number(v.likes) || 0); }, 0);
  const nVid  = vids.length;
  const foll  = _myFollowers();
  const xpViews = views * 1;
  const xpLikes = likes * 5;
  const xpVid   = nVid * 50;
  const xpFoll  = foll * 20;
  const xp = xpViews + xpLikes + xpVid + xpFoll;

  let level = 1;
  while (_xpForLevel(level + 1) <= xp && level < 999) level++;
  const base = _xpForLevel(level);
  const next = _xpForLevel(level + 1);
  const into = xp - base;
  const span = Math.max(1, next - base);
  const pct  = Math.max(0, Math.min(100, Math.round(into / span * 100)));
  const remain = Math.max(0, next - xp);

  const TITLES = ["Pemula", "Pendatang", "Kreator Naik Daun", "Kreator Aktif",
    "Kreator Andal", "Kreator Pro", "Bintang Lokal", "Influencer",
    "Ikon Playly", "Legenda Playly"];
  const titleFor = function (L) {
    return TITLES[Math.min(L, TITLES.length) - 1] || "Legenda Playly";
  };

  // Ikon minimalis monokrom (per request user 2026-05-16, bukan emoji warna)
  const _si = 'viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"';
  const ICV_EYE   = '<svg ' + _si + '><path d="M2 12s3.5-7 10-7 10 7 10 7-3.5 7-10 7S2 12 2 12Z"/><circle cx="12" cy="12" r="3"/></svg>';
  const ICV_HEART = '<svg ' + _si + '><path d="M20.8 4.6a5.5 5.5 0 0 0-7.8 0L12 5.6l-1-1a5.5 5.5 0 1 0-7.8 7.8l1 1L12 21l7.8-7.8 1-1a5.5 5.5 0 0 0 0-7.6Z"/></svg>';
  const ICV_VIDEO = '<svg ' + _si + '><rect x="2" y="4" width="20" height="16" rx="2"/><path d="M10 9l5 3-5 3z"/></svg>';
  const ICV_USERS = '<svg ' + _si + '><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87M16 3.13a4 4 0 0 1 0 7.75"/></svg>';
  const chip = function (ico, label, val) {
    return '<span class="hlv-chip">' + ico + ' ' + label +
      ' <b>+' + fmtNum(val) + '</b></span>';
  };

  wrap.innerHTML =
    '<div class="hlv-head">' +
      '<div class="hlv-titlewrap">' +
        '<span class="sec-icon-v582" aria-hidden="true"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="3 17 9 11 13 15 21 7"/><polyline points="15 7 21 7 21 13"/></svg></span>' +
        '<div class="hlv-titlewrap-text">' +
          '<h3>Level Kreator</h3>' +
          '<small class="hlv-sub">Naik level dari aktivitas channel — terus tumbuh, tanpa batas</small>' +
        '</div>' +
      '</div>' +
      '<small class="hlv-note">XP: tontonan + suka + video + pengikut</small>' +
    '</div>' +
    '<div class="hlv-main">' +
      '<div class="hlv-badge"><span class="hlv-lv">Lv</span>' +
        '<span class="hlv-lvnum">' + level + '</span></div>' +
      '<div class="hlv-body">' +
        '<div class="hlv-title">' + titleFor(level) +
          '<span class="hlv-xp">' + fmtNum(xp) + ' XP</span></div>' +
        '<div class="hlv-bar"><i style="width:' + pct + '%"></i></div>' +
        '<div class="hlv-next">' +
          (remain > 0
            ? fmtNum(remain) + ' XP lagi menuju <b>Lv ' + (level + 1) +
              ' &middot; ' + titleFor(level + 1) + '</b>'
            : 'Level maksimum tercapai 🎉') +
        '</div>' +
      '</div>' +
    '</div>' +
    '<div class="hlv-break">' +
      chip(ICV_EYE, 'Tontonan', xpViews) +
      chip(ICV_HEART, 'Suka', xpLikes) +
      chip(ICV_VIDEO, 'Video', xpVid) +
      chip(ICV_USERS, 'Pengikut', xpFoll) +
    '</div>';
}

// (Rekap Mingguan / renderHomeRecap DIHAPUS per request user 2026-05-16.
//  CSS .hrc-* dibiarkan jadi dead-rule, sesuai konvensi codebase.)

// (Video Lagi Naik / renderHomeMomentum DIHAPUS per request user 2026-05-16.
//  CSS .hmo-* dibiarkan jadi dead-rule. Helper _vTs/_myVideos/_myFollowers
//  dibiarkan — tak dipakai lagi tapi harmless, sesuai konvensi codebase.)

// =================== SUGGEST USERS (sarankan kreator di Discover sidebar) ===================
function renderSuggestUsers() {
  const wrap = document.querySelector("#suggestUsersList");
  if (!wrap) return;
  let creators = [];
  try {
    creators = (typeof getPlatformCreators === "function" ? getPlatformCreators({ activeOnly: true }) : []) || [];
  } catch { creators = []; }
  // Sort by videoCount/views — kreator yg lebih aktif rank atas; ambil 20 teratas (sisanya bisa di-scroll)
  creators.sort((a, b) => (b.videos || b.videoCount || 0) - (a.videos || a.videoCount || 0));
  const top = creators.slice(0, 20);
  const following = (state?.followingCreators || []).map(x => String(x).toLowerCase());

  if (top.length === 0) {
    wrap.innerHTML = `
      <div class="suggest-empty">
        <div class="suggest-empty-icon">👥</div>
        <p>Belum ada kreator lain</p>
        <small>Kreator akan muncul di sini setelah ada user yang upload video.</small>
      </div>`;
    return;
  }

  const FRESH_WINDOW_MS = 24 * 60 * 60 * 1000;
  const now = Date.now();
  wrap.innerHTML = top.map(c => {
    const uname = String(c.name || c.username || "").toLowerCase();
    const display = c.displayName || c.name || c.username || "Kreator";
    const init = (display.split(/\s+/).map(s => s[0]).slice(0, 2).join("") || "U").toUpperCase();
    const isFollowing = following.includes(uname);
    const videoCount = c.videos || c.videoCount || 0;
    // Fresh ring — kreator yang upload < 24 jam dapat ring gradient (Instagram-style).
    const isFresh = c.latestUploadAt && (now - c.latestUploadAt) < FRESH_WINDOW_MS;
    const avatarCls = `suggest-avatar${isFresh ? " fresh" : ""}`;
    return `<div class="suggest-item" data-suggest-uname="${escapeHtml(uname)}">
      <div class="${avatarCls}"${isFresh ? ' title="Baru upload — &lt; 24 jam"' : ""}>${c.avatar ? `<img src="${escapeHtml(c.avatar)}" alt=""/>` : `<span>${escapeHtml(init)}</span>`}</div>
      <div class="suggest-info">
        <strong>${escapeHtml(display)}</strong>
        <small>@${escapeHtml(uname)} · ${videoCount} video</small>
      </div>
      <button class="btn ${isFollowing ? "ghost" : "primary"} sm" data-suggest-action="follow" type="button">
        ${isFollowing ? "✓ Following" : "+ Follow"}
      </button>
    </div>`;
  }).join("");

  wrap.querySelectorAll(".suggest-item").forEach(item => {
    const uname = item.dataset.suggestUname;
    // Klik area card (selain tombol follow) → buka profil kreator
    item.addEventListener("click", e => {
      if (e.target.closest("[data-suggest-action]")) return;
      if (typeof openUserProfile === "function") openUserProfile(uname);
      else { switchView("user-profile"); }
    });
    // Tombol follow
    const followBtn = item.querySelector('[data-suggest-action="follow"]');
    followBtn?.addEventListener("click", e => {
      e.stopPropagation();
      if (!Array.isArray(state.followingCreators)) state.followingCreators = [];
      const idx = state.followingCreators.findIndex(x => String(x).toLowerCase() === uname);
      if (idx >= 0) {
        state.followingCreators.splice(idx, 1);
        toast(`Berhenti follow <b>@${escapeHtml(uname)}</b>`, "info");
      } else {
        state.followingCreators.push(uname);
        toast(`✓ Follow <b>@${escapeHtml(uname)}</b>`, "success");
      }
      saveState();
      renderSuggestUsers();
      if (typeof renderUserStats === "function") renderUserStats();
    });
  });
}

// Wire button "Follow Semua" di Sarankan Kreator card — follow semua kreator yg ditampilkan
document.addEventListener("click", e => {
  const btn = e.target.closest("#suggestFollowAll");
  if (!btn) return;
  e.preventDefault();
  const items = document.querySelectorAll("#suggestUsersList .suggest-item");
  if (!items.length) return;
  if (!Array.isArray(state.followingCreators)) state.followingCreators = [];
  let added = 0;
  items.forEach(it => {
    const uname = (it.dataset.suggestUname || "").toLowerCase();
    if (!uname) return;
    if (!state.followingCreators.some(x => String(x).toLowerCase() === uname)) {
      state.followingCreators.push(uname);
      added++;
    }
  });
  if (added > 0) {
    saveState();
    renderSuggestUsers();
    if (typeof renderUserStats === "function") renderUserStats();
    toast(`✓ Follow <b>${added}</b> kreator sekaligus`, "success");
  } else {
    toast("Sudah follow semua kreator yang disarankan", "info");
  }
});

// "Lihat semua →" di Trending card — buka X.com search top trending hari ini
document.addEventListener("click", e => {
  const link = e.target.closest("[data-trending-more]");
  if (!link) return;
  e.preventDefault();
  window.open("https://x.com/explore/tabs/trending", "_blank", "noopener");
});



// Spotlight Kreator — carousel asli (avatar + nama + stats per slide).
// cs-thumb (kolom card preview video) DIHILANGKAN per request user, sisanya
// tetap pakai carousel layout dengan dots + nav buttons.
function renderCreatorSpotlight() {
  const stage = $("#creatorSpotlight");
  const track = $("#csTrack");
  const dots = $("#csDots");
  const current = $("#csCurrent");
  const total = $("#csTotal");
  if (!stage || !track) return;

  const creators = getPlatformCreators({ activeOnly: true }).map(c => {
    const stateRaw = localStorage.getItem(`playly-state-${c.name}`);
    let videos = [];
    try { videos = JSON.parse(stateRaw)?.myVideos || []; } catch {}
    // Filter hanya video yang sudah published (sama dengan getPlatformVideos)
    const publishedVideos = videos.filter(v => !v.adminStatus || v.adminStatus === "published");
    const totalViews = publishedVideos.reduce((s, v) => s + (v.viewsNum || 0), 0);
    const totalLikes = publishedVideos.reduce((s, v) => s + (v.likes || 0), 0);
    const followers = (typeof getUserFollowers === "function" ? getUserFollowers(c.name).length : 0);
    // Top 3 video kreator ini berdasarkan views
    const topVideos = [...publishedVideos]
      .sort((a, b) => (b.viewsNum || 0) - (a.viewsNum || 0))
      .slice(0, 3);
    let avatar = null;
    try {
      for (let i = 0; i < localStorage.length; i++) {
        const k = localStorage.key(i);
        if (!k || !k.startsWith("playly-account-")) continue;
        const a = JSON.parse(localStorage.getItem(k));
        if (a?.username && String(a.username).toLowerCase() === String(c.name).toLowerCase()) {
          avatar = a.avatar || null;
          break;
        }
      }
    } catch {}
    return { ...c, totalViews, totalLikes, followers, avatar, topVideos };
  }).sort((a, b) => b.totalViews - a.totalViews).slice(0, 5);

  csState.list = creators;
  csState.idx = 0;

  if (!creators.length) {
    track.innerHTML = `<div class="cs-empty">🌟 Belum ada kreator aktif. Jadilah yang pertama upload video!</div>`;
    if (dots) dots.innerHTML = "";
    if (current) current.textContent = "0";
    if (total) total.textContent = "0";
    csStopAutoplay();
    return;
  }

  if (current) current.textContent = "1";
  if (total) total.textContent = String(creators.length);

  // Slide: avatar + info + stats di atas, plus row "Top Videos" di bawah.
  track.innerHTML = creators.map(c => {
    const initials = (c.displayName || c.name || "?").split(/\s+/).map(p => p[0]).slice(0, 2).join("").toUpperCase();
    const avatarInner = c.avatar
      ? `<img src="${c.avatar}" alt=""/>`
      : `<span>${escapeHtml(initials)}</span>`;

    const topVidsHtml = (c.topVideos && c.topVideos.length)
      ? `<div class="cs-top-videos">
          <div class="cs-top-videos-label">${t("spotlight.topvideos")}</div>
          <div class="cs-top-videos-row">
            ${c.topVideos.map(v => `
              <button type="button" class="cs-top-vid" data-vid="${v.id}" title="${escapeHtml(v.title || "")}">
                <div class="cs-top-vid-thumb" ${v.thumb ? `style="background-image:url('${v.thumb}')"` : ""}>
                  ${v.duration ? `<span class="cs-top-vid-dur">${v.duration}</span>` : ""}
                  <span class="cs-top-vid-play">▶</span>
                </div>
                <div class="cs-top-vid-meta">
                  <strong>${escapeHtml(v.title || "Untitled")}</strong>
                  <small>${fmtNum(v.viewsNum || 0)} views</small>
                </div>
              </button>
            `).join("")}
          </div>
        </div>`
      : "";

    return `
      <div class="cs-slide cs-slide-no-thumb" data-creator="${escapeHtml(c.name)}">
        <div class="cs-slide-head">
          <div class="cs-avatar">${avatarInner}</div>
          <div class="cs-info">
            <h4>${escapeHtml(c.displayName || c.name)}</h4>
            <div class="uname">@${escapeHtml(c.name)}</div>
            <div class="stats">
              <span><b>${fmtNum(c.videoCount)}</b>${t("spotlight.video")}</span>
              <span><b>${fmtNum(c.totalViews)}</b>${t("spotlight.views")}</span>
              <span><b>${fmtNum(c.followers)}</b>${t("spotlight.followers")}</span>
              <span><b>${fmtNum(c.totalLikes)}</b>${t("spotlight.likes")}</span>
            </div>
          </div>
        </div>
        ${topVidsHtml}
      </div>
    `;
  }).join("");

  if (dots) {
    dots.innerHTML = creators.map((_, i) =>
      `<button class="cs-dot ${i === 0 ? "active" : ""}" data-cs-dot="${i}" aria-label="Slide ${i + 1}"></button>`
    ).join("");
    dots.querySelectorAll("[data-cs-dot]").forEach(d => {
      d.addEventListener("click", () => { csGoTo(parseInt(d.dataset.csDot)); csStartAutoplay(); });
    });
  }

  // Slide click → buka profil kreator. Klik thumbnail video → langsung play.
  track.querySelectorAll(".cs-top-vid").forEach(b => {
    b.addEventListener("click", e => {
      e.stopPropagation();
      const vid = +b.dataset.vid;
      if (vid && typeof openPlayer === "function") openPlayer(vid);
    });
  });
  track.querySelectorAll(".cs-slide").forEach(s => {
    // Bind klik di area head (avatar+info), bukan area top-videos
    const head = s.querySelector(".cs-slide-head");
    (head || s).addEventListener("click", () => {
      const cname = s.dataset.creator;
      if (cname && typeof openUserProfile === "function") openUserProfile(cname);
    });
  });

  csGoTo(0);
  csStartAutoplay();
}

function csGoTo(idx) {
  const track = $("#csTrack");
  const current = $("#csCurrent");
  if (!track || !csState.list.length) return;
  csState.idx = ((idx % csState.list.length) + csState.list.length) % csState.list.length;
  track.style.transform = `translateX(-${csState.idx * 100}%)`;
  if (current) current.textContent = String(csState.idx + 1);
  $$(".cs-dot").forEach((d, i) => d.classList.toggle("active", i === csState.idx));
}

function csStartAutoplay() {
  csStopAutoplay();
  if (csState.list.length < 2) return;
  csState.timer = setInterval(() => csGoTo(csState.idx + 1), 5000);
}
function csStopAutoplay() {
  if (csState.timer) { clearInterval(csState.timer); csState.timer = null; }
}

function bindCreatorSpotlight() {
  const prev = $("#csPrev"), next = $("#csNext"), wrap = $("#creatorSpotlight");
  if (prev && !prev.dataset.bound) {
    prev.dataset.bound = "1";
    prev.addEventListener("click", () => { csGoTo(csState.idx - 1); csStartAutoplay(); });
  }
  if (next && !next.dataset.bound) {
    next.dataset.bound = "1";
    next.addEventListener("click", () => { csGoTo(csState.idx + 1); csStartAutoplay(); });
  }
  if (wrap && !wrap.dataset.bound) {
    wrap.dataset.bound = "1";
    wrap.addEventListener("mouseenter", csStopAutoplay);
    wrap.addEventListener("mouseleave", csStartAutoplay);
  }
}

// Auto-bind static handler saat DOM siap
bindQuickActions();
bindCreatorSpotlight();

function renderCreators() {
  const list = $("#creatorList");
  if (!list) return;
  // Home "Online Sekarang" — hanya kreator aktif (sudah upload minimal 1 video)
  const creators = getPlatformCreators({ activeOnly: true });
  const onlinePill = list.parentElement.querySelector(".online-pill");

  if (!creators.length) {
    list.innerHTML = `<div style="text-align:center; padding:24px 12px; color:var(--muted); font-size:12.5px">
      <div style="font-size:32px; opacity:.5; margin-bottom:6px">👥</div>
      Belum ada kreator aktif.<br/>Cek <b style="color:var(--primary); cursor:pointer" data-jump="discover">Discover</b> untuk eksplor.
    </div>`;
    if (onlinePill) onlinePill.style.display = "none";
    return;
  }
  if (onlinePill) {
    onlinePill.style.display = "";
    onlinePill.innerHTML = `<i></i> ${creators.filter(c => c.online).length} online`;
  }
  list.innerHTML = creators.slice(0, 6).map(c => `
    <div class="creator-item">
      <div class="avatar">
        <span>${c.init}</span>
        ${c.online ? '<i class="status"></i>' : ''}
      </div>
      <div class="info">
        <strong>@${c.name}</strong>
        <small>${c.subs}</small>
      </div>
      <button class="follow-btn ${state.followingCreators.includes(c.name) ? 'following' : ''}" data-follow="${c.name}">
        ${state.followingCreators.includes(c.name) ? '✓' : '+ Follow'}
      </button>
    </div>
  `).join("");
  $$("[data-follow]", list).forEach(b => b.addEventListener("click", () => toggleFollow(b.dataset.follow)));
}

function toggleFollow(name) {
  const wasFollowing = state.followingCreators.includes(name);
  if (wasFollowing) {
    state.followingCreators = state.followingCreators.filter(x => x !== name);
    toast(`Berhenti mengikuti <b>@${name}</b>`);
  } else {
    state.followingCreators.push(name);
    toast(`✓ Mengikuti <b>@${name}</b>`, "success");
    state.activities.unshift({ type: "follow", text: `You started following <b>@${name}</b>`, time: "just now", icon: "👤", ts: Date.now() });
  }
  saveState();
  // Untuk akun real (terdaftar di platform): mirror relasi ke followers user lain.
  if (findAccountByUsername(name)) {
    setFollowerOnOtherUser(name, !wasFollowing);
    if (!wasFollowing) {
      const initials = (user?.name || user?.username || "U").split(/\s+/).map(p => p[0]).slice(0, 2).join("").toUpperCase();
      deliverNotification(name, {
        type: "follow",
        init: initials,
        fromUsername: user.username,
        text: `<b>@${user.username}</b> started following you 👤`
      });
    }
  }
  renderCreators();
  renderDiscoverCreators();
  renderHomeTrending();
  renderHomeStats();
  renderHomeActivity();
  renderActivityList();
  renderUserStats();
  refreshHeroGreeting();
  if (state.currentView === "people") renderPeople();
  if (state.currentView === "user-profile") renderUserProfile();
}

// Tulis/hapus current user di array followers user lain (cross-storage).
// Hanya dipanggil untuk akun real — supaya tidak bikin record state hantu.
function setFollowerOnOtherUser(otherUsername, follow) {
  if (!otherUsername || !user) return;
  const key = `playly-state-${otherUsername}`;
  let s;
  try { s = JSON.parse(localStorage.getItem(key)); } catch { s = null; }
  if (!s) s = {};
  if (!Array.isArray(s.followers)) s.followers = [];
  const me = user.username;
  const has = s.followers.includes(me);
  if (follow && !has) s.followers.push(me);
  if (!follow && has) s.followers = s.followers.filter(x => x !== me);
  try { localStorage.setItem(key, JSON.stringify(s)); } catch {}
  // Sinkron dengan state in-memory kalau kebetulan login sebagai user itu (jarang).
  if (user.username === otherUsername && Array.isArray(state?.followers)) {
    state.followers = s.followers;
  }
}

// Daftar followers user mana pun (pakai state in-memory kalau itu user login).
function getUserFollowers(username) {
  if (!username) return [];
  if (user && user.username === username) return Array.isArray(state?.followers) ? state.followers.slice() : [];
  try {
    const s = JSON.parse(localStorage.getItem(`playly-state-${username}`));
    return Array.isArray(s?.followers) ? s.followers : [];
  } catch { return []; }
}

// Daftar kreator yang diikuti user mana pun.
function getUserFollowing(username) {
  if (!username) return [];
  if (user && user.username === username) return Array.isArray(state?.followingCreators) ? state.followingCreators.slice() : [];
  try {
    const s = JSON.parse(localStorage.getItem(`playly-state-${username}`));
    return Array.isArray(s?.followingCreators) ? s.followingCreators : [];
  } catch { return []; }
}

function renderFeatured() {
  const slot = $("#featuredVideo");
  const card = $("#featuredCard");
  if (!slot || !card) return;

  // Priority 1: video terbaru user sendiri (myVideos sudah unshift saat upload, jadi [0] = terbaru)
  // Priority 2: kalau user belum upload, fallback ke video terpopuler platform
  const ownLatest = state?.myVideos?.[0];
  const platform = getPlatformVideos();
  const v = ownLatest || platform[0];

  // Card SELALU muncul — kalau tidak ada video, tampilkan empty state biar user
  // tahu lokasi tile-nya & ada CTA upload.
  card.style.display = "";

  const heading = card.querySelector(".card-head h3");

  if (!v) {
    if (heading) heading.textContent = "⭐ Video Terbaru Saya";
    slot.innerHTML = `
      <div class="featured-empty">
        <div class="featured-empty-icon">🎬</div>
        <h4>Belum ada video</h4>
        <p>Upload video pertamamu untuk muncul di sini sebagai sorotan utama.</p>
        <button class="btn primary small" data-jump="upload">📤 Upload Sekarang</button>
      </div>
    `;
    return;
  }

  // Update heading sesuai konteks (own = "Video Terbaru Saya", platform = "Featured")
  if (heading) heading.textContent = ownLatest ? "⭐ Video Terbaru Saya" : "⭐ Featured";

  // Real-time relative timestamp
  const ts = v.createdAt || (typeof v.id === "number" && v.id > 1e12 ? v.id : null);
  const timeText = ts ? relTime(ts) : (v.time || "");
  const viewsText = v.views ? `${v.views} views` : (typeof v.viewsNum === "number" ? `${fmtNum(v.viewsNum)} views` : "");
  // Badge "Baru" / "Trending" untuk visual distinction
  const badgeText = ownLatest ? "🆕 Video Baru" : "🔥 Trending";

  slot.innerHTML = `
    <div class="featured-video">
      <div class="thumb">
        <img src="${v.thumb}" alt="${escapeHtml(v.title)}"/>
        <span class="featured-badge">${badgeText}</span>
        <div class="thumb-overlay">
          <button class="play-btn" data-feat-vid="${v.id}"><svg viewBox="0 0 24 24" fill="currentColor"><path d="M8 5v14l11-7z"/></svg></button>
          <span class="duration">${escapeHtml(v.duration || "0:00")}</span>
        </div>
      </div>
      <div class="featured-info">
        <h4>${escapeHtml(v.title)}</h4>
        <p><b>@${escapeHtml(v.creator)}</b>${viewsText ? " • " + viewsText : ""}${timeText ? " • " + escapeHtml(timeText) : ""}</p>
      </div>
    </div>
  `;
  slot.querySelector("[data-feat-vid]")?.addEventListener("click", e => {
    e.stopPropagation();
    openPlayer(+e.currentTarget.dataset.featVid);
  });
}

// ----------------------- VIDEOS VIEW -----------------------
function syncVideoTabCounts() {
  const all = state.myVideos?.length || 0;
  const up = state.uploadingVideos?.length || 0;
  const tr = state.deletedVideos?.length || 0;
  const setT = (id, n) => { const el = $("#" + id); if (el) el.textContent = n; };
  setT("chipCountAll", all);
  setT("chipCountUploading", up);
  setT("chipCountTrash", tr);
}

function renderVideoGrid() {
  const grid = $("#videoGrid");
  if (!grid) return;
  syncVideoTabCounts();

  // Sembunyikan dropdown "Sort" untuk tab non-Semua (tidak relevan)
  const sortEl = $("#videoSort");
  if (sortEl) sortEl.style.visibility = state.filter === "all" ? "" : "hidden";

  if (state.filter === "uploading") return renderUploadingList(grid);
  if (state.filter === "trash") return renderTrashList(grid);

  // Default: Semua
  grid.classList.remove("trash-grid");
  let list = [...state.myVideos];
  if (state.videoSort === "views") list.sort((a, b) => (b.viewsNum || 0) - (a.viewsNum || 0));
  else if (state.videoSort === "likes") list.sort((a, b) => (b.likes || 0) - (a.likes || 0));

  if (!list.length) {
    grid.innerHTML = emptyHTML("🎬", "Belum ada video",
      "Upload video pertamamu untuk mulai berbagi kreasi ke seluruh dunia.",
      "📤 Upload Video Pertama", "upload");
  } else {
    grid.innerHTML = list.map(videoCardHTML).join("");
    bindVideoCards(grid);
    // Bind delete buttons di tiap card
    $$("[data-delete-vid]", grid).forEach(b => b.addEventListener("click", e => {
      e.stopPropagation();
      moveVideoToTrash(+b.dataset.deleteVid);
    }));
  }
}

function renderUploadingList(grid) {
  grid.classList.add("trash-grid");
  const list = state.uploadingVideos || [];
  if (!list.length) {
    grid.innerHTML = emptyHTML("⏳", "Tidak ada upload aktif",
      "Video yang sedang diunggah akan muncul di sini dengan progress real-time.",
      "📤 Upload Sekarang", "upload");
    return;
  }
  grid.innerHTML = `<div style="display:flex; flex-direction:column; gap:10px">${list.map(uploadCardHTML).join("")}</div>`;
  $$("[data-cancel-up]", grid).forEach(b => b.addEventListener("click", () => {
    cancelUpload(b.dataset.cancelUp);
  }));
}

function renderTrashList(grid) {
  grid.classList.add("trash-grid");
  const list = state.deletedVideos || [];
  if (!list.length) {
    grid.innerHTML = emptyHTML("🗑️", "Sampah kosong",
      "Video yang kamu hapus akan muncul di sini. Bisa dipulihkan kapan saja.",
      "", "");
    return;
  }
  grid.innerHTML = `<div style="display:flex; flex-direction:column; gap:10px">${list.map(trashCardHTML).join("")}</div>`;
  $$("[data-restore]", grid).forEach(b => b.addEventListener("click", () => restoreVideo(+b.dataset.restore)));
  $$("[data-delete-perm]", grid).forEach(b => b.addEventListener("click", () => permaDeleteVideo(+b.dataset.deletePerm)));
}

function uploadCardHTML(u) {
  const pct = Math.floor(u.progress || 0);
  const totalSize = u.size ? fmtBytes(u.size) : "";
  const uploadedSize = (u.size && u.progress) ? fmtBytes(Math.floor(u.size * (u.progress / 100))) : "";
  const sizeText = u.size
    ? (u.status === "done"
      ? totalSize
      : `${uploadedSize} / ${totalSize}`)
    : "";
  return `
    <div class="upload-progress-card" data-up="${u.id}">
      <div class="thumb-mini">${u.thumb ? `<img src="${u.thumb}" alt=""/>` : ""}</div>
      <div class="info">
        <strong>${escapeHtml(u.title)}</strong>
        <small>${u.status === "done" ? `✓ Selesai${totalSize ? ` · ${totalSize}` : ""}` : `Mengunggah... ${pct}%${sizeText ? ` · ${sizeText}` : ""}`}</small>
        <div class="progress-bar"><i style="width:${pct}%"></i></div>
      </div>
      ${u.status === "uploading" ? `<button class="btn ghost" data-cancel-up="${u.id}">Batal</button>` : ""}
    </div>
  `;
}

function trashCardHTML(v) {
  const ago = v.deletedAt ? relTime(v.deletedAt) : "—";
  return `
    <div class="trash-card" data-vid="${v.id}">
      <div class="thumb-mini"><img src="${v.thumb}" alt=""/></div>
      <div class="info">
        <strong>${escapeHtml(v.title)}</strong>
        <small>Dihapus ${ago} • ${v.duration || "0:00"}</small>
      </div>
      <div class="actions">
        <button class="btn primary" data-restore="${v.id}">↺ Pulihkan</button>
        <button class="btn ghost" data-delete-perm="${v.id}" title="Hapus permanen">🗑️</button>
      </div>
    </div>
  `;
}

// ----------------------- DELETE / RESTORE / PERMA-DELETE -----------------------
function moveVideoToTrash(id) {
  const idx = state.myVideos.findIndex(v => v.id === id);
  if (idx < 0) return;
  const [v] = state.myVideos.splice(idx, 1);
  v.deletedAt = Date.now();
  state.deletedVideos = state.deletedVideos || [];
  state.deletedVideos.unshift(v);
  saveState();
  refreshAllVideoGrids();
  renderUserStats();
  toast(`🗑️ <b>${escapeHtml(v.title)}</b> dipindah ke Sampah`, "warning");
}

function restoreVideo(id) {
  const idx = state.deletedVideos.findIndex(v => v.id === id);
  if (idx < 0) return;
  const [v] = state.deletedVideos.splice(idx, 1);
  delete v.deletedAt;
  state.myVideos.unshift(v);
  saveState();
  refreshAllVideoGrids();
  renderUserStats();
  toast(`✓ <b>${escapeHtml(v.title)}</b> berhasil dipulihkan`, "success");
}

function permaDeleteVideo(id) {
  const idx = state.deletedVideos.findIndex(v => v.id === id);
  if (idx < 0) return;
  const v = state.deletedVideos[idx];
  openConfirm({
    icon: "🗑️", iconClass: "danger",
    title: "Delete Permanently?",
    desc: `Video <b>${escapeHtml(v.title)}</b> akan dihapus secara permanen dan tidak bisa dipulihkan.`,
    btnText: "Delete Permanently", btnClass: "danger",
    onConfirm: () => {
      state.deletedVideos.splice(idx, 1);
      saveState();
      // Hapus juga file aslinya dari IndexedDB
      try {
        openVideoDB().then(db => {
          const tx = db.transaction(VIDEO_STORE, "readwrite");
          tx.objectStore(VIDEO_STORE).delete(id);
          tx.oncomplete = () => refreshStorageUsage();
        });
      } catch {}
      refreshAllVideoGrids();
      toast(`🗑️ Video dihapus permanen`, "error");
    }
  });
}

function cancelUpload(uid) {
  state.uploadingVideos = (state.uploadingVideos || []).filter(u => u.id !== uid);
  // tandai supaya tick loop di startUpload berhenti
  if (window.__activeUploads) delete window.__activeUploads[uid];
  saveState();
  renderVideoGrid();
  toast("Upload dibatalkan", "warning");
}

$("#videoSort")?.addEventListener("change", e => { state.videoSort = e.target.value; renderVideoGrid(); });
$$("#filterTabs button").forEach(b => {
  b.addEventListener("click", () => {
    $$("#filterTabs button").forEach(x => x.classList.remove("active"));
    b.classList.add("active");
    state.filter = b.dataset.filter;
    renderVideoGrid();
  });
});

// ----------------------- MY LIBRARY VIEW (videos) -----------------------
// Render 3 koleksi: My Video (upload sendiri), New Videos (terbaru dari kreator
// lain), Download (yang sudah ditandai diunduh). Click → buka player video.
function renderMyLibrary() {
  const renderCard = (v, opts = {}) => {
    const id = v.id;
    const title = escapeHtml(v.title || "Video");
    const thumb = v.thumb || v.thumbnail || "";
    const creator = escapeHtml(v.creator || v.uploader || "—");
    const views = v.viewsNum != null ? fmtNum(v.viewsNum) : (v.views || "0");
    const duration = v.duration || "";
    const thumbBg = thumb ? `style="background-image:url('${thumb}')"` : "";
    // Status badge — hanya ditampilkan untuk video user sendiri (My Video)
    let statusBadge = "";
    if (opts.showStatus) {
      const st = v.adminStatus || "published";
      const map = {
        pending:   { label: "⏳ Pending Review", cls: "warn" },
        published: { label: "✓ Published",       cls: "ok" },
        rejected:  { label: "✕ Rejected",        cls: "bad" },
        takedown:  { label: "⛔ Takedown",        cls: "bad" },
      };
      const m = map[st];
      if (m && st !== "published") {
        statusBadge = `<span class="lib-thumb-status ${m.cls}">${m.label}</span>`;
      }
    }
    // Action buttons — kebab menu (Edit / Draft / Hapus) untuk My Videos +
    // pending/takedown; restore + perma-delete (Sampah) tetap pakai inline btns.
    let actionsHtml = "";
    let menuHtml = "";
    if (opts.canDelete) {
      // Kebab menu — single button di pojok kanan atas thumbnail, popup .lib-card-menu di luar thumb
      actionsHtml = `<div class="lib-card-actions">
        <button type="button" class="lib-card-kebab" data-lib-kebab="${id}" title="Opsi video" aria-label="Opsi video" aria-haspopup="menu" aria-expanded="false">
          <svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><circle cx="12" cy="5" r="2"/><circle cx="12" cy="12" r="2"/><circle cx="12" cy="19" r="2"/></svg>
        </button>
      </div>`;
      menuHtml = `<div class="lib-card-menu" data-lib-menu-for="${id}" hidden role="menu" aria-label="Opsi video">
        <button type="button" class="lcm-item" data-lib-edit="${id}" role="menuitem">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4 12.5-12.5z"/></svg>
          <span>Edit</span>
        </button>
        <button type="button" class="lcm-item" data-lib-draft="${id}" role="menuitem">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>
          <span>Simpan ke Draft</span>
        </button>
        <button type="button" class="lcm-item lcm-danger" data-lib-delete="${id}" role="menuitem">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/><path d="M10 11v6M14 11v6"/><path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"/></svg>
          <span>Hapus</span>
        </button>
      </div>`;
    } else if (opts.canRestore) {
      const restoreActions = [
        `<button type="button" class="lib-card-action lib-action-restore" data-lib-restore="${id}" title="Pulihkan video">↺</button>`,
        `<button type="button" class="lib-card-action lib-action-perma" data-lib-perma="${id}" title="Hapus permanen">🗑️</button>`
      ];
      actionsHtml = `<div class="lib-card-actions">${restoreActions.join("")}</div>`;
    }
    return `<div class="lib-item" data-vid="${id}">
      <div class="lib-thumb" ${thumbBg}>
        ${thumb ? "" : "<span class='lib-thumb-fallback'>🎬</span>"}
        ${duration ? `<span class="lib-thumb-dur">${duration}</span>` : ""}
        ${statusBadge}
        ${actionsHtml}
      </div>
      ${menuHtml}
      <div class="lib-meta">
        <strong title="${title}">${title}</strong>
        <small>@${creator} · ${views} views</small>
      </div>
    </div>`;
  };
  const emptyMsg = (icon, msg) => `<div class="lib-empty"><div class="lib-empty-icon">${icon}</div><p>${msg}</p></div>`;

  // Render satu lib section: full grid besar selalu ditampilkan (no preview /
  // no collapse). Tile size konsisten di semua state. Klik tile → openPlayer.
  function renderLibSection(list, gridId, countId, emptyIcon, emptyMsgHtml, opts = {}) {
    const gridEl = $(`#${gridId}`);
    const countEl = $(`#${countId}`);
    if (countEl) countEl.textContent = list.length;
    if (!gridEl) return;
    if (!list.length) {
      gridEl.innerHTML = `<div class="lib-empty"><div class="lib-empty-icon">${emptyIcon}</div><p>${emptyMsgHtml}</p></div>`;
      return;
    }
    gridEl.innerHTML = list.map(v => renderCard(v, opts)).join("");
  }

  // Pisahkan video user berdasarkan status admin:
  //   - My Videos = sudah published (live di platform) — bisa di-delete
  //   - Status Videos = pending / takedown (belum live) + sampah (state.deletedVideos)
  const allMyVideos = Array.isArray(state?.myVideos) ? [...state.myVideos] : [];
  allMyVideos.sort((a, b) => (b.id || 0) - (a.id || 0));
  const isPublished = v => !v.adminStatus || v.adminStatus === "published";
  const myVideos = allMyVideos.filter(isPublished);
  const pendingVideos = allMyVideos.filter(v => v.adminStatus === "pending");
  const takedownVideos = allMyVideos.filter(v => v.adminStatus === "takedown" || v.adminStatus === "rejected");
  const draftVideos = allMyVideos.filter(v => v.adminStatus === "draft");
  const trashVideos = Array.isArray(state?.deletedVideos) ? [...state.deletedVideos] : [];
  const allStatusList = [...pendingVideos, ...takedownVideos, ...trashVideos];

  // Ikon empty-state minimalis monokrom (per request user 2026-05-16, bukan
  // emoji warna). SVG string single-quote, NO backtick — di-inject lewat
  // renderLibSection(...).innerHTML template (var emptyIcon).
  const _LS = 'viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"';
  const LIB_FILM  = '<svg ' + _LS + '><rect x="2" y="2" width="20" height="20" rx="2"/><path d="M7 2v20M17 2v20M2 12h20M2 7h5M2 17h5M17 17h5M17 7h5"/></svg>';
  const LIB_CLIP  = '<svg ' + _LS + '><rect x="8" y="2" width="8" height="4" rx="1"/><path d="M16 4h2a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h2"/><path d="M9 12h6M9 16h6"/></svg>';
  const LIB_DRAFT = '<svg ' + _LS + '><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h7"/><polyline points="14 2 14 8 20 8"/><path d="M18.4 12.6a2 2 0 0 1 3 3L17 20l-3 1 1-3Z"/></svg>';
  const LIB_BAN   = '<svg ' + _LS + '><circle cx="12" cy="12" r="9"/><path d="M5.6 5.6l12.8 12.8"/></svg>';
  const LIB_TV    = '<svg ' + _LS + '><rect x="2" y="7" width="20" height="14" rx="2"/><polyline points="8 3 12 7 16 3"/></svg>';
  const LIB_SAVE  = '<svg ' + _LS + '><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2Z"/><polyline points="17 21 17 13 7 13 7 21"/><polyline points="7 3 7 8 15 8"/></svg>';

  // 1. My Videos — hanya yang sudah disetujui admin (+ delete button)
  renderLibSection(myVideos, "myVideoGrid", "myVideoCount", LIB_FILM,
    "No videos are live yet. <a href='#' data-jump='upload' style='color:var(--primary)'>Upload now</a>",
    { showStatus: true, canDelete: true });

  // 2. Status Videos — render section sesuai sub-tab aktif.
  // Tabs: Published (semua) | Trash (user-deleted) | Takedown (admin-takedown).
  // Sanitize legacy "pending" subTab.
  if (state.statusSubTab === "pending") {
    state.statusSubTab = "all";
  }
  state.statusSubTab = state.statusSubTab || "all";
  const subTab = state.statusSubTab;
  // BUG fix 2026-05-10: dulu sub-tab "all" merge trashVideos juga → user delete
  // video, video tetap muncul di tab Diterbitkan karena trashVideos masih dihitung.
  // Sekarang trashVideos cuma muncul di tab Sampah; "all" = pending + takedown.
  const subTabMap = {
    all:      { list: [...pendingVideos, ...takedownVideos],
                empty: "No videos in status." },
    draft:    { list: draftVideos,
                empty: "Belum ada draft. Simpan video ke Draft via menu titik tiga di setiap card." },
    trash:    { list: trashVideos,
                empty: "Trash kosong — video yang kamu hapus sendiri akan muncul di sini." },
    takedown: { list: takedownVideos,
                empty: "Belum ada video yang di-takedown admin." },
  };
  const cur = subTabMap[subTab] || subTabMap.all;
  // Draft items: show kebab menu (Edit/Delete) supaya user bisa lanjut edit / hapus draft
  const allowKebab = subTab === "draft" || subTab === "all";
  renderLibSection(cur.list, "statusVideoGrid", "statusVideoCount",
    subTab === "takedown" ? LIB_BAN : subTab === "draft" ? LIB_DRAFT : LIB_CLIP,
    cur.empty,
    { showStatus: true, canRestore: subTab === "trash", canDelete: allowKebab });
  // Update sub-tab counters
  const setT = (id, n) => { const el = document.getElementById(id); if (el) el.textContent = n; };
  setT("statusCntAll",      subTabMap.all.list.length);
  setT("statusCntDraft",    draftVideos.length);
  setT("statusCntTrash",    trashVideos.length);
  setT("statusCntTakedown", takedownVideos.length);
  // Sync active state pada sub-tab buttons
  document.querySelectorAll(".status-sub-tab").forEach(b => {
    b.classList.toggle("active", b.dataset.statusTab === subTab);
  });

  // New Videos dipindah ke Discover — lihat renderDiscoverNewVideos()
  const myIds = new Set(allMyVideos.map(v => v.id));
  const platform = (typeof getPlatformVideos === "function" ? getPlatformVideos() : [])
    .filter(v => !myIds.has(v.id));

  // 3. Download — split jadi 2 section: Dashboard (offline-in-app) & File (to device).
  // Filter: video user sendiri TIDAK boleh muncul di download — user hanya bisa
  // download video kreator lain (per request user).
  const downloads = Array.isArray(state?.downloaded) ? state.downloaded : [];
  const myIdSet = new Set(allMyVideos.map(v => v.id));
  const allLookup = new Map();
  [...allMyVideos, ...platform].forEach(v => allLookup.set(v.id, v));

  const resolveEntry = (d) => {
    const v = allLookup.get(d?.videoId);
    if (!v) return null;
    if (myIdSet.has(v.id)) return null; // skip video sendiri
    return { v, kind: d?.kind || (d?.fileSaved ? "file" : "dashboard") };
  };
  const resolved = downloads.map(resolveEntry).filter(Boolean);
  const dashList = resolved.filter(r => r.kind !== "file").map(r => r.v);
  const fileList = resolved.filter(r => r.kind === "file").map(r => r.v);

  renderLibSection(dashList, "downloadDashboardGrid", "downloadVideoCount", LIB_TV,
    "Belum ada video tersimpan di dashboard. Tonton video kreator lain lalu klik tombol Simpan di player.");
  renderLibSection(fileList, "downloadFileGrid", null, LIB_SAVE,
    "Belum ada video yang di-download ke file. Buka player video kreator lain → klik Download untuk simpan ke perangkat.");

  // Total counter = gabungan dua section
  const totalDlEl = document.getElementById("downloadVideoCount");
  if (totalDlEl) totalDlEl.textContent = (dashList.length + fileList.length);

  // Click handler — klik tile → play video INLINE di atas halaman (tidak
  // navigate ke /watch view, tetap di My Library). Delegasi sekali per view.
  const view = document.querySelector('section.view[data-view="videos"]');
  if (view && !view.__libBound) {
    view.__libBound = true;
    view.addEventListener("click", e => {
      // Tutup player
      if (e.target.closest("#libInlineClose")) {
        closeLibInlinePlayer();
        return;
      }
      // Sub-tab Status switcher
      const subBtn = e.target.closest("[data-status-tab]");
      if (subBtn) {
        state.statusSubTab = subBtn.dataset.statusTab;
        // Tutup player kalau sedang terbuka — supaya tidak "leak" ke tab lain
        closeLibInlinePlayer();
        renderMyLibrary();
        return;
      }
      // Kebab menu button — toggle dropdown menu.
      // KRITIS: `.lib-item` punya transition transform (saat hover translateY)
      // yang bikin parent punya transform stacking context. `position: fixed`
      // di dalam transformed-ancestor jadi anchored ke ancestor itu, bukan
      // viewport — pop-up nyasar. Solusi: pindahin menu ke document.body saat
      // open (escape stacking context), restore ke parent asli saat close.
      const kebabBtn = e.target.closest("[data-lib-kebab]");
      if (kebabBtn) {
        e.stopPropagation();
        e.preventDefault();
        const id = kebabBtn.dataset.libKebab;
        // Tutup semua menu lain dulu (return ke parent asli kalau lagi di body)
        document.querySelectorAll(".lib-card-menu").forEach(m => {
          m.hidden = true;
          if (m._libOrigParent && m.parentElement === document.body) {
            try { m._libOrigParent.insertBefore(m, m._libOrigNextSibling || null); } catch {}
          }
        });
        document.querySelectorAll(".lib-card-kebab").forEach(b => b.setAttribute("aria-expanded", "false"));
        // Cari menu untuk kebab ini — boleh di parent .lib-item atau di body
        let menu = view.querySelector(`.lib-card-menu[data-lib-menu-for="${id}"]`)
                || document.querySelector(`.lib-card-menu[data-lib-menu-for="${id}"]`);
        const wasOpen = false; // udah di-tutup di atas
        if (menu && !wasOpen) {
          // Simpan ref parent asli untuk restore
          if (menu.parentElement !== document.body) {
            menu._libOrigParent = menu.parentElement;
            menu._libOrigNextSibling = menu.nextSibling;
            document.body.appendChild(menu);
          }
          menu.hidden = false;
          kebabBtn.setAttribute("aria-expanded", "true");
          // Posisikan menu pakai fixed coords (sekarang true viewport reference)
          const r = kebabBtn.getBoundingClientRect();
          const sp = (k, v) => menu.style.setProperty(k, v, "important");
          sp("position", "fixed");
          sp("top", `${r.bottom + 6}px`);
          const menuW = menu.offsetWidth || 200;
          let left = r.right - menuW;
          if (left < 8) left = 8;
          if (left + menuW > window.innerWidth - 8) left = window.innerWidth - menuW - 8;
          sp("left", `${left}px`);
          sp("right", "auto");
          sp("bottom", "auto");
          sp("z-index", "9999");
        }
        return;
      }
      // Edit menu item → open edit modal
      const editBtn = e.target.closest("[data-lib-edit]");
      if (editBtn) {
        e.stopPropagation();
        const id = +editBtn.dataset.libEdit;
        view.querySelectorAll(".lib-card-menu").forEach(m => { m.hidden = true; });
        view.querySelectorAll(".lib-card-kebab").forEach(b => b.setAttribute("aria-expanded", "false"));
        if (typeof openVideoEditModal === "function") openVideoEditModal(id);
        return;
      }
      // Draft menu item → set adminStatus="draft" + persist + re-render
      const draftBtn = e.target.closest("[data-lib-draft]");
      if (draftBtn) {
        e.stopPropagation();
        const id = +draftBtn.dataset.libDraft;
        view.querySelectorAll(".lib-card-menu").forEach(m => { m.hidden = true; });
        view.querySelectorAll(".lib-card-kebab").forEach(b => b.setAttribute("aria-expanded", "false"));
        const v = (state.myVideos || []).find(x => x.id === id);
        if (!v) return;
        v.adminStatus = "draft";
        if (typeof saveState === "function") saveState();
        if (typeof toast === "function") toast(`📝 <b>${escapeHtml(v.title || "Video")}</b> disimpan ke Draft`, "success");
        renderMyLibrary();
        return;
      }
      // Delete button — konfirmasi → moveVideoToTrash
      const delBtn = e.target.closest("[data-lib-delete]");
      if (delBtn) {
        e.stopPropagation();
        const id = +delBtn.dataset.libDelete;
        const v = state.myVideos.find(x => x.id === id);
        if (!v) return;
        // Tutup menu lebih dulu
        view.querySelectorAll(".lib-card-menu").forEach(m => { m.hidden = true; });
        view.querySelectorAll(".lib-card-kebab").forEach(b => b.setAttribute("aria-expanded", "false"));
        if (typeof openConfirm === "function") {
          openConfirm({
            icon: "🗑️", iconClass: "danger",
            title: "Hapus Video?",
            desc: `Video <b>${escapeHtml(v.title || "")}</b> akan dipindahkan ke Sampah. Bisa dipulihkan kapan saja dari Status Videos → Sampah.`,
            btnText: "Hapus", btnClass: "danger",
            onConfirm: () => { if (typeof moveVideoToTrash === "function") moveVideoToTrash(id); renderMyLibrary(); }
          });
        } else {
          if (typeof moveVideoToTrash === "function") moveVideoToTrash(id);
          renderMyLibrary();
        }
        return;
      }
      // Restore from trash
      const restoreBtn = e.target.closest("[data-lib-restore]");
      if (restoreBtn) {
        e.stopPropagation();
        const id = +restoreBtn.dataset.libRestore;
        if (typeof restoreVideo === "function") restoreVideo(id);
        renderMyLibrary();
        return;
      }
      // Permanent delete
      const permaBtn = e.target.closest("[data-lib-perma]");
      if (permaBtn) {
        e.stopPropagation();
        const id = +permaBtn.dataset.libPerma;
        if (typeof permaDeleteVideo === "function") permaDeleteVideo(id);
        return;
      }
      const item = e.target.closest(".lib-item");
      if (!item) return;
      const id = Number(item.dataset.vid);
      if (Number.isFinite(id)) {
        // Video harus exist di section yang lagi visible — kalau dipanggil di
        // section yang berbeda (mis. lewat history), filter out.
        if (typeof openLibInlinePlayer === "function") openLibInlinePlayer(id);
      }
    });
  }
}

// Per request user 2026-05-10: custom mini-floating popup DIHAPUS — tidak
// berguna. Saat user pindah view, langsung close inline player. Kalau user mau
// lanjut nonton sambil browse, pakai native PiP via kebab ⋮ → Pop-up (browser
// PiP punya semua kontrol native + bisa di-drag bebas di OS).
window.addEventListener("playly:view-changed", e => {
  const newView = e.detail?.view;
  const wrap = document.getElementById("libInlinePlayer");
  if (!wrap || wrap.hidden) return;
  if (newView !== "videos") {
    if (typeof closeLibInlinePlayer === "function") closeLibInlinePlayer();
  }
});

// Toggle mini-floating mode (pop-up kecil di pojok kanan-bawah, tidak nutup
// dashboard). KRITIS: parent `.view` punya transform dari animation viewIn
// (translateY(0) scale(1)) yang stays setelah animation end → bikin `position:
// fixed` di descendant anchor ke `.view`, BUKAN viewport. Solusi: pindahin
// player ke document.body saat mini-floating aktif (escape transform context),
// restore ke parent asli saat disable.
function toggleLibMiniFloating(enable) {
  const wrap = document.getElementById("libInlinePlayer");
  if (!wrap || wrap.hidden) return;
  if (enable) {
    // Pindah ke body biar position:fixed bener-bener viewport-relative
    if (wrap.parentElement !== document.body) {
      if (!wrap._origParent) {
        wrap._origParent = wrap.parentElement;
        wrap._origNextSibling = wrap.nextSibling;
      }
      document.body.appendChild(wrap);
    }
    // Clear stale inline position styles, lalu restore saved pos kalau ada.
    wrap.style.left = ""; wrap.style.top = "";
    wrap.style.right = ""; wrap.style.bottom = "";
    wrap.classList.add("mini-floating");
    // Restore posisi terakhir per user 2026-05-10au
    // Plus safety clamp: kalau saved pos out-of-viewport (mis. window di-resize
    // atau saved dari device lain), clear saved + fallback ke default pojok kanan-bawah.
    try {
      const raw = localStorage.getItem("playly-mini-pip-pos");
      if (raw) {
        const p = JSON.parse(raw);
        if (p?.left && p?.top) {
          const x = parseFloat(p.left);
          const y = parseFloat(p.top);
          // Estimate width ~320px (CSS default), height ~180px (16:9 of 320)
          const maxX = window.innerWidth - 320;
          const maxY = window.innerHeight - 180;
          if (Number.isFinite(x) && Number.isFinite(y) && x >= 0 && y >= 0 && x <= maxX && y <= maxY) {
            wrap.style.left = p.left;
            wrap.style.top = p.top;
            wrap.style.right = "auto";
            wrap.style.bottom = "auto";
          } else {
            // Out of bounds → clear, biarkan default CSS (right: 20px; bottom: 20px)
            localStorage.removeItem("playly-mini-pip-pos");
          }
        }
      }
    } catch {}
    setupLibMiniDrag();
  } else {
    wrap.classList.remove("mini-floating");
    wrap.style.left = ""; wrap.style.top = "";
    wrap.style.right = ""; wrap.style.bottom = "";
    // Restore ke parent asli kalau lagi di body
    if (wrap._origParent && wrap.parentElement === document.body) {
      try { wrap._origParent.insertBefore(wrap, wrap._origNextSibling || null); } catch {}
      wrap._origParent = null;
      wrap._origNextSibling = null;
    }
  }
}

// Drag handler untuk mini floating player — user bisa pindah-pindah pojok.
let __libDragState = null;
function setupLibMiniDrag() {
  const wrap = document.getElementById("libInlinePlayer");
  if (!wrap || wrap.__dragBound) return;
  wrap.__dragBound = true;

  // Drag state + rAF throttle untuk smooth movement (per request user 2026-05-10:
  // sebelumnya pakai direct style.left/top di pointermove → trigger reflow setiap
  // frame, jadi laggy. Sekarang batched lewat rAF + width cached saat pointerdown
  // supaya gak panggil offsetWidth/offsetHeight tiap move).
  let dragRaf = null;
  let dragX = 0, dragY = 0;
  let dragMaxX = 0, dragMaxY = 0;

  wrap.addEventListener("pointerdown", e => {
    if (!wrap.classList.contains("mini-floating")) return;
    if (e.target.closest(".lib-inline-close")) return;
    if (e.target.closest("video")) return;
    const rect = wrap.getBoundingClientRect();
    __libDragState = {
      offsetX: e.clientX - rect.left,
      offsetY: e.clientY - rect.top,
    };
    // Cache viewport bounds — gak perlu re-measure tiap pointermove
    dragMaxX = window.innerWidth - rect.width;
    dragMaxY = window.innerHeight - rect.height;
    wrap.setPointerCapture(e.pointerId);
    wrap.style.transition = "none";
    wrap.classList.add("is-dragging");
  });
  wrap.addEventListener("pointermove", e => {
    if (!__libDragState) return;
    const x = e.clientX - __libDragState.offsetX;
    const y = e.clientY - __libDragState.offsetY;
    dragX = Math.max(0, Math.min(dragMaxX, x));
    dragY = Math.max(0, Math.min(dragMaxY, y));
    if (dragRaf) return;
    dragRaf = requestAnimationFrame(() => {
      dragRaf = null;
      wrap.style.left = `${dragX}px`;
      wrap.style.top = `${dragY}px`;
      wrap.style.right = "auto";
      wrap.style.bottom = "auto";
    });
  });
  wrap.addEventListener("pointerup", e => {
    if (!__libDragState) return;
    __libDragState = null;
    if (dragRaf) { cancelAnimationFrame(dragRaf); dragRaf = null; }
    try { wrap.releasePointerCapture(e.pointerId); } catch {}
    wrap.style.transition = "";
    wrap.classList.remove("is-dragging");
    // Save posisi terakhir ke localStorage supaya restore saat reload / toggle.
    // Per user 2026-05-10au.
    try {
      if (wrap.style.left && wrap.style.top) {
        localStorage.setItem("playly-mini-pip-pos", JSON.stringify({
          left: wrap.style.left,
          top: wrap.style.top
        }));
      }
    } catch {}
  });
  // Behavior klik mini-floating per request user 2026-05-10:
  //   - SINGLE click area video → kembali ke halaman play video (expand ke inline)
  //   - X close button → close player completely
  // Iklan tidak ada lagi di mini popup (di-skip di applyAdOverlays), jadi
  // single-click gak perlu "hide running text" lagi.
  wrap.addEventListener("click", e => {
    if (!wrap.classList.contains("mini-floating")) return;
    if (e.target.closest(".lib-inline-close")) return;
    if (!(e.target.closest("video") || e.target === wrap || e.target.closest(".lib-inline-screen"))) return;
    e.preventDefault();
    e.stopPropagation();
    // Return ke videos view + expand kembali ke inline player
    if (typeof switchView === "function") switchView("videos");
    toggleLibMiniFloating(false);
  });
}

// ----------------------- HISTORY VIEW -----------------------
// Pagination state — increment per klik "more >" (10 per halaman)
const historyState = { contLimit: 10, riwayatLimit: 10 };

// ===== Riwayat sections (pembelian / pencarian) =====
// Tab switcher: all | aktivitas | pembelian | search-user | search-video
// "all" = tampilkan semua section sekaligus (default saat klik dari sidebar).
function setRiwayatTab(tab) {
  const view = document.querySelector('section.view[data-view="history"]');
  if (!view) return;
  const valid = ["all", "aktivitas", "pembelian", "search-user", "search-video"];
  const key = valid.includes(tab) ? tab : "all";
  view.dataset.riwayatTab = key;
  // Persist
  if (typeof state === "object" && state) state.riwayatTab = key;
  // Update tab button active state
  document.querySelectorAll("[data-riwayat-tab]").forEach(b => {
    if (b.tagName === "BUTTON") {
      b.classList.toggle("active", b.dataset.riwayatTab === key);
    }
  });
  // Update title + description + breadcrumb.
  // v590h (2026-05-27): strip emoji prefix dari title — sekarang ada SVG
  // wine box icon di .lib-header-flex (sibling h2), jadi emoji di text =
  // double icon. Title text-only sekarang.
  const meta = {
    "all":          { title: "Riwayat",                desc: "Semua aktivitas kamu di Playly — dikelompokkan per kategori.", crumb: "Riwayat" },
    "aktivitas":    { title: "Riwayat Aktivitas",      desc: "Semua aktivitas tontonan kamu di Playly.",          crumb: "Riwayat Aktivitas" },
    "pembelian":    { title: "Riwayat Pembelian",      desc: "Transaksi premium, upgrade tier, dan pembelian lain.", crumb: "Riwayat Pembelian" },
    "search-user":  { title: "Riwayat Pencarian User", desc: "Username/nama yang pernah kamu cari.",                 crumb: "Pencarian User" },
    "search-video": { title: "Riwayat Pencarian Video", desc: "Kata kunci video / tag yang pernah kamu cari.",       crumb: "Pencarian Video" },
  }[key];
  const titleEl = document.getElementById("riwayatPageTitle");
  const descEl  = document.getElementById("riwayatPageDesc");
  if (titleEl && meta) titleEl.textContent = meta.title;
  if (descEl  && meta) descEl.textContent  = meta.desc;
  // Update breadcrumb (label active)
  const crumb = document.getElementById("breadcrumb");
  const activeBcLast = crumb?.querySelector("a.active");
  if (activeBcLast && meta) activeBcLast.textContent = meta.crumb;
}

document.addEventListener("click", e => {
  const btn = e.target.closest("button[data-riwayat-tab]");
  if (!btn) return;
  e.preventDefault();
  setRiwayatTab(btn.dataset.riwayatTab);
});

// v590 (2026-05-27): Pustaka Saya tab system — wire data-focus-tab buttons
// ke applyFocus(). Mirror sidebar sub-action focus:X tapi via tab pill di
// page itself. Default tab: my-video (set via HTML data-focus="my-video").
document.addEventListener("click", e => {
  const btn = e.target.closest("button[data-focus-tab]");
  if (!btn) return;
  e.preventDefault();
  const view = btn.closest("section.view");
  if (!view) return;
  const key = btn.dataset.focusTab;
  // Update active state pada semua sibling tabs
  view.querySelectorAll("button[data-focus-tab]").forEach(b => {
    b.classList.toggle("active", b === btn);
  });
  // Apply focus mode (hide non-matching sections)
  if (typeof applyFocus === "function") applyFocus(view, key);
});

// On page load, apply default focus untuk views yang punya data-focus attribute.
// Tanpa ini, semua sections render dulu (terlihat sekejap) sebelum tab JS jalan.
(function applyInitialFocusOnLoad() {
  const run = () => {
    document.querySelectorAll("section.view[data-focus]").forEach(view => {
      const key = view.dataset.focus || "all";
      if (typeof applyFocus === "function") applyFocus(view, key);
    });
  };
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", run, { once: true });
  } else {
    run();
  }
})();

// People tab switch (Semua / Followers / Following) di halaman Pencarian.
// 2026-05-25 req user: tab User/Admin diganti jadi sosial graph Followers/
// Following — lebih relevan untuk user biasa daripada role filter.
document.addEventListener("click", e => {
  const btn = e.target.closest("button[data-people-tab]");
  if (!btn) return;
  e.preventDefault();
  const view = document.querySelector('section.view[data-view="people"]');
  if (!view) return;
  const validTabs = ["all", "followers", "following"];
  const requested = btn.dataset.peopleTab;
  const key = validTabs.includes(requested) ? requested : "all";
  view.dataset.peopleTab = key;
  document.querySelectorAll("button[data-people-tab]").forEach(b => {
    b.classList.toggle("active", b.dataset.peopleTab === key);
  });
  if (typeof renderPeople === "function") renderPeople();
});

function renderPurchaseHistory() {
  const wrap = document.getElementById("purchaseHistoryList");
  if (!wrap) return;
  // Per user 2026-05-06: Riwayat Pembelian harus tampil dari playly-premium-payments
  // (transaksi premium real user). Filter ke email user yang lagi aktif.
  // v604 (2026-05-28): + summary Total Charge/Refund/Net Spent (merged dari
  // Riwayat Pembayaran di Settings yang dihapus).
  let purchases = [];
  let totalCharged = 0;
  let totalRefunded = 0;
  try {
    const allPayments = (typeof getPremiumPayments === "function") ? getPremiumPayments() : [];
    const myEmail = String(user?.email || "").toLowerCase();
    if (myEmail) {
      const myPayments = allPayments.filter(p => p && String(p.email || "").toLowerCase() === myEmail);
      // Aggregate summary
      myPayments.forEach(p => {
        const amt = Number(p.amount || 0);
        if (p.status === "approved") totalCharged += amt;
        else if (p.status === "rejected") totalRefunded += amt;
      });
      purchases = myPayments
        .map(p => ({
          ts: Number(p.processedAt || p.paidAt || p.createdAt || Date.now()),
          label: p.plan === "monthly" ? "Playly Premium · Bulanan"
               : p.plan === "yearly"  ? "Playly Premium · Tahunan"
               : p.plan === "lifetime" ? "Playly Premium · Seumur Hidup"
               : `Playly Premium · ${p.plan || "—"}`,
          amount: `$${(p.amount || 0).toFixed(2)}`,
          status: p.status,
          code: p.code,
          method: p.method,
        }))
        .sort((a, b) => b.ts - a.ts);
    }
  } catch {}
  const netSpent = totalCharged - totalRefunded;
  // Summary cards (Total Charge / Refund / Net Spent) — merged dari Settings billing.
  const summaryHtml = `
    <div class="rwt-billing-summary">
      <div class="rbs-cell">
        <small>Total Charge</small>
        <b>$${totalCharged.toFixed(2)}</b>
      </div>
      <div class="rbs-cell">
        <small>Total Refund</small>
        <b>$${totalRefunded.toFixed(2)}</b>
      </div>
      <div class="rbs-cell rbs-cell-net">
        <small>Net Spent</small>
        <b>$${netSpent.toFixed(2)}</b>
      </div>
    </div>`;
  // v592 (2026-05-28): table list — per request user.
  const tableHead = `<thead><tr>
      <th style="width:20%">Tanggal</th>
      <th style="width:34%">Item</th>
      <th style="width:16%">Metode</th>
      <th style="width:16%">Status</th>
      <th style="width:14%">Jumlah</th>
    </tr></thead>`;
  if (!purchases.length) {
    wrap.innerHTML = summaryHtml + `<table class="riwayat-table">${tableHead}
      <tbody><tr class="rwt-empty-row"><td colspan="5">Belum ada riwayat pembelian. Upgrade premium akan tampil di sini.</td></tr></tbody>
    </table>`;
    return;
  }
  const statusBadge = (st) => {
    if (st === "approved") return '<span class="riwayat-status-badge ok">✓ Approved</span>';
    if (st === "rejected") return '<span class="riwayat-status-badge bad">✕ Rejected</span>';
    if (st === "pending")  return '<span class="riwayat-status-badge warn">⏳ Pending</span>';
    return '<span class="rwt-when">—</span>';
  };
  const rows = purchases.slice(0, 30).map(p => {
    const when = p.ts ? new Date(p.ts).toLocaleString("id-ID", { day: "numeric", month: "short", year: "numeric", hour: "2-digit", minute: "2-digit" }) : "—";
    return `<tr>
      <td class="rwt-when">${escapeHtml(when)}</td>
      <td><strong>${escapeHtml(p.label)}</strong>${p.code ? `<br><small class="rwt-method">${escapeHtml(p.code)}</small>` : ""}</td>
      <td class="rwt-method">${p.method ? escapeHtml(p.method) : "—"}</td>
      <td>${statusBadge(p.status)}</td>
      <td class="rwt-amount" style="text-align:right">${escapeHtml(p.amount)}</td>
    </tr>`;
  }).join("");
  wrap.innerHTML = summaryHtml + `<table class="riwayat-table">${tableHead}<tbody>${rows}</tbody></table>`;
}

function renderSearchHistorySections() {
  const userWrap = document.getElementById("searchUserHistoryList");
  const vidWrap  = document.getElementById("searchVideoHistoryList");
  const userQs = Array.isArray(state?.searchHistoryUser)  ? state.searchHistoryUser  : [];
  const vidQs  = Array.isArray(state?.searchHistoryVideo) ? state.searchHistoryVideo : [];
  // v592 (2026-05-28): table list — per request user.
  const renderTable = (wrap, items, kind) => {
    if (!wrap) return;
    const isUser = kind === "user";
    const head = `<thead><tr><th style="width:62%">Kueri</th><th style="width:18%">Tipe</th><th style="width:20%">Aksi</th></tr></thead>`;
    if (!items.length) {
      wrap.innerHTML = `<table class="riwayat-table">${head}
        <tbody><tr class="rwt-empty-row"><td colspan="3">${isUser ? "Belum ada pencarian user." : "Belum ada pencarian video."}</td></tr></tbody>
      </table>`;
      return;
    }
    const rows = items.slice(0, 30).map(q => {
      const qe = escapeHtml(String(q));
      return `<tr class="riwayat-chip" data-kind="${kind}" data-q="${qe}" style="cursor:pointer">
        <td><span class="rwt-query">${qe}</span></td>
        <td class="rwt-method">${isUser ? "User" : "Video"}</td>
        <td style="text-align:right">
          <button type="button" class="rwt-act rwt-act-play" data-kind="${kind}" data-q="${qe}" title="Cari ulang" aria-label="Cari ulang">↗</button>
          <button type="button" class="rwt-act" data-kind="${kind}-rm" data-q="${qe}" title="Hapus" aria-label="Hapus">✕</button>
        </td>
      </tr>`;
    }).join("");
    wrap.innerHTML = `<table class="riwayat-table">${head}<tbody>${rows}</tbody></table>`;
  };
  renderTable(userWrap, userQs, "user");
  renderTable(vidWrap,  vidQs,  "video");
}

// Hapus chip pencarian / klik chip
document.addEventListener("click", e => {
  const x = e.target.closest("[data-kind$='-rm']");
  if (x) {
    e.stopPropagation();
    const q = x.dataset.q;
    const kind = x.dataset.kind === "user-rm" ? "searchHistoryUser" : "searchHistoryVideo";
    if (Array.isArray(state[kind])) {
      state[kind] = state[kind].filter(item => String(item) !== q);
      saveState?.();
      renderSearchHistorySections();
    }
    return;
  }
  const chip = e.target.closest(".riwayat-chip[data-kind]");
  if (chip) {
    const q = chip.dataset.q;
    const kind = chip.dataset.kind;
    if (kind === "user") { switchView?.("people"); setTimeout(() => { const i = document.getElementById("peopleSearch"); if (i) { i.value = q; i.dispatchEvent(new Event("input")); } }, 100); }
    else if (kind === "video") { switchView?.("discover"); setTimeout(() => { const i = document.getElementById("discoverSearch") || document.getElementById("topSearch"); if (i) { i.value = q; i.dispatchEvent(new Event("input")); } }, 100); }
  }
});

function renderHistory() {
  // Setiap masuk halaman Riwayat → reset ke "all" (semua section terlihat).
  // User pilih pill spesifik kalau mau filter — bukan memori tab terakhir.
  setRiwayatTab("all");
  // Render semua section content (filtering visual diatur via CSS by data-riwayat-tab)
  renderPurchaseHistory();
  renderSearchHistorySections();

  if (!state.history.length) {
    // v592 (2026-05-28): tabel empty state (sebelumnya emptyHTML card).
    $("#continueList") && ($("#continueList").innerHTML = "");
    $("#historyGroups") && ($("#historyGroups").innerHTML = `<table class="riwayat-table">
      <thead><tr><th style="width:18%">Tanggal</th><th style="width:48%">Video</th><th style="width:22%">Progress</th><th style="width:12%">Aksi</th></tr></thead>
      <tbody><tr class="rwt-empty-row"><td colspan="4">Riwayat masih kosong. Video yang kamu tonton akan muncul di sini.</td></tr></tbody>
    </table>`);
    return;
  }

  // Lanjutkan Nonton — max contLimit (default 10)
  const allCont = state.history.filter(h => h.progress < 100);
  const contLimit = historyState.contLimit;
  const cont = allCont.slice(0, contLimit);
  const contRemaining = Math.max(0, allCont.length - cont.length);
  $("#continueList").innerHTML = cont.length ? cont.map(h => {
    const v = findVideo(h.videoId);
    if (!v) return "";
    const histIdx = state.history.indexOf(h);
    return `
      <div class="continue-card" data-vid="${v.id}">
        <div class="mini-thumb">
          <img src="${v.thumb}" alt=""/>
          <div class="progress-bar"><i style="width:${h.progress}%"></i></div>
        </div>
        <div class="info">
          <h5>${v.title}</h5>
          <p class="meta">@${v.creator}</p>
          <div class="pct">▶ ${h.progress}% selesai</div>
        </div>
        <button class="remove-btn" data-cont-rm="${histIdx}" title="Hapus dari Lanjutkan Tontonan" aria-label="Hapus">✕</button>
      </div>
    `;
  }).join("") : `<div style="grid-column:1/-1; padding:20px; text-align:center; color:var(--muted); font-size:13px">No videos in progress.</div>`;

  // "more >" button untuk Lanjutkan Nonton kalau total > limit
  if (contRemaining > 0) {
    $("#continueList").innerHTML += `
      <button type="button" class="people-more-btn history-more-btn" data-history-more="cont">
        <span>more (+${contRemaining})</span>
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M9 6l6 6-6 6"/></svg>
      </button>`;
  }

  // Riwayat Tontonan — flat list, batas riwayatLimit (default 10)
  const q = ($("#historySearch")?.value || "").toLowerCase();
  const filteredAll = state.history.filter(h => {
    if (!q) return true;
    const v = findVideo(h.videoId);
    return v && (v.title.toLowerCase().includes(q) || v.creator.toLowerCase().includes(q));
  });
  const riwayatLimit = historyState.riwayatLimit;
  const riwayatVisible = filteredAll.slice(0, riwayatLimit);
  const riwayatRemaining = Math.max(0, filteredAll.length - riwayatVisible.length);

  // Group by date for visible items
  const groups = {};
  riwayatVisible.forEach(h => {
    if (!groups[h.group]) groups[h.group] = [];
    groups[h.group].push(h);
  });
  const groupOrder = ["Today", "Yesterday", "This week", "Older"];

  // v592 (2026-05-28): Tabel list — Tanggal | Video | Progress | Aksi.
  // Group dibuat jadi rwt-group-row (separator row di dalam tabel).
  const tableRows = groupOrder.filter(g => groups[g]).map(g => {
    const items = groups[g];
    const groupRow = `<tr class="rwt-group-row"><td colspan="4">${g}</td></tr>`;
    const itemRows = items.map(h => {
      const v = findVideo(h.videoId);
      if (!v) return "";
      const idx = state.history.indexOf(h);
      const pct = Math.max(0, Math.min(100, Math.round(h.progress || 0)));
      return `<tr class="history-item" data-vid="${v.id}">
        <td class="rwt-when">${escapeHtml(h.time || "")}</td>
        <td>
          <div class="rwt-video-cell">
            <img class="rwt-thumb" src="${escapeHtml(v.thumb)}" alt=""/>
            <div class="rwt-video-meta">
              <strong>${escapeHtml(v.title)}</strong>
              <small>@${escapeHtml(v.creator)} · ${escapeHtml(String(v.views))} views</small>
            </div>
          </div>
        </td>
        <td>
          <span class="rwt-progress">${pct}% ditonton<i><span style="width:${pct}%"></span></i></span>
        </td>
        <td style="text-align:right">
          <button class="rwt-act" data-rm="${idx}" title="Hapus" aria-label="Hapus">✕</button>
        </td>
      </tr>`;
    }).join("");
    return groupRow + itemRows;
  }).join("");

  const tableHead = `<thead><tr><th style="width:18%">Tanggal</th><th style="width:48%">Video</th><th style="width:22%">Progress</th><th style="width:12%">Aksi</th></tr></thead>`;
  $("#historyGroups").innerHTML = tableRows
    ? `<table class="riwayat-table">${tableHead}<tbody>${tableRows}</tbody></table>`
    : `<table class="riwayat-table">${tableHead}<tbody><tr class="rwt-empty-row"><td colspan="4">Tidak ada riwayat yang cocok.</td></tr></tbody></table>`;

  // "more >" untuk Riwayat Tontonan
  if (riwayatRemaining > 0) {
    $("#historyGroups").innerHTML += `
      <button type="button" class="people-more-btn history-more-btn" data-history-more="riwayat" style="margin-top:10px">
        <span>more (+${riwayatRemaining})</span>
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M9 6l6 6-6 6"/></svg>
      </button>`;
  }

  $$("#continueList .continue-card, #historyGroups .history-item").forEach(c => {
    c.addEventListener("click", e => {
      if (e.target.closest(".remove-btn") || e.target.closest(".rwt-act")) return;
      openPlayer(+c.dataset.vid);
    });
  });
  $$("[data-rm]").forEach(b => b.addEventListener("click", e => {
    e.stopPropagation();
    state.history.splice(+b.dataset.rm, 1);
    saveState();
    renderHistory();
    toast("🗑️ Item dihapus dari riwayat");
  }));
  // Delete handler khusus Lanjutkan Tontonan
  $$("[data-cont-rm]").forEach(b => b.addEventListener("click", e => {
    e.stopPropagation();
    state.history.splice(+b.dataset.contRm, 1);
    saveState();
    renderHistory();
    toast("🗑️ Dihapus dari Lanjutkan Tontonan");
  }));
}

// Re-render History view tiap kali state.history berubah (mis. user nonton
// video baru dari sub-section lain). Polling cepat: bind sekali, listen
// `playly:state-changed` event kalau ada, fallback periodic refresh.
window.addEventListener("playly:cloud-applied", () => {
  if (state?.currentView === "history" && typeof renderHistory === "function") {
    renderHistory();
  }
});

$("#historySearch")?.addEventListener("input", () => {
  historyState.riwayatLimit = 10; // reset pagination saat search
  renderHistory();
});
// Klik "more >" di kolom history → tambah 10 lagi
document.addEventListener("click", e => {
  const btn = e.target.closest("[data-history-more]");
  if (!btn) return;
  const kind = btn.dataset.historyMore;
  if (kind === "cont") historyState.contLimit += 10;
  else if (kind === "riwayat") historyState.riwayatLimit += 10;
  renderHistory();
});
$("#clearHistory")?.addEventListener("click", () => {
  if (!state.history.length) return toast("Riwayat sudah kosong");
  // Pakai openConfirm modal in-app, bukan browser confirm() (yang muncul
  // sebagai pop-up native browser di luar dashboard).
  if (typeof openConfirm === "function") {
    openConfirm({
      icon: "🗑️", iconClass: "danger",
      title: "Clear All History?",
      desc: `Semua <b>${state.history.length}</b> riwayat tonton akan dihapus dan tidak bisa dipulihkan.`,
      btnText: "Hapus Semua", btnClass: "danger",
      onConfirm: () => {
        state.history = [];
        saveState();
        renderHistory();
        toast("✓ Riwayat dikosongkan", "success");
      }
    });
  } else {
    state.history = [];
    saveState();
    renderHistory();
    toast("✓ Riwayat dikosongkan", "success");
  }
});

// ----------------------- STATS VIEW -----------------------
// Helper: localized day/month labels berdasarkan bahasa user aktif.
function _chartLabels(range) {
  const isID = (typeof currentLang === "function" && currentLang() === "id");
  if (range === "weekly") {
    return isID ? ["Sen","Sel","Rab","Kam","Jum","Sab","Min"]
                : ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"];
  }
  if (range === "monthly") {
    return isID ? ["M1","M2","M3","M4"] : ["W1","W2","W3","W4"];
  }
  // yearly
  return isID
    ? ["Jan","Feb","Mar","Apr","Mei","Jun","Jul","Agu","Sep","Okt","Nov","Des"]
    : ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
}

const CHART_DATA_DEMO = {
  get weekly() { return { labels: _chartLabels("weekly"), values: [120,180,150,240,220,320,280] }; },
  get monthly() { return { labels: _chartLabels("monthly"), values: [820,1240,980,1680] }; },
  get yearly() { return { labels: _chartLabels("yearly"), values: [3200,2800,4100,3600,5200,4800,6100,5800,7200,6900,8400,9200] }; },
};

function emptyChartData(range) {
  const counts = { weekly: 7, monthly: 4, yearly: 12 };
  return { labels: _chartLabels(range), values: new Array(counts[range] || 7).fill(0) };
}

// Generate data per metric berdasarkan range. Untuk metric Video → jumlah
// upload per period. Untuk Views → akumulasi viewsNum. Untuk Followers →
// growth simulasi (real data limited, jadi pakai pattern). Semua berbasis
// state.myVideos real-time supaya angka match dashboard.
function generateChartData(metric, range) {
  const labels = (CHART_DATA_DEMO[range] || CHART_DATA_DEMO.weekly).labels;
  const myVideos = Array.isArray(state?.myVideos) ? state.myVideos : [];
  const totalVideos = myVideos.length;
  const totalViews = myVideos.reduce((s, v) => s + (v.viewsNum || 0), 0);
  const followerCount = (typeof getUserFollowers === "function" && user?.username)
    ? getUserFollowers(user.username).length : 0;
  // v595 (2026-05-28): comments series — total komentar di semua video user.
  const totalComments = myVideos.reduce((s, v) =>
    s + ((state.comments?.[v.id]?.length) || 0), 0);

  const total = metric === "videos"   ? totalVideos
    : metric === "views"              ? totalViews
    : metric === "comments"           ? totalComments
    : followerCount;
  const n = labels.length;
  const values = [];

  // v602d (2026-05-28): DUMMY DATA preview mode — kalau total 0, inject
  // realistic varying values per metric biar chart bentuknya kelihatan.
  // HAPUS block ini kalau data real sudah masuk. Variasi per metric beda
  // pattern (videos = ascending discrete, views = exponential, followers =
  // steady growth, comments = spiky).
  if (total === 0) {
    const DUMMY = {
      weekly: {
        videos:    [2, 1, 3, 2, 4, 5, 3],
        views:     [120, 280, 180, 420, 380, 680, 520],
        followers: [45, 52, 58, 67, 78, 84, 92],
        comments:  [8, 24, 12, 18, 32, 28, 41],
      },
      monthly: {
        videos:    [8, 12, 9, 16],
        views:     [1200, 2400, 1800, 4200],
        followers: [120, 180, 230, 310],
        comments:  [45, 82, 67, 124],
      },
      yearly: {
        videos:    [3, 5, 4, 8, 6, 10, 12, 9, 15, 18, 14, 22],
        views:     [800, 1200, 980, 2400, 1800, 3600, 5200, 4100, 7800, 9200, 8400, 12400],
        followers: [50, 80, 120, 180, 240, 320, 410, 520, 680, 820, 980, 1240],
        comments:  [12, 28, 18, 64, 42, 92, 138, 84, 220, 280, 240, 380],
      },
    };
    const demo = (DUMMY[range] && DUMMY[range][metric]) || new Array(n).fill(0);
    for (let i = 0; i < n; i++) values.push(demo[i] || 0);
    const demoTotal = values.reduce((s, v) => s + v, 0);
    return { labels, values, total: demoTotal, isDummy: true };
  }

  // Smooth growth curve, ending at `total`
  for (let i = 0; i < n; i++) {
    const ratio = (i + 1) / n;
    values.push(Math.round(total * (0.4 + 0.6 * ratio)));
  }
  return { labels, values, total };
}

// v602 (2026-05-28): Modern UI/UX redesign — Vercel/Linear/Stripe analytics
// pattern. Big number headline + delta % vs periode sebelumnya + smooth
// bezier area sparkline (no axis, no grid, no labels — minimal & clear).
// Hover → tooltip via data point.
function drawMiniChart(metric) {
  const svg = document.querySelector(`[data-chart-svg="${metric}"]`);
  const empty = document.querySelector(`[data-chart-empty="${metric}"]`);
  if (!svg) return;
  const wrap = svg.parentElement;
  const card = wrap?.closest(".mini-chart-card");
  const data = generateChartData(metric, state.chartRange);
  const hasData = data.total > 0;

  // Modern card layout — find/create headline + delta elements
  const head = card?.querySelector(".mini-chart-head");
  let bigEl = card?.querySelector(".mc-big");
  let deltaEl = card?.querySelector(".mc-delta");
  if (head && !bigEl) {
    const wrapEl = document.createElement("div");
    wrapEl.className = "mc-headline";
    wrapEl.innerHTML = '<b class="mc-big"></b><span class="mc-delta"></span>';
    head.insertAdjacentElement("afterend", wrapEl);
    bigEl = wrapEl.querySelector(".mc-big");
    deltaEl = wrapEl.querySelector(".mc-delta");
  }

  if (!hasData) {
    svg.innerHTML = "";
    if (empty) empty.hidden = false;
    if (bigEl) bigEl.textContent = "0";
    if (deltaEl) { deltaEl.textContent = ""; deltaEl.className = "mc-delta"; }
    return;
  }
  if (empty) empty.hidden = true;

  // Compute delta: current period total vs previous period (last half vs first half)
  const half = Math.floor(data.values.length / 2);
  const prevSum = data.values.slice(0, half).reduce((s, v) => s + v, 0);
  const currSum = data.values.slice(half).reduce((s, v) => s + v, 0);
  let deltaPct = 0;
  if (prevSum > 0) deltaPct = ((currSum - prevSum) / prevSum) * 100;
  else if (currSum > 0) deltaPct = 100;
  const deltaTrend = deltaPct > 0 ? "up" : deltaPct < 0 ? "down" : "flat";
  const deltaSign = deltaPct > 0 ? "+" : "";
  const deltaArrow = deltaTrend === "up" ? "↑" : deltaTrend === "down" ? "↓" : "·";

  if (bigEl) bigEl.textContent = (typeof fmtNum === "function" ? fmtNum(data.total) : String(data.total));
  if (deltaEl) {
    deltaEl.className = `mc-delta mc-delta-${deltaTrend}`;
    deltaEl.innerHTML = `<i>${deltaArrow}</i> ${deltaSign}${deltaPct.toFixed(1)}% <small>vs sebelumnya</small>`;
  }

  // === v603 (2026-05-28): Step Chart (stair-step path) ===
  // Discrete stair-step path bukan smooth curve. Cocok untuk data integer
  // (video count, follower count) yang nggak ada nilai 0.5. Path naik tegak
  // di tengah antar period biar visual jelas "lompat" per period.
  wrap.innerHTML = ""; // clear old DOM
  // Restore main SVG
  if (svg) {
    svg.style.display = "";
    wrap.appendChild(svg);
  }

  // Restore big number (in case prev render hid it for ring style)
  if (bigEl) bigEl.style.display = "";

  const containerW = Math.max(280, Math.round(wrap?.offsetWidth || svg.clientWidth || 600));
  const W = containerW, H = 80, PAD_X = 4, PAD_Y = 4;
  svg.setAttribute("viewBox", `0 0 ${W} ${H}`);
  svg.setAttribute("preserveAspectRatio", "none");

  const n = data.values.length;
  const min = Math.min(...data.values, 0);
  const max = Math.max(...data.values, 1);
  const range = max - min || 1;
  const stepX = (W - PAD_X * 2) / Math.max(1, n);
  const points = data.values.map((v, i) => [
    PAD_X + (i + 0.5) * stepX, // center of each segment
    H - PAD_Y - ((v - min) / range) * (H - PAD_Y * 2),
  ]);

  const colors = {
    videos:    "#BE9752",
    views:     "#7d3640",
    followers: "#f59e0b",
    comments:  "#10b981",
  };
  const c = colors[metric] || colors.videos;
  const fillId = `chartFill-${metric}`;

  // Build stair-step path:
  // M startX,startY → H (next segment edge) → V (newY) → H (next segment edge) → V (newY) ...
  let stepPath = "";
  let areaPath = "";
  if (n > 0) {
    // Start at left edge of first segment, height = first value
    const firstY = points[0][1];
    const startX = PAD_X;
    stepPath = `M ${startX} ${firstY.toFixed(2)} `;
    let prevY = firstY;
    for (let i = 0; i < n; i++) {
      // Segment runs from i*stepX to (i+1)*stepX, height = points[i][1]
      const segLeft = PAD_X + i * stepX;
      const segRight = PAD_X + (i + 1) * stepX;
      const y = points[i][1];
      if (i > 0 && y !== prevY) {
        // Vertical step at boundary
        stepPath += `L ${segLeft.toFixed(2)} ${y.toFixed(2)} `;
      }
      // Horizontal across segment
      stepPath += `L ${segRight.toFixed(2)} ${y.toFixed(2)} `;
      prevY = y;
    }
    // Area = step + close to bottom
    areaPath = stepPath + `L ${(PAD_X + n * stepX).toFixed(2)} ${H} L ${PAD_X} ${H} Z`;
  }

  // Markers at each step's right edge (data point indicator)
  let markers = "";
  points.forEach((p, i) => {
    markers += `<circle cx="${p[0].toFixed(2)}" cy="${p[1].toFixed(2)}" r="3" fill="${c}" stroke="rgba(0,0,0,0.4)" stroke-width="1" class="chart-step-marker" style="opacity:0;animation-delay:${(0.8 + i * 0.08).toFixed(2)}s"/>`;
    // Invisible wider hit target
    const segLeft = PAD_X + i * stepX;
    markers += `<rect x="${segLeft.toFixed(2)}" y="0" width="${stepX.toFixed(2)}" height="${H}" fill="transparent" data-i="${i}" data-val="${data.values[i]}" data-x="${p[0].toFixed(2)}" data-y="${p[1].toFixed(2)}" class="chart-step-hit" style="cursor:pointer"/>`;
  });

  // Path length for draw animation
  let pathLen = 0;
  // Approximate: sum H + V segments
  for (let i = 1; i < points.length; i++) {
    pathLen += stepX + Math.abs(points[i][1] - points[i - 1][1]);
  }
  pathLen += stepX; // first segment horizontal
  pathLen *= 1.1;

  svg.innerHTML = `
    <defs>
      <linearGradient id="${fillId}" x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stop-color="${c}" stop-opacity=".35"/>
        <stop offset="100%" stop-color="${c}" stop-opacity="0"/>
      </linearGradient>
    </defs>
    <path class="chart-area-anim" d="${areaPath}" fill="url(#${fillId})"/>
    <path class="chart-line-anim" d="${stepPath}" fill="none" stroke="${c}" stroke-width="2.2" stroke-linejoin="miter" stroke-linecap="square" style="stroke-dasharray:${pathLen.toFixed(0)};stroke-dashoffset:${pathLen.toFixed(0)};--chart-len:${pathLen.toFixed(0)}"/>
    ${markers}
  `;

  const tip = $("#chartTip");
  const unitLabel = metric === "videos" ? "video"
    : metric === "views" ? "views"
    : metric === "comments" ? "komentar"
    : "followers";
  $$(".chart-step-hit", svg).forEach((d, i) => {
    d.addEventListener("mouseenter", () => {
      const marker = svg.querySelectorAll(".chart-step-marker")[i];
      if (marker) marker.setAttribute("r", "5");
      const rect = svg.getBoundingClientRect();
      const cx = +d.getAttribute("data-x") * (rect.width / W) + rect.left + window.scrollX;
      const cy = +d.getAttribute("data-y") * (rect.height / H) + rect.top + window.scrollY;
      if (tip) {
        tip.innerHTML = `<small>${data.labels[i] || ""}</small><b>${(+d.getAttribute("data-val")).toLocaleString("id-ID")} ${unitLabel}</b>`;
        tip.style.position = "fixed";
        tip.style.left = `${cx - tip.offsetWidth / 2 - window.scrollX}px`;
        tip.style.top = `${cy - tip.offsetHeight - 10 - window.scrollY}px`;
        tip.style.transform = "";
        tip.classList.add("show");
      }
    });
    d.addEventListener("mouseleave", () => {
      const marker = svg.querySelectorAll(".chart-step-marker")[i];
      if (marker) marker.setAttribute("r", "3");
      if (tip) tip.classList.remove("show");
    });
  });
}

function drawChart() {
  // Render 4 chart sekaligus + update total angka di header.
  // v595 (2026-05-28): + Comments chart.
  const fmt = n => (typeof fmtNum === "function" ? fmtNum(n) : String(n));
  const myVideos = Array.isArray(state?.myVideos) ? state.myVideos : [];
  const totalViews = myVideos.reduce((s, v) => s + (v.viewsNum || 0), 0);
  const totalComments = myVideos.reduce((s, v) =>
    s + ((state.comments?.[v.id]?.length) || 0), 0);
  const followerCount = (typeof getUserFollowers === "function" && user?.username)
    ? getUserFollowers(user.username).length : 0;
  const setT = (id, n) => { const el = document.getElementById(id); if (el) el.textContent = fmt(n); };
  setT("chartTotalVideos", myVideos.length);
  setT("chartTotalViews", totalViews);
  setT("chartTotalFollowers", followerCount);
  setT("chartTotalComments", totalComments);

  const subtitle = $("#chartSubtitle");
  if (subtitle) {
    const labelMap = { weekly: "minggu ini", monthly: "bulan ini", yearly: "tahun ini" };
    if (myVideos.length === 0 && totalViews === 0 && followerCount === 0 && totalComments === 0) {
      subtitle.textContent = "Belum ada data — unggah video untuk mulai tracking";
    } else {
      subtitle.textContent = `Performa ${labelMap[state.chartRange]}`;
    }
  }

  drawMiniChart("videos");
  drawMiniChart("views");
  drawMiniChart("followers");
  drawMiniChart("comments");
}

