function openChatUserPicker() {
  document.getElementById("__chatUserPicker")?.remove();
  const modal = document.createElement("div");
  modal.className = "hs-popup-modal";
  modal.id = "__chatUserPicker";
  modal.innerHTML = `
    <div class="hs-popup-backdrop" data-cup-close></div>
    <div class="hs-popup-panel email-user-picker-panel">
      <button type="button" class="hs-popup-close" data-cup-close aria-label="Close">✕</button>
      <h3 class="email-recipient-title">💬 New Message</h3>
      <p class="email-recipient-desc">Choose a user to chat with.</p>
      <div class="email-user-search">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"><circle cx="11" cy="11" r="7"/><path d="m20 20-3.5-3.5"/></svg>
        <input type="text" id="chatUserSearchInput" placeholder="Search name or username..." autocomplete="off"/>
      </div>
      <div class="email-user-list" id="chatUserPickerList"></div>
    </div>
  `;
  document.body.appendChild(modal);
  requestAnimationFrame(() => modal.classList.add("show"));
  modal.querySelectorAll("[data-cup-close]").forEach(b => b.addEventListener("click", () => modal.remove()));
  const input = modal.querySelector("#chatUserSearchInput");
  const list = modal.querySelector("#chatUserPickerList");
  const renderList = () => {
    const q = (input.value || "").toLowerCase().trim();
    const accounts = (typeof getAllAccounts === "function" ? getAllAccounts() : [])
      .filter(a => a.username !== user?.username)
      .filter(a => !q || (a.name || "").toLowerCase().includes(q) || (a.username || "").toLowerCase().includes(q))
      .slice(0, 30);
    if (!accounts.length) {
      list.innerHTML = `<div class="email-user-empty">${q ? "Tidak ada user yang cocok." : "Belum ada user lain."}</div>`;
      return;
    }
    list.innerHTML = accounts.map(a => {
      const label = a.name || a.username || "U";
      const init = String(label).split(/\s+/).map(s => s[0]).slice(0, 2).join("").toUpperCase() || "U";
      const handle = escapeHtml(a.username || "");
      const avatar = a.avatar
        ? `<div class="avatar"><img src="${escapeHtml(a.avatar)}" alt=""/></div>`
        : `<div class="avatar"><span>${escapeHtml(init)}</span></div>`;
      return `
        <button type="button" class="email-user-item" data-cup-pick="${handle}">
          ${avatar}
          <div class="info">
            <strong>${escapeHtml(label)}</strong>
            <small>@${handle}</small>
          </div>
        </button>
      `;
    }).join("");
    list.querySelectorAll("[data-cup-pick]").forEach(b => {
      b.addEventListener("click", () => {
        const uname = b.dataset.cupPick;
        modal.remove();
        if (typeof startChatWithUser === "function") startChatWithUser(uname);
      });
    });
  };
  input.addEventListener("input", renderList);
  renderList();
  setTimeout(() => input.focus(), 100);
}

// ----------------------- UPLOAD VIEW -----------------------
const dropzone = $("#dropzone");
const fileInput = $("#fileInput");
const uploadPreview = $("#uploadPreview");
let pendingUpload = null; // { file, thumb (data URL), duration (string), videoUrl (blob URL) }

// Character counters
(function() {
  function bindCounter(inputId, counterId, max) {
    const el = $("#" + inputId), ctr = $("#" + counterId);
    if (!el || !ctr) return;
    function update() {
      const n = el.value.length;
      ctr.textContent = `${n}/${max}`;
      ctr.classList.toggle("near", n > max * .85 && n < max);
      ctr.classList.toggle("over", n >= max);
    }
    el.addEventListener("input", update);
    update();
  }
  bindCounter("upTitle", "upTitleCounter", 100);
  bindCounter("upDesc", "upDescCounter", 2000);
  // v681 (1o): auto-grow upload description textarea to fit content (still
  // manually resizable via CSS `resize: vertical`).
  (function autoGrowDesc() {
    const ta = document.getElementById("upDesc");
    if (!ta) return;
    const grow = function () {
      ta.style.height = "auto";
      ta.style.height = Math.min(ta.scrollHeight, 480) + "px";
    };
    ta.addEventListener("input", grow);
  })();
})();

// Tag input
(function() {
  const wrap = $("#upTagsWrap"), list = $("#upTagsList"), input = $("#upTagsInput");
  if (!wrap || !list || !input) return;
  let tags = [];
  const MAX_TAGS = 10;

  function renderTags() {
    list.innerHTML = "";
    tags.forEach((t, i) => {
      const pill = document.createElement("span");
      pill.className = "upf-tag";
      pill.innerHTML = `${t}<button class="upf-tag-rm" data-i="${i}" title="Hapus" type="button">×</button>`;
      list.appendChild(pill);
    });
  }
  function addTag(raw) {
    const val = raw.trim().toLowerCase().replace(/[^a-z0-9À-ɏ\s_-]/gi, "").trim();
    if (!val || tags.includes(val) || tags.length >= MAX_TAGS) return;
    tags.push(val);
    renderTags();
  }
  input.addEventListener("keydown", e => {
    if (e.key === "Enter" || e.key === ",") {
      e.preventDefault();
      addTag(input.value.replace(/,$/, ""));
      input.value = "";
    } else if (e.key === "Backspace" && !input.value && tags.length) {
      tags.pop();
      renderTags();
    }
  });
  input.addEventListener("blur", () => { if (input.value.trim()) { addTag(input.value); input.value = ""; } });
  list.addEventListener("click", e => {
    const btn = e.target.closest(".upf-tag-rm");
    if (!btn) return;
    tags.splice(+btn.dataset.i, 1);
    renderTags();
  });
  wrap.addEventListener("click", () => input.focus());
  window._getUploadTags = () => [...tags];
  window._clearUploadTags = () => { tags = []; renderTags(); };
  // Expose setter supaya AI Assist bisa pre-fill tags
  window._setUploadTags = (arr) => {
    if (!Array.isArray(arr)) return;
    tags = [];
    arr.slice(0, MAX_TAGS).forEach(t => addTag(String(t)));
  };
})();

// =====================================================================
// UPLOAD — VIDEO INFO CARD + COVER FRAME PICKER
// Per request user 2026-05-14. Section di bawah dropzone Video (wajib):
// 1) Info Card: auto-populate metadata (durasi/ukuran/resolusi/format/bitrate)
// 2) Frame Picker: scrub video via slider, draw frame ke canvas, set sebagai thumb.
// =====================================================================
(function wireVideoInfoAndFramePicker() {
  const infoSection = document.getElementById("upInfoSection");
  const frameSection = document.getElementById("upFrameSection");
  const infoDur  = document.getElementById("upInfoDuration");
  const infoSize = document.getElementById("upInfoSize");
  const infoRes  = document.getElementById("upInfoResolution");
  const infoAsp  = document.getElementById("upInfoAspect");
  const infoFmt  = document.getElementById("upInfoFormat");
  const infoBr   = document.getElementById("upInfoBitrate");

  const frameVideo = document.getElementById("upFrameVideo");
  const frameCanvas = document.getElementById("upFrameCanvas");
  const frameSlider = document.getElementById("upFrameSlider");
  const frameTime = document.getElementById("upFrameTime");
  const frameApply = document.getElementById("upFrameApply");
  const frameLoading = document.getElementById("upFrameLoading");

  if (!infoSection || !frameSection || !frameVideo) return;

  function fmtTime(sec) {
    if (!isFinite(sec) || sec < 0) return "0:00";
    const m = Math.floor(sec / 60);
    const s = Math.floor(sec % 60);
    return `${m}:${String(s).padStart(2, "0")}`;
  }
  function fmtBytesLocal(n) {
    if (typeof fmtBytes === "function") return fmtBytes(n);
    if (n < 1024) return n + " B";
    if (n < 1024 * 1024) return (n / 1024).toFixed(1) + " KB";
    if (n < 1024 * 1024 * 1024) return (n / (1024 * 1024)).toFixed(1) + " MB";
    return (n / (1024 * 1024 * 1024)).toFixed(2) + " GB";
  }
  function aspectRatio(w, h) {
    if (!w || !h) return "—";
    // Common ratios
    const r = w / h;
    if (Math.abs(r - 16 / 9) < 0.02) return "16:9";
    if (Math.abs(r - 9 / 16) < 0.02) return "9:16";
    if (Math.abs(r - 4 / 3)  < 0.02) return "4:3";
    if (Math.abs(r - 1)      < 0.02) return "1:1";
    if (Math.abs(r - 21 / 9) < 0.02) return "21:9";
    // GCD-based reduction
    const gcd = (a, b) => b === 0 ? a : gcd(b, a % b);
    const g = gcd(w, h);
    return `${w / g}:${h / g}`;
  }
  function fmtBitrate(bytes, durSec) {
    if (!bytes || !durSec) return "—";
    const bps = (bytes * 8) / durSec;
    if (bps < 1e6) return (bps / 1e3).toFixed(0) + " kbps";
    return (bps / 1e6).toFixed(1) + " Mbps";
  }

  function reset() {
    // Per fix user 2026-05-15 v28: section TETAP visible — toggle .is-empty
    // class supaya CSS handle empty placeholder (bukan hidden the whole section).
    infoSection.classList.add("is-empty");
    frameSection.classList.add("is-empty");
    // Reset info pill values ke "—"
    if (infoDur)  infoDur.textContent  = "—";
    if (infoSize) infoSize.textContent = "—";
    if (infoRes)  infoRes.textContent  = "—";
    if (infoFmt)  infoFmt.textContent  = "—";
    if (frameVideo.src) {
      try { frameVideo.removeAttribute("src"); frameVideo.load(); } catch {}
    }
    if (frameSlider) frameSlider.value = 500;
    if (frameTime) frameTime.textContent = "0:00 / 0:00";
  }

  // Update slider track fill (CSS var --val) sesuai posisi thumb
  function updateSliderFill() {
    if (!frameSlider) return;
    const pct = (Number(frameSlider.value) / Number(frameSlider.max)) * 100;
    frameSlider.style.setProperty("--val", pct + "%");
  }

  // Draw current video frame ke canvas — dipakai saat user klik "Pakai Frame"
  function drawCurrentFrameToCanvas() {
    if (!frameVideo.videoWidth) return null;
    const w = frameVideo.videoWidth;
    const h = frameVideo.videoHeight;
    // Target max 1280px width supaya thumb tidak terlalu besar
    const targetW = Math.min(1280, w);
    const scale = targetW / w;
    frameCanvas.width = Math.round(w * scale);
    frameCanvas.height = Math.round(h * scale);
    const ctx = frameCanvas.getContext("2d");
    try {
      ctx.drawImage(frameVideo, 0, 0, frameCanvas.width, frameCanvas.height);
      return frameCanvas.toDataURL("image/jpeg", 0.88);
    } catch (err) {
      console.warn("[frame-picker] drawImage failed:", err);
      return null;
    }
  }

  // Public init: dipanggil dari handlePickedFile setelah pendingUpload ready
  window._initVideoInfoAndFrame = function (file, videoUrl) {
    if (!file || !videoUrl) { reset(); return; }
    // Per fix user 2026-05-15 v28: ganti .is-empty → state filled, section
    // selalu visible (no hidden toggle).
    infoSection.classList.remove("is-empty");
    frameSection.classList.remove("is-empty");
    const ext = (file.name.split(".").pop() || "").toUpperCase() || "—";
    infoSize.textContent = fmtBytesLocal(file.size);
    infoFmt.textContent = ext;
    // Reset video element & load new source
    frameVideo.src = videoUrl;
    if (frameLoading) frameLoading.hidden = false;
    frameVideo.preload = "auto";

    frameVideo.addEventListener("loadedmetadata", function onMeta() {
      frameVideo.removeEventListener("loadedmetadata", onMeta);
      const dur = frameVideo.duration || 0;
      const w = frameVideo.videoWidth || 0;
      const h = frameVideo.videoHeight || 0;
      infoDur.textContent = fmtTime(dur);
      infoRes.textContent = w && h ? `${w}×${h}` : "—";
      infoAsp.textContent = aspectRatio(w, h);
      infoBr.textContent = fmtBitrate(file.size, dur);
      if (frameTime) frameTime.textContent = `${fmtTime(dur * 0.5)} / ${fmtTime(dur)}`;
      // Set slider to mid-frame (50%)
      frameVideo.currentTime = dur * 0.5;
    }, { once: true });

    frameVideo.addEventListener("seeked", function onSeeked() {
      if (frameLoading) frameLoading.hidden = true;
      const dur = frameVideo.duration || 0;
      if (frameTime) frameTime.textContent = `${fmtTime(frameVideo.currentTime)} / ${fmtTime(dur)}`;
    });

    updateSliderFill();
  };

  // Reset hook supaya saat user clear/replace video, section ke-reset
  window._resetVideoInfoAndFrame = reset;

  // Slider: scrub video saat user drag
  if (frameSlider) {
    frameSlider.addEventListener("input", function () {
      updateSliderFill();
      const dur = frameVideo.duration || 0;
      if (!dur) return;
      const pct = Number(frameSlider.value) / Number(frameSlider.max);
      // Throttle: seek hanya di event input (yang sudah debounced oleh range native)
      frameVideo.currentTime = pct * dur;
    });
  }

  // "Pakai Frame Ini" button — generate dataURL & set sebagai custom thumb
  if (frameApply) {
    frameApply.addEventListener("click", function () {
      const dataUrl = drawCurrentFrameToCanvas();
      if (!dataUrl) {
        if (typeof toast === "function") toast("⚠️ Gagal capture frame — coba lagi", "warning");
        return;
      }
      const t = fmtTime(frameVideo.currentTime);
      // Set sebagai custom thumb DENGAN source 'frame' — preview muncul di Frame Picker,
      // BUKAN di Thumbnail Kustom (per request user 2026-05-14).
      if (typeof window._setCustomThumb === "function") {
        window._setCustomThumb(dataUrl, `frame-${t.replace(":", "m")}s.jpg`, "frame");
      } else {
        window._customThumb = dataUrl;
        window._customThumbSource = "frame";
        window._frameThumb = dataUrl;
        // Update applied preview di Frame Picker
        const fpImg = document.getElementById("upFrameAppliedThumb");
        const fpSection = document.getElementById("upFrameAppliedPreview");
        if (fpImg) fpImg.src = dataUrl;
        if (fpSection) fpSection.hidden = false;
      }
      if (typeof toast === "function") toast(`📸 Frame di ${t} dipakai sebagai thumbnail!`, "success");
    });
  }
})();

// =====================================================================
// UPLOAD — THUMBNAIL ACTIVE BADGES + EDITOR MODAL (Crop / Filter / Text)
// Per request user 2026-05-14:
// - Hanya 1 thumbnail aktif (Frame Picker atau Custom Upload); badge "✓ Aktif"
//   menandakan section mana yang sedang jadi sumber _customThumb.
// - Tombol "Edit" di kedua section → buka modal canvas editor.
// =====================================================================
(function wireThumbActiveBadges() {
  const frameBadge = document.getElementById("upFrameActiveBadge");
  const thumbBadge = document.getElementById("upThumbActiveBadge");
  window._refreshThumbActiveBadges = function () {
    const src = window._customThumbSource;
    // Badge "✓ Aktif" hanya muncul di section yang jadi sumber thumb saat ini.
    // - 'frame'  → Frame Picker
    // - 'upload' atau 'editor' → Thumbnail Kustom (editor result hidup di section ini)
    if (frameBadge) frameBadge.hidden = src !== "frame";
    if (thumbBadge) thumbBadge.hidden = !(src === "upload" || src === "editor");
  };
  window._refreshThumbActiveBadges();
})();

// =====================================================================
// THUMBNAIL EDITOR MODAL — Crop / Filter / Text
// Canvas-based mini image editor untuk thumbnail. Reload image dari
// window._customThumb, user edit, klik Apply → set ulang via _setCustomThumb.
// =====================================================================
(function wireThumbEditor() {
  const modal     = document.getElementById("thumbEditorModal");
  const canvas    = document.getElementById("teCanvas");
  const canvasWrap = document.getElementById("teCanvasWrap");
  const tabs      = modal?.querySelectorAll(".te-tab");
  const panels    = modal?.querySelectorAll("[data-te-panel]");
  const cropOverlay = document.getElementById("teCropOverlay");
  const cropFrame   = document.getElementById("teCropFrame");
  const textOverlay = document.getElementById("teTextOverlay");
  const filterGrid  = document.getElementById("teFilterGrid");
  const aspectPills = modal?.querySelectorAll(".te-aspect");
  const teTextInput = document.getElementById("teTextInput");
  const teTextSize  = document.getElementById("teTextSize");
  const teTextColor = document.getElementById("teTextColor");
  const teTextStroke= document.getElementById("teTextStroke");
  const teTextAdd   = document.getElementById("teTextAdd");
  const teTextClear = document.getElementById("teTextClear");
  const teReset     = document.getElementById("teReset");
  const teApply     = document.getElementById("teApply");

  if (!modal || !canvas) return;

  const ctx = canvas.getContext("2d");

  // ===== State =====
  let baseImg = null;          // Original Image untuk reset
  let activeFilter = "none";   // Current filter key
  let aspectMode = "free";     // Free | 16:9 | 9:16 | 1:1 | 4:3 | 3:4
  let crop = { x: 0, y: 0, w: 0, h: 0 }; // Crop region in image coords
  let textItems = [];          // Array of { text, size, color, strokeW, x, y } where x/y are fraction 0-1
  let activeTextIdx = -1;

  // ===== Filter presets =====
  const FILTERS = [
    { key: "none",     label: "Asli",      css: "none" },
    { key: "vivid",    label: "Vivid",     css: "saturate(1.4) contrast(1.1)" },
    { key: "warm",     label: "Warm",      css: "sepia(.25) saturate(1.3) hue-rotate(-10deg) brightness(1.05)" },
    { key: "cool",     label: "Cool",      css: "hue-rotate(180deg) saturate(.9) brightness(1.05) contrast(1.05)" },
    { key: "bw",       label: "B&W",       css: "grayscale(1) contrast(1.15)" },
    { key: "sepia",    label: "Sepia",     css: "sepia(.85) brightness(1.05)" },
    { key: "bright",   label: "Bright",    css: "brightness(1.25) contrast(1.05)" },
    { key: "dark",     label: "Moody",     css: "brightness(.75) contrast(1.25) saturate(1.1)" },
    { key: "fade",     label: "Fade",      css: "contrast(.85) brightness(1.1) saturate(.85)" },
    { key: "drama",    label: "Drama",     css: "contrast(1.35) saturate(1.25) brightness(.95)" },
  ];

  // Tracking: source asal saat editor dibuka — supaya Apply tahu balikkan ke section mana
  let editorOpenedFromSource = null;

  // ===== Open editor with dataURL =====
  // sourceHint: 'frame' atau 'upload' — kalau diberikan, Apply akan balikkan ke section
  // tersebut. Kalau tidak, inherit dari window._customThumbSource saat ini.
  window._openThumbEditor = function (dataUrl, sourceHint) {
    if (!dataUrl) {
      if (typeof toast === "function") toast("⚠️ Pilih thumbnail dulu sebelum edit", "warning");
      return;
    }
    console.log("[ThumbEditor] open called, sourceHint:", sourceHint, "dataUrl length:", dataUrl.length);
    editorOpenedFromSource = sourceHint || window._customThumbSource || "upload";
    // Show modal IMMEDIATELY supaya user lihat feedback klik tombol
    modal.classList.add("show");
    document.body.style.overflow = "hidden";
    setActiveTab("crop");

    // Force canvas display dimensions via inline style supaya tidak ke-collapse
    // oleh CSS max-width/max-height constraints atau parent flex layout.
    canvas.style.width = "100%";
    canvas.style.maxWidth = "640px";
    canvas.style.height = "auto";
    canvas.style.display = "block";

    // Draw placeholder while waiting for image to load
    canvas.width = 800;
    canvas.height = 450;
    console.log("[ThumbEditor] canvas dims set:", canvas.width, "×", canvas.height, "displayed:", canvas.clientWidth, "×", canvas.clientHeight);
    redraw();

    const img = new Image();
    img.onload = function () {
      console.log("[ThumbEditor] image loaded:", img.naturalWidth, "×", img.naturalHeight);
      baseImg = img;
      activeFilter = "none";
      aspectMode = "free";
      textItems = [];
      activeTextIdx = -1;
      // Setup canvas to natural image size (limit max 1280 untuk performance)
      const maxDim = 1280;
      let w = img.naturalWidth || 1280;
      let h = img.naturalHeight || 720;
      if (w > maxDim || h > maxDim) {
        const s = Math.min(maxDim / w, maxDim / h);
        w = Math.round(w * s);
        h = Math.round(h * s);
      }
      canvas.width = w;
      canvas.height = h;
      crop = { x: 0, y: 0, w, h };
      // Initial render — perlu RAF supaya modal sudah layout (canvas visible) baru draw
      redraw();
      // Re-draw setelah 2x RAF untuk pastiin layout sudah stabil sebelum setup crop frame
      requestAnimationFrame(() => {
        requestAnimationFrame(() => {
          redraw();
          setupCropFrame();
          renderFilterGrid();
          renderTextOverlay();
          // Reset aspect pill ke "free"
          aspectPills?.forEach(p => p.classList.toggle("active", p.dataset.aspect === "free"));
        });
      });
    };
    img.onerror = function (err) {
      console.warn("[thumb-editor] Image load error:", err);
      if (typeof toast === "function") toast("⚠️ Gagal load thumbnail untuk edit — coba pilih ulang", "error");
      closeModal();
    };
    img.src = dataUrl;
  };

  function closeModal() {
    modal.classList.remove("show");
    document.body.style.overflow = "";
  }

  // ===== Tab switcher =====
  function setActiveTab(key) {
    tabs.forEach(t => {
      const isActive = t.dataset.teTab === key;
      t.classList.toggle("active", isActive);
      t.setAttribute("aria-selected", isActive ? "true" : "false");
    });
    panels.forEach(p => { p.hidden = p.dataset.tePanel !== key; });
    // Show/hide crop & text overlay sesuai tab
    if (cropOverlay) cropOverlay.hidden = key !== "crop";
    if (textOverlay) textOverlay.hidden = key !== "text";
  }
  tabs?.forEach(t => t.addEventListener("click", () => setActiveTab(t.dataset.teTab)));

  // ===== Redraw canvas: drawImage + filter (text di-overlay HTML, di-bake saat Apply) =====
  function redraw() {
    console.log("[ThumbEditor] redraw called", {
      canvasW: canvas.width, canvasH: canvas.height,
      hasBaseImg: !!baseImg,
      imgNaturalW: baseImg?.naturalWidth, imgNaturalH: baseImg?.naturalHeight,
    });
    // ALWAYS draw a debug marker at top-left so user can see canvas IS being painted.
    // If marker invisible → canvas has 0 dimensions or context not working.
    ctx.save();
    ctx.filter = "none";
    ctx.fillStyle = "#1a1a1d";
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    // Debug marker (small red bar top-left)
    ctx.fillStyle = "#ef4444";
    ctx.fillRect(0, 0, 40, 6);
    ctx.restore();
    if (!baseImg) {
      ctx.save();
      ctx.fillStyle = "#888";
      ctx.font = "16px Inter, sans-serif";
      ctx.textAlign = "center";
      ctx.textBaseline = "middle";
      ctx.fillText("Memuat gambar...", canvas.width / 2, canvas.height / 2);
      ctx.restore();
      return;
    }
    // Ensure image is fully loaded
    if (!baseImg.complete || baseImg.naturalWidth === 0) {
      ctx.save();
      ctx.fillStyle = "#fbbf24";
      ctx.font = "14px Inter, sans-serif";
      ctx.textAlign = "center";
      ctx.fillText("⚠ Image not complete (w=" + baseImg.naturalWidth + ")", canvas.width / 2, canvas.height / 2);
      ctx.restore();
      return;
    }
    try {
      ctx.save();
      ctx.filter = filterCssOf(activeFilter);
      ctx.drawImage(baseImg, 0, 0, canvas.width, canvas.height);
      ctx.restore();
    } catch (err) {
      console.error("[ThumbEditor] drawImage failed:", err);
      ctx.save();
      ctx.fillStyle = "#ef4444";
      ctx.font = "14px Inter, sans-serif";
      ctx.textAlign = "center";
      ctx.fillText("⚠ Error drawing: " + err.message, canvas.width / 2, canvas.height / 2);
      ctx.restore();
    }
  }
  function filterCssOf(key) {
    return FILTERS.find(f => f.key === key)?.css || "none";
  }

  // ===== Filter grid render =====
  function renderFilterGrid() {
    if (!filterGrid || !baseImg) return;
    filterGrid.innerHTML = "";
    // Generate thumb preview for each filter (small canvas)
    const previewW = 80, previewH = 45;
    FILTERS.forEach(f => {
      const item = document.createElement("button");
      item.type = "button";
      item.className = "te-filter-item" + (f.key === activeFilter ? " active" : "");
      item.dataset.filter = f.key;
      // Generate preview via offscreen canvas
      const off = document.createElement("canvas");
      off.width = previewW; off.height = previewH;
      const offCtx = off.getContext("2d");
      offCtx.filter = f.css;
      offCtx.drawImage(baseImg, 0, 0, previewW, previewH);
      const img = document.createElement("img");
      img.src = off.toDataURL("image/jpeg", 0.7);
      img.alt = f.label;
      const span = document.createElement("span");
      span.textContent = f.label;
      item.append(img, span);
      item.addEventListener("click", () => {
        activeFilter = f.key;
        filterGrid.querySelectorAll(".te-filter-item").forEach(el => el.classList.toggle("active", el.dataset.filter === f.key));
        redraw();
      });
      filterGrid.appendChild(item);
    });
  }

  // ===== CROP — draggable frame on overlay =====
  function setupCropFrame() {
    if (!cropFrame || !canvas) return;
    const rect = canvas.getBoundingClientRect();
    const wrapRect = canvasWrap.getBoundingClientRect();
    const offsetLeft = rect.left - wrapRect.left;
    const offsetTop  = rect.top - wrapRect.top;
    // Use full canvas as initial crop
    cropFrame.style.left = offsetLeft + "px";
    cropFrame.style.top  = offsetTop + "px";
    cropFrame.style.width  = rect.width + "px";
    cropFrame.style.height = rect.height + "px";
    syncCropFromFrame();
  }
  function syncCropFromFrame() {
    if (!baseImg || !canvas || !cropFrame) return;
    const cRect = canvas.getBoundingClientRect();
    const fRect = cropFrame.getBoundingClientRect();
    const scaleX = canvas.width / cRect.width;
    const scaleY = canvas.height / cRect.height;
    crop.x = Math.max(0, Math.round((fRect.left - cRect.left) * scaleX));
    crop.y = Math.max(0, Math.round((fRect.top - cRect.top) * scaleY));
    crop.w = Math.min(canvas.width - crop.x, Math.round(fRect.width * scaleX));
    crop.h = Math.min(canvas.height - crop.y, Math.round(fRect.height * scaleY));
  }

  // Drag crop frame (move + resize via handles)
  let cropDrag = null;
  cropFrame?.addEventListener("mousedown", function (e) {
    if (!cropOverlay || cropOverlay.hidden) return;
    e.preventDefault();
    const handle = e.target.closest(".te-crop-handle");
    const startRect = cropFrame.getBoundingClientRect();
    const wrapRect = canvasWrap.getBoundingClientRect();
    const startX = e.clientX, startY = e.clientY;
    cropDrag = {
      mode: handle ? "resize" : "move",
      handle: handle?.dataset.handle,
      startX, startY,
      startLeft: startRect.left - wrapRect.left,
      startTop:  startRect.top - wrapRect.top,
      startW: startRect.width,
      startH: startRect.height,
    };
  });
  document.addEventListener("mousemove", function (e) {
    if (!cropDrag) return;
    const dx = e.clientX - cropDrag.startX;
    const dy = e.clientY - cropDrag.startY;
    const canvasRect = canvas.getBoundingClientRect();
    const wrapRect = canvasWrap.getBoundingClientRect();
    const cLeft = canvasRect.left - wrapRect.left;
    const cTop  = canvasRect.top - wrapRect.top;
    const cW = canvasRect.width, cH = canvasRect.height;

    if (cropDrag.mode === "move") {
      let nx = cropDrag.startLeft + dx;
      let ny = cropDrag.startTop + dy;
      nx = Math.max(cLeft, Math.min(cLeft + cW - cropDrag.startW, nx));
      ny = Math.max(cTop,  Math.min(cTop + cH - cropDrag.startH, ny));
      cropFrame.style.left = nx + "px";
      cropFrame.style.top  = ny + "px";
    } else if (cropDrag.mode === "resize") {
      let nx = cropDrag.startLeft, ny = cropDrag.startTop;
      let nw = cropDrag.startW, nh = cropDrag.startH;
      switch (cropDrag.handle) {
        case "nw":
          nx = cropDrag.startLeft + dx;
          ny = cropDrag.startTop + dy;
          nw = cropDrag.startW - dx;
          nh = cropDrag.startH - dy;
          break;
        case "ne":
          ny = cropDrag.startTop + dy;
          nw = cropDrag.startW + dx;
          nh = cropDrag.startH - dy;
          break;
        case "sw":
          nx = cropDrag.startLeft + dx;
          nw = cropDrag.startW - dx;
          nh = cropDrag.startH + dy;
          break;
        case "se":
          nw = cropDrag.startW + dx;
          nh = cropDrag.startH + dy;
          break;
      }
      // Aspect ratio lock
      if (aspectMode !== "free") {
        const [aw, ah] = aspectMode.split(":").map(Number);
        const r = aw / ah;
        // Use width as primary
        nh = nw / r;
        // Adjust y for nw/ne handles
        if (cropDrag.handle === "nw" || cropDrag.handle === "ne") {
          ny = cropDrag.startTop + (cropDrag.startH - nh);
        }
      }
      // Min size
      const MIN = 50;
      if (nw < MIN) nw = MIN;
      if (nh < MIN) nh = MIN;
      // Clamp to canvas
      if (nx < cLeft) { nw -= (cLeft - nx); nx = cLeft; }
      if (ny < cTop)  { nh -= (cTop - ny);  ny = cTop; }
      if (nx + nw > cLeft + cW) nw = cLeft + cW - nx;
      if (ny + nh > cTop  + cH) nh = cTop + cH - ny;
      cropFrame.style.left = nx + "px";
      cropFrame.style.top = ny + "px";
      cropFrame.style.width = nw + "px";
      cropFrame.style.height = nh + "px";
    }
    syncCropFromFrame();
  });
  document.addEventListener("mouseup", function () {
    if (cropDrag) cropDrag = null;
  });

  // Aspect ratio pills
  aspectPills?.forEach(p => p.addEventListener("click", function () {
    aspectMode = p.dataset.aspect;
    aspectPills.forEach(x => x.classList.toggle("active", x === p));
    if (aspectMode !== "free" && cropFrame) {
      // Re-apply aspect ratio to current crop frame width
      const rect = cropFrame.getBoundingClientRect();
      const wrapRect = canvasWrap.getBoundingClientRect();
      const [aw, ah] = aspectMode.split(":").map(Number);
      const newH = rect.width * (ah / aw);
      cropFrame.style.height = newH + "px";
      // Clamp
      const canvasRect = canvas.getBoundingClientRect();
      const top = parseFloat(cropFrame.style.top);
      const maxTop = (canvasRect.top - wrapRect.top) + canvasRect.height - newH;
      if (top > maxTop) cropFrame.style.top = maxTop + "px";
      syncCropFromFrame();
    }
  }));

  // ===== TEXT overlay =====
  function renderTextOverlay() {
    if (!textOverlay) return;
    textOverlay.innerHTML = "";
    const cRect = canvas.getBoundingClientRect();
    const wRect = canvasWrap.getBoundingClientRect();
    const ofsX = cRect.left - wRect.left;
    const ofsY = cRect.top - wRect.top;
    textItems.forEach((item, i) => {
      const el = document.createElement("div");
      el.className = "te-text-item" + (i === activeTextIdx ? " active" : "");
      el.textContent = item.text;
      el.style.fontSize = Math.round(item.size * (cRect.width / canvas.width)) + "px";
      el.style.color = item.color;
      el.style.fontWeight = "800";
      el.style.fontFamily = "Inter, sans-serif";
      el.style.left = (ofsX + item.x * cRect.width) + "px";
      el.style.top  = (ofsY + item.y * cRect.height) + "px";
      if (item.strokeW > 0) {
        el.style.webkitTextStroke = item.strokeW + "px #000";
      }
      el.dataset.idx = String(i);
      textOverlay.appendChild(el);
    });
  }

  // Add text
  teTextAdd?.addEventListener("click", function () {
    const text = teTextInput.value.trim();
    if (!text) {
      if (typeof toast === "function") toast("⚠️ Tulis teks dulu", "warning");
      return;
    }
    textItems.push({
      text,
      size: Number(teTextSize.value) || 56,
      color: teTextColor.value || "#ffffff",
      strokeW: Number(teTextStroke.value) || 0,
      x: 0.5, y: 0.5,
    });
    activeTextIdx = textItems.length - 1;
    teTextInput.value = "";
    renderTextOverlay();
  });
  teTextClear?.addEventListener("click", function () {
    textItems = [];
    activeTextIdx = -1;
    renderTextOverlay();
  });

  // Color presets
  modal.querySelectorAll(".te-color-preset").forEach(c => c.addEventListener("click", function () {
    teTextColor.value = c.dataset.color;
  }));

  // Drag text items
  let textDrag = null;
  textOverlay?.addEventListener("mousedown", function (e) {
    const el = e.target.closest(".te-text-item");
    if (!el) return;
    e.preventDefault();
    const idx = Number(el.dataset.idx);
    activeTextIdx = idx;
    const cRect = canvas.getBoundingClientRect();
    const startX = e.clientX, startY = e.clientY;
    const item = textItems[idx];
    textDrag = { idx, startX, startY, origX: item.x, origY: item.y, cRect };
    el.classList.add("dragging");
  });
  document.addEventListener("mousemove", function (e) {
    if (!textDrag) return;
    const dx = (e.clientX - textDrag.startX) / textDrag.cRect.width;
    const dy = (e.clientY - textDrag.startY) / textDrag.cRect.height;
    const item = textItems[textDrag.idx];
    item.x = Math.max(0, Math.min(1, textDrag.origX + dx));
    item.y = Math.max(0, Math.min(1, textDrag.origY + dy));
    renderTextOverlay();
  });
  document.addEventListener("mouseup", function () {
    if (textDrag) {
      const els = textOverlay.querySelectorAll(".te-text-item");
      els.forEach(el => el.classList.remove("dragging"));
      textDrag = null;
    }
  });

  // ===== Reset =====
  teReset?.addEventListener("click", function () {
    if (!baseImg) return;
    activeFilter = "none";
    aspectMode = "free";
    textItems = [];
    activeTextIdx = -1;
    crop = { x: 0, y: 0, w: canvas.width, h: canvas.height };
    aspectPills?.forEach(p => p.classList.toggle("active", p.dataset.aspect === "free"));
    filterGrid?.querySelectorAll(".te-filter-item").forEach(el => el.classList.toggle("active", el.dataset.filter === "none"));
    setupCropFrame();
    redraw();
    renderTextOverlay();
  });

  // ===== Apply: bake crop + filter + text → set _customThumb =====
  teApply?.addEventListener("click", function () {
    if (!baseImg) return;
    // Build final canvas with crop dimensions
    const out = document.createElement("canvas");
    out.width = crop.w || canvas.width;
    out.height = crop.h || canvas.height;
    const octx = out.getContext("2d");
    octx.fillStyle = "#000";
    octx.fillRect(0, 0, out.width, out.height);
    // Draw cropped region with filter applied
    octx.filter = filterCssOf(activeFilter);
    octx.drawImage(canvas, crop.x, crop.y, crop.w, crop.h, 0, 0, out.width, out.height);
    octx.filter = "none";
    // Bake text items
    textItems.forEach(item => {
      const fontSize = item.size;
      octx.font = `800 ${fontSize}px Inter, Arial, sans-serif`;
      octx.textAlign = "center";
      octx.textBaseline = "middle";
      const x = item.x * out.width;
      const y = item.y * out.height;
      if (item.strokeW > 0) {
        octx.lineWidth = item.strokeW;
        octx.strokeStyle = "#000";
        octx.lineJoin = "round";
        octx.strokeText(item.text, x, y);
      }
      octx.fillStyle = item.color;
      octx.fillText(item.text, x, y);
    });
    const dataUrl = out.toDataURL("image/jpeg", 0.92);
    if (typeof window._setCustomThumb === "function") {
      // Apply balikkan ke section asal: kalau editor dibuka dari 'frame', save sebagai
      // frame thumb (tidak menyentuh Thumb Kustom preview). Kalau dari 'upload', save
      // sebagai upload thumb (isi Thumb Kustom preview).
      const finalSource = editorOpenedFromSource === "frame" ? "frame" : "upload";
      window._setCustomThumb(dataUrl, "thumbnail-edited.jpg", finalSource);
    }
    if (typeof toast === "function") toast("✓ Thumbnail tersimpan!", "success");
    closeModal();
  });

  // Close handlers
  modal.querySelectorAll("[data-close]").forEach(el => el.addEventListener("click", closeModal));

  // Helper: capture frame video element ke dataURL dengan sanity check
  function captureFrameVideoToDataUrl() {
    const frameVideo = document.getElementById("upFrameVideo");
    const frameCanvas = document.getElementById("upFrameCanvas");
    if (!frameVideo || !frameCanvas) return null;
    const w = frameVideo.videoWidth || 0;
    const h = frameVideo.videoHeight || 0;
    if (w === 0 || h === 0) return null;
    const target = Math.min(1280, w);
    const s = target / w;
    frameCanvas.width = Math.round(w * s);
    frameCanvas.height = Math.round(h * s);
    const fctx = frameCanvas.getContext("2d");
    try {
      fctx.drawImage(frameVideo, 0, 0, frameCanvas.width, frameCanvas.height);
      const dataUrl = frameCanvas.toDataURL("image/jpeg", 0.92);
      if (!dataUrl || dataUrl.length < 1000) {
        console.warn("[ThumbEditor] captured frame suspicious, length:", dataUrl?.length);
        return null;
      }
      return dataUrl;
    } catch (err) {
      console.error("[ThumbEditor] capture failed:", err);
      return null;
    }
  }

  // Wire tombol Edit di Frame Picker — sourceHint 'frame' supaya Apply balikkan
  // ke section Frame Picker, bukan ke Thumbnail Kustom.
  document.getElementById("upFrameEdit")?.addEventListener("click", function () {
    let dataUrl = captureFrameVideoToDataUrl();
    if (!dataUrl && window.pendingUpload?.thumb) dataUrl = window.pendingUpload.thumb;
    if (!dataUrl) {
      if (typeof toast === "function") toast("⚠️ Pilih video dulu, lalu coba lagi", "warning");
      return;
    }
    window._openThumbEditor(dataUrl, "frame");
  });

  // Wire tombol Edit di Thumbnail Kustom — hanya edit _uploadThumb (file upload)
  document.getElementById("upThumbEditBtn")?.addEventListener("click", function (e) {
    e.preventDefault();
    e.stopPropagation();
    if (window._uploadThumb) { window._openThumbEditor(window._uploadThumb, "upload"); return; }
    if (typeof toast === "function") toast("⚠️ Upload thumbnail file dulu sebelum edit", "warning");
  });

  // Wire tombol di applied-preview Frame Picker
  document.getElementById("upFrameAppliedEdit")?.addEventListener("click", function () {
    if (window._frameThumb) { window._openThumbEditor(window._frameThumb, "frame"); return; }
    if (typeof toast === "function") toast("⚠️ Belum ada frame yang dipilih", "warning");
  });
  document.getElementById("upFrameAppliedClear")?.addEventListener("click", function () {
    window._frameThumb = null;
    const fp = document.getElementById("upFrameAppliedPreview");
    if (fp) fp.hidden = true;
    // Kalau active source = 'frame', clear _customThumb juga
    if (window._customThumbSource === "frame") {
      window._customThumb = null;
      window._customThumbSource = window._uploadThumb ? "upload" : null;
      if (window._uploadThumb) window._customThumb = window._uploadThumb;
    }
    if (typeof window._refreshThumbActiveBadges === "function") {
      window._refreshThumbActiveBadges();
    }
    if (typeof toast === "function") toast("Frame dihapus", "info");
  });

  // Tombol Edit Video di dropzone overlay → open Video Editor (BUKAN thumbnail editor).
  // Per request user 2026-05-14: "edit video" beda dari "edit thumbnail".
  document.getElementById("dropzoneEditVideoBtn")?.addEventListener("click", function (e) {
    e.preventDefault();
    e.stopPropagation();
    if (typeof window._openVideoEditor === "function") {
      window._openVideoEditor();
    } else {
      if (typeof toast === "function") toast("⚠️ Video editor belum siap", "warning");
    }
  });
})();

// =====================================================================
// THUMBNAIL EDITOR V2 — REWRITE (bulletproof canvas-paint, per user 2026-05-14)
// Override window._openThumbEditor dengan implementasi canvas-paint single-source:
// - Semua dim crop area, text, dan crop frame DI-PAINT di canvas (no HTML overlay)
// - Mouse events langsung di canvas (no overlay layering issues)
// - Cleaner state management
// Tombol-tombol Edit di section (upFrameEdit, upThumbEditBtn, dll) tetap di-wire
// oleh IIFE wireThumbEditor lama yang call window._openThumbEditor — yang
// implementasinya sekarang di-override oleh V2 ini.
// =====================================================================
(function thumbEditorV2() {
  const modal = document.getElementById("thumbEditorModal");
  const canvas = document.getElementById("teCanvas");
  if (!modal || !canvas) return;
  const ctx = canvas.getContext("2d");

  // Hide HTML crop & text overlays — V2 paint semua di canvas
  const htmlCropOverlay = document.getElementById("teCropOverlay");
  const htmlTextOverlay = document.getElementById("teTextOverlay");
  if (htmlCropOverlay) htmlCropOverlay.hidden = true;
  if (htmlTextOverlay) htmlTextOverlay.hidden = true;
  if (htmlCropOverlay) htmlCropOverlay.style.display = "none";
  if (htmlTextOverlay) htmlTextOverlay.style.display = "none";

  // State
  let img = null;
  let activeTab = "crop";
  let filterName = "none";
  let aspectMode = "free";
  let crop = null;          // { x, y, w, h } in canvas coords (= image-scaled coords)
  let textItems = [];       // { text, size, color, strokeW, xFrac, yFrac }
  let selectedTextIdx = -1;
  let editorSource = "upload";

  const FILTERS = [
    { key: "none",   label: "Asli",   css: "none" },
    { key: "vivid",  label: "Vivid",  css: "saturate(1.4) contrast(1.1)" },
    { key: "warm",   label: "Warm",   css: "sepia(.25) saturate(1.3) hue-rotate(-10deg) brightness(1.05)" },
    { key: "cool",   label: "Cool",   css: "hue-rotate(180deg) saturate(.9) brightness(1.05) contrast(1.05)" },
    { key: "bw",     label: "B&W",    css: "grayscale(1) contrast(1.15)" },
    { key: "sepia",  label: "Sepia",  css: "sepia(.85) brightness(1.05)" },
    { key: "bright", label: "Bright", css: "brightness(1.25) contrast(1.05)" },
    { key: "dark",   label: "Moody",  css: "brightness(.75) contrast(1.25) saturate(1.1)" },
    { key: "fade",   label: "Fade",   css: "contrast(.85) brightness(1.1) saturate(.85)" },
    { key: "drama",  label: "Drama",  css: "contrast(1.35) saturate(1.25) brightness(.95)" },
  ];
  function getFilterCss(key) { return FILTERS.find(f => f.key === key)?.css || "none"; }

  function redraw() {
    ctx.save();
    // Always clear with bg first
    ctx.filter = "none";
    ctx.fillStyle = "#1a1a1d";
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    if (!img) {
      ctx.fillStyle = "#888";
      ctx.font = "20px Inter, sans-serif";
      ctx.textAlign = "center";
      ctx.textBaseline = "middle";
      ctx.fillText("Memuat gambar...", canvas.width / 2, canvas.height / 2);
      ctx.restore();
      return;
    }

    // Draw image (full canvas, filter applied)
    try {
      ctx.filter = getFilterCss(filterName);
      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
      ctx.filter = "none";
    } catch (err) {
      console.error("[ThumbEditorV2] drawImage failed:", err);
      ctx.fillStyle = "#ef4444";
      ctx.font = "16px sans-serif";
      ctx.textAlign = "center";
      ctx.fillText("Error: " + err.message, canvas.width / 2, canvas.height / 2);
      ctx.restore();
      return;
    }

    // Crop dim overlay (only on Crop tab)
    if (activeTab === "crop" && crop) {
      ctx.fillStyle = "rgba(0, 0, 0, 0.55)";
      if (crop.y > 0) ctx.fillRect(0, 0, canvas.width, crop.y);
      if (crop.y + crop.h < canvas.height) ctx.fillRect(0, crop.y + crop.h, canvas.width, canvas.height - crop.y - crop.h);
      if (crop.x > 0) ctx.fillRect(0, crop.y, crop.x, crop.h);
      if (crop.x + crop.w < canvas.width) ctx.fillRect(crop.x + crop.w, crop.y, canvas.width - crop.x - crop.w, crop.h);
      // Border
      ctx.strokeStyle = "#fff";
      ctx.lineWidth = 2;
      ctx.strokeRect(crop.x, crop.y, crop.w, crop.h);
      // Corner handles (filled circles)
      const handles = [
        [crop.x, crop.y],
        [crop.x + crop.w, crop.y],
        [crop.x, crop.y + crop.h],
        [crop.x + crop.w, crop.y + crop.h],
      ];
      handles.forEach(([x, y]) => {
        ctx.beginPath();
        ctx.arc(x, y, 7, 0, Math.PI * 2);
        ctx.fillStyle = "#fff";
        ctx.fill();
        ctx.strokeStyle = "#6D2932";
        ctx.lineWidth = 2;
        ctx.stroke();
      });
    }

    // Text overlays
    textItems.forEach((item, i) => {
      ctx.save();
      ctx.font = `800 ${item.size}px Inter, Arial, sans-serif`;
      ctx.textAlign = "center";
      ctx.textBaseline = "middle";
      const x = item.xFrac * canvas.width;
      const y = item.yFrac * canvas.height;
      if (item.strokeW > 0) {
        ctx.lineWidth = item.strokeW;
        ctx.strokeStyle = "#000";
        ctx.lineJoin = "round";
        ctx.strokeText(item.text, x, y);
      }
      ctx.fillStyle = item.color;
      ctx.fillText(item.text, x, y);
      // Selection box (Text tab only)
      if (activeTab === "text" && i === selectedTextIdx) {
        const m = ctx.measureText(item.text);
        ctx.strokeStyle = "#6366f1";
        ctx.lineWidth = 2;
        ctx.setLineDash([6, 4]);
        ctx.strokeRect(x - m.width/2 - 6, y - item.size*0.55 - 4, m.width + 12, item.size*1.1 + 8);
        ctx.setLineDash([]);
      }
      ctx.restore();
    });

    ctx.restore();
  }

  function setActiveTab(key) {
    activeTab = key;
    modal.querySelectorAll(".te-tab").forEach(t => {
      const a = t.dataset.teTab === key;
      t.classList.toggle("active", a);
      t.setAttribute("aria-selected", a ? "true" : "false");
    });
    modal.querySelectorAll("[data-te-panel]").forEach(p => p.hidden = p.dataset.tePanel !== key);
    redraw();
  }

  function getCanvasPos(e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const cx = (e.touches ? e.touches[0].clientX : e.clientX);
    const cy = (e.touches ? e.touches[0].clientY : e.clientY);
    return { x: (cx - rect.left) * scaleX, y: (cy - rect.top) * scaleY };
  }

  // Mouse drag handlers
  let dragMode = null;
  let dragStart = null;

  canvas.addEventListener("mousedown", function (e) {
    if (!img) return;
    const pos = getCanvasPos(e);
    if (activeTab === "crop" && crop) {
      const hs = 24; // hit area for handle (canvas-pixels)
      if (Math.abs(pos.x - crop.x) < hs && Math.abs(pos.y - crop.y) < hs) dragMode = "nw";
      else if (Math.abs(pos.x - (crop.x + crop.w)) < hs && Math.abs(pos.y - crop.y) < hs) dragMode = "ne";
      else if (Math.abs(pos.x - crop.x) < hs && Math.abs(pos.y - (crop.y + crop.h)) < hs) dragMode = "sw";
      else if (Math.abs(pos.x - (crop.x + crop.w)) < hs && Math.abs(pos.y - (crop.y + crop.h)) < hs) dragMode = "se";
      else if (pos.x > crop.x && pos.x < crop.x + crop.w && pos.y > crop.y && pos.y < crop.y + crop.h) dragMode = "move";
      else return;
      e.preventDefault();
      dragStart = { pos, crop: { ...crop } };
    } else if (activeTab === "text") {
      let hit = -1;
      for (let i = textItems.length - 1; i >= 0; i--) {
        const item = textItems[i];
        ctx.font = `800 ${item.size}px Inter, Arial, sans-serif`;
        const m = ctx.measureText(item.text);
        const x = item.xFrac * canvas.width;
        const y = item.yFrac * canvas.height;
        if (Math.abs(pos.x - x) < m.width/2 + 14 && Math.abs(pos.y - y) < item.size*0.6 + 8) { hit = i; break; }
      }
      selectedTextIdx = hit;
      if (hit >= 0) {
        e.preventDefault();
        dragMode = "text";
        dragStart = { pos, xFrac: textItems[hit].xFrac, yFrac: textItems[hit].yFrac, idx: hit };
      }
      redraw();
    }
  });

  document.addEventListener("mousemove", function (e) {
    if (!dragMode || !dragStart || !img) return;
    const pos = getCanvasPos(e);

    if (dragMode === "text") {
      const dx = (pos.x - dragStart.pos.x) / canvas.width;
      const dy = (pos.y - dragStart.pos.y) / canvas.height;
      const t = textItems[dragStart.idx];
      t.xFrac = Math.max(0, Math.min(1, dragStart.xFrac + dx));
      t.yFrac = Math.max(0, Math.min(1, dragStart.yFrac + dy));
      redraw();
      return;
    }
    if (!crop) return;
    const dx = pos.x - dragStart.pos.x;
    const dy = pos.y - dragStart.pos.y;
    let nx = dragStart.crop.x, ny = dragStart.crop.y;
    let nw = dragStart.crop.w, nh = dragStart.crop.h;
    if (dragMode === "move") { nx += dx; ny += dy; }
    else if (dragMode === "nw") { nx += dx; ny += dy; nw -= dx; nh -= dy; }
    else if (dragMode === "ne") { ny += dy; nw += dx; nh -= dy; }
    else if (dragMode === "sw") { nx += dx; nw -= dx; nh += dy; }
    else if (dragMode === "se") { nw += dx; nh += dy; }

    if (aspectMode !== "free" && dragMode !== "move") {
      const [aw, ah] = aspectMode.split(":").map(Number);
      const r = aw / ah;
      nh = nw / r;
      if (dragMode === "nw" || dragMode === "ne") {
        ny = dragStart.crop.y + (dragStart.crop.h - nh);
      }
    }
    nw = Math.max(50, nw);
    nh = Math.max(50, nh);
    nx = Math.max(0, Math.min(canvas.width - nw, nx));
    ny = Math.max(0, Math.min(canvas.height - nh, ny));
    nw = Math.min(canvas.width - nx, nw);
    nh = Math.min(canvas.height - ny, nh);
    crop.x = nx; crop.y = ny; crop.w = nw; crop.h = nh;
    redraw();
  });

  document.addEventListener("mouseup", function () {
    dragMode = null;
    dragStart = null;
  });

  // Replace old listeners on tabs/aspect/preset/etc by cloning
  function replaceListeners(selector) {
    modal.querySelectorAll(selector).forEach(el => {
      const clone = el.cloneNode(true);
      el.parentNode.replaceChild(clone, el);
    });
  }
  replaceListeners(".te-tab");
  replaceListeners(".te-aspect");
  replaceListeners(".te-color-preset");

  // Tab handlers (V2)
  modal.querySelectorAll(".te-tab").forEach(t => t.addEventListener("click", () => setActiveTab(t.dataset.teTab)));

  // Aspect handlers (V2)
  modal.querySelectorAll(".te-aspect").forEach(p => p.addEventListener("click", function () {
    aspectMode = p.dataset.aspect;
    modal.querySelectorAll(".te-aspect").forEach(x => x.classList.toggle("active", x === p));
    if (aspectMode !== "free" && crop) {
      const [aw, ah] = aspectMode.split(":").map(Number);
      const r = aw / ah;
      crop.h = crop.w / r;
      if (crop.y + crop.h > canvas.height) {
        crop.h = canvas.height - crop.y;
        crop.w = crop.h * r;
      }
      redraw();
    }
  }));

  // Color preset handlers (V2)
  modal.querySelectorAll(".te-color-preset").forEach(c => c.addEventListener("click", function () {
    const colorEl = document.getElementById("teTextColor");
    if (colorEl) colorEl.value = c.dataset.color;
  }));

  // Replace + wire teTextAdd, teTextClear, teReset, teApply, close buttons
  function rewire(id, handler) {
    const el = document.getElementById(id);
    if (!el) return;
    const clone = el.cloneNode(true);
    el.parentNode.replaceChild(clone, el);
    document.getElementById(id).addEventListener("click", handler);
  }

  function renderFilterGrid() {
    const grid = document.getElementById("teFilterGrid");
    if (!grid || !img) return;
    grid.innerHTML = "";
    FILTERS.forEach(f => {
      const item = document.createElement("button");
      item.type = "button";
      item.className = "te-filter-item" + (f.key === filterName ? " active" : "");
      item.dataset.filter = f.key;
      const off = document.createElement("canvas");
      off.width = 80; off.height = 45;
      const offCtx = off.getContext("2d");
      try {
        offCtx.filter = f.css;
        offCtx.drawImage(img, 0, 0, 80, 45);
      } catch {}
      const previewImg = document.createElement("img");
      previewImg.src = off.toDataURL("image/jpeg", 0.7);
      previewImg.alt = f.label;
      const span = document.createElement("span");
      span.textContent = f.label;
      item.append(previewImg, span);
      item.addEventListener("click", () => {
        filterName = f.key;
        grid.querySelectorAll(".te-filter-item").forEach(el => el.classList.toggle("active", el === item));
        redraw();
      });
      grid.appendChild(item);
    });
  }

  rewire("teTextAdd", function () {
    const text = document.getElementById("teTextInput")?.value.trim();
    if (!text) { if (typeof toast === "function") toast("⚠️ Tulis teks dulu", "warning"); return; }
    textItems.push({
      text,
      size: Number(document.getElementById("teTextSize")?.value) || 56,
      color: document.getElementById("teTextColor")?.value || "#ffffff",
      strokeW: Number(document.getElementById("teTextStroke")?.value) || 0,
      xFrac: 0.5, yFrac: 0.5,
    });
    selectedTextIdx = textItems.length - 1;
    const inp = document.getElementById("teTextInput");
    if (inp) inp.value = "";
    redraw();
  });

  rewire("teTextClear", function () {
    textItems = [];
    selectedTextIdx = -1;
    redraw();
  });

  rewire("teReset", function () {
    if (!img) return;
    filterName = "none";
    aspectMode = "free";
    textItems = [];
    selectedTextIdx = -1;
    crop = { x: 0, y: 0, w: canvas.width, h: canvas.height };
    modal.querySelectorAll(".te-aspect").forEach(p => p.classList.toggle("active", p.dataset.aspect === "free"));
    renderFilterGrid();
    redraw();
  });

  rewire("teApply", function () {
    if (!img) return;
    const out = document.createElement("canvas");
    out.width = Math.max(1, Math.round(crop.w));
    out.height = Math.max(1, Math.round(crop.h));
    const octx = out.getContext("2d");
    octx.fillStyle = "#000";
    octx.fillRect(0, 0, out.width, out.height);
    try {
      octx.filter = getFilterCss(filterName);
      const srcX = crop.x * (img.naturalWidth / canvas.width);
      const srcY = crop.y * (img.naturalHeight / canvas.height);
      const srcW = crop.w * (img.naturalWidth / canvas.width);
      const srcH = crop.h * (img.naturalHeight / canvas.height);
      octx.drawImage(img, srcX, srcY, srcW, srcH, 0, 0, out.width, out.height);
      octx.filter = "none";
    } catch (err) {
      console.error("[ThumbEditorV2] apply drawImage failed:", err);
    }
    // Bake text
    textItems.forEach(item => {
      octx.font = `800 ${item.size}px Inter, Arial, sans-serif`;
      octx.textAlign = "center";
      octx.textBaseline = "middle";
      const canvasX = item.xFrac * canvas.width;
      const canvasY = item.yFrac * canvas.height;
      const outX = (canvasX - crop.x) * (out.width / crop.w);
      const outY = (canvasY - crop.y) * (out.height / crop.h);
      if (item.strokeW > 0) {
        octx.lineWidth = item.strokeW;
        octx.strokeStyle = "#000";
        octx.lineJoin = "round";
        octx.strokeText(item.text, outX, outY);
      }
      octx.fillStyle = item.color;
      octx.fillText(item.text, outX, outY);
    });
    const dataUrl = out.toDataURL("image/jpeg", 0.92);
    if (typeof window._setCustomThumb === "function") {
      const finalSrc = editorSource === "frame" ? "frame" : "upload";
      window._setCustomThumb(dataUrl, "thumbnail-edited.jpg", finalSrc);
    }
    if (typeof toast === "function") toast("✓ Thumbnail tersimpan!", "success");
    closeModal();
  });

  function closeModal() {
    modal.classList.remove("show");
    document.body.style.overflow = "";
  }
  modal.querySelectorAll("[data-close]").forEach(el => {
    const clone = el.cloneNode(true);
    el.parentNode.replaceChild(clone, el);
  });
  modal.querySelectorAll("[data-close]").forEach(el => el.addEventListener("click", closeModal));

  // Override window._openThumbEditor
  window._openThumbEditor = function (dataUrl, sourceHint) {
    if (!dataUrl) {
      if (typeof toast === "function") toast("⚠️ Pilih thumbnail dulu sebelum edit", "warning");
      return;
    }
    console.log("[ThumbEditorV2] open called, sourceHint:", sourceHint, "dataUrl length:", dataUrl.length);
    editorSource = sourceHint || window._customThumbSource || "upload";

    // Reset state
    img = null;
    filterName = "none";
    aspectMode = "free";
    textItems = [];
    selectedTextIdx = -1;

    // Show modal & default tab
    modal.classList.add("show");
    document.body.style.overflow = "hidden";
    setActiveTab("crop");
    modal.querySelectorAll(".te-aspect").forEach(p => p.classList.toggle("active", p.dataset.aspect === "free"));

    // Placeholder canvas — fixed landscape 1280×720 supaya layout predictable
    // regardless source aspect (portrait/landscape/square). Image akan
    // di-letterbox di dalam canvas.
    canvas.width = 1280;
    canvas.height = 720;
    redraw();

    // Load image
    const newImg = new Image();
    newImg.onload = function () {
      console.log("[ThumbEditorV2] image loaded:", newImg.naturalWidth, "×", newImg.naturalHeight);
      if (!newImg.naturalWidth || !newImg.naturalHeight) {
        if (typeof toast === "function") toast("⚠️ Image 0×0 — coba pilih ulang", "warning");
        return;
      }
      img = newImg;
      // Canvas size = fit image into 1280×720 bounding box preserving aspect.
      // Untuk portrait image (e.g., 576×1024 dari TikTok-style video), canvas
      // jadi 405×720 sehingga display di modal selalu fit dengan benar.
      const maxW = 1280, maxH = 720;
      const imgW = newImg.naturalWidth, imgH = newImg.naturalHeight;
      const scale = Math.min(maxW / imgW, maxH / imgH);
      const cw = Math.max(100, Math.round(imgW * scale));
      const ch = Math.max(100, Math.round(imgH * scale));
      canvas.width = cw;
      canvas.height = ch;
      crop = { x: 0, y: 0, w: cw, h: ch };
      console.log("[ThumbEditorV2] canvas sized:", cw, "×", ch);
      renderFilterGrid();
      redraw();
    };
    newImg.onerror = function () {
      console.error("[ThumbEditorV2] image load failed for dataUrl length", dataUrl.length);
      if (typeof toast === "function") toast("⚠️ Gagal load thumbnail untuk edit", "error");
      closeModal();
    };
    newImg.src = dataUrl;
  };

  console.log("[ThumbEditorV2] ready — _openThumbEditor overridden");
})();

// =====================================================================
// VIDEO EDITOR MODAL — Trim / Speed / Mute (metadata-only)
// Per request user 2026-05-14. Tidak mengubah file asli; metadata
// disimpan di pendingUpload.videoEdit dan di-apply saat playback.
// =====================================================================
(function wireVideoEditor() {
  const modal = document.getElementById("videoEditorModal");
  const video = document.getElementById("veVideo");
  // Match HTML IDs di #videoEditorModal (per fix user 2026-05-14 v10)
  const timeCurEl   = document.getElementById("veTimeCurrent");
  const timeTotalEl = document.getElementById("veTimeTotal");
  const trimTrack   = document.getElementById("veTrimTrack");
  const trimRange   = document.getElementById("veTrimRange");
  const trimStartH  = document.getElementById("veTrimStart");
  const trimEndH    = document.getElementById("veTrimEnd");
  const trimPlayhead = document.getElementById("veTrimPlayhead");
  const startTimeEl = document.getElementById("veStartTime");
  const endTimeEl   = document.getElementById("veEndTime");
  const durTimeEl   = document.getElementById("veDurationTime");
  const speedPills  = modal?.querySelectorAll(".ve-speed");
  const muteCb      = document.getElementById("veMute");
  const previewBtn  = document.getElementById("vePreviewBtn");
  const resetBtn    = document.getElementById("veReset");
  const applyBtn    = document.getElementById("veApply");
  // v681: preview btn now has icon + label span — update only the label text
  // so the SVG icon is preserved across play/pause toggles.
  function setPreviewLabel(txt) {
    if (!previewBtn) return;
    const lbl = previewBtn.querySelector(".ve-preview-label");
    if (lbl) lbl.textContent = txt; else previewBtn.textContent = txt;
  }

  if (!modal || !video) {
    console.warn("[VideoEditor] modal or video element missing");
    return;
  }
  console.log("[VideoEditor] ready");

  let duration = 0;
  let trimStart = 0;
  let trimEnd = 0;
  let speed = 1;
  let muted = false;
  let previewMode = false;

  function fmtT(sec) {
    if (!isFinite(sec) || sec < 0) sec = 0;
    const m = Math.floor(sec / 60);
    const s = Math.floor(sec % 60);
    return `${m}:${String(s).padStart(2, "0")}`;
  }

  function updateTrimUI() {
    if (!duration) return;
    const startPct = (trimStart / duration) * 100;
    const endPct = (trimEnd / duration) * 100;
    if (trimRange) {
      trimRange.style.left = startPct + "%";
      trimRange.style.width = (endPct - startPct) + "%";
    }
    if (trimStartH) trimStartH.style.left = startPct + "%";
    if (trimEndH)   trimEndH.style.left = endPct + "%";
    if (startTimeEl) startTimeEl.textContent = fmtT(trimStart);
    if (endTimeEl)   endTimeEl.textContent = fmtT(trimEnd);
    if (durTimeEl)   durTimeEl.textContent = fmtT(trimEnd - trimStart);
  }

  function updatePlayhead() {
    if (!duration) return;
    const pct = (video.currentTime / duration) * 100;
    if (trimPlayhead) trimPlayhead.style.left = pct + "%";
    if (timeCurEl) timeCurEl.textContent = fmtT(video.currentTime);
  }

  function closeModal() {
    modal.classList.remove("show");
    modal.style.display = "";  // Remove inline style supaya CSS-driven show/hide bekerja next time
    document.body.style.overflow = "";
    try { video.pause(); } catch {}
    previewMode = false;
    if (previewBtn) setPreviewLabel("Putar Preview");
  }

  window._openVideoEditor = function () {
    console.log("[VideoEditor] open called");
    // Akses pendingUpload via top-level binding (let, BUKAN window.pendingUpload).
    // window.pendingUpload selalu undefined karena let tidak attach ke window.
    // Per fix user 2026-05-14 v13.
    const pu = (typeof pendingUpload !== "undefined" && pendingUpload) ? pendingUpload : null;
    if (!pu || !pu.videoUrl) {
      console.warn("[VideoEditor] no pendingUpload.videoUrl", { pu });
      if (typeof toast === "function") toast("⚠️ Pilih video dulu", "warning");
      return;
    }
    // Force-show modal FIRST (no race with potential video load errors)
    modal.classList.add("show");
    modal.style.display = "flex";  // Failsafe: override any CSS display:none rules
    document.body.style.overflow = "hidden";
    console.log("[VideoEditor] modal classes:", modal.className, "computed display:", getComputedStyle(modal).display);

    video.src = pu.videoUrl;
    video.muted = false;
    video.playbackRate = 1;
    const prev = pu.videoEdit || {};
    speed = prev.speed || 1;
    muted = !!prev.muted;
    speedPills?.forEach(p => p.classList.toggle("active", Number(p.dataset.speed) === speed));
    if (muteCb) muteCb.checked = muted;
    video.muted = muted;
    video.playbackRate = speed;

    video.addEventListener("loadedmetadata", function onMeta() {
      video.removeEventListener("loadedmetadata", onMeta);
      duration = video.duration || 0;
      if (timeTotalEl) timeTotalEl.textContent = fmtT(duration);
      trimStart = prev.trimStart != null ? Math.max(0, Math.min(prev.trimStart, duration)) : 0;
      trimEnd = prev.trimEnd != null ? Math.max(trimStart + 0.1, Math.min(prev.trimEnd, duration)) : duration;
      video.currentTime = trimStart;
      updateTrimUI();
      updatePlayhead();
      console.log("[VideoEditor] loaded, dur=", duration);
    }, { once: true });
    // Modal sudah di-show di atas (force display:flex). No-op duplicate dihapus.
  };

  video?.addEventListener("timeupdate", function () {
    updatePlayhead();
    if (previewMode && video.currentTime >= trimEnd) {
      video.pause();
      previewMode = false;
      if (previewBtn) setPreviewLabel("Putar Preview");
    }
  });

  // Drag handlers for trim handles
  let dragHandle = null;
  function onPointerDown(e) {
    const handle = e.target.closest(".ve-trim-handle");
    if (!handle) return;
    e.preventDefault();
    dragHandle = handle.dataset.handle;
  }
  function onPointerMove(e) {
    if (!dragHandle || !duration || !trimTrack) return;
    const rect = trimTrack.getBoundingClientRect();
    const x = (e.clientX !== undefined ? e.clientX : (e.touches && e.touches[0]?.clientX)) || 0;
    let pct = (x - rect.left) / rect.width;
    pct = Math.max(0, Math.min(1, pct));
    const t = pct * duration;
    if (dragHandle === "start") {
      trimStart = Math.min(t, trimEnd - 0.1);
      video.currentTime = trimStart;
    } else {
      trimEnd = Math.max(t, trimStart + 0.1);
      video.currentTime = trimEnd;
    }
    updateTrimUI();
  }
  function onPointerUp() { dragHandle = null; }
  trimTrack?.addEventListener("mousedown", onPointerDown);
  document.addEventListener("mousemove", onPointerMove);
  document.addEventListener("mouseup", onPointerUp);

  // Click on track (not handle) = seek video
  trimTrack?.addEventListener("click", function (e) {
    if (e.target.closest(".ve-trim-handle")) return;
    if (!duration) return;
    const rect = trimTrack.getBoundingClientRect();
    const pct = (e.clientX - rect.left) / rect.width;
    video.currentTime = pct * duration;
  });

  // Speed pills
  speedPills?.forEach(p => p.addEventListener("click", function () {
    speed = Number(p.dataset.speed) || 1;
    speedPills.forEach(x => x.classList.toggle("active", x === p));
    video.playbackRate = speed;
  }));

  // Mute toggle
  muteCb?.addEventListener("change", function () {
    muted = muteCb.checked;
    video.muted = muted;
  });

  // Preview button — play dari trimStart ke trimEnd
  previewBtn?.addEventListener("click", function () {
    if (previewMode) {
      video.pause();
      previewMode = false;
      setPreviewLabel("Putar Preview");
      return;
    }
    video.currentTime = trimStart;
    video.playbackRate = speed;
    video.muted = muted;
    previewMode = true;
    setPreviewLabel("Pause Preview");
    video.play().catch(err => console.warn("[VideoEditor] play failed:", err));
  });

  // Reset
  resetBtn?.addEventListener("click", function () {
    trimStart = 0;
    trimEnd = duration;
    speed = 1;
    muted = false;
    speedPills?.forEach(p => p.classList.toggle("active", Number(p.dataset.speed) === 1));
    if (muteCb) muteCb.checked = false;
    video.muted = false;
    video.playbackRate = 1;
    video.currentTime = 0;
    updateTrimUI();
  });

  // Apply
  applyBtn?.addEventListener("click", function () {
    const pu = (typeof pendingUpload !== "undefined" && pendingUpload) ? pendingUpload : null;
    if (!pu) { closeModal(); return; }
    pu.videoEdit = {
      trimStart: trimStart,
      trimEnd: trimEnd,
      speed: speed,
      muted: muted,
    };
    const trimmedDur = (trimEnd - trimStart) / speed;
    const durStr = fmtT(trimmedDur);
    const upDur = document.getElementById("uploadPreviewDuration");
    if (upDur) upDur.textContent = durStr + " (trim)";
    if (typeof toast === "function") toast("✓ Edit video tersimpan!", "success");
    closeModal();
  });

  modal.querySelectorAll("[data-close]").forEach(el => el.addEventListener("click", closeModal));
})();

// =====================================================================
// UPLOAD — CUSTOM DROPDOWN (Kategori) — scrollable popup
// Native select dropdown popup tidak bisa di-scroll saat opsi banyak.
// Per request user 2026-05-14. Pattern: hidden #upCategory.value tetap
// jadi source of truth supaya code lama (startUpload) tidak break.
// =====================================================================
(function wireCategoryDropdown() {
  const wrap    = document.getElementById("upCategorySelect");
  const trigger = document.getElementById("upCategoryTrigger");
  const pop     = document.getElementById("upCategoryPop");
  const labelEl = document.getElementById("upCategoryLabel");
  const hidden  = document.getElementById("upCategory");
  if (!wrap || !trigger || !pop || !labelEl || !hidden) return;

  const defaultLabel = "— pilih kategori —";

  function open() {
    pop.hidden = false;
    trigger.setAttribute("aria-expanded", "true");
    // Scroll selected option ke view kalau ada
    const selected = pop.querySelector('.ucs-option[aria-selected="true"]');
    if (selected) {
      try { selected.scrollIntoView({ block: "nearest" }); } catch {}
    }
  }
  function close() {
    pop.hidden = true;
    trigger.setAttribute("aria-expanded", "false");
    // Clear keyboard-active state
    pop.querySelectorAll(".ucs-option.active").forEach(o => o.classList.remove("active"));
  }
  function toggle() { pop.hidden ? open() : close(); }

  function selectValue(value, label, fireChange = true) {
    hidden.value = value || "";
    labelEl.textContent = label || defaultLabel;
    pop.querySelectorAll(".ucs-option").forEach(o => {
      o.setAttribute("aria-selected", o.dataset.value === (value || "") ? "true" : "false");
    });
    if (fireChange) hidden.dispatchEvent(new Event("change", { bubbles: true }));
  }
  // Initial selection
  selectValue(hidden.value || "", defaultLabel, false);

  // Expose reset helper supaya startUpload bisa reset kategori setelah upload
  window._resetUpCategory = function () { selectValue("", defaultLabel, false); };

  trigger.addEventListener("click", function (e) {
    e.preventDefault();
    e.stopPropagation();
    toggle();
  });

  pop.addEventListener("click", function (e) {
    const opt = e.target.closest(".ucs-option");
    if (!opt) return;
    selectValue(opt.dataset.value, opt.dataset.label || opt.textContent.trim());
    close();
    trigger.focus();
  });

  // Close on outside click
  document.addEventListener("click", function (e) {
    if (pop.hidden) return;
    if (wrap.contains(e.target)) return;
    close();
  });

  // Keyboard nav: Esc, Enter, ArrowUp/Down
  trigger.addEventListener("keydown", function (e) {
    if (e.key === "ArrowDown" || e.key === "Enter" || e.key === " ") {
      e.preventDefault();
      if (pop.hidden) open();
      const first = pop.querySelector(".ucs-option");
      if (first) {
        pop.querySelectorAll(".ucs-option.active").forEach(o => o.classList.remove("active"));
        first.classList.add("active");
        first.scrollIntoView({ block: "nearest" });
      }
    }
  });
  document.addEventListener("keydown", function (e) {
    if (pop.hidden) return;
    if (e.key === "Escape") {
      e.preventDefault();
      close();
      trigger.focus();
      return;
    }
    const opts = Array.from(pop.querySelectorAll(".ucs-option"));
    if (opts.length === 0) return;
    let idx = opts.findIndex(o => o.classList.contains("active"));
    if (e.key === "ArrowDown") {
      e.preventDefault();
      idx = (idx + 1) % opts.length;
      opts.forEach(o => o.classList.remove("active"));
      opts[idx].classList.add("active");
      opts[idx].scrollIntoView({ block: "nearest" });
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      idx = idx <= 0 ? opts.length - 1 : idx - 1;
      opts.forEach(o => o.classList.remove("active"));
      opts[idx].classList.add("active");
      opts[idx].scrollIntoView({ block: "nearest" });
    } else if (e.key === "Enter") {
      if (idx >= 0) {
        e.preventDefault();
        const o = opts[idx];
        selectValue(o.dataset.value, o.dataset.label || o.textContent.trim());
        close();
        trigger.focus();
      }
    }
  });
})();

// =====================================================================
// UPLOAD — AI ASSIST (Premium-only) — generate title/desc/tags otomatis
// dari subtitle transcript + filename + category. Per request user 2026-05-14.
// Bukan AI sungguhan — deterministic generator dari signal yang ada di form.
// =====================================================================
(function wireUploadAiAssist() {
  const card = document.getElementById("upAiAssist");
  if (!card) return;
  const noteEl = document.getElementById("upAiNote");

  function isPremium() {
    // Pakai sumber kanonik yang sama dengan badge "Premium AKTIF" di topbar.
    if (typeof isPremiumActive === "function" && isPremiumActive(user)) return true;
    if (user && (user.tier === "premium" || user.role === "admin")) return true;
    return document.body.dataset.tier === "premium";
  }
  function gatedToast() {
    if (typeof toast === "function") toast("⭐ AI Assist hanya untuk Premium. Upgrade dulu yuk!", "warning");
  }

  // Cleanup transcript → words
  function getTranscriptWords() {
    const vtt = window._uploadSubtitle?.vtt || "";
    if (!vtt) return [];
    return vtt
      .replace(/WEBVTT[^\n]*/i, "")
      .replace(/\d{2}:\d{2}:\d{2}\.\d{3}\s*-->\s*\d{2}:\d{2}:\d{2}\.\d{3}/g, " ")
      .replace(/<[^>]+>/g, " ")
      .replace(/[^a-zA-Z0-9À-ɏ\s]/g, " ")
      .toLowerCase()
      .split(/\s+/)
      .filter(w => w.length > 3);
  }
  // Stopwords ID + EN (mini list)
  const STOP = new Set("yang dan atau ini itu ada saya kamu mereka sebuah dalam pada untuk dari dengan tidak juga akan tapi tetapi bisa harus sudah karena kalau jika sebagai banyak sekali masih the and for that this with from your you have are was were will would been just like what when why how about over under into your they been them their there will been have all not but can has its any our some such only also more most very much even still your other another about which while their there those these where here now then over only also so up down out off been very what should could".split(/\s+/));

  function topKeywords(words, k) {
    const freq = {};
    for (const w of words) {
      if (STOP.has(w) || /^\d+$/.test(w)) continue;
      freq[w] = (freq[w] || 0) + 1;
    }
    return Object.entries(freq)
      .sort((a, b) => b[1] - a[1])
      .slice(0, k)
      .map(([w]) => w);
  }

  function cap(s) { return s ? s.charAt(0).toUpperCase() + s.slice(1) : s; }

  function generateTitle() {
    const words = getTranscriptWords();
    const cat = document.getElementById("upCategory")?.value || "";
    const fileName = (window.pendingUpload?.file?.name || "").replace(/\.[^.]+$/, "");
    const top = topKeywords(words, 4);
    let title;
    if (top.length >= 2) {
      const catLabel = cat ? cap(cat) : "Video";
      const main = top.slice(0, 3).map(cap).join(" ");
      title = `${catLabel}: ${main} — Wajib Tonton!`;
    } else if (fileName) {
      title = `${cap(fileName)} | Video Terbaru ${cap(cat || "Kreator")}`;
    } else {
      title = `Video ${cap(cat || "Kreator")} Terbaru — Wajib Tonton!`;
    }
    return title.slice(0, 100);
  }

  function generateDesc() {
    const words = getTranscriptWords();
    const cat = document.getElementById("upCategory")?.value || "";
    const top = topKeywords(words, 6);
    const tagsLine = top.length
      ? top.map(t => "#" + t).join(" ")
      : (cat ? `#${cat} #playly` : "#playly #video");
    const intro = top.length >= 3
      ? `Di video ini kita bahas seputar ${top.slice(0, 3).join(", ")}.`
      : `Konten ${cap(cat || "video")} terbaru dari channel ini.`;
    const cta = `Jangan lupa like, komentar, dan follow ya supaya nggak ketinggalan update video selanjutnya!`;
    const sections = [
      intro,
      "",
      "📌 Yang dibahas di video:",
      top.length ? top.slice(0, 5).map((w, i) => `${i + 1}. ${cap(w)}`).join("\n") : "1. Pembahasan utama\n2. Tips & insight\n3. Q&A penutup",
      "",
      cta,
      "",
      "💬 Diskusi di kolom komentar — share pendapatmu!",
      "",
      tagsLine,
    ];
    return sections.join("\n").slice(0, 2000);
  }

  function generateTags() {
    const words = getTranscriptWords();
    const cat = document.getElementById("upCategory")?.value || "";
    const top = topKeywords(words, 8);
    const base = cat ? [cat, "playly"] : ["playly", "video"];
    const combined = [...base, ...top].slice(0, 10);
    return [...new Set(combined)];
  }

  // ---- NEW FLOW (per request user 2026-05-16): user ketik judul/TOPIK →
  // AI (heuristik lokal, bukan AI sungguhan) kasih PAKET referensi: beberapa
  // saran judul + draft deskripsi + daftar tag, masing-masing ada tombol
  // "Pakai" yang isi ke form upload. generateTitle/Desc/Tags lama (berbasis
  // transcript video) dibiarkan = dead code, tidak dipanggil lagi.
  // HTML hasil dibangun via string-concat single-quote — NO backtick.
  const genBtn = document.getElementById("upAiGenBtn");
  const topicInput = document.getElementById("upAiTopic");
  const resultEl = document.getElementById("upAiResult");
  let lastPkg = null;

  function cleanTopic(s) { return String(s || "").replace(/\s+/g, " ").trim(); }
  function topicWords(tp) {
    return cleanTopic(tp).toLowerCase()
      .replace(/[^a-z0-9À-ɏ\s]/gi, " ")
      .split(/\s+/)
      .filter(w => w.length > 2 && !STOP.has(w));
  }
  function titleCase(s) {
    return cleanTopic(s).replace(/\b\w/g, c => c.toUpperCase());
  }
  function esc(s) {
    if (typeof escapeHtml === "function") return escapeHtml(String(s));
    return String(s).replace(/[&<>"]/g, c => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" }[c]));
  }

  function genTitles(topic) {
    const T = titleCase(topic);
    const cand = [
      T,
      "Cara " + T + " yang Wajib Kamu Tahu",
      T + " — Tips Anti Gagal untuk Pemula",
      "Rahasia " + T + " ala Pro",
      "5 Hal Penting Soal " + T,
      T + " Lengkap dari Nol sampai Bisa"
    ];
    const seen = {}; const out = [];
    cand.forEach(s => {
      const v = s.slice(0, 100).trim();
      const k = v.toLowerCase();
      if (v && !seen[k]) { seen[k] = 1; out.push(v); }
    });
    return out.slice(0, 5);
  }
  function genTags(topic) {
    const w = topicWords(topic);
    const cat = document.getElementById("upCategory")?.value || "";
    const base = cat ? [cat, "playly"] : ["playly", "video"];
    return [...new Set([...base, ...w])].slice(0, 10);
  }
  function genDesc(topic) {
    const T = cleanTopic(topic);
    const w = topicWords(topic);
    const cat = document.getElementById("upCategory")?.value || "";
    const tagSrc = w.length ? w : (cat ? [cat] : ["video"]);
    const tagLine = tagSrc.slice(0, 6).map(x => "#" + x).join(" ");
    const pts = w.length >= 3
      ? w.slice(0, 5).map((x, i) => (i + 1) + ". " + cap(x)).join("\n")
      : "1. Pengenalan " + (T || "topik") + "\n2. Langkah / pembahasan utama\n3. Tips & kesalahan umum\n4. Penutup & Q&A";
    return [
      "Di video ini kita bahas tentang " + (T || "topik ini") + ".",
      "",
      "Yang dibahas di video:",
      pts,
      "",
      "Jangan lupa like, komentar, dan follow biar nggak ketinggalan video berikutnya!",
      "",
      tagLine
    ].join("\n").slice(0, 2000);
  }

  function renderResult(pkg) {
    if (!resultEl) return;
    const H = [];
    H.push('<div class="upf-air-sec"><div class="upf-air-h">' + esc(t("upload.ai.res.titles")) + '</div>');
    pkg.titles.forEach(tt => {
      H.push('<div class="upf-air-row"><span class="upf-air-txt">' + esc(tt) +
        '</span><button type="button" class="upf-ai-use" data-apply="title" data-val="' + esc(tt) + '">' +
        esc(t("upload.ai.use")) + '</button></div>');
    });
    H.push('</div>');
    H.push('<div class="upf-air-sec"><div class="upf-air-h">' + esc(t("upload.ai.res.desc")) +
      '<button type="button" class="upf-ai-use" data-apply="desc">' + esc(t("upload.ai.use")) + '</button></div>');
    H.push('<div class="upf-air-desc">' + esc(pkg.desc) + '</div></div>');
    H.push('<div class="upf-air-sec"><div class="upf-air-h">' + esc(t("upload.ai.res.tags")) +
      '<button type="button" class="upf-ai-use" data-apply="tags">' + esc(t("upload.ai.use")) + '</button></div>');
    H.push('<div class="upf-air-tags">');
    pkg.tags.forEach(tg => { H.push('<span class="upf-air-tag">#' + esc(tg) + '</span>'); });
    H.push('</div></div>');
    resultEl.innerHTML = H.join("");
    resultEl.hidden = false;
  }

  if (genBtn) {
    genBtn.addEventListener("click", function (e) {
      e.preventDefault();
      if (!isPremium()) { gatedToast(); return; }
      const topic = cleanTopic(topicInput ? topicInput.value : "");
      if (!topic) {
        if (typeof toast === "function") toast(t("upload.ai.empty"), "warning");
        if (topicInput) topicInput.focus();
        return;
      }
      genBtn.disabled = true;
      genBtn.classList.add("is-loading");
      setTimeout(() => {
        try {
          lastPkg = { titles: genTitles(topic), desc: genDesc(topic), tags: genTags(topic) };
          renderResult(lastPkg);
          if (typeof toast === "function") toast(t("upload.ai.generated"), "success");
        } finally {
          genBtn.disabled = false;
          genBtn.classList.remove("is-loading");
        }
      }, 550);
    });
    if (topicInput) {
      topicInput.addEventListener("keydown", function (e) {
        if (e.key === "Enter") { e.preventDefault(); genBtn.click(); }
      });
    }
  }

  if (resultEl) {
    resultEl.addEventListener("click", function (e) {
      const b = e.target.closest(".upf-ai-use");
      if (!b) return;
      e.preventDefault();
      const kind = b.dataset.apply;
      if (kind === "title") {
        const el = document.getElementById("upTitle");
        if (el) { el.value = (b.dataset.val || "").slice(0, 100); el.dispatchEvent(new Event("input", { bubbles: true })); }
      } else if (kind === "desc") {
        const d = document.getElementById("upDesc");
        if (d && lastPkg) { d.value = lastPkg.desc; d.dispatchEvent(new Event("input", { bubbles: true })); }
      } else if (kind === "tags") {
        if (lastPkg && typeof window._setUploadTags === "function") window._setUploadTags(lastPkg.tags);
      }
      if (typeof toast === "function") toast(t("upload.ai.applied"), "success");
    });
  }

  // Update note saat tier user berubah. Soft state untuk Free user: pakai
  // sparkle icon (✨ aspirational) bukan lock icon (🔒 punitive).
  function refreshAiNote() {
    if (topicInput) topicInput.placeholder = t("upload.ai.topic.ph");
    if (!noteEl) return;
    if (!isPremium()) {
      const ICO_SPARK = '<svg class="upf-spark-ico" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 3v3M12 18v3M3 12h3M18 12h3M5.6 5.6l2.1 2.1M16.3 16.3l2.1 2.1M5.6 18.4l2.1-2.1M16.3 7.7l2.1-2.1"/></svg>';
      noteEl.innerHTML = ICO_SPARK + " " + t("upload.ai.note.locked");
      noteEl.hidden = false;
      card.classList.add("locked");
    } else {
      noteEl.innerHTML = "";
      noteEl.hidden = true;
      card.classList.remove("locked");
    }
  }
  refreshAiNote();
  // BUGFIX 2026-05-16: dulu listen `document` + "playly:viewchange" — event
  // itu TIDAK PERNAH ada (app dispatch `window` + "playly:view-changed", lihat
  // ~26436). Akibatnya refreshAiNote cuma jalan sekali saat load (user msh
  // null → terkunci) & tidak pernah refresh walau akun Premium. Fix: pakai
  // event + target yang benar + cloud-applied (login selesai) + delayed recheck.
  window.addEventListener("playly:view-changed", refreshAiNote);
  window.addEventListener("playly:cloud-applied", refreshAiNote);
  setTimeout(refreshAiNote, 900);
})();

// Thumbnail custom upload — drag-drop + hover overlay (Upload/Trash) + filename row
(function() {
  const thumbLabel = $("#upThumbLabel");
  const thumbInput = $("#upThumbInput"), thumbPreview = $("#upThumbPreview");
  const thumbClear = $("#upThumbClear");
  const thumbReplaceBtn = $("#upThumbReplaceBtn");
  const thumbMeta = $("#upThumbMeta"), thumbName = $("#upThumbName"), thumbMetaX = $("#upThumbMetaX");
  if (!thumbInput || !thumbLabel) return;

  function setFilled(dataUrl, filename) {
    thumbPreview.src = dataUrl;
    thumbLabel.dataset.state = "filled";
    if (thumbMeta && thumbName) {
      thumbName.textContent = filename || "";
      thumbMeta.hidden = !filename;
    }
    window._customThumb = dataUrl;
    // Track upload-side thumbnail terpisah (per request user 2026-05-14)
    window._uploadThumb = dataUrl;
    // Auto-open media preview popup
    if (typeof openMediaPreview === "function") {
      openMediaPreview({ type: "image", src: dataUrl, filename });
    }
  }
  function setEmpty() {
    thumbInput.value = "";
    thumbPreview.removeAttribute("src");
    thumbLabel.dataset.state = "empty";
    if (thumbMeta) thumbMeta.hidden = true;
    if (thumbName) thumbName.textContent = "";
    window._customThumb = null;
    window._uploadThumb = null;
  }

  function pickFile(f) {
    if (!f) return;
    if (f.size > 2 * 1024 * 1024) return toast("⚠️ Thumbnail max 2 MB", "warning");
    if (!/^image\//.test(f.type)) return toast("⚠️ File harus gambar (JPG/PNG/WebP)", "warning");
    const reader = new FileReader();
    reader.onload = e => {
      setFilled(e.target.result, f.name);
      // Track source = 'upload' supaya badge "✓ Aktif" muncul di Thumbnail Kustom
      window._customThumbSource = "upload";
      if (typeof window._refreshThumbActiveBadges === "function") {
        window._refreshThumbActiveBadges();
      }
    };
    reader.readAsDataURL(f);
  }

  thumbInput.addEventListener("change", () => pickFile(thumbInput.files?.[0]));

  // Drag & drop on the label
  ["dragenter", "dragover"].forEach(ev =>
    thumbLabel.addEventListener(ev, e => { e.preventDefault(); thumbLabel.classList.add("is-dragging"); })
  );
  ["dragleave", "drop"].forEach(ev =>
    thumbLabel.addEventListener(ev, e => { e.preventDefault(); thumbLabel.classList.remove("is-dragging"); })
  );
  thumbLabel.addEventListener("drop", e => {
    const f = e.dataTransfer.files?.[0];
    if (f && f.type.startsWith("image/")) pickFile(f);
  });
  thumbLabel.addEventListener("click", e => {
    if (e.target.closest(".dz-pro-action")) return;
    // Saat filled, klik body thumbnail → buka popup pratinjau (per request 2026-05-10)
    if (thumbLabel.dataset.state === "filled") {
      e.preventDefault();
      if (window._customThumb && typeof openMediaPreview === "function") {
        openMediaPreview({
          type: "image",
          src: window._customThumb,
          filename: thumbName?.textContent || "thumbnail"
        });
      }
      return;
    }
  });

  thumbReplaceBtn?.addEventListener("click", e => {
    e.preventDefault(); e.stopPropagation();
    thumbInput.click();
  });
  thumbClear?.addEventListener("click", e => {
    e.preventDefault(); e.stopPropagation();
    setEmpty();
  });
  thumbMetaX?.addEventListener("click", e => {
    e.preventDefault(); e.stopPropagation();
    setEmpty();
  });

  window._customThumb = null;
  window._customThumbSource = null;  // 'upload' | 'frame' | 'editor' | null
  // Per request user 2026-05-14: Frame Picker preview & Thumbnail Kustom preview TIDAK SHARE.
  // _frameThumb = thumbnail dari frame video (live di section Frame Picker)
  // _uploadThumb = thumbnail dari file upload (live di section Thumbnail Kustom)
  // _customThumb = LATEST active value (yang akan dipakai saat upload final)
  window._frameThumb = null;
  window._uploadThumb = null;

  window._clearCustomThumb = function () {
    setEmpty();
    window._customThumb = null;
    window._customThumbSource = null;
    window._frameThumb = null;
    window._uploadThumb = null;
    const fp = document.getElementById("upFrameAppliedPreview");
    if (fp) fp.hidden = true;
    if (typeof window._refreshThumbActiveBadges === "function") {
      window._refreshThumbActiveBadges();
    }
  };

  // _setCustomThumb — source-aware. Hanya source 'upload' atau 'editor-from-upload'
  // yang isi preview Thumbnail Kustom. Source 'frame' atau 'editor-from-frame'
  // tidak menyentuh Thumbnail Kustom — hanya track internal + tampil di Frame Picker.
  window._setCustomThumb = function (dataUrl, filename, source) {
    const src = source || "upload";
    window._customThumb = dataUrl;
    window._customThumbSource = src;
    if (src === "frame") {
      // Frame Picker source — JANGAN isi Thumbnail Kustom preview.
      window._frameThumb = dataUrl;
      // Update Frame Picker applied-preview (kalau elemen ada)
      const fpImg = document.getElementById("upFrameAppliedThumb");
      const fpSection = document.getElementById("upFrameAppliedPreview");
      if (fpImg) fpImg.src = dataUrl;
      if (fpSection) fpSection.hidden = false;
    } else {
      // 'upload' atau 'editor' — isi Thumbnail Kustom preview
      window._uploadThumb = dataUrl;
      setFilled(dataUrl, filename || "");
    }
    if (typeof window._refreshThumbActiveBadges === "function") {
      window._refreshThumbActiveBadges();
    }
  };

})();

// =================== MEDIA PREVIEW POPUP ===================
// Auto-open saat user upload video / thumbnail. Card hover-style dgn play
// bar animation. Per request user 2026-05-10.
(function() {
  const modal = document.getElementById("mediaPreviewModal");
  if (!modal) return;
  const wrap = document.getElementById("mpmMediaWrap");
  const titleEl = document.getElementById("mpmTitle");
  const filenameEl = document.getElementById("mpmFilename");

  window.openMediaPreview = function({ type, src, filename }) {
    if (!wrap) return;
    wrap.innerHTML = "";
    const card = document.getElementById("mediaPreviewCard");
    // Reset aspect-ratio sebelum load — biar pas media baru di-set ulang sesuai
    // dimensi asli, gak nyangkut ke ratio media sebelumnya.
    if (card) card.style.aspectRatio = "";
    if (type === "video") {
      const v = document.createElement("video");
      v.src = src;
      v.muted = true;                     // mulai muted — tidak surprise sound
      v.volume = 0.3;                     // volume default rendah saat user unmute
      v.playsInline = true;
      v.preload = "metadata";
      v.controls = true;                  // native HTML5 controls (play, volume slider, mute, scrubber, fullscreen)
      v.setAttribute("controlsList", "nodownload noplaybackrate noremoteplayback");
      v.disablePictureInPicture = true;   // hide picture-in-picture button
      v.addEventListener("loadedmetadata", () => {
        // Set aspect-ratio card sesuai dimensi asli video (16:9, 9:16, 1:1, dst.)
        if (card && v.videoWidth && v.videoHeight) {
          card.style.aspectRatio = `${v.videoWidth} / ${v.videoHeight}`;
        }
      });
      // Auto-play saat user hover ke card; pause saat leave.
      // User tetap bisa unmute + atur volume via native control.
      if (card) {
        card.addEventListener("mouseenter", () => v.play().catch(() => {}));
        card.addEventListener("mouseleave", () => { v.pause(); });
      }
      wrap.appendChild(v);
      if (titleEl) titleEl.textContent = "Pratinjau Video";
    } else {
      const img = document.createElement("img");
      img.src = src;
      img.alt = filename || "Pratinjau thumbnail";
      img.addEventListener("load", () => {
        // Set aspect-ratio card sesuai dimensi asli foto thumbnail
        if (card && img.naturalWidth && img.naturalHeight) {
          card.style.aspectRatio = `${img.naturalWidth} / ${img.naturalHeight}`;
        }
      });
      wrap.appendChild(img);
      if (titleEl) titleEl.textContent = "Pratinjau Thumbnail";
    }
    if (filenameEl) filenameEl.textContent = filename || "";
    modal.hidden = false;
    document.body.style.overflow = "hidden";
  };

  function closeMediaPreview() {
    modal.hidden = true;
    document.body.style.overflow = "";
    // Cleanup video element supaya tidak terus jalan di background
    if (wrap) {
      const v = wrap.querySelector("video");
      if (v) { v.pause(); v.removeAttribute("src"); v.load(); }
      wrap.innerHTML = "";
    }
  }

  // Close handlers — backdrop, X button, Esc key
  modal.addEventListener("click", e => {
    if (e.target.closest("[data-mpm-close]")) closeMediaPreview();
  });
  document.addEventListener("keydown", e => {
    if (e.key === "Escape" && !modal.hidden) closeMediaPreview();
  });

  window._closeMediaPreview = closeMediaPreview;
})();

// =================== SUBTITLE: Upload (.vtt/.srt) + Auto-generate (Whisper.js) ===================
// Opsi 1: Creator upload file subtitle
// Opsi 2: Auto-generate via @xenova/transformers (Whisper.js) di browser
(function() {
  const dzLabel = document.getElementById("upSubtitleLabel");
  const dzInput = document.getElementById("upSubtitleInput");
  const dzPlaceholder = document.getElementById("upSubtitlePlaceholder");
  const dzInfo = document.getElementById("upSubtitleInfo");
  const dzName = document.getElementById("upSubtitleName");
  const dzMeta = document.getElementById("upSubtitleMeta");
  const dzReplaceBtn = document.getElementById("upSubtitleReplaceBtn");
  const dzClear = document.getElementById("upSubtitleClear");
  const autoBtn = document.getElementById("upSubtitleAutoBtn");
  const modelSelect = document.getElementById("upSubtitleModel");
  const progress = document.getElementById("upSubtitleProgress");
  const progressBar = document.getElementById("upSubtitleProgressBar");
  const progressStatus = document.getElementById("upSubtitleProgressStatus");
  const progressEta = document.getElementById("upSubtitleProgressEta");
  if (!dzLabel || !dzInput) return;

  // ---- VTT/SRT Parser ----
  // Returns array of cues: [{start: seconds, end: seconds, text: string}]
  window.parseSubtitleVtt = function(text) {
    if (!text) return [];
    // Strip BOM if present
    text = text.replace(/^﻿/, "").trim();
    // Detect SRT vs VTT — SRT doesn't have "WEBVTT" header
    const isVtt = /^WEBVTT/i.test(text);
    if (!isVtt) {
      // Convert SRT → VTT by replacing "," with "." in timestamps
      text = "WEBVTT\n\n" + text.replace(/(\d{2}:\d{2}:\d{2}),(\d{3})/g, "$1.$2");
    }
    const cues = [];
    const blocks = text.split(/\r?\n\r?\n/);
    for (const block of blocks) {
      const lines = block.split(/\r?\n/).map(l => l.trim()).filter(Boolean);
      if (!lines.length) continue;
      // Find timestamp line: "00:00:01.000 --> 00:00:05.000"
      const tsLineIdx = lines.findIndex(l => /-->/.test(l));
      if (tsLineIdx < 0) continue;
      const m = lines[tsLineIdx].match(/(\d{2}:\d{2}:\d{2}\.\d{3})\s*-->\s*(\d{2}:\d{2}:\d{2}\.\d{3})/);
      if (!m) continue;
      const toSec = ts => {
        const [h, mn, s] = ts.split(":");
        return Number(h) * 3600 + Number(mn) * 60 + Number(s);
      };
      const start = toSec(m[1]);
      const end = toSec(m[2]);
      const textLines = lines.slice(tsLineIdx + 1).join("\n");
      if (textLines) cues.push({ start, end, text: textLines });
    }
    return cues;
  };

  // ---- Convert seconds to VTT timestamp ----
  function secToVttTs(sec) {
    const h = String(Math.floor(sec / 3600)).padStart(2, "0");
    const m = String(Math.floor((sec % 3600) / 60)).padStart(2, "0");
    const s = String(Math.floor(sec % 60)).padStart(2, "0");
    const ms = String(Math.floor((sec % 1) * 1000)).padStart(3, "0");
    return `${h}:${m}:${s}.${ms}`;
  }

  // ---- Build VTT string from cues ----
  window.buildVttFromCues = function(cues) {
    let out = "WEBVTT\n\n";
    cues.forEach((c, i) => {
      out += `${i + 1}\n${secToVttTs(c.start)} --> ${secToVttTs(c.end)}\n${c.text}\n\n`;
    });
    return out;
  };

  // ---- UI helpers ----
  function setFilled(vttText, filename, lang) {
    const cues = parseSubtitleVtt(vttText);
    if (!cues.length) {
      toast("⚠️ Subtitle file kosong atau format tidak dikenali", "warning");
      return;
    }
    dzLabel.dataset.state = "filled";
    if (dzName) dzName.textContent = filename || "subtitle.vtt";
    if (dzMeta) dzMeta.textContent = `${cues.length} cues · ${lang || "auto"}`;
    window._uploadSubtitle = { vtt: vttText, lang: lang || "auto", cues: cues.length };
  }
  function setEmpty() {
    dzInput.value = "";
    dzLabel.dataset.state = "empty";
    if (dzMeta) dzMeta.textContent = "";
    window._uploadSubtitle = null;
    if (progress) progress.hidden = true;
  }
  window._clearUploadSubtitle = setEmpty;
  window._uploadSubtitle = null;

  // ---- Opsi 1: Upload subtitle file ----
  function pickFile(f) {
    if (!f) return;
    if (f.size > 5 * 1024 * 1024) return toast("⚠️ Subtitle max 5 MB", "warning");
    const reader = new FileReader();
    reader.onload = e => {
      const text = e.target.result;
      // Detect language from filename (e.g., "video.id.vtt" → "id")
      const langMatch = (f.name || "").match(/\.([a-z]{2})\.(vtt|srt)$/i);
      const lang = langMatch ? langMatch[1] : "auto";
      setFilled(text, f.name, lang);
      toast(`✓ Subtitle ter-upload (${parseSubtitleVtt(text).length} cues)`, "success");
    };
    reader.onerror = () => toast("❌ Gagal baca file subtitle", "error");
    reader.readAsText(f);
  }

  dzInput.addEventListener("change", () => pickFile(dzInput.files?.[0]));
  ["dragenter", "dragover"].forEach(ev =>
    dzLabel.addEventListener(ev, e => { e.preventDefault(); dzLabel.classList.add("is-dragging"); })
  );
  ["dragleave", "drop"].forEach(ev =>
    dzLabel.addEventListener(ev, e => { e.preventDefault(); dzLabel.classList.remove("is-dragging"); })
  );
  dzLabel.addEventListener("drop", e => {
    const f = e.dataTransfer.files?.[0];
    if (f) pickFile(f);
  });
  dzLabel.addEventListener("click", e => {
    if (e.target.closest(".dz-pro-action")) return;
    // Skip kalau target = input itu sendiri (programmatic click dari Replace button).
    // Tanpa skip ini, label.preventDefault() saat state=filled cancel file picker.
    if (e.target === dzInput || e.target.id === "upSubtitleInput") return;
    if (dzLabel.dataset.state === "filled") { e.preventDefault(); return; }
  });
  dzReplaceBtn?.addEventListener("click", e => {
    e.preventDefault(); e.stopPropagation();
    // Reset value supaya file yang sama bisa di-pick ulang (change event butuh value beda)
    dzInput.value = "";
    dzInput.click();
  });
  dzClear?.addEventListener("click", e => {
    e.preventDefault(); e.stopPropagation();
    setEmpty();
  });

  // ---- Opsi 2: Auto-generate dengan Whisper.js via WEB WORKER ----
  // Per user 2026-05-08: transkripsi WAJIB jalan di Worker thread supaya
  // dashboard tetap responsive selama proses (sidebar nav, modal, scroll
  // semua tetap kerja). Worker = ESM module yang import transformers.js
  // dari CDN, di-spawn via Blob URL.
  let __whisperWorker = null;
  let __whisperBusy = false;
  let __whisperDevice = "wasm"; // diisi worker via {type:'deviceDetected'}

  // Kode worker sebagai string — di-inject via Blob URL.
  // Worker punya cache pipeline per-model di scope-nya sendiri.
  const WHISPER_WORKER_SRC = `
import { pipeline, env } from "https://cdn.jsdelivr.net/npm/@xenova/transformers@2.17.2";

const cache = {};
let activeAbort = false;

env.allowLocalModels = false;
env.useBrowserCache = true;

async function detectDevice() {
  try {
    if (typeof navigator !== "undefined" && navigator.gpu) {
      const adapter = await navigator.gpu.requestAdapter();
      if (adapter) return "webgpu";
    }
  } catch {}
  return "wasm";
}

self.onmessage = async (e) => {
  const msg = e.data || {};
  if (msg.type === "abort") { activeAbort = true; return; }
  if (msg.type !== "transcribe") return;

  activeAbort = false;
  const { modelKey, audioData, audioDuration } = msg;
  try {
    let pipe = cache[modelKey];
    if (!pipe) {
      const device = await detectDevice();
      self.postMessage({ type: "deviceDetected", device });
      const modelName = modelKey === "base" ? "Xenova/whisper-base" : "Xenova/whisper-tiny";
      pipe = await pipeline("automatic-speech-recognition", modelName, {
        device,
        progress_callback: (data) => { self.postMessage({ type: "modelProgress", data }); }
      });
      cache[modelKey] = pipe;
      self.postMessage({ type: "modelReady" });
    }
    if (activeAbort) { self.postMessage({ type: "aborted" }); return; }

    const transcribeStart = Date.now();
    let lastEtaUpdate = 0;
    const result = await pipe(audioData, {
      chunk_length_s: 30,
      stride_length_s: 5,
      return_timestamps: true,
      language: null,
      task: "transcribe",
      chunk_callback: (chunk) => {
        if (activeAbort) return;
        const now = Date.now();
        if (now - lastEtaUpdate < 500) return;
        lastEtaUpdate = now;
        const lastTs = (chunk && chunk.timestamp && (chunk.timestamp[1] != null ? chunk.timestamp[1] : chunk.timestamp[0])) || 0;
        const audioPct = audioDuration > 0 ? Math.min(0.99, lastTs / audioDuration) : 0;
        const elapsed = (now - transcribeStart) / 1000;
        self.postMessage({ type: "transcribeProgress", audioPct, elapsed });
      }
    });
    if (activeAbort) { self.postMessage({ type: "aborted" }); return; }
    self.postMessage({ type: "result", result });
  } catch (err) {
    self.postMessage({ type: "error", message: (err && err.message) || "unknown" });
  }
};
`;

  function ensureWhisperWorker() {
    if (__whisperWorker) return __whisperWorker;
    const blob = new Blob([WHISPER_WORKER_SRC], { type: "application/javascript" });
    __whisperWorker = new Worker(URL.createObjectURL(blob), { type: "module" });
    return __whisperWorker;
  }

  // Format detik → "M menit S detik" / "S detik" untuk ETA display
  function fmtEta(s) {
    if (!isFinite(s) || s < 0) return "";
    if (s < 60) return `~${Math.ceil(s)}d`;
    const m = Math.floor(s / 60);
    const sec = Math.round(s % 60);
    return sec > 0 ? `~${m}m ${sec}d` : `~${m}m`;
  }

  // Yield ke event loop — defensive util tetap dipertahankan
  const yieldUI = () => new Promise(r => setTimeout(r, 0));

  function setProgress(pct, status, eta) {
    if (!progress) return;
    progress.hidden = false;
    if (progressBar) progressBar.style.width = `${Math.max(0, Math.min(100, pct))}%`;
    if (progressStatus && status) progressStatus.textContent = status;
    if (progressEta) progressEta.textContent = eta || "";
  }

  function resetAutoBtn() {
    if (autoBtn) {
      autoBtn.dataset.running = "0";
      autoBtn.disabled = false;
      autoBtn.textContent = "🎙 Auto-generate (AI)";
    }
  }

  async function autoGenerateSubtitle() {
    // Cancel handler — post abort msg ke worker. Worker bakal stop di chunk
    // boundary berikutnya. Listener `aborted` reject promise di main thread.
    if (autoBtn?.dataset.running === "1") {
      try { __whisperWorker?.postMessage({ type: "abort" }); } catch {}
      __whisperBusy = false;
      resetAutoBtn();
      if (progress) progress.hidden = true;
      toast("⛔ Auto-generate dibatalkan", "warning");
      return;
    }
    // Get current uploaded video file
    const videoFile = window._uploadCapturedFile || window._captured?.file;
    if (!videoFile) {
      return toast("⚠️ Upload video dulu sebelum auto-generate subtitle", "warning");
    }
    // Warn untuk file besar
    const fileMB = videoFile.size / (1024 * 1024);
    if (fileMB > 200) {
      const ok = confirm(
        `Video ${fileMB.toFixed(0)} MB cukup besar.\n` +
        `Auto-generate bisa butuh 5-15 menit & memakan banyak memory.\n` +
        `Tapi tenang — dashboard tetap bisa dipakai sambil nunggu.\n\n` +
        `Lanjutkan?`
      );
      if (!ok) return;
    }
    if (__whisperBusy) {
      return toast("⏳ Sudah ada proses transkripsi berjalan", "warning");
    }
    __whisperBusy = true;
    const modelKey = (modelSelect?.value === "base") ? "base" : "tiny";
    const modelLabel = modelKey === "base" ? "base ~150 MB" : "tiny ~75 MB";
    if (autoBtn) {
      autoBtn.dataset.running = "1";
      autoBtn.disabled = false;
      autoBtn.textContent = "⛔ Batalkan";
    }

    try {
      // Step 1: Decode audio di main thread (cepat — AudioContext tidak
      // available di Worker, jadi decode wajib di sini).
      setProgress(5, "Mengekstrak audio dari video...", "");
      await yieldUI();
      const arrayBuffer = await videoFile.arrayBuffer();
      await yieldUI();
      const AudioCtx = window.AudioContext || window.webkitAudioContext;
      const audioCtx = new AudioCtx({ sampleRate: 16000 });
      const audioBuffer = await audioCtx.decodeAudioData(arrayBuffer.slice(0));
      let audioData;
      if (audioBuffer.numberOfChannels === 1) {
        audioData = new Float32Array(audioBuffer.getChannelData(0));
      } else {
        const ch0 = audioBuffer.getChannelData(0);
        const ch1 = audioBuffer.getChannelData(1);
        audioData = new Float32Array(ch0.length);
        for (let i = 0; i < ch0.length; i++) audioData[i] = (ch0[i] + ch1[i]) / 2;
      }
      const audioDurSec = audioBuffer.duration;
      try { audioCtx.close?.(); } catch {}

      // Step 2: Spawn worker (kalau belum), pasang one-shot listener,
      // kirim audio dengan transferable ArrayBuffer (zero-copy IPC).
      const worker = ensureWhisperWorker();
      const initialRtf = (__whisperDevice === "webgpu")
        ? (modelKey === "base" ? 0.6 : 0.3)
        : (modelKey === "base" ? 2.0 : 0.8);
      const initialEta = audioDurSec * initialRtf;

      const result = await new Promise((resolve, reject) => {
        const downloadStart = Date.now();
        const transcribeStart = { ts: 0 };
        // Periodic ETA tick saat transcribe berjalan — chunk_callback di
        // transformers.js v2 untuk Whisper tidak reliable, fallback time-based.
        let progressTick = null;
        const startTick = () => {
          if (progressTick) return;
          transcribeStart.ts = Date.now();
          const deviceLabel = __whisperDevice === "webgpu" ? "GPU" : "CPU";
          progressTick = setInterval(() => {
            const elapsed = (Date.now() - transcribeStart.ts) / 1000;
            const estPct = Math.min(0.95, elapsed / Math.max(1, initialEta));
            const remaining = Math.max(0, initialEta - elapsed);
            const overallPct = 60 + (estPct * 35);
            setProgress(
              overallPct,
              `Transkripsi (${deviceLabel} · ${modelKey}) — dashboard tetap bisa dipakai`,
              fmtEta(remaining)
            );
          }, 500);
        };
        const cleanup = () => {
          if (progressTick) clearInterval(progressTick);
          worker.removeEventListener("message", onMsg);
        };
        const onMsg = (e) => {
          const msg = e.data || {};
          switch (msg.type) {
            case "deviceDetected":
              __whisperDevice = msg.device;
              setProgress(8, `Memuat model Whisper ${modelLabel} (${msg.device.toUpperCase()})...`, "");
              break;
            case "modelProgress":
              if (msg.data?.status === "progress" && msg.data.progress != null) {
                const pct = Math.max(0, Math.min(100, msg.data.progress));
                const elapsed = (Date.now() - downloadStart) / 1000;
                const remaining = pct > 5 ? (elapsed / pct) * (100 - pct) : 0;
                setProgress(8 + (pct * 0.5), `Download model: ${Math.round(pct)}%`, fmtEta(remaining));
              }
              break;
            case "modelReady":
              startTick();
              setProgress(60, `Transkripsi audio dimulai... dashboard tetap bisa dipakai`, fmtEta(initialEta));
              break;
            case "transcribeProgress": {
              startTick();
              const audioPct = msg.audioPct || 0;
              const elapsed = msg.elapsed || 0;
              const adaptiveTotal = audioPct > 0.05 ? (elapsed / audioPct) : initialEta;
              const remaining = Math.max(0, adaptiveTotal - elapsed);
              const overallPct = 60 + (audioPct * 35);
              const deviceLabel = __whisperDevice === "webgpu" ? "GPU" : "CPU";
              setProgress(
                overallPct,
                `Transkripsi: ${Math.round(audioPct * 100)}% (${deviceLabel} · ${modelKey})`,
                fmtEta(remaining)
              );
              break;
            }
            case "result":
              cleanup();
              resolve(msg.result);
              break;
            case "aborted":
              cleanup();
              reject(new DOMException("Aborted", "AbortError"));
              break;
            case "error":
              cleanup();
              reject(new Error(msg.message || "Worker error"));
              break;
          }
        };
        worker.addEventListener("message", onMsg);
        // Transfer audioData.buffer ke worker (no copy) — main thread lepas
        // ownership dari ArrayBuffer-nya, tapi kita ga butuh lagi di sini.
        worker.postMessage(
          { type: "transcribe", modelKey, audioData, audioDuration: audioDurSec },
          [audioData.buffer]
        );
      });

      // Step 3: Convert chunks → VTT cues (back on main thread, cepat)
      setProgress(95, "Menyusun subtitle...", "");
      await yieldUI();
      const chunks = result.chunks || [];
      if (!chunks.length) {
        toast("⚠️ Tidak ada audio terdeteksi di video", "warning");
        if (progress) progress.hidden = true;
        return;
      }
      const cues = chunks
        .filter(c => c.timestamp && c.timestamp[0] != null && c.text)
        .map(c => ({
          start: c.timestamp[0] || 0,
          end: c.timestamp[1] || (c.timestamp[0] + 4),
          text: c.text.trim()
        }));
      const vtt = buildVttFromCues(cues);
      const detectedLang = result.language || "auto";
      setFilled(vtt, `auto-generated.vtt`, detectedLang);
      setProgress(100, `✓ Selesai! ${cues.length} cues ter-generate`, "");
      toast(`✓ Auto-subtitle ter-generate (${cues.length} cues)`, "success");
      setTimeout(() => { if (progress) progress.hidden = true; }, 2000);
    } catch (err) {
      if (err?.name === "AbortError") {
        // user abort — silent
      } else {
        console.error("[auto-subtitle] error:", err);
        toast(`❌ Gagal generate: ${err.message || "unknown error"}`, "error");
      }
      if (progress) progress.hidden = true;
    } finally {
      __whisperBusy = false;
      resetAutoBtn();
    }
  }

  // SUBTITLE AI FREE QUOTA — 3x per bulan untuk Free user.
  // Hook: kasih user free experience supaya bisa nilai kualitas Subtitle AI
  // sebelum decide upgrade. Quota di-reset otomatis tiap bulan kalender.
  // Stored di localStorage: { month: "2026-05", used: 0..3 }
  const SUB_FREE_QUOTA = 3;
  function _subFreeKey() { return "playly-sub-ai-free-quota"; }
  function _currentMonthKey() {
    const d = new Date();
    return d.getFullYear() + "-" + String(d.getMonth() + 1).padStart(2, "0");
  }
  function getSubFreeQuotaUsed() {
    try {
      const raw = localStorage.getItem(_subFreeKey());
      if (!raw) return 0;
      const obj = JSON.parse(raw);
      if (obj.month !== _currentMonthKey()) return 0; // bulan baru = reset
      return Math.max(0, Math.min(SUB_FREE_QUOTA, obj.used || 0));
    } catch { return 0; }
  }
  function incrementSubFreeQuota() {
    const used = getSubFreeQuotaUsed() + 1;
    try {
      localStorage.setItem(_subFreeKey(), JSON.stringify({ month: _currentMonthKey(), used }));
    } catch {}
    return used;
  }
  function getSubFreeQuotaRemaining() {
    return Math.max(0, SUB_FREE_QUOTA - getSubFreeQuotaUsed());
  }
  // Expose untuk testing
  window._subFreeQuota = { used: getSubFreeQuotaUsed, remaining: getSubFreeQuotaRemaining };

  autoBtn?.addEventListener("click", e => {
    e.preventDefault();
    const isPremium = !!(user && (user.tier === "premium" || user.role === "admin"));
    if (!isPremium) {
      // Free user: cek quota sebelum gate ke premium prompt.
      const remaining = getSubFreeQuotaRemaining();
      if (remaining <= 0) {
        if (typeof toast === "function") {
          toast("🎁 Kuota gratis bulan ini habis. Upgrade Premium untuk akses unlimited.", "warning");
        }
        return;
      }
      // Confirm sekali sebelum konsumsi quota — supaya user sadar ini "dihitung"
      const willUse = SUB_FREE_QUOTA - remaining + 1;
      const ok = confirm(
        "🎁 Kamu masih punya " + remaining + " dari " + SUB_FREE_QUOTA + " percobaan gratis bulan ini.\n\n" +
        "Lanjut generate subtitle (percobaan ke-" + willUse + ")?\n\n" +
        "Setelah kuota habis, fitur ini perlu Premium."
      );
      if (!ok) return;
      incrementSubFreeQuota();
      // Refresh UI counter setelah quota dipakai
      if (typeof window.refreshSubtitleAiLockedState === "function") {
        // Tunggu sebentar supaya state localStorage ter-flush
        setTimeout(window.refreshSubtitleAiLockedState, 50);
      }
    }
    autoGenerateSubtitle();
  });

  // Apply visual state ke kartu subtitle AI.
  // Free user dengan quota tersisa → soft state (ungu/sparkle, ada counter).
  // Free user kuota habis → muted lock state.
  // Premium → fully unlocked, no banner.
  window.refreshSubtitleAiLockedState = function () {
    const card = document.getElementById("upSubtitleAiCard");
    const btn = document.getElementById("upSubtitleAutoBtn");
    const note = document.getElementById("upSubtitleAiNote");
    if (!card) return;
    const _u = (typeof user !== "undefined" ? user : null) || window.user;
    const isPremium =
      (typeof isPremiumActive === "function" && isPremiumActive(_u)) ||
      !!(_u && (_u.tier === "premium" || _u.role === "admin")) ||
      document.body.dataset.tier === "premium";

    const remaining = isPremium ? Infinity : getSubFreeQuotaRemaining();
    const hasFreeQuota = !isPremium && remaining > 0;
    const quotaExhausted = !isPremium && remaining <= 0;

    // 3-state class system:
    //  is-unlocked  → Premium / admin (full access, no banner)
    //  has-quota    → Free user dengan quota tersisa (soft sparkle state)
    //  locked       → Free user, quota habis (locked, premium prompt)
    card.classList.toggle("is-unlocked", isPremium);
    card.classList.toggle("has-quota", hasFreeQuota);
    card.classList.toggle("locked", quotaExhausted);

    if (note) {
      if (isPremium) {
        note.innerHTML = "";
        note.hidden = true;
      } else if (hasFreeQuota) {
        // Soft sparkle state — tampilkan counter quota
        const ICO_SPARK = '<svg class="upf-spark-ico" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 3v3M12 18v3M3 12h3M18 12h3M5.6 5.6l2.1 2.1M16.3 16.3l2.1 2.1M5.6 18.4l2.1-2.1M16.3 7.7l2.1-2.1"/></svg>';
        note.innerHTML = ICO_SPARK + " " + t("upload.sub.note.quota").replace("{n}", String(remaining));
        note.hidden = false;
      } else {
        // Kuota habis — soft lock state (bukan harsh)
        const ICO_GIFT = '<svg class="upf-lock-ico" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="8" width="18" height="13" rx="2"/><path d="M12 8v13M3 13h18M7.5 8a2.5 2.5 0 0 1 0-5C9 3 12 5 12 8c0-3 3-5 4.5-5a2.5 2.5 0 0 1 0 5"/></svg>';
        note.innerHTML = ICO_GIFT + " " + t("upload.sub.note.quota.out");
        note.hidden = false;
      }
    }

    // Button enable/disable — Premium dan Free-with-quota bisa klik.
    // Free-no-quota: disabled (tapi click handler tetap kasih friendly toast).
    if (btn) {
      if (isPremium || hasFreeQuota) {
        btn.removeAttribute("disabled");
        btn.removeAttribute("aria-disabled");
        btn.title = isPremium ? "" : ("Sisa " + remaining + " percobaan gratis bulan ini");
      } else {
        btn.setAttribute("disabled", "disabled");
        btn.setAttribute("aria-disabled", "true");
        btn.title = t("upload.sub.note.quota.out");
      }
    }

    // Sync AI Assist card juga — selalu locked untuk non-premium (no quota).
    const aiAssistCard = document.getElementById("upAiAssist");
    if (aiAssistCard) aiAssistCard.classList.toggle("is-unlocked", isPremium);
  };
  window.refreshSubtitleAiLockedState();
  // Re-check setiap view change (user mungkin upgrade tier saat session aktif).
  // BUGFIX 2026-05-16: event yg benar = window + "playly:view-changed" (bukan
  // document + "playly:viewchange" yg tidak pernah ada). + cloud-applied saat
  // login selesai + delayed recheck biar Premium tidak ke-lock palsu.
  window.addEventListener("playly:view-changed", window.refreshSubtitleAiLockedState);
  window.addEventListener("playly:cloud-applied", window.refreshSubtitleAiLockedState);
  setTimeout(window.refreshSubtitleAiLockedState, 900);
})();

// =================== SUBTITLE: Lihat / Unggah / Pilih File (per kartu) ======
// Per request user 2026-05-16. Tiap kartu subtitle (Auto AI + Manual) punya
// 3 tombol: aksi-utama | Lihat | Unggah. Semua operasi pada subtitle aktif
// global window._uploadSubtitle (cuma ada satu). HTML string-concat, NO
// backtick. Tombol di dalam <label> manual → preventDefault (cancel default
// label, pola sama #upSubtitleReplaceBtn) supaya file-picker tidak ke-trigger.
// Close modal: [data-close] global handler (~L41217) + Escape (~L41238).
(function wireSubtitleActions() {
  const modal = document.getElementById("subtitlePreviewModal");
  const body = document.getElementById("spvBody");
  const meta = document.getElementById("spvMeta");

  function pad2(n) { return String(n).padStart(2, "0"); }
  function fmt(sec) {
    sec = Math.max(0, Math.floor(Number(sec) || 0));
    const h = Math.floor(sec / 3600);
    const m = Math.floor((sec % 3600) / 60);
    const s = sec % 60;
    return (h > 0 ? h + ":" + pad2(m) : m) + ":" + pad2(s);
  }
  function esc(s) {
    if (typeof escapeHtml === "function") return escapeHtml(String(s));
    return String(s).replace(/[&<>"]/g, c => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" }[c]));
  }
  function currentCues() {
    const sub = window._uploadSubtitle;
    const vtt = sub && sub.vtt;
    return {
      sub: sub,
      cues: (vtt && typeof parseSubtitleVtt === "function") ? parseSubtitleVtt(vtt) : []
    };
  }

  function openPreview() {
    if (!modal) return;
    const { sub, cues } = currentCues();
    if (!cues.length) {
      if (typeof toast === "function") toast(t("subprev.empty"), "warning");
      return;
    }
    if (meta) meta.textContent = cues.length + " cues · " + ((sub && sub.lang) || "auto");
    const H = [];
    cues.forEach(function (c, i) {
      H.push(
        '<div class="spv-cue"><span class="spv-idx">' + (i + 1) +
        '</span><span class="spv-time">' + fmt(c.start) + " → " + fmt(c.end) +
        '</span><span class="spv-txt">' + esc(c.text).replace(/\n/g, "<br>") + "</span></div>"
      );
    });
    if (body) { body.innerHTML = H.join(""); body.scrollTop = 0; }
    modal.classList.add("show");
  }

  function applySubtitle() {
    const { cues } = currentCues();
    if (!cues.length) {
      if (typeof toast === "function") toast(t("subprev.empty"), "warning");
      return;
    }
    // Subtitle sudah auto-terpasang di window._uploadSubtitle & ikut saat
    // video di-upload. Tombol ini = konfirmasi eksplisit (per pilihan user).
    if (typeof toast === "function") toast(t("subprev.applied"), "success");
  }

  function pickFile() {
    const inp = document.getElementById("upSubtitleInput");
    if (inp) { inp.value = ""; inp.click(); }
  }

  function bindAll(sel, fn) {
    document.querySelectorAll(sel).forEach(function (b) {
      b.addEventListener("click", function (e) {
        e.preventDefault();   // cancel default <label> (no double file dialog)
        e.stopPropagation();
        fn();
      });
    });
  }
  bindAll(".js-sub-preview", openPreview);
  bindAll(".js-sub-apply", applySubtitle);
  bindAll(".js-sub-pick", pickFile);
})();

// =================== SUBTITLE EDIT (untuk video yang sudah di-upload) ===================
// Sama seperti upload page subtitle, tapi sumber video dari IndexedDB blob
// (bukan file picker). Stage staging di `window._editSubtitle` lalu di-flush
// ke v.subtitleVtt + v.subtitleLang saat saveVideoEdit() jalan.
(function() {
  const dzLabel = document.getElementById("vemSubtitleLabel");
  const dzInput = document.getElementById("vemSubtitleInput");
  const dzName = document.getElementById("vemSubtitleName");
  const dzMeta = document.getElementById("vemSubtitleMeta");
  const dzReplaceBtn = document.getElementById("vemSubtitleReplaceBtn");
  const dzClear = document.getElementById("vemSubtitleClear");
  const autoBtn = document.getElementById("vemSubtitleAutoBtn");
  const modelSelect = document.getElementById("vemSubtitleModel");
  const progress = document.getElementById("vemSubtitleProgress");
  const progressBar = document.getElementById("vemSubtitleProgressBar");
  const progressStatus = document.getElementById("vemSubtitleProgressStatus");
  const progressEta = document.getElementById("vemSubtitleProgressEta");
  if (!dzLabel || !dzInput) return;

  // Worker dipisah dari upload page supaya state-nya independen.
  const WHISPER_WORKER_SRC = `
import { pipeline, env } from "https://cdn.jsdelivr.net/npm/@xenova/transformers@2.17.2";
const cache = {};
let activeAbort = false;
env.allowLocalModels = false;
env.useBrowserCache = true;
async function detectDevice() {
  try {
    if (typeof navigator !== "undefined" && navigator.gpu) {
      const adapter = await navigator.gpu.requestAdapter();
      if (adapter) return "webgpu";
    }
  } catch {}
  return "wasm";
}
self.onmessage = async (e) => {
  const msg = e.data || {};
  if (msg.type === "abort") { activeAbort = true; return; }
  if (msg.type !== "transcribe") return;
  activeAbort = false;
  const { modelKey, audioData, audioDuration } = msg;
  try {
    let pipe = cache[modelKey];
    if (!pipe) {
      const device = await detectDevice();
      self.postMessage({ type: "deviceDetected", device });
      const modelName = modelKey === "base" ? "Xenova/whisper-base" : "Xenova/whisper-tiny";
      pipe = await pipeline("automatic-speech-recognition", modelName, {
        device,
        progress_callback: (data) => { self.postMessage({ type: "modelProgress", data }); }
      });
      cache[modelKey] = pipe;
      self.postMessage({ type: "modelReady" });
    }
    if (activeAbort) { self.postMessage({ type: "aborted" }); return; }
    const transcribeStart = Date.now();
    let lastEtaUpdate = 0;
    const result = await pipe(audioData, {
      chunk_length_s: 30,
      stride_length_s: 5,
      return_timestamps: true,
      language: null,
      task: "transcribe",
      chunk_callback: (chunk) => {
        if (activeAbort) return;
        const now = Date.now();
        if (now - lastEtaUpdate < 500) return;
        lastEtaUpdate = now;
        const lastTs = (chunk && chunk.timestamp && (chunk.timestamp[1] != null ? chunk.timestamp[1] : chunk.timestamp[0])) || 0;
        const audioPct = audioDuration > 0 ? Math.min(0.99, lastTs / audioDuration) : 0;
        const elapsed = (now - transcribeStart) / 1000;
        self.postMessage({ type: "transcribeProgress", audioPct, elapsed });
      }
    });
    if (activeAbort) { self.postMessage({ type: "aborted" }); return; }
    self.postMessage({ type: "result", result });
  } catch (err) {
    self.postMessage({ type: "error", message: (err && err.message) || "unknown" });
  }
};
`;

  let __worker = null;
  let __busy = false;
  let __device = "wasm";

  function ensureWorker() {
    if (__worker) return __worker;
    const blob = new Blob([WHISPER_WORKER_SRC], { type: "application/javascript" });
    __worker = new Worker(URL.createObjectURL(blob), { type: "module" });
    return __worker;
  }

  function fmtEta(s) {
    if (!isFinite(s) || s < 0) return "";
    if (s < 60) return `~${Math.ceil(s)}d`;
    const m = Math.floor(s / 60);
    const sec = Math.round(s % 60);
    return sec > 0 ? `~${m}m ${sec}d` : `~${m}m`;
  }
  const yieldUI = () => new Promise(r => setTimeout(r, 0));

  function setProgress(pct, status, eta) {
    if (!progress) return;
    progress.hidden = false;
    if (progressBar) progressBar.style.width = `${Math.max(0, Math.min(100, pct))}%`;
    if (progressStatus && status) progressStatus.textContent = status;
    if (progressEta) progressEta.textContent = eta || "";
  }

  function resetAutoBtn() {
    if (autoBtn) {
      autoBtn.dataset.running = "0";
      autoBtn.disabled = false;
      autoBtn.textContent = "🎙 Auto-generate (AI)";
    }
  }

  function setFilled(vttText, filename, lang) {
    const cues = (typeof parseSubtitleVtt === "function") ? parseSubtitleVtt(vttText) : [];
    if (!cues.length) {
      toast("⚠️ Subtitle file kosong atau format tidak dikenali", "warning");
      return;
    }
    dzLabel.dataset.state = "filled";
    if (dzName) dzName.textContent = filename || "subtitle.vtt";
    if (dzMeta) dzMeta.textContent = `${cues.length} cues · ${lang || "auto"}`;
    window._editSubtitle = { vtt: vttText, lang: lang || "auto", cues: cues.length };
  }
  function setEmpty() {
    dzInput.value = "";
    dzLabel.dataset.state = "empty";
    if (dzMeta) dzMeta.textContent = "";
    window._editSubtitle = null;
    if (progress) progress.hidden = true;
  }
  // Expose helper supaya openVideoEditModal bisa reset/populate state
  window._vemSubtitleSetEmpty = setEmpty;
  window._vemSubtitleSetFilled = setFilled;

  // ---- Opsi 1: Upload subtitle file ----
  function pickFile(f) {
    if (!f) return;
    if (f.size > 5 * 1024 * 1024) return toast("⚠️ Subtitle max 5 MB", "warning");
    const reader = new FileReader();
    reader.onload = e => {
      const text = e.target.result;
      const langMatch = (f.name || "").match(/\.([a-z]{2})\.(vtt|srt)$/i);
      const lang = langMatch ? langMatch[1] : "auto";
      setFilled(text, f.name, lang);
      const cueCount = (typeof parseSubtitleVtt === "function") ? parseSubtitleVtt(text).length : 0;
      toast(`✓ Subtitle ter-upload (${cueCount} cues)`, "success");
    };
    reader.onerror = () => toast("❌ Gagal baca file subtitle", "error");
    reader.readAsText(f);
  }
  dzInput.addEventListener("change", () => pickFile(dzInput.files?.[0]));
  ["dragenter", "dragover"].forEach(ev =>
    dzLabel.addEventListener(ev, e => { e.preventDefault(); dzLabel.classList.add("is-dragging"); })
  );
  ["dragleave", "drop"].forEach(ev =>
    dzLabel.addEventListener(ev, e => { e.preventDefault(); dzLabel.classList.remove("is-dragging"); })
  );
  dzLabel.addEventListener("drop", e => {
    const f = e.dataTransfer.files?.[0];
    if (f) pickFile(f);
  });
  dzLabel.addEventListener("click", e => {
    if (e.target.closest(".dz-pro-action")) return;
    // Skip programmatic click dari Replace button (target = input itself)
    if (e.target === dzInput || (e.target.id && e.target.id.endsWith("SubtitleInput"))) return;
    if (dzLabel.dataset.state === "filled") { e.preventDefault(); return; }
  });
  dzReplaceBtn?.addEventListener("click", e => {
    e.preventDefault(); e.stopPropagation();
    dzInput.value = "";
    dzInput.click();
  });
  dzClear?.addEventListener("click", e => {
    e.preventDefault(); e.stopPropagation();
    setEmpty();
  });

  // ---- Opsi 2: Auto-generate dari video blob di IndexedDB ----
  async function autoGenerate() {
    if (autoBtn?.dataset.running === "1") {
      try { __worker?.postMessage({ type: "abort" }); } catch {}
      __busy = false;
      resetAutoBtn();
      if (progress) progress.hidden = true;
      toast("⛔ Auto-generate dibatalkan", "warning");
      return;
    }
    const id = +(document.getElementById("vemId")?.value || 0);
    if (!id) return toast("⚠️ Video tidak ditemukan", "warning");

    let videoBlob = null;
    try {
      videoBlob = await getVideoBlob(id);
    } catch {}
    if (!videoBlob) {
      // Fallback: coba ambil dari videoUrl (kalau itu Blob URL/data URL)
      const v = (state?.myVideos || []).find(x => x.id === id);
      const url = v?.videoUrl;
      if (url && /^blob:|^data:/i.test(url)) {
        try {
          const res = await fetch(url);
          videoBlob = await res.blob();
        } catch {}
      }
    }
    if (!videoBlob) {
      return toast("⚠️ Video file tidak tersedia (mungkin URL eksternal). Auto-generate butuh file lokal.", "warning");
    }
    const fileMB = videoBlob.size / (1024 * 1024);
    if (fileMB > 200) {
      const ok = confirm(
        `Video ${fileMB.toFixed(0)} MB cukup besar.\n` +
        `Auto-generate bisa butuh 5-15 menit & memakan banyak memory.\n\n` +
        `Lanjutkan?`
      );
      if (!ok) return;
    }
    if (__busy) return toast("⏳ Sudah ada proses transkripsi berjalan", "warning");
    __busy = true;
    const modelKey = (modelSelect?.value === "base") ? "base" : "tiny";
    const modelLabel = modelKey === "base" ? "base ~150 MB" : "tiny ~75 MB";
    if (autoBtn) {
      autoBtn.dataset.running = "1";
      autoBtn.disabled = false;
      autoBtn.textContent = "⛔ Batalkan";
    }

    try {
      setProgress(5, "Mengekstrak audio dari video...", "");
      await yieldUI();
      const arrayBuffer = await videoBlob.arrayBuffer();
      await yieldUI();
      const AudioCtx = window.AudioContext || window.webkitAudioContext;
      const audioCtx = new AudioCtx({ sampleRate: 16000 });
      const audioBuffer = await audioCtx.decodeAudioData(arrayBuffer.slice(0));
      let audioData;
      if (audioBuffer.numberOfChannels === 1) {
        audioData = new Float32Array(audioBuffer.getChannelData(0));
      } else {
        const ch0 = audioBuffer.getChannelData(0);
        const ch1 = audioBuffer.getChannelData(1);
        audioData = new Float32Array(ch0.length);
        for (let i = 0; i < ch0.length; i++) audioData[i] = (ch0[i] + ch1[i]) / 2;
      }
      const audioDurSec = audioBuffer.duration;
      try { audioCtx.close?.(); } catch {}

      const worker = ensureWorker();
      const initialRtf = (__device === "webgpu")
        ? (modelKey === "base" ? 0.6 : 0.3)
        : (modelKey === "base" ? 2.0 : 0.8);
      const initialEta = audioDurSec * initialRtf;

      const result = await new Promise((resolve, reject) => {
        const downloadStart = Date.now();
        const transcribeStart = { ts: 0 };
        let progressTick = null;
        const startTick = () => {
          if (progressTick) return;
          transcribeStart.ts = Date.now();
          const deviceLabel = __device === "webgpu" ? "GPU" : "CPU";
          progressTick = setInterval(() => {
            const elapsed = (Date.now() - transcribeStart.ts) / 1000;
            const estPct = Math.min(0.95, elapsed / Math.max(1, initialEta));
            const remaining = Math.max(0, initialEta - elapsed);
            const overallPct = 60 + (estPct * 35);
            setProgress(overallPct, `Transkripsi (${deviceLabel} · ${modelKey})`, fmtEta(remaining));
          }, 500);
        };
        const cleanup = () => {
          if (progressTick) clearInterval(progressTick);
          worker.removeEventListener("message", onMsg);
        };
        const onMsg = (e) => {
          const msg = e.data || {};
          switch (msg.type) {
            case "deviceDetected":
              __device = msg.device;
              setProgress(8, `Memuat model Whisper ${modelLabel} (${msg.device.toUpperCase()})...`, "");
              break;
            case "modelProgress":
              if (msg.data?.status === "progress" && msg.data.progress != null) {
                const pct = Math.max(0, Math.min(100, msg.data.progress));
                const elapsed = (Date.now() - downloadStart) / 1000;
                const remaining = pct > 5 ? (elapsed / pct) * (100 - pct) : 0;
                setProgress(8 + (pct * 0.5), `Download model: ${Math.round(pct)}%`, fmtEta(remaining));
              }
              break;
            case "modelReady":
              startTick();
              setProgress(60, `Transkripsi audio dimulai...`, fmtEta(initialEta));
              break;
            case "transcribeProgress": {
              startTick();
              const audioPct = msg.audioPct || 0;
              const elapsed = msg.elapsed || 0;
              const adaptiveTotal = audioPct > 0.05 ? (elapsed / audioPct) : initialEta;
              const remaining = Math.max(0, adaptiveTotal - elapsed);
              const overallPct = 60 + (audioPct * 35);
              const deviceLabel = __device === "webgpu" ? "GPU" : "CPU";
              setProgress(overallPct, `Transkripsi: ${Math.round(audioPct * 100)}% (${deviceLabel} · ${modelKey})`, fmtEta(remaining));
              break;
            }
            case "result":   cleanup(); resolve(msg.result); break;
            case "aborted":  cleanup(); reject(new DOMException("Aborted", "AbortError")); break;
            case "error":    cleanup(); reject(new Error(msg.message || "Worker error")); break;
          }
        };
        worker.addEventListener("message", onMsg);
        worker.postMessage(
          { type: "transcribe", modelKey, audioData, audioDuration: audioDurSec },
          [audioData.buffer]
        );
      });

      setProgress(95, "Menyusun subtitle...", "");
      await yieldUI();
      const chunks = result.chunks || [];
      if (!chunks.length) {
        toast("⚠️ Tidak ada audio terdeteksi di video", "warning");
        if (progress) progress.hidden = true;
        return;
      }
      const cues = chunks
        .filter(c => c.timestamp && c.timestamp[0] != null && c.text)
        .map(c => ({
          start: c.timestamp[0] || 0,
          end: c.timestamp[1] || (c.timestamp[0] + 4),
          text: c.text.trim()
        }));
      const vtt = (typeof buildVttFromCues === "function") ? buildVttFromCues(cues) : "";
      const detectedLang = result.language || "auto";
      setFilled(vtt, `auto-generated.vtt`, detectedLang);
      setProgress(100, `✓ Selesai! ${cues.length} cues ter-generate`, "");
      toast(`✓ Auto-subtitle ter-generate (${cues.length} cues)`, "success");
      setTimeout(() => { if (progress) progress.hidden = true; }, 2000);
    } catch (err) {
      if (err?.name !== "AbortError") {
        console.error("[edit-subtitle] error:", err);
        toast(`❌ Gagal generate: ${err.message || "unknown error"}`, "error");
      }
      if (progress) progress.hidden = true;
    } finally {
      __busy = false;
      resetAutoBtn();
    }
  }

  autoBtn?.addEventListener("click", e => {
    e.preventDefault();
    // Premium-only gate juga di sini (video edit modal) supaya konsisten dengan upload page.
    const isPremium = !!(user && (user.tier === "premium" || user.role === "admin"));
    if (!isPremium) {
      if (typeof toast === "function") {
        toast("⭐ Auto-generate AI subtitle hanya untuk Premium. Upgrade dulu yuk!", "warning");
      }
      return;
    }
    autoGenerate();
  });
})();

// =================== CUSTOM DATETIME PICKER (#upSchedule) ===================
// Replaces native <input type="datetime-local"> — fully theme-controllable
// (wine/cream user, blue/slate admin). Stores ISO string in hidden input.
(function() {
  const trigger = document.getElementById("upScheduleDisplay");
  const pop = document.getElementById("upSchedulePop");
  const hidden = document.getElementById("upSchedule");
  const textEl = document.getElementById("upScheduleText");
  const clearIcon = document.getElementById("upScheduleClear");
  if (!trigger || !pop || !hidden || !textEl) return;

  const MONTHS_ID = ["Jan", "Feb", "Mar", "Apr", "Mei", "Jun", "Jul", "Agu", "Sep", "Okt", "Nov", "Des"];
  const DOW_ID = ["Min", "Sen", "Sel", "Rab", "Kam", "Jum", "Sab"];

  let viewYear = new Date().getFullYear();
  let viewMonth = new Date().getMonth();
  let selDate = null;     // Date object (date only)
  let selH = 12, selM = 0; // hour 0-23, minute 0-59

  function pad(n) { return String(n).padStart(2, "0"); }

  function setDisplay() {
    if (!selDate) {
      textEl.textContent = "Pilih tanggal & waktu";
      textEl.classList.add("is-placeholder");
      hidden.value = "";
      if (clearIcon) clearIcon.hidden = true;
      return;
    }
    const d = selDate;
    const dispText = `${pad(d.getDate())} ${MONTHS_ID[d.getMonth()]} ${d.getFullYear()} · ${pad(selH)}:${pad(selM)}`;
    textEl.textContent = dispText;
    textEl.classList.remove("is-placeholder");
    // ISO local format (no timezone): YYYY-MM-DDTHH:MM
    hidden.value = `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(selH)}:${pad(selM)}`;
    if (clearIcon) clearIcon.hidden = false;
  }

  function buildPop() {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const first = new Date(viewYear, viewMonth, 1);
    const startDow = first.getDay();
    const daysInMonth = new Date(viewYear, viewMonth + 1, 0).getDate();
    const daysPrev = new Date(viewYear, viewMonth, 0).getDate();

    const cells = [];
    for (let i = 0; i < startDow; i++) {
      cells.push({ d: daysPrev - startDow + 1 + i, otherMonth: true, prevMonth: true });
    }
    for (let i = 1; i <= daysInMonth; i++) cells.push({ d: i });
    while (cells.length % 7 !== 0) {
      const lastIdx = cells.length;
      cells.push({ d: lastIdx - daysInMonth - startDow + 1, otherMonth: true, nextMonth: true });
    }

    const html = `
      <div class="udp-head">
        <button type="button" class="udp-nav-btn" data-udp-act="prev" aria-label="Bulan sebelumnya">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><path d="M15 18l-6-6 6-6"/></svg>
        </button>
        <span class="udp-month-label">${MONTHS_ID[viewMonth]} ${viewYear}</span>
        <button type="button" class="udp-nav-btn" data-udp-act="next" aria-label="Bulan berikutnya">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><path d="M9 18l6-6-6-6"/></svg>
        </button>
      </div>
      <div class="udp-dow">${DOW_ID.map(d => `<span>${d}</span>`).join("")}</div>
      <div class="udp-grid">
        ${cells.map(c => {
          let cls = "udp-day";
          if (c.otherMonth) cls += " is-other-month";
          const cellDate = c.otherMonth
            ? (c.prevMonth ? new Date(viewYear, viewMonth - 1, c.d) : new Date(viewYear, viewMonth + 1, c.d))
            : new Date(viewYear, viewMonth, c.d);
          if (cellDate.getTime() === today.getTime()) cls += " is-today";
          if (selDate && cellDate.getTime() === new Date(selDate.getFullYear(), selDate.getMonth(), selDate.getDate()).getTime()) {
            cls += " is-selected";
          }
          return `<button type="button" class="${cls}" data-udp-day="${cellDate.toISOString()}">${c.d}</button>`;
        }).join("")}
      </div>
      <div class="udp-time">
        <span class="udp-time-label">Waktu</span>
        <input type="text" class="udp-time-input" data-udp-time="h" value="${pad(selH)}" maxlength="2" inputmode="numeric"/>
        <span class="udp-time-sep">:</span>
        <input type="text" class="udp-time-input" data-udp-time="m" value="${pad(selM)}" maxlength="2" inputmode="numeric"/>
      </div>
      <div class="udp-foot">
        <button type="button" class="udp-clear" data-udp-act="clear">Hapus</button>
        <button type="button" class="udp-today-quick" data-udp-act="today">Hari ini</button>
        <button type="button" class="udp-apply" data-udp-act="apply">Terapkan</button>
      </div>
    `;
    pop.innerHTML = html;
  }

  function positionPop() {
    // Pop dipakai position:fixed, jadi harus dihitung manual relative ke trigger.
    // Pop mau muncul di bawah trigger; kalau gak cukup space, flip ke atas.
    const tr = trigger.getBoundingClientRect();
    const popH = pop.offsetHeight || 380;
    const popW = pop.offsetWidth || 360;
    const vw = window.innerWidth;
    const vh = window.innerHeight;
    let top = tr.bottom + 6;
    if (top + popH > vh - 12) {
      // Not enough space below → flip above trigger
      top = Math.max(12, tr.top - popH - 6);
    }
    let left = tr.left;
    if (left + popW > vw - 12) left = vw - popW - 12;
    if (left < 12) left = 12;
    pop.style.top = `${top}px`;
    pop.style.left = `${left}px`;
  }

  function openPop() {
    if (selDate) {
      viewYear = selDate.getFullYear();
      viewMonth = selDate.getMonth();
    }
    buildPop();
    pop.hidden = false;
    trigger.setAttribute("aria-expanded", "true");
    // Position after content rendered
    requestAnimationFrame(positionPop);
  }
  function closePop() {
    pop.hidden = true;
    trigger.setAttribute("aria-expanded", "false");
  }
  // Re-position on scroll/resize so popover follows trigger
  window.addEventListener("scroll", () => { if (!pop.hidden) positionPop(); }, true);
  window.addEventListener("resize", () => { if (!pop.hidden) positionPop(); });

  trigger.addEventListener("click", e => {
    e.preventDefault();
    e.stopPropagation();
    if (pop.hidden) openPop(); else closePop();
  });
  // Click outside to close
  document.addEventListener("click", e => {
    if (pop.hidden) return;
    if (!pop.contains(e.target) && e.target !== trigger && !trigger.contains(e.target)) closePop();
  });
  // Esc to close
  document.addEventListener("keydown", e => {
    if (e.key === "Escape" && !pop.hidden) closePop();
  });

  // Clear button (X icon in trigger)
  clearIcon?.addEventListener("click", e => {
    e.preventDefault();
    e.stopPropagation();
    selDate = null;
    setDisplay();
    if (!pop.hidden) buildPop();
  });

  // Delegate clicks inside popover
  pop.addEventListener("click", e => {
    const dayBtn = e.target.closest("[data-udp-day]");
    if (dayBtn) {
      e.preventDefault();
      const iso = dayBtn.dataset.udpDay;
      selDate = new Date(iso);
      // Update view if selected from other month
      viewYear = selDate.getFullYear();
      viewMonth = selDate.getMonth();
      buildPop();
      return;
    }
    const actBtn = e.target.closest("[data-udp-act]");
    if (!actBtn) return;
    e.preventDefault();
    const act = actBtn.dataset.udpAct;
    if (act === "prev") {
      viewMonth--; if (viewMonth < 0) { viewMonth = 11; viewYear--; }
      buildPop();
      requestAnimationFrame(positionPop);
    } else if (act === "next") {
      viewMonth++; if (viewMonth > 11) { viewMonth = 0; viewYear++; }
      buildPop();
      requestAnimationFrame(positionPop);
    } else if (act === "today") {
      const t = new Date();
      selDate = new Date(t.getFullYear(), t.getMonth(), t.getDate());
      selH = t.getHours();
      selM = t.getMinutes();
      viewYear = t.getFullYear();
      viewMonth = t.getMonth();
      buildPop();
      requestAnimationFrame(positionPop);
    } else if (act === "clear") {
      selDate = null;
      selH = 12; selM = 0;
      setDisplay();
      buildPop();
      requestAnimationFrame(positionPop);
    } else if (act === "apply") {
      // Read time inputs and apply
      const hIn = pop.querySelector('[data-udp-time="h"]');
      const mIn = pop.querySelector('[data-udp-time="m"]');
      const h = Math.max(0, Math.min(23, parseInt(hIn?.value, 10) || 0));
      const m = Math.max(0, Math.min(59, parseInt(mIn?.value, 10) || 0));
      selH = h; selM = m;
      setDisplay();
      closePop();
    }
  });

  // Time input live update + validation
  pop.addEventListener("input", e => {
    const input = e.target.closest("[data-udp-time]");
    if (!input) return;
    const kind = input.dataset.udpTime;
    let v = input.value.replace(/\D/g, "").slice(0, 2);
    input.value = v;
  });

  // Initialize
  setDisplay();
})();

function fmtBytes(n) {
  if (n < 1024) return `${n} B`;
  if (n < 1024 * 1024) return `${(n / 1024).toFixed(1)} KB`;
  return `${(n / (1024 * 1024)).toFixed(1)} MB`;
}

function fmtDurationSec(sec) {
  if (!isFinite(sec) || sec <= 0) return "0:00";
  const m = Math.floor(sec / 60);
  const s = Math.floor(sec % 60);
  return `${m}:${s.toString().padStart(2, "0")}`;
}

// Bikin thumbnail dari frame video (~detik 1) + ukur durasi.
function generateVideoThumb(file) {
  return new Promise((resolve, reject) => {
    const url = URL.createObjectURL(file);
    const v = document.createElement("video");
    v.preload = "metadata";
    v.muted = true;
    v.playsInline = true;
    // JANGAN set crossOrigin untuk blob URL — bisa bikin canvas tainted
    // di iOS Safari sehingga toDataURL throw SecurityError.
    v.src = url;
    let captured = false;
    const cleanup = () => { try { URL.revokeObjectURL(url); } catch {} };

    const tryCapture = () => {
      if (captured) return;
      try {
        const w = 480;
        const ratio = v.videoHeight && v.videoWidth ? v.videoHeight / v.videoWidth : 9 / 16;
        const h = Math.round(w * ratio);
        const canvas = document.createElement("canvas");
        canvas.width = w; canvas.height = h;
        const ctx = canvas.getContext("2d");
        ctx.drawImage(v, 0, 0, w, h);
        const thumb = canvas.toDataURL("image/jpeg", 0.72);
        captured = true;
        const duration = fmtDurationSec(v.duration || 0);
        cleanup();
        resolve({ thumb, duration });
      } catch (err) {
        cleanup();
        reject(err);
      }
    };

    v.addEventListener("loadedmetadata", () => {
      const target = Math.min(1.0, (v.duration || 1) * 0.1);
      try { v.currentTime = target; }
      catch { /* mobile mungkin block seek — fallback langsung capture */ tryCapture(); }
    }, { once: true });
    v.addEventListener("seeked", tryCapture, { once: true });
    // Fallback untuk mobile yang gak fire 'seeked': capture saat data tersedia
    v.addEventListener("loadeddata", () => {
      // Tunggu dikit biar frame ke-decode
      setTimeout(() => { if (!captured) tryCapture(); }, 400);
    }, { once: true });
    v.addEventListener("error", () => {
      cleanup();
      reject(new Error("Tidak bisa membaca file video"));
    }, { once: true });
    // Timeout 12 detik (lebih panjang untuk mobile lambat)
    setTimeout(() => {
      if (!captured) {
        cleanup();
        reject(new Error("Timeout membaca video"));
      }
    }, 12000);
  });
}

async function handlePickedFile(file) {
  if (!file) return;
  if (!file.type.startsWith("video/")) return toast("⚠️ File harus berupa video", "warning");

  // === FREE TIER LIMITS (per request 2026-05-03 — Free vs Premium) ===
  // Free user: max 60 video upload/bulan, max 1 GB total upload size/bulan.
  // Premium user: unlimited (skip checks). Limit per calendar month.
  const tier = user?.tier || "free";
  if (tier === "free") {
    const FREE_MAX_VIDEOS_PER_MONTH = 60;
    const FREE_MAX_BYTES_PER_MONTH = 1024 * 1024 * 1024; // 1 GB
    const myVideos = Array.isArray(state?.myVideos) ? state.myVideos : [];
    const now = new Date();
    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).getTime();
    const thisMonth = myVideos.filter(v => (v.createdAt || v.id || 0) >= monthStart);
    const usedCount = thisMonth.length;
    const usedBytes = thisMonth.reduce((s, v) => s + (v.fileSize || 0), 0);

    if (usedCount >= FREE_MAX_VIDEOS_PER_MONTH) {
      return openConfirm({
        icon: "⭐", iconClass: "warn",
        title: "Free upload limit reached",
        desc: `You've uploaded <b>${usedCount}/${FREE_MAX_VIDEOS_PER_MONTH}</b> videos this month.<br><br>Upgrade to <b>Premium</b> for unlimited uploads.`,
        btnText: "⭐ Upgrade to Premium", btnClass: "primary",
        onConfirm: () => document.getElementById("pdUpgradeBtn")?.click()
      });
    }
    if (usedBytes + file.size > FREE_MAX_BYTES_PER_MONTH) {
      const usedMB = (usedBytes / (1024 * 1024)).toFixed(0);
      return openConfirm({
        icon: "⭐", iconClass: "warn",
        title: "Free storage quota exceeded",
        desc: `You've used <b>${usedMB} MB / 1 GB</b> this month. This file (${fmtBytes(file.size)}) won't fit.<br><br>Upgrade to <b>Premium</b> for unlimited storage.`,
        btnText: "⭐ Upgrade to Premium", btnClass: "primary",
        onConfirm: () => document.getElementById("pdUpgradeBtn")?.click()
      });
    }
  }

  // Browser quota warning (independent dari tier — premium juga tetap warn)
  if (file.size > 2 * 1024 * 1024 * 1024) {
    toast(`ℹ️ File besar (${fmtBytes(file.size)}) — pastikan browser quota cukup`, "info");
  }

  $("#upTitle").value = file.name.replace(/\.[^.]+$/, "");

  // Tampilkan preview placeholder dulu, generate thumbnail di background
  uploadPreview.hidden = false;
  $("#uploadPreviewThumb").src = "";
  $("#uploadPreviewName").textContent = file.name;
  $("#uploadPreviewMeta").textContent = `${fmtBytes(file.size)} • memproses thumbnail...`;
  $("#uploadPreviewDuration").textContent = "—";
  dropzone.classList.add("has-file");
  dropzone.dataset.state = "filled";

  // Buat blob URL dulu (dipakai untuk playback nanti)
  const videoUrl = URL.createObjectURL(file);
  pendingUpload = { file, thumb: null, duration: "0:00", videoUrl };
  // Expose ke window supaya autoGenerateSubtitle bisa akses file-nya
  window._uploadCapturedFile = file;
  // Init Video Info Card + Cover Frame Picker (per request user 2026-05-14)
  if (typeof window._initVideoInfoAndFrame === "function") {
    window._initVideoInfoAndFrame(file, videoUrl);
  }
  // Auto-open media preview popup
  if (typeof openMediaPreview === "function") {
    openMediaPreview({ type: "video", src: videoUrl, filename: file.name });
  }

  try {
    const { thumb, duration } = await generateVideoThumb(file);
    pendingUpload.thumb = thumb;
    pendingUpload.duration = duration;
    $("#uploadPreviewThumb").src = thumb;
    const dzFill = $("#dropzonePreviewFill"); if (dzFill) dzFill.src = thumb;
    $("#uploadPreviewMeta").textContent = `${fmtBytes(file.size)} • ${duration}`;
    $("#uploadPreviewDuration").textContent = duration;
  } catch (err) {
    console.warn("Gagal generate thumb:", err);
    // Fallback ke gambar acak
    pendingUpload.thumb = `https://picsum.photos/seed/u${Date.now()}/600/340`;
    $("#uploadPreviewThumb").src = pendingUpload.thumb;
    const dzFill = $("#dropzonePreviewFill"); if (dzFill) dzFill.src = pendingUpload.thumb;
    $("#uploadPreviewMeta").textContent = `${fmtBytes(file.size)} • thumbnail otomatis`;
  }
}

function clearPendingUpload() {
  if (pendingUpload?.videoUrl) URL.revokeObjectURL(pendingUpload.videoUrl);
  pendingUpload = null;
  fileInput.value = "";
  uploadPreview.hidden = true;
  dropzone.classList.remove("has-file");
  dropzone.dataset.state = "empty";
  const dzFill = $("#dropzonePreviewFill"); if (dzFill) dzFill.src = "";
  window._uploadCapturedFile = null;
  // Reset subtitle state juga (subtitle nempel ke video file ini)
  if (typeof window._clearUploadSubtitle === "function") window._clearUploadSubtitle();
  // Hide Info Card + Frame Picker (per request user 2026-05-14)
  if (typeof window._resetVideoInfoAndFrame === "function") window._resetVideoInfoAndFrame();
}

dropzone?.addEventListener("click", e => {
  // Cegah re-trigger kalau klik dari area preview/btn atau dari overlay action
  if (e.target.closest(".upload-preview")) return;
  if (e.target.closest(".dz-pro-action")) return;
  // Skip kalau click datang langsung dari input (avoid recursive double-trigger)
  if (e.target === fileInput) return;
  // Saat filled, klik body dropzone → buka popup pratinjau (per request 2026-05-10)
  if (dropzone.dataset.state === "filled") {
    e.preventDefault();
    if (pendingUpload?.videoUrl && typeof openMediaPreview === "function") {
      openMediaPreview({
        type: "video",
        src: pendingUpload.videoUrl,
        filename: pendingUpload.file?.name || "video"
      });
    }
    return;
  }
  // Cegah native label→input behavior (label punya child input hidden), supaya
  // tidak terjadi double-trigger: native label click + explicit fileInput.click()
  // yang membuat 2 dialog beruntun (yang ke-2 cancel yang ke-1, user mesti klik ulang).
  e.preventDefault();
  fileInput.click();
});
["dragenter", "dragover"].forEach(ev => dropzone?.addEventListener(ev, e => { e.preventDefault(); dropzone.classList.add("drag"); dropzone.classList.add("is-dragging"); }));
["dragleave", "drop"].forEach(ev => dropzone?.addEventListener(ev, e => { e.preventDefault(); dropzone.classList.remove("drag"); dropzone.classList.remove("is-dragging"); }));
dropzone?.addEventListener("drop", e => {
  const f = e.dataTransfer.files?.[0];
  if (f) {
    fileInput.files = e.dataTransfer.files;
    handlePickedFile(f);
  }
});
fileInput?.addEventListener("change", () => handlePickedFile(fileInput.files[0]));
$("#uploadPreviewClear")?.addEventListener("click", e => {
  e.preventDefault();
  e.stopPropagation();
  clearPendingUpload();
});
$("#dropzoneReplaceBtn")?.addEventListener("click", e => {
  e.preventDefault(); e.stopPropagation();
  fileInput.click();
});
$("#dropzoneRemoveBtn")?.addEventListener("click", e => {
  e.preventDefault(); e.stopPropagation();
  clearPendingUpload();
});

// Popup konfirmasi setelah upload selesai. Menggantikan inline notice merah +
// toast simpel sebelumnya. Popup ini menjelaskan ke user bahwa video sudah
// terkirim ke admin dan sedang menunggu approval, plus shortcut buat lihat
// status di My Library → Status Videos.
function showUploadSuccessPopup(title, newVid) {
  // Hapus modal lama kalau ada (defensif)
  document.getElementById("__uploadSuccessModal")?.remove();

  const modal = document.createElement("div");
  modal.className = "hs-popup-modal";
  modal.id = "__uploadSuccessModal";
  modal.innerHTML = `
    <div class="hs-popup-backdrop" data-upload-success-close></div>
    <div class="hs-popup-panel upload-success-panel">
      <button type="button" class="hs-popup-close" data-upload-success-close aria-label="Tutup">✕</button>
      <div class="upload-success-icon">🎉</div>
      <h3 class="upload-success-title">Upload Berhasil!</h3>
      <p class="upload-success-desc">
        Video <b>${escapeHtml(title)}</b> berhasil diupload dan sudah dikirim ke admin
        untuk di-review. Kamu akan dapat notifikasi setelah disetujui atau di-reject.
      </p>
      <div class="upload-success-meta">
        <span class="upload-success-status">⏳ Menunggu approval admin</span>
      </div>
      <div class="upload-success-actions">
        <button type="button" class="btn primary" id="uploadSuccessGoStatus">📋 Lihat Status Videos</button>
        <button type="button" class="btn ghost" data-upload-success-close>Tutup</button>
      </div>
    </div>
  `;
  document.body.appendChild(modal);
  requestAnimationFrame(() => modal.classList.add("show"));

  const close = () => modal.remove();
  modal.querySelectorAll("[data-upload-success-close]").forEach(b => b.addEventListener("click", close));
  modal.querySelector("#uploadSuccessGoStatus")?.addEventListener("click", () => {
    close();
    if (typeof switchView === "function") switchView("videos");
    // Apply focus ke Status Videos supaya user langsung lihat video yang baru diupload
    setTimeout(() => {
      const view = document.querySelector('section.view[data-view="videos"]');
      if (view && typeof applyFocus === "function") applyFocus(view, "status-videos");
      // Sync sidebar active state
      const sub = document.querySelector('.nav-subitem[data-sub-action="focus:status-videos"]');
      if (sub) {
        document.querySelectorAll('.nav-group[data-nav-group="videos"] .nav-subitem.active')
          .forEach(x => x.classList.remove('active'));
        sub.classList.add('active');
      }
    }, 80);
  });
}

// ----------------------- URL Video Source -----------------------
function parseVideoUrl(url) {
  if (!url || typeof url !== "string") return null;
  const u = url.trim();
  let m = u.match(/(?:youtube\.com\/(?:watch\?v=|embed\/|shorts\/)|youtu\.be\/)([A-Za-z0-9_-]{11})/);
  if (m) {
    const id = m[1];
    return { provider: "youtube", videoId: id,
      embedUrl: `https://www.youtube.com/embed/${id}?rel=0&modestbranding=1&iv_load_policy=3`,
      originalUrl: u, thumbUrl: `https://i.ytimg.com/vi/${id}/hqdefault.jpg`,
      allowFs: true, icon: "▶", label: "YouTube" };
  }
  m = u.match(/vimeo\.com\/(?:video\/|channels\/[^\/]+\/|groups\/[^\/]+\/videos\/)?(\d+)/);
  if (m) {
    const id = m[1];
    return { provider: "vimeo", videoId: id,
      embedUrl: `https://player.vimeo.com/video/${id}`,
      originalUrl: u, thumbUrl: null, allowFs: true, icon: "🅥", label: "Vimeo" };
  }
  m = u.match(/tiktok\.com\/@[^\/]+\/video\/(\d+)/);
  if (m) {
    const id = m[1];
    return { provider: "tiktok", videoId: id,
      embedUrl: `https://www.tiktok.com/embed/v2/${id}`,
      originalUrl: u, thumbUrl: null, allowFs: false, icon: "🎵", label: "TikTok" };
  }
  m = u.match(/dailymotion\.com\/(?:video\/|embed\/video\/)([a-zA-Z0-9]+)/);
  if (m) {
    const id = m[1];
    return { provider: "dailymotion", videoId: id,
      embedUrl: `https://www.dailymotion.com/embed/video/${id}`,
      originalUrl: u, thumbUrl: null, allowFs: true, icon: "📺", label: "Dailymotion" };
  }
  m = u.match(/(?:clips\.twitch\.tv\/|twitch\.tv\/[^\/]+\/clip\/)([A-Za-z0-9-]+)/);
  if (m) {
    const slug = m[1];
    return { provider: "twitch", videoId: slug,
      embedUrl: `https://clips.twitch.tv/embed?clip=${slug}&parent=${location.hostname}`,
      originalUrl: u, thumbUrl: null, allowFs: true, icon: "🎮", label: "Twitch" };
  }
  if (/\.(mp4|webm|ogg|mov|m3u8)(\?.*)?$/i.test(u)) {
    return { provider: "direct", videoId: null, embedUrl: u, originalUrl: u,
      thumbUrl: null, allowFs: true, icon: "🎬", label: "Direct video file" };
  }
  return null;
}

// Source tab switch (File ↔ URL)
document.addEventListener("click", e => {
  const tab = e.target.closest(".ust-tab[data-upload-source]");
  if (!tab) return;
  e.preventDefault();
  const src = tab.dataset.uploadSource;
  document.querySelectorAll(".ust-tab").forEach(b => {
    const a = b.dataset.uploadSource === src;
    b.classList.toggle("active", a);
    b.setAttribute("aria-selected", a ? "true" : "false");
  });
  const wrap = document.querySelector(".upload-layout-bare[data-upload-source]");
  if (wrap) wrap.dataset.uploadSource = src;
  pendingUpload = null;
  const fp = document.getElementById("uploadPreview"); if (fp) fp.hidden = true;
  const up = document.getElementById("uploadUrlPreview"); if (up) up.hidden = true;
  const dz = document.getElementById("dropzone"); if (dz) dz.classList.remove("has-file");
});

// URL detect button → parse + populate pendingUpload + show preview
// Fetch video metadata via oEmbed (no API key needed)
async function fetchVideoOEmbed(data) {
  const endpoints = {
    youtube:     `https://www.youtube.com/oembed?url=${encodeURIComponent(data.originalUrl)}&format=json`,
    vimeo:       `https://vimeo.com/api/oembed.json?url=${encodeURIComponent(data.originalUrl)}`,
    dailymotion: `https://www.dailymotion.com/services/oembed?url=${encodeURIComponent(data.originalUrl)}&format=json`,
    tiktok:      `https://www.tiktok.com/oembed?url=${encodeURIComponent(data.originalUrl)}`,
  };
  const url = endpoints[data.provider];
  if (!url) return null;
  try {
    const res = await fetch(url, { signal: AbortSignal.timeout(6000) });
    if (!res.ok) return null;
    return await res.json();
  } catch { return null; }
}

// Set autofill fields with animation indicator
function setAutofillField(id, value, isNew) {
  const el = document.getElementById(id);
  if (!el || !value) return;
  el.value = value;
  if (isNew) {
    el.style.transition = "box-shadow .3s";
    el.style.boxShadow = "0 0 0 3px rgba(109,41,50,.35)";
    setTimeout(() => { el.style.boxShadow = ""; }, 1400);
  }
}

document.getElementById("uploadUrlDetect")?.addEventListener("click", async () => {
  const input = document.getElementById("uploadUrlInput");
  const preview = document.getElementById("uploadUrlPreview");
  const warn = document.getElementById("uploadUrlWarn");
  const btn = document.getElementById("uploadUrlDetect");
  const url = (input?.value || "").trim();
  if (!url) return toast("⚠️ Paste a video URL first", "warning");
  if (/netflix\.com|disneyplus\.com|hbomax\.com|primevideo\.com|spotify\.com/i.test(url)) {
    if (warn) warn.hidden = false;
    if (preview) preview.hidden = true;
    pendingUpload = null;
    return;
  }
  if (warn) warn.hidden = true;
  const data = parseVideoUrl(url);
  if (!data) {
    if (preview) preview.hidden = true;
    pendingUpload = null;
    return toast("⚠️ URL tidak dikenali. Coba YouTube / Vimeo / TikTok / .mp4 link.", "warning");
  }
  document.getElementById("uupIcon").textContent = data.icon;
  document.getElementById("uupProvider").textContent = data.label;
  document.getElementById("uupVideoId").textContent = data.videoId ? `ID: ${data.videoId}` : "Direct file";
  document.getElementById("uupBadge").textContent = data.provider === "direct" ? "Direct" : "Embed";
  const iframeWrap = document.getElementById("uupIframeWrap");
  if (iframeWrap) {
    if (data.provider === "direct") {
      iframeWrap.innerHTML = `<video src="${escapeHtml(data.embedUrl)}" controls preload="metadata" style="width:100%;border-radius:10px;background:#000"></video>`;
    } else {
      const _ytMask = data.provider === "youtube" ? `<div class="yt-edge-mask"></div>` : "";
      iframeWrap.innerHTML = `<iframe src="${escapeHtml(data.embedUrl)}" frameborder="0" ${data.allowFs ? 'allowfullscreen' : ''} loading="lazy" style="width:100%;aspect-ratio:16/9;border:0;border-radius:10px;background:#000"></iframe>${_ytMask}`;
    }
  }
  if (preview) preview.hidden = false;
  pendingUpload = {
    file: null,
    thumb: data.thumbUrl || `https://picsum.photos/seed/${(data.videoId || Date.now()).toString().slice(-6)}/600/340`,
    duration: "—",
    videoUrl: data.embedUrl,
    sourceType: data.provider === "direct" ? "url" : "embed",
    embedProvider: data.provider,
    embedVideoId: data.videoId,
    embedOriginalUrl: data.originalUrl,
  };

  // --- Auto-fill title & description via oEmbed ---
  const titleEl = document.getElementById("upTitle");
  const descEl  = document.getElementById("upDesc");
  const titleWasEmpty = !titleEl?.value.trim();
  const descWasEmpty  = !descEl?.value.trim();

  // Show loading state while fetching
  if (btn) { btn.disabled = true; btn.textContent = "Mengambil info..."; }
  const meta = await fetchVideoOEmbed(data);
  if (btn) { btn.disabled = false; btn.textContent = "Detect"; }

  if (meta) {
    // Title: from oEmbed title, else fallback to generic
    const fetchedTitle = meta.title || null;
    const fetchedDesc  = meta.description || (meta.author_name ? `${data.label} oleh ${meta.author_name}.` : null);
    // Update thumbnail if oEmbed returns higher quality
    if (meta.thumbnail_url && pendingUpload) pendingUpload.thumb = meta.thumbnail_url;

    if (titleWasEmpty && fetchedTitle) setAutofillField("upTitle", fetchedTitle, true);
    else if (titleWasEmpty) setAutofillField("upTitle", `${data.label} video${data.videoId ? ` ${data.videoId}` : ""}`, false);

    if (descWasEmpty && fetchedDesc) setAutofillField("upDesc", fetchedDesc, true);
  } else {
    // No oEmbed — use generic fallback title only
    if (titleWasEmpty) setAutofillField("upTitle", `${data.label} video${data.videoId ? ` ${data.videoId}` : ""}`, false);
  }
});

$("#startUpload")?.addEventListener("click", () => {
  // URL upload: pendingUpload sudah ada tapi tanpa file. File upload: dengan file.
  const isUrlUpload = pendingUpload && pendingUpload.sourceType && !pendingUpload.file;
  if (!pendingUpload || (!pendingUpload.file && !isUrlUpload)) {
    return toast("⚠️ Pilih video atau detect URL dulu", "warning");
  }
  const title = $("#upTitle").value.trim();
  if (!title) return toast("⚠️ Judul wajib diisi", "warning");
  // Visibility & audience dari radio cards (default public/all kalau tidak terpilih)
  const visibility = document.querySelector('input[name="upVisibility"]:checked')?.value || "public";
  const audience   = document.querySelector('input[name="upAudience"]:checked')?.value || "all";
  // Sync ke legacy hidden #upAge supaya code lain yang baca upAge.value tidak break
  const upAgeEl = $("#upAge");
  if (upAgeEl) upAgeEl.value = audience;
  // Engagement toggles
  const allowComments  = $("#upAllowComments")?.checked  !== false;  // default true
  const allowReactions = $("#upAllowReactions")?.checked !== false;  // default true
  const allowDuet      = !!$("#upAllowDuet")?.checked;
  const allowDownload  = !!$("#upAllowDownload")?.checked;
  const category = $("#upCategory")?.value || "";
  const tags = (typeof window._getUploadTags === "function") ? window._getUploadTags() : [];
  // Thumbnail final: prioritas _customThumb (yang aktif — bisa dari frame, upload, atau editor)
  // Fallback ke _frameThumb atau _uploadThumb kalau salah satu valid.
  const customThumb = window._customThumb || window._uploadThumb || window._frameThumb || null;
  const captured = pendingUpload; // freeze
  const desc = $("#upDesc").value || "Video baru saja diunggah.";
  const wrap = $("#uploadProgress"), bar = $("#upBar"), status = $("#upStatus");
  wrap.hidden = false;

  // Tracking entry untuk tab "Sedang Upload"
  const uploadId = "u" + Date.now();
  const uploadEntry = {
    id: uploadId,
    title,
    thumb: captured.thumb,
    size: captured?.file?.size || 0,
    progress: 0,
    status: "uploading",
    startedAt: Date.now()
  };
  state.uploadingVideos = state.uploadingVideos || [];
  state.uploadingVideos.unshift(uploadEntry);
  saveState();
  syncVideoTabCounts();

  window.__activeUploads = window.__activeUploads || {};
  window.__activeUploads[uploadId] = true;

  let p = 0;
  const tick = setInterval(() => {
    // Cek kalau upload dibatalkan
    if (!window.__activeUploads[uploadId]) {
      clearInterval(tick);
      wrap.hidden = true; bar.style.width = "0%";
      return;
    }
    p += Math.random() * 12 + 4;
    uploadEntry.progress = Math.min(100, p);
    // Update tampilan tab "Sedang Upload" kalau sedang dilihat
    if (state.filter === "uploading" && state.currentView === "videos") renderVideoGrid();

    if (p >= 100) {
      p = 100; clearInterval(tick);
      delete window.__activeUploads[uploadId];
      uploadEntry.status = "done";
      status.textContent = "✓ Upload selesai!";
      const _now = Date.now();
      const subtitleData = window._uploadSubtitle || null;
      const newVid = {
        id: _now, createdAt: _now, title, creator: user.username, category, tags, visibility,
        // Audience & engagement (per request user 2026-05-14)
        audience, allowComments, allowReactions, allowDuet, allowDownload,
        views: "0", viewsNum: 0,
        time: "just now", duration: captured.duration || "0:00", likes: 0,
        thumb: customThumb || captured.thumb || `https://picsum.photos/seed/u${_now}/600/340`,
        videoUrl: captured.videoUrl,
        desc,
        // Source tracking — file (default), url (direct video URL), embed (YouTube/Vimeo/etc)
        sourceType: captured.sourceType || "file",
        embedProvider: captured.embedProvider || null,
        embedVideoId: captured.embedVideoId || null,
        embedOriginalUrl: captured.embedOriginalUrl || null,
        // Track file size untuk monthly quota tracking (Free tier limit 1 GB/bulan)
        fileSize: captured.file?.size || 0,
        // Subtitle (Opsi 1 manual upload / Opsi 2 auto-generate AI)
        subtitleVtt: subtitleData?.vtt || null,
        subtitleLang: subtitleData?.lang || null,
        // Auto-publish (2026-05-25): video langsung live setelah upload, tidak
        // perlu admin approval. Sebelumnya default "pending" → user kreator
        // bingung kenapa video tidak muncul di "Video Saya". Admin tetap bisa
        // takedown via Kontrol Konten kalau ada masalah (reaktif, bukan
        // gate). Visibility "draft" tetap respect — user simpan draft sendiri.
        adminStatus: visibility === "draft" ? "draft" : "published",
        submittedAt: _now,
      };
      state.myVideos.unshift(newVid);
      // Pindahkan dari uploadingVideos
      state.uploadingVideos = state.uploadingVideos.filter(u => u.id !== uploadId);
      state.activities.unshift({ type: "upload", text: `You uploaded <i>${title}</i>`, time: "just now", icon: "🎬", ts: Date.now() });
      saveState();
      // Simpan file aslinya ke IndexedDB — skip kalau URL upload (no file to save)
      if (captured.file) {
        saveVideoBlob(newVid.id, captured.file).then(() => refreshStorageUsage());
      }
      // Cloud sync: upload juga ke Supabase Storage agar bisa diputar di browser lain
      if (captured.file && window.cloudSync?.uploadVideoBlob) {
        window.cloudSync.uploadVideoBlob(newVid.id, captured.file).then(result => {
          if (result && result.ok && result.url) {
            newVid.videoUrl = result.url;
            saveState();
            toast("☁️ Video tersimpan di cloud — bisa diputar di device lain.", "success");
          } else if (result && !result.ok) {
            // Upload ke cloud gagal — beritahu user, tapi video tetap aman di lokal
            const reason =
              result.message ||
              (result.error === "file_too_large"
                ? "File terlalu besar untuk Supabase Storage."
                : "Upload ke cloud gagal — video disimpan lokal saja.");
            toast(`⚠️ ${reason} Video kamu masih bisa diputar di browser ini.`, "warning");
          }
        }).catch(err => {
          console.warn("[upload] cloud sync exception:", err);
          toast("⚠️ Sync video ke cloud gagal — video disimpan lokal saja.", "warning");
        });
      }
      refreshAllVideoGrids();
      renderUserStats();
      renderActivityList();
      renderHomeActivity();
      renderHomeTrending();
      renderHomeStats();
      renderFeatured(); // Update tile "⭐ Video Terbaru Saya" di Home
      renderTopPerforming();
      renderDiscoverCreators();
      refreshHeroGreeting();
      pendingUpload = null; // jangan revoke videoUrl — masih dipakai newVid
      setTimeout(() => {
        wrap.hidden = true; bar.style.width = "0%";
        $("#upTitle").value = ""; $("#upDesc").value = "";
        // Reset kategori — pakai helper kalau ada (custom dropdown), fallback ke direct value set
        if (typeof window._resetUpCategory === "function") {
          window._resetUpCategory();
        } else if ($("#upCategory")) {
          $("#upCategory").value = "";
        }
        if (typeof window._clearUploadTags === "function") window._clearUploadTags();
        if (typeof window._clearCustomThumb === "function") window._clearCustomThumb();
        // Reset visibility & audience ke default
        const visPub = document.querySelector('input[name="upVisibility"][value="public"]');
        if (visPub) visPub.checked = true;
        const audAll = document.querySelector('input[name="upAudience"][value="all"]');
        if (audAll) audAll.checked = true;
        // Reset engagement toggles ke default
        if ($("#upAllowComments"))  $("#upAllowComments").checked  = true;
        if ($("#upAllowReactions")) $("#upAllowReactions").checked = true;
        if ($("#upAllowDuet"))      $("#upAllowDuet").checked      = false;
        if ($("#upAllowDownload"))  $("#upAllowDownload").checked  = false;
        uploadPreview.hidden = true;
        dropzone.classList.remove("has-file");
        fileInput.value = "";
        // Tampilkan popup konfirmasi (bukan toast saja) supaya user dapat
        // notifikasi yang jelas + tahu video lagi menunggu approval admin.
        showUploadSuccessPopup(title, newVid);
      }, 800);
    }
    bar.style.width = p + "%";
    const _fileSize = captured?.file?.size || 0;
    const _sizeText = _fileSize
      ? ` · ${fmtBytes(Math.floor(_fileSize * (p / 100)))} / ${fmtBytes(_fileSize)}`
      : "";
    status.textContent = `Mengunggah... ${Math.floor(p)}%${_sizeText}`;
  }, 200);
});

// ----------------------- PLAYER MODAL -----------------------
// Render daftar "Diunduh" di sidebar player.
// Source: state.downloaded (array {videoId, ts}). Resolve ke video object via findVideo()
// — kalau video sudah dihapus dari platform, skip (filter out).
function renderDownloadedList(currentId) {
  const listEl = document.querySelector("#downloadedList");
  const cntEl = document.querySelector("#downloadedCount");
  if (!listEl) return;
  const downloaded = Array.isArray(state?.downloaded) ? state.downloaded : [];
  const items = downloaded
    .map(d => ({ ...d, video: typeof findVideo === "function" ? findVideo(d.videoId) : null }))
    .filter(x => x.video);
  if (cntEl) cntEl.textContent = items.length;

  if (items.length === 0) {
    listEl.innerHTML = `
      <div class="upnext-empty">
        <div class="upnext-empty-icon">📥</div>
        <p>Belum ada unduhan</p>
        <small>Klik tombol Unduh di bawah video untuk simpan ke daftar ini.</small>
      </div>`;
    return;
  }
  listEl.innerHTML = items.map(({ video: x, videoId }) => `
    <div class="upload-item ${videoId === currentId ? "active" : ""}" data-vid="${videoId}">
      <div class="mini-thumb"><img src="${x.thumb}" alt=""/><span class="duration">${x.duration}</span></div>
      <div class="info"><h5>${escapeHtml(x.title)}</h5><p>@${escapeHtml(x.creator)} • ${x.views} views</p></div>
    </div>
  `).join("");
  listEl.querySelectorAll(".upload-item").forEach(c => {
    c.addEventListener("click", () => {
      const vid = +c.dataset.vid;
      if (vid === currentId) return;
      openPlayer(vid);
    });
  });
}

// =================== USER EMAIL VIEW (kontak admin) ===================
// Render list email yang user kirim ke admin (dari getAdminData("tickets")
// filtered by user.email/username). Tiap item: subject, body preview, status,
// jumlah balasan dari admin. Klik baris → buka popup detail thread (subject,
// body, semua replies). Tombol compose pakai openSupportCompose yang sudah ada.
const userEmailState = { filter: "all" };

// Email yang user kirim KE ADMIN (dari admin tickets store).
function getAdminEmailsForUser() {
  if (!user?.email && !user?.username) return [];
  const tickets = (typeof getAdminData === "function") ? getAdminData("tickets") : [];
  return tickets.filter(t => {
    if (t.type === "bug") return false;
    if (user.email && t.fromEmail === user.email) return true;
    if (user.username && (t.from || "").toLowerCase().includes("@" + user.username.toLowerCase())) return true;
    return false;
  });
}

// Email yang user kirim KE USER LAIN (dari state.userMailbox.sent).
function getUserSentEmails() {
  return Array.isArray(state?.userMailbox?.sent) ? state.userMailbox.sent : [];
}

// Email yang DITERIMA dari user lain (dari state.userMailbox.received).
function getUserReceivedEmails() {
  return Array.isArray(state?.userMailbox?.received) ? state.userMailbox.received : [];
}

// Normalisasi tiap entry ke shape yang sama supaya gampang di-render:
//   { id, kind: 'admin-out'|'user-out'|'user-in', title, body, createdAt,
//     replies: [], _readByUser, fromLabel, toLabel, peerUsername }
// Trashed emails tracking — simple Set of email IDs persisted per-user.
// Independent dari storage email asli (tickets/state.messages) supaya simple.
function _emailTrashKey() {
  return `playly-trashemails-${(user?.username || "anon")}`;
}
function getTrashedEmails() {
  try { return new Set(JSON.parse(localStorage.getItem(_emailTrashKey()) || "[]")); }
  catch { return new Set(); }
}
function saveTrashedEmails(set) {
  try { localStorage.setItem(_emailTrashKey(), JSON.stringify([...set])); }
  catch {}
}
function markEmailTrashed(id, trashed) {
  const set = getTrashedEmails();
  if (trashed) set.add(String(id));
  else set.delete(String(id));
  saveTrashedEmails(set);
}
function deleteEmailPermanent(id) {
  // Hapus dari set trash + (kalau memungkinkan) hapus juga dari source storage.
  const idStr = String(id);
  const set = getTrashedEmails();
  set.delete(idStr);
  saveTrashedEmails(set);
  // Hapus dari source storage — best effort cover semua kind
  try {
    // Tickets (admin-out kind) — pakai getAdminData/saveAdminData
    if (typeof getAdminData === "function" && typeof saveAdminData === "function") {
      const tickets = getAdminData("tickets") || [];
      const filtered = tickets.filter(t => String(t.id) !== idStr);
      if (filtered.length !== tickets.length) saveAdminData("tickets", filtered);
    }
  } catch {}
  try {
    // user-out / user-in dari state.userEmails / state.receivedEmails
    if (state && Array.isArray(state.userEmails)) {
      state.userEmails = state.userEmails.filter(m => String(m.id) !== idStr);
    }
    if (state && Array.isArray(state.receivedEmails)) {
      state.receivedEmails = state.receivedEmails.filter(m => String(m.id) !== idStr);
    }
    if (typeof saveState === "function") saveState();
  } catch {}
}

function normalizeEmailEntries() {
  const trashed = getTrashedEmails();
  const items = [];
  const tagTrash = (it) => { it._trashed = trashed.has(String(it.id)); return it; };

  // Email user → admin (outgoing)
  getAdminEmailsForUser().forEach(t => {
    items.push(tagTrash({
      id: t.id,
      kind: "admin-out",
      _ticket: t,
      title: t.title,
      body: t.body,
      createdAt: t.createdAt,
      replies: t.replies || [],
      _readByUser: t._readByUser,
      fromLabel: "Kamu",
      toLabel: "🛡️ Admin Playly",
      peerUsername: "admin",
    }));
  });

  // Email user → user lain (outgoing)
  getUserSentEmails().forEach(m => {
    items.push(tagTrash({
      id: m.id,
      kind: "user-out",
      _user: m,
      title: m.subject,
      body: m.body,
      createdAt: m.createdAt,
      replies: m.replies || [],
      _readByUser: true,
      fromLabel: "Kamu",
      toLabel: `@${m.to || "user"}`,
      peerUsername: m.to,
    }));
  });

  // Email user lain → kamu (incoming)
  getUserReceivedEmails().forEach(m => {
    items.push(tagTrash({
      id: m.id,
      kind: "user-in",
      _user: m,
      title: m.subject,
      body: m.body,
      createdAt: m.createdAt,
      replies: m.replies || [],
      _readByUser: !m._unread,
      fromLabel: `@${m.from || "user"}`,
      toLabel: "Kamu",
      peerUsername: m.from,
    }));
  });

  return items.sort((a, b) => (b.createdAt || 0) - (a.createdAt || 0));
}

// Backward-compat alias — kode lain (badge sync, dll) masih panggil ini.
function getUserEmails() { return normalizeEmailEntries(); }

// Folder metadata — dipakai untuk filter, judul, hint, dan empty state.
const USER_EMAIL_FOLDERS = {
  all:     { title: "📂 Semua Email",      hint: "Gabungan semua email dari Inbox, Terkirim, Balasan, dan Menunggu.", empty: { icon: "📂", title: "Belum ada email",       desc: "Tulis email pertamamu lewat tombol Compose di atas." } },
  inbox:   { title: "📥 Inbox",            hint: "Replies from admin & incoming email from other users.", empty: { icon: "📭", title: "No incoming email yet",  desc: "Replies from admin & email from other users will appear here." } },
  sent:    { title: "📤 Sent",             hint: "All emails you've sent (admin & users).",                empty: { icon: "✉️", title: "No sent email yet",       desc: 'Click "Compose" to send to admin or another user.' } },
  replied: { title: "💬 Replies",          hint: "Emails that have received a reply.",                    empty: { icon: "💬", title: "No replies yet",          desc: "Emails replied to by admin or other users will appear here." } },
  waiting: { title: "⏳ Awaiting Reply",   hint: "Your emails that haven't been replied to.",             empty: { icon: "⏳", title: "Nothing is waiting",      desc: "All of your emails have been replied to." } },
  trash:   { title: "🗑️ Sampah",          hint: "Email yang kamu hapus. Bisa di-restore atau dihapus permanen.", empty: { icon: "🗑️", title: "Sampah kosong",       desc: "Email yang kamu hapus akan muncul di sini." } },
};

function filterUserEmailsByFolder(all, folder) {
  // Trash filter: tampilkan HANYA email yang ditandai trashed
  if (folder === "trash") return all.filter(e => e._trashed);
  // Semua filter lain: exclude email yang udah ditrash
  const notTrashed = all.filter(e => !e._trashed);
  if (folder === "all") return notTrashed;
  if (folder === "inbox") {
    return notTrashed.filter(e => (e.kind === "admin-out" && e.replies.length) || e.kind === "user-in");
  }
  if (folder === "sent") {
    return notTrashed.filter(e => e.kind === "admin-out" || e.kind === "user-out");
  }
  if (folder === "replied") {
    return notTrashed.filter(e => (e.kind === "admin-out" || e.kind === "user-out") && e.replies.length);
  }
  if (folder === "waiting") {
    return notTrashed.filter(e => (e.kind === "admin-out" || e.kind === "user-out") && !e.replies.length);
  }
  return notTrashed;
}

function renderUserEmail() {
  const list = document.getElementById("userEmailList");
  if (!list) return;
  const all = normalizeEmailEntries();

  // Counts per folder
  const inboxItems = filterUserEmailsByFolder(all, "inbox");
  const sentItems = filterUserEmailsByFolder(all, "sent");
  const repliedItems = filterUserEmailsByFolder(all, "replied");
  const waitingItems = filterUserEmailsByFolder(all, "waiting");
  const inboxUnread = inboxItems.filter(e => !e._readByUser).length;

  const setCount = (id, n) => { const el = document.getElementById(id); if (el) el.textContent = n; };
  const trashItems = all.filter(e => e._trashed);
  setCount("userEmailCountAll", all.filter(e => !e._trashed).length);
  setCount("userEmailCountInbox", inboxUnread || inboxItems.length);
  setCount("userEmailCountSent", sentItems.length);
  setCount("userEmailCountReplied", repliedItems.length);
  setCount("userEmailCountWaiting", waitingItems.length);
  setCount("userEmailCountTrash", trashItems.length);

  // Sync folder buttons
  document.querySelectorAll(".user-email-folder").forEach(b => {
    b.classList.toggle("active", b.dataset.uemailFilter === userEmailState.filter);
  });

  // Sync folder header
  const meta = USER_EMAIL_FOLDERS[userEmailState.filter] || USER_EMAIL_FOLDERS.inbox;
  const titleEl = document.getElementById("userEmailFolderTitle");
  const hintEl = document.getElementById("userEmailFolderHint");
  if (titleEl) titleEl.textContent = meta.title;
  if (hintEl) hintEl.textContent = meta.hint;

  const filtered = filterUserEmailsByFolder(all, userEmailState.filter);

  if (!filtered.length) {
    list.innerHTML = `<div class="user-email-empty">
      <div class="user-email-empty-icon">${meta.empty.icon}</div>
      <h4>${meta.empty.title}</h4>
      <p>${meta.empty.desc}</p>
    </div>`;
    return;
  }

  list.innerHTML = filtered.map(e => {
    const replyCount = e.replies.length;
    const lastReply = replyCount ? e.replies[replyCount - 1] : null;
    const isUnread = !e._readByUser && (e.kind === "user-in" || (lastReply && e.kind === "admin-out"));
    // Pilih timestamp yang paling relevan untuk folder ini
    const tsRaw = (userEmailState.filter === "inbox" && lastReply?.ts) ? lastReply.ts : e.createdAt;
    const ts = tsRaw ? (typeof relTime === "function" ? relTime(tsRaw) : "") : "";

    // Badge status — beda style per kind
    let statusBadge = "";
    if (e.kind === "user-in") {
      statusBadge = `<span class="user-email-badge info">📥 From ${escapeHtml(e.fromLabel)}</span>`;
    } else if (replyCount) {
      statusBadge = `<span class="user-email-badge ok">✓ ${replyCount} ${replyCount === 1 ? "reply" : "replies"}${isUnread ? ' • new' : ''}</span>`;
    } else {
      const target = e.kind === "admin-out" ? "admin" : "user";
      statusBadge = `<span class="user-email-badge warn">⏳ Awaiting ${target} reply</span>`;
    }

    // Icon — admin = shield, user-out = sent, user-in = inbox
    const icon = e.kind === "admin-out" ? "🛡️" : (e.kind === "user-in" ? "📥" : "📤");

    // Preview body — kalau inbox dan punya reply, pakai body reply terakhir
    const previewSrc = (userEmailState.filter === "inbox" && lastReply?.body) ? lastReply.body : (e.body || "");

    // Meta line — siapa to / from
    const metaLine = e.kind === "user-in"
      ? `From ${escapeHtml(e.fromLabel)}`
      : `To ${escapeHtml(e.toLabel)}`;

    const isTrash = userEmailState.filter === "trash";
    const trashAction = isTrash
      ? `<button type="button" class="uef-row-action" data-uemail-restore="${e.id}" title="Pulihkan">↺</button>
         <button type="button" class="uef-row-action" data-uemail-delete-permanent="${e.id}" title="Hapus permanen">🗑️</button>`
      : `<button type="button" class="uef-row-action" data-uemail-trash="${e.id}" title="Pindahkan ke Sampah">🗑️</button>`;
    return `
      <div class="user-email-item ${isUnread ? 'unread' : ''}" data-uemail-id="${e.id}" data-uemail-kind="${e.kind}">
        <div class="user-email-icon">${icon}</div>
        <div class="user-email-body">
          <div class="user-email-row">
            <strong class="user-email-subject">${escapeHtml(e.title || "(no subject)")}</strong>
            <span class="user-email-time">${escapeHtml(ts)}</span>
          </div>
          <small class="user-email-meta-line">${metaLine}</small>
          <p class="user-email-preview">${escapeHtml(String(previewSrc).slice(0, 120))}${previewSrc.length > 120 ? "…" : ""}</p>
          ${statusBadge}
        </div>
        <div class="user-email-row-actions" style="display:flex;gap:4px;align-items:center;flex-shrink:0">
          ${trashAction}
        </div>
      </div>`;
  }).join("");

  // Trash / restore / delete-permanent handlers
  list.querySelectorAll("[data-uemail-trash]").forEach(btn => {
    btn.addEventListener("click", e => {
      e.stopPropagation();
      const id = btn.dataset.uemailTrash;
      markEmailTrashed(id, true);
      toast?.("🗑️ Email dipindah ke Sampah", "");
      renderUserEmail();
    });
  });
  list.querySelectorAll("[data-uemail-restore]").forEach(btn => {
    btn.addEventListener("click", e => {
      e.stopPropagation();
      const id = btn.dataset.uemailRestore;
      markEmailTrashed(id, false);
      toast?.("↺ Email dipulihkan", "success");
      renderUserEmail();
    });
  });
  list.querySelectorAll("[data-uemail-delete-permanent]").forEach(btn => {
    btn.addEventListener("click", e => {
      e.stopPropagation();
      const id = btn.dataset.uemailDeletePermanent;
      if (!window.confirm("Hapus email ini permanen? Tidak bisa di-restore.")) return;
      deleteEmailPermanent(id);
      toast?.("🗑️ Email dihapus permanen", "success");
      renderUserEmail();
    });
  });

  // Klik item → open detail popup. Support 2 jenis: admin ticket vs user-to-user mail.
  list.querySelectorAll("[data-uemail-id]").forEach(el => {
    el.addEventListener("click", () => {
      const id = el.dataset.uemailId;
      const kind = el.dataset.uemailKind;
      const entry = all.find(e => String(e.id) === String(id) && e.kind === kind);
      if (!entry) return;
      if (entry.kind === "admin-out") {
        openUserEmailDetail(entry._ticket);
      } else {
        openUserEmailDetailUser(entry);
      }
    });
  });
}

// Detail popup untuk email user-to-user (in atau out). Mirip openUserEmailDetail
// tapi untuk peer username, bukan admin.
function openUserEmailDetailUser(entry) {
  // Mark as read kalau ini incoming
  if (entry.kind === "user-in" && entry._user) {
    entry._user._unread = false;
    state.userMailbox = state.userMailbox || { sent: [], received: [] };
    const idx = (state.userMailbox.received || []).findIndex(m => String(m.id) === String(entry.id));
    if (idx >= 0) {
      state.userMailbox.received[idx]._unread = false;
      saveState();
    }
  }

  closeUserEmailDetail();
  const modal = document.createElement("div");
  modal.className = "hs-popup-modal";
  modal.id = "__userEmailModal";

  const ts = entry.createdAt ? (typeof relTime === "function" ? relTime(entry.createdAt) : "") : "";
  const isIncoming = entry.kind === "user-in";
  const peer = entry.peerUsername || "user";
  const headerSenderName = isIncoming ? entry.fromLabel : "You";
  const subjectIcon = isIncoming ? "📥" : "📤";

  const replies = (entry.replies || []).map(r => {
    const fromMe = r.from === user?.username || r.fromMe;
    return `
    <div class="user-email-thread-msg ${fromMe ? 'me' : 'admin'}">
      <div class="user-email-thread-head">
        <strong>${escapeHtml(fromMe ? "You" : (r.fromName || `@${r.from || peer}`))}</strong>
        <small>${escapeHtml(typeof relTime === "function" && r.ts ? relTime(r.ts) : "")}</small>
      </div>
      <p class="user-email-thread-body">${escapeHtml(r.body || "")}</p>
    </div>
  `;
  }).join("");

  modal.innerHTML = `
    <div class="hs-popup-backdrop" data-uemail-close></div>
    <div class="hs-popup-panel user-email-panel">
      <button type="button" class="hs-popup-close" data-uemail-close aria-label="Tutup">✕</button>
      <div class="user-email-thread-subject">${subjectIcon} ${escapeHtml(entry.title || "(no subject)")}</div>
      <small class="user-email-thread-meta">${isIncoming ? `From ${escapeHtml(entry.fromLabel)}` : `To @${escapeHtml(peer)}`} • ${escapeHtml(ts)}</small>
      <div class="user-email-thread-body-wrap">
        <div class="user-email-thread-msg ${isIncoming ? 'admin' : 'me'}">
          <div class="user-email-thread-head">
            <strong>${escapeHtml(headerSenderName)}</strong>
            <small>${escapeHtml(ts)}</small>
          </div>
          <p class="user-email-thread-body">${escapeHtml(entry.body || "")}</p>
        </div>
        ${replies}
      </div>
      <form class="user-email-reply-form" id="userEmailReplyForm">
        <textarea name="reply" rows="3" placeholder="Balas pesan..." required minlength="2"></textarea>
        <button type="submit" class="btn primary small">📤 Kirim Balasan</button>
      </form>
    </div>
  `;
  document.body.appendChild(modal);
  requestAnimationFrame(() => modal.classList.add("show"));

  modal.querySelector("#userEmailReplyForm")?.addEventListener("submit", e => {
    e.preventDefault();
    const fd = new FormData(e.target);
    const reply = String(fd.get("reply") || "").trim();
    if (reply.length < 2) return;
    sendUserEmailReply(entry, reply);
    closeUserEmailDetail();
    toast(`📤 Balasan terkirim`, "success");
    renderUserEmail();
    syncPdEmailBadge();
  });

  renderUserEmail();
  syncPdEmailBadge();
}

// Kirim reply untuk email user-to-user. Tulis ke kedua sisi (sender + recipient).
function sendUserEmailReply(entry, replyBody) {
  if (!user?.username) return;
  const me = user.username;
  const peer = entry.peerUsername;
  if (!peer) return;
  const replyObj = {
    from: me,
    fromName: user.name || me,
    body: replyBody,
    ts: Date.now(),
    fromMe: true,
  };

  // Update di sisi kita (state lokal)
  state.userMailbox = state.userMailbox || { sent: [], received: [] };
  const ownArr = entry.kind === "user-in" ? state.userMailbox.received : state.userMailbox.sent;
  const ownIdx = ownArr.findIndex(m => String(m.id) === String(entry.id));
  if (ownIdx >= 0) {
    ownArr[ownIdx].replies = ownArr[ownIdx].replies || [];
    ownArr[ownIdx].replies.push(replyObj);
    saveState();
  }

  // Update di sisi peer (cross-storage)
  const peerKey = `playly-state-${peer}`;
  let peerState;
  try { peerState = JSON.parse(localStorage.getItem(peerKey)); } catch { peerState = null; }
  if (!peerState) peerState = {};
  peerState.userMailbox = peerState.userMailbox || { sent: [], received: [] };
  // Reply ke email peer = mirror balik. Kalau entry kita user-in (peer kirim ke kita),
  // di sisi peer email tsb ada di .sent. Kalau entry kita user-out (kita kirim ke peer),
  // di sisi peer email tsb ada di .received.
  const peerArr = entry.kind === "user-in" ? (peerState.userMailbox.sent || []) : (peerState.userMailbox.received || []);
  const peerIdx = peerArr.findIndex(m => String(m.id) === String(entry.id));
  if (peerIdx >= 0) {
    peerArr[peerIdx].replies = peerArr[peerIdx].replies || [];
    // Mark unread untuk peer
    peerArr[peerIdx]._unread = true;
    peerArr[peerIdx].replies.push({ ...replyObj, fromMe: false });
    if (entry.kind === "user-in") peerState.userMailbox.sent = peerArr;
    else peerState.userMailbox.received = peerArr;
    try { localStorage.setItem(peerKey, JSON.stringify(peerState)); } catch {}
    if (window.cloudSync?.pushKey) try { window.cloudSync.pushKey(peerKey); } catch {}
  }
}

