/* =========================================================
   USER HOME — topbar nav clickable scroll to section (2026-05-08)
   ========================================================= */
(function () {
  if (window.__pjUserHomeTopbarNav) return;
  window.__pjUserHomeTopbarNav = true;

  var SECTIONS = [
    { id: "home-hero",     label: "Beranda",   selector: "section[data-view='home'] .hero", icon: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M4 11l8-7 8 7"/><path d="M6 10v9h12v-9"/><path d="M10 19v-5h4v5"/></svg>' }
  ];

  function tagSections() {
    var view = document.querySelector("section[data-view='home']");
    if (!view) return;
    SECTIONS.forEach(function (s) {
      var el = view.querySelector(s.selector);
      if (el && !el.dataset.homeSection) {
        el.dataset.homeSection = s.id;
        el.id = el.id || s.id;
      }
    });
  }

  function buildNav() {
    if (document.body && document.body.dataset.role === "admin") return;
    var topbar = document.querySelector(".topbar");
    if (!topbar) return;
    if (topbar.querySelector(".topbar-home-nav")) return;

    var nav = document.createElement("nav");
    nav.className = "topbar-home-nav";
    SECTIONS.forEach(function (s) {
      var btn = document.createElement("button");
      btn.type = "button";
      btn.className = "thn-link";
      btn.innerHTML = (s.icon ? s.icon : "") + '<span>' + s.label + '</span>';
      btn.dataset.thnTarget = s.id;
      btn.setAttribute("data-no-i18n", "");
      btn.addEventListener("click", function () {
        var target = document.querySelector("[data-home-section='" + s.id + "']") || document.getElementById(s.id);
        if (!target) return;
        // Make sure home view is active first
        var homeNavBtn = document.querySelector('[data-view="home"]');
        if (homeNavBtn && typeof switchView === "function") {
          try { switchView("home"); } catch (e) {}
        }
        setTimeout(function () {
          target.scrollIntoView({ behavior: "smooth", block: "start" });
        }, 100);
      });
      nav.appendChild(btn);
    });

    var breadcrumb = topbar.querySelector(".breadcrumb");
    if (breadcrumb && breadcrumb.parentNode === topbar) {
      breadcrumb.parentNode.insertBefore(nav, breadcrumb.nextSibling);
    } else {
      topbar.insertBefore(nav, topbar.firstChild);
    }
  }

  function setupActiveTracker() {
    var view = document.querySelector("section[data-view='home']");
    if (!view) return;
    var sections = view.querySelectorAll("[data-home-section]");
    if (!sections.length) return;
    var io = new IntersectionObserver(function (entries) {
      entries.forEach(function (en) {
        if (en.isIntersecting && en.intersectionRatio > 0.3) {
          var id = en.target.dataset.homeSection;
          document.querySelectorAll(".thn-link").forEach(function (l) {
            l.classList.toggle("active", l.dataset.thnTarget === id);
          });
        }
      });
    }, { threshold: [0, 0.3, 0.6, 1], rootMargin: "-80px 0px -40% 0px" });
    sections.forEach(function (s) { io.observe(s); });
  }

  function init() {
    tagSections();
    buildNav();
    setupActiveTracker();
  }

  // Hide nav when not on home view
  function syncVisibility() {
    var nav = document.querySelector(".topbar-home-nav");
    if (!nav) return;
    var homeActive = !!document.querySelector("section[data-view='home'].active");
    nav.style.display = homeActive ? "inline-flex" : "none";
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", function () { init(); syncVisibility(); });
  } else {
    init();
    syncVisibility();
  }

  // Re-sync on view change
  document.addEventListener("click", function (e) {
    if (e.target.closest("[data-view]")) {
      setTimeout(syncVisibility, 100);
    }
  });

  // Watch for view changes
  var bodyObserver = new MutationObserver(syncVisibility);
  if (document.body) bodyObserver.observe(document.body, { attributes: true, attributeFilter: ["class", "data-view"] });
})();

/* =========================================================
   ADMIN SECURITY CARD — wrap with 3D flip v2 (preserve content)
   ========================================================= */
(function () {
  if (window.__pjAscFlip2) return;
  window.__pjAscFlip2 = true;

  var BACK_CONTENT = [
    { icon: "🛡️", capKey: "lp.flip.preseed.cap",  subKey: "lp.flip.preseed.sub"  },
    { icon: "🔐", capKey: "lp.flip.2fa.cap",      subKey: "lp.flip.2fa.sub"      },
    { icon: "👥", capKey: "lp.flip.role.cap",     subKey: "lp.flip.role.sub"     },
    { icon: "📋", capKey: "lp.flip.audit.cap",    subKey: "lp.flip.audit.sub"    },
    { icon: "⏱️", capKey: "lp.flip.cooldown.cap", subKey: "lp.flip.cooldown.sub" },
    { icon: "🔒", capKey: "lp.flip.encrypt.cap",  subKey: "lp.flip.encrypt.sub"  }
  ];

  function wrapCard(card, idx) {
    if (card.dataset.ascFlipped === "1") return;
    card.dataset.ascFlipped = "1";
    var back = BACK_CONTENT[idx] || BACK_CONTENT[0];

    // Move existing children to a fragment (preserve them as front content)
    var frag = document.createDocumentFragment();
    while (card.firstChild) frag.appendChild(card.firstChild);

    var front = document.createElement("div");
    front.className = "asc-flip-front";
    front.appendChild(frag);

    var backEl = document.createElement("div");
    backEl.className = "asc-flip-back";
    backEl.innerHTML =
      '<div class="ascb-icon">' + back.icon + '</div>' +
      '<div class="ascb-caption" data-i18n="' + back.capKey + '">' + t(back.capKey) + '</div>' +
      '<div class="ascb-sub" data-i18n="' + back.subKey + '">' + t(back.subKey) + '</div>';

    var inner = document.createElement("div");
    inner.className = "asc-flip-inner";
    inner.appendChild(front);
    inner.appendChild(backEl);
    card.appendChild(inner);
  }

  function applyAll() {
    if (!document.body || document.body.dataset.role !== "admin") return;
    var cards = document.querySelectorAll(".admin-security-grid .admin-security-card");
    cards.forEach(wrapCard);
  }

  function watch() {
    applyAll();
    var grid = document.querySelector(".admin-security-grid");
    if (!grid) { setTimeout(watch, 600); return; }
    var mo = new MutationObserver(applyAll);
    mo.observe(grid, { childList: true, subtree: true });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", watch);
  } else {
    watch();
  }
})();
