// ----------------------- PLAYER KEYBOARD SHORTCUTS -----------------------
// Per user 2026-05-08: tambah skip 10s di video player.
//   ←  Mundur 10 detik    →  Maju 10 detik
//   J  Mundur 10 detik    L  Maju 10 detik   (YouTube convention)
//   Space  Play/Pause     M  Mute/Unmute
// Hanya aktif saat user di view "player" atau "admin-player" + tidak sedang
// fokus di input/textarea/contenteditable.
(function () {
  function isTyping() {
    const a = document.activeElement;
    if (!a) return false;
    const tag = a.tagName;
    return tag === "INPUT" || tag === "TEXTAREA" || a.isContentEditable;
  }
  function activeVideo() {
    const userView  = document.querySelector('section.view[data-view="player"].active');
    const adminView = document.querySelector('section.view[data-view="admin-player"].active');
    if (userView)  return document.getElementById("videoEl");
    if (adminView) return document.getElementById("apVideo");
    // Library inline player — aktif kalau visible (di view "videos" / others)
    const inline = document.getElementById("libInlinePlayer");
    if (inline && !inline.hidden) {
      const v = document.getElementById("libInlineVideo");
      if (v && v.src) return v;
    }
    return null;
  }
  document.addEventListener("keydown", e => {
    if (isTyping()) return;
    const v = activeVideo();
    if (!v) return;
    const k = e.key.toLowerCase();
    if (e.key === "ArrowLeft" || k === "j") {
      e.preventDefault();
      v.currentTime = Math.max(v.currentTime - 10, 0);
    } else if (e.key === "ArrowRight" || k === "l") {
      e.preventDefault();
      v.currentTime = Math.min(v.currentTime + 10, v.duration || 0);
    } else if (e.key === " " || k === "k") {
      e.preventDefault();
      v.paused ? v.play() : v.pause();
    } else if (k === "m") {
      e.preventDefault();
      v.muted = !v.muted;
    }
  });
})();

// ----------------------- NOTIF DROPDOWN POPUP (admin, anchored below bell) -----------------------
// Per user 2026-05-10: admin dashboard bell → dropdown popup di bawah icon.
// Tombol "Lihat detail" di footer buka side panel detail (#notifPanel) yang
// punya section Perlu Perhatian + Aktivitas Real-time + user notifs.
function renderNotifDropdownContent() {
  const body = document.getElementById("notifDropdownBody");
  if (!body) return;
  const isAdmin = document.body.dataset.role === "admin";
  const items = [];
  if (isAdmin) {
    // Admin: ambil 5 alert terbaru + 3 live feed event
    try {
      const alerts = (typeof getAdminAlerts === "function") ? getAdminAlerts().slice(0, 4) : [];
      alerts.forEach(a => items.push({
        icon: a.icon || "⚠️",
        text: a.text || a.title || "Alert",
        time: a.time || ""
      }));
    } catch {}
    try {
      const feed = (typeof getAdminLiveFeed === "function") ? getAdminLiveFeed().slice(0, 3) : [];
      feed.forEach(f => items.push({
        icon: f.icon || "🔥",
        text: f.text || f.title || "Activity",
        time: f.time || ""
      }));
    } catch {}
  } else {
    // User: ambil notif list standard
    try {
      const list = (typeof getNotifList === "function") ? getNotifList().slice(0, 5) : [];
      list.forEach(n => items.push({
        icon: n.icon || NI_BELL,
        text: n.text || n.title || "Notification",
        time: n.time || ""
      }));
    } catch {}
  }
  if (!items.length) {
    body.innerHTML = `<div class="ndd-empty">Belum ada notifikasi baru.</div>`;
    return;
  }
  body.innerHTML = items.map(it => `
    <div class="ndd-item">
      <span class="ndd-icon">${it.icon}</span>
      <div class="ndd-text">${it.text}</div>
      ${it.time ? `<span class="ndd-time">${it.time}</span>` : ""}
    </div>
  `).join("");
}

function toggleNotifDropdown() {
  const dd = document.getElementById("notifDropdown");
  const bell = document.getElementById("openNotif");
  if (!dd || !bell) return;
  if (!dd.hidden) {
    closeNotifDropdown();
    return;
  }
  // Lazy-mount notif panel content sebelum populate dropdown — supaya
  // getAdminAlerts/getAdminLiveFeed/getNotifList yg query #notifPanel
  // dapat data (v479).
  if (typeof ensureLazyPanelMounted === "function") {
    if (ensureLazyPanelMounted("notifPanel")) {
      // Baru di-mount — populate section dulu supaya dropdown ada datanya.
      try { renderAdminAlerts?.(); } catch {}
      try { renderAdminLiveFeed?.(); } catch {}
      try { renderUserNotifAlerts?.(); } catch {}
      try { renderUserLiveFeed?.(); } catch {}
      try { renderNotifications?.(); } catch {}
    }
  }
  renderNotifDropdownContent();
  dd.hidden = false;
  // Position fixed anchored below bell (centered horizontally)
  const r = bell.getBoundingClientRect();
  dd.style.position = "fixed";
  dd.style.top = `${Math.round(r.bottom + 10)}px`;
  // Right-align supaya dropdown tidak keluar viewport (bell biasanya near right edge)
  dd.style.right = `${Math.round(window.innerWidth - r.right)}px`;
  dd.style.left = "auto";
  requestAnimationFrame(() => dd.classList.add("show"));
}

function closeNotifDropdown() {
  const dd = document.getElementById("notifDropdown");
  if (!dd) return;
  dd.classList.remove("show");
  setTimeout(() => { dd.hidden = true; }, 220);
}
window.toggleNotifDropdown = toggleNotifDropdown;
window.closeNotifDropdown = closeNotifDropdown;

// Helper getters — fallback kalau function aslinya belum di-define
function getAdminAlerts() {
  try {
    const ul = document.querySelector("#notifPanel .admin-alerts");
    if (!ul) return [];
    return Array.from(ul.querySelectorAll("li")).map(li => ({
      icon: li.querySelector(".na-icon")?.textContent || "⚠️",
      text: li.querySelector(".na-text")?.textContent || li.textContent.trim(),
      time: li.querySelector(".na-time")?.textContent || ""
    }));
  } catch { return []; }
}
function getAdminLiveFeed() {
  try {
    const ul = document.querySelector("#adminLiveFeed");
    if (!ul) return [];
    return Array.from(ul.querySelectorAll("li")).slice(0, 3).map(li => ({
      icon: li.querySelector(".af-icon")?.textContent || "🔥",
      text: li.querySelector(".af-text")?.textContent || li.textContent.trim(),
      time: li.querySelector(".af-time")?.textContent || ""
    }));
  } catch { return []; }
}
function getNotifList() {
  try {
    const ul = document.querySelector("#notifList");
    if (!ul) return [];
    // #notifList di-render renderNotifications() sebagai .notif-cat blocks
    // (icon = SVG monokrom di .notif-cat-icon, item di .notif-item). Flatten
    // jadi list per-notif supaya dropdown nampilin baris bersih + ikon SVG
    // yang sama (bukan emoji 🔔 lagi).
    const out = [];
    ul.querySelectorAll(".notif-cat").forEach(cat => {
      const icon = cat.querySelector(".notif-cat-icon")?.innerHTML?.trim() || "";
      cat.querySelectorAll(".notif-item").forEach(it => {
        out.push({
          icon: icon,
          text: (it.querySelector(".info p")?.textContent || it.textContent || "").trim().slice(0, 80),
          time: (it.querySelector(".time")?.textContent || "").trim()
        });
      });
    });
    return out.slice(0, 5);
  } catch { return []; }
}

// Mini-floating drag handler ada di setupLibMiniDrag() — tidak duplikasi.
